window.HADITH_CACHE["bukhari_8"] = {"4001":{"ar":"حَدَّثَنَا مُؤَمَّلٌ هُوَ ابْنُ هِشَامٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَوْفٌ حَدَّثَنَا أَبُو رَجَاءٍ حَدَّثَنَا سَمُرَةُ بْنُ جُنْدَبٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَا أَتَانِي اللَّيْلَةَ آتِيَانِ فَابْتَعَثَانِي فَانْتَهَيْنَا إِلَى مَدِينَةٍ مَبْنِيَّةٍ بِلَبِنِ ذَهَبٍ وَلَبِنِ فِضَّةٍ فَتَلَقَّانَا رِجَالٌ شَطْرٌ مِنْ خَلْقِهِمْ كَأَحْسَنِ مَا أَنْتَ رَاءٍ وَشَطْرٌ كَأَقْبَحِ مَا أَنْتَ رَاءٍ قَالَا لَهُمْ اذْهَبُوا فَقَعُوا فِي ذَلِكَ النَّهْرِ فَوَقَعُوا فِيهِ ثُمَّ رَجَعُوا إِلَيْنَا قَدْ ذَهَبَ ذَلِكَ السُّوءُ عَنْهُمْ فَصَارُوا فِي أَحْسَنِ صُورَةٍ قَالَا لِي هَذِهِ جَنَّةُ عَدْنٍ وَهَذَاكَ مَنْزِلُكَ قَالَا أَمَّا الْقَوْمُ الَّذِينَ كَانُوا شَطْرٌ مِنْهُمْ حَسَنٌ وَشَطْرٌ مِنْهُمْ قَبِيحٌ فَإِنَّهُمْ خَلَطُوا عَمَلًا صَالِحًا وَآخَرَ سَيِّئًا تَجَاوَزَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Muammal] yaitu Ibnu Hisyam Telah menceritakan kepada kami [Isma'il bin Ibrahim] Telah menceritakan kepada kami ['Auf] Telah menceritakan kepada kami [Abu Raja'] Telah menceritakan kepada kami [Samurah bin Jundab radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tadi malam dua orang (tamu) berkunjung kepadaku (dalam mimpiku) dan membawaku ke sebuah kota yang dibangun dari emas dan perak. Di sana kami bertemu sejumlah laki-laki yang setengah tubuhnya terlihat sangat tampan seperti manusia tertampan yang pernah kalian lihat. Dan setengah tubuh yang lainnya sangat buruk seperti manusia yang paling buruk yang pernah kalian lihat. Dua orang tamu itu berkata kepada mereka berdua, pergilah berendam di sungai itu. Maka mereka pun berendam di dalam sungai itu kemudian kembali kepada kami. keburukan mereka lenyap dan mereka sekarang benar-benar tampan. Tamu-tamuku berkata kepadaku; 'Yang pertama (Anda lihat) adalah surga Adn dan itu adalah tempatmu.' Kemudian mereka berkata; sedangkan mereka yang separuh tampan separuh buruk rupa adalah orang yang mencampur adukan perbuatan baik dan perbuatan jahat, namun Allah memberi mereka ampunan.'"},"4002":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ دَخَلَ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ يَا أَبَا طَالِبٍ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَنَزَلَتْ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] Telah menceritakan kepada kami ['Abdur Razzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Bapaknya] dia berkata; \"Ketika Abu Thalib mendekati ajalnya, Rasulullah shallallahu 'alaihi wasallam masuk menemuinya dan di dekatnya ada Abu Jahal dan Abdullah bin Abu Umayyah. Lalu beliau bersabda: \"Wahai pamanku, ucapkanlah 'Laa Ilaaha Illallah (tidak ada sesembahan yang berhak di sembah selain Allah) ' yang dengannya aku akan berhujah untuk membelamu di sisi Allah -Azza wa Jalla-.\" Maka Abu Jahal dan Abdullah bin Umayyah berkata kepadanya; \"Wahai Abu Thalib, Apakah kamu benci dengan agama Abdul Muthalib?\" Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh akan aku akan mintakan ampunan untukmu selama aku tidak dilarang.\" Lalu turunlah ayat, \"Tidak sepatutnya bagi Nabi dan orang-orang yang beriman memintakan ampun (kepada Allah) bagi orang-orang musyrik walaupun orang-orang musyrik itu adalah kaum kerabat (nya), sesudah jelas bagi mereka, bahwasanya orang-orang musyrik itu adalah penghuni neraka jahanam.\" (Qs. At Taubah; 113)."},"4003":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ ح قَالَ أَحْمَدُ وَحَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ كَعْبِ بْنِ مَالِكٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ كَعْبٍ وَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍفِي حَدِيثِهِ{ وَعَلَى الثَّلَاثَةِ الَّذِينَ خُلِّفُوا }قَالَ فِي آخِرِ حَدِيثِهِ إِنَّ مِنْ تَوْبَتِي أَنْ أَنْخَلِعَ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] dia berkata; Telah menceritakan kepadaku [Ibnu Wahb] dia berkata; Telah mengabarkan kepadaku [Yunus] -Demikian juga diriwayatkan dari jalur lainnya-, [Ahmad] berkata; Dan telah menceritakan kepada kami ['Anbasah] Telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Abdur Rahman bin Ka'ab bin Malik] dia berkata; Telah mengabarkan kepadaku ['Abdullah bin Ka'ab] dan dia adalah anaknya yang biasa menuntun Ka'ab ketika dia buta. Dia berkata; Aku mendengar [Ka'b bin Malik] menceritakan peristiwanya mengenai firman: dan terhadap tiga orang yang ditangguhkan (penerimaan taubat) mereka, (At Taubah: 118). Diakhir ceritanya Ka'ab berkata; wahai Rasulullah, sesungguhnya taubatku adalah melepaskan diri dari hartaku sebagai sedekah kepada Allah dan RasulNya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tahanlah sebagian hartamu, hal tersebut lebih baik bagimu.\""},"4004":{"ar":"حَدَّثَنِي مُحَمَّدٌ حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي شُعَيْبٍ حَدَّثَنَا مُوسَى بْنُ أَعْيَنَ حَدَّثَنَا إِسْحَاقُ بْنُ رَاشِدٍ أَنَّ الزُّهْرِيَّ حَدَّثَهُ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَسَمِعْتُ أَبِي كَعْبَ بْنَ مَالِكٍ وَهُوَ أَحَدُ الثَّلَاثَةِ الَّذِينَ تِيبَ عَلَيْهِمْ أَنَّهُ لَمْ يَتَخَلَّفْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ غَزَاهَا قَطُّ غَيْرَ غَزْوَتَيْنِ غَزْوَةِ الْعُسْرَةِ وَغَزْوَةِ بَدْرٍ قَالَ فَأَجْمَعْتُ صِدْقِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضُحًى وَكَانَ قَلَّمَا يَقْدَمُ مِنْ سَفَرٍ سَافَرَهُ إِلَّا ضُحًى وَكَانَ يَبْدَأُ بِالْمَسْجِدِ فَيَرْكَعُ رَكْعَتَيْنِ وَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَلَامِي وَكَلَامِ صَاحِبَيَّ وَلَمْ يَنْهَ عَنْ كَلَامِ أَحَدٍ مِنْ الْمُتَخَلِّفِينَ غَيْرِنَا فَاجْتَنَبَ النَّاسُ كَلَامَنَا فَلَبِثْتُ كَذَلِكَ حَتَّى طَالَ عَلَيَّ الْأَمْرُ وَمَا مِنْ شَيْءٍ أَهَمُّ إِلَيَّ مِنْ أَنْ أَمُوتَ فَلَا يُصَلِّي عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ يَمُوتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكُونَ مِنْ النَّاسِ بِتِلْكَ الْمَنْزِلَةِ فَلَا يُكَلِّمُنِي أَحَدٌ مِنْهُمْ وَلَا يُصَلِّي وَلَا يُسَلِّمُ عَلَيَّ فَأَنْزَلَ اللَّهُ تَوْبَتَنَا عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ بَقِيَ الثُّلُثُ الْآخِرُ مِنْ اللَّيْلِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ أُمِّ سَلَمَةَ وَكَانَتْ أُمُّ سَلَمَةَ مُحْسِنَةً فِي شَأْنِي مَعْنِيَّةً فِي أَمْرِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُمَّ سَلَمَةَ تِيبَ عَلَى كَعْبٍ قَالَتْ أَفَلَا أُرْسِلُ إِلَيْهِ فَأُبَشِّرَهُ قَالَ إِذًا يَحْطِمَكُمْ النَّاسُ فَيَمْنَعُونَكُمْ النَّوْمَ سَائِرَ اللَّيْلَةِ حَتَّى إِذَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْفَجْرِ آذَنَ بِتَوْبَةِ اللَّهِ عَلَيْنَا وَكَانَ إِذَا اسْتَبْشَرَ اسْتَنَارَ وَجْهُهُ حَتَّى كَأَنَّهُ قِطْعَةٌ مِنْ الْقَمَرِ وَكُنَّا أَيُّهَا الثَّلَاثَةُ الَّذِينَ خُلِّفُوا عَنْ الْأَمْرِ الَّذِي قُبِلَ مِنْ هَؤُلَاءِ الَّذِينَ اعْتَذَرُوا حِينَ أَنْزَلَ اللَّهُ لَنَا التَّوْبَةَ فَلَمَّا ذُكِرَ الَّذِينَ كَذَبُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُتَخَلِّفِينَ وَاعْتَذَرُوا بِالْبَاطِلِ ذُكِرُوا بِشَرِّ مَا ذُكِرَ بِهِ أَحَدٌ قَالَ اللَّهُ سُبْحَانَهُ{ يَعْتَذِرُونَ إِلَيْكُمْ إِذَا رَجَعْتُمْ إِلَيْهِمْ قُلْ لَا تَعْتَذِرُوا لَنْ نُؤْمِنَ لَكُمْ قَدْ نَبَّأَنَا اللَّهُ مِنْ أَخْبَارِكُمْ وَسَيَرَى اللَّهُ عَمَلَكُمْ وَرَسُولُهُ }الْآيَةَ","id":"Telah menceritakan kepadaku [Muhammad] Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib] Telah menceritakan kepada kami [Musa bin A'yan] Telah menceritakan kepada kami [Ishaq bin Rasyid] bahwa [Az Zuhri] Telah menceritakan kepadanya dia berkata; Telah menceritakan kepadaku ['Abdur Rahman bin 'Abdullah bin Ka'ab bin Malik] dari [Bapaknya] dia berkata; saya mendengar ayahku [Telah mengabarkan kepadaku'ab bin Malik] -ia adalah salah satu dari tiga orang yang diterima taubatnya- bahwa dia tidak pernah tertinggal dari Rasulullah shallallahu 'alaihi wasallam dalam peperangan yang beliau ikuti selain dua peperangan yaitu perang 'Usrah dan perang Badar. Dia berkata; Maka aku pun berusaha untuk mengungkapkan kejujuranku kepada Rasulullah shallallahu 'alaihi wasallam diwaktu dluha. Karena sudah menjadi tradisi beliau apabila datang dari suatu perjalanan beliau selalu shalat dluha. Beliau selalu ke masjid terlebih dahulu kemudian shalat dua raka'at. Beliau melarangku dan kedua sahabatku untuk berbicara. Padahal beliau tidak melarang orang yang tertinggal selainku. Hingga orang-orang pun menjauhi untuk berbicara kepada kami. Hal itu terjadi begitu lama. Dan tidaklah yang membuatku cemas kecuali rasa takutku apabila aku mati sedangkan Nabi shallallahu 'alaihi wasallam tidak mau menshalatiku. Atau Nabi shallallahu 'alaihi wasallam yang meninggal dunia, hingga aku termasuk orang yang buruk keadaannya, tidak seorang pun yang mau berbicara denganku, dan tidak mau menshalati serta mengucapkan salam kepadaku. Kemudian Allah menurunkan ayat kepada Nabi shallallahu 'alaihi wasallam pada sepertiga malam terakhir yang memberitakan taubat kami. Pada waktu itu Rasulullah shallallahu 'alaihi wasallam berada di sisi Ummu Salamah. Ummu Salamah adalah orang yang senantiasa menyebut kebaikan-kebaikan urusanku dan membelaku. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Ya Ummu Salamah, Ka'ab telah diterima taubatnya.' Ummu Salamah berkata; Apakah aku harus mengutus seseorang kepadanya untuk memberikan kabar gembira? Beliau bersabda: Jangan, nanti orang-orang akan memukuli kamu dan menahan kamu dari tidur di malam hari. Hingga tatkala Rasulullah shallallahu 'alaihi wasallam shalat Subuh beliau mengumumkan bahwa Allah telah menerima taubat kami. Dan beliau apabila sedang memberi kabar gembira, wajah beliau kelihatan bersinar seperti bersinarnya sebagian bulan. Dan kamilah yang dimaksudkan ayat, tiga orang yang menyelisihi perintah, yang kemudian diterima alasannya dari orang-orang yang meminta izin untuk tidak berperang. Yaitu ketika Allah menurunkan penerimaan taubat kami. Padahal dulu tatkala disebutkan orang-orang yang mendustakan Rasulullah shallallahu 'alaihi wasallam, yaitu orang-orang yang tidak ikut berperang dan beralasan dengan alasan yang batil. Mereka dikatakan sebagai sejelek-jelek manusia. Allah Ta'ala berfirman: Mereka (orang-orang munafik) mengemukakan 'uzurnya kepadamu, apabila kamu telah kembali kepada mereka (dari medan perang). Katakanlah: \"Janganlah kamu mengemukakan 'uzur; kami tidak percaya lagi kepadamu, (karena) sesungguhnya Allah telah memberitahukan kepada kami beritamu yang sebenarnya. Dan Allah serta Rasul-Nya akan melihat pekerjaanmu…. (At Taubah: 94)."},"4005":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ وَكَانَ قَائِدَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍيُحَدِّثُ حِينَ تَخَلَّفَ عَنْ قِصَّةِ تَبُوكَ فَوَاللَّهِ مَا أَعْلَمُ أَحَدًا أَبْلَاهُ اللَّهُ فِي صِدْقِ الْحَدِيثِ أَحْسَنَ مِمَّا أَبْلَانِي مَا تَعَمَّدْتُ مُنْذُ ذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى يَوْمِي هَذَا كَذِبًا وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لَقَدْ تَابَ اللَّهُ عَلَى النَّبِيِّ وَالْمُهَاجِرِينَ وَالْأَنْصَارِ إِلَى قَوْلِهِ وَكُونُوا مَعَ الصَّادِقِينَ }","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Abdur Rahman bin 'Abdullah bin Ka'ab bin Malik] dari ['Abdullah bin Ka'ab bin Malik] -dia adalah penuntun Ka'ab bin Malik- dia berkata; Aku mendengar [Ka'ab bin Malik] bercerita mengenai ketertinggalannya dari perang Tabuk. Demi Allah, setahu saya tidak ada seorang muslim yang telah di uji Allah dalam kejujuran ucapannya, yang ia lebih baik dari pada apa yang telah diujikan Allah kepada saya sejak saya ceritakan hal ini kepada Rasulullah shallallahu 'alaihi wasallam, saya tidak pernah bermaksud untuk berdusta kepada Rasulullah hingga sekarang ini. Allah Azza wa Jalla berfirman kepada Rasulullah-Nya shallallahu 'alaihi wasallam: \"Sesungguhnya Allah telah menerima taubat Nabi, orang-orang Muhajirin, dan orang-orang Anshar… hingga ayat: 'dan hendaklah kamu bersama orang-orang yang jujur.' (Qs. At-Taubah (9): 117-119)."},"4006":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ الْأَنْصَارِيَّ رَضِيَ اللَّهُ عَنْهُوَكَانَ مِمَّنْ يَكْتُبُ الْوَحْيَ قَالَ أَرْسَلَ إِلَيَّ أَبُو بَكْرٍ مَقْتَلَ أَهْلِ الْيَمَامَةِ وَعِنْدَهُ عُمَرُ فَقَالَ أَبُو بَكْرٍ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِالنَّاسِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِالْقُرَّاءِ فِي الْمَوَاطِنِ فَيَذْهَبَ كَثِيرٌ مِنْ الْقُرْآنِ إِلَّا أَنْ تَجْمَعُوهُ وَإِنِّي لَأَرَى أَنْ تَجْمَعَ الْقُرْآنَ قَالَ أَبُو بَكْرٍ قُلْتُ لِعُمَرَ كَيْفَ أَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي فِيهِ حَتَّى شَرَحَ اللَّهُ لِذَلِكَ صَدْرِي وَرَأَيْتُ الَّذِي رَأَى عُمَرُ قَالَ زَيْدُ بْنُ ثَابِتٍ وَعُمَرُ عِنْدَهُ جَالِسٌ لَا يَتَكَلَّمُ فَقَالَ أَبُو بَكْرٍ إِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ وَلَا نَتَّهِمُكَ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ فَوَاللَّهِ لَوْ كَلَّفَنِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ أَثْقَلَ عَلَيَّ مِمَّا أَمَرَنِي بِهِ مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلَانِ شَيْئًا لَمْ يَفْعَلْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ أَزَلْ أُرَاجِعُهُ حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ اللَّهُ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ فَقُمْتُ فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الرِّقَاعِ وَالْأَكْتَافِ وَالْعُسُبِ وَصُدُورِ الرِّجَالِ حَتَّى وَجَدْتُ مِنْ سُورَةِ التَّوْبَةِ آيَتَيْنِ مَعَ خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهُمَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ حَرِيصٌ عَلَيْكُمْ }إِلَى آخِرِهِمَا وَكَانَتْ الصُّحُفُ الَّتِي جُمِعَ فِيهَا الْقُرْآنُ عِنْدَ أَبِي بَكْرٍ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ عُمَرَ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَتَابَعَهُ عُثْمَانُ بْنُ عُمَرَ وَاللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ وَقَالَ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ وَقَالَ مُوسَى عَنْ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ شِهَابٍ مَعَ أَبِي خُزَيْمَةَ وَتَابَعَهُ يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ أَبِيهِ وَقَالَ أَبُو ثَابِتٍ حَدَّثَنَا إِبْرَاهِيمُ وَقَالَ مَعَ خُزَيْمَةَ أَوْ أَبِي خُزَيْمَةَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Ibnu As Sabbaq] bahwa [Zaid bin Tsabit Al Anshari radliallahu 'anhu] -salah seorang penulis wahyu- dia berkata; Abu Bakar As shiddiq datang kepadaku pada waktu perang Yamamah, ketika itu Umar disampingnya. Abu Bakr berkata bahwasanya Umar mendatangiku dan mengatakan; \"Sesungguhnya perang Yamamah telah berkecamuk (menimpa) para sahabat, dan aku khawatir akan menimpa para penghafal Qur'an di negeri-negeri lainnya sehingga banyak yang gugur dari mereka kecuali engkau memerintahkan pengumpulan (pendokumentasian) al Qur`an.\" Abu Bakar berkata kepada Umar; \"Bagaimana aku mengerjakan suatu proyek yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Umar menjawab; \"Demi Allah hal itu adalah sesuatu yang baik.\" Ia terus mengulangi hal itu sampai Allah melapangkan dadaku sebagaimana melapangkan dada Umar dan aku sependapat dengannya. Zaid berkata; Abu Bakar berkata; -pada waktu itu disampingnya ada Umar sedang duduk, dan dia tidak berkata apa-apa.- \"Sesungguhnya kamu adalah pemuda yang cerdas, kami tidak meragukanmu, dan kamu juga menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam, karena itu kumpulkanlah al Qur'an (dengan seksama).\" Zaid berkata; \"Demi Allah, seandainya mereka menyuruhku untuk memindahkan gunung dari gunung-gunung yang ada, maka hal itu tidak lebih berat bagiku dari pada (pengumpulan atau pendokumentasian al Qur'an). kenapa kalian mengerjakan sesuatu yang tidak pernah dikerjakan Rasulullah shallallahu 'alaihi wasallam?\" Abu Bakar menjawab; \"Demi Allah hal itu adalah baik.\" Aku pun terus mengulanginya, sehingga Allah melapangkan dadaku sebagaimana melapangkan dada keduanya (Abu Bakar dan Umar). Lalu aku kumpulkan al Qur'an (yang ditulis) pada kulit, pelepah kurma, dan batu putih lunak, juga dada (hafalan) para sahabat. Hingga aku mendapatkan dua ayat dari surat Taubah berada pada Khuzaimah yang tidak aku temukan pada sahabat mana pun. Yaitu ayat: Sungguh telah datang kepadamu seorang Rasul dari kaummu sendiri, berat terasa olehnya penderitaanmu, sangat menginginkan (keimanan dan keselamatan) bagimu, amat belas kasihan lagi penyayang terhadap orang-orang mukmin. Jika mereka berpaling (dari keimanan), maka katakanlah: \"Cukuplah Allah bagiku; tidak ada Tuhan selain Dia. Hanya kepada-Nya aku bertawakkal dan Dia adalah Tuhan yang memiliki 'Arsy yang agung.\" (9: 128-129). Dan mushaf yang telah aku kumpulkan itu berada pada Abu Bakr hingga dia wafat, kemudian berada pada Umar hingga dia wafat, setelah itu berada pada Hafshah putri Umar. Diriwiyatkan pula oleh ['Utsman bin 'Umar] dan [Al Laits] dari [Yunus] dari [Ibnu Syihab]; Al Laits berkata; Telah menceritakan kepadaku ['Abdur Rahman bin Khalid] dari [Ibnu Syihab]; dia berkata; ada pada Abu Huzaimah Al Anshari. Sedang [Musa] berkata; Dari [Ibrahim] Telah menceritakan kepada kami [Ibnu Syihab]; 'Ada pada Abu Khuzaimah.' Juga diriwayatkan oleh [Ya'qub bin Ibrahim] dari [Bapaknya]. [Abu Tsabit] berkata; Telah menceritakan kepada kami [Ibrahim] dia berkata; 'Ada pada Khuzaimah atau Abu Khuzaimah."},"4007":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَالْيَهُودُ تَصُومُ عَاشُورَاءَ فَقَالُوا هَذَا يَوْمٌ ظَهَرَ فِيهِ مُوسَى عَلَى فِرْعَوْنَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ أَنْتُمْ أَحَقُّ بِمُوسَى مِنْهُمْ فَصُومُوا","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tiba di Madinah, beliau melihat kaum Yahudi berpuasa pada hari Asyura`, mereka berkata; \"Lebih tepatnya pada hari Musa mengalahkan Fir'aun. Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Kalian lebih berhak terhadap Musa daripada mereka, maka berpuasalah.\""},"4008":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدِ بْنِ صَبَّاحٍ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبَّادِ بْنِ جَعْفَرٍ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍيَقْرَأُ أَلَا إِنَّهُمْ تَثْنَوْنِي صُدُورُهُمْ قَالَ سَأَلْتُهُ عَنْهَا فَقَالَ أُنَاسٌ كَانُوا يَسْتَحْيُونَ أَنْ يَتَخَلَّوْا فَيُفْضُوا إِلَى السَّمَاءِ وَأَنْ يُجَامِعُوا نِسَاءَهُمْ فَيُفْضُوا إِلَى السَّمَاءِ فَنَزَلَ ذَلِكَ فِيهِمْ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad bin Shabbah] Telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; Telah mengabarkan kepadaku [Muhammad bin 'Abbad bin Ja'far] bahwasanya aku mendengar [Ibnu Abbas] membaca; 'Ketahuilah, sesungguhnya mereka memalingkan dada mereka (QS. Hud; 5).' Ibnu Ja'far berkata; Aku bertanya kepadanya mengenai ayat tersebut. Maka Ibnu Abbas menjawab; beberapa dari kalangan orang-orang munafik merasa malu ketika membuang hajat mereka dalam keadaan telanjang dan ketika mereka bersetubuh dengan istri-istri mereka. Maka ayat ini turun kepada mereka."},"4009":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ وَأَخْبَرَنِي مُحَمَّدُ بْنُ عَبَّادِ بْنِ جَعْفَرٍ أَنَّ ابْنَ عَبَّاسٍقَرَأَ أَلَا إِنَّهُمْ تَثْنَوْنِي صُدُورُهُمْ قُلْتُ يَا أَبَا الْعَبَّاسِ مَا تَثْنَوْنِي صُدُورُهُمْ قَالَ كَانَ الرَّجُلُ يُجَامِعُ امْرَأَتَهُ فَيَسْتَحِي أَوْ يَتَخَلَّى فَيَسْتَحِي فَنَزَلَتْ أَلَا إِنَّهُمْ تَثْنَوْنِي صُدُورُهُمْ","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam] dari [Ibnu Juraij] Dan telah mengabarkan kepadaku [Muhammad bin 'Abbad bin Ja'far] bahwa [Ibnu 'Abbas] membaca; 'Ketahuilah, sesungguhnya mereka memalingkan dada mereka dariku.'Ibnu Ja'far berkata; Aku bertanya kepadanya; 'Wahai Ibnu Abbas, apa yang dimaksud dengan ayat itu? Maka Ibnu Abbas menjawab; seseorang merasa malu ketika hendak bersetubuh dengan istrinya dan ketika membuang hajat dalam keadaan telanjang. Maka turunlah ayat ini."},"4010":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو قَالَ قَرَأَ ابْنُ عَبَّاسٍ{ أَلَا إِنَّهُمْ يَثْنُونَ صُدُورَهُمْ لِيَسْتَخْفُوا مِنْهُ أَلَا حِينَ يَسْتَغْشُونَ ثِيَابَهُمْ }و قَالَ غَيْرُهُ عَنْ ابْنِ عَبَّاسٍ{ يَسْتَغْشُونَ }يُغَطُّونَ رُءُوسَهُمْ{ سِيءَ بِهِمْ }سَاءَ ظَنُّهُ بِقَوْمِهِ{ وَضَاقَ بِهِمْ }بِأَضْيَافِهِ{ بِقِطْعٍ مِنْ اللَّيْلِ }بِسَوَادٍ وَقَالَ مُجَاهِدٌ{ إِلَيْهِ أُنِيبُ }أَرْجِعُ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami ['Amru] dia berkata; [Ibnu 'Abbas] membaca ayat: Ingatlah, sesungguhnya (orang munafik itu) memalingkan dada mereka untuk menyembunyikan diri daripadanya (Muhammad), Ingatlah, di waktu mereka menyelimuti dirinya dengan kain.. (Huud: 5). Yang lainnya berkata; dari Ibnu Abbas arti Yastagsyuuna adalah; menutup kepala mereka. Arti sii`a bihim (Huud: 77 adalah berperangsangka buruk kepada kaumnya. Dan dlaaqa bihim yaitu terhadap para tamu mereka. Sedangkan arti Qitha'i manal lail yaitu kegelapan. Mujahid berkata; arti ilaihi Unib yaitu saya kembali."},"4011":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ أَنْفِقْ أُنْفِقْ عَلَيْكَ وَقَالَ يَدُ اللَّهِ مَلْأَى لَا تَغِيضُهَا نَفَقَةٌ سَحَّاءُ اللَّيْلَ وَالنَّهَارَ وَقَالَ أَرَأَيْتُمْ مَا أَنْفَقَ مُنْذُ خَلَقَ السَّمَاءَ وَالْأَرْضَ فَإِنَّهُ لَمْ يَغِضْ مَا فِي يَدِهِ وَكَانَ عَرْشُهُ عَلَى الْمَاءِ وَبِيَدِهِ الْمِيزَانُ يَخْفِضُ وَيَرْفَعُ{ اعْتَرَاكَ }افْتَعَلَكَ مِنْ عَرَوْتُهُ أَيْ أَصَبْتُهُ وَمِنْهُ يَعْرُوهُ وَاعْتَرَانِي{ آخِذٌ بِنَاصِيَتِهَا }أَيْ فِي مِلْكِهِ وَسُلْطَانِهِ عَنِيدٌ وَعَنُودٌ وَعَانِدٌ وَاحِدٌ هُوَ تَأْكِيدُ التَّجَبُّرِ{ اسْتَعْمَرَكُمْ }جَعَلَكُمْ عُمَّارًا أَعْمَرْتُهُ الدَّارَ فَهِيَ عُمْرَى جَعَلْتُهَا لَهُ{ نَكِرَهُمْ }وَأَنْكَرَهُمْ وَاسْتَنْكَرَهُمْ وَاحِدٌ{ حَمِيدٌ مَجِيدٌ }كَأَنَّهُ فَعِيلٌ مِنْ مَاجِدٍ مَحْمُودٌ مِنْ حَمِدَ سِجِّيلٌ الشَّدِيدُ الْكَبِيرُ سِجِّيلٌ وَسِجِّينٌ وَاللَّامُ وَالنُّونُ أُخْتَانِ وَقَالَ تَمِيمُ بْنُ مُقْبِلٍ وَرَجْلَةٍ يَضْرِبُونَ الْبَيْضَ ضَاحِيَةًضَرْبًا تَوَاصَى بِهِ الْأَبْطَالُ سِجِّينَا","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza wa Jalla berfirman: 'Berinfaklah, maka aku akan berinfak kepadamu.' Dan Nabi shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya tangan Allah terisi penuh, pemberian-Nya siang maupun malam tidak pernah menguranginya.\" Juga beliau bersabda: \"Tidakkah kalian melihat bagaimana Allah telah memberikan nafkah (rezeki) semenjak Dia mencipta langit dan bumi. Sesungguhnya Allah tidak pernah berkurang apa yang ada pada tangan kanan-Nya.\" Beliau bersabda: \"Dan 'Arsy-Nya ada di atas air, di tangan-Nya yang lain terdapat neraca, Dia merendahkan dan meninggikan.\""},"4012":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ وَهِشَامٌ قَالَا حَدَّثَنَا قَتَادَةُ عَنْ صَفْوَانَ بْنِ مُحْرِزٍ قَالَ بَيْنَا ابْنُ عُمَرَ يَطُوفُ إِذْ عَرَضَ رَجُلٌ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ أَوْ قَالَ يَا ابْنَ عُمَرَ سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّجْوَى فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُدْنَى الْمُؤْمِنُ مِنْ رَبِّهِ وَقَالَ هِشَامٌيَدْنُو الْمُؤْمِنُ حَتَّى يَضَعَ عَلَيْهِ كَنَفَهُ فَيُقَرِّرُهُ بِذُنُوبِهِ تَعْرِفُ ذَنْبَ كَذَا يَقُولُ أَعْرِفُ يَقُولُ رَبِّ أَعْرِفُ مَرَّتَيْنِ فَيَقُولُ سَتَرْتُهَا فِي الدُّنْيَا وَأَغْفِرُهَا لَكَ الْيَوْمَ ثُمَّ تُطْوَى صَحِيفَةُ حَسَنَاتِهِ وَأَمَّا الْآخَرُونَ أَوْ الْكُفَّارُ فَيُنَادَى عَلَى رُءُوسِ الْأَشْهَادِ{ هَؤُلَاءِ الَّذِينَ كَذَبُوا عَلَى رَبِّهِمْ أَلَا لَعْنَةُ اللَّهِ عَلَى الظَّالِمِينَ }وَقَالَ شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا صَفْوَانُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yazid bin Zura'i] Telah menceritakan kepada kami [Sa'id] dan [Hisyam] keduanya berkata; Telah menceritakan kepada kami [Qatadah] dari [Shafwan bin Muhriz] dia berkata; ketika Ibnu 'Umar sedang thawaf, tiba-tiba seseorang menghadangnya seraya berkata; wahai Abu 'Abdur Rahman, atau wahai Ibnu 'Umar apa kamu mendengar dari Nabi shallallahu 'alaihi wasallam mengenai An-Najwa (bisikan dihari kiamat)? [Ibnu Umar] menjawab: \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: Nanti di hari kiamat, seorang mukmin mendekat kepada Rabb-nya. Hisyam berkata; 'Seorang mukmin mendekat hingga Dia meletakkan naungan-Nya ke atasnya, yaitu menutupi (dosa-dosa) -nya kemudian Dia berkata, \"Apakah kamu mengakui dosa ini?\" dia menjawab, \"Wahai Rabb-ku, saya mengetahuinya.\" -sebanyak dua kali- Allah berfirman kepadanya: \"Saya telah menutupinya (merahasiakannya) di dunia dan pada hari ini aku telah mengampuninya bagimu.\" Kemudian diberikanlah kepadanya catatan kebaikan-kebaikannya. Adapun yang lainnya atau orang-orang kafir, maka mereka dipanggil dihadapan semua manusia dan dikatakan: \"Inilah mereka yang telah mendustakan Rabb mereka, ketahuilah bahwa laknat Allah berlaku atas orang-orang yang zalim.\" (Hud: 18). Dan [Syaiban] berkata; Dari [Qatadah] Telah menceritakan kepada kami [Shafwan]."},"4013":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا بُرَيْدُ بْنُ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَيُمْلِي لِلظَّالِمِ حَتَّى إِذَا أَخَذَهُ لَمْ يُفْلِتْهُ قَالَ ثُمَّ قَرَأَ{ وَكَذَلِكَ أَخْذُ رَبِّكَ إِذَا أَخَذَ الْقُرَى وَهِيَ ظَالِمَةٌ إِنَّ أَخْذَهُ أَلِيمٌ شَدِيدٌ }","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] Telah mengabarkan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Buraid bin Abu Burdah] dari [Abu Burdah] dari [Abu Musa radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Subhanahu wa Ta 'ala akan menangguhkan siksaan bagi orang yang berbuat zhalim. Dan apabila Allah telah menghukumnya, maka Dia tidak akan pernah melepaskannya.\" Kemudian Rasulullah membaca ayat yang berbunyi: 'Begitulah adzab Tuhanmu, apabila Dia mengadzab penduduk negeri-negeri yang berbuat zhalim. Sesungguhnya adzab-Nya itu sangat pedih dan keras.' (Qs. Huud (11): 102)."},"4014":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ هُوَ ابْنُ زُرَيْعٍ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَصَابَ مِنْ امْرَأَةٍ قُبْلَةً فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَأُنْزِلَتْ عَلَيْهِ{ وَأَقِمْ الصَّلَاةَ طَرَفَيْ النَّهَارِ وَزُلَفًا مِنْ اللَّيْلِ إِنَّ الْحَسَنَاتِ يُذْهِبْنَ السَّيِّئَاتِ ذَلِكَ ذِكْرَى لِلذَّاكِرِينَ }قَالَ الرَّجُلُ أَلِيَ هَذِهِ قَالَ لِمَنْ عَمِلَ بِهَا مِنْ أُمَّتِي","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yazid] yaitu Ibnu Zura'i Telah menceritakan kepada kami [Sulaiman At Tamimi] dari [Abu 'Utsman] dari [Ibnu Mas'ud radliallahu 'anhu] bahwasanya seorang lelaki pernah mencium seorang wanita, lalu dia menemui Nabi shallallahu 'alaihi wasallam dan mengabarkannya kepada Nabi shallallahu 'alaihi wasallam. Maka turunlah ayat: \"Dan dirikanlah shalat itu pada kedua tepi siang (pagi dan petang) dan pada bagian permulaan daripada malam. Sesungguhnya perbuatan-perbuatan yang baik itu menghapuskan (dosa) perbuatan-perbuatan yang buruk. Itulah peringatan bagi orang-orang yang ingat.\" (QS Hud; 114). Abdullah berkata; laki-laki itu bertanya; \"Wahai Rasulullah, apakah ayat ini hanya khusus untukku?\" Beliau menjawab: \"Ayat tersebut adalah untuk orang-orang yang melakukannya dari ummatku.\""},"4015":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الصَّمَدِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَرِيمُ ابْنُ الْكَرِيمِ ابْنِ الْكَرِيمِ ابْنِ الْكَرِيمِ يُوسُفُ بْنُ يَعْقُوبَ بْنِ إِسْحَاقَ بْنِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami ['Abdush Shamad] dari ['Abdur Rahman bin 'Abdullah bin Dinar] dari [Bapaknya] dari ['Abdullah bin 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Orang mulia, putra orang mulia, putra orang mulia, putra orang mulia, adalah Yusuf bin Ya'qub bin Ishaq bin Ibrahim.\""},"4016":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ النَّاسِ أَكْرَمُ قَالَ أَكْرَمُهُمْ عِنْدَ اللَّهِ أَتْقَاهُمْ قَالُوا لَيْسَ عَنْ هَذَا نَسْأَلُكَ قَالَ فَأَكْرَمُ النَّاسِ يُوسُفُ نَبِيُّ اللَّهِ ابْنُ نَبِيِّ اللَّهِ ابْنِ نَبِيِّ اللَّهِ ابْنِ خَلِيلِ اللَّهِ قَالُوا لَيْسَ عَنْ هَذَا نَسْأَلُكَ قَالَ فَعَنْ مَعَادِنِ الْعَرَبِ تَسْأَلُونِي قَالُوا نَعَمْ قَالَ فَخِيَارُكُمْ فِي الْجَاهِلِيَّةِ خِيَارُكُمْ فِي الْإِسْلَامِ إِذَا فَقِهُواتَابَعَهُ أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ","id":"Telah menceritakan kepadaku [Muhammad] Telah mengabarkan kepada kami ['Abdah] dari ['Ubaidillah] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya; \"Siapakah menusia yang paling mulia?\" Beliau bersabda: \"Orang yang paling bertaqwa dari mereka.\" para sahabat berkata; \"Bukan itu yang kami tanyakan?\" beliau bersabda: \"Jika bukan, berarti Yusuf Nabi Allah putra Nabi Allah (Ya'qub) putra Nabi Allah (Ishaq) putra Ibrahim kekasih Allah, \" para sahabat berkata; \"Bukan itu yang kami tanyakan, \" beliau bersabda: \"Apakah tentang bangsa Arab yang kalian tanyakan?, mereka menjawab; 'Ya.' Rasulullah shallallahu 'alaihi wasallam bersabda: orang yang paling baik dari mereka dimasa jahiliyyah adalah orang yang paling baik dimasa Islam, jika mereka paham Islam.\" Demikian juga diriwayatkan oleh [Abu Usamah] dari [Ubaidullah]."},"4017":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ ح و حَدَّثَنَا الْحَجَّاجُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ النُّمَيْرِيُّ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ الْأَيْلِيُّ قَالَ سَمِعْتُ الزُّهْرِيَّ سَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ وَسَعِيدَ بْنَ الْمُسَيَّبِ وَعَلْقَمَةَ بْنَ وَقَّاصٍ وَعُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ عَنْ حَدِيثِ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَبَرَّأَهَا اللَّهُ كُلٌّ حَدَّثَنِي طَائِفَةً مِنْ الْحَدِيثِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كُنْتِ بَرِيئَةً فَسَيُبَرِّئُكِ اللَّهُ وَإِنْ كُنْتِ أَلْمَمْتِ بِذَنْبٍ فَاسْتَغْفِرِي اللَّهَ وَتُوبِي إِلَيْهِ قُلْتُ إِنِّي وَاللَّهِ لَا أَجِدُ مَثَلًا إِلَّا أَبَا يُوسُفَ{ فَصَبْرٌ جَمِيلٌ وَاللَّهُ الْمُسْتَعَانُ عَلَى مَا تَصِفُونَ }وَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ جَاءُوا بِالْإِفْكِ عُصْبَةٌ مِنْكُمْ }الْعَشْرَ الْآيَاتِ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] dia berkata; Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepada kami [Al Hajjaj]; Telah menceritakan kepada kami ['Abdullah bin 'Umar An Numair]; Telah menceritakan kepada kami [Yunus bin Zaid Al Aili] dia berkata; Aku mendengar [Az Zuhri], aku mendengar ['Urwah bin Az Zubair] dan [Sa'id bin Al Musayyab] dan ['Alqamah bin Waqqash] dan ['Ubaidillah bin Abdullah] dari cerita ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam tatkala orang yang memfitnahnya berkata kepadanya dengan semua isu (ghosip) yang mereka sebarluaskan. Lalu Allah menjelaskan akan terbebasnya dirinya dari tuduhan tersebut. Setiap orang menceritakan sebagian dari berita ghosip tersebut. Nabi shallallahu 'alaihi wasallam berkata kepada Aisyah: \"Jika kamu tidak melakukannya, maka Allah akan membebaskan kamu dari tuduhan tersebut, tapi jika kamu melakukan dosa, maka meminta ampunlah kepada Allah dan bertaubatlah. Aisyah berkata; 'Demi Allah, aku tidak mendapatkan perumpamaan ini selain sebagaimana Abu Yusuf (Ya'qub) ketika berkata; maka lakukanlah kesabaran yang baik, itulah (kesabaranku). Dan Allah sajalah yang dimohon pertolongan-Nya terhadap apa yang kamu ceritakan.\" (Yusuf: 18). Kemudian Allah menurunkan ayat: Sesungguhnya orang-orang yang membawa berita bohong itu adalah dari golongan kamu juga. (An Nuur: 11). -hingga sepuluh ayat.-"},"4018":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ حُصَيْنٍ عَنْ أَبِي وَائِلٍ قَالَ حَدَّثَنِي مَسْرُوقُ بْنُ الْأَجْدَعِ قَالَ حَدَّثَتْنِي أُمُّ رُومَانَ وَهْيَ أُمُّ عَائِشَةَ قَالَتْبَيْنَا أَنَا وَعَائِشَةُ أَخَذَتْهَا الْحُمَّى فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّ فِي حَدِيثٍ تُحُدِّثَ قَالَتْ نَعَمْ وَقَعَدَتْ عَائِشَةُ قَالَتْ مَثَلِي وَمَثَلُكُمْ كَيَعْقُوبَ وَبَنِيهِ{ بَلْ سَوَّلَتْ لَكُمْ أَنْفُسُكُمْ أَمْرًا فَصَبْرٌ جَمِيلٌ وَاللَّهُ الْمُسْتَعَانُ عَلَى مَا تَصِفُونَ }","id":"Telah menceritakan kepada kami [Musa] Telah menceritakan kepada kami [Abu 'Awanah] dari [Hushain] dari [Abu Wail] dia berkata; Telah menceritakan kepadaku [Masruq bin Al Ajda'] dia berkata; Telah menceritakan kepadaku [Ummu Rumman] yaitu Ummu 'Aisyah dia berkata; ketika kami bersama Aisyah yang sedang menderita demam, Nabi shallallahu 'alaihi wasallam berkata; semoga ada wahyu yang mengabarkan tentang Aisyah. Ummu Ruman berkata; 'Ya.' Lalu Aisyah duduk seraya berkata; perumpamaanku dengan kalian adalah seperti perkataannya Ya'qub kepada putra-putranya: \"Sebenarnya dirimu sendirilah yang memandang baik perbuatan (yang buruk) itu; maka kesabaran yang baik itulah (kesabaranku). Dan Allah sajalah yang dimohon pertolongan-Nya terhadap apa yang kamu ceritakan.\" (Yusuf: 18)."},"4019":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ سَعِيدٍ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ{ هَيْتَ لَكَ }قَالَ وَإِنَّمَا نَقْرَؤُهَا كَمَا عُلِّمْنَاهَا{ مَثْوَاهُ }مُقَامُهُ{ وَأَلْفَيَا }وَجَدَا{ أَلْفَوْا آبَاءَهُمْ }{ أَلْفَيْنَا }وَعَنْ ابْنِ مَسْعُودٍ{ بَلْ عَجِبْتُ وَيَسْخَرُونَ }","id":"Telah menceritakan kepadaku [Ahmad bin Sa'id] Telah menceritakan kepada kami [Bisyr bin 'Umar] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Wail] dari ['Abdullah bin Mas'ud] dia berkata; mengenai firman Allah: \"Marilah ke sini, (Yusuf: 23).\" Ibnu Mas'ud berkata; Kami membacanya sesuai dengan yang telah diajarkan kepada kami. Arti Matswaahu: tempat tinggalnya. Arti Al Fayaa: keduanya mendapatkan. Sebagaimana perkataan Al Fau Aabaa`ahum: yakni mereka mendapatkan. Demikian juga dari Ibnu Mas'ud mengenai firman Allah: Bahkan aku menjadi heran (terhadap keingkaran mereka) dan mereka menghinakan kamu. (As Shafaat: 12)."},"4020":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ قُرَيْشًا لَمَّا أَبْطَئُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْإِسْلَامِ قَالَ اللَّهُمَّ اكْفِنِيهِمْ بِسَبْعٍ كَسَبْعِ يُوسُفَ فَأَصَابَتْهُمْ سَنَةٌ حَصَّتْ كُلَّ شَيْءٍ حَتَّى أَكَلُوا الْعِظَامَ حَتَّى جَعَلَ الرَّجُلُ يَنْظُرُ إِلَى السَّمَاءِ فَيَرَى بَيْنَهُ وَبَيْنَهَا مِثْلَ الدُّخَانِ قَالَ اللَّهُ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ }قَالَ اللَّهُ{ إِنَّا كَاشِفُو الْعَذَابِ قَلِيلًا إِنَّكُمْ عَائِدُونَ }أَفَيُكْشَفُ عَنْهُمْ الْعَذَابُ يَوْمَ الْقِيَامَةِ وَقَدْ مَضَى الدُّخَانُ وَمَضَتْ الْبَطْشَةُ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Muslim] dari [Masruq] dari ['Abdullah radliallahu 'anhu] bahwa ketika orang-orang Quraisy menangguhkan untuk memeluk Islam, maka Nabi shallallahu 'alaihi wasallam mendo'akan kebinasaan bagi mereka: \"Ya Allah, tolonglah kami dalam menghadapi mereka dengan mengirimkan tujuh tahun (kelaparan) sebagaimana yang telah menimpa Yusuf. Maka kemudian mereka tertimpa tahun paceklik yang menghabiskan segala sesuatu hingga diantara mereka memakan tulang. Dan seseorang dari mereka ketika melihat ke langit, ia melihat antara dia dan langit seakan-akan terhalangi oleh asap (karena rasa lapar). Allah berfirman: Maka tunggulah hari ketika langit membawa kabut yang nyata. (QS.Ad Dukhan: 10). Allah juga berfirman: Sesungguhnya (kalau) Kami akan melenyapkan siksaan itu agak sedikit sesungguhnya kamu akan kembali ingkar, (QS.Ad Dukhan: 15). Maka bagaimana adzab akan dihentikan pada hari kiamat, padahal telah berlalu bagi mereka kabut dan hantaman keras?."},"4021":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ تَلِيدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ بَكْرِ بْنِ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُ اللَّهُ لُوطًا لَقَدْ كَانَ يَأْوِي إِلَى رُكْنٍ شَدِيدٍ وَلَوْ لَبِثْتُ فِي السِّجْنِ مَا لَبِثَ يُوسُفُ لَأَجَبْتُ الدَّاعِيَ وَنَحْنُ أَحَقُّ مِنْ إِبْرَاهِيمَ إِذْ قَالَ لَهُ{ أَوَلَمْ تُؤْمِنْ قَالَ بَلَى وَلَكِنْ لِيَطْمَئِنَّ قَلْبِي }","id":"Telah menceritakan kepada kami [Sa'id bin Talid] Telah menceritakan kepada kami ['Abdur Rahman bin Al Qasim] dari [Bakr bin Mudlar] dari ['Amru bin Al Harits] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdur Rahman] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Rahmat Allah semoga terlimpah kepada Luth sungguh ia telah berlindung kepada keluarga yang kuat. Sekiranya aku masuk penjara dan mendekam selama mendekamnya Yusuf, tentu aku akan menuruti ajakan penggoda. Dan kita lebih berhak untuk meminta kemantapan dari pada Ibrahim 'Alaihis Salam ketika Allah berfirman kepadanya: \"Apakah kamu tidak beriman?\" Ibrahim berkata; \"Tentu aku sebenarnya telah beriman, akan tetapi agar hatiku lebih mantap. (QS.Al Baqarah: 260)."},"4022":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاقَالَتْ لَهُ وَهُوَ يَسْأَلُهَا عَنْ قَوْلِ اللَّهِ تَعَالَى{ حَتَّى إِذَا اسْتَيْأَسَ الرُّسُلُ }قَالَ قُلْتُ أَكُذِبُوا أَمْ كُذِّبُوا قَالَتْ عَائِشَةُ كُذِّبُوا قُلْتُ فَقَدْ اسْتَيْقَنُوا أَنَّ قَوْمَهُمْ كَذَّبُوهُمْ فَمَا هُوَ بِالظَّنِّ قَالَتْ أَجَلْ لَعَمْرِي لَقَدْ اسْتَيْقَنُوا بِذَلِكَ فَقُلْتُ لَهَا وَظَنُّوا أَنَّهُمْ قَدْ كُذِبُوا قَالَتْ مَعَاذَ اللَّهِ لَمْ تَكُنْ الرُّسُلُ تَظُنُّ ذَلِكَ بِرَبِّهَا قُلْتُ فَمَا هَذِهِ الْآيَةُ قَالَتْ هُمْ أَتْبَاعُ الرُّسُلِ الَّذِينَ آمَنُوا بِرَبِّهِمْ وَصَدَّقُوهُمْ فَطَالَ عَلَيْهِمْ الْبَلَاءُ وَاسْتَأْخَرَ عَنْهُمْ النَّصْرُ حَتَّى إِذَا اسْتَيْأَسَ الرُّسُلُ مِمَّنْ كَذَّبَهُمْ مِنْ قَوْمِهِمْ وَظَنَّتْ الرُّسُلُ أَنَّ أَتْبَاعَهُمْ قَدْ كَذَّبُوهُمْ جَاءَهُمْ نَصْرُ اللَّهِ عِنْدَ ذَلِكَحَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ فَقُلْتُ لَعَلَّهَا كُذِبُوا مُخَفَّفَةً قَالَتْ مَعَاذَ اللَّهِ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] Telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Shalih] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anhuma] dia berkata kepadanya ketika Urwah bertanya mengenai firman Allah Ta'ala: Sehingga apabila para rasul tidak mempunyai harapan lagi (tentang keimanan mereka).. maka aku bertanya; apakah mereka 'kudzibuu atau Kudzdzibuu' -dengan menggunakan tasydid-? Aisyah menjawab; 'mereka didustakan.' -dengan menggunakan tasydid-. Aku bertanya; sungguh mereka telah yakin bahwa kaumnya pasti akan mendustakannya, lalu apa yang dimaksud dengan persangkaan mereka? Aisyah menjawab; 'Ya, demi umurku, mereka telah yakin dengan hal itu, aku pun bertanya lagi; lalu kenapa mereka tidak punya harapan lagi? Aisyah berkata; Aku berlindung kepada Allah, para rasul tidak pernah menyangka demikian terhadap Rabbnya. Aku bertanya; lalu apa maksud ayat ini? Aisyah menjawab; merekalah para pengikut rasul, yang telah beriman kepada Rabb mereka dan mempercayai para rasul tersebut, namun ujian yang begitu panjang serta pertolongan tidak kunjung tiba kepada mereka. Maka maksud dari ayat; Sehingga apabila para rasul tidak mempunyai harapan lagi (tentang keimanan mereka).. dari kaumnya yang mendustakan mereka, hingga mereka menyangka bahwa para pengikutnya telah mendustakan mereka, maka ketika itu datanglah kepada mereka pertolongan Allah. Telah menceritakan kepada kami [Abu Al Yaman]; Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku ['Urwah] maka aku berkata; semoga maksudnya adalah 'Kudzibuu' (mereka di dustakan) -tanpa tasydid-. Maka [Aisyah] berkata; 'Aku berlindung kepada Allah, -dengan lafazh yang serupa.-"},"4023":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَفَاتِحُ الْغَيْبِ خَمْسٌ لَا يَعْلَمُهَا إِلَّا اللَّهُ لَا يَعْلَمُ مَا فِي غَدٍ إِلَّا اللَّهُ وَلَا يَعْلَمُ مَا تَغِيضُ الْأَرْحَامُ إِلَّا اللَّهُ وَلَا يَعْلَمُ مَتَى يَأْتِي الْمَطَرُ أَحَدٌ إِلَّا اللَّهُ وَلَا تَدْرِي نَفْسٌ بِأَيِّ أَرْضٍ تَمُوتُ وَلَا يَعْلَمُ مَتَى تَقُومُ السَّاعَةُ إِلَّا اللَّهُ","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Ma'an] dia berkata; Telah menceritakan kepadaku [Malik] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kunci perkara ghaib itu ada lima, tidak ada yang mengetahuinya kecuali Allah. Tidak ada yang tahu apa yang akan terjadi dengan hari esok kecuali Allah. Tidak ada yang tahu apa yang terjadi di dalam rahim-rahim kecuali Allah. Tidak ada yang tahu kapan datangnya hujan kecuali Allah. Tidak ada seorangpun yang tahu dimana dia akan meninggal. Dan tidak ada yang tahu kapan terjadi hari kiamat kecuali Allah.\""},"4024":{"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَخْبِرُونِي بِشَجَرَةٍ تُشْبِهُ أَوْ كَالرَّجُلِ الْمُسْلِمِ لَا يَتَحَاتُّ وَرَقُهَا وَلَا وَلَا وَلَا تُؤْتِي أُكْلَهَا كُلَّ حِينٍ قَالَ ابْنُ عُمَرَ فَوَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ وَرَأَيْتُ أَبَا بَكْرٍ وَعُمَرَ لَا يَتَكَلَّمَانِ فَكَرِهْتُ أَنْ أَتَكَلَّمَ فَلَمَّا لَمْ يَقُولُوا شَيْئًا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ النَّخْلَةُ فَلَمَّا قُمْنَا قُلْتُ لِعُمَرَ يَا أَبَتَاهُ وَاللَّهِ لَقَدْ كَانَ وَقَعَ فِي نَفْسِي أَنَّهَا النَّخْلَةُ فَقَالَ مَا مَنَعَكَ أَنْ تَكَلَّمَ قَالَ لَمْ أَرَكُمْ تَكَلَّمُونَ فَكَرِهْتُ أَنْ أَتَكَلَّمَ أَوْ أَقُولَ شَيْئًا قَالَ عُمَرُ لَأَنْ تَكُونَ قُلْتَهَا أَحَبُّ إِلَيَّ مِنْ كَذَا وَكَذَا","id":"Telah menceritakan kepadaku ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidillah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dia berkata; ketika kami bersama Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Beritahukan padaku suatu pohon yang mirip seorang muslim, daunnya tidak berguguran, dan ia tidak berbuah setiap waktu.\" Ibnu Umar berkata: Hatiku mengatakan bahwa pohon itu adalah pohon kurma. Aku melihat Abu Bakar dan Umar tidak berbicara sehingga aku tidak mau berbicara atau mengatakan apa pun. Tatkala para sahabat tidak ada yang menjawab sedikitpun, Rasulullah shallallahu 'alaihi wasallam bersabda: 'Yaitu pohon kurma.' Ketika kami sudah beranjak pergi, aku berkata kepada Umar; Wahai bapakku, dalam hatiku juga mengatakan bahwa itu adalah pohon kurma. Lalu ia berkata; Kenapa kamu tidak mengatakannya tadi? Ibnu Umar menjawab; 'Aku melihat kalian semua tidak menjawab, maka aku pun tidak mau menjawab atau mengatakan sesuatu pun. Umar berkata: 'Andai kau mengatakannya, itu lebih aku sukai dari ini dan ini.'"},"4025":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَلْقَمَةُ بْنُ مَرْثَدٍ قَالَ سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْلِمُ إِذَا سُئِلَ فِي الْقَبْرِ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَذَلِكَ قَوْلُهُ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","id":"Telah menceritakan kepada kami [Abu Al Walid] Telah menceritakan kepada kami [Syu'bah] dia berkata; Telah mengabarkan kepadaku ['Alqamah bin Martsad] dia berkata; 'Aku mendengar [Sa'ad bin 'Ubaidah] dari [Al Bara' bin 'Azib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim apabila ditanya di dalam kubur, maka akan bersaksi bahwa tidak ada Ilah yang berhak disembah kecuali Allah dan Muhammad utusan Allah. itulah firman Allah yang berbunyi: \"Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat.\" (Ibrahiim: 27)."},"4026":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ سَمِعَ ابْنَ عَبَّاسٍ{ أَلَمْ تَرَ إِلَى الَّذِينَ بَدَّلُوا نِعْمَةَ اللَّهِ كُفْرًا }قَالَ هُمْ كُفَّارُ أَهْلِ مَكَّةَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari ['Atha] dia mendengar [Ibnu 'Abbas] berkata mengenai firman Allah: Tidakkah kamu perhatikan orang-orang yang telah menukar nikmat Allah dengan kekafiran, mereka adalah orang-orang kafir Makkah."},"4027":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَضَى اللَّهُ الْأَمْرَ فِي السَّمَاءِ ضَرَبَتْ الْمَلَائِكَةُ بِأَجْنِحَتِهَا خُضْعَانًا لِقَوْلِهِ كَالسِّلْسِلَةِ عَلَى صَفْوَانٍ قَالَ عَلِيٌّ وَقَالَ غَيْرُهُ صَفْوَانٍ يَنْفُذُهُمْ ذَلِكَ فَإِذَا{ فُزِّعَ عَنْ قُلُوبِهِمْ قَالُوا مَاذَا قَالَ رَبُّكُمْ قَالُوا }لِلَّذِي قَالَ{ الْحَقَّ وَهُوَ الْعَلِيُّ الْكَبِيرُ }فَيَسْمَعُهَا مُسْتَرِقُو السَّمْعِ وَمُسْتَرِقُو السَّمْعِ هَكَذَا وَاحِدٌ فَوْقَ آخَرَ وَوَصَفَ سُفْيَانُ بِيَدِهِ وَفَرَّجَ بَيْنَ أَصَابِعِ يَدِهِ الْيُمْنَى نَصَبَهَا بَعْضَهَا فَوْقَ بَعْضٍ فَرُبَّمَا أَدْرَكَ الشِّهَابُ الْمُسْتَمِعَ قَبْلَ أَنْ يَرْمِيَ بِهَا إِلَى صَاحِبِهِ فَيُحْرِقَهُ وَرُبَّمَا لَمْ يُدْرِكْهُ حَتَّى يَرْمِيَ بِهَا إِلَى الَّذِي يَلِيهِ إِلَى الَّذِي هُوَ أَسْفَلَ مِنْهُ حَتَّى يُلْقُوهَا إِلَى الْأَرْضِ وَرُبَّمَا قَالَ سُفْيَانُ حَتَّى تَنْتَهِيَ إِلَى الْأَرْضِ فَتُلْقَى عَلَى فَمْ السَّاحِرِ فَيَكْذِبُ مَعَهَا مِائَةَ كَذْبَةٍ فَيُصَدَّقُ فَيَقُولُونَ أَلَمْ يُخْبِرْنَا يَوْمَ كَذَا وَكَذَا يَكُونُ كَذَا وَكَذَا فَوَجَدْنَاهُ حَقًّا لِلْكَلِمَةِ الَّتِي سُمِعَتْ مِنْ السَّمَاءِحَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ إِذَا قَضَى اللَّهُ الْأَمْرَ وَزَادَ وَالْكَاهِنِ و حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ فَقَالَ قَالَ عَمْرٌو سَمِعْتُ عِكْرِمَةَ حَدَّثَنَا أَبُو هُرَيْرَةَ قَالَ إِذَا قَضَى اللَّهُ الْأَمْرَ وَقَالَ عَلَى فَمْ السَّاحِرِ قُلْتُ لِسُفْيَانَ آنْتَ سَمِعْتَ عَمْرًا قَالَ سَمِعْتُ عِكْرِمَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَ نَعَمْ قُلْتُ لِسُفْيَانَ إِنَّ إِنْسَانًا رَوَى عَنْكَ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ وَيَرْفَعُهُ أَنَّهُ قَرَأَ فُرِّغَ قَالَ سُفْيَانُ هَكَذَا قَرَأَ عَمْرٌو فَلَا أَدْرِي سَمِعَهُ هَكَذَا أَمْ لَا قَالَ سُفْيَانُ وَهِيَ قِرَاءَتُنَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdillah] Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari ['Ikrimah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila Allah menetapkan satu perkara di atas langit maka para malaikat mengepakkan sayap-sayap mereka karena tunduk kepada firman-Nya, seakan-akan rantai yang berada di atas batu besar. Ali dan yang lainya berkata; hal itu sebagaimana firman Allah: \"Apabila hati mereka telah menjadi stabil, mereka berkata; 'Apa yang difirmankan Rabb kita? ' mereka menjawab; 'Al Haq, dan Dia Maha Tinggi lagi Maha Besar.' Dan para pencuri berita langit (jin) mendengarkannya, (mereka bersusun) sebagian di atas sebagian yang lainnya. -Sufyan seraya memberikan isyarat dengan telunjuknya.- Para pencuri berita langit itu mencuri dengar kalimat lalu menyampaikannya kepada yang berada di bawahnya. Bisa jadi jin itu diterjang bintang sebelum menyampaikannya kepada yang di bawahnya hingga ia terbakar, kemudian mereka menyampaikanya kepada lisan dukun atau tukang sihir. Bisa jadi mereka tidak diterjang oleh bintang sehingga dapat menyampaikannya, kemudian dicampur dengan seratus kebohongan. Maka kalimat yang didengar bisa sesuai (cocok) dengan yang dari langit.\" Telah menceritakan kepada kami 'Ali bin 'Abdillah Telah menceritakan kepada kami Sufyan Telah menceritakan kepada kami 'Amru dari 'Ikrimah dari Abu Hurairah dia berkata; Apabila Allah memutuskan suatu perkara, -dan dia berkata dengan lafazh; 'kepada mulut tukang sihir.' Aku bertanya kepada Sufyan, Apakah kamu mendengar Amru berkata; Aku mendengar Ikrimah dia berkata; Aku mendengar Abu Hurairah? Sufyan berkata; 'Ya.' Aku bertanya lagi kepada Sufyan Sesungguhnya orang-orang meriwayatkan dari kamu dari Amru dari Abu Hurairah secara marfu' bahwa ia berkata dengan lafazh; 'Furrigha' (bila telah selesai). Sufyan berkata; begitulah Amru membacanya, maka aku tidak tahu apakah dia mendengar Abu Hurairah membaca demikan atau tidak, dan itu menjadi bacaan kami."},"4028":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَصْحَابِ الْحِجْرِ لَا تَدْخُلُوا عَلَى هَؤُلَاءِ الْقَوْمِ إِلَّا أَنْ تَكُونُوا بَاكِينَ فَإِنْ لَمْ تَكُونُوا بَاكِينَ فَلَا تَدْخُلُوا عَلَيْهِمْ أَنْ يُصِيبَكُمْ مِثْلُ مَا أَصَابَهُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Ma'an] dia berkata; Telah menceritakan kepadaku [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada para sahabat beliau yang tengah melintasi hijr (tempat kaum Tsamud, pent.): \"Jangan kalian memasuki kepada mereka yaitu kaum yang disiksa kecuali kalian menangis, bila kalian tidak menangis, jangan memasuki mereka, karena dikhawatirkan kalian akan tertimpa seperti yang menimpa mereka.\""},"4029":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى قَالَمَرَّ بِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أُصَلِّي فَدَعَانِي فَلَمْ آتِهِ حَتَّى صَلَّيْتُ ثُمَّ أَتَيْتُ فَقَالَ مَا مَنَعَكَ أَنْ تَأْتِيَنِي فَقُلْتُ كُنْتُ أُصَلِّي فَقَالَ أَلَمْ يَقُلْ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْ }ثُمَّ قَالَ أَلَا أُعَلِّمُكَ أَعْظَمَ سُورَةٍ فِي الْقُرْآنِ قَبْلَ أَنْ أَخْرُجَ مِنْ الْمَسْجِدِ فَذَهَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَخْرُجَ مِنْ الْمَسْجِدِ فَذَكَّرْتُهُ فَقَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ هِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُهُ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin 'Abdur Rahman] dari [Hafsh bin 'Ashim] dari [Abu Sa'id bin Al Mu'alla] dia berkata; ketika saya sedang shalat, Rasulullah Shallallahu'alaihiwasallam lewat, lalu beliau memanggilku namun saya tidak mendatanginya sehingga shalat saya selesai. Kemudian aku menemuinya. Beliau bertanya: Apa yang mengahalangimu untuk datang kepadaku? Abu Sa'id menjawab; saya sedang shalat. Beliau bersabda: \"Bukankah Allah Tabaraka Wa Ta'ala telah berfirman: \"Hai orang-orang yang beriman, penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu kepada suatu yang memberi kehidupan kepada kamu.\" (Al Anfal: 24). Lalu beliau bersabda: \"Maukah saya ajarkan surat yang paling agung dalam alqur'an sebelum saya keluar dari masjid ini?. Abu Sa'id bin Al Mu'alla berkata; ketika Rasulullah Shallallahu'alaihi wa sallam hendak pergi, saya mengingatkan beliau, lalu beliau bersabda: \"Segala puji bagi Allah rabb semesta alam.\" (Al Fatihah: 2), itu adalah termasuk Assabu' Al Matsani (tujuh ayat yang terulang-ulang) dan Al quran yang agung yang diberikan kepadaku."},"4030":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمُّ الْقُرْآنِ هِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Ibnu Abu Dzi'b] Telah menceritakan kepada kami [Sa'id Al Maqburi] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ummul Qur'an (Al Fatihah) adalah Assab'u Al Matsaani dan Al Qur'an yang agung.\""},"4031":{"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ الَّذِينَ جَعَلُوا الْقُرْآنَ عِضِينَ }قَالَ هُمْ أَهْلُ الْكِتَابِ جَزَّءُوهُ أَجْزَاءً فَآمَنُوا بِبَعْضِهِ وَكَفَرُوا بِبَعْضِهِ","id":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah: \"yaitu orang-orang yang telah menjadikan Al Quran itu terbagi-bagi.\" (Al Hijr: 91). Ibnu Abbas berkata; Mereka adalah ahlu kitab, mereka telah membagi Al Qur'an menjadi beberapa bagian, kemudian mereka beriman dengan sebagiannya dan kafir dengan sebagian yang lain.\""},"4032":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ الْأَعْمَشِ عَنْ أَبِي ظَبْيَانَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ كَمَا أَنْزَلْنَا عَلَى الْمُقْتَسِمِينَ }قَالَ آمَنُوا بِبَعْضٍ وَكَفَرُوا بِبَعْضٍ الْيَهُودُ وَالنَّصَارَى","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Al A'masy] dari [Abu Zhabyan] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah: Sebagaimana Kami telah menurunkan (azab) kepada orang-orang yang membagi-bagi Kitab Allah. (Al Hijr: 90). Ibnu Abbas berkata; \"Mereka beriman dengan sebagiannya dan kafir dengan sebagian yang lain, mereka adalah Yahudi dan Nashrani.\"34"},"4033":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَارُونُ بْنُ مُوسَى أَبُو عَبْدِ اللَّهِ الْأَعْوَرُ عَنْ شُعَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو أَعُوذُ بِكَ مِنْ الْبُخْلِ وَالْكَسَلِ وَأَرْذَلِ الْعُمُرِ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الدَّجَّالِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Harun bin Musa Abu 'Abdillah Al A'war] dari [Syu'aib] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam berdoa: 'A'UUDZU BIKA MINAL BUKHLI WAL KASALI, WA ARDZALIL 'UMURI WA'ADZAABIL QABRI WAFITNATID DAJJAAL WAFITNATIL MAHYAA WAL MAMAAT \"Ya Allah, aku berlindung kepada-Mu dari kekikiran, kemalasan, kepikunan, siksa kubur, fitnah Dajjal serta fitnah kehidupan dan kematian.\""},"4034":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ قَالَ سَمِعْتُ ابْنَ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُقَالَ فِي بَنِي إِسْرَائِيلَ وَالْكَهْفِ وَمَرْيَمَ إِنَّهُنَّ مِنْ الْعِتَاقِ الْأُوَلِ وَهُنَّ مِنْ تِلَادِي{ فَسَيُنْغِضُونَ إِلَيْكَ رُءُوسَهُمْ }قَالَ ابْنُ عَبَّاسٍ يَهُزُّونَ وَقَالَ غَيْرُهُ نَغَضَتْ سِنُّكَ أَيْ تَحَرَّكَتْ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; Aku mendengar ['Abdur Rahman bin Yazid] dia berkata; Aku mendengar [Ibnu Mas'ud radliallahu 'anhu] dia berkata mengenai surat Bani Israil, Ashabul Al Kahfi, dan Maryam; Mereka adalah orang-orang terdahulu, dan surat-surat itu sudah lama aku membacanya. Adapun arti Lalu mereka akan menggeleng-gelengkan kepala mereka.. (Al Israa: 51). Ibnu Abbas berkata; yaitu menggerak-gerakannya. Yang lainnya berkata; 'Naghdlat Sinnuka.' Yakni; gigimu bergerak-gerak."},"4035":{"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ ح و حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ ابْنُ الْمُسَيَّبِ قَالَ أَبُو هُرَيْرَةَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ بِإِيلِيَاءَ بِقَدَحَيْنِ مِنْ خَمْرٍ وَلَبَنٍ فَنَظَرَ إِلَيْهِمَا فَأَخَذَ اللَّبَنَ قَالَ جِبْرِيلُ الْحَمْدُ لِلَّهِ الَّذِي هَدَاكَ لِلْفِطْرَةِ لَوْ أَخَذْتَ الْخَمْرَ غَوَتْ أُمَّتُكَ","id":"Telah menceritakan kepada kami ['Abdan] Telah menceritakan kepada kami ['Abdullah] Telah mengabarkan kepada kami [Yunus]; Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepada kami [Ahmad bin Shalih] Telah menceritakan kepada kami ['Anbasah] Telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dia berkata; [Ibnu Al Musayyab] dia berkata; [Abu Hurairah] berkata; Pada malam Rasulullah shallallahu 'alaihi wasallam diisra'kan di Iliya, dihidangkan kepada beliau dua bejana; khamer dan susu. Lalu beliau memandangi keduanya seraya mengambil bejana yang berisi susu. Jibril 'Alaihis Salam pun berkata; \"Segala puji bagi Allah yang telah menunjukimu kepada fitrah, sekiranya engkau mengambil khamer maka umatmu tersesat.\""},"4036":{"ar":"حَدَّثَنَا أَحْمَدُ بْن�� صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَبُو سَلَمَةَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَمَّا كَذَّبَتْنِي قُرَيْشٌ قُمْتُ فِي الْحِجْرِ فَجَلَّى اللَّهُ لِي بَيْتَ الْمَقْدِسِ فَطَفِقْتُ أُخْبِرُهُمْ عَنْ آيَاتِهِ وَأَنَا أَنْظُرُ إِلَيْهِزَادَ يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ لَمَّا كَذَّبَتْنِي قُرَيْشٌ حِينَ أُسْرِيَ بِي إِلَى بَيْتِ الْمَقْدِسِ نَحْوَهُ{ قَاصِفًا }رِيحٌ تَقْصِفُ كُلَّ شَيْءٍ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] Telah menceritakan kepada kami [Ibnu Wahb] dia berkata; Telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab], [Abu Usamah] berkata; Aku mendengar [Jabir bin 'Abdullah radliallahu 'anhuma] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Ketika orang-orang Quraisy mendustakan perjalananku ke Baitil Maqdis, saya berdiri di Hijr Isma'il, lalu Allah menampakkan Baitul Maqdis kepadaku hingga saya memberi tahu kepada mereka tentang tanda-tandanya, dan saya dapat melihatnya.\" [Ya'qub bin Ibrahim] menambahkan; Telah menceritakan kepada kami [anak saudaraku yaitu Ibnu Syihab] dari [pamannya]; Tatkala orang-orang Quraisy mendustakanku pada hari aku diisra'kan ke baitul maqdis -dengan Hadits yang serupa. Arti Qashifan, (Al Isra: 69), yaitu angin yang menghancurkan segala sesuatu."},"4037":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ أَخْبَرَنَا مَنْصُورٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا نَقُولُ لِلْحَيِّ إِذَا كَثُرُوا فِي الْجَاهِلِيَّةِ أَمِرَ بَنُو فُلَانٍحَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ وَقَالَ أَمَرَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Sufyan] Telah mengabarkan kepada kami [Manshur] dari [Abu Wail] dari ['Abdullah] dia berkata; pada masa jahiliyah kami biasa mengatakan bagi suatu kaum apabila mereka berjumlah banyak, dengan perkataan; Bani Fulan banyak anaknya. Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] dia berkata dengan lafazh; 'Amara.'"},"4038":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا أَبُو حَيَّانَ التَّيْمِيُّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأُتِيَ بِلَحْمٍ فَرُفِعَ إِلَيْهِ الذِّرَاعُ وَكَانَتْ تُعْجِبُهُ فَنَهَشَ مِنْهَا نَهْشَةً ثُمَّ قَالَ أَنَا سَيِّدُ النَّاسِ يَوْمَ الْقِيَامَةِ وَهَلْ تَدْرُونَ مِمَّ ذَلِكَ يَجْمَعُ اللَّهُ النَّاسَ الْأَوَّلِينَ وَالْآخِرِينَ فِي صَعِيدٍ وَاحِدٍ يُسْمِعُهُمْ الدَّاعِي وَيَنْفُذُهُمْ الْبَصَرُ وَتَدْنُو الشَّمْسُ فَيَبْلُغُ النَّاسَ مِنْ الْغَمِّ وَالْكَرْبِ مَا لَا يُطِيقُونَ وَلَا يَحْتَمِلُونَ فَيَقُولُ النَّاسُ أَلَا تَرَوْنَ مَا قَدْ بَلَغَكُمْ أَلَا تَنْظُرُونَ مَنْ يَشْفَعُ لَكُمْ إِلَى رَبِّكُمْ فَيَقُولُ بَعْضُ النَّاسِ لِبَعْضٍ عَلَيْكُمْ بِآدَمَ فَيَأْتُونَ آدَمَ عَلَيْهِ السَّلَام فَيَقُولُونَ لَهُ أَنْتَ أَبُو الْبَشَرِ خَلَقَكَ اللَّهُ بِيَدِهِ وَنَفَخَ فِيكَ مِنْ رُوحِهِ وَأَمَرَ الْمَلَائِكَةَ فَسَجَدُوا لَكَ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى إِلَى مَا نَحْنُ فِيهِ أَلَا تَرَى إِلَى مَا قَدْ بَلَغَنَا فَيَقُولُ آدَمُ إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنَّهُ قَدْ نَهَانِي عَنْ الشَّجَرَةِ فَعَصَيْتُهُ نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى نُوحٍ فَيَأْتُونَ نُوحًا فَيَقُولُونَ يَا نُوحُ إِنَّكَ أَنْتَ أَوَّلُ الرُّسُلِ إِلَى أَهْلِ الْأَرْضِ وَقَدْ سَمَّاكَ اللَّهُ عَبْدًا شَكُورًا اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى إِلَى مَا نَحْنُ فِيهِ فَيَقُولُ إِنَّ رَبِّي عَزَّ وَجَلَّ قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنَّهُ قَدْ كَانَتْ لِي دَعْوَةٌ دَعَوْتُهَا عَلَى قَوْمِي نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى إِبْرَاهِيمَ فَيَأْتُونَ إِبْرَاهِيمَ فَيَقُولُونَ يَا إِبْرَاهِيمُ أَنْتَ نَبِيُّ اللَّهِ وَخَلِيلُهُ مِنْ أَهْلِ الْأَرْضِ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى إِلَى مَا نَحْنُ فِيهِ فَيَقُولُ لَهُمْ إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنِّي قَدْ كُنْتُ كَذَبْتُ ثَلَاثَ كَذِبَاتٍ فَذَكَرَهُنَّ أَبُو حَيَّانَ فِي الْحَدِيثِ نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى مُوسَى فَيَأْتُونَ مُوسَى فَيَقُولُونَ يَا مُوسَى أَنْتَ رَسُولُ اللَّهِ فَضَّلَكَ اللَّهُ بِرِسَالَتِهِ وَبِكَلَامِهِ عَلَى النَّاسِ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى إِلَى مَا نَحْنُ فِيهِ فَيَقُولُ إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَإِنِّي قَدْ قَتَلْتُ نَفْسًا لَمْ أُومَرْ بِقَتْلِهَا نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى عِيسَى ابْنِ مَرْيَمَ فَيَأْتُونَ عِيسَى فَيَقُولُونَ يَا عِيسَى أَنْتَ رَسُولُ اللَّهِ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ وَرُوحٌ مِنْهُ وَكَلَّمْتَ النَّاسَ فِي الْمَهْدِ صَبِيًّا اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى إِلَى مَا نَحْنُ فِيهِ فَيَقُولُ عِيسَى إِنَّ رَبِّي قَدْ غَضِبَ الْيَوْمَ غَضَبًا لَمْ يَغْضَبْ قَبْلَهُ مِثْلَهُ قَطُّ وَلَنْ يَغْضَبَ بَعْدَهُ مِثْلَهُ وَلَمْ يَذْكُرْ ذَنْبًا نَفْسِي نَفْسِي نَفْسِي اذْهَبُوا إِلَى غَيْرِي اذْهَبُوا إِلَى مُحَمَّدٍ فَيَأْتُونَ مُحَمَّدًا فَيَقُولُونَ يَا مُحَمَّدُ أَنْتَ رَسُولُ اللَّهِ وَخَاتِمُ الْأَنْبِيَاءِ وَقَدْ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ اشْفَعْ لَنَا إِلَى رَبِّكَ أَلَا تَرَى إِلَى مَا نَحْنُ فِيهِ فَأَنْطَلِقُ فَآتِي تَحْتَ الْعَرْشِ فَأَقَعُ سَاجِدًا لِرَبِّي عَزَّ وَجَلَّ ثُمَّ يَفْتَحُ اللَّهُ عَلَيَّ مِنْ مَحَامِدِهِ وَحُسْنِ الثَّنَاءِ عَلَيْهِ شَيْئًا لَمْ يَفْتَحْهُ عَلَى أَحَدٍ قَبْلِي ثُمَّ يُقَالُ يَا مُحَمَّدُ ارْفَعْ رَأْسَكَ سَلْ تُعْطَهْ وَاشْفَعْ تُشَفَّعْ فَأَرْفَعُ رَأْسِي فَأَقُولُ أُمَّتِي يَا رَبِّ أُمَّتِي يَا رَبِّ أُمَّتِي يَا رَبِّ فَيُقَالُ يَا مُحَمَّدُ أَدْخِلْ مِنْ أُمَّتِكَ مَنْ لَا حِسَابَ عَلَيْهِمْ مِنْ الْبَابِ الْأَيْمَنِ مِنْ أَبْوَابِ الْجَنَّةِ وَهُمْ شُرَكَاءُ النَّاسِ فِيمَا سِوَى ذَلِكَ مِنْ الْأَبْوَابِ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ مَا بَيْنَ الْمِصْرَاعَيْنِ مِنْ مَصَارِيعِ الْجَنَّةِ كَمَا بَيْنَ مَكَّةَ وَحِمْيَرَ أَوْ كَمَا بَيْنَ مَكَّةَ وَبُصْرَى","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami ['Abdullah] Telah mengabarkan kepada kami [Abu Hayyan At Taimi] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah Shallallahu 'alahi wa Salam diberi sepotong daging maka beliau pun mengangkat lengannya, dan beliau menyukai daging itu, hingga beliau menggigitnya. Setelah itu beliau bersabda: \"Aku pemimpin manusia pada hari kiamat, tahukah kalian kenapa? Allah akan mengumpulkan semua manusia dari yang pertama hingga yang akhir dalam satu tanah lapang, seorang penyeru akan menyeru mereka, pandangan menembus mereka dan matahari mendekat, duka dan kesusahan manusia sampai pada batas yang tidak mampu mereka pikul. Orang-orang saling berkata satu sama lain: Apa kalian tidak melihat yang telah menimpa kalian, apakah kalian tidak melihat siapa yang memberi kalian syafaat kepada Rabb kalian. Orang-orang saling berkata satu sama lain: Hendaklah kalian menemui Adam. Mereka menemui Adam lalu berkata: Engkau adalah bapak seluruh manusia, Allah menciptakanmu dengan tanganNya, meniupkan ruh-Nya padamu dan memerintahkan para malaikat lalu mereka sujud padamu, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Adam berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu Ia melarangku mendekati pohon tapi aku durhaka. Oh diriku, Oh diriku, Ohh diriku. Pergilah pada selainku, pergilah ke Nuh. Mereka mendatangi Nuh lalu berkata: Hai Nuh, engkau adalah rasul pertama untuk penduduk bumi, Allah menyebutmu hamba yang sangat bersyukur, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Nuh berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu aku pernah berdoa keburukan untuk kaumku, Oh diriku, Oh diriku, Oh diriku, pergilah kepada selainku, pergilah ke Ibrahim. Mereka mendatangi Ibrahim lalu berkata: Wahai Ibrahim, engkau nabi Allah dan kekasihNya dari penduduk bumi, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Ibrahim berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu aku pernah bedusta tiga kali -Abu Hayyan menyebut ketiga-tiganya dalam hadits ini- oh diriku, diriku, diriku, pergilah kepada selainku, pergilah ke Musa. Mereka menemui Musa lalu berkata: Wahai Musa, engkau utusan Allah, Allah melebihkanmu dengan risalah dan kalamNya atas seluruh manusia, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Musa berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, dulu aku pernah membunuh jiwa padahal aku tidak diperintahkan untuk membunuhnya, oh diriku, diriku, diriku, pergilah kepada selainku, pergilah ke 'Isa. Mereka mendatangi 'Isa lalu berkata: Hai 'Isa, engkau adalah utusan Allah, kalimatNya yang disampaikan ke maryam, ruh dariNya, engkau berbicara pada manusia saat masih berada dalam buaian, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami, apa kau tidak melihat yang menimpa kami? Isa berkata kepada mereka: Rabbku saat ini benar-benar marah, Ia tidak pernah marah seperti itu sebelumnya dan tidak akan pernah seperti itu sesudahnya, namun ia tidak menyebut dosanya, oh diriku, diriku, diriku, pergilah ke selainku, pergilah ke Muhammad. Mereka mendatangi Muhammad lalu berkata: Wahai Muhammad, engkau adalah utusan Allah, penutup para nabi, dosamu yang telah lalu dan yang kemudian telah diampuni, berilah kami syafaat kepada Rabbmu, apa kau tidak lihat kondisi kami. Lalu aku pergi hingga sampai di bawah 'arsy, aku tersungkur sujud pada Rabbku lalu Allah memulai dengan pujian dan sanjungan untukku yang belum pernah disampaikan pada seorang pun sebelumku, kemudian dikatakan: Hai Muhammad, angkatlah kepalamu, mintalah pasti kau diberi, berilah syafaat nicaya kau diizinkan untuk memberi syafaat. Maka aku mengangkat kepalaku, aku berkata: Wahai Rabb, ummatku, wahai Rabb, ummatku, wahai Rabb, ummatku. Ia berkata: Hai Muhammad, masukkan orang yang tidak dihisab dari ummatmu melalui pintu-pintu surga sebelah kanan dan mereka adalah sekutu semua manusia selain pintu-pintu itu.\" Setelah itu beliau bersabda: \"Demi Dzat yang jiwaku berada ditanganNya, jarak antara dua daun pintu-pintu surga seperti jarak antara Makkah dan Himyar atau seperti jarak antara Makkah dan Bashrah.\""},"4039":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خُفِّفَ عَلَى دَاوُدَ الْقِرَاءَةُ فَكَانَ يَأْمُرُ بِدَابَّتِهِ لِتُسْرَجَ فَكَانَ يَقْرَأُ قَبْلَ أَنْ يَفْرُغَيَعْنِي الْقُرْآنَ","id":"Telah menceritakan kepadaku [Ishaq bin Nashr] Telah menceritakan kepada kami ['Abdur Razzaq] dari [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dawud 'Alaihis Salam dimudahkan untuk membaca, dia pernah menyuruh orang untuk memasangkan pelana pada tunggangannya, dan dia membaca Al Qur`an terlebih dahulu sebelum pelananya selesai dipasangkan pada tunggangannya.\""},"4040":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنِي سُلَيْمَانُ عَنْ إِبْرَاهِيمَ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ{ إِلَى رَبِّهِمْ الْوَسِيلَةَ }قَالَ كَانَ نَاسٌ مِنْ الْإِنْسِ يَعْبُدُونَ نَاسًا مِنْ الْجِنِّ فَأَسْلَمَ الْجِنُّ وَتَمَسَّكَ هَؤُلَاءِ بِدِينِهِمْزَادَ الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ{ قُلْ ادْعُوا الَّذِينَ زَعَمْتُمْ }","id":"Telah menceritakan kepadaku ['Amru bin 'Ali] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepadaku [Sulaiman] dari [Ibrahim] dari [Abu Ma'mar] dari ['Abdullah] mengenai firman Allah: Orang-orang yang mereka seru itu, mereka sendiri mencari jalan kepada Tuhan mereka.., (Al Isra: 57). Abdullah berkata; Sebagian orang menyembah bangsa Jin. Lalu bangsa jin tersebut masuk Islam, sedangkan orang yang menyembahnya tetap pada keyakinan mereka. [Al Asyaj] menambahkan dari [Sufyan] dari [Al A'masy] yaitu firman Allah: Katakanlah: \"Panggillah mereka yang kamu anggap (tuhan) selain Allah.., (Al Isra: 56)."},"4041":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُفِي هَذِهِ الْآيَةِ{ الَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَى رَبِّهِمْ الْوَسِيلَةَ }قَالَ كَانَ نَاسٌ مِنْ الْجِنِّ يُعْبَدُونَ فَأَسْلَمُوا","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Abu Ma'mar] dari ['Abdullah radliallahu 'anhu] mengenai firman Allah: Orang-orang yang mereka seru itu, mereka sendiri mencari jalan kepada Tuhan mereka.., (Al Isra: 57). Abdullah berkata; 'Sebagian kelompok dari bangsa Jin disembah manusia. Lalu bangsa jin tersebut masuk Islam.'"},"4042":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُ{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ{ وَالشَّجَرَةَ الْمَلْعُونَةَ }شَجَرَةُ الزَّقُّومِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhu] berkenaan dengan ayat …Dan Kami tidak menjadikan mimpi yang telah Kami perlihatkan kepadamu, melainkan sebagai ujian bagi manusia dan (begitu pula) pohon kayu yang terkutuk dalam Al Qur'an…, (Al Isra: 60) ia mengatakan; ia adalah mimpi yang diperlihatkan kepada Nabi shallallahu 'alaihi wasallam pada malam beliau diIsra-kan ke Baitul Maqdis, dan pohon yang dilaknat di dalam al Qur'an yaitu pohon Zaqqum.\""},"4043":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ وَابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَضْلُ صَلَاةِ الْجَمِيعِ عَلَى صَلَاةِ الْوَاحِدِ خَمْسٌ وَعِشْرُونَ دَرَجَةً وَتَجْتَمِعُ مَلَائِكَةُ اللَّيْلِ وَمَلَائِكَةُ النَّهَارِ فِي صَلَاةِ الصُّبْحِ يَقُولُ أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ{ وَقُرْآنَ الْفَجْرِ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }","id":"Telah menceritakan kepadaku ['Abdullah bin Muhammad] Telah menceritakan kepada kami ['Abdur Razzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dan [Ibnu Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Keutamaan shalat berjama'ah dari shalat sendirian adalah dua puluh lima derajat, dan malaikat malam dan malaikat siang berkumpul ketika shalat subuh.\" lalu Abu Hurairah berkata: \"jika kalian mau bacalah: \"dan (dirikanlah pula shalat) subuh. Sesungguhnya shalat subuh itu disaksikan (oleh malaikat).\" (Al Isra: 78)."},"4044":{"ar":"حَدَّثَنِي إِسْمَاعِيلُ بْنُ أَبَانَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ آدَمَ بْنِ عَلِيٍّ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُإِنَّ النَّاسَ يَصِيرُونَ يَوْمَ الْقِيَامَةِ جُثًا كُلُّ أُمَّةٍ تَتْبَعُ نَبِيَّهَا يَقُولُونَ يَا فُلَانُ اشْفَعْ يَا فُلَانُ اشْفَعْ حَتَّى تَنْتَهِيَ الشَّفَاعَةُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَلِكَ يَوْمَ يَبْعَثُهُ اللَّهُ الْمَقَامَ الْمَحْمُودَ","id":"Telah menceritakan kepadaku [Isma'il bin Aban] Telah menceritakan kepada kami [Abu Al Ahwash] dari [Adam bin 'Ali] dia berkata; Aku mendengar [Ibnu 'Umar radliallahu 'anhuma] berkata; Sesungguhnya pada hari kiamat kelak manusia akan menjadi bangkai. Setiap umat akan mengikuti nabinya hingga mereka saling berkata; 'Ya Fulan, berilah aku syafa'at. ya fulan, berilah aku syafa'at.' Sampai akhirnya mereka mendatangi Nabi shallallahu 'alaihi wasallam. Itulah hari ketika Allah membangkitkan Nabi shallallahu 'alaihi wasallam pada kedudukan yang terpuji."},"4045":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يَسْمَعُ النِّدَاءَ اللَّهُمَّ رَبَّ هَذِهِ الدَّعْوَةِ التَّامَّةِ وَالصَّلَاةِ الْقَائِمَةِ آتِ مُحَمَّدًا الْوَسِيلَةَ وَالْفَضِيلَةَ وَابْعَثْهُ مَقَامًا مَحْمُودًا الَّذِي وَعَدْتَهُ حَلَّتْ لَهُ شَفَاعَتِي يَوْمَ الْقِيَامَةِرَوَاهُ حَمْزَةُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ali bin 'Ayyasy] Telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] dari [Muhammad bin Al Munkadir] dari [Jabir bin 'Abdullah radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca ketika mendengar adzan; \"ALLAHUMMA ROBA HADZIHID DA'WAATIT TAAMMAH WAS SHALATIL QOOIMAH ATI MUHAMMADANIL WASILATA WAL FADHIILAH WAB'ATSHU MAQOOMAM MAHMUDANIL LADZI WA'ADTAHU\" (Ya Allah pemilik panggilan yang sempurna ini dan shalat yang didirikan berilah Muhammad wasilah dan keutamaan dan bangkitkanlah dia pada tempat yang terpuji yang telah Engkau janjikan padanya) melainkan ia akan mendapatkan syafa'atku pada hari kiamat.\" Diriwayatkan oleh [Hamzah bin Abdullah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam."},"4046":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَحَوْلَ الْبَيْتِ سِتُّونَ وَثَلَاثُ مِائَةِ نُصُبٍ فَجَعَلَ يَطْعُنُهَا بِعُودٍ فِي يَدِهِ وَيَقُولُ{ جَاءَ الْحَقُّ وَزَهَقَ الْبَاطِلُ إِنَّ الْبَاطِلَ كَانَ زَهُوقًا }{ جَاءَ الْحَقُّ وَمَا يُبْدِئُ الْبَاطِلُ وَمَا يُعِيدُ }","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] dari [Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari ['Abdullah bin Mas'ud radliallahu 'anhu] dia berkata; Ketika Nabi shallallaahu 'alaihi wasallam masuk Makkah, di sekeliling ka'bah terdapat tiga ratus enam puluh berhala, lalu Nabi memecahkannya dengan tongkat yang berada di tangannya seraya mengucapkan firman Allah: \"Yang benar telah datang dan yang batil telah lenyap. Sesungguhnya yang batil itu adalah sesuatu yang pasti lenyap. (Al Isra: 81). Kebenaran telah datang dan yang batil itu tidak akan memulai dan tidak (pula) akan mengulangi.\""},"4047":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَا أَنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرْثٍ وَهُوَ مُتَّكِئٌ عَلَى عَسِيبٍ إِذْ مَرَّ الْيَهُودُ فَقَالَ بَعْضُهُمْ لِبَعْضٍ سَلُوهُ عَنْ الرُّوحِ فَقَالَ مَا رَأْيُكُمْ إِلَيْهِ وَقَالَ بَعْضُهُمْ لَا يَسْتَقْبِلُكُمْ بِشَيْءٍ تَكْرَهُونَهُ فَقَالُوا سَلُوهُ فَسَأَلُوهُ عَنْ الرُّوحِ فَأَمْسَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَرُدَّ عَلَيْهِمْ شَيْئًا فَعَلِمْتُ أَنَّهُ يُوحَى إِلَيْهِ فَقُمْتُ مَقَامِي فَلَمَّا نَزَلَ الْوَحْيُ قَالَ{ وَيَسْأَلُونَكَ عَنْ الرُّوحِ قُلْ الرُّوحُ مِنْ أَمْرِ رَبِّي وَمَا أُوتِيتُمْ مِنْ الْعِلْمِ إِلَّا قَلِيلًا }","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] dia berkata; Telah menceritakan kepadaku [Ibrahim] dari ['Alqamah] dari ['Abdullah radliallahu 'anhu] dia berkata; \"ketika aku bersama nabi shallallahu 'alaihi wasallam disuatu ladang sementara beliau tengah bersandar, tiba-tiba beberapa orang Yahudi lewat, mereka saling berkata satu sama lain: 'Tanyakan padanya tentang ruh sehingga ia kembali bertanya 'bagaimana pendapat kalian tentangnya! Namun sebagian mengatakan \"Jangan sampai ia meminta kalian mendatangkan sesuatu yang kalian sen diri tidak menyukainya.' Mereka berkata, 'Bertanyalah padanya.' Kemudian sebagian dari mereka menghampiri beliau, lalu bertanya tentang roh'.\" Nabi shallallahu 'alaihi wasallam diam dan tidak menjawab apa pun. Aku tahu beliau tengah diberi wahyu. Aku berdiri dari tempatku. Saat wahyu turun, beliau bersabda: 'Dan mereka bertanya kepadamu tentang roh. Katakanlah: 'Roh itu termasuk urusan Tuhan-ku, dan tidaklah kamu diberi pengetahuan melainkan sedikit.\" (Al Israa`: 85)."},"4048":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ تَعَالَى{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ كَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ بِالْقُرْآنِ فَإِذَا سَمِعَهُ الْمُشْرِكُونَ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ تَعَالَى لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا تُسْمِعُهُمْ{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Husyaim] Telah menceritakan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] mengenai firman Allah: \"dan janganlah kamu mengeraskan suaramu dalam shalatmu dan janganlah pula merendahkannya…, \" (Al Israa: 110). Ibnu Abbas berkata; ayat ini turun ketika Rasulullah shallallahu 'alaihi wasallam sembunyi-sembunyi di Makkah. Beliau shallallahu 'alaihi wasallam bila mengimami shalat para sahabatnya, beliau mengeraskannya saat membaca al Qur`an. Tatkala orang-orang musyrik mendengarkan hal itu, mereka mencela al Qur`an, mencela yang menurunkannya dan yang membawakannya. Maka Allah Azza Wa Jalla berfirman kepada NabiNya: (Dan janganlah kamu mengeraskan suaramu dalam shalatmu) maksudnya adalah dalam bacaanmu sehingga orang-orang musyrik mendengarnya dan mereka mencela al Qu`ran dan: Dan janganlah pula merendahkannya dari para sahabatmu sehingga mereka tidak dapat mendengarkan dan mengambil Al Qu`ran darimu dan: Maka carilah jalan tengah di antara kedua itu."},"4049":{"ar":"حَدَّثَنِي طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا زَائِدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأُنْزِلَ ذَلِكَ فِي الدُّعَاءِ","id":"Telah menceritakan kepadaku [Thalq bin Ghannam] Telah menceritakan kepada kami [Zaidah] dari [Hisyam] dari [Bapaknya] dari ['Aisyah radliallahu 'anha] dia berkata; \"Ayat di atas turun berkenaan dengan do'a.\""},"4050":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَاب�� قَالَ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنٍ أَنَّ حُسَيْنَ بْنَ عَلِيٍّ أَخْبَرَهُ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَقَهُ وَفَاطِمَةَ قَالَ أَلَا تُصَلِّيَانِ{ رَجْمًا بِالْغَيْبِ }لَمْ يَسْتَبِنْ{ فُرُطًا }يُقَالُ نَدَمًا{ سُرَادِقُهَا }مِثْلُ السُّرَادِقِ وَالْحُجْرَةِ الَّتِي تُطِيفُ بِالْفَسَاطِيطِ{ يُحَاوِرُهُ }مِنْ الْمُحَاوَرَةِ{ لَكِنَّا هُوَ اللَّهُ رَبِّي }أَيْ لَكِنْ أَنَا{ هُوَ اللَّهُ رَبِّي }ثُمَّ حَذَفَ الْأَلِفَ وَأَدْغَمَ إِحْدَى النُّونَيْنِ فِي الْأُخْرَى{ وَفَجَّرْنَا خِلَالَهُمَا نَهَرًا }يَقُولُ بَيْنَهُمَا{ زَلَقًا }لَا يَثْبُتُ فِيهِ قَدَمٌ{ هُنَالِكَ الْوِلَايَةُ }مَصْدَرُ الْوَلِيِّ{ عُقُبًا }عَاقِبَةً وَعُقْبَى وَعُقْبَةً وَاحِدٌ وَهِيَ الْآخِرَةُ{ قِبَلًا }وَقُبُلًا وَقَبَلًا اسْتِئْنَافًا{ لِيُدْحِضُوا }لِيُزِيلُوا الدَّحْضُ الزَّلَقُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] Telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'ad] Telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Ali bin Husain] bahwa [Hushain bin 'Ali] mengabarkan kepadanya dari ['Ali radliallahu 'anhu] bahwa suatu ketika Rasulullah shallallahu 'alaihi wasallam pernah mendatangi dia dan Fatimah lalu beliau bertanya: \"Tidakkah kalian shalat (malam)?\" makna RAJMAN BIL GHAIB, (Al Kahfi: 22) yaitu; belum nampak. FURUTHAA, artinya; Nadaman (penyesalan). SURADIQUHA, artinya; seperti tenda dan kamar yang di kelilingi paviliyun.' YUHAWIRU, berasal dari kata Muhawarah. LAKINNA HUWALLAH, maksudnya; Tetapi aku (percaya bahwa): Dialah Allah, Tuhanku. -dengan membuang alif dan menggabungkan dua nun.-"},"4051":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ إِنَّ نَوْفًا الْبِكَالِيَّ يَزْعُمُ أَنَّ مُوسَى صَاحِبَ الْخَضِرِ لَيْسَ هُوَ مُوسَى صَاحِبَ بَنِي إِسْرَائِيلَ فَقَالَ ابْنُ عَبَّاسٍ كَذَبَ عَدُوُّ اللَّهِ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مُوسَى قَامَ خَطِيبًا فِي بَنِي إِسْرَائِيلَ فَسُئِلَ أَيُّ النَّاسِ أَعْلَمُ فَقَالَ أَنَا فَعَتَبَ اللَّهُ عَلَيْهِ إِذْ لَمْ يَرُدَّ الْعِلْمَ إِلَيْهِ فَأَوْحَى اللَّهُ إِلَيْهِ إِنَّ لِي عَبْدًا بِمَجْمَعِ الْبَحْرَيْنِ هُوَ أَعْلَمُ مِنْكَ قَالَ مُوسَى يَا رَبِّ فَكَيْفَ لِي بِهِ قَالَ تَأْخُذُ مَعَكَ حُوتًا فَتَجْعَلُهُ فِي مِكْتَلٍ فَحَيْثُمَا فَقَدْتَ الْحُوتَ فَهُوَ ثَمَّ فَأَخَذَ حُوتًا فَجَعَلَهُ فِي مِكْتَلٍ ثُمَّ انْطَلَقَ وَانْطَلَقَ مَعَهُ بِفَتَاهُ يُوشَعَ بْنِ نُونٍ حَتَّى إِذَا أَتَيَا الصَّخْرَةَ وَضَعَا رُءُوسَهُمَا فَنَامَا وَاضْطَرَبَ الْحُوتُ فِي الْمِكْتَلِ فَخَرَجَ مِنْهُ فَسَقَطَ فِي الْبَحْرِ{ فَاتَّخَذَ سَبِيلَهُ فِي الْبَحْرِ سَرَبًا }وَأَمْسَكَ اللَّهُ عَنْ الْحُوتِ جِرْيَةَ الْمَاءِ فَصَارَ عَلَيْهِ مِثْلَ الطَّاقِ فَلَمَّا اسْتَيْقَظَ نَسِيَ صَاحِبُهُ أَنْ يُخْبِرَهُ بِالْحُوتِ فَانْطَلَقَا بَقِيَّةَ يَوْمِهِمَا وَلَيْلَتَهُمَا حَتَّى إِذَا كَانَ مِنْ الْغَدِ قَالَ مُوسَى{ لِفَتَاهُ آتِنَا غَدَاءَنَا لَقَدْ لَقِينَا مِنْ سَفَرِنَا هَذَا نَصَبًا }قَالَ وَلَمْ يَجِدْ مُوسَى النَّصَبَ حَتَّى جَاوَزَا الْمَكَانَ الَّذِي أَمَرَ اللَّهُ بِهِ فَقَالَ لَهُ فَتَاهُ{ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ وَمَا أَنْسَانِيهِ إِلَّا الشَّيْطَانُ أَنْ أَذْكُرَهُ وَاتَّخَذَ سَبِيلَهُ فِي الْبَحْرِ عَجَبًا }قَالَ فَكَانَ لِلْحُوتِ سَرَبًا وَلِمُوسَى وَلِفَتَاهُ عَجَبًا فَقَالَ مُوسَى{ ذَلِكَ مَا كُنَّا نَبْغِي فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا }قَالَ رَجَعَا يَقُصَّانِ آثَارَهُمَا حَتَّى انْتَهَيَا إِلَى الصَّخْرَةِ فَإِذَا رَجُلٌ مُسَجًّى ثَوْبًا فَسَلَّمَ عَلَيْهِ مُوسَى فَقَالَ الْخَضِرُ وَأَنَّى بِأَرْضِكَ السَّلَامُ قَالَ أَنَا مُوسَى قَالَ مُوسَى بَنِي إِسْرَائِيلَ قَالَ نَعَمْ أَتَيْتُكَ لِتُعَلِّمَنِي مِمَّا عُلِّمْتَ رَشَدًا قَالَ{ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِي صَبْرًا }يَا مُوسَى إِنِّي عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَنِيهِ لَا تَعْلَمُهُ أَنْتَ وَأَنْتَ عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَكَهُ اللَّهُ لَا أَعْلَمُهُ فَقَالَ مُوسَى{ سَتَجِدُنِي إِنْ شَاءَ اللَّهُ صَابِرًا وَلَا أَعْصِي لَكَ أَمْرًا }فَقَالَ لَهُ الْخَضِرُ{ فَإِنْ اتَّبَعْتَنِي فَلَا تَسْأَلْنِي عَنْ شَيْءٍ حَتَّى أُحْدِثَ لَكَ مِنْهُ ذِكْرًا }فَانْطَلَقَا يَمْشِيَانِ عَلَى سَاحِلِ الْبَحْرِ فَمَرَّتْ سَفِينَةٌ فَكَلَّمُوهُمْ أَنْ يَحْمِلُوهُمْ فَعَرَفُوا الْخَضِرَ فَحَمَلُوهُمْ بِغَيْرِ نَوْلٍ فَلَمَّا رَكِبَا فِي السَّفِينَةِ لَمْ يَفْجَأْ إِلَّا وَالْخَضِرُ قَدْ قَلَعَ لَوْحًا مِنْ أَلْوَاحِ السَّفِينَةِ بِالْقَدُومِ فَقَالَ لَهُ مُوسَى قَوْمٌ قَدْ حَمَلُونَا بِغَيْرِ نَوْلٍ عَمَدْتَ إِلَى سَفِينَتِهِمْ فَخَرَقْتَهَا{ لِتُغْرِقَ أَهْلَهَا لَقَدْ جِئْتَ شَيْئًا إِمْرًا قَالَ أَلَمْ أَقُلْ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِي صَبْرًا قَالَ لَا تُؤَاخِذْنِي بِمَا نَسِيتُ وَلَا تُرْهِقْنِي مِنْ أَمْرِي عُسْرًا }قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ الْأُولَى مِنْ مُوسَى نِسْيَانًا قَالَ وَجَاءَ عُصْفُورٌ فَوَقَعَ عَلَى حَرْفِ السَّفِينَةِ فَنَقَرَ فِي الْبَحْرِ نَقْرَةً فَقَالَ لَهُ الْخَضِرُ مَا عِلْمِي وَعِلْمُكَ مِنْ عِلْمِ اللَّهِ إِلَّا مِثْلُ مَا نَقَصَ هَذَا الْعُصْفُورُ مِنْ هَذَا الْبَحْرِ ثُمَّ خَرَجَا مِنْ السَّفِينَةِ فَبَيْنَا هُمَا يَمْشِيَانِ عَلَى السَّاحِلِ إِذْ أَبْصَرَ الْخَضِرُ غُلَامًا يَلْعَبُ مَعَ الْغِلْمَانِ فَأَخَذَ الْخَضِرُ رَأْسَهُ بِيَدِهِ فَاقْتَلَعَهُ بِيَدِهِ فَقَتَلَهُ فَقَالَ لَهُ مُوسَى{ أَقَتَلْتَ نَفْسًا زَاكِيَةً بِغَيْرِ نَفْسٍ لَقَدْ جِئْتَ شَيْئًا نُكْرًا قَالَ أَلَمْ أَقُلْ لَكَ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِي صَبْرًا }قَالَ وَهَذِهِ أَشَدُّ مِنْ الْأُولَى{ قَالَ إِنْ سَأَلْتُكَ عَنْ شَيْءٍ بَعْدَهَا فَلَا تُصَاحِبْنِي قَدْ بَلَغْتَ مِنْ لَدُنِّي عُذْرًا فَانْطَلَقَا حَتَّى إِذَا أَتَيَا أَهْلَ قَرْيَةٍ اسْتَطْعَمَا أَهْلَهَا فَأَبَوْا أَنْ يُضَيِّفُوهُمَا فَوَجَدَا فِيهَا جِدَارًا يُرِيدُ أَنْ يَنْقَضَّ }قَالَ مَائِلٌ فَقَامَ الْخَضِرُ فَأَقَامَهُ بِيَدِهِ فَقَالَ مُوسَى قَوْمٌ أَتَيْنَاهُمْ فَلَمْ يُطْعِمُونَا وَلَمْ يُضَيِّفُونَا{ لَوْ شِئْتَ لَاتَّخَذْتَ عَلَيْهِ أَجْرًا قَالَ هَذَا فِرَاقُ بَيْنِي وَبَيْنِكَ إِلَى قَوْلِهِ ذَلِكَ تَأْوِيلُ مَا لَمْ تَسْطِعْ عَلَيْهِ صَبْرًا }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدِدْنَا أَنَّ مُوسَى كَانَ صَبَرَ حَتَّى يَقُصَّ اللَّهُ عَلَيْنَا مِنْ خَبَرِهِمَا قَالَ سَعِيدُ بْنُ جُبَيْرٍ فَكَانَ ابْنُ عَبَّاسٍ يَقْرَأُ وَكَانَ أَمَامَهُمْ مَلِكٌ يَأْخُذُ كُلَّ سَفِينَةٍ صَالِحَةٍ غَصْبًا وَكَانَ يَقْرَأُ وَأَمَّا الْغُلَامُ فَكَانَ كَافِرًا وَكَانَ أَبَوَاهُ مُؤْمِنَيْنِ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami ['Amru bin Dinar] dia berkata; Telah mengabarkan kepadaku [Sa'id bin Jubair] dia berkata; \"Saya berkata kepada Ibnu Abbas bahwasanya Nauf Al Bikali menganggap bahwa Musa 'Alaihis Salam yang berada di tengah kaum Bani Israil bukanlah Musa yang menyertai Nabi Khidhir.\" [Ibnu Abbas] berkata; 'Berdustalah musuh Allah. Telah menceritakan kepadaku [Ubay bin Ka'ab] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Suatu ketika Nabi Musa 'Alaihis Salam berdiri untuk berpidato di hadapan kaum Bani israil.' Setelah itu, seseorang bertanya kepadanya; 'Hai Musa, siapakah orang yang paling banyak ilmunya di muka bumi ini? ' Nabi Musa menjawab; 'Akulah orang yang paling banyak ilmunya di muka bumi ini.' Oleh karena itu, Allah sangat mencela Musa 'Alaihis Salam. Karena ia tidak menyadari bahwa ilmu yang diperolehnya itu adalah pemberian Allah. Lalu Allah mewahyukan kepada Musa; 'Hai Musa, sesungguhnya ada seorang hamba-Ku yang lebih banyak ilmunya dan lebih pandai darimu dan ia sekarang berada di pertemuan dua lautan.' Nabi Musa 'Alaihis Salam bertanya; 'Ya Tuhan, bagaimana caranya saya dapat bertemu dengan hambaMu itu? ' Dijawab; 'Bawalah seekor ikan di dalam keranjang dari daun kurma. Manakala ikan tersebut lompat, maka di situlah hambaKu berada.' Kemudian Musa pun berangkat ke tempat itu dengan ditemani seorang muridnya yang bernama Yusya' bin Nun. Nabi Musa sendiri membawa seekor ikan di dalam keranjang yang terbuat dari daun kurma. Keduanya berjalan kaki menuju tempat tersebut. Ketika keduanya sampai di sebuah batu besar, maka keduanya pun tertidur lelap. Tiba-tiba ikan yang berada di dalam keranjang tersebut berguncang keluar, lalu masuk ke dalam air laut. lalu ikan itu melompat mengambil jalannya ke laut itu, (Al Kahfi: 61). 'Allah telah menahan air yang dilalui ikan tersebut, hingga menjadi terowongan. Akhirnya mereka berdua melanjutkan perjalanannya siang dan malam. Rupanya murid Nabi Musa lupa untuk memberitahukannya. Pada pagi harinya, Nabi Musa berkata kepada muridnya; 'Bawalah makanan kita kemari! Sesungguhnya kita merasa letih karena perjalanan kita ini.' Rasulullah shallallahu 'alaihi wasallam berkata: 'Belum berapa jauh Musa melewati tempat yang diperintahkan untuk mencarinya, muridnya berkata; 'Tahukah Anda tatkala kita mencari tempat berlindung di batu besar tadi, maka sesungguhnya saya lupa menceritakan tentang ikan itu dan tidak ada yang membuat saya lupa untuk menceritakannya kecuali syetan, sedangkan ikan tersebut mengambil jalannya ke laut dengan cara yang aneh sekali.' Musa berkata; 'Itulah tempat yang sedang kita cari.' Lalu keduanya kembali mengikuti jalan mereka semula. 'Kemudian keduanya menelusuri jejak mereka semula.' Setelah keduanya tiba di batu besar tadi, maka mereka melihat seorang laki-laki yang sedang tertidur berselimutkan kain. Lalu Nabi Musa 'Alaihis Salam mengucapkan salam kepadanya. Nabi Khidhir bertanya kepada Musa; 'Dan dari manakah salam di negerimu? ' Musa berkata; 'Saya adalah Musa.' Nabi Khidhir bertanya; 'Musa Bani Israil.' Nabi Musa menjawab; 'Ya.' Musa berkata kepada Khidhir; Aku mendatangimu agar engkau mengajarkan kepadaku ilmu yang benar di antara ilmu-ilmu yang telah diajarkan kepadamu? ' Nabi Khidhir menjawab; 'Sesungguhnya sekali-kali kamu tidak akan sanggup dan sabar bersamaku. Bagaimana kamu bisa sabar atas sesuatu yang kamu belum mempunyai pengetahuan yang cukup tentang hal itu? ' Musa berkata; 'Insya Allah kamu akan mendapatiku sebagai orang yang sabar dan aku pun tidak akan menentangmu dalam suatu urusan pun.' Khidhir menjawab; 'Jika kamu tetap mengikutiku, maka janganlah kamu menanyakan sesuatu hingga aku sendiri yang akan menerangkannya kepadamu.' Musa menjawab; 'Baiklah.' Rasulullah shallallahu 'alaihi wasallam berkata: 'Kemudian Musa dan Khidhir berjalan menyusuri pantai. Tak lama kemudian ada sebuah perahu yang lewat. Lalu keduanya meminta tumpangan perahu. Ternyata orang-orang perahu itu mengenal baik Nabi Khidhir, hingga akhirnya mereka mengangkut keduanya tanpa meminta upah.' Lalu Nabi Khidhir mendekat ke salah satu papan di bagian perahu itu dan setelah itu mencabutnya. Melihat hal itu, Musa menegur dan memarahinya; 'Mereka ini adalah orang-orang yang mengangkut kita tanpa meminta upah, tetapi mengapa kamu malah melubangi perahu mereka untuk kamu tenggelamkan penumpangnya? ' Khidhir menjawab; 'Bukankah telah aku katakan kepadamu bahwasanya kamu sekali-kali tidak akan sabar ikut bersamaku.' Musa berkata sambil merayu; 'Janganlah kamu menghukumku karena kealpaanku dan janganlah kamu membebaniku dengan suatu kesulitan dalam urusanku.' Tak lama kemudian, keduanya pun turun dari perahu tersebut. Ketika keduanya sedang berjalan-jalan di tepi pantai, tiba-tiba ada seorang anak kecil yang sedang bermain dengan teman-temannya yang lain. Kemudian, Nabi Khidhir segera memegang dan membekuk kepala anak kecil itu dengan tangannya hingga menemui ajalnya. Dengan gusarnya Nabi Musa berupaya menghardik Nabi Khidhir; 'Mengapa kamu bunuh jiwa yang tak berdosa, sedangkan anak kecil itu belum pernah membunuh? Sungguh kamu telah melakukan perbuatan yang munkar? ' Khidhir berkata; 'Bukankah sudah aku katakan bahwasanya kamu tidak akan mampu untuk bersabar dalam mengikutiku. Dan ini melebihi dari yang sebelumnya.' Musa berkata; 'Jika aku bertanya kepadamu tenteng sesuatu setelah ini, maka janganlah kamu perbolehkan aku untuk menyertaimu. Sesungguhnya kamu sudah cukup memberikan uzur (maaf) kepadaku.' Selanjutnya Nabi Musa dan Khidhir melanjutkan perjalanannya. Ketika kami berdua tiba di suatu negeri, maka keduanya pun meminta jamuan dari penduduk negeri tersebut, tapi sayangnya mereka enggan menjamu keduanya. Lalu keduanya mendapatkan sebuah dinding rumah yang hampir roboh dan Nabi Khidhir pun langsung menegakkannya (memperbaikinya). Rasulullah shallallahu 'alaihi wasallam bersabda: 'Dinding itu miring (sambil memberi isyarat dengan tangannya) lalu ditegakkan oleh Khidhir.' Musa berkata kepada Khidhir; 'Kamu telah mengetahui bahwa para penduduk negeri yang kita datangi ini enggan menyambut dan menjamu kita. Kalau kamu mau, sebaiknya kamu minta upah dari hasil perbaikan dinding rumah tersebut. Akhirnya Khidhir berkata; 'Inilah perpisahan antara aku dan kamu. Aku akan beritahukan kepadamu tentang rahasia segala perbuatan yang kamu tidak sabar padanya.' Rasulullah shallallahu 'alaihi wasallam berkata: Sebenarnya aku lebih senang jika Musa dapat sedikit bersabar, hingga kisah Musa dan Khidhir bisa diceritakan kepada kita dengan lebih panjang lagi. Sa'id bin Zubair berkata; 'Ibnu Abbas membacakan ayat Al Qur'an yang artinya; 'Di depan mereka ada seorang penguasa yang merampas setiap perahu yang bagus. Ibnu Abbas juga membacakan ayat Al Qur'an yang artinya; 'Anak kecil yang dibunuh Nabi Khidhir itu adalah kafir sedangkan kedua orang tuanya mukmin.'"},"4052":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي يَعْلَى بْنُ مُسْلِمٍ وَعَمْرُو بْنُ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ يَزِيدُ أَحَدُهُمَا عَلَى صَاحِبِهِ وَغَيْرُهُمَا قَدْ سَمِعْتُهُ يُحَدِّثُهُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ إِنَّا لَعِنْدَ ابْنِ عَبَّاسٍ فِي بَيْتِهِ إِذْ قَالَ سَلُونِي قُلْتُ أَيْ أَبَا عَبَّاسٍ جَعَلَنِي اللَّهُ فِدَاءَكَ بِالْكُوفَةِ رَجُلٌ قَاصٌّ يُقَالُ لَهُ نَوْفٌ يَزْعُمُ أَنَّهُ لَيْسَ بِمُوسَى بَنِي إِسْرَائِيلَ أَمَّا عَمْرٌو فَقَالَ لِي قَالَ قَدْ كَذَبَ عَدُوُّ اللَّهِ وَأَمَّا يَعْلَى فَقَالَ لِي قَالَ ابْنُ عَبَّاسٍ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوسَى رَسُولُ اللَّهِ عَلَيْهِ السَّلَام قَالَ ذَكَّرَ النَّاسَ يَوْمًا حَتَّى إِذَا فَاضَتْ الْعُيُونُ وَرَقَّتْ الْقُلُوبُ وَلَّى فَأَدْرَكَهُ رَجُلٌ فَقَالَ أَيْ رَسُولَ اللَّهِ هَلْ فِي الْأَرْضِ أَحَدٌ أَعْلَمُ مِنْكَ قَالَ لَا فَعَتَبَ عَلَيْهِ إِذْ لَمْ يَرُدَّ الْعِلْمَ إِلَى اللَّهِ قِيلَ بَلَى قَالَ أَيْ رَبِّ فَأَيْنَ قَالَ بِمَجْمَعِ الْبَحْرَيْنِ قَالَ أَيْ رَبِّ اجْعَلْ لِي عَلَمًا أَعْلَمُ ذَلِكَ بِهِ فَقَالَ لِي عَمْرٌو قَالَ حَيْثُ يُفَارِقُكَ الْحُوتُ وَقَالَ لِي يَعْلَى قَالَ خُذْ نُونًا مَيِّتًا حَيْثُ يُنْفَخُ فِيهِ الرُّوحُ فَأَخَذَ حُوتًا فَجَعَلَهُ فِي مِكْتَلٍ فَقَالَ لِفَتَاهُ لَا أُكَلِّفُكَ إِلَّا أَنْ تُخْبِرَنِي بِحَيْثُ يُفَارِقُكَ الْحُوتُ قَالَ مَا كَلَّفْتَ كَثِيرًا فَذَلِكَ قَوْلُهُ جَلَّ ذِكْرُهُ{ وَإِذْ قَالَ مُوسَى لِفَتَاهُ }يُوشَعَ بْنِ نُونٍ لَيْسَتْ عَنْ سَعِيدٍ قَالَ فَبَيْنَمَا هُوَ فِي ظِلِّ صَخْرَةٍ فِي مَكَانٍ ثَرْيَانَ إِذْ تَضَرَّبَ الْحُوتُ وَمُوسَى نَائِمٌ فَقَالَ فَتَاهُ لَا أُوقِظُهُ حَتَّى إِذَا اسْتَيْقَظَ نَسِيَ أَنْ يُخْبِرَهُ وَتَضَرَّبَ الْحُوتُ حَتَّى دَخَلَ الْبَحْرَ فَأَمْسَكَ اللَّهُ عَنْهُ جِرْيَةَ الْبَحْرِ حَتَّى كَأَنَّ أَثَرَهُ فِي حَجَرٍ قَالَ لِي عَمْرٌو هَكَذَا كَأَنَّ أَثَرَهُ فِي حَجَرٍ وَحَلَّقَ بَيْنَ إِبْهَامَيْهِ وَاللَّتَيْنِ تَلِيَانِهِمَا{ لَقَدْ لَقِينَا مِنْ سَفَرِنَا هَذَا نَصَبًا }قَالَ قَدْ قَطَعَ اللَّهُ عَنْكَ النَّصَبَ لَيْسَتْ هَذِهِ عَنْ سَعِيدٍ أَخْبَرَهُ فَرَجَعَا فَوَجَدَا خَضِرًا قَالَ لِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ عَلَى طِنْفِسَةٍ خَضْرَاءَ عَلَى كَبِدِ الْبَحْرِ قَالَ سَعِيدُ بْنُ جُبَيْرٍ مُسَجًّى بِثَوْبِهِ قَدْ جَعَلَ طَرَفَهُ تَحْتَ رِجْلَيْهِ وَطَرَفَهُ تَحْتَ رَأْسِهِ فَسَلَّمَ عَلَيْهِ مُوسَى فَكَشَفَ عَنْ وَجْهِهِ وَقَالَ هَلْ بِأَرْضِي مِنْ سَلَامٍ مَنْ أَنْتَ قَالَ أَنَا مُوسَى قَالَ مُوسَى بَنِي إِسْرَائِيلَ قَالَ نَعَمْ قَالَ فَمَا شَأْنُكَ قَالَ جِئْتُ لِتُعَلِّمَنِي مِمَّا عُلِّمْتَ رَشَدًا قَالَ أَمَا يَكْفِيكَ أَنَّ التَّوْرَاةَ بِيَدَيْكَ وَأَنَّ الْوَحْيَ يَأْتِيكَ يَا مُوسَى إِنَّ لِي عِلْمًا لَا يَنْبَغِي لَكَ أَنْ تَعْلَمَهُ وَإِنَّ لَكَ عِلْمًا لَا يَنْبَغِي لِي أَنْ أَعْلَمَهُ فَأَخَذَ طَائِرٌ بِمِنْقَارِهِ مِنْ الْبَحْرِ وَقَالَ وَاللَّهِ مَا عِلْمِي وَمَا عِلْمُكَ فِي جَنْبِ عِلْمِ اللَّهِ إِلَّا كَمَا أَخَذَ هَذَا الطَّائِرُ بِمِنْقَارِهِ مِنْ الْبَحْرِ حَتَّى إِذَا رَكِبَا فِي السَّفِينَةِ وَجَدَا مَعَابِرَ صِغَارًا تَحْمِلُ أَهْلَ هَذَا السَّاحِلِ إِلَى أَهْلِ هَذَا السَّاحِلِ الْآخَرِ عَرَفُوهُ فَقَالُوا عَبْدُ اللَّهِ الصَّالِحُ قَالَ قُلْنَا لِسَعِيدٍ خَضِرٌ قَالَ نَعَمْ لَا نَحْمِلُهُ بِأَجْرٍ فَخَرَقَهَا وَوَتَدَ فِيهَا وَتِدًا قَالَ مُوسَى{ أَخَرَقْتَهَا لِتُغْرِقَ أَهْلَهَا لَقَدْ جِئْتَ شَيْئًا إِمْرًا }قَالَ مُجَاهِدٌ مُنْكَرًا{ قَالَ أَلَمْ أَقُلْ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِي صَبْرًا }كَانَتْ الْأُولَى نِسْيَانًا وَالْوُسْطَى شَرْطًا وَالثَّالِثَةُ عَمْدًا{ قَالَ لَا تُؤَاخِذْنِي بِمَا نَسِيتُ وَلَا تُرْهِقْنِي مِنْ أَمْرِي عُسْرًا }لَقِيَا غُلَامًا فَقَتَلَهُ قَالَ يَعْلَى قَالَ سَعِيدٌ وَجَدَ غِلْمَانًا يَلْعَبُونَ فَأَخَذَ غُلَامًا كَافِرًا ظَرِيفًا فَأَضْجَعَهُ ثُمَّ ذَبَحَهُ بِالسِّكِّينِ{ قَالَ أَقَتَلْتَ نَفْسًا زَكِيَّةً بِغَيْرِ نَفْسٍ }لَمْ تَعْمَلْ بِالْحِنْثِ وَكَانَ ابْنُ عَبَّاسٍ قَرَأَهَا زَكِيَّةً{ زَاكِيَةً }مُسْلِمَةً كَقَوْلِكَ غُلَامًا زَكِيًّا فَانْطَلَقَا فَوَجَدَا جِدَارًا يُرِيدُ أَنْ يَنْقَضَّ فَأَقَامَهُ قَالَ سَعِيدٌ بِيَدِهِ هَكَذَا وَرَفَعَ يَدَهُ فَاسْتَقَامَ قَالَ يَعْلَى حَسِبْتُ أَنَّ سَعِيدًا قَالَ فَمَسَحَهُ بِيَدِهِ فَاسْتَقَامَ{ لَوْ شِئْتَ لَاتَّخَذْتَ عَلَيْهِ أَجْرًا }قَالَ سَعِيدٌ أَجْرًا نَأْكُلُهُ{ وَكَانَ وَرَاءَهُمْ }وَكَانَ أَمَامَهُمْ قَرَأَهَا ابْنُ عَبَّاسٍ أَمَامَهُمْ مَلِكٌ يَزْعُمُونَ عَنْ غَيْرِ سَعِيدٍ أَنَّهُ هُدَدُ بْنُ بُدَدَ وَالْغُلَامُ الْمَقْتُولُ اسْمُهُ يَزْعُمُونَ جَيْسُورٌ{ مَلِكٌ يَأْخُذُ كُلَّ سَفِينَةٍ غَصْبًا }فَأَرَدْتُ إِذَا هِيَ مَرَّتْ بِهِ أَنْ يَدَعَهَا لِعَيْبِهَا فَإِذَا جَاوَزُوا أَصْلَحُوهَا فَانْتَفَعُوا بِهَا وَمِنْهُمْ مَنْ يَقُولُ سَدُّوهَا بِقَارُورَةٍ وَمِنْهُمْ مَنْ يَقُولُ بِالْقَارِ{ كَانَ أَبَوَاهُ مُؤْمِنَيْنِ }وَكَانَ كَافِرًا{ فَخَشِينَا أَنْ يُرْهِقَهُمَا طُغْيَانًا وَكُفْرًا }أَنْ يَحْمِلَهُمَا حُبُّهُ عَلَى أَنْ يُتَابِعَاهُ عَلَى دِينِهِ{ فَأَرَدْنَا أَنْ يُبَدِّلَهُمَا رَبُّهُمَا خَيْرًا مِنْهُ زَكَاةً }لِقَوْلِهِ{ أَقَتَلْتَ نَفْسًا زَكِيَّةً }{ وَأَقْرَبَ رُحْمًا }هُمَا بِهِ أَرْحَمُ مِنْهُمَا بِالْأَوَّلِ الَّذِي قَتَلَ خَضِرٌ وَزَعَمَ غَيْرُ سَعِيدٍ أَنَّهُمَا أُبْدِلَا جَارِيَةً وَأَمَّا دَاوُدُ بْنُ أَبِي عَاصِمٍ فَقَالَ عَنْ غَيْرِ وَاحِدٍ إِنَّهَا جَارِيَةٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka, dia berkata; Telah mengabarkan kepadaku [Ya'la bin Muslim] dan ['Amru bin Dinar] dari [Sa'id bin Jubair] salah satu dari mereka menambahkan yang lainnya, aku mendengarnya bercerita dari Sa'id bin Jubair dia berkata; sesungguhnya pada suatu saat aku berada di sisi Ibnu 'Abbas di rumahnya. Lalu ia berkata; 'Bertanyalah kepadaku, maka aku berkata; Wahai Ibnu 'Abbas semoga Allah menjadikanku sebagai tebusanmu, sungguh di Kufah ada seseorang yang bercerita, ia biasa di panggil Nauf, ia menganggap bahwa Musa 'Alaihis Salam yang berada di tengah kaum Bani Israil bukanlah Musa yang menyertai Nabi Khidhir.\" Sedangkan [Amru] berkata kepadaku; Ibnu Abbas berkata; Berdustalah musuh Allah. sedangkan [Ya'la] berkata kepadaku; bahwa [Ibnu Abbas] berkata; Telah menceritakan kepadaku [Ubay bin Ka'ab], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: “Musa adalah Utusan Allah, suatu ketika Nabi Musa 'Alaihis Salam berdiri untuk berpidato mengingatkan kaum Bani israil, hingga semua mata mencucurkan airnya dan semua hati pun merasa terharu. Setelah itu, seseorang bertanya kepadanya; “Wahai utusan Allah, Apakah dibumi ini ada orang lain yang lebih berilmu darimu?” Nabi Musa menjawab; “Tidak ada”. Oleh karena itu, Allah sangat mencela Musa 'Alaihis Salam. Karena ia tidak mengembalikan ilmu itu kepada Allah. Lantas ada suara \"Bahkan ada\". Musa bertanya \"Wahai Rabb-ku dimana orang itu?\" \"Ia berada di pertemuan dua lautan.' Nabi Musa 'Alaihis Salam bertanya; 'Ya Rabb-ku, berikan aku tanda-tanda agar dapat mengenalinya?'. [Amru] berkata kepadaku: “Allah berfirman: 'di tempat seekor ikan memisahkan diri darimu.” Sedangkan [Ya'la] berkata kepadaku; “Allah berfirman: 'Ambillah Nun yang sudah mati hingga ditiupkan ruh padanya'. Maka musa mengambilnya dan menempatkannya di dalam keranjang, kemudian dia berkata kepada pembantunya, aku tidak membebanimu kecuali engkau memberitahukan kepadaku tempat ikan tersebut memisahkan diri darimu. Maka pembantunya menjawab: “Engkau tidak membebaniku dengan sesuatu yang berat”. Yang demikian itu adalah firman Azza wajalla: “Dan ketika Musa berkata kepada pembantunya”. Yaitu Yusa bin Nun. Sedangkan riwayat selain dari Sa'id menerangkan: Ketika mereka berada di bayang-bayang batu besar di tempat yang airnya mengalir, pada saat itu ikan yang ada di dalam keranjang melompat-lompat, sedang Musa tertidur. Maka pembantunya berkata: “Aku tidak akan membangunkannya sampai ia bangun sendiri”, tetapi pembantunya rupanya lupa untuk memberitahukan kepada Musa sehingga ikan itu melompat-lompat hingga keluar dari keranjang dan terjebur ke laut. Tapi Allah subhanahu wa ta'ala menahan laju air laut itu, sehingga bekas laju ikan tersebut terbentuk. Sedangkan menurut ['Amru] dengan redaksi: “Seakan-akan bekasnya itu di atas batu”, kemudian dia melingkarkan dua ibu jarinya dan dua jari lainnya (hingga membentuk seperti lubang). Firman Allah subhanahu wata'ala: “(Musa berkata) Sesungguhnya kita sudah letih karena perjalanan kita ini”. Pembantunya berkata: “Allah subhanahu wata'ala telah menghilangkan kelelahan darimu. Dan redaksi ini bukan dari riwayat Sa'id. Kemudian mereka berdua kembali dan mereka menemukan Khidir. [Utsman bin Abi Sulaiman] berkata kepadaku: “Di atas permadani hijau di tengah-tengah laut”. Sedang [Sa'id bin Jubair] menerangkan: “Berselimutkan baju yang salah satu ujung bajunya diletakkan di bawah kedua kakinya, dan ujung lainnya di bawah kepalanya. Maka Musa mengucapkan salam kepadanya dan Khidir menyingkap wajahnya dan menjawab: “Apakah di bumiku keselamatan? Siapa anda?” Musa menjawab: “Saya Musa”, Khidir bertanya: “Musa bani Isra'il?” Nabi Musa menjawab; 'Ya.' Khidir bertanya lagi: “Apa keperluanmu?” Musa menjawab: “Aku mendatangimu agar engkau mengajarkan kepadaku ilmu-ilmu yang diajarkan kepadamu.” Khidir berkata: “Apakah tidak cukup dengan Taurat di tanganmu? Dan wahyu pun turun kepadamu wahai Musa. Sesungguhnya aku memiliki ilmu yang tidak layak bagimu untuk mengetahuinya, dan kamupun memiliki ilmu yang tidak layak bagiku untuk mengetahuinya”. Tiba-tiba seekor burung menukik dengan paruhnya mengambil setetes air di tengah laut. Khidir melanjutkan: “Demi Allah ilmumu dan ilmuku tidak ada apa-apanya dengan ilmu Allah subhanahu wata'ala kecuali seperti burung ini yang menukik dengan paruhnya mengambil setetes air di tengah laut. Sehingga ketika mereka menaiki perahu mereka berdua menemukan kapal kecil yang mengantarkan penduduk yang berada di tepi pantai ini menuju ke tepi pantai lainnya, dan rupanya mereka mengenali Khidir maka mereka berkata: “Hamba Allah yang shaleh”. Ya'la berkata: Kami bertanya kepada Sa'id; “Khidir?” ia menjawab: “Ya”. Maka mereka berkata kami membawanya dengan tidak mengambil upah. Tetapi Khidir membakarnya dan melubanginya, maka Musa bertanya kepadanya; “kepana kamu membakarnya untuk menenggelamkan penumpangnya. Sungguh kamu telah melakukan sesuatu yang sangat berbahaya.” Mujahid menerangkan; Mungkar. Allah berfirman; “bukankah aku telah berkata kepadamu; bahwasanya kamu tidak akan mampu untuk bersabar bersamaku?” ini merupakan kejadian pertama tentang lupanya Musa terhadap perjanjian awwalnya, sedang yang pertengahan adalah syarat,  sedang yang ketiga adalah kesengajaan. Allah berfirman; “Musa berkata; “ janganlah kamu menghukumku karena kelupaanku, dan janganlah kamu membebani aku dengan kesuslitan dalam urursanku.” Kemudian mereka berjumpa dengan seorang anak kecil, maka Khidir membunuhnya. Ya'la berkata; menurut fersi Sa'id, dengan redaksi; anak-anak kecil yang sedang bermain, kemudian Khidir mengambil seorang anak kecil yang kafir, kemudian dia membaringkannya dan menyembelihnya dengan pisau. Allah berfirman; “maka (Musa) berkata;   apakah kamu membunuh jiwa yang suci (padahal dia) tidak (membunuh) jiwa.”  Jiwa itu tidak melakukan perbuatan keji. [Ibnu Abbas] membacanya dengan lafazh; “Zakiyyatan” sedang dalam Mushhaf tertulis “Zaakiyatan” yang suci lagi muslim, sebagaimana perkataanmu; ghulaaman zakiyyan. Kemudian keduanya bergegas pergi, (di tengah perjalanan mereka) menemukan tembok yang hendak roboh, maka Khidir menegakkannya kembali. Menurut riwayat [Sa'id] dengan redaksi; dengan tangannya, seperti ini. Dia mengangkat tangannya dan meluruskannya. [Ya'la] berkata; aku mengira Sa'id berkata; maka dia mengusapnya dengan tangannya, sehingga menjadi tegak berdiri. Allah berfirman: “(musa berkata;) sekiranya kamu mau, maka kamu dapat menambil upah dari itu.” [Sa'id] menjelaskan; “upah yang dapat kita makan.” Allah berfirman; “dan di belakang mereka” dan di hadapan mereka. Sedang [Ibnu Abbas] membacanya dengan lafazh; amamahum malikun. Para perawi selain Sa'id menjelaskan, bahwa (raja tersebut) adalah Hudad bin Budad, sedang anak kecil yang di bunuh namanya Jaisur. Allah berfirman; “seorang raja yang merampas setiap perahu secara paksa.” Maka aku ingin jika perahu ini melewatinya, raja tersebut meninggalkannya karena terdapat cacat di perahu tersebut. Maka apabila mereka dapat melewatinya mereka dapat membenahinya dan dapat memanfa'atkannya kembali. Dan diantara mereka ada yang berkata; tutuplah denan botol, dan diantara mereka ada yang berkata; tutuplah dengan al Qaar. Allah berfirman; “dan kedua orang tuanya adalah mu`min” sedang anaknya kafir, Allah berfirman ”maka kami khawatir dia akan memaksa kedua orang tuanya untuk berbuat kesesatan dan kekafiran.” Kecintaan kepadanya akan mendorong keduanya untuk mengikuti anak tersebut dalam agamanya. Allah berfirman: “maka kami ingin Rabb orang tuanya menggantikan anak tersebut dengan yang lebih baik dan lebih suci” untuk jawaban pertanyaan Musa; “apakah kamu membunuh jiwa yang suci?” “dan lebih dalam kasih sayang” keduanya kepada anaknya lebih sayang dari keduanya terhadap yang pertama yang telah di bunuh oleh Khidir.” Sedang selain Sa'id mengira bahwa keduanya di berikan ganti dengan seorang anak perempuan. Sedangkan Daud bin Abi 'Ashim berkata; dari beberapa orang berpendapat bahwasa (penggantinya) adalah seorang anak perempuan."},"4053":{"ar":"حَدَّثَنِي قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنِي سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍإِنَّ نَوْفًا الْبَكَالِيَّ يَزْعُمُ أَنَّ مُوسَى بَنِي إِسْرَائِيلَ لَيْسَ بِمُوسَى الْخَضِرِ فَقَالَ كَذَبَ عَدُوُّ اللَّهِ حَدَّثَنَا أُبَيُّ بْنُ كَعْبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَامَ مُوسَى خَطِيبًا فِي بَنِي إِسْرَائِيلَ فَقِيلَ لَهُ أَيُّ النَّاسِ أَعْلَمُ قَالَ أَنَا فَعَتَبَ اللَّهُ عَلَيْهِ إِذْ لَمْ يَرُدَّ الْعِلْمَ إِلَيْهِ وَأَوْحَى إِلَيْهِ بَلَى عَبْدٌ مِنْ عِبَادِي بِمَجْمَعِ الْبَحْرَيْنِ هُوَ أَعْلَمُ مِنْكَ قَالَ أَيْ رَبِّ كَيْفَ السَّبِيلُ إِلَيْهِ قَالَ تَأْخُذُ حُوتًا فِي مِكْتَلٍ فَحَيْثُمَا فَقَدْتَ الْحُوتَ فَاتَّبِعْهُ قَالَ فَخَرَجَ مُوسَى وَمَعَهُ فَتَاهُ يُوشَعُ بْنُ نُونٍ وَمَعَهُمَا الْحُوتُ حَتَّى انْتَهَيَا إِلَى الصَّخْرَةِ فَنَزَلَا عِنْدَهَا قَالَ فَوَضَعَ مُوسَى رَأْسَهُ فَنَامَ قَالَ سُفْيَانُ وَفِي حَدِيثِ غَيْرِ عَمْرٍو قَالَ وَفِي أَصْلِ الصَّخْرَةِ عَيْنٌ يُقَالُ لَهَا الْحَيَاةُ لَا يُصِيبُ مِنْ مَائِهَا شَيْءٌ إِلَّا حَيِيَ فَأَصَابَ الْحُوتَ مِنْ مَاءِ تِلْكَ الْعَيْنِ قَالَ فَتَحَرَّكَ وَانْسَلَّ مِنْ الْمِكْتَلِ فَدَخَلَ الْبَحْرَ فَلَمَّا اسْتَيْقَظَ مُوسَى قَالَ{ لِفَتَاهُ آتِنَا غَدَاءَنَا }الْآيَةَ قَالَ وَلَمْ يَجِدْ النَّصَبَ حَتَّى جَاوَزَ مَا أُمِرَ بِهِ قَالَ لَهُ فَتَاهُ يُوشَعُ بْنُ نُونٍ{ أَرَأَيْتَ إِذْ أَوَيْنَا إِلَى الصَّخْرَةِ فَإِنِّي نَسِيتُ الْحُوتَ }الْآيَةَ قَالَ فَرَجَعَا يَقُصَّانِ فِي آثَارِهِمَا فَوَجَدَا فِي الْبَحْرِ كَالطَّاقِ مَمَرَّ الْحُوتِ فَكَانَ لِفَتَاهُ عَجَبًا وَلِلْحُوتِ سَرَبًا قَالَ فَلَمَّا انْتَهَيَا إِلَى الصَّخْرَةِ إِذْ هُمَا بِرَجُلٍ مُسَجًّى بِثَوْبٍ فَسَلَّمَ عَلَيْهِ مُوسَى قَالَ وَأَنَّى بِأَرْضِكَ السَّلَامُ فَقَالَ أَنَا مُوسَى قَالَ مُوسَى بَنِي إِسْرَائِيلَ قَالَ نَعَمْ قَالَ هَلْ أَتَّبِعُكَ عَلَى أَنْ تُعَلِّمَنِي مِمَّا عُلِّمْتَ رَشَدًا قَالَ لَهُ الْخَضِرُ يَا مُوسَى إِنَّكَ عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَكَهُ اللَّهُ لَا أَعْلَمُهُ وَأَنَا عَلَى عِلْمٍ مِنْ عِلْمِ اللَّهِ عَلَّمَنِيهِ اللَّهُ لَا تَعْلَمُهُ قَالَ بَلْ أَتَّبِعُكَ قَالَ{ فَإِنْ اتَّبَعْتَنِي فَلَا تَسْأَلْنِي عَنْ شَيْءٍ حَتَّى أُحْدِثَ لَكَ مِنْهُ ذِكْرًا }فَانْطَلَقَا يَمْشِيَانِ عَلَى السَّاحِلِ فَمَرَّتْ بِهِمْ سَفِينَةٌ فَعُرِفَ الْخَضِرُ فَحَمَلُوهُمْ فِي سَفِينَتِهِمْ بِغَيْرِ نَوْلٍ يَقُولُ بِغَيْرِ أَجْرٍ فَرَكِبَا السَّفِينَةَ قَالَ وَوَقَعَ عُصْفُورٌ عَلَى حَرْفِ السَّفِينَةِ فَغَمَسَ مِنْقَارَهُ فِي الْبَحْرِ فَقَالَ الْخَضِرُ لِمُوسَى مَا عِلْمُكَ وَعِلْمِي وَعِلْمُ الْخَلَائِقِ فِي عِلْمِ اللَّهِ إِلَّا مِقْدَارُ مَا غَمَسَ هَذَا الْعُصْفُورُ مِنْقَارَهُ قَالَ فَلَمْ يَفْجَأْ مُوسَى إِذْ عَمَدَ الْخَضِرُ إِلَى قَدُومٍ فَخَرَقَ السَّفِينَةَ فَقَالَ لَهُ مُوسَى قَوْمٌ حَمَلُونَا بِغَيْرِ نَوْلٍ عَمَدْتَ إِلَى سَفِينَتِهِمْ فَخَرَقْتَهَا{ لِتُغْرِقَ أَهْلَهَا لَقَدْ جِئْتَ }الْآيَةَ فَانْطَلَقَا إِذَا هُمَا بِغُلَامٍ يَلْعَبُ مَعَ الْغِلْمَانِ فَأَخَذَ الْخَضِرُ بِرَأْسِهِ فَقَطَعَهُ قَالَ لَهُ مُوسَى{ أَقَتَلْتَ نَفْسًا زَكِيَّةً بِغَيْرِ نَفْسٍ لَقَدْ جِئْتَ شَيْئًا نُكْرًا قَالَ أَلَمْ أَقُلْ لَكَ إِنَّكَ لَنْ تَسْتَطِيعَ مَعِي صَبْرًا إِلَى قَوْلِهِ فَأَبَوْا أَنْ يُضَيِّفُوهُمَا فَوَجَدَا فِيهَا جِدَارًا يُرِيدُ أَنْ يَنْقَضَّ }فَقَالَ بِيَدِهِ هَكَذَا فَأَقَامَهُ فَقَالَ لَهُ مُوسَى إِنَّا دَخَلْنَا هَذِهِ الْقَرْيَةَ فَلَمْ يُضَيِّفُونَا وَلَمْ يُطْعِمُونَا{ لَوْ شِئْتَ لَاتَّخَذْتَ عَلَيْهِ أَجْرًا قَالَ هَذَا فِرَاقُ بَيْنِي وَبَيْنِكَ سَأُنَبِّئُكَ بِتَأْوِيلِ مَا لَمْ تَسْتَطِعْ عَلَيْهِ صَبْرًا }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدِدْنَا أَنَّ مُوسَى صَبَرَ حَتَّى يُقَصَّ عَلَيْنَا مِنْ أَمْرِهِمَا قَالَ وَكَانَ ابْنُ عَبَّاسٍ يَقْرَأُ وَكَانَ أَمَامَهُمْ مَلِكٌ يَأْخُذُ كُلَّ سَفِينَةٍ صَالِحَةٍ غَصْبًا وَأَمَّا الْغُلَامُ فَكَانَ كَافِرًا","id":"Telah menceritakan kepadaku [Qutaibah bin Sa'id] dia berkata; Telah menceritakan kepadaku [Sufyan bin 'Uyainah] dari ['Amru bin Dinar] dari [Sa'id bin Jubair] dia berkata; \"Saya telah berkata kepada [Ibnu Abbas] bahwasanya Nauf Al Bikali mengatakan bahwa Musa 'Alaihis Salam yang berada di tengah kaum Bani Israil bukanlah Musa yang menyertai Nabi Khidhir.\" Ibnu Abbas berkata; 'Berdustalah musuh Allah. Telah menceritakan kepada kami [Ubay bin Ka'ab] dari Rasulullah shallallahu 'alaihi wasallam bersabda: 'Suatu ketika Nabi Musa 'Alaihis Salam berdiri untuk berpidato di hadapan kaum Bani israil.' Setalah itu, seseorang bertanya kepadanya; 'Hai Musa, siapakah orang yang paling banyak ilmunya di muka bumi ini? ' Nabi Musa menjawab; 'Akulah orang yang paling banyak ilmunya di muka bumi ini.' Rasulullah shallallahu 'alaihi wasallam berkata: Oleh karena itu, Allah sangat mencela Musa 'Alaihis Salam. Karena ia tidak menyadari bahwa ilmu yang diperolehnya itu adalah pemberian Allah. Lalu Allah mewahyukan kepada Musa; 'Hai Musa, sesungguhnya ada seorang hamba-Ku yang lebih banyak ilmunya dan lebih pandai darimu dan ia sekarang berada di pertemuan dua lautan.' Nabi Musa 'Alaihis Salam bertanya; 'Ya Tuhan, bagaimana caranya saya dapat bertemu dengan hambaMu itu? ' Dijawab; 'bawalah seekor ikan di dalam keranjang dari daun kurma. Manakala ikan tersebut lompat, maka di situlah hambaKu berada.' Kemudian Musa pun berangkat ke tempat itu dengan ditemani seorang muridnya yang bernama Yusya' bin Nun. Nabi Musa sendiri membawa seekor ikan di dalam keranjang yang terbuat dari daun kurma. Keduanya berjalan kaki menuju tempat tersebut. Ketika keduanya sampai di sebuah batu besar, maka keduanya pun tertidur lelap. Sufyan berkata pada hadits selain hadits Amru, dia berkata; Tiba-tiba ikan yang berada di dalam keranjang tersebut berguncang keluar, lalu masuk ke dalam air laut. Rasulullah shallallahu 'alaihi wasallam berkata: 'Allah telah menahan air yang dilalui ikan tersebut, hingga menjadi terowongan. Ikan itu menempuh jalannya di lautan, sementara Musa dan muridnya kagum melihat pemandangan yang unik itu. Akhirnya mereka berdua melanjutkan perjalanannya siang dan malam. Rupanya murid Nabi Musa lupa untuk memberitahukannya. Pada pagi harinya, Nabi Musa berkata kepada muridnya; 'Bawalah makanan kita kemari! Sesungguhnya kita merasa letih karena perjalanan kita ini.' Rasulullah shallallahu 'alaihi wasallam berkata: 'Belum berapa jauh Musa melewati tempat yang diperintahkan untuk mencarinya, muridnya berkata; 'Tahukah Anda tatkala kita mencari tempat berlindung di batu besar tadi, maka sesungguhnya saya lupa menceritakan tentang ikan itu dan tidak ada yang membuat saya lupa untuk menceritakannya kecuali syetan, sedangkan ikan tersebut mengambil jalannya ke laut dengan cara yang aneh sekali.' Musa berkata; 'Itulah tempat yang sedang kita cari.' Lalu keduanya kembali mengikuti jalan mereka semula. Rasulullah shallallahu 'alaihi wasallam berkata: 'Kemudian keduanya menelusuri jejak mereka semula.' Setelah keduanya tiba di batu besar tadi, maka mereka melihat seorang laki-laki yang sedang tertidur berselimutkan kain. Lalu Nabi Musa 'Alaihis Salam mengucapkan salam kepadanya. Nabi Khidhir bertanya kepada Musa; 'Dari manakah salam di negerimu? ' Musa berkata; 'Saya adalah Musa.' Nabi Khidhir terperanjat dan bertanya; 'Musa Bani Israil.' Nabi Musa menjawab; 'Ya.' Nabi Khidhir berkata kepada Musa; 'Sesungguhnya kamu mendapatkan sebagian ilmu Allah yang diajarkanNya kepadamu yang tidak aku ketahui dan aku mendapatkan sebagian ilmu Allah yang diajarkanNya kepadaku yang kamu tidak ketahui.' Musa berkata kepada Khidhir; 'Bolehkah aku mengikutimu agar kamu dapat mengajarkan kepadaku ilmu yang benar di antara ilmu-ilmu yang telah diajarkan kepadamu? ' Nabi Khidhir menjawab; 'Sesungguhnya sekali-kali kamu tidak akan sanggup dan sabar bersamaku. Bagaimana kamu bisa sabar atas sesuatu yang kamu belum mempunyai pengetahuan yang cukup tentang hal itu? ' Musa berkata; 'Insya Allah kamu akan mendapatiku sebagai orang yang sabar dan aku pun tidak akan menentangmu dalam suatu urusan pun.' Khidhir menjawab; 'Jika kamu tetap mengikutiku, maka janganlah kamu menanyakan sesuatu hingga aku sendiri yang akan menerangkannya kepadamu.' Musa menjawab; 'Baiklah.' Rasulullah shallallahu 'alaihi wasallam berkata: 'Kemudian Musa dan Khidhir berjalan menusuri pantai. Tak lama kemudian ada sebuah perahu yang lewat. Lalu keduanya meminta tumpangan perahu. Ternyata orang-orang perahu itu mengenal baik Nabi Khidhir, hingga akhirnya mereka mengangkut keduanya tanpa meminta upah.' Lalu Nabi Khidhir mendekat ke salah satu papan di bagian perahu itu dan setelah itu mencabutnya. Melihat hal itu, Musa menegur dan memarahinya; 'Mereka ini adalah orang-orang yang mengangkut kita tanpa meminta upah, tetapi mengapa kamu malah melubangi perahu mereka untuk kamu tenggelamkan penumpangnya? ' Khidhir menjawab; 'Bukankah telah aku katakan kepadamu bahwasanya kamu sekali-kali tidak akan sabar ikut bersamaku.' Musa berkata sambil merayu; 'Janganlah kamu menghukumku karena kealpaanku dan janganlah kamu membebaniku dengan suatu kesulitan dalam urusanku.' Tak lama kemudian, keduanya pun turun dari perahu tersebut. Ketika keduanya sedang berjalan-jalan di tepi pantai, tiba-tiba ada seorang anak kecil yang sedang bermain dengan teman-temannya yang lain. Kemudian, Nabi Khidhir segera memegang dan membekuk kepala anak kecil itu dengan tangannya hingga menemui ajalnya. Dengan gusarnya Nabi Musa berupaya menghardik Nabi Khidhir; 'Mengapa kamu bunuh jiwa yang tak berdosa, sedangkan anak kecil itu belum pernah membunuh? Sungguh kamu telah melakukan perbuatan yang munkar? ' Khidhir berkata; 'Bukankah sudah aku katakan bahwasanya kamu tidak akan mampu untuk bersabar dalam mengikutiku. Dan ini melebihi dari yang sebelumnya.' Musa berkata; 'Jika aku bertanya kepadamu tentang sesuatu setelah ini, maka janganlah kamu perbolehkan aku untuk menyertaimu. Sesungguhnya kamu sudah cukup memberikan uzur (maaf) kepadaku.' Selanjutnya Nabi Musa dan Khidhir melanjutkan perjalanannya. Ketika kami berdua tiba di suatu negeri, maka keduanya pun meminta jamuan dari penduduk negeri tersebut, tapi sayangnya mereka enggan menjamu keduanya. Lalu keduanya mendapatkan sebuah dinding rumah yang hampir roboh dan Nabi Khidhir pun langsung menegakkannya (memperbaikinya). Rasulullah shallallahu 'alaihi wasallam bersabda: 'Dinding itu miring (sambil memberi isyarat dengan tangannya) lalu ditegakkan oleh Khidhir.' Musa berkata kepada Khidhir; 'Kamu telah mengetahui bahwa para penduduk negeri yang kita datangi ini enggan menyambut dan menjamu kita. Kalau kamu mau, sebaiknya kamu minta upah dari hasil perbaikan dinding rumah tersebut. Akhirnya Khidhir berkata; 'Inilah perpisahan antara aku dan kamu. Aku akan beritahukan kepadamu tentang rahasia segala perbuatan yang kamu tidak sabar terhadapnya.' Rasulullah shallallahu 'alaihi wasallam berkata: 'Semoga Allah memberikan rahmat dan karuniaNya kepada Nabi Musa 'Alaihis Salam. Sebenarnya aku lebih senang jika Musa dapat sedikit bersabar, hingga kisah Musa dan Khidhir bisa diceritakan kepada kita dengan lebih panjang lagi. Ubay bin Ka'ab berkata; 'Rasulullah shallallahu 'alaihi wasallam bersabda: 'Penyebab perpisahan tersebut adalah karena Musa alpa.' Rasulullah shallallahu 'alaihi wasallam berkata: 'Tak lama kemudian, datanglah burung kecil tersebut mematuk air laut dengan paruhnya. Lalu Khidhir berkata kepada Musa; 'Sesungguhnya ilmuku dan ilmumu dan ilmu yang kita peroleh dari Allah itu hanyalah seperti seteguk air laut yang diperoleh burung kecil itu di antara hamparan lautan ilmu yang dimiliki Allah.' Sa'id bin Zubair berkata; 'Ibnu Abbas membacakan ayat Al Qur'an yang artinya; 'Di depan mereka ada seorang penguasa yang merampas setiap perahu yang bagus. Dan adapun 'Anak kecil yang dibunuh Nabi Khidhir itu adalah kafir.'"},"4054":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ مُصْعَبِ بْنِ سَعْدٍ قَالَ سَأَلْتُ أَبِي{ قُلْ هَلْ نُنَبِّئُكُمْ بِالْأَخْسَرِينَ أَعْمَالًا }هُمْ الْحَرُورِيَّةُ قَالَ لَا هُمْ الْيَهُودُ وَالنَّصَارَى أَمَّا الْيَهُودُ فَكَذَّبُوا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّا النَّصَارَى فَكَفَرُوا بِالْجَنَّةِ وَقَالُوا لَا طَعَامَ فِيهَا وَلَا شَرَابَ وَالْحَرُورِيَّةُ{ الَّذِينَ يَنْقُضُونَ عَهْدَ اللَّهِ مِنْ بَعْدِ مِيثَاقِهِ }وَكَانَ سَعْدٌ يُسَمِّيهِمْ الْفَاسِقِينَ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Mush'ab bin Sa'ad] dia berkata; Aku bertanya kepada Bapakku mengenai firman Allah; Katakanlah: \"Apakah akan Kami beritahukan kepadamu tentang orang-orang yang paling merugi perbuatannya?\" apakah mereka orang Harury (nama sebuah desa kaum khawarij)? [Bapakku] menjawab; bukan, mereka adalah Yahudi dan Nashrani. Adapun orang-orang Yahudi, mereka telah mendustakan Nabi shallallahu 'alaihi wasallam. Sedangkan Nashrani mereka telah mengingkari surga. Mereka mengatakan; didalamnya tidak ada makanan dan minuman. Adapun Haruriy mereka adalah orang-orang yang melanggar perjanjian Allah sesudah perjanjian itu teguh... dan Sa'ad menamakan mereka sebagai orang-orang yang fasik."},"4055":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهُ لَيَأْتِي الرَّجُلُ الْعَظِيمُ السَّمِينُ يَوْمَ الْقِيَامَةِ لَا يَزِنُ عِنْدَ اللَّهِ جَنَاحَ بَعُوضَةٍ وَقَالَ اقْرَءُوا{ فَلَا نُقِيمُ لَهُمْ يَوْمَ الْقِيَامَةِ وَزْنًا }وَعَنْ يَحْيَى بْنِ بُكَيْرٍ عَنْ الْمُغِيرَةِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah] Telah menceritakan kepada kami [Sa'id bin Abu Maryam] Telah mengabarkan kepada kami [Al Mughirah bin 'Abdur Rahman] dia berkata; Telah menceritakan kepadaku [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh pada hari kiamat akan datang seseorang yang berbadan gemuk namun di sisi Allah timbangannya tidak dapat melebihi berat sayap seekor nyamuk. Bacalah ayat; …dan kami tidak memberikan penimbangan terhadap (amal) mereka pada hari kiamat, (Al Kahfi: 105). Dan dari [Yahya bin Bukair] dari [Al Mughirah bin Abdurrahman] dari [Abu Az Zinad] dengan Hadits yang serupa."},"4056":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِالْمَوْتِ كَهَيْئَةِ كَبْشٍ أَمْلَحَ فَيُنَادِي مُنَادٍ يَا أَهْلَ الْجَنَّةِ فَيَشْرَئِبُّونَ وَيَنْظُرُونَ فَيَقُولُ هَلْ تَعْرِفُونَ هَذَا فَيَقُولُونَ نَعَمْ هَذَا الْمَوْتُ وَكُلُّهُمْ قَدْ رَآهُ ثُمَّ يُنَادِي يَا أَهْلَ النَّارِ فَيَشْرَئِبُّونَ وَيَنْظُرُونَ فَيَقُولُ هَلْ تَعْرِفُونَ هَذَا فَيَقُولُونَ نَعَمْ هَذَا الْمَوْتُ وَكُلُّهُمْ قَدْ رَآهُ فَيُذْبَحُ ثُمَّ يَقُولُ يَا أَهْلَ الْجَنَّةِ خُلُودٌ فَلَا مَوْتَ وَيَا أَهْلَ النَّارِ خُلُودٌ فَلَا مَوْتَ ثُمَّ قَرَأَ{ وَأَنْذِرْهُمْ يَوْمَ الْحَسْرَةِ إِذْ قُضِيَ الْأَمْرُ وَهُمْ فِي غَفْلَةٍ }وَهَؤُلَاءِ فِي غَفْلَةٍ أَهْلُ الدُّنْيَا{ وَهُمْ لَا يُؤْمِنُونَ }","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Abu Shalih] dari [Abu Sa'id Al Khudri radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Kematian didatangkan pada hari kiamat seperti kambing kelabu. Kemudian dikatakan: Wahai penduduk surga! maka mereka melihat dengan mendongak, lalu dikatakan; apa kalian mengetahui ini? mereka menjawab: 'Ya, itu adalah kematian.' Dan semuanya telah melihatnya. kemudian dikatakan kepada penduduk neraka: 'Wahai penghuni neraka, apa kalian mengetahui ini? ' Mereka melihat dengan mendongak, mereka menjawab: 'Ya, ' itu adalah kematian.' Dan semuanya telah melihatnya. Lalu kematian itu disembelih. Setelah itu dikatakan: 'Wahai penduduk surga, kekal tidak ada ada kematian dan wahai penduduk neraka, kekal tidak ada kematian'.\" Setelah itu beliau membaca: \"Dan berilah mereka peringatan tentang hari penyesalan, (yaitu) ketika segala perkara telah diputus dan mereka dalam kelalaian dan mereka tidak (pula) beriman.\" (Maryam: 39). Merekalah penduduk dunia yang lalai dan mereka tidak beriman."},"4057":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ قَالَ سَمِعْتُ أَبِي عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِجِبْرِيلَ مَا يَمْنَعُكَ أَنْ تَزُورَنَا أَكْثَرَ مِمَّا تَزُورُنَا فَنَزَلَتْ{ وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ لَهُ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا }","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami ['Umar bin Dzar] dia berkata; Aku mendengar [ayahku] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bertanya kepada Jibril 'Alaihissalam: \"Mengapa engkau tidak sering lagi mengunjungiku sebagaimana biasanya?\" Lalu turunlah ayat: Dan tidaklah kami (Jibril) turun, kecuali dengan perintah Tuhanmu. kepunyaan-Nyalah apa-apa yang ada di hadapan kita, dan apa-apa yang ada di belakang kita. (Maryam: 64)."},"4058":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ سَمِعْتُ خَبَّابًا قَالَجِئْتُ الْعَاصَ بْنَ وَائِلٍ السَّهْمِيَّ أَتَقَاضَاهُ حَقًّا لِي عِنْدَهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَا حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَيِّتٌ ثُمَّ مَبْعُوثٌ قُلْتُ نَعَمْ قَالَ إِنَّ لِي هُنَاكَ مَالًا وَوَلَدًا فَأَقْضِيكَهُ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }رَوَاهُ الثَّوْرِيُّ وَشُعْبَةُ وَحَفْصٌ وَأَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dia berkata; Aku mendengar [Khabbab] dia berkata; Aku menemui Al 'Ash bin Wail As Sahmi untuk menuntut hakku padanya lalu ia mengatakan \"Aku tidak akan memberikannya sehingga kamu kafir terhadap Muhammad.\" Maka kukatakan; \"Tidak, sampai kamu mati dan dibangkitkan kembali.\" Dia berkata; \"Apakah jika aku mati akan dibangkitkan kembali?\" 'ya, ' jawabku.\"Sesungguhnya aku masih memiliki harta dan anak karena itu akan aku bayarkan padamu.\" Maka turunlah (ayat): Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat Kami dan ia mengatakan: \"Pasti aku akan diberi harta dan anak\". (Maryam: 77). diriwayatkan oleh [Ats Tsauri], [Syu'bah], [Hafsh], [Abu Mu'awiyah] dan [Waki'] dari [Al A'masy]."},"4059":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا بِمَكَّةَ فَعَمِلْتُ لِلْعَاصِ بْنِ وَائِلٍ السَّهْمِيِّ سَيْفًا فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قُلْتُ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يُحْيِيَكَ قَالَ إِذَا أَمَاتَنِي اللَّهُ ثُمَّ بَعَثَنِي وَلِي مَالٌ وَوَلَدٌ فَأَنْزَلَ اللَّهُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا }قَالَ مَوْثِقًالَمْ يَقُلْ الْأَشْجَعِيُّ عَنْ سُفْيَانَ سَيْفًا وَلَا مَوْثِقًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi di Makkah, dan aku membuatkan sebilah pedang untuk Al Ash bin Wa'il As Sahmi. Tatkala aku mendatanginya untuk menagih bayarannya, dia berkata; \"Aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu dimatikan Allah kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Kalau begitu tunggulah sampai aku mati dan dibangkitkan kembali hingga aku diberi harta dan anak, maka aku akan membayarmu. Maka turunlah ayat ini: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah?. (QS. Maryam: 77-78). Khabab berkata; Yaitu ikatan janji. Namun [Al Asyja'i] tidak menyebutkan lafazh 'saif' (pedang) dan 'Mautsiq' (perjanjian)."},"4060":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ سَمِعْتُ أَبَا الضُّحَى يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي دَيْنٌ عَلَى الْعَاصِ بْنِ وَائِلٍ قَالَ فَأَتَاهُ يَتَقَاضَاهُ فَقَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَاللَّهِ لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ يَبْعَثَكَ قَالَ فَذَرْنِي حَتَّى أَمُوتَ ثُمَّ أُبْعَثَ فَسَوْفَ أُوتَى مَالًا وَوَلَدًا فَأَقْضِيكَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا }","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] Aku mendengar [Abu Adl Dluha] bercerita dari [Masruq] dari [Khabbab] dia berkata; \"Pada masa Jahiliyah aku adalah seorang pandai besi, dan Al Ash bin Wa'il mempunyai hutang kepadaku. Khabab berkata; maka aku datang kepadanya untuk menagihnya, namun dia berkata; \"Aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu dimatikan Allah kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Kalau begitu tunggulah sampai aku mati dan dibangkitkan kembali hingga aku diberi harta dan anak, maka aku akan membayarmu. Maka turunlah ayat ini: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. (QS. Maryam: 77)."},"4061":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ رَجُلًا قَيْنًا وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ فَقَالَ لِي لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ لَنْ أَكْفُرَ بِهِ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ وَإِنِّي لَمَبْعُوثٌ مِنْ بَعْدِ الْمَوْتِ فَسَوْفَ أَقْضِيكَ إِذَا رَجَعْتُ إِلَى مَالٍ وَوَلَدٍ قَالَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا كَلَّا سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُ مِنْ الْعَذَابِ مَدًّا وَنَرِثُهُ مَا يَقُولُ وَيَأْتِينَا فَرْدًا }","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari [Khabbab] dia berkata; \"Aku adalah seorang pandai besi yang bekerja untuk Al Ash bin Wa'il, ketika aku datang untuk menagih gajiku, dia berkata; \"Tidak, demi Allah aku tidak akan membayarkannya sampai kamu mendustakan Muhammad.\" Khabab berkata; \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan kembali.\" Al Ash bin Wa`il berkata; \"Apabila aku mati dan dibangkitkan serta dapat kembali kepada harta dan anakku, maka baru aku akan membayarmu!\" Khabbab berkata; maka turunlah ayat: 'Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak. Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan Yang Maha Pemurah? sekali-kali tidak, Kami akan menulis apa yang ia katakan, dan benar-benar Kami akan memperpanjang azab untuknya, dan Kami akan mewarisi apa yang ia katakan itu, dan ia akan datang kepada Kami dengan seorang diri. (QS. Maryam: 77-80)."},"4062":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْتَقَى آدَمُ وَمُوسَى فَقَالَ مُوسَى لِآدَمَ آنْتَ الَّذِي أَشْقَيْتَ النَّاسَ وَأَخْرَجْتَهُمْ مِنْ الْجَنَّةِ قَالَ آدَمُ أَنْتَ مُوسَى الَّذِي اصْطَفَاكَ اللَّهُ بِرِسَالَتِهِ وَاصْطَفَاكَ لِنَفْسِهِ وَأَنْزَلَ عَلَيْكَ التَّوْرَاةَ قَالَ نَعَمْ قَالَ فَوَجَدْتَهَا كُتِبَ عَلَيَّ قَبْلَ أَنْ يَخْلُقَنِي قَالَ نَعَمْ فَحَجَّ آدَمُ مُوسَى","id":"Telah menceritakan kepada kami [Ash Shalt bin Muhammad] Telah menceritakan kepada kami [Mahdi bin Maimun] Telah menceritakan kepada kami [Muhammad bin Sirin] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adam dan Musa bertemu, Musa berkata kepada Adam; 'Wahai Adam, engkaulah orang yang telah mencelakakan manusia dan mengeluarkan mereka dari surga.' Lalu Adam ganti berkata kepada Musa; 'Wahai Musa, Bukankah Allah telah memilihmu dengan risalah dan kalam-Nya (diajak bicara secara langsung), dan Allah juga telah menurunkan kepadamu Taurat? Musa menjawab; 'Ya.' Adam berkata lagi; Bukankah kamu mendapatkan di dalamnya bahwa hal itu telah ditetapkan kepadaku sebelum aku diciptakan? Musa menjawab: 'Ya.' Beliau bersabda: \"Maka Adam dapat mengalahkan Musa.\""},"4063":{"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَالْيَهُودُ تَصُومُ يَوْمَ عَاشُورَاءَ فَسَأَلَهُمْ فَقَالُوا هَذَا الْيَوْمُ الَّذِي ظَهَرَ فِيهِ مُوسَى عَلَى فِرْعَوْنَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ أَوْلَى بِمُوسَى مِنْهُمْ فَصُومُوهُ","id":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; Tatkala Rasulullah shallallahu 'alaihi wasallam datang ke Madinah, orang-orang Yahudi sedang berpuasa pada hari 'Asyura. Lalu beliau bertanya kepada mereka, mereka menjawab: Ini adalah hari ketika Musa dapat mengalahkan Fir'aun. Maka Nabi shallallahu 'alaihi wasallam bersabda kepada para sahabat: 'Kita lebih berhak atas Musa dari mereka, maka berpuasalah kalian.\""},"4064":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَيُّوبُ بْنُ النَّجَّارِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَاجَّ مُوسَى آدَمَ فَقَالَ لَهُ أَنْتَ الَّذِي أَخْرَجْتَ النَّاسَ مِنْ الْجَنَّةِ بِذَنْبِكَ وَأَشْقَيْتَهُمْ قَالَ قَالَ آدَمُ يَا مُوسَى أَنْتَ الَّذِي اصْطَفَاكَ اللَّهُ بِرِسَالَتِهِ وَبِكَلَامِهِ أَتَلُومُنِي عَلَى أَمْرٍ كَتَبَهُ اللَّهُ عَلَيَّ قَبْلَ أَنْ يَخْلُقَنِي أَوْ قَدَّرَهُ عَلَيَّ قَبْلَ أَنْ يَخْلُقَنِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَجَّ آدَمُ مُوسَى","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Ayyub bin An Najjar] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdur Rahman] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam \"Musa pernah mendebat Adam, Musa berkata kepada Adam; 'Wahai Adam, engkaulah orang yang telah mencelakakan manusia dan mengeluarkan mereka dari surga.' Lalu Adam ganti berkata kepada Musa; 'Wahai Musa, Bukankah Allah telah memilihmu dengan risalah dan kalam-Nya (diajak bicara secara langsung), maka kenapa kamu mencelaku atas suatu perkara yang telah dicatat dan di takdirkan kepadaku sebelum aku diciptakan? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka Adam dapat mengalahkan Musa.\""},"4065":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ عَنْ عَبْدِ اللَّهِقَالَ بَنِي إِسْرَائِيلَ وَالْكَهْفُ وَمَرْيَمُ وَطه وَالْأَنْبِيَاءُ هُنَّ مِنْ الْعِتَاقِ الْأُوَلِ وَهُنَّ مِنْ تِلَادِيوَقَالَ قَتَادَةُ{ جُذَاذًا }قَطَّعَهُنَّ وَقَالَ الْحَسَنُ{ فِي فَلَكٍ }مِثْلِ فَلْكَةِ الْمِغْزَلِ{ يَسْبَحُونَ }يَدُورُونَ قَالَ ابْنُ عَبَّاسٍ{ نَفَشَتْ }رَعَتْ لَيْلًا{ يُصْحَبُونَ }يُمْنَعُونَ{ أُمَّتُكُمْ أُمَّةً وَاحِدَةً }قَالَ دِينُكُمْ دِينٌ وَاحِدٌ وَقَالَ عِكْرِمَةُ{ حَصَبُ }حَطَبُ بِالْحَبَشِيَّةِ وَقَالَ غَيْرُهُ{ أَحَسُّوا }تَوَقَّعُوا مِنْ أَحْسَسْتُ{ خَامِدِينَ }هَامِدِينَ وَالْحَصِيدُ مُسْتَأْصَلٌ يَقَعُ عَلَى الْوَاحِدِ وَالِاثْنَيْنِ وَالْجَمِيعِ{ لَا يَسْتَحْسِرُونَ }لَا يُعْيُونَ وَمِنْهُ{ حَسِيرٌ }وَحَسَرْتُ بَعِيرِي عَمِيقٌ بَعِيدٌ نُكِّسُوا رُدُّوا{ صَنْعَةَ لَبُوسٍ }الدُّرُوعُ{ تَقَطَّعُوا أَمْرَهُمْ }اخْتَلَفُوا الْحَسِيسُ وَالْحِسُّ وَالْجَرْسُ وَالْهَمْسُ وَاحِدٌ وَهُوَ مِنْ الصَّوْتِ الْخَفِيِّ{ آذَنَّاكَ }أَعْلَمْنَاكَ{ آذَنْتُكُمْ }إِذَا أَعْلَمْتَهُ فَأَنْتَ وَهُوَ{ عَلَى سَوَاءٍ }لَمْ تَغْدِرْ وَقَالَ مُجَاهِدٌ{ لَعَلَّكُمْ تُسْأَلُونَ }تُفْهَمُونَ{ ارْتَضَى }رَضِيَ{ التَّمَاثِيلُ }الْأَصْنَامُ السِّجِلُّ الصَّحِيفَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; Aku mendengar ['Abdur Rahman bin Yazid] dari ['Abdullah] dia berkata; \"Bani Israil, Al Kahfi, Maryam, Thahaa, Al Anbiya, mereka adalah generasi terdahulu, dan ia adalah surat-surat yang sudah lama aku baca. Qatadah berkata; arti 'Judzadzan, ' adalah; Ibrahim memotong-motong berhala-berhala itu. Al Hasan berkata; 'Fi Falakin, ' artinya; seperti ujung roda. Yasbahuun, artinya; Berputar. Ibnu Abbas berkata; Nafasat artinya; mengembala diwaktu malam. Yusbahuun artinya; di larang. Umatukum Ummatan Waahidatan, dia berkata; agama yang satu. Ikrimah berkata; Hashabun artinya; kayu dari Habasyi. Yang lainnya berkata; Ahassuu, artinya: beranggapan Khaadimiin artinya; bertempat tinggal."},"4066":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ شَيْخٌ مِنْ النَّخَعِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَطَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّكُمْ مَحْشُورُونَ إِلَى اللَّهِ حُفَاةً عُرَاةً غُرْلًا{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ وَعْدًا عَلَيْنَا إِنَّا كُنَّا فَاعِلِينَ }ثُمَّ إِنَّ أَوَّلَ مَنْ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ أَلَا إِنَّهُ يُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيُقَالُ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ إِلَى قَوْلِهِ شَهِيدٌ }فَيُقَالُ إِنَّ هَؤُلَاءِ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ مُنْذُ فَارَقْتَهُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah bin An Nu'man] -salah seorang syaikh dari Nakha.- dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah seraya bersabda: \"Wahai sekalian manusia, sesungguhnya kalian dikumpulkan menuju Allah dalam keadaan tidak beralas kaki, telanjang dan masih berkulup (belum dikhitan), 'Sebagaimana Kami telah memulai penciptaan pertama begitulah kami akan mengulanginya. Itulah suatu janji yang pasti kami tepati; Sesungguhnya Kami-lah yang akan melaksanakannya.' (Al Anbiyaa`: 104) kemudian beliau bersabda: \"Sesungguhnya orang pertama yang diberi pakaian pada hari kiamat adalah Ibrahim 'Alaihis Salaam. Ketahuilah, sesungguhnya beberapa orang dari ummatku akan didatangkan lalu mereka diambil ke golongan kiri. Maka aku berkata: 'Wahai Rabb, itu sahabatku.' Dikatakan: 'Sesungguhnya engkau tidak tahu apa yang mereka buat-buat sepeninggalmu.' Lalu aku mengucapkan seperti perkataan seorang hamba shalih: 'Aku menjadi saksi atas mereka selagi aku bersama mereka namun tatkala Engkau wafatkan aku, Engkaulah yang mengawasi mereka dan Engkau Maha menyaksikan terhadap segala sesuatu. Jika Engkau siksa mereka maka sesungguhnya mereka adalah hambaMu.' (Al Maa`idah: 117-118) lalu dijawab: Mereka senantiasa kembali ke belakang (murtad) sejak kau tinggalkan mereka.\""},"4067":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ يَا آدَمُ يَقُولُ لَبَّيْكَ رَبَّنَا وَسَعْدَيْكَ فَيُنَادَى بِصَوْتٍ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تُخْرِجَ مِنْ ذُرِّيَّتِكَ بَعْثًا إِلَى النَّارِ قَالَ يَا رَبِّ وَمَا بَعْثُ النَّارِ قَالَ مِنْ كُلِّ أَلْفٍ أُرَاهُ قَالَ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ فَحِينَئِذٍ تَضَعُ الْحَامِلُ حَمْلَهَا وَيَشِيبُ الْوَلِيدُ{ وَتَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }فَشَقَّ ذَلِكَ عَلَى النَّاسِ حَتَّى تَغَيَّرَتْ وُجُوهُهُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ يَأْجُوجَ وَمَأْجُوجَ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ وَمِنْكُمْ وَاحِدٌ ثُمَّ أَنْتُمْ فِي النَّاسِ كَالشَّعْرَةِ السَّوْدَاءِ فِي جَنْبِ الثَّوْرِ الْأَبْيَضِ أَوْ كَالشَّعْرَةِ الْبَيْضَاءِ فِي جَنْبِ الثَّوْرِ الْأَسْوَدِ وَإِنِّي لَأَرْجُو أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا ثُمَّ قَالَ ثُلُثَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَا ثُمَّ قَالَ شَطْرَ أَهْلِ الْجَنَّةِ فَكَبَّرْنَاقَالَ أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ{ تَرَى النَّاسَ سُكَارَى وَمَا هُمْ بِسُكَارَى }وَقَالَ مِنْ كُلِّ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ وَقَالَ جَرِيرٌ وَعِيسَى بْنُ يُونُسَ وَأَبُو مُعَاوِيَةَ{ سَكْرَى وَمَا هُمْ بِسَكْرَى }","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Abu Shalih] dari [Abu Sa'id Al Khudri] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Allah Azza Wa Jalla pada hari kiamat berfirman: 'Wahai Adam, lalu Adam berkata; 'Aku penuhi panggilan-Mu dan kebahagian ada di tangan-Mu wahai Rabb. Lalu dikatakan dengan suara; Sesungguhnya Allah memerintahkan kepadamu untuk mengeluarkan dari keturunanmu ba'tsun naar (utusan-utusan ke neraka). Adam berkata; Ya Rabb, apa yang Engkau maksud Ba'tsunnar (utusan-utusan neraka) itu?) Allah berfirman: 'Setiap seribu ambillah sembilan ratus sembilan puluh sembilan.'\" Beliau bersabda: \"Maka pada saat itu wanita yang hamil gugur kandungannya, anak kecil akan beruban, dan kamu melihat manusia dalam keadaan mabuk, padahal sebenarnya mereka tidak mabuk, akan tetapi azab Allah itu sangat kerasnya, (Al Hajj: 2).\" hal itu sangat terasa berat bagi umat manusia, hingga wajah mereka berubah. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sembilan ratus sembilan puluh sembilan itu adalah dari Ya'juj dan Ma'juj dan satu orangnya dari kalian.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Adapun kalian pada hari kiamat dalam bandingan seluruh manusia seperti selembar bulu hitam pada kulit sapi yang berwarna putih. Atau beliau mengatakan: seperti selembar bulu putih pada kulit sapi yang berwarna hitam. Dan sungguh aku berharap kalian menjadi seperempat dari penduduk surga? Maka kami (para sahabat) bertakbir. Kemudian beliau bersabda: aku berharap kalian adalah sepertiga dari penduduk surga, Maka kami (para sahabat) bertakbir. Kemudian beliau bersabda: \"Sungguh aku berharap kalian adalah setengah dari penduduk surga.\" para sahabat pun bertakbir kembali. [Abu Usamah] berkata; dari [Al A'Masy] mengenai firman Allah: Dan kalian melihat manusia dalam keadaan mabuk, padahal mereka tidak mabuk. Dia berkata; setiap dari seribu, terdapat Sembilan ratus Sembilan puluh Sembilan.' [Jarir], [Isa bin Yunus] dan [Abu Mu'awiyah] berkata; dengan lafazh 'Sakraa wamaahum bi sakraa.' Bukan 'sukaara.'"},"4068":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْحَارِثِ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ{ وَمِنْ النَّاسِ مَنْ يَعْبُدُ اللَّهَ عَلَى حَرْفٍ }قَالَ كَانَ الرَّجُلُ يَقْدَمُ الْمَدِينَةَ فَإِنْ وَلَدَتْ امْرَأَتُهُ غُلَامًا وَنُتِجَتْ خَيْلُهُ قَالَ هَذَا دِينٌ صَالِحٌ وَإِنْ لَمْ تَلِدْ امْرَأَتُهُ وَلَمْ تُنْتَجْ خَيْلُهُ قَالَ هَذَا دِينُ سُوءٍ","id":"Telah menceritakan kepadaku [Ibrahim bin Al Harits] Telah menceritakan kepada kami [Yahya bin Abu Bukair] Telah menceritakan kepada kami [Israil] dari [Abu Hashin] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; berkenaan dengan firman Allah: Dan di antara manusia ada orang yang menyembah Allah dengan berada di tepi. (Al Hajj: 11), bahwa dulu ada seseorang yang datang ke Madinah, apabila istrinya melahirkan seorang bayi dan kudanya beranak maka dia mengatakan; ini agama yang baik. Dan jika istrinya tidak melahirkan demikian juga kudanya, maka dia mengatakan ini adalah agama yang buruk.\""},"4069":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو هَاشِمٍ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُأَنَّهُ كَانَ يُقْسِمُ قَسَمًا إِنَّ هَذِهِ الْآيَةَ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }نَزَلَتْ فِي حَمْزَةَ وَصَاحِبَيْهِ وَعُتْبَةَ وَصَاحِبَيْهِ يَوْمَ بَرَزُوا فِي يَوْمِ بَدْرٍرَوَاهُ سُفْيَانُ عَنْ أَبِي هَاشِمٍ وَقَالَ عُثْمَانُ عَنْ جَرِيرٍ عَنْ مَنْصُورٍ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ قَوْلَهُ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Hasyim] dari [Abu Mijlaz] dari [Qais bin 'Ubad] dari [Abu Dzar radliallahu 'anhu] bahwa ia pernah bersumpah: sesungguhnya ayat ini: \"Inilah dua golongan (golongan mukmin dan golongan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka.\" (Al Hajj: 19). Ayat ini turun berkenaan dengan Hamzah dan kedua sahabatnya serta Utbah dan kedua sahabatnya pada hari perang Badar. Diriwayatkan oleh [Sufyan] dari [Abu Hasyim]. Dan 'Utsman berkata; dari Jarir dari Manshur dari Abu Hasyim dari Abu Mijlaz."},"4070":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا أَبُو مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَنَا أَوَّلُ مَنْ يَجْثُو بَيْنَ يَدَيْ الرَّحْمَنِ لِلْخُصُومَةِ يَوْمَ الْقِيَامَةِ قَالَ قَيْسٌ وَفِيهِمْ نَزَلَتْ{ هَذَانِ خَصْمَانِ اخْتَصَمُوا فِي رَبِّهِمْ }قَالَ هُمْ الَّذِينَ بَارَزُوا يَوْمَ بَدْرٍ عَلِيٌّ وَحَمْزَةُ وَعُبَيْدَةُ وَشَيْبَةُ بْنُ رَبِيعَةَ وَعُتْبَةُ بْنُ رَبِيعَةَ وَالْوَلِيدُ بْنُ عُتْبَةَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dia berkata; Aku mendengar [Bapakku] berkata; Telah menceritakan kepada kami [Abu Mijlaz] dari [Qais bin 'Ubad] dari ['Ali bin Abu Thalib radliallahu 'anhu] dia berkata; Pada hari kiamat aku adalah orang yang pertama kali bertekuk lutut di hadapan Allah untuk sebuah perdebatan. Qais berkata; dan berkenaan dengan mereka turunlah ayat: \"Inilah dua golongan (golongan mukmin dan golongan kafir) yang bertengkar, mereka saling bertengkar mengenai Rabb mereka.\" Qais berkata; mereka adalah orang-orang yang berperang pada hari perang Badar. Yaitu Ali, Hamzah, Ubaidah bin Harits, Syaibah bin Rabi'ah, Utbah bin Rabi'ah dan Al Walid bin Utbah."},"4071":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ عُوَيْمِرًا أَتَى عَاصِمَ بْنَ عَدِيٍّ وَكَانَ سَيِّدَ بَنِي عَجْلَانَ فَقَالَ كَيْفَ تَقُولُونَ فِي رَجُلٍ وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَصْنَعُ سَلْ لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَتَى عَاصِمٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ فَسَأَلَهُ عُوَيْمِرٌ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَرِهَ الْمَسَائِلَ وَعَابَهَا قَالَ عُوَيْمِرٌ وَاللَّهِ لَا أَنْتَهِي حَتَّى أَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَجَاءَ عُوَيْمِرٌ فَقَالَ يَا رَسُولَ اللَّهِ رَجُلٌ وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَصْنَعُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَنْزَلَ اللَّهُ الْقُرْآنَ فِيكَ وَفِي صَاحِبَتِكَ فَأَمَرَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمُلَاعَنَةِ بِمَا سَمَّى اللَّهُ فِي كِتَابِهِ فَلَاعَنَهَا ثُمَّ قَالَ يَا رَسُولَ اللَّهِ إِنْ حَبَسْتُهَا فَقَدْ ظَلَمْتُهَا فَطَلَّقَهَا فَكَانَتْ سُنَّةً لِمَنْ كَانَ بَعْدَهُمَا فِي الْمُتَلَاعِنَيْنِ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوا فَإِنْ جَاءَتْ بِهِ أَسْحَمَ أَدْعَجَ الْعَيْنَيْنِ عَظِيمَ الْأَلْيَتَيْنِ خَدَلَّجَ السَّاقَيْنِ فَلَا أَحْسِبُ عُوَيْمِرًا إِلَّا قَدْ صَدَقَ عَلَيْهَا وَإِنْ جَاءَتْ بِهِ أُحَيْمِرَ كَأَنَّهُ وَحَرَةٌ فَلَا أَحْسِبُ عُوَيْمِرًا إِلَّا قَدْ كَذَبَ عَلَيْهَا فَجَاءَتْ بِهِ عَلَى النَّعْتِ الَّذِي نَعَتَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ تَصْدِيقِ عُوَيْمِرٍ فَكَانَ بَعْدُ يُنْسَبُ إِلَى أُمِّهِ","id":"Telah menceritakan kepada kami [Ishaq] Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Al Auza'i] dia berkata; Telah menceritakan kepadaku [Az Zuhri] dari [Sahl bin Sa'ad] bahwa 'Uwaimir menemui 'Ashim bin 'Adi pemimpin bani 'Ajlan dan berkata; \"Apa pendapatmu tentang seorang lelaki yang memergoki lelaki lain tengah bersama istrinya, haruskah ia membunuh lelaki itu atau bagaimana? Tolong tanyakan permasalahan ini kepada Rasulullah shallallahu 'alaihi wasallam atas namaku. Maka Ashim menemui Nabi shallallahu 'alaihi wasallam seraya berkata; Ya Rasulullah. Namun Rasulullah shallallahu 'alaihi wasallam tidak menyukai pertanyaan itu. Ketika Uwaimir bertanya kepada Ashim perihal jawaban Nabi shallallahu 'alaihi wasallam atas persoalan itu, ia menjawab; Rasulullah shallallahu 'alaihi wasallam tidak menyukai pertanyaan tersebut dan menganggapnya sangat memalukan. Kemudian 'Uwaimir berkata; 'Demi Allah, aku tidak akan berhenti bertanya sampai Rasulullah shallallahu 'alaihi wasallam memberi jawaban untuk persoalan itu. 'Uwaimir menemui Nabi shallallahu 'alaihi wasallam dan berkata; 'Ya Rasulullah shallallahu 'alaihi wasallam, seorang lelaki menemukan lelaki lain tengah bersama istrinya, haruskah ia membunuh lelaki itu atau bagaimana? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Allah telah menurunkan ayat yang berhubungan dengan persoalanmu di dalam Al Qur'an.\" Maka Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka melakukan mulaa'anah (saling bersumpah atas tuduhannya) dengan istrinya sesuai yang telah disebutkan Allah dalam kitab-Nya. Maka 'Uwaimir melakukan mulaa'anah dengan istrinya. Kemudian 'Uwaimir berkata; 'Wahai Rasulullah, jika aku menahannya maka aku telah berbuat zhalim terhadapnya. Maka ia menceraikan istrinya, dan begitulah perceraian kemudian menjadi tradisi bagi mereka yang bersangkut mulaa'anah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lihatlah! Seandainya ia (istri Uwaimir) melahirkan seorang bayi hitam dengan mata hitam yang lebar dan dalam, pantat besar dan kaki yang gemuk, maka aku akan berpendapat bahwa 'Uwaimir berkata benar. Tetapi jika ia melahirkan seorang bayi berkulit kemerahan mirip tokek maka kita berpendapat bahwa 'Uwaimir berkata dusta. Di kemudian hari ia melahirkan bayi yang ciri-cirinya seperti disebutkan Nabi shallallahu 'alaihi wasallam yang membuktikan kebenaran pengakuan 'Uwaimir. Maka untuk selanjutnya anak itu dinisbahkan kepada ibunya."},"4072":{"ar":"حَدَّثَنِي سُلَيْمَانُ بْنُ دَاوُدَ أَبُو الرَّبِيعِ حَدَّثَنَا فُلَيْحٌ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا رَأَى مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ فَأَنْزَلَ اللَّهُ فِيهِمَا مَا ذُكِرَ فِي الْقُرْآنِ مِنْ التَّلَاعُنِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قُضِيَ فِيكَ وَفِي امْرَأَتِكَ قَالَ فَتَلَاعَنَا وَأَنَا شَاهِدٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَارَقَهَا فَكَانَتْ سُنَّةً أَنْ يُفَرَّقَ بَيْنَ الْمُتَلَاعِنَيْنِ وَكَانَتْ حَامِلًا فَأَنْكَرَ حَمْلَهَا وَكَانَ ابْنُهَا يُدْعَى إِلَيْهَا ثُمَّ جَرَتْ السُّنَّةُ فِي الْمِيرَاثِ أَنْ يَرِثَهَا وَتَرِثَ مِنْهُ مَا فَرَضَ اللَّهُ لَهَا","id":"Telah menceritakan kepadaku [Sulaiman bin Daud Abu Ar Rabi'] Telah menceritakan kepada kami [Fulaih] dari [Az Zuhri] dari [Sahl bin Sa'ad] bahwa seorang lelaki menemui Nabi shallallahu 'alaihi wasallam seraya berkata; 'Ya Rasulullah, bagaimana pendapatmu jika seseorang menemukan lelaki lain tengah bersama istrinya apakah ia harus membunuh lelaki itu atau bagaimana? Maka Allah menurunkan ayat berkenaan dengah hal itu yang disebutkan di dalam Al Qur'an yaitu hendaknya saling mulaa'anah (bersumpah). Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Urusanmu dan istrimu telah diputuskan di dalam Al Qur'an.\" Sahal berkata; maka keduanya saling bermulaa'anah dan aku sendiri menyaksikannya di samping Rasulullah shallallahu 'alaihi wasallam. kemudian ia menceraikan istrinya, dan begitulah perceraian kemudian menjadi tradisi bagi mereka yang bersangkut mulaa'anah. Setelah itu istrinya hamil, dan suaminya tidak mengakuinya sebagai anaknya. Akhirnya anaknya dinasabkan kepada ibunya. Maka kemudian menjadi ketetapan di dalam sunnah anak dan ibu itu bisa saling mewarisi sesuai yang telah Allah tetapkan kepada istrinya."},"4073":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامِ بْنِ حَسَّانَ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍأَنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ امْرَأَتَهُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرِيكِ ابْنِ سَحْمَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّنَةَ أَوْ حَدٌّ فِي ظَهْرِكَ فَقَالَ يَا رَسُولَ اللَّهِ إِذَا رَأَى أَحَدُنَا عَلَى امْرَأَتِهِ رَجُلًا يَنْطَلِقُ يَلْتَمِسُ الْبَيِّنَةَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْبَيِّنَةَ وَإِلَّا حَدٌّ فِي ظَهْرِكَ فَقَالَ هِلَالٌ وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنِّي لَصَادِقٌ فَلَيُنْزِلَنَّ اللَّهُ مَا يُبَرِّئُ ظَهْرِي مِنْ الْحَدِّ فَنَزَلَ جِبْرِيلُ وَأَنْزَلَ عَلَيْهِ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ فَقَرَأَ حَتَّى بَلَغَ إِنْ كَانَ مِنْ الصَّادِقِينَ }فَانْصَرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَيْهَا فَجَاءَ هِلَالٌ فَشَهِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ ثُمَّ قَامَتْ فَشَهِدَتْ فَلَمَّا كَانَتْ عِنْدَ الْخَامِسَةِ وَقَّفُوهَا وَقَالُوا إِنَّهَا مُوجِبَةٌ قَالَ ابْنُ عَبَّاسٍ فَتَلَكَّأَتْ وَنَكَصَتْ حَتَّى ظَنَنَّا أَنَّهَا تَرْجِعُ ثُمَّ قَالَتْ لَا أَفْضَحُ قَوْمِي سَائِرَ الْيَوْمِ فَمَضَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْصِرُوهَا فَإِنْ جَاءَتْ بِهِ أَكْحَلَ الْعَيْنَيْنِ سَابِغَ الْأَلْيَتَيْنِ خَدَلَّجَ السَّاقَيْنِ فَهُوَ لِشَرِيكِ ابْنِ سَحْمَاءَ فَجَاءَتْ بِهِ كَذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا مَا مَضَى مِنْ كِتَابِ اللَّهِ لَكَانَ لِي وَلَهَا شَأْنٌ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Hisyam bin Hassan] Telah menceritakan kepada kami ['Ikrimah] dia berkata; Rasulullah [Ibnu 'Abbas] bahwa Hilal bin Umayyah menuduh istrinya melakukan zina dengan Syarik bin Samha dan membawa persoalan tersebut kehadapan Nabi shallallahu 'alaihi wasallam. maka Nabi shallallahu 'alaihi wasallam bersabda: 'Bawalah bukti yang menguatkan (empat orang saksi) atau kamu akan dihukum cambuk dipunggungmu. Hilal berkata; Ya Rasulullah, jika salah seorang dari kita melihat seorang laki-laki lain bersama istrinya, haruskah ia mencari saksi? Nabi shallallahu 'alaihi wasallam bersabda: Bawalah bukti yang menguatkan (empat orang saksi) atau kamu yang akan dihukum cambuk dipunggungmu. Hilal kemudian berkata; Demi Zat yang mengutusmu dengan kebenaran, aku berkata benar dan Allah akan mewahyukan kepadamu yang menyelamatkan punggungku dari hukuman cambuk. Maka Jibril turun menyampaikan wahyu Allah kepada Nabi shallallahu 'alaihi wasallam Dan merekalah yang menuduh para istrinya…. (An Nuur; 6-9). Nabi shallallahu 'alaihi wasallam membacanya hingga sampai bagian Jika suaminya itu termasuk orang-orang yang benar. Kemudian Nabi shallallahu 'alaihi wasallam ia pergi menjemput istrinya. Hilal pulang dan kembali dengan membawa istrinya. Nabi shallallahu 'alaihi wasallam bersabda: \"Allah tahu bahwa salah seorang dari kalian berdusta, jadi siapa diantara kalian yang akan bertaubat? Kemudian istri Hilal bangun dan bersumpah dan ketika ia akan mengucapkan sumpah yang kelima, mereka menghentikannya dan berkata; Sumpah kelima itu akan membawa laknat kepadamu (jika kamu bersalah). Ia pun tampak ragu melakukannya sehingga kami berfikir bahwa ia akan menyerah. Namun kemudian istri Hilal berkata; Aku tidak akan menjatuhkan kehormatan keluargaku, dan melanjutkan mengambil sumpah. Nabi shallallahu 'alaihi wasallam kemudian berkata; Perhatikan ia. Jika ia melahirkan seorang bayi dengan mata hitam, berpantat besar, dan kaki yang gemuk, maka bayi itu adalah anak Syarik bin Samha. Di kemudian hari ia melahirkan bayi yang ciri-cirinya seperti yang digambarkan Nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jika persoalan ini tidak diputuskan Allah terlebih dahulu, maka tentu aku akan menjatuhkan hukuman yang berat terhadapnya.\""},"4074":{"ar":"حَدَّثَنَا مُقَدَّمُ بْنُ مُحَمَّدِ بْنِ يَحْيَى حَدَّثَنَا عَمِّي الْقَاسِمُ بْنُ يَحْيَى عَنْ عُبَيْدِ اللَّهِ وَقَدْ سَمِعَ مِنْهُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا رَمَى امْرَأَتَهُ فَانْتَفَى مِنْ وَلَدِهَا فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَلَاعَنَا كَمَا قَالَ اللَّهُ ثُمَّ قَضَى بِالْوَلَدِ لِلْمَرْأَةِ وَفَرَّقَ بَيْنَ الْمُتَلَاعِنَيْنِ","id":"Telah menceritakan kepada kami [Muqaddam bin Muhammad bin Yahya] Telah menceritakan kepada kami pamanku [Al Qasim bin Yahya] dari ['Ubaidullah] -dia telah mendengar darinya- dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa pada masa Rasulullah shallallahu 'alaihi wasallam, ada seorang lelaki meli'an (menuduh) isterinya dan tidak mengakui janin yang yang dikandungnya adalah anaknya. Maka Rasulullah menyuruh keduanya menghadap namun keduanya malah saling menuduh. Sebagaimana firman Allah, Rasulullah memutuskan anaknya milik sang istri dan memisahkan keduanya, (suami dan istri)."},"4075":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَالَّذِي تَوَلَّى كِبْرَهُ }قَالَتْ عَبْد�� اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah radliallahu 'anha] mengenai firman Allah: Dan orang yang berandil besar (dalam memfitnah Aisyah) …. (Qs.An Nuur: 11), ia berkata; yaitu Abdullah bin Ubay bin Salul."},"4076":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَسَعِيدُ بْنُ الْمُسَيَّبِ وَعَلْقَمَةُ بْنُ وَقَّاصٍ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ حَدِيثِ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَبَرَّأَهَا اللَّهُ مِمَّا قَالُوا وَكُلٌّ حَدَّثَنِي طَائِفَةً مِنْ الْحَدِيثِ وَبَعْضُ حَدِيثِهِمْ يُصَدِّقُ بَعْضًا وَإِنْ كَانَ بَعْضُهُمْ أَوْعَى لَهُ مِنْ بَعْضٍ الَّذِي حَدَّثَنِي عُرْوَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَخْرُجَ أَقْرَعَ بَيْنَ أَزْوَاجِهِ فَأَيَّتُهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُ قَالَتْ عَائِشَةُ فَأَقْرَعَ بَيْنَنَا فِي غَزْوَةٍ غَزَاهَا فَخَرَجَ سَهْمِي فَخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا نَزَلَ الْحِجَابُ فَأَنَا أُحْمَلُ فِي هَوْدَجِي وَأُنْزَلُ فِيهِ فَسِرْنَا حَتَّى إِذَا فَرَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَتِهِ تِلْكَ وَقَفَلَ وَدَنَوْنَا مِنْ الْمَدِينَةِ قَافِلِينَ آذَنَ لَيْلَةً بِالرَّحِيلِ فَقُمْتُ حِينَ آذَنُوا بِالرَّحِيلِ فَمَشَيْتُ حَتَّى جَاوَزْتُ الْجَيْشَ فَلَمَّا قَضَيْتُ شَأْنِي أَقْبَلْتُ إِلَى رَحْلِي فَإِذَا عِقْدٌ لِي مِنْ جَزْعِ ظَفَارِ قَدْ انْقَطَعَ فَالْتَمَسْتُ عِقْدِي وَحَبَسَنِي ابْتِغَاؤُهُ وَأَقْبَلَ الرَّهْطُ الَّذِينَ كَانُوا يَرْحَلُونَ لِي فَاحْتَمَلُوا هَوْدَجِي فَرَحَلُوهُ عَلَى بَعِيرِي الَّذِي كُنْتُ رَكِبْتُ وَهُمْ يَحْسِبُونَ أَنِّي فِيهِ وَكَانَ النِّسَاءُ إِذْ ذَاكَ خِفَافًا لَمْ يُثْقِلْهُنَّ اللَّحْمُ إِنَّمَا تَأْكُلُ الْعُلْقَةَ مِنْ الطَّعَامِ فَلَمْ يَسْتَنْكِرْ الْقَوْمُ خِفَّةَ الْهَوْدَجِ حِينَ رَفَعُوهُ وَكُنْتُ جَارِيَةً حَدِيثَةَ السِّنِّ فَبَعَثُوا الْجَمَلَ وَسَارُوا فَوَجَدْتُ عِقْدِي بَعْدَمَا اسْتَمَرَّ الْجَيْشُ فَجِئْتُ مَنَازِلَهُمْ وَلَيْسَ بِهَا دَاعٍ وَلَا مُجِيبٌ فَأَمَمْتُ مَنْزِلِي الَّذِي كُنْتُ بِهِ وَظَنَنْتُ أَنَّهُمْ سَيَفْقِدُونِي فَيَرْجِعُونَ إِلَيَّ فَبَيْنَا أَنَا جَالِسَةٌ فِي مَنْزِلِي غَلَبَتْنِي عَيْنِي فَنِمْتُ وَكَانَ صَفْوَانُ بْنُ الْمُعَطَّلِ السُّلَمِيُّ ثُمَّ الذَّكْوَانِيُّ مِنْ وَرَاءِ الْجَيْشِ فَأَدْلَجَ فَأَصْبَحَ عِنْدَ مَنْزِلِي فَرَأَى سَوَادَ إِنْسَانٍ نَائِمٍ فَأَتَانِي فَعَرَفَنِي حِينَ رَآنِي وَكَانَ رَآنِي قَبْلَ الْحِجَابِ فَاسْتَيْقَظْتُ بِاسْتِرْجَاعِهِ حِينَ عَرَفَنِي فَخَمَّرْتُ وَجْهِي بِجِلْبَابِي وَ وَاللَّهِ مَا كَلَّمَنِي كَلِمَةً وَلَا سَمِعْتُ مِنْهُ كَلِمَةً غَيْرَ اسْتِرْجَاعِهِ حَتَّى أَنَاخَ رَاحِلَتَهُ فَوَطِئَ عَلَى يَدَيْهَا فَرَكِبْتُهَا فَانْطَلَقَ يَقُودُ بِي الرَّاحِلَةَ حَتَّى أَتَيْنَا الْجَيْشَ بَعْدَمَا نَزَلُوا مُوغِرِينَ فِي نَحْرِ الظَّهِيرَةِ فَهَلَكَ مَنْ هَلَكَ وَكَانَ الَّذِي تَوَلَّى الْإِفْكَ عَبْدَ اللَّهِ بْنَ أُبَيٍّ ابْنَ سَلُولَ فَقَدِمْنَا الْمَدِينَةَ فَاشْتَكَيْتُ حِينَ قَدِمْتُ شَهْرًا وَالنَّاسُ يُفِيضُونَ فِي قَوْلِ أَصْحَابِ الْإِفْكِ لَا أَشْعُرُ بِشَيْءٍ مِنْ ذَلِكَ وَهُوَ يَرِيبُنِي فِي وَجَعِي أَنِّي لَا أَعْرِفُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّطَفَ الَّذِي كُنْتُ أَرَى مِنْهُ حِينَ أَشْتَكِي إِنَّمَا يَدْخُلُ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُسَلِّمُ ثُمَّ يَقُولُ كَيْفَ تِيكُمْ ثُمَّ يَنْصَرِفُ فَذَاكَ الَّذِي يَرِيبُنِي وَلَا أَشْعُرُ بِالشَّرِّ حَتَّى خَرَجْتُ بَعْدَمَا نَقَهْتُ فَخَرَجَتْ مَعِي أُمُّ مِسْطَحٍ قِبَلَ الْمَنَاصِعِ وَهُوَ مُتَبَرَّزُنَا وَكُنَّا لَا نَخْرُجُ إِلَّا لَيْلًا إِلَى لَيْلٍ وَذَلِكَ قَبْلَ أَنْ نَتَّخِذَ الْكُنُفَ قَرِيبًا مِنْ بُيُوتِنَا وَأَمْرُنَا أَمْرُ الْعَرَبِ الْأُوَلِ فِي التَّبَرُّزِ قِبَلَ الْغَائِطِ فَكُنَّا نَتَأَذَّى بِالْكُنُفِ أَنْ نَتَّخِذَهَا عِنْدَ بُيُوتِنَا فَانْطَلَقْتُ أَنَا وَأُمُّ مِسْطَحٍ وَهِيَ ابْنَةُ أَبِي رُهْمِ بْنِ عَبْدِ مَنَافٍ وَأُمُّهَا بِنْتُ صَخْرِ بْنِ عَامِرٍ خَالَةُ أَبِي بَكْرٍ الصِّدِّيقِ وَابْنُهَا مِسْطَحُ بْنُ أُثَاثَةَ فَأَقْبَلْتُ أَنَا وَأُمُّ مِسْطَحٍ قِبَلَ بَيْتِي وَقَدْ فَرَغْنَا مِنْ شَأْنِنَا فَعَثَرَتْ أُمُّ مِسْطَحٍ فِي مِرْطِهَا فَقَالَتْ تَعِسَ مِسْطَحٌ فَقُلْتُ لَهَا بِئْسَ مَا قُلْتِ أَتَسُبِّينَ رَجُلًا شَهِدَ بَدْرًا قَالَتْ أَيْ هَنْتَاهْ أَوَلَمْ تَسْمَعِي مَا قَالَ قَالَتْ قُلْتُ وَمَا قَالَ فَأَخْبَرَتْنِي بِقَوْلِ أَهْلِ الْإِفْكِ فَازْدَدْتُ مَرَضًا عَلَى مَرَضِي فَلَمَّا رَجَعْتُ إِلَى بَيْتِي وَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْنِي سَلَّمَ ثُمَّ قَالَ كَيْفَ تِيكُمْ فَقُلْتُ أَتَأْذَنُ لِي أَنْ آتِيَ أَبَوَيَّ قَالَتْ وَأَنَا حِينَئِذٍ أُرِيدُ أَنْ أَسْتَيْقِنَ الْخَبَرَ مِنْ قِبَلِهِمَا قَالَتْ فَأَذِنَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتُ أَبَوَيَّ فَقُلْتُ لِأُمِّي يَا أُمَّتَاهْ مَا يَتَحَدَّثُ النَّاسُ قَالَتْ يَا بُنَيَّةُ هَوِّنِي عَلَيْكِ فَوَاللَّهِ لَقَلَّمَا كَانَتْ امْرَأَةٌ قَطُّ وَضِيئَةٌ عِنْدَ رَجُلٍ يُحِبُّهَا وَلَهَا ضَرَائِرُ إِلَّا كَثَّرْنَ عَلَيْهَا قَالَتْ فَقُلْتُ سُبْحَانَ اللَّهِ أَوَلَقَدْ تَحَدَّثَ النَّاسُ بِهَذَا قَالَتْ فَبَكَيْتُ تِلْكَ اللَّيْلَةَ حَتَّى أَصْبَحْتُ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ حَتَّى أَصْبَحْتُ أَبْكِي فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيَّ بْنَ أَبِي طَالِبٍ وَأُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا حِينَ اسْتَلْبَثَ الْوَحْيُ يَسْتَأْمِرُهُمَا فِي فِرَاقِ أَهْلِهِ قَالَتْ فَأَمَّا أُسَامَةُ بْنُ زَيْدٍ فَأَشَارَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالَّذِي يَعْلَمُ مِنْ بَرَاءَةِ أَهْلِهِ وَبِالَّذِي يَعْلَمُ لَهُمْ فِي نَفْسِهِ مِنْ الْوُدِّ فَقَالَ يَا رَسُولَ اللَّهِ أَهْلَكَ وَلَا نَعْلَمُ إِلَّا خَيْرًا وَأَمَّا عَلِيُّ بْنُ أَبِي طَالِبٍ فَقَالَ يَا رَسُولَ اللَّهِ لَمْ يُضَيِّقْ اللَّهُ عَلَيْكَ وَالنِّسَاءُ سِوَاهَا كَثِيرٌ وَإِنْ تَسْأَلْ الْجَارِيَةَ تَصْدُقْكَ قَالَتْ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَرِيرَةَ فَقَالَ أَيْ بَرِيرَةُ هَلْ رَأَيْتِ مِنْ شَيْءٍ يَرِيبُكِ قَالَتْ بَرِيرَةُ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنْ رَأَيْتُ عَلَيْهَا أَمْرًا أَغْمِصُهُ عَلَيْهَا أَكْثَرَ مِنْ أَنَّهَا جَارِيَةٌ حَدِيثَةُ السِّنِّ تَنَامُ عَنْ عَجِينِ أَهْلِهَا فَتَأْتِي الدَّاجِنُ فَتَأْكُلُهُ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَعْذَرَ يَوْمَئِذٍ مِنْ عَبْدِ اللَّهِ بْنِ أُبَيٍّ ابْنِ سَلُولَ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَا مَعْشَرَ الْمُسْلِمِينَ مَنْ يَعْذِرُنِي مِنْ رَجُلٍ قَدْ بَلَغَنِي أَذَاهُ فِي أَهْلِ بَيْتِي فَوَاللَّهِ مَا عَلِمْتُ عَلَى أَهْلِي إِلَّا خَيْرًا وَلَقَدْ ذَكَرُوا رَجُلًا مَا عَلِمْتُ عَلَيْهِ إِلَّا خَيْرًا وَمَا كَانَ يَدْخُلُ عَلَى أَهْلِي إِلَّا مَعِي فَقَامَ سَعْدُ بْنُ مُعَاذٍ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنَا أَعْذِرُكَ مِنْهُ إِنْ كَانَ مِنْ الْأَوْسِ ضَرَبْتُ عُنُقَهُ وَإِنْ كَانَ مِنْ إِخْوَانِنَا مِنْ الْخَزْرَجِ أَمَرْتَنَا فَفَعَلْنَا أَمْرَكَ قَالَتْ فَقَامَ سَعْدُ بْنُ عُبَادَةَ وَهُوَ سَيِّدُ الْخَزْرَجِ وَكَانَ قَبْلَ ذَلِكَ رَجُلًا صَالِحًا وَلَكِنْ احْتَمَلَتْهُ الْحَمِيَّةُ فَقَالَ لِسَعْدٍ كَذَبْتَ لَعَمْرُ اللَّهِ لَا تَقْتُلُهُ وَلَا تَقْدِرُ عَلَى قَتْلِهِ فَقَامَ أُسَيْدُ بْنُ حُضَيْرٍ وَهُوَ ابْنُ عَمِّ سَعْدِ بْنِ مُعَاذٍ فَقَالَ لِسَعْدِ بْنِ عُبَادَةَ كَذَبْتَ لَعَمْرُ اللَّهِ لَنَقْتُلَنَّهُ فَإِنَّكَ مُنَافِقٌ تُجَادِلُ عَنْ الْمُنَافِقِينَ فَتَثَاوَرَ الْحَيَّانِ الْأَوْسُ وَالْخَزْرَجُ حَتَّى هَمُّوا أَنْ يَقْتَتِلُوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ عَلَى الْمِنْبَرِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخَفِّضُهُمْ حَتَّى سَكَتُوا وَسَكَتَ قَالَتْ فَبَكَيْتُ يَوْمِي ذَلِكَ لَا يَرْقَأُ لِي دَمْعٌ وَلَا أَكْتَحِلُ بِنَوْمٍ قَالَتْ فَأَصْبَحَ أَبَوَايَ عِنْدِي وَقَدْ بَكَيْتُ لَيْلَتَيْنِ وَيَوْمًا لَا أَكْتَحِلُ بِنَوْمٍ وَلَا يَرْقَأُ لِي دَمْعٌ يَظُنَّانِ أَنَّ الْبُكَاءَ فَالِقٌ كَبِدِي قَالَتْ فَبَيْنَمَا هُمَا جَالِسَانِ عِنْدِي وَأَنَا أَبْكِي فَاسْتَأْذَنَتْ عَلَيَّ امْرَأَةٌ مِنْ الْأَنْصَارِ فَأَذِنْتُ لَهَا فَجَلَسَتْ تَبْكِي مَعِي قَالَتْ فَبَيْنَا نَحْنُ عَلَى ذَلِكَ دَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ ثُمَّ جَلَسَ قَالَتْ وَلَمْ يَجْلِسْ عِنْدِي مُنْذُ قِيلَ مَا قِيلَ قَبْلَهَا وَقَدْ لَبِثَ شَهْرًا لَا يُوحَى إِلَيْهِ فِي شَأْنِي قَالَتْ فَتَشَهَّدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ جَلَسَ ثُمَّ قَالَ أَمَّا بَعْدُ يَا عَائِشَةُ فَإِنَّهُ قَدْ بَلَغَنِي عَنْكِ كَذَا وَكَذَا فَإِنْ كُنْتِ بَرِيئَةً فَسَيُبَرِّئُكِ اللَّهُ وَإِنْ كُنْتِ أَلْمَمْتِ بِذَنْبٍ فَاسْتَغْفِرِي اللَّهَ وَتُوبِي إِلَيْه�� فَإِنَّ الْعَبْدَ إِذَا اعْتَرَفَ بِذَنْبِهِ ثُمَّ تَابَ إِلَى اللَّهِ تَابَ اللَّهُ عَلَيْهِ قَالَتْ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَتَهُ قَلَصَ دَمْعِي حَتَّى مَا أُحِسُّ مِن","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku ['Urwah bin Az Zubair] dan [Sa'id bin Al Musayyab] dan ['Alqamah bin Waqqash] dan ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] dari cerita ['Aisyah radliallahu 'anha] istri Nabi shallallahu 'alaihi wasallam, tatkala orang yang memfitnahnya menyebarkan ghosip tentangnya dengan segala yang mereka katakana, Allah menjelaskan akan terbebasnya dirinya dari tuduhan tersebut. Sekelompok orang menceritakan tentangku sehimpunan-sehimpunan, sebagian mereka menerima cerita kejadian tersebut dari sebagian yang lain, sehingga kisah tersebut seolah-olah menjadi kuat, hingga saya hafal perkataan dari setiap yang mereka ceritakan kepadaku dan sebagian cerita membenarkan yang lain. Dari Urwah ia menceritakan kepadaku dari Aisyah istri Nabi shallallahu 'alaihi wasallam berkata; bahwa apabila Rasulullah shallaallahu 'alaihi wa sallam hendak berpergian, beliau mengundi di antara isteri-isterinya. Barang siapa yang keluar undiannya, dialah yang ikut pergi bersama Rasulullah shallaallahu 'alaihi wa sallam.\" Aisyah berkata; \"Kemudian beliau mengundi di antara kami pada suatu peperangan dan keluarlah undian anak panahku, sehingga aku pergi bersama Rasulullah shallaallahu 'alaihi wa sallam. Kejadian tersebut setelah diturunkannya ayat tentang hijab. Lalu saya dibawa di sekedupku. Di tengah perjalanan, saya turun hingga Rasulullah shallaallahu 'alaihi wa sallam telah selesai dari sebuah peperangan dan beliau pun kembali ke Madinah. Pada suatu malam saya berada bersama kelompok kaum muslimin. Tatkala mereka tertidur, saya bangun dan berjalan hingga aku mendahului mereka. Setelah saya selesai menunaikan urusanku, saya kembali bergabung dengan kelompok kaum muslimin. Tatkala saya meraba dadaku, ternyata kalungku yang berasal dari Zhafar, Yaman, putus. Maka saya kembali dan mencari kalungku, pencarian itu membuatku terlambat. Dan, sekelompok orang yang membawa sekedupku telah berangkat, mereka berjalan dengan meletakkan sekedupku di atas untaku yang biasa saya kendarai. Mereka mengira bila aku sudah berada di dalamnya.\" Aisyah berkata; \"Tatkala itu, isteri-isteri beliau kurus-kurus dan ringan, karena tidak pernah makan daging. Tetapi, mereka hanya memakan makanan ringan. Sehingga, tidak ada orang yang curiga terhadap beratnya sekedup tersebut, ketika mereka berjalan dan mengangkatnya. Terlebih, kala itu aku masih kecil. Akhirnya mereka pun membawa unta-untanya dan berjalan (meneruskan perjalanan). Saya mendapatkan kalungku tatkala bala tentara telah berlalu. Sehingga, ketika saya mendatangi tempat duduk mereka, tidak ada seorang pun yang memanggil dan tidak ada pula orang yang menjawab. Lalu saya kembali ke tempat dudukku yang semula saya jadikan tempat duduk. Saya berharap akan ada suatu kaum (dari tentara kaum muslimin) yang menemukanku dan kembali menjemputku. Tatkala saya duduk di tempat dudukku, saya merasa ngantuk dan tertidur. Sedangkan Shafwan bin Mu'atthal Assulami dan orang-orang Dzakwan tinggal di belakang pasukan (memeriksa bila ada yang ketinggalan). Mereka berjalan diawal malam dan di pagi harinya mereka sampai di tempat dudukku. Shafwan bin Al Mu'atthal Assulami melihat ada seseorang yang masih tertidur, maka dia mendatangiku dan dia telah mengenaliku tatkala dia melihatku. Karena, dia telah melihatku sebelum diwajibkan memakai hijab atasku. Seketika saya terbangun dan saya mendengar dia beristirja' (mengucapkan, inna lillahi wa inna ilaihi raaji'un) tatkala ia mengetahuiku. Saya langsung menutupi wajahku dengan jilbabku. Demi Allah, dia tidak berbicara sepatah kata pun dan saya sama sekali tidak mendengar satu patah kata pun kecuali kata istirja'nya. Akhirnya ia pun merundukkan untanya dan saya pun menaikinya. Lalu ia pergi dan menuntun unta (yang saya naiki) hingga kami berhasil menyusul pasukan kaum muslimin setelah mereka berisitirahat di pantai Azhzhariah. Celakalah orang yang telah berburuk sangka pada urusanku. Ketika itu, orang yang paling mendalangi issue ghosip itu adalah Abdullah bin Ubay bin Salul. Akhirnya, saya pun sampai di Madinah. Setelah kedatangan kami, saya mendadak sakit hampir selama satu bulan, sementara orang-orang terus larut membicarakan tuduhan (yang ditujukan kepadaku), padahal aku tidak sedikit pun merasa melakukan hal itu. Sehingga, beliau pun meragukan sakitku. Saya tidak lagi merasakan kelembutan Rasulullah shallaallahu 'alaihi wa sallam yang pernah aku lihat darinya sebelumnya. Tatkala aku sakit, Rasulullah shallaallahu 'alaihi wa sallam masuk dan memberi salam seraya bertanya; \"Bagaimana denganmu?\" Seolah-olah tatkala itu beliau meragukanku, sementara saya tidak merasa telah melakukan kejelekan tersebut. Setelah saya merasa mulai sembuh, saya keluar bersama Ummu Misthah ke tempat tertutup untuk buang air, kami tidak pernah keluar kecuali di malam hari hingga malam lagi. Tempat tertutup tersebut dibuat di dekat rumah-rumah kami. Urusan kami seperti para pendahulu orang-orang Arab, kami biasa membuat tempat tertutup untuk buang air di rumah. Kemudian saya dan Ummu Misthah -dia adalah anak perempuannya Abi Ruhmi bin Al Muthallib bin Abdi Manaf dan ibunya adalah anak perempuannya Shakhri bin Amir, bibinya Abu Bakr ash Shidiq dan anaknya adalah Misthah bin Utsabah bin Abbad bin Al Muthallib- kembali ke rumahku setelah urusan kami selesai. Tatkala itu, Ummu Misthah terpeleset karena menginjak atau terjerat kainnya. Ketika itu ia berkata; \"Celaka Misthah.\" Saya bertanya kepadanya; \"Alangkah jeleknya apa yang telah kamu katakan, engkau mencela orang yang telah ikut perang Badar.\" Dia berkata; \"Ya, apakah kamu tidak mendengar apa yang dia katakan?\" saya berkata; \"Apa yang telah dia katakan?\" maka dia mengabarkan kepadaku dengan perkataan orang-orang yang menuduhku. Tatkala itu saya bertambah sakit dan ketika saya kembali ke rumahku, Rasulullah shallaallahu 'alaihi wa sallam menemuiku dan mengucapkan salam. Kemudian beliau bersabda: \"Bagaimana keadaanmu?\" Saya berkata; \"Apakah engkau mengizinkanku untuk mendatangi kedua orang tuaku?\" ia berkata; \"Ketika itu saya ingin meyakinkan kabar tersebut dari mereka berdua. Akhirnya, Rasulullah shallaallahu 'alaihi wa sallam pun mengizinkanku. Lalu saya mendatangi kedua orang tuaku, saya bertanya kepada ibuku; \"Wahai ibuku, apa yang sedang dibicarakan oleh orang-orang?\" ia menjawab; \"Wahai anakku, semoga urusanmu dimudahkan, demi Allah, tidaklah seorang wanita yang jelas-jelas bersama lelaki yang mencintainya sedang laki-laki tersebut memiliki isteri lainnya, kecuali mereka akan memperbanyak tuduhan atas diri wanita tersebut.\" ia berkata; \"Maha Suci Allah, apakah ini yang dibicarakan oleh orang-orang?\" ia berkata; \"Pada malam itu juga aku menangis, hingga di pagi harinya air mataku tidak lagi bisa mengalir karena habis dan saya tidak berselak ketika tidur. Ketika di pagi harinya, saya terus menangis. Dan, ketika itu Rasulullah shallaallahu 'alaihi wa sallam memanggil Ali bin Abi Thalib dan Usamah bin Zaid untuk mengajak keduanya bermusyawarah dalam rangka memisahkan isterinya selama wahyu belum turun.\" Aisyah berkata; \"Adapun Usamah bin Zaid, dia memberi saran kepada Rasulullah shallaallahu 'alaihi wa sallam dengan apa yang ia ketahui yaitu jauhnya isteri beliau dari perbuatan tersebut dan apa yang ia ketahui dari hakikat kecintaannya kepada beliau. Usamah berkata; 'Wahai Rasulullah! Mereka adalah isteri-isterimu, kami tidak mengetahui kecuali kebaikan semata.' Adapun Ali bin Abi Thalib, ia berkata; \"Allah Azzawajalla tidak akan memberi kesempitan kepadamu dan wanita selainnya masih banyak. Dan sungguh, jika engkau bertanya kepada budakmu, pasti dia akan jujur'.\" Aisyah berkata; \"Kemudian Rasulullah shallaallahu 'alaihi wa sallam memanggil Barirah, beliau bertanya: \"Wahai Barirah! Apakah engkau melihat ada sesuatu yang meragukan bagimu dari diri Aisyah?\" Barirah menjawab; \"Demi Dzat yang mengutusmu dengan kebenaran, jika saya melihat pada dirinya suatu hal yang kurang beres, sungguh itu tak lebih hanyalah ketika ia masih kecil umurnya, yang ia ketiduran dari menunggu adonan tepung di keluarganya, lantas ada binatang jinak datang dan menyantapnya.\" Kemudian Rasulullah shallaallahu 'alaihi wa sallam berdiri dan meminta argumentasi dari seorang lelaki yang bernama Abdullah bin Ubai bin Salul. Tatkala Rasulullah shallaallahu 'alaihi wa sallam berada di atas mimbar, Rasulullah shallaallahu 'alaihi wa sallam bersabda: \"Wahai seluruh kaum muslimin, siapakah yang mau memberiku argumentasi dari seorang lelaki yang telah menyakiti keluargaku. Sungguh demi Allah, saya tidak mengetahui sesuatupun dari keluargaku kecuali kebaikan semata. Mereka telah menceritakan mengenai seorang lelaki yang saya tidak mengetahui dari dirinya kecuali kebaikan. Dan tidaklah ada orang yang menemui isteriku kecuali ia bersamaku.\" Sa'ad bin Mu'adz Al Anshari berkata; \"Wahai Rasulullah! aku akan menolongmu. Baiklah, bila yang menyebarkan isu itu dari bani Aus, akan aku penggal lehernya, sebaliknya bila berasal dari saudara kami dari bani Khazraj, silahkan engkau perintahkan kami sehingga kami laksanakan perintahmu.\" Seketika itu juga Sa'ad bin Ubadah -dia adalah pemimpin dari bani Khazraj, ia adalah seorang lelaki yang shalih. Hanya saja, ia masih memiliki sikap fanatis- berkata kepada Sa'ad bin Mu'ad; \"Demi Allah, engkau tidak akan bisa membunuhnya dan tidak akan mampu untuk membunuhnya.\" Maka berdirilah Usaid bin Hudlair dan dia adalah keponakan Sa'ad bin Mu'adz, ia berkata kepada Sa'ad bin Ubadah; \"Engkau bohong, sungguh kami akan membunuhnya karena kamu seorang yang munafik yang memperdebatkan orang-orang munafik.\" Keadaan pun semakin memanas antara bani Aus dan Khazraj, hingga mereka ingin saling bunuh membunuh sedangkan Rasulullah shallaallahu 'alaihi wa sallam masih tetap beridri di atas mimbar. Kemudian Rasulullah shallaallahu 'alaihi wa sallam menenangkan mereka, hingga mereka terdiam dan beliau pun terdiam. Pada hari itu, aku pun menangis hingga air mataku habis dan aku tidak memakai celak tatkala tidur. Malam berikutnya, aku masih menangis hingga air mataku habis dan aku tidak memakai celak ketika tidur. Kedua orang tuaku mengira tangisanku akan dapat membahayakan hatiku. Aisyah berakta; \"Lalu keduanya duduk di sisiku sementara saya masih terus menangis. Ketika itu, ada seorang wanita Anshar yang meminta izin kepadaku untuk menemuiku, aku pun mengizinkannya. Ia pun duduk dan ikut menangis bersamaku. Tatkala kami dalam kondisi seperti itu, Rasulullah shallaallahu 'alaihi wa sallam masuk menemui kami, beliau mengucapkan salam lantas beliau duduk.\" Ia berkata; \"Beliau tidak pernah duduk di sisiku selama satu bulan, sejak wahyu tidak diturunkan kepadanya mengenai urusanku.\" Ia berkata; \"Rasulullah shallaallahu 'alaihi wa sallam pun bersaksi, seraya mengucapkan salam sambil duduk. beliau bersabda: \"Amma ba'd, Wahai Aisyah, sesungguhnya telah sampai kepadaku berita begini dan begini, sungguh jika engkau terlepas dari hal itu karena tidak melakukannya, semoga Allah Azzawajalla menjauhkanmu. Adapun jika kamu melakukan dosa tersebut, minta ampunlah kepada Allah dan bertaubatlah kepada-Nya. Karena seorang hamba yang mengakui dosanya kemudian bertaubat maka Allah akan menerima taubatnya.\" Aisyah berkata; \"Ketika Rasulullah shallaallahu 'alaihi wa sallam selesai berkata, air mataku semakin deras mengalir hingga tidak terasa lagi tetesan air mata tersebut.\" Saya berkata kepada ayahku; \"Jawablah apa yang telah dikatakan Rasulullah shallaallahu 'alaihi wa sallam mengenai diriku.\" Ayahku berkata; \"Saya tidak tahu, demi Allah, saya tidak akan berbicara kepada Rasulullah shallaallahu 'alaihi wa sallam.\" Lalu saya berkata kepada ibuku; \"Jawablah apa yang telah dikatakan Rasulullah shallaallahu 'alaihi wa sallam mengenai diriku!\" ibuku berkata; \"Demi Allah, saya tidak tahu apa yang harus saya katakan kepada Rasulullah shallaallahu 'alaihi wa sallam.\" Aisyah berkata; saya berkata; \"Saya adalah seorang gadis yang masih kecil usianya, saya tidak banyak membaca Al Qur'an. Demi Allah, sungguh aku mengetahui engkau telah mendengar hal ini hingga kamu merasa mantap dan percaya terhadap hal itu. Bila toh aku katakan kepada kalian bahwa aku jauh dari perbuatan tersebut dan Allah Azzawajalla Maha Mengetahui bila aku jauh dari perbuatan tersebut, kalian juga tidak akan percaya terhadap hal itu. Jika saya mengaku kepada kalian dengan suatu perkara, sedang Allah Azzawajalla Maha Mengetahui bahwa aku jauh dari perbuatan tersebut, kalian pasti akan mempercayaiku. Demi Allah, sungguh tidak ada perkataan antara diriku dengan kalian kecuali sebagaimana yang dikatakan oleh Abu Yusuf; Sabar itu adalah baik dan Allah adalah tempat meminta pertolongan terhadap apa yang kalian tuduhkan'.\" Aisyah berkata; \"Kemudian saya merubah posisiku, aku berbaring di atas ranjangku.\" Ia berkata; \"Demi Allah, ketika itu saya mengetahui bahwa aku jauh dari perbuatan tersebut, dan Allah Azzawajalla akan menjauhkanku karena aku jauh dari perbuatan tersebut. Akan tetapi, demi Allah, saya tidak mengira akan turun wahyu pada perkaraku. Dan sungguh, aku merasakan perkaraku terasa lebih sepele daripada Allah Azza wa jalla berfirman padaku dengan suatu wahyu yang dibacakan. Tetapi, saya hanya berharap supaya pada mimpinya Rasulullah shallaallahu 'alaihi wa sallam diperlihatkan bahwa Allah Azzawajalla menjauhkan diriku dari perbuatan tersebut.\" Aisyah berkata; \"Demi Allah, tidaklah Rasulullah shallaallahu 'alaihi wa sallam keluar dari majelisnya, dan tidak ada seorang pun yang keluar dari penghuni rumah tersebut hingga Allah Azzawajalla menurunkan wahyu kepada Nabi-Nya. Sehingga, kondisi beliau berubah sebagaimana perubahan yang biasa terjadi tatkala wahyu turun, keringat beliau terus mengucur padahal hari itu adalah musim dingin. Hal itu karena begitu beratnya firman yang telah diturunkan kepadanya.\" Aisyah berkata; \"Ketika Rasulullah shallaallahu 'alaihi wa sallam mendapat kabar gembira tersebut, beliau tertawa dan kalimat yang pertama kali beliau katakan ketika itu adalah: \"Kabar gembira wahai Aisyah! Allah Azza wa jalla telah menjauhkanmu dari perbuatan tersebut.\" Kemudian ibuku berkata kepadaku; \"Berdirilah kepadanya.\" Aku berkata; \"Demi Allah, aku tidak akan berdiri kepadanya dan aku tidak akan memuji kecuali kepada Allah Azza wa jalla, Dialah yang telah menurunkan wahyu yang menjelaskan akan jauhnya diriku. Allah Azzawajalla. telah menurunkan ayat yang artinya: Sesungguhnya orang-orang yang membawa berita bohong itu adalah dari golongan kamu juga hingga sepuluh ayat. Allah Azzawajalla telah menurunkan beberapa ayat yang menjelaskan akan jauhnya diriku dari perbuatan tersebut.\" Aisyah berkata; \"Dahulu Abu Bakr terbiasa berinfak (memberi bayaran) kepada Misthah, karena ia adalah kerabatnya dan ia adalah seorang yang fakir. Ia berkata; 'Demi Allah, aku tidak akan pernah memberi bantuan untuknya selamanya setelah dia menuduh Aisyah.' Lalu Allah Azzawajalla menurunkan wahyu, yang artinya; Dan janganlah orang-orang yang mempunyai -sampai kepada firman-Nya- apakah kamu tidak ingin bahwa Allah mengampunimu\" Abu Bakr berkata; 'Demi Allah, saya lebih senang bila Allah mengampuniku'. Kemudian ia kembali memberi bantuan kepada Misthah seperti biasa ia memberi bantuan kepadanya. Abu Bakr berkata; 'Sungguh, aku tidak akan berhenti membantunya selamanya'.\" Aisyah berkata; Rasulullah shallaallahu 'alaihi wa sallam bertanya kepada Zainab binti Jahsy, istri Nabi shallaallahu 'alaihi wa sallam, mengenai perkara yang terjadi padaku: \"Apa yang kamu ketahui, apa yang kamu lihat, atau berita apa yang telah sampai kepadamu?\" dia menjawab; \"Wahai Rasulullah! Saya selalu menjaga pendengaran dan penglihatanku, dan saya tidak mengetahuinya kecuali kebaikan semata.\" Aisyah berkata; \"Padahal dia adalah di antara isteri-isteri Nabi shallaallahu 'alaihi wa sallam yang merasa lebih tinggi daripadaku, hanya Allah menjaganya dengan sik ap wara', sekalipun saudara perempuannya, Hamnah binti Jahsyin, membencinya sehingga ia termasuk di antara orang menyebarkan berita bohong yang celaka.\""},"4077":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُلَيْمَانُ عَنْ حُصَيْنٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ أُمِّ رُومَانَ أُمِّ عَائِشَةَ أَنَّهَا قَالَتْلَمَّا رُمِيَتْ عَائِشَةُ خَرَّتْ مَغْشِيًّا عَلَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sulaiman] dari [Hushain] dari [Abu Wail] dari [Masruq] dari [Ummu Ruman] yaitu ibu Aisyah dia berkata; 'Tatkala Aisyah dituduh berbuat keji, ia tersungkur pingsan karenanya.'"},"4078":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ ابْنُ أَبِي مُلَيْكَةَ سَمِعْتُ عَائِشَةَتَقْرَأُ إِذْ تَلِقُونَهُ بِأَلْسِنَتِكُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah menceritakan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka. [Ibnu Abu Mulaikah] dia berkata; Aku mendengar [Aisyah] membaca ayat: Ingatlah, di waktu kamu menerima berita bohong itu dari mulut ke mulut. (An Nuur: 15)."},"4079":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ عُمَرَ بْنِ سَعِيدِ بْنِ أَبِي حُسَيْنٍ قَالَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ قَالَ اسْتَأْذَنَ ابْنُ عَبَّاسٍقَبْلَ مَوْتِهَا عَلَى عَائِشَةَ وَهِيَ مَغْلُوبَةٌ قَالَتْ أَخْشَى أَنْ يُثْنِيَ عَلَيَّ فَقِيلَ ابْنُ عَمِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمِنْ وُجُوهِ الْمُسْلِمِينَ قَالَتْ ائْذَنُوا لَهُ فَقَالَ كَيْفَ تَجِدِينَكِ قَالَتْ بِخَيْرٍ إِنْ اتَّقَيْتُ قَالَ فَأَنْتِ بِخَيْرٍ إِنْ شَاءَ اللَّهُ زَوْجَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَنْكِحْ بِكْرًا غَيْرَكِ وَنَزَلَ عُذْرُكِ مِنْ السَّمَاءِ وَدَخَلَ ابْنُ الزُّبَيْرِ خِلَافَهُ فَقَالَتْ دَخَلَ ابْنُ عَبَّاسٍ فَأَثْنَى عَلَيَّ وَوَدِدْتُ أَنِّي كُنْتُ نِسْيًا مَنْسِيًّاحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الْقَاسِمِ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُ اسْتَأْذَنَ عَلَى عَائِشَةَ نَحْوَهُ وَلَمْ يَذْكُرْ نِسْيًا مَنْسِيًّا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] dari ['Umar bin Sa'id bin Abu Hushain] berkata; Telah menceritakan kepadaku [Ibnu Abu Mulaikah] dia berkata; sebelum wafat Aisyah, [Ibnu 'Abbas] meminta izin untuk menemuinya yang pada waktu itu Aisyah dalam keadan sangat lemah. Aisyah berkata; Aku takut ia akan memujiku. Lalu di katakan kepadanya, ia adalah putra paman Rasulullah shallallahu 'alaihi wasallam dan pembesar kaum muslimin. Maka Aisyah pun berkata; izinkanlah ia masuk. Setelah masuk Ibnu Abbas berkata; bagaimana keadaamu? Aisyah menjawab; saya dalam keadaan baik-baik jika saya bertakwa. Ibnu Abbas berkata; sebagai istri Rasulullah shallallahu 'alaihi wasallam, Insya Allah engkau dalam akan selalu dalam keadaan baik, beliau tidak menikahi seorang perawan selain engkau. Dan dari langit Allah telah membebaskanmu dari tuduhan keji. Ketika Ibnu Abbas pulang, Ibnu Jubair masuk. Lalu Aisyah berkata; Barusan Ibnu Abbas masuk, dan ia telah memujiku. Aku ingin sekali bisa melupakannya (pujiannya). Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami ['Abdul Wahhab bin 'Abdul Majid] Telah menceritakan kepada kami [Ibnu 'Aun] dari [Al Qasim] bahwa [Ibnu 'Abbas radliallahu 'anhu] meminta izin untuk menemui Aisyah -dengan Hadits yang serupa- namun dia tidak menyebutkan kalimat; 'Aku ingin sekali bisa melupakannya.'"},"4080":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَ حَسَّانُ بْنُ ثَابِتٍ يَسْتَأْذِنُ عَلَيْهَا قُلْتُ أَتَأْذَنِينَ لِهَذَا قَالَتْ أَوَلَيْسَ قَدْ أَصَابَهُ عَذَابٌ عَظِيمٌ قَالَ سُفْيَانُ تَعْنِي ذَهَابَ بَصَرِهِ فَقَالَ حَصَانٌ رَزَانٌ مَا تُزَنُّ بِرِيبَةٍوَتُصْبِحُ غَرْثَى مِنْ لُحُومِ الْغَوَافِلِقَالَتْ لَكِنْ أَنْتَ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dari ['Aisyah radliallahu 'anha] dia berkata; Suatu ketika Hassan bin Tsabit datang meminta izin menemui Aisyah. Lalu Aku berkata; Wahai Aisyah, apakah kamu mengizinkan orang ini? Aisyah menjawab; Bukankah ia telah ditimpa adzab yang besar. Sufyan berkata; yaitu hilang penglihatannya. Lalu Hassan melantunkan syair: Engkaulah wanita yang suci, Hidup tenang tanpa adanya keraguan. Pagi-pagi engkau merasa lapar dengan tidak pernah membicarakan keburukan orang lain.' Kemudian Aisyah menjawab, tapi, bukankah dahulu kamu tidak demikian hai Hassan?\""},"4081":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ أَنْبَأَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَدَخَلَ حَسَّانُ بْنُ ثَابِتٍ عَلَى عَائِشَةَ فَشَبَّبَ وَقَالَ حَصَانٌ رَزَانٌ مَا تُزَنُّ بِرِيبَةٍوَتُصْبِحُ غَرْثَى مِنْ لُحُومِ الْغَوَافِلِقَالَتْ لَسْتَ كَذَاكَ قُلْتُ تَدَعِينَ مِثْلَ هَذَا يَدْخُلُ عَلَيْكِ وَقَدْ أَنْزَلَ اللَّهُ{ وَالَّذِي تَوَلَّى كِبْرَهُ مِنْهُمْ }فَقَالَتْ وَأَيُّ عَذَابٍ أَشَدُّ مِنْ الْعَمَى وَقَالَتْ وَقَدْ كَانَ يَرُدُّ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ibnu Abu 'Adi] telah mengabarkan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Adl Dluha] dari [Masruq] dia berkata; Suatu hari Hasan bin Tsabit masuk menemui Aisyah lalu ia melantunkan syair: Engkaulah wanita yang suci, # hidup tenang tanpa adanya keraguan, # Pagi-pagi engkau merasa lapar karena tidak pernah membicarakan keburukan orang lain.' Kemudian [Aisyah] menjawab, Tapi, bukankah kamu dahulu tidak demikian hai Hassan?\" Masruq berkata; \"Saya bertanya kepada Aisyah, 'Wahai Ummul mukminin, mengapa engkau izinkan Hassan bin Tsabit masuk ke rumahmu? Bukankah Allah telah berfirman, (Dan orang yang berandil besar (dalam memfitnah Aisyah), maka ia akan memperoleh adzab yang besar?. (Qs.An Nuur: 11) Mendengar pertanyaan seperti itu. Aisyah menjawab; \"Adzab apalagi yang lebih pedih daripada kebutaan? Yang telah berlalu biarlah berlalu, namun bukankah sekarang Hassan bin Tsabit berjasa dalam membela Rasulullah shallallahu 'alaihi wasallam? "},"4082":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَتْ تَقُولُ لَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ }أَخَذْنَ أُزْرَهُنَّ فَشَقَّقْنَهَا مِنْ قِبَلِ الْحَوَاشِي فَاخْتَمَرْنَ بِهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Al Hasan bin Muslim] dari [Shafiyyah binti Syaibah] bahwa ['Aisyah radliallahu 'anha] pernah berkata; Tatkala turun ayat: Dan hendaklah mereka menutupkan kain kudung kedadanya.. (An Nuur: 31). Maka mereka langsung mengambil sarung-sarung mereka dan menyobeknya dari bagian bawah lalu menjadikannya sebagai kerudung mereka."},"4083":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ الْبَغْدَادِيُّ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا قَالَ يَا نَبِيَّ اللَّهِ يُحْشَرُ الْكَافِرُ عَلَى وَجْهِهِ يَوْمَ الْقِيَامَةِ قَالَ أَلَيْسَ الَّذِي أَمْشَاهُ عَلَى الرِّجْلَيْنِ فِي الدُّنْيَا قَادِرًا عَلَى أَنْ يُمْشِيَهُ عَلَى وَجْهِهِ يَوْمَ الْقِيَامَةِ قَالَ قَتَادَةُ بَلَى وَعِزَّةِ رَبِّنَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] Telah menceritakan kepada kami [Yunus bin Muhammad Al Baghdadi] Telah menceritakan kepada kami [Syaiban] dari [Qatadah] Telah menceritakan kepada kami [Anas bin Malik radliallahu 'anhu] sesungguhnya seseorang yang bertanya, \"Wahai Nabiyullah, bagaimana orang kafir bisa dikumpulkan dengan berjalan di atas kepalanya pada hari kiamat?\" Nabiyulloh shallallahu 'alaihi wasallam bersabda: \"Bukankah Dzat yang menjadikan (orang kafir) berjalan dengan kakinya ketika di dunia, Maha Kuasa untuk menjadikan dia berjalan dengan wajahnya pada hari kiamat? Qatadah berkata; Ya, Demi keagungan Rabb kami."},"4084":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي مَنْصُورٌ وَسُلَيْمَانُ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَيْسَرَةَ عَنْ عَبْدِ اللَّهِ ح قَالَ وَحَدَّثَنِي وَاصِلٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلْتُ أَوْ سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الذَّنْبِ عِنْدَ اللَّهِ أَكْبَرُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ ثُمَّ أَيٌّ قَالَ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ خَشْيَةَ أَنْ يَطْعَمَ مَعَكَ قُلْتُ ثُمَّ أَيٌّ قَالَ أَنْ تُزَانِيَ بِحَلِيلَةِ جَارِكَ قَالَ وَنَزَلَتْ هَذِهِ الْآيَةُ تَصْدِيقًا لِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ }","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; Telah menceritakan kepadaku [Manshur] dan [Sulaiman] dari [Abu Wail] dari [Abu Maisarah] dari ['Abdullah] Demikian juga diriwayatkan dari jalur lainnya, berkata; Dan telah menceritakan kepadaku [Washil] dari [Abu Wail] dari ['Abdullah radliallahu 'anhu] dia berkata; Aku bertanya, atau Rasulullah shallallaahu 'alaihi wasallam ditanya, dosa apakah yang paling besar di sisi Allah? Beliau menjawab: \"yaitu kamu menjadikan bagi Allah sekutu padahal Dia telah menciptakanmu.\" Aku bertanya lagi; kemudian apa? Nabi berkata: kamu membunuh anakmu karena takut makan bersamamu. Aku bertanya; kemudian apa? Beliau menjawab: 'Kemudian engkau berzina dengan istri tetanggamu.' Ibnu Mas'ud; Kemudian Allah menurunkan ayat yang membenarkan hal itu, yaitu: \"Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar, dan tidak berzina…, \" (Al Furqan: 68)."},"4085":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي الْقَاسِمُ بْنُ أَبِي بَزَّةَ أَنَّهُ سَأَلَ سَعِيدَ بْنَ جُبَيْرٍهَلْ لِمَنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا مِنْ تَوْبَةٍ فَقَرَأْتُ عَلَيْهِ{ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }فَقَالَ سَعِيدٌ قَرَأْتُهَا عَلَى ابْنِ عَبَّاسٍ كَمَا قَرَأْتَهَا عَلَيَّ فَقَالَ هَذِهِ مَكِّيَّةٌ نَسَخَتْهَا آيَةٌ مَدَنِيَّةٌ الَّتِي فِي سُورَةِ النِّسَاءِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] Telah mengabarkan kepada mereka dia berkata; Telah mengabarkan kepadaku [Qasim bin Abu Bazzah] bahwsanya dia bertanya [Sa'id bin Jubair] apakah ada taubat bagi orang yang telah membunuh seorang mukmin? Lalu aku membacakan ayat; dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar... (Al Furqan: 68). Maka Sa'id berkata; Aku telah membacakannya kepada [Ibnu Abbas] sebagaimana kamu membacakannya kepadaku. Dia berkata; Ayat ini turun di Makkah, telah dinasakh (dihapus) oleh ayat yang turun di Madinah yang ada di didalam surat An Nisa."},"4086":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَاخْتَلَفَ أَهْلُ الْكُوفَةِ فِي قَتْلِ الْمُؤْمِنِ فَرَحَلْتُ فِيهِ إِلَى ابْنِ عَبَّاسٍ فَقَالَ نَزَلَتْ فِي آخِرِ مَا نَزَلَ وَلَمْ يَنْسَخْهَا شَيْءٌ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah bin An Nu'man] dari [Sa'id bin Jubair] dia berkata; Penduduk Kufah berselisih pendapat di dalam masalah membunuh orang mukmin. Maka aku pergi menemui Ibnu Abbas untuk menanyakan hal itu. Lalu [Ibnu Abbas] berkata; ayat itu turun terakhir kali, tidak ada yang menasakhnya (menghapusnya) sedikitpun."},"4087":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَنْصُورٌ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ قَوْلِهِ تَعَالَى{ فَجَزَاؤُهُ جَهَنَّمُ }قَالَ لَا تَوْبَةَ لَهُ وَعَنْ قَوْلِهِ جَلَّ ذِكْرُهُ{ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }قَالَ كَانَتْ هَذِهِ فِي الْجَاهِلِيَّةِ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Manshur] dari [Sa'id bin Jubair] dia berkata; Aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhuma] tentang firman Allah: Maka balasannya adalah nerakan Jahannam. Ibnu Abbas berkata; 'Tidak ada taubat baginya.' Dan mengenai firman Allah: Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah. (Al Furqan: 68). Ibnu Abbas berkata; 'Ayat ini turun pada masa Jahiliyah.'"},"4088":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقَالَ ابْنُ أَبْزَى سَلْ ابْنَ عَبَّاسٍ عَنْ قَوْلِهِ تَعَالَى{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ خَالِدًا فِيهَا }وَقَوْلِهِ{ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ حَتَّى بَلَغَ إِلَّا مَنْ تَابَ وَآمَنَ }فَسَأَلْتُهُ فَقَالَ لَمَّا نَزَلَتْ قَالَ أَهْلُ مَكَّةَ فَقَدْ عَدَلْنَا بِاللَّهِ وَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا إِلَى قَوْلِهِ غَفُورًا رَحِيمًا }","id":"Telah menceritakan kepada kami [Sa'ad bin Hafsh] Telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Sa'id bin Jubair] dia berkata; Ibnu Abza berkata; tanyakanlah kepada [Ibnu 'Abbas] mengenai firman Allah: \"Dan barangsiapa yang membunuh orang mu'min secara sengaja maka balasannya adalah jahanam, ia kekal didalamnya.\" (An Nisaa`: 93) dan firman Allah: dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar.. hingga ayat kecuali orang-orang yang bertaubat... (Al Furqan: 68-70). maka aku pun menanyakannya, Ia menjawab: 'Tatkala ayat ini turun, penduduk Makkah berkata; kami telah berpaling dari Allah, kami membunuh jiwa yang diharamkan Allah dan kami telah melakukan perbuatan-perbuatan keji. Lalu Allah 'azza wajalla menurunkan: \"Kecuali orang-orang yang bertaubat, beriman dan mengerjakan amal shalih...\" Hingga akhir ayat."},"4089":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا أَبِي عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى أَنْ أَسْأَلَ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُهُ فَقَالَ لَمْ يَنْسَخْهَا شَيْءٌ وَعَنْ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }قَالَ نَزَلَتْ فِي أَهْلِ الشِّرْكِ","id":"Telah menceritakan kepada kami ['Abdan] Telah mengabarkan kepada kami [Bapakku] dari [Syu'bah] dari [Manshur] dari [Sa'id bin Jubair] dia berkata; 'Abdur Rahman bin Abza menyuruhku untuk menanyakan kepada [Ibnu 'Abbas] mengenai kedua ayat ini: \"Dan barangsiapa yang membunuh orang mu'min secara sengaja maka balasannya adalah jahanam, ia kekal didalamnya.\" (An Nisaa`: 93) maka aku bertanya padanya, ia menjawab: Ini tidak dihapus oleh (ayat) apa pun. Dan tentang ayat ini: \"Dan orang-orang yang tidak menyembah Tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar.\" (Al Furqaan: 68) ia menjawab: 'Ayat ini turun tentang para pelaku kesyirikan.'"},"4090":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا مُسْلِمٌ عَنْ مَسْرُوقٍ قَالَ قَالَ عَبْدُ اللَّهِخَمْسٌ قَدْ مَضَيْنَ الدُّخَانُ وَالْقَمَرُ وَالرُّومُ وَالْبَطْشَةُ وَاللِّزَامُ{ فَسَوْفَ يَكُونُ لِزَامًا }","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Muslim] dari [Masruq] dia berkata; ['Abdullah] berkata; \"Lima (tanda-tanda) telah terjadi: kabut, terbelahnya bulan, (kemenangan) atas Romawi hantaman keras, dan adzab. karena itu kelak (azab) pasti menimpamu. (Al Furqan: 77).\""},"4091":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَخِي عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَلْقَى إِبْرَاهِيمُ أَبَاهُ فَيَقُولُ يَا رَبِّ إِنَّكَ وَعَدْتَنِي أَنْ لَا تُخْزِيَنِي يَوْمَ يُبْعَثُونَ فَيَقُولُ اللَّهُ إِنِّي حَرَّمْتُ الْجَنَّةَ عَلَى الْكَافِرِينَ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Saudara laki-lakiku] dari [Ibnu Abu Dzib] dari [Sa'id Al Maqburi] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Tatkala Ibrahim bertemu bapaknya, dia berkata; Ya Rabbku, Engkau telah menjanjikan kepadaku bahwa Engkau tidak akan membuatku sedih pada hari kiamat. Maka Allah berfirman: \"Sesungguhnya Aku telah mengharamkan surga bagi orang-orang kafir.\""},"4092":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا نَزَلَتْ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }صَعِدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الصَّفَا فَجَعَلَ يُنَادِي يَا بَنِي فِهْرٍ يَا بَنِي عَدِيٍّ لِبُطُونِ قُرَيْشٍ حَتَّى اجْتَمَعُوا فَجَعَلَ الرَّجُلُ إِذَا لَمْ يَسْتَطِعْ أَنْ يَخْرُجَ أَرْسَلَ رَسُولًا لِيَنْظُرَ مَا هُوَ فَجَاءَ أَبُو لَهَبٍ وَقُرَيْشٌ فَقَالَ أَرَأَيْتَكُمْ لَوْ أَخْبَرْتُكُمْ أَنَّ خَيْلًا بِالْوَادِي تُرِيدُ أَنْ تُغِيرَ عَلَيْكُمْ أَكُنْتُمْ مُصَدِّقِيَّ قَالُوا نَعَمْ مَا جَرَّبْنَا عَلَيْكَ إِلَّا صِدْقًا قَالَ فَإِنِّي نَذِيرٌ لَكُمْ بَيْنَ يَدَيْ عَذَابٍ شَدِيدٍ فَقَالَ أَبُو لَهَبٍ تَبًّا لَكَ سَائِرَ الْيَوْمِ أَلِهَذَا جَمَعْتَنَا فَنَزَلَتْ{ تَبَّتْ يَدَا أَبِي لَهَبٍ وَتَبَّ مَا أَغْنَى عَنْهُ مَالُهُ وَمَا كَسَبَ }","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Al A'masy] dia berkata; Telah menceritakan kepadaku ['Amru bin Murrah] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; Tatkala turun ayat: Dan peringatkanlah keluargamu yang terdekat, (As Syu'ara: 214). Rasulullah shallallahu 'alaihi wasallam naik ke Shofa dan berteriak memanggil-manggil; 'Wahai bani Fihr, wahai Bani 'Adi dari keturunan Quraisy! Hingga orang-orang pun berkumpul dan apabila ada di antara mereka yang tidak bisa hadir, mereka mengutus utusan untuk menghadirinya. Demikian juga Abu Jahal dan orang-orang Quraisy pun berdatangan. Beliau bersabda: 'Apa pendapat kalian jika kuberitahukan kepada kalian bahwa pasukan berkuda dari musuh di balik lembah ini akan menyerang kalian apakah kalian akan membenarkanku (mempercayaiku)? Mereka menjawab: Tentu, karena kamu tidak pernah berdusta. Lalu beliau berkata: 'Sesungguhnya aku memperingatkan kalian akan adzab yang berat. Maka Abu Lahab berkata: 'Apakah untuk ini engkau mengumpulkan kami?! Celakalah kamu! ia berkata: Maka Allah azza wa jalla menurunkan \"Binasalah kedua tangan abu Lahab dan Sesungguhnya dia akan binasa.\" (QS. Al Lahab: 1)."},"4093":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَنْزَلَ اللَّهُ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }قَالَ يَا مَعْشَرَ قُرَيْشٍ أَوْ كَلِمَةً نَحْوَهَا اشْتَرُوا أَنْفُسَكُمْ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا بَنِي عَبْدِ مَنَافٍ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا عَبَّاسُ بْنَ عَبْدِ الْمُطَّلِبِ لَا أُغْنِي عَنْكَ مِنْ اللَّهِ شَيْئًا وَيَا صَفِيَّةُ عَمَّةَ رَسُولِ اللَّهِ لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًا وَيَا فَاطِمَةُ بِنْتَ مُحَمَّدٍ سَلِينِي مَا شِئْتِ مِنْ مَالِي لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًاتَابَعَهُ أَصْبَغُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdur Rahman] bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam berdiri ketika diturunkan kepadanya ayat: Dan peringatkanlah keluargamu yang terdekat. (As Syu'ara: 214). Beliau bersabda: \"Wahai orang-orang Quraisy, -atau ucapan yang serupa dengannya- belilah diri kalian dari Allah, saya tidak mampu menolong kalian sedikitpun dari Allah, wahai Bani Abd Manaf, saya tidak mampu menolong kalian sedikitpun dari Allah, wahai Abbas bin Abdul Muththalib, saya tidak mampu menolong kamu sedikitpun dari Allah, wahai Shafiyah bibi Rasulullah, saya tidak mampu menolong kamu sedikitpun dari Allah, wahai Fathimah binti Muhammad mintalah kepadaku apa yang engkau inginkan dari hartaku, saya tidak mampu menolong kamu sedikitpun dari Allah.\" Diriwayatkan pula oleh [Ashbagh] dari [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab]."},"4094":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ عِنْدَهُ أَبَا جَهْلٍ وَعَبْدَ اللَّهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ فَقَالَ أَيْ عَمِّ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللَّهِ بْنُ أَبِي أُمَيَّةَ أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ فَلَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُهَا عَلَيْهِ وَيُعِيدَانِهِ بِتِلْكَ الْمَقَالَةِ حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ وَأَبَى أَنْ يَقُولَ لَا إِلَهَ إِلَّا اللَّهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ فَأَنْزَلَ اللَّهُ{ مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ }وَأَنْزَلَ اللَّهُ فِي أَبِي طَالِبٍ فَقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ }قَالَ ابْنُ عَبَّاسٍ{ أُولِي الْقُوَّةِ }لَا يَرْفَعُهَا الْعُصْبَةُ مِنْ الرِّجَالِ{ لَتَنُوءُ }لَتُثْقِلُ{ فَارِغًا }إِلَّا مِنْ ذِكْرِ مُوسَى{ الْفَرِحِينَ }الْمَرِحِينَ{ قُصِّيهِ }اتَّبِعِي أَثَرَهُ وَقَدْ يَكُونُ أَنْ يَقُصَّ الْكَلَامَ{ نَحْنُ نَقُصُّ عَلَيْكَ }{ عَنْ جُنُبٍ }عَنْ بُعْدٍ عَنْ جَنَابَةٍ وَاحِدٌ وَعَنْ اجْتِنَابٍ أَيْضًا يَبْطِشُ وَيَبْطُشُ{ يَأْتَمِرُونَ }يَتَشَاوَرُونَ الْعُدْوَانُ وَالْعَدَاءُ وَالتَّعَدِّي وَاحِدٌ{ آنَسَ }أَبْصَرَ الْجِذْوَةُ قِطْعَةٌ غَلِيظَةٌ مِنْ الْخَشَبِ لَيْسَ فِيهَا لَهَبٌ وَالشِّهَابُ فِيهِ لَهَبٌ وَالْحَيَّاتُ أَجْنَاسٌ الْجَانُّ وَالْأَفَاعِي وَالْأَسَاوِدُ{ رِدْءًا }مُعِينًا قَالَ ابْنُ عَبَّاسٍ{ يُصَدِّقُنِي }وَقَالَ غَيْرُهُ{ سَنَشُدُّ }سَنُعِينُكَ كُلَّمَا عَزَّزْتَ شَيْئًا فَقَدْ جَعَلْتَ لَهُ عَضُدًا مَقْبُوحِينَ مُهْلَكِينَ{ وَصَّلْنَا }بَيَّنَّاهُ وَأَتْمَمْنَاهُ{ يُجْبَى }يُجْلَبُ{ بَطِرَتْ }أَشِرَتْ{ فِي أُمِّهَا رَسُولًا }أُمُّ الْقُرَى مَكَّةُ وَمَا حَوْلَهَا{ تُكِنُّ }تُخْفِي أَكْنَنْتُ الشَّيْءَ أَخْفَيْتُهُ وَكَنَنْتُهُ أَخْفَيْتُهُ وَأَظْهَرْتُهُ{ وَيْكَأَنَّ اللَّهَ }مِثْلُ أَلَمْ تَرَ أَنَّ اللَّهَ{ يَبْسُطُ الرِّزْقَ لِمَنْ يَشَاءُ وَيَقْدِرُ }يُوَسِّعُ عَلَيْهِ وَيُضَيِّقُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dari [bapaknya] dia berkata; 'Saat Abu Thalib sekarat, nabi shallallahu 'alaihi wasallam masuk dan di dekatnya ada Abu Jahal dan 'Abdullah bin Abu Umaiyah, nabi shallallahu 'alaihi wasallam bersabda: \"Paman! Ucapkan: LAA ILAAHA ILLALLAAH sebuah kalimat yang akan aku jadikan sebagai pembela untukmu disisi Allah 'azza wajalla.\" Abu jahal dan 'Abdullah bin Abu Umaiyah berkata: Hai Abu Thalib! Apa kau membenci agama 'Abdul Muththallib? Keduanya terus mengucapkannya hingga Abu Thalib mengucapkan sesuatu diakhir kata-katanya yang menunjukkan ia berada diatas agama 'Abdul Muththallib lalu nabi shallallahu 'alaihi wasallam bersabda: \"Aku akan memintakan ampunan untukmu selama aku tidak dilarang darimu.\" Kemudian turunlah ayat \"Tidak patut bagi nabi dan orang-orang yang beriman memintakan ampunan kepada orang-orang musyrik meski mereka memiliki kekerabatan setelah jelas bagi mereka bahwa mereka adalah para penghuni neraka jahim.\" (At-Taubah: 113). Dan berkenaan dengan Abu Thalib Allah menurunkan kepada Nabi shallallahu 'alaihi wasallam ayat; \"Sesungguhnya engkau tidaklah memberi petunjuk kepada orang yang kau cinta.\" (Al Qashash: 56)."},"4095":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا يَعْلَى حَدَّثَنَا سُفْيَانُ الْعُصْفُرِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ{ لَرَادُّكَ إِلَى مَعَادٍ }قَالَ إِلَى مَكَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Ya'la] Telah menceritakan kepada kami [Sufyan Al 'Ushfuri] dari ['Ikrimah] dari [Ibnu 'Abbas] mengenai firman Allah: Sesungguhnya yang mewajibkan atasmu (melaksanakan hukum-hukum) Al Quran, benar-benar akan mengembalikan kamu ke tempat kembali (al Qashshas: 85). Ibnu Abbas berkata; Tempat kembali yang dimaksudkan yaitu Makkah."},"4096":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مَنْصُورٌ وَالْأَعْمَشُ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَبَيْنَمَا رَجُلٌ يُحَدِّثُ فِي كِنْدَةَ فَقَالَ يَجِيءُ دُخَانٌ يَوْمَ الْقِيَامَةِ فَيَأْخُذُ بِأَسْمَاعِ الْمُنَافِقِينَ وَأَبْصَارِهِمْ يَأْخُذُ الْمُؤْمِنَ كَهَيْئَةِ الزُّكَامِ فَفَزِعْنَا فَأَتَيْتُ ابْنَ مَسْعُودٍ وَكَانَ مُتَّكِئًا فَغَضِبَ فَجَلَسَ فَقَالَ مَنْ عَلِمَ فَلْيَقُلْ وَمَنْ لَمْ يَعْلَمْ فَلْيَقُلْ اللَّهُ أَعْلَمُ فَإِنَّ مِنْ الْعِلْمِ أَنْ يَقُولَ لِمَا لَا يَعْلَمُ لَا أَعْلَمُ فَإِنَّ اللَّهَ قَالَ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ قُلْ مَا أَسْأَلُكُمْ عَلَيْهِ مِنْ أَجْرٍ وَمَا أَنَا مِنْ الْمُتَكَلِّفِينَ }وَإِنَّ قُرَيْشًا أَبْطَئُوا عَنْ الْإِسْلَامِ فَدَعَا عَلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اللَّهُمَّ أَعِنِّي عَلَيْهِمْ بِسَبْعٍ كَسَبْعِ يُوسُفَ فَأَخَذَتْهُمْ سَنَةٌ حَتَّى هَلَكُوا فِيهَا وَأَكَلُوا الْمَيْتَةَ وَالْعِظَامَ وَيَرَى الرَّجُلُ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ كَهَيْئَةِ الدُّخَانِ فَجَاءَهُ أَبُو سُفْيَانَ فَقَالَ يَا مُحَمَّدُ جِئْتَ تَأْمُرُنَا بِصِلَةِ الرَّحِمِ وَإِنَّ قَوْمَكَ قَدْ هَلَكُوا فَادْعُ اللَّهَ فَقَرَأَ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ إِلَى قَوْلِهِ عَائِدُونَ }أَفَيُكْشَفُ عَنْهُمْ عَذَابُ الْآخِرَةِ إِذَا جَاءَ ثُمَّ عَادُوا إِلَى كُفْرِهِمْ فَذَلِكَ قَوْلُهُ تَعَالَى{ يَوْمَ نَبْطِشُ الْبَطْشَةَ الْكُبْرَى }يَوْمَ بَدْرٍ وَ{ لِزَامًا }يَوْمَ بَدْرٍ{ الم غُلِبَتْ الرُّومُ إِلَى سَيَغْلِبُونَ }وَالرُّومُ قَدْ مَضَى","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Manshur] dan [Al 'Amasy] dari [Abu Dluha] dari [Masruq] dia berkata; Ketika ada seorang laki-laki berpidato di depan suku Kindah seraya berkata; Pada hari kiamat kabut akan menghalangi pendengaran dan pandangan orang-orang munafik, dan orang-orang Mukmin akan diserang hawa dingin. Maka dengan marah [Ibnu Mas'ud] yang tadinya sedang bersandar, merubah posisinya dan duduk lalu berkata; Orang yang mengetahui sesuatu hendaklah ia mengatakan apa yang diketahuinya. Tetapi jika tidak tahu hendaklah ia mengatakan; Allahu 'A'lam. Karena termasuk dari Ilmu adalah mengatakan Allah A'lam terhadap sesuatu yang tidak diketahuinya. Sesungguhnya Allah berfirman kepada Nabi shallallahu 'alaihi wasallam: Katakanlah (hai Muhammad): \"Aku tidak meminta upah sedikitpun padamu atas da'wahku dan bukanlah aku termasuk orang-orang yang mengada-ada.\" (Shaad: 86). Dan sesungguhnya orang-orang Quraisy tatkala enggan menerima Islam, Nabi shallallahu 'alaihi wasallam mendoakan bagi mereka: Ya Allah, timpakan kepada mereka tujuh tahun kelaparan sebagaimana yang telah menimpa Yusuf. Maka mereka pun ditimpa tahun kelaparan hingga mereka binasa karenanya, mereka makan bangkai, tulang, dan seseorang dari mereka melihat antara dirinya dibumi dan langit seperti ada kabut. Lalu Abu Sufyan datang seraya berkata; 'Ya Muhammad, engkau datang memerintahkan kami untuk menyambung silaturrahmi, namun kaummu sekarang telah binasa, maka mintakanlah kepada Allah keselamatan. Maka Nabi shallallahu 'alaihi wasallam membaca: Maka tunggulah hari ketika langit membawa kabut yang nyata yang meliputi manusia. Inilah azab yang pedih. Mereka berdoa: \"Ya Tuhan kami, lenyapkanlah dari kami azab itu. Sesungguhnya kami akan beriman.\" Hingga ayat: \"Sesungguhnya (kalau) Kami akan melenyapkan siksaan itu agak sedikit sesungguhnya kamu akan kembali ingkar. (QS. Addukhan 10-15), Bagaimana siksa itu akan dilenyapkan dari mereka pada hari kiamat sedangkan mereka kembali kepada kekafiran. Itulah yang dimaksud dengan firman Allah: Ingatlah) hari (ketika) Kami menghantam mereka dengan hantaman yang keras. Sesungguhnya Kami adalah Pemberi balasan. (Ad Dukhan: 16). Yaitu pada perang Badar. Sedangkan Lizaaman (Al Furqan: 77), juga berarti perang Badar. Alif Laam Miim. Telah dikalahkan bangsa Rumawi di negeri yang terdekat. dan mereka sesudah dikalahkan itu akan menang. (Ar Ruum: 1-3). Dan kemenangan Ramawi telah berlalu."},"4097":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مَوْلُودٍ إِلَّا يُولَدُ عَلَى الْفِطْرَةِ فَأَبَوَاهُ يُهَوِّدَانِهِ أَوْ يُنَصِّرَانِهِ أَوْ يُمَجِّسَانِهِ كَمَا تُنْتَجُ الْبَهِيمَةُ بَهِيمَةً جَمْعَاءَ هَلْ تُحِسُّونَ فِيهَا مِنْ جَد��عَاءَ ثُمَّ يَقُولُ{ فِطْرَةَ اللَّهِ الَّتِي فَطَرَ النَّاسَ عَلَيْهَا لَا تَبْدِيلَ لِخَلْقِ اللَّهِ ذَلِكَ الدِّينُ الْقَيِّمُ }","id":"Telah menceritakan kepada kami ['Abdan] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Seorang bayi tidak dilahirkan (ke dunia ini) melainkan ia berada dalam kesucian (fitrah). Kemudian kedua orang tuanyalah yang akan membuatnya menjadi Yahudi, Nasrani, ataupun Majusi -sebagaimana hewan yang dilahirkan dalam keadaan selamat tanpa cacat. Maka, apakah kalian merasakan adanya cacat? ' kemudian beliau membaca firman Allah yang berbunyi: '…tetaplah atas fitrah Allah yang telah menciptakan manusia menurut fitrahnya itu. Tidak ada perubahan atas fitrah Allah.' (QS. Ar Ruum (30): 30)."},"4098":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ }شَقَّ ذَلِكَ عَلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا أَيُّنَا لَمْ يَلْبِسْ إِيمَانَهُ بِظُلْمٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيْسَ بِذَاكَ أَلَا تَسْمَعُ إِلَى قَوْلِ لُقْمَانَ لِابْنِهِ{ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ }","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Al Qamah] dari [Abdullah radliallahu 'anhu] dia berkata; Tatkala turun ayat: Orang-orang yang beriman dan tidak mencampuradukkan iman mereka dengan kezaliman…. (Al An'am: 82). Maka hal itu terasa berat bagi para sahabat Rasulullah shallallahu 'alaihi wasallam, mereka berkata; Siapakah di antara kami yang tidak pernah mencampuri keimanannya dengan kezhaliman? Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukan itu maksudnya, bukankah kalian pernah mendengar perkataan Lukman kepada anaknya Sesungguhnya kesyirikan itu adalah kezhaliman yang besar?. (Luqman: 13)."},"4099":{"ar":"حَدَّثَنِي إِسْحَاقُ عَنْ جَرِيرٍ عَنْ أَبِي حَيَّانَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَوْمًا بَارِزًا لِلنَّاسِ إِذْ أَتَاهُ رَجُلٌ يَمْشِي فَقَالَ يَا رَسُولَ اللَّهِ مَا الْإِيمَانُ قَالَ الْإِيمَانُ أَنْ تُؤْمِنَ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَلِقَائِهِ وَتُؤْمِنَ بِالْبَعْثِ الْآخِرِ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ الْإِسْلَامُ أَنْ تَعْبُدَ اللَّهَ وَلَا تُشْرِكَ بِهِ شَيْئًا وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ الْمَفْرُوضَةَ وَتَصُومَ رَمَضَانَ قَالَ يَا رَسُولَ اللَّهِ مَا الْإِحْسَانُ قَالَ الْإِحْسَانُ أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ قَالَ يَا رَسُولَ اللَّهِ مَتَى السَّاعَةُ قَالَ مَا الْمَسْئُولُ عَنْهَا بِأَعْلَمَ مِنْ السَّائِلِ وَلَكِنْ سَأُحَدِّثُكَ عَنْ أَشْرَاطِهَا إِذَا وَلَدَتْ الْمَرْأَةُ رَبَّتَهَا فَذَاكَ مِنْ أَشْرَاطِهَا وَإِذَا كَانَ الْحُفَاةُ الْعُرَاةُ رُءُوسَ النَّاسِ فَذَاكَ مِنْ أَشْرَاطِهَا فِي خَمْسٍ لَا يَعْلَمُهُنَّ إِلَّا اللَّهُ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ وَيُنْزِلُ الْغَيْثَ وَيَعْلَمُ مَا فِي الْأَرْحَامِ }ثُمَّ انْصَرَفَ الرَّجُلُ فَقَالَ رُدُّوا عَلَيَّ فَأَخَذُوا لِيَرُدُّوا فَلَمْ يَرَوْا شَيْئًا فَقَالَ هَذَا جِبْرِيلُ جَاءَ لِيُعَلِّمَ النَّاسَ دِينَهُمْ","id":"Telah menceritakan kepadaku [Ishaq] dari [Jarir] dari [Abu Hayyan] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam sedang berada bersama kami, lalu datanglah seorang laki-laki dengan berjalan kaki, lantas bertanya; \"Wahai Rasulullah, apakah iman itu?\" beliau menjawab: \"Engkau beriman kepada Allah, malaikat-Nya, para Rasul-Nya, kitab-kitab-Nya, dan hari akhir.\" Lalu ia bertanya lagi; Wahai Rasulullah, apakah Islam itu?\" Beliau menjawab: \"Kamu beribadah kepada Allah dan tidak menyekutukan-Nya dengan sesuatu pun, menegakkan shalat, menunaikan zakat, dan puasa di bulan Ramadlan.\" Kemudian ia bertanya lagi; \"Wahai Muhammad, apakah Ihsan itu?\" beliau menjawab: \"Engkau menyembah Allah seakan-akan engkau melihat-Nya. Jika engkau tidak dapat melihat-Nya sesungguhnya Dia melihatmu.\" Ia bertanya lagi, \"Kapan hari kiamat datang?\" beliau menjawab: \"Orang yang ditanya tentangnya tidak lebih tahu dari orang yang bertanya, namun aku akan memberitahukan kepadamu tanda-tandanya; 'Apabila Seorang budak perempuan melahirkan anak majikannya, di antara tandanya juga; \"Orang yang bertelanjang kaki dan dada menjadi pemimpin manusia. Itulah diantara tanda-tandanya. Ada lima hal yang tidak dapat mengetahuinya kecuali Allah saja; Sesungguhnya Allahlah yang mengetahui kapan terjadinya hari kiamat, kapan turunnya hujan, dan mengetahui apa yang ada di dalam rahim-rahim ibu. Kemudian orang yang bertanya tadi pergi. Nabi shallallahu 'alaihi wasallam berkata; 'Panggilkan orang itu! Maka para sahabat itu mencarinya untuk memanggilnya namun mereka tidak melihat sesuatu pun. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya itu Jibril, dia datang untuk mengajari manusia perkara agamanya.'"},"4100":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي عُمَرُ بْنُ مُحَمَّدِ بْنِ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَفَاتِيحُ الْغَيْبِ خَمْسٌ ثُمَّ قَرَأَ{ إِنَّ اللَّهَ عِنْدَهُ عِلْمُ السَّاعَةِ }","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] dia berkata; Telah menceritakan kepadaku [Ibnu Wahab] dia berkata; Telah menceritakan kepadaku [Umar bin Muhammad bin Zaid bin Abdullah bin Umar] bahwa [Bapaknya] menceritakan kepadanya; Sesungguhnya [Abdullah bin Umar radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Kunci-kunci perkara ghaib ada lima.\" lalu beliau membaca ayat; Sesungguhnya hanya pada Allah sajalah pengetahuan tentang Hari Kiamat.. (Luqman: 34)."},"4101":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ تَبَارَكَ وَتَعَالَى أَعْدَدْتُ لِعِبَادِي الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ قَالَ أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ }و حَدَّثَنَا عَلِيٌّ قَالَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ اللَّهُ مِثْلَهُ قِيلَ لِسُفْيَانَ رِوَايَةً قَالَ فَأَيُّ شَيْءٍ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: Allah Tabaraka wa Ta'ala berfirman: 'Aku telah menyiapkan bagi hamba-hambaku yang shalih sesuatu yang belum pernah dilihat mata, belum pernah didengar telinga dan tidak pernah terlintas dibenak manusia.' Abu Hurairah berkata; Jika kalian mau, bacalah ayat; \"Tak seorangpun mengetahui berbagai nikmat yang menanti, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan (As Sajdah: 17).\" Dan telah menceritakan kepada kami [Ali] dia berkata; Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Allah berfirman: -dengan redaksi yang sama-. Menurut riwayat Sufyan dia berkata; Apakah itu?"},"4102":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْأَعْمَشِ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ تَعَالَى أَعْدَدْتُ لِعِبَادِي الصَّالِحِينَ مَا لَا عَيْنٌ رَأَتْ وَلَا أُذُنٌ سَمِعَتْ وَلَا خَطَرَ عَلَى قَلْبِ بَشَرٍ ذُخْرًا بَلْهَ مَا أُطْلِعْتُمْ عَلَيْهِ ثُمَّ قَرَأَ{ فَلَا تَعْلَمُ نَفْسٌ مَا أُخْفِيَ لَهُمْ مِنْ قُرَّةِ أَعْيُنٍ جَزَاءً بِمَا كَانُوا يَعْمَلُونَ }قَالَ أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ قَرَأَ أَبُو هُرَيْرَةَ قُرَّاتِ أَعْيُنٍ","id":"Telah menceritakan kepadaku [Ishaq bin Nashr] Telah menceritakan kepada kami [Abu Usamah] dari [Al A'masy] Telah menceritakan kepada kami [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, Allah Ta'ala berfirman: \"Aku telah menyiapkan bagi hamba-hambaku yang shalih sesuatu yang belum pernah dilihat mata, belum pernah didengar telinga dan tidak pernah terlintas dibenak manusia.\" Sebagai simpanan, biarkan apa yang diperlihatkan Allah pada kalian.\" Lalu beliau membaca ayat: \"Tak seorangpun mengetahui berbagai nikmat yang menanti, yang indah dipandang sebagai balasan bagi mereka, atas apa yang mereka kerjakan (As Sajdah: 17). [Abu Mu'awiyah] berkata; dari [Al A'masy] dari [Abu Shalih], [Abu Hurairah] membaca dengan lafazh 'Qurraat A'yun.'"},"4103":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ حَدَّثَنَا أَبِي عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُؤْمِنٍ إِلَّا وَأَنَا أَوْلَى النَّاسِ بِهِ فِي الدُّنْيَا وَالْآخِرَةِ اقْرَءُوا إِنْ شِئْتُمْ{ النَّبِيُّ أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ }فَأَيُّمَا مُؤْمِنٍ تَرَكَ مَالًا فَلْيَرِثْهُ عَصَبَتُهُ مَنْ كَانُوا فَإِنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَلْيَأْتِنِي فَأَنَا مَوْلَاهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Muhammad bin Fulaih] Telah menceritakan kepada kami [Bapakku] dari [Hilal bin Ali] dari [Abdurrahman bin Abu 'Amrah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam dia berkata; \"Tidaklah ada seorang mukmin kecuali aku lebih utama atas dirinya baik di dunia maupun di akhirat, bacalah jika engkau mau: \"Nabi itu (hendaknya) lebih utama bagi orang-orang mukmin dari diri mereka sendiri.. (Al Ahzab: 6), \" maka seorang mukmin manapun yang meninggal dan meninggalkan harta maka hendaklah ahli warisnya mewarisinya, dan barangsiapa meninggalkan hutang atau keluarga maka hendaklah ia datang kepadaku karena aku adalah walinya.\""},"4104":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ حَدَّثَنِي سَالِمٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ زَيْدَ بْنَ حَارِثَةَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كُنَّا نَدْعُوهُ إِلَّا زَيْدَ بْنَ مُحَمَّدٍ حَتَّى نَزَلَ الْقُرْآنُ{ ادْعُوهُمْ لِآبَائِهِمْ هُوَ أَقْسَطُ عِنْدَ اللَّهِ }","id":"Telah menceritakan kepada kami [Mu'ala bin Asad] Telah menceritakan kepada kami [Abdul 'Aziz bin Al Mukhtar] Telah menceritakan kepada kami [Musa bin Uqbah] dia berkata; Telah menceritakan kepadaku [Salim] dari [Abdullah bin Umar radliallahu 'anhuma] bahwa Zaid bin Haritsah mantan budak Rasulullah shallallahu 'alaihi wasallam biasa kami panggil dengan Zaid bin Muhammad hingga Allah menurunkan ayat: \"Panggillah dia dengan nama bapak-bapaknya, karena hal itu lebih adil di sisi Allah.\" (QS. Ahzab 5)."},"4105":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَنُرَى هَذِهِ الْآيَةَ نَزَلَتْ فِي أَنَسِ بْنِ النَّضْرِ{ مِنْ الْمُؤْمِنِينَ رِجَالٌ صَدَقُوا مَا عَاهَدُوا اللَّهَ عَلَيْهِ }","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] Telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Tsumamah] dari [Anas bin Malik radliallahu 'anhu] dia berkata; \"Kami melihat ayat ini turun berkenaan dengan Anas bin An Nadlr, yaitu ayat: Di antara orang-orang mukmin itu terdapat orang-orang yang menepati apa yang telah mereka janjikan kepada Allah, (Al Ahzab: 23)."},"4106":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ أَنَّ زَيْدَ بْنَ ثَابِتٍ قَالَلَمَّا نَسَخْنَا الصُّحُفَ فِي الْمَصَاحِفِ فَقَدْتُ آيَةً مِنْ سُورَةِ الْأَحْزَابِ كُنْتُ كَثِيرًا أَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا لَمْ أَجِدْهَا مَعَ أَحَدٍ إِلَّا مَعَ خُزَيْمَةَ الْأَنْصَارِيِّ الَّذِي جَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهَادَتَهُ شَهَادَةَ رَجُلَيْنِ{ مِنْ الْمُؤْمِنِينَ رِجَالٌ صَدَقُوا مَا عَاهَدُوا اللَّهَ عَلَيْهِ }","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Kharijah bin Zaid bin Tsabit] bahwa [Zaid bin Tsabit] berkata; Tatkala kami mencatat ayat-ayat Al Qur'an dari beberapa Mushaf, aku kehilangan satu ayat dari surat Al Ahzab yang aku sering mendengar Rasulullah shallallahu 'alaihi wasallam membacanya. Aku tidak menemukannya dari siapapun kecuali hanya dari Khuzaimah Al Anshari, orang yang kesaksiannya dianggap oleh Rasulullah shallallahu 'alaihi wasallam sebanding dengan kesaksian dua orang laki-laki. Yaitu ayat: Di antara orang-orang mukmin itu terdapat orang-orang yang menepati apa yang telah mereka janjikan kepada Allah, (Al Ahzab: 23)."},"4107":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهَا حِينَ أَمَرَهُ اللَّهُ أَنْ يُخَيِّرَ أَزْوَاجَهُ فَبَدَأَ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي ذَاكِرٌ لَكِ أَمْرًا فَلَا عَلَيْكِ أَنْ لَا تَسْتَعْجِلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ وَقَدْ عَلِمَ أَنَّ أَبَوَيَّ لَمْ يَكُونَا يَأْمُرَانِي بِفِرَاقِهِ قَالَتْ ثُمَّ قَالَ إِنَّ اللَّهَ قَالَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ }إِلَى تَمَامِ الْآيَتَيْنِ فَقُلْتُ لَهُ فَفِي أَيِّ هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Aisyah radliallahu 'anha] -istri Rasulullah shallallahu 'alaihi wasallam- mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah mendatangi Aisyah ketika Allah menyuruhnya untuk memilih (cerai atau tetap bersama) para istrinya, beliau memulai denganku. Beliau bersabda: \"Saya hendak memberitahukan kepadamu hal yang sangat penting, karena itu, janganlah kamu terburu-buru menjawabnya sebelum kamu bermusyawarah dengan kedua orang tuamu.\" Dia (Aisyah) berkata; Beliau tahu benar, kedua orang tuaku tidak akan mengizinkanku bercerai dengan beliau. Dia (Aisyah) melanjutkan; Kemudian beliau bersabda: \"Sesungguhnya Allah berfirman: 'Wahai Nabi, katakanlah kepada istri-istrimu, jika kalian menghendaki kehidupan dunia beserta perhiasannya, marilah kuberikan kepadamu suatu pemberian, kemudian kuceraikan kamu dengan cara yang baik, dan jika kalian menghendaki Allah dan Rasul-Nya serta kampung akhirat, sesungguhnya Allah menyediakan pahala yang besar bagi yang berbuat kebajikan di antara kamu'. Al Ahzab: 28). Aisyah berkata; Apa untuk yang seperti ini saya harus minta musyawarah kepada kedua orang tuaku?, sudah tentu saya menghendaki Allah dan Rasul-Nya serta kampung akhirat."},"4108":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا مُعَلَّى بْنُ مَنْصُورٍ عَنْ حَمَّادِ بْنِ زَيْدٍ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ هَذِهِ الْآيَةَ{ وَتُخْفِي فِي نَفْسِكَ مَا اللَّهُ مُبْدِيهِ }نَزَلَتْ فِي شَأْنِ زَيْنَبَ بِنْتِ جَحْشٍ وَزَيْدِ بْنِ حَارِثَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah menceritakan kepada kami [Mu'alla bin Manshur] dari [Hammad bin Zaid] Telah menceritakan kepada kami [Tsabit] dari [Anas bin Malik radliallahu 'anhu] bahwa ayat ini: \"Sedang kamu menyembunyikan di dalam hatimu apa yang Allah akan menyatakannya.. (Al Ahzab: 37). Diturunkan berkenaan dengan Zainab binti Jahsy dan Zaid bin Haritsah."},"4109":{"ar":"حَدَّثَنَا زَكَرِيَّاءُ بْنُ يَحْيَى حَدَّثَنَا أَبُو أُسَامَةَ قَالَ هِشَامٌ حَدَّثَنَا عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَغَارُ عَلَى اللَّاتِي وَهَبْنَ أَنْفُسَهُنَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَقُولُ أَتَهَبُ الْمَرْأَةُ نَفْسَهَا فَلَمَّا أَنْزَلَ اللَّهُ تَعَالَى{ تُرْجِئُ مَنْ تَشَاءُ مِنْهُنَّ وَتُؤْوِي إِلَيْكَ مَنْ تَشَاءُ وَمَنْ ابْتَغَيْتَ مِمَّنْ عَزَلْتَ فَلَا جُنَاحَ عَلَيْكَ }قُلْتُ مَا أُرَى رَبَّكَ إِلَّا يُسَارِعُ فِي هَوَاكَ","id":"Telah menceritakan kepada kami [Zakariya bin Yahya] Telah menceritakan kepada kami [Abu Usamah], [Hisyam] berkata; Telah menceritakan kepada kami dari [Bapaknya] dari [Aisyah radliallahu 'anha] dia berkata; Saya selalu cemburu kepada setiap wanita yang menyerahkan dirinya kepada Rasulullah shallallahu 'alaihi wasallam, saya berkata; Apakah seorang wanita menyerahkan dirinya? Maka ketika Allah Azza Wa Jalla menurunkan ayat: \"Kamu boleh menangguhkan (menggauli) siapa yang kamu kehendaki di antara mereka (isteri-isterimu) dan (boleh pula) menggauli siapa yang kamu kehendaki. Dan siapa-siapa yang kamu ingini untuk menggaulinya kembali dari perempuan yang telah kamu cerai maka tidak ada dosa bagimu….\" (Al Ahzab: 51). Saya (Aisyah) berkata; Demi Allah, saya tidak melihat Rabbmu kecuali sangat cepat memenuhi keinganan anda."},"4110":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمٌ الْأَحْوَلُ عَنْ مُعَاذَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَأْذِنُ فِي يَوْمِ الْمَرْأَةِ مِنَّا بَعْدَ أَنْ أُنْزِلَتْ هَذِهِ الْآيَةُ{ تُرْجِئُ مَنْ تَشَاءُ مِنْهُنَّ وَتُؤْوِي إِلَيْكَ مَنْ تَشَاءُ وَمَنْ ابْتَغَيْتَ مِمَّنْ عَزَلْتَ فَلَا جُنَاحَ عَلَيْكَ }فَقُلْتُ لَهَا مَا كُنْتِ تَقُولِينَ قَالَتْ كُنْتُ أَقُولُ لَهُ إِنْ كَانَ ذَاكَ إِلَيَّ فَإِنِّي لَا أُرِيدُ يَا رَسُولَ اللَّهِ أَنْ أُوثِرَ عَلَيْكَ أَحَدًاتَابَعَهُ عَبَّادُ بْنُ عَبَّادٍ سَمِعَ عَاصِمًا","id":"Telah menceritakan kepada kami [Hibban bin Musa] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami ['Ashim Al Ahwal] dari [Mu'adzah] dari [Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam biasa meminta izin kepada kami jika tiba giliran beliau bersama salah satu istrinya setelah turunnya ayat: \"Kamu boleh menangguhkan menggauli siapa saja yang kamu kehendaki di antara mereka dan boleh pula menggauli siapa saja yang kamu kehendaki. Dan siapa-siapa yang kamu ingini untuk menggaulinya kembali dari perempuan yang telah kamu cerai maka tidak ada dosa bagimu….\" (Al Ahzab: 51). Maka Mu'adzah bertanya Aisyah; Apa yang kamu katakan kepada Nabi shallallahu 'alaihi wasallam ketika beliau meminta izin kepadamu? Dia menjawab; Aku katakan kepada beliau jika hari itu hari giliranku, maka saya tidak akan memberikannya untuk yang lain. Hadits ini diriwayatkan pula oleh ['Abad bin 'Abad] dia mendengar ['Ashim]."},"4111":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ قُلْتُيَا رَسُولَ اللَّهِ يَدْخُلُ عَلَيْكَ الْبَرُّ وَالْفَاجِرُ فَلَوْ أَمَرْتَ أُمَّهَاتِ الْمُؤْمِنِينَ بِالْحِجَابِ فَأَنْزَلَ اللَّهُ آيَةَ الْحِجَابِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Humaid] dari [Anas] dia berkata; [Umar radliallahu 'anhu] berkata; \"Ya Rasulullah, di antara yang menemui engkau ada yang baik ada juga yang jahat, maka alangkah baiknya sekiranya engkau menyuruh para ummul mukminin memakai hijab. Maka Allah pun menurunkan ayat hijab.\""},"4112":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبِي يَقُولُ حَدَّثَنَا أَبُو مِجْلَزٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا تَزَوَّجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْنَبَ بِنْتَ جَحْشٍ دَعَا الْقَوْمَ فَطَعِمُوا ثُمَّ جَلَسُوا يَتَحَدَّثُونَ وَإِذَا هُوَ كَأَنَّهُ يَتَهَيَّأُ لِلْقِيَامِ فَلَمْ يَقُومُوا فَلَمَّا رَأَى ذَلِكَ قَامَ فَلَمَّا قَامَ قَامَ مَنْ قَامَ وَقَعَدَ ثَلَاثَةُ نَفَرٍ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَدْخُلَ فَإِذَا الْقَوْمُ جُلُوسٌ ثُمَّ إِنَّهُمْ قَامُوا فَانْطَلَقْتُ فَجِئْتُ فَأَخْبَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ قَدْ انْطَلَقُوا فَجَاءَ حَتَّى دَخَلَ فَذَهَبْتُ أَدْخُلُ فَأَلْقَى الْحِجَابَ بَيْنِي وَبَيْنَهُ فَأَنْزَلَ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَدْخُلُوا بُيُوتَ النَّبِيِّ }الْآيَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Ar Raqasyi] Telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dia berkata; Aku mendengar [Bapakku] berkata; Telah menceritakan kepada kami [Abu Mijlaz] dari [Anas bin Malik radliallahu 'anhu] dia berkata; Tatkala Rasulullah shallallahu 'alaihi wasallam menikahi Zainab binti Jahsy, beliau mengundang orang-orang, lalu beliau menjamu mereka, mereka pun menikmati hidangan tersebut, kemudian mereka duduk dan berbincang-bincang.\" Lalu beliau merubah posisi seakan-akan ingin berdiri, namun orang-orang tidak juga berdiri, ketika beliau berdiri maka orang-orang pun ikut berdiri.\" Setelah itu tiga orang duduk lagi. Nabi shallallahu 'alaihi wasallam datang dan hendak masuk ke kamar Zainab, namun orang-orang masih tetap duduk-duduk, setelah itu mereka berdiri dan beranjak pergi. Anas berkata; Lalu saya mengabarkan kepada Nabi shallallahu 'alaihi wasallam bahwa mereka sudah beranjak pergi.\" Kemudian beliau masuk dan saya mengikuti beliau masuk, lantas beliau menurunkan kain tirainya antara saya dengan beliau.\" Lalu Allah Azza Wa Jalla menurunkan (ayat): \"Wahai orang-orang yang beriman, janganlah kalian masuk ke rumah Nabi…. (Al Ahzab: 53)."},"4113":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ قَالَ أَنَسُ بْنُ مَالِكٍأَنَا أَعْلَمُ النَّاسِ بِهَذِهِ الْآيَةِ آيَةِ الْحِجَابِ لَمَّا أُهْدِيَتْ زَيْنَبُ بِنْتُ جَحْشٍ رَضِيَ اللَّهُ عَنْهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ مَعَهُ فِي الْبَيْتِ صَنَعَ طَعَامًا وَدَعَا الْقَوْمَ فَقَعَدُوا يَتَحَدَّثُونَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ ثُمَّ يَرْجِعُ وَهُمْ قُعُودٌ يَتَحَدَّثُونَ فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَدْخُلُوا بُيُوتَ النَّبِيِّ إِلَّا أَنْ يُؤْذَنَ لَكُمْ إِلَى طَعَامٍ غَيْرَ نَاظِرِينَ إِنَاهُ إِلَى قَوْلِهِ مِنْ وَرَاءِ حِجَابٍ }فَضُرِبَ الْحِجَابُ وَقَامَ الْقَوْمُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah], [Anas bin Malik] berkata; Aku orang yang lebih tahu tentang ayat hijab ini, yaitu ketika Zainab binti Jahsy dihadiahkan kepada Rasulullah shallallahu 'alaihi wasallam. Suatu ketika Zainab bersama Rasulullah shallallahu 'alaihi wasallam di rumahnya, beliau membuat makanan lalu mengundang orang-orang. Kemudian mereka pun duduk-duduk sambil berbincang-bincang. Nabi shallallahu 'alaihi wasallam sengaja keluar masuk, namun mereka masih duduk-duduk sambil berbincang-bincang. Maka Allah Ta'ala menurunkan ayat: Hai orang-orang yang beriman, janganlah kamu memasuki rumah- rumah Nabi kecuali bila kamu diizinkan untuk makan dengan tidak menunggu-nunggu waktu masak makanannya…, hingga ayat: maka mintalah dari belakang tabir. (Al Ahzab: 53). Maka dibuatkanlah tabir dan orang-orang pun beranjak pergi."},"4114":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَبُنِيَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَيْنَبَ بِنْتِ جَحْشٍ بِخُبْزٍ وَلَحْمٍ فَأُرْسِلْتُ عَلَى الطَّعَامِ دَاعِيًا فَيَجِيءُ قَوْمٌ فَيَأْكُلُونَ وَيَخْرُجُونَ ثُمَّ يَجِيءُ قَوْمٌ فَيَأْكُلُونَ وَيَخْرُجُونَ فَدَعَوْتُ حَتَّى مَا أَجِدُ أَحَدًا أَدْعُو فَقُلْتُ يَا نَبِيَّ اللَّهِ مَا أَجِدُ أَحَدًا أَدْعُوهُ قَالَ ارْفَعُوا طَعَامَكُمْ وَبَقِيَ ثَلَاثَةُ رَهْطٍ يَتَحَدَّثُونَ فِي الْبَيْتِ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ إِلَى حُجْرَةِ عَائِشَةَ فَقَالَ السَّلَامُ عَلَيْكُمْ أَهْلَ الْبَيْتِ وَرَحْمَةُ اللَّهِ فَقَالَتْ وَعَلَيْكَ السَّلَامُ وَرَحْمَةُ اللَّهِ كَيْفَ وَجَدْتَ أَهْلَكَ بَارَكَ اللَّهُ لَكَ فَتَقَرَّى حُجَرَ نِسَائِهِ كُلِّهِنَّ يَقُولُ لَهُنَّ كَمَا يَقُولُ لِعَائِشَةَ وَيَقُلْنَ لَهُ كَمَا قَالَتْ عَائِشَةُ ثُمَّ رَجَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا ثَلَاثَةٌ مِنْ رَهْطٍ فِي الْبَيْتِ يَتَحَدَّثُونَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَدِيدَ الْحَيَاءِ فَخَرَجَ مُنْطَلِقًا نَحْوَ حُجْرَةِ عَائِشَةَ فَمَا أَدْرِي آخْبَرْتُهُ أَوْ أُخْبِرَ أَنَّ الْقَوْمَ خَرَجُوا فَرَجَعَ حَتَّى إِذَا وَضَعَ رِجْلَهُ فِي أُسْكُفَّةِ الْبَابِ دَاخِلَةً وَأُخْرَى خَارِجَةً أَرْخَى السِّتْرَ بَيْنِي وَبَيْنَهُ وَأُنْزِلَتْ آيَةُ الْحِجَابِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Abdul 'Aziz bin Shuhaib] dari [Anas radliallahu 'anhu] dia berkata; ketika Nabi shallallahu 'alaihi wasallam menikah dengan Zaenab binti Jahsy, beliau membuat makanan yang terbuat dari roti dan daging. Lalu aku mengutus penyeru untuk mengundang makan-makan. Kemudian datanglah suatu kaum, mereka makan lalu keluar lagi. Setelah itu datang lagi satu kaum, setelah mereka makan, mereka pulang. Aku terus menyeru hingga tidak ada lagi yang dapat aku undang. Aku berkata; Ya Nabiyullah, aku sudah tidak mendapatkan orang yang dapat aku undang. Beliau bersabda: 'Angkatlah makanan kalian.' Namun disana ada tiga orang yang sedang berbincang-bincang. Nabi shallallahu 'alaihi wasallam keluar ke kamar Aisyah seraya berkata; Assalamu'alaikum wahai ahlu bait warahmatullah. Aisyah menjawab; Wa 'Alaikassalaam warahmatullah, bagaimana kamu mendapatkan istrimu? Semoga Allah memberkahi anda. Beliau berkeliling ke kamar seluruh istri-istri beliau dan mengucapkan kepada mereka sebagaimana yang beliau ucapkan kepada Aisyah, demikian juga mereka menjawab sebagaimana Aisyah menjawab. Kemudian Nabi shallallahu 'alaihi wasallam kembali, namun tiga orang itu masih tetap berbincang-bincang di rumah beliau. Padahal Nabi shallallahu 'alaihi wasallam sangat pemalu. Lalu beliau pergi lagi ke kamar Aisyah, aku tidak tahu apakah aku sudah mengabarkan kepada beliau atau belum bahwa kaum tersebut sudah pulang semua. Lalu beliau kembali hingga tatkala beliau melangkahkan kakinya di pintu kamar, beliau menutupkan tabir antara aku dengan beliau, dan pada waktu itu turun ayat hijab."},"4115":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَوْلَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ بَنَى بِزَيْنَبَ بِنْتِ جَحْشٍ فَأَشْبَعَ النَّاسَ خُبْزًا وَلَحْمًا ثُمَّ خَرَجَ إِلَى حُجَرِ أُمَّهَاتِ الْمُؤْمِنِينَ كَمَا كَانَ يَصْنَعُ صَبِيحَةَ بِنَائِهِ فَيُسَلِّمُ عَلَيْهِنَّ وَيُسَلِّمْنَ عَلَيْهِ وَيَدْعُو لَهُنَّ وَيَدْعُونَ لَهُ فَلَمَّا رَجَعَ إِلَى بَيْتِهِ رَأَى رَجُلَيْنِ جَرَى بِهِمَا الْحَدِيثُ فَلَمَّا رَآهُمَا رَجَعَ عَنْ بَيْتِهِ فَلَمَّا رَأَى الرَّجُلَانِ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَعَ عَنْ بَيْتِهِ وَثَبَا مُسْرِعَيْنِ فَمَا أَدْرِي أَنَا أَخْبَرْتُهُ بِخُرُوجِهِمَا أَمْ أُخْبِرَ فَرَجَعَ حَتَّى دَخَلَ الْبَيْتَ وَأَرْخَى السِّتْرَ بَيْنِي وَبَيْنَهُ وَأُنْزِلَتْ آيَةُ الْحِجَابِوَقَالَ ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى حَدَّثَنِي حُمَيْدٌ سَمِعَ أَنَسًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] Telah mengabarkan kepada kami [Abdullah bin Bakr As Sahmi] Telah menceritakan kepada kami [Humaid] dari [Anas radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam mengadakan walimah ketika menikah dengan Zainab binti Jahsy. Orang-orang pun merasa kenyang dengan roti dan daging. Kemudian beliau keluar ke kamar semua Ummul Mukminin, sebagaimana yang biasa beliau lakukan. Beliau mengucapkan salam kepada mereka dan mereka pun menjawab salam beliau. Beliau mendo'akan mereka, sebaliknya mereka pun mendo'akan beliau. Tatkala beliau kembali ke rumah, beliau melihat dua orang laki-laki sedang berbincang-bincang di rumah beliau. Melihat hal itu, beliau kembali dari rumahnya. Dan tatkala kedua orang itu melihat Nabi shallallahu 'alaihi wasallam kembali, mereka akhirnya cepat-cepat pulang. Aku tidak tahu, apakah aku telah mengabarkan kepada beliau atau belum, mengenai kepulangan kedua orang itu. Kemudian Nabi shallallahu 'alaihi wasallam kembali dan masuk ke rumah beliau seraya menutupkan tabir antara aku dan beliau. Pada waktu itu turun ayat hijab. [Ibnu Abu Maryam] berkata; Telah mengabarkan kepada kami [Yahya] Telah menceritakan kepadaku [Humaid] dia mendengar [Anas] dari Nabi shallallahu 'alaihi wasallam."},"4116":{"ar":"حَدَّثَنِي زَكَرِيَّاءُ بْنُ يَحْيَى حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجَتْ سَوْدَةُ بَعْدَمَا ضُرِبَ الْحِجَابُ لِحَاجَتِهَا وَكَانَتْ امْرَأَةً جَسِيمَةً لَا تَخْفَى عَلَى مَنْ يَعْرِفُهَا فَرَآهَا عُمَرُ بْنُ الْخَطَّابِ فَقَالَ يَا سَوْدَةُ أَمَا وَاللَّهِ مَا تَخْفَيْنَ عَلَيْنَا فَانْظُرِي كَيْفَ تَخْرُجِينَ قَالَتْ فَانْكَفَأَتْ رَاجِعَةً وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي وَإِنَّهُ لَيَتَعَشَّى وَفِي يَدِهِ عَرْقٌ فَدَخَلَتْ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي خَرَجْتُ لِبَعْضِ حَاجَتِي فَقَالَ لِي عُمَرُ كَذَا وَكَذَا قَالَتْ فَأَوْحَى اللَّهُ إِلَيْهِ ثُمَّ رُفِعَ عَنْهُ وَإِنَّ الْعَرْقَ فِي يَدِهِ مَا وَضَعَهُ فَقَالَ إِنَّهُ قَدْ أُذِنَ لَكُنَّ أَنْ تَخْرُجْنَ لِحَاجَتِكُنَّ","id":"Telah menceritakan kepadaku [Zakaria bin Yahya] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Bapaknya] dari [Aisyah radliallahu 'anha] dia berkata; \"Pada suatu ketika Saudah keluar untuk hajatnya sesudah diwajibkannya hijab atas para wanita.\" Ia berkata; \"Saudah adalah seorang wanita yang tinggi besar sehingga mudah sekali orang mengenalnya.\" Kemudian Umar melihatnya, dia pun memanggilnya; Wahai Saudah! Sungguh saya bisa mengenalimu, jika kamu keluar maka lihatlah bagaimana kamu keluar.\" Akhirnya Saudah berbalik pulang kepada Rasulullah shalallahu'alaihi wa sallam yang ketika itu beliau sedang makan malam di rumahku, ditangan beliau ada sepotong daging. Saudah pun masuk seraya berkata; Ya Rasulullah, Aku keluar untuk keperluanku, lalu Umar berkata begini dan begitu kepadaku. Aisyah berkata; Lalu Allah mewahyukan kepada beliau dan ketika wahyu telah tersampaikan padanya sepotong daging tersebut masih terdapat di tangan beliau tanpa beliau letakkan. Kemudian beliau bersabda: \"Telah diperbolehkan bagi kalian untuk keluar dalam rangka memenuhi hajat kalian.\""},"4117":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَأْذَنَ عَلَيَّ أَفْلَحُ أَخُو أَبِي الْقُعَيْسِ بَعْدَمَا أُنْزِلَ الْحِجَابُ فَقُلْتُ لَا آذَنُ لَهُ حَتَّى أَسْتَأْذِنَ فِيهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ أَخَاهُ أَبَا الْقُعَيْسِ لَيْسَ هُوَ أَرْضَعَنِي وَلَكِنْ أَرْضَعَتْنِي امْرَأَةُ أَبِي الْقُعَيْسِ فَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ يَا رَسُولَ اللَّهِ إِنَّ أَفْلَحَ أَخَا أَبِي الْقُعَيْسِ اسْتَأْذَنَ فَأَبَيْتُ أَنْ آذَنَ لَهُ حَتَّى أَسْتَأْذِنَكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا مَنَعَكِ أَنْ تَأْذَنِي عَمُّكِ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ الرَّجُلَ لَيْسَ هُوَ أَرْضَعَنِي وَلَكِنْ أَرْضَعَتْنِي امْرَأَةُ أَبِي الْقُعَيْسِ فَقَالَ ائْذَنِي لَهُ فَإِنَّهُ عَمُّكِ تَرِبَتْ يَمِينُكِ قَالَ عُرْوَةُ فَلِذَلِكَ كَانَتْ عَائِشَةُ تَقُولُ حَرِّمُوا مِنْ الرَّضَاعَةِ مَا تُحَرِّمُونَ مِنْ النَّسَبِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] Telah menceritakan kepadaku [Urwah bin Jubair] bahwa ['Aisyah radliallahu 'anha] berkata; bahwa Aflah, saudara Abu Al Qu'ais datang meminta izin untuk menemuinya setelah turunnya ayat hijab, Abu Al Qu'ais adalah ayah 'Aisyah dari susuan, Aisyah berkata; saya tidak akan mengizinkan Aflah masuk menemuiku sehingga saya meminta izin Rasulullah shallallahu 'alaihi wasallam terlebih dahulu. Karena bukan saudara Abu Al Qu'ais yang menyusuiku, tetapi istrinya yang menyusuiku. Setelah Rasulullah shallallahu 'alaihi wasallam datang, saya berkata; Wahai Rasulullah, sesungguhnya Aflah, yaitu saudara Abu Al Qu'ais telah datang minta izin untuk menemuiku, namun saya menolak mengizinkannya sebelum aku meminta izin kepada engkau. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apa yang menghalangimu dari mengizinkan pamanmu?\" Aisyah berkata; Ya Rasulullah, dia bukanlah yang menyusuiku, tapi istri Abu Al Qu'aislah yang menyusuiku. Lalu Nabi shallallahu 'alaihi wasallam bersabda: 'Izinkanlah ia, karena sesungguhnya ia adalah pamanmu, maka kamu akan beruntung.' Urwah berkata; Oleh karena itu Aisyah berkata; \"Jadikanlah mahram saudara dari sesusuan sebagaimana kalian menjadikan mahram saudara dari keturunan.\""},"4118":{"ar":"حَدَّثَنِي سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ حَدَّثَنَا أَبِي حَدَّثَنَا مِسْعَرٌ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُ قِيلَيَا رَسُولَ اللَّهِ أَمَّا السَّلَامُ عَلَيْكَ فَقَدْ عَرَفْنَاهُ فَكَيْفَ الصَّلَاةُ عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepadaku [Sa'id bin Yahya bin Sa'id] Telah menceritakan kepada kami [Bapakku] Telah menceritakan kepada kami [Mis'ar] dari [Al Hakam] dari [Ibnu Abu Laila] dari [Ka'ab bin 'Ujrah radliallahu 'anhu] ketika dikatakan; Wahai Rasulullah, kami telah mengetahui salam kepadamu, lalu bagaimanakah caranya bershalawat kepadamu? Beliau menjawab: \"Ucapkanlah; ALLAHUMMA SHALLI 'ALAA MUHAMMAD WA 'ALAA AALI MUHAMMAD KAMAA SHALLAITA 'ALAA AALII IBRAAHIM INNAKA HAMIIDUM MAJIID. ALLAAHUMMA BAARIK 'ALAA MUHAMMAD WA'ALAA AALI MUHAMMAD KAMAA BAARAKTA 'ALAA 'AALI IBRAHIIMA INNAKA HAMIIDUM MAJIID.\""},"4119":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَذَا التَّسْلِيمُ فَكَيْفَ نُصَلِّي عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ عَبْدِكَ وَرَسُولِكَ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَقَالَ أَبُو صَالِحٍ عَنْ اللَّيْثِ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ وَالدَّرَاوَرْدِيُّ عَنْ يَزِيدَ وَقَالَ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَآلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَآلِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] dia berkata; Telah menceritakan kepadaku [Ibnu Al Haad] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudzri] dia berkata; Aku berkata; 'Ya Rasulullah, mengucapkan salam udah kami ketahui, lalu bagaimana mengucapkan shalawat kepadamu? Beliau menjawab: \"Ucapkanlah: ALLAAHUMMA SHALLI 'ALAA MUHAMMAD, 'ABDIKA WA RASUULIKA KAMAA SHALAITA ALAA AALI IBRAHIM WA BAARIK AALA MUHAMMAD WA 'ALAA 'AALI MUHAMMAD KAMAA BAARAKTA 'ALAA IBRAHIM. - [Abu Shalih] berkata; dari [Al Laits] - dengan lafazh; 'AlAA MUHAMMAD WA 'ALAA 'AALI MUHAMMAD KAMAA BAARAKTA 'ALAA AALI IBRAHIM.' Telah menceritakan kepada kami [Ibrahim bin Hamzah] Telah menceritakan kepada kami [Ibnu Abu Hazim] dan [Ad Daraawardi] dari [Yazid] ia berkata dengan lafazh; 'KAMA SHALAITA 'ALAA IBRAHIM, WA BAARIK ALAA MUHAMMAD WA AALI MUHAMMAD KAMAA BARAKTA ALAA IBRAHIM WA AALI IBRAHIM.'"},"4120":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا عَوْفٌ عَنْ الْحَسَنِ وَمُحَمَّدٍ وَخِلَاسٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مُوسَى كَانَ رَجُلًا حَيِيًّا وَذَلِكَ قَوْلُهُ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَكُونُوا كَالَّذِينَ آذَوْا مُوسَى فَبَرَّأَهُ اللَّهُ مِمَّا قَالُوا وَكَانَ عِنْدَ اللَّهِ وَجِيهًا }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] Telah mengabarkan kepada kami [Rauh bin 'Ubadah] Telah menceritakan kepada kami ['Auf] dari [Al Hasan] dan [Muhammad] serta [Khilas] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: Sesungguhnya Musa adalah orang yang sangat pemalu, hal itu sebagaimana firman Allah: \"Hai orang-orang yang beriman, janganlah kamu menjadi seperti orang-orang yang menyakiti Musa; maka Allah membersihkannya dari tuduhan-tuduhan yang mereka katakan. Dan adalah dia seorang yang mempunyai kedudukan terhormat di sisi Allah.\" (Al Ahzaab: 69)."},"4121":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو قَالَ سَمِعْتُ عِكْرِمَةَ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَضَى اللَّهُ الْأَمْرَ فِي السَّمَاءِ ضَرَبَتْ الْمَلَائِكَةُ بِأَجْنِحَتِهَا خُضْعَانًا لِقَوْلِهِ كَأَنَّهُ سِلْسِلَةٌ عَلَى صَفْوَانٍ فَإِذَا{ فُزِّعَ عَنْ قُلُوبِهِمْ قَالُوا مَاذَا قَالَ رَبُّكُمْ قَالُوا }لِلَّذِي قَالَ{ الْحَقَّ وَهُوَ الْعَلِيُّ الْكَبِيرُ }فَيَسْمَعُهَا مُسْتَرِقُ السَّمْعِ وَمُسْتَرِقُ السَّمْعِ هَكَذَا بَعْضُهُ فَوْقَ بَعْضٍ وَوَصَفَ سُفْيَانُ بِكَفِّهِ فَحَرَفَهَا وَبَدَّدَ بَيْنَ أَصَابِعِهِ فَيَسْمَعُ الْكَلِمَةَ فَيُلْقِيهَا إِلَى مَنْ تَحْتَهُ ثُمَّ يُلْقِيهَا الْآخَرُ إِلَى مَنْ تَحْتَهُ حَتَّى يُلْقِيَهَا عَلَى لِسَانِ السَّاحِرِ أَوْ الْكَاهِنِ فَرُبَّمَا أَدْرَكَ الشِّهَابُ قَبْلَ أَنْ يُلْقِيَهَا وَرُبَّمَا أَلْقَاهَا قَبْلَ أَنْ يُدْرِكَهُ فَيَكْذِبُ مَعَهَا مِائَةَ كَذْبَةٍ فَيُقَالُ أَلَيْسَ قَدْ قَالَ لَنَا يَوْمَ كَذَا وَكَذَا كَذَا وَكَذَا فَيُصَدَّقُ بِتِلْكَ الْكَلِمَةِ الَّتِي سَمِعَ مِنْ السَّمَاءِ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Amru] dia berkata; Aku mendengar [Ikrimah] berkata; Aku mendengar [Abu Hurairah] berkata; Sesungguhnya Nabiyullah shallallahu 'alaihi wasallam bersabda: \"Apabila Allah menetapkan satu perkara di atas langit maka para malaikat mengepakkan sayap-sayap mereka karena tunduk kepada firman-Nya, seakan-akan rantai yang berada di atas batu besar. Apabila hati mereka telah menjadi stabil, mereka berkata; 'Apa yang difirmankan Rabb kalian? ' mereka menjawab; 'Al Haq, dan Dia Maha Tinggi lagi Maha Besar.' Jin-jin pencuri berita mendengarkannya, (mereka bersusun-susun) sebagian di atas sebagian yang lainnya. Mereka mencuri dengar kalimat lalu menyampaikannya kepada yang berada di bawahnya. Bisa jadi jin itu diterjang bintang sebelum menyampaikannya kepada yang di bawahnya, kemudian mereka menyampaikanya kepada lisan dukun atau tukang sihir. Bisa jadi mereka tidak diterjang oleh bintang sehingga dapat menyampaikannya, kemudian dicampur dengan seratus kebohongan. Maka kalimat yang didengar bisa sesuai dengan yang dari langit.\""},"4122":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ حَدَّثَنَا الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَعِدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّفَا ذَاتَ يَوْمٍ فَقَالَ يَا صَبَاحَاهْ فَاجْتَمَعَتْ إِلَيْهِ قُرَيْشٌ قَالُوا مَا لَكَ قَالَ أَرَأَيْتُمْ لَوْ أَخْبَرْتُكُمْ أَنَّ الْعَدُوَّ يُصَبِّحُكُمْ أَوْ يُمَسِّيكُمْ أَمَا كُنْتُمْ تُصَدِّقُونِي قَالُوا بَلَى قَالَ فَإِنِّي نَذِيرٌ لَكُمْ بَيْنَ يَدَيْ عَذَابٍ شَدِيدٍ فَقَالَ أَبُو لَهَبٍ تَبًّا لَكَ أَلِهَذَا جَمَعْتَنَا فَأَنْزَلَ اللَّهُ{ تَبَّتْ يَدَا أَبِي لَهَبٍ }","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Muhammad bin Khazim] Telah menceritakan kepada kami [Al 'A'Masy] dari [Amru bin Murrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; Suatu hari Rasulullah shallallahu 'alaihi wasallam naik ke Shofa dan berkata: Wahai orang-orang! Lalu orang-orang Quraisy pun berkumpul mendekati beliau. Mereka bertanya: Ada apa? Beliau menjawab: 'Apa pendapat kalian jika aku memberitahu kalian bahwa ada musuh yang akan menyerang kalian dipagi hari atau di sore hari, apakah kalian akan membenarkanku (mempercayaiku)? Mereka menjawab: Tentu. Lalu beliau berkata: \"Sesungguhnya aku memperingatkan kalian tentang adzab yang berat di hadapan kalian. Maka Abu Lahab berkata: Apakah untuk ini engkau mengumpulkan kami?! Celakalah kamu! Maka Allah azza wa jalla menurunkan \"Binasalah kedua tangan abu Lahab dan Sesungguhnya dia akan binasa.\" (QS. Al Lahab: 1)."},"4123":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ عِنْدَ غُرُوبِ الشَّمْسِ فَقَالَ يَا أَبَا ذَرٍّ أَتَدْرِي أَيْنَ تَغْرُبُ الشَّمْسُ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهَا تَذْهَبُ حَتَّى تَسْجُدَ تَحْتَ الْعَرْشِ فَذَلِكَ قَوْلُهُ تَعَالَى{ وَالشَّمْسُ تَجْرِي لِمُسْتَقَرٍّ لَهَا ذَلِكَ تَقْدِيرُ الْعَزِيزِ الْعَلِيمِ }","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Al A'masy] dari [Ibrahim At Taimi] dari [Bapaknya] dari [Abu Dzar radliallahu 'anhu] dia berkata; Aku pernah bersama Nabi shallallahu 'alaihi wasallam di masjid pada saat matahari mulai terbenam. Lalu beliau bertanya; Wahai Abu Dzar, tahukah kamu dimana matahari terbenam? Aku menjawab; Allah dan Rasul-Nya yang lebih tahu. Beliau bersabda: \"Sesungguhnya matahari itu pergi hingga ia bersujud di bawah Arsy. Itulah yang dimaksud firman Allah Ta'ala: \"dan matahari berjalan ditempat peredarannya.\" Beliau bersabda: \"Tempat peredarannya berada dibawah Arsy, \" (Yasiin: 38)."},"4124":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَوْلِهِ تَعَالَى{ وَالشَّمْسُ تَجْرِي لِمُسْتَقَرٍّ لَهَا }قَالَ مُسْتَقَرُّهَا تَحْتَ الْعَرْشِ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al A'masy] dari [Ibrahim At Taimi] dari [Bapaknya] dari [Abu Dzar] dia berkata; Aku bertanya kepada Nabi shallallahu 'alaihi wasallam tentang firman Allah Ta'ala: \"dan matahari berjalan ditempat peredarannya.\" Beliau bersabda: \"Tempat peredarannya berada dibawah Arsy.\" (Yasiin: 38)."},"4125":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَنْبَغِي لِأَحَدٍ أَنْ يَكُونَ خَيْرًا مِنْ يُونُسَ بْنِ مَتَّى","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa'il] dari [Abdullah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak layak bagi seorang pun untuk mengatakan saya lebih baik dari Yunus bin Matta.\""},"4126":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ قَالَ حَدَّثَنِي أَبِي عَنْ هِلَالِ بْنِ عَلِيٍّ مِنْ بَنِي عَامِرِ بْنِ لُؤَيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ أَنَا خَيْرٌ مِنْ يُونُسَ بْنِ مَتَّى فَقَدْ كَذَبَ","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Muhammad bin Fulaih] dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Hilal bin 'Ali] dari Bani 'Amir bin Luay dari ['Atha bin Yasar] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam dia berkata; \"Barang siapa yang berkata; saya lebih baik dari Yunus bin Matta, maka ia telah berdusta.\""},"4127":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْعَوَّامِ قَالَ سَأَلْتُ مُجَاهِدًا عَنْ السَّجْدَةِ فِي ص قَالَ سُئِلَ ابْنُ عَبَّاسٍ فَقَالَ{ أُولَئِكَ الَّذِينَ هَدَى اللَّهُ فَبِهُدَاهُمْ اقْتَدِهْ }وَكَانَ ابْنُ عَبَّاسٍ يَسْجُدُ فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Gundar] Telah menceritakan kepada kami [Syu'bah] dari [Al 'Awwam] dia berkata; Aku bertanya kepada [Mujahid] mengenai ayat sajdah di dalam surat Shaad, lalu ia berkata; [Ibnu 'Abbas] ditanya tentang hal itu lalu ia menjawab; \"Mereka itulah orang-orang yang telah diberi petunjuk oleh Allah, maka ikutilah petunjuk mereka.\" (Al 'An'am: 90). Dan Ibnu Abbas sujud pada ayat itu."},"4128":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ الْعَوَّامِ قَالَ سَأَلْتُ مُجَاهِدًا عَنْ سَجْدَةٍ فِي ص فَقَالَسَأَلْتُ ابْنَ عَبَّاسٍ مِنْ أَيْنَ سَجَدْتَ فَقَالَ أَوَ مَا تَقْرَأُ{ وَمِنْ ذُرِّيَّتِهِ دَاوُدَ وَسُلَيْمَانَ }{ أُولَئِكَ الَّذِينَ هَدَى اللَّهُ فَبِهُدَاهُمْ اقْتَدِهْ }فَكَانَ دَاوُدُ مِمَّنْ أُمِرَ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْتَدِيَ بِهِ فَسَجَدَهَا دَاوُدُ عَلَيْهِ السَّلَام فَسَجَدَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ عُجَابٌ }عَجِيبٌ الْقِطُّ الصَّحِيفَةُ هُوَ هَا هُنَا صَحِيفَةُ الْحِسَابِ وَقَالَ مُجَاهِدٌ{ فِي عِزَّةٍ }مُعَازِّينَ{ الْمِلَّةِ الْآخِرَةِ }مِلَّةُ قُرَيْشٍ الْاخْتِلَاقُ الْكَذِبُ الْأَسْبَابُ طُرُقُ السَّمَاءِ فِي أَبْوَابِهَا قَوْلُهُ{ جُنْدٌ مَا هُنَالِكَ مَهْزُومٌ }يَعْنِي قُرَيْشًا{ أُولَئِكَ الْأَحْزَابُ }الْقُرُونُ الْمَاضِيَةُ{ فَوَاقٍ }رُجُوعٍ{ قِطَّنَا }عَذَابَنَا{ اتَّخَذْنَاهُمْ سُخْرِيًّا }أَحَطْنَا بِهِمْ{ أَتْرَابٌ }أَمْثَالٌ وَقَالَ ابْنُ عَبَّاسٍ الْأَيْدُ الْقُوَّةُ فِي الْعِبَادَةِ الْأَبْصَارُ الْبَصَرُ فِي أَمْرِ اللَّهِ{ حُبَّ الْخَيْرِ عَنْ ذِكْرِ رَبِّي }مِنْ ذِكْرِ طَفِقَ مَسْحًا يَمْسَحُ أَعْرَافَ الْخَيْلِ وَعَرَاقِيبَهَا{ الْأَصْفَادِ }الْوَثَاقِ","id":"Telah menceritakan kepadaku [Muhammad bin Abdullah] Telah menceritakan kepada kami [Muhammad bin 'Ubaid At Thanafisi] dari [Al 'Awwam] dia berkata; Aku bertanya kepada [Mujahid] mengenai ayat sajdah pada surat Shaad. Ia menjawab; Aku bertanya kepada Ibnu Abbas, pada ayat mana kamu bersujud? [Ibnu Abbas] menjawab; Apakah kamu tidak membaca; dan kepada sebahagian dari keturunannya (Nuh) yaitu Daud, Sulaiman,... (Al An'am: 84). Mereka itulah orang-orang yang telah diberi petunjuk oleh Allah, maka ikutilah petunjuk mereka. (Al An'am: 90). Nabi Daud adalah salah satu orang yang diperintahkan oleh Rasulullah shallallahu 'alaihi wasallam untuk kalian ikuti. Maka ketika Daud sujud pada surat itu, Rasulullah shallallahu 'alaihi wasallam pun sujud. 'UJAABUN, artinya lembaran hisab. Mujahid berkata; FI 'IZZATIN, yakni mereka dimuliakan. AL MILLAH AL AKHIRAH yaitu agama Quraisy yang bercampur kedustaan. JUNDUN MAA HUNAALIKA MAHZUUM, yaitu orang-orang Quraisy."},"4129":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا رَوْحٌ وَمُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ عِفْرِيتًا مِنْ الْجِنِّ تَفَلَّتَ عَلَيَّ الْبَارِحَةَ أَوْ كَلِمَةً نَحْوَهَا لِيَقْطَعَ عَلَيَّ الصَّلَاةَ فَأَمْكَنَنِي اللَّهُ مِنْهُ وَأَرَدْتُ أَنْ أَرْبِطَهُ إِلَى سَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ حَتَّى تُصْبِحُوا وَتَنْظُرُوا إِلَيْهِ كُلُّكُمْ فَذَكَرْتُ قَوْلَ أَخِي سُلَيْمَانَ رَبِّ{ هَبْ لِي مُلْكًا لَا يَنْبَغِي لِأَحَدٍ مِنْ بَعْدِي }قَالَ رَوْحٌ فَرَدَّهُ خَاسِئًا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] Telah menceritakan kepada kami [Rauh] dan [Muhammad bin Ja'far] dari [Syu'bah] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya jin ifrit telah meloncatiku semalam -atau beliau bersabda dengan kalimat yang serupa- untuk memutuskan shalatku maka Allah memberi kekuatan kepadaku darinya, dan sungguh aku ingin mengikatnya di salah satu tiang masjid, lalu pada pagi harinya kalian semua bisa melihatnya.\" Beliau bersabda lagi: \"namun aku teringat akan doa saudaraku Sulaiman; 'Tuhanku anugerahkanlah kepadaku kerajaan yang tidak dimiliki oleh seorangpun sesudahku.' Rauh berkata; \"Maka Rasulullah shallallahu 'alaihi wasallam pun melepaskannya dalam keadaan hina.\""},"4130":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ دَخَلْنَا عَلَى عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَيَا أَيُّهَا النَّاسُ مَنْ عَلِمَ شَيْئًا فَلْيَقُلْ بِهِ وَمَنْ لَمْ يَعْلَمْ فَلْيَقُلْ اللَّهُ أَعْلَمُ فَإِنَّ مِنْ الْعِلْمِ أَنْ يَقُولَ لِمَا لَا يَعْلَمُ اللَّهُ أَعْلَمُ قَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ قُلْ مَا أَسْأَلُكُمْ عَلَيْهِ مِنْ أَجْرٍ وَمَا أَنَا مِنْ الْمُتَكَلِّفِينَ }وَسَأُحَدِّثُكُمْ عَنْ الدُّخَانِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا قُرَيْشًا إِلَى الْإِسْلَامِ فَأَبْطَئُوا عَلَيْهِ فَقَالَ اللَّهُمَّ أَعِنِّي عَلَيْهِمْ بِسَبْعٍ كَسَبْعِ يُوسُفَ فَأَخَذَتْهُمْ سَنَةٌ فَحَصَّتْ كُلَّ شَيْءٍ حَتَّى أَكَلُوا الْمَيْتَةَ وَالْجُلُودَ حَتَّى جَعَلَ الرَّجُلُ يَرَى بَيْنَهُ وَبَيْنَ السَّمَاءِ دُخَانًا مِنْ الْجُوعِ قَالَ اللَّهُ عَزَّ وَجَلَّ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ يَغْشَى النَّاسَ هَذَا عَذَابٌ أَلِيمٌ }قَالَ فَدَعَوْا{ رَبَّنَا اكْشِفْ عَنَّا الْعَذَابَ إِنَّا مُؤْمِنُونَ أَنَّى لَهُمْ الذِّكْرَى وَقَدْ جَاءَهُمْ رَسُولٌ مُبِينٌ ثُمَّ تَوَلَّوْا عَنْهُ وَقَالُوا مُعَلَّمٌ مَجْنُونٌ إِنَّا كَاشِفُو الْعَذَابِ قَلِيلًا إِنَّكُمْ عَائِدُونَ }أَفَيُكْشَفُ الْعَذَابُ يَوْمَ الْقِيَامَةِ قَالَ فَكُشِفَ ثُمَّ عَادُوا فِي كُفْرِهِمْ فَأَخَذَهُمْ اللَّهُ يَوْمَ بَدْرٍ قَالَ اللَّهُ تَعَالَى{ يَوْمَ نَبْطِشُ الْبَطْشَةَ الْكُبْرَى إِنَّا مُنْتَقِمُونَ }","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dia berkata; Ketika aku menemui [Abdullah bin Mas'ud], ia berkata; Barang siapa yang mengetahui sesuatu hendaklah ia mengatakan apa yang diketahuinya. Dan barang siapa yang tidak mengetahuinya maka hendaklah ia mengatakan Allah yang Maha Tahu. Karena termasuk dari ilmu ketika ia tidak mengetahuinya, ia mengatakan; 'Allah Maha tahu.' Allah Azza wa Jalla berfirman kepada Nabi shallallahu 'alaihi wasallam: Katakanlah (hai Muhammad): \"Aku tidak meminta upah sedikitpun padamu atas da'wahku dan bukanlah aku termasuk orang-orang yang mengada-adakan. (Shaad: 86). Dan Aku akan menyampaikan kepada kalian tentang Kabut, sesungguhnya Rasulullah shallallahu 'alaihi wasallam menyeru orang-orang Quraisy untuk memeluk Islam, namun menangguhkan untuk menerimanya. Maka Nabi shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam berdo'a: Ya Allah, tolonglah aku menghadapi mereka dengan mengirimkan kepada mereka tujuh tahun kelaparan sebagaimana tujuh tahun Yusuf. Maka mereka diserang tahun kelaparan hingga mereka makan bangkai dan kulit. Seseorang dari mereka melihat ada kabut antara dia dengan langit kerena rasa laparnya. Allah Azza Wa Jalla berfirman: Maka tunggulah hari ketika langit membawa kabut yang nyata yang meliputi manusia. Inilah azab yang pedih. (Ad Dukhan: 10-11). Abdullah berkata; maka mereka pun berdo'a: \"Ya Tuhan kami, lenyapkanlah dari kami azab itu. Sesungguhnya kami akan beriman.\" Bagaimanakah mereka dapat menerima peringatan, padahal telah datang kepada mereka seorang rasul yang memberi penjelasan, kemudian mereka berpaling daripadanya dan berkata: \"Dia adalah seorang yang menerima ajaran (dari orang lain) lagi pula seorang yang gila Sesungguhnya (kalau) Kami akan melenyapkan siksaan itu agak sedikit sesungguhnya kamu akan kembali (ingkar). (Ad Dukhan: 12-15). Apakah Adzab mereka akan dihentikan pada hari kiamat. Ibnu Mas'ud berkata; Maka adzab dihentikan, tetapi mereka kembali kepada kekufuran. Hingga Allah pun menghancurkan mereka pada perang Badar sebagaimana firman-Nya: \"(Ingatlah) hari (ketika) Kami menghantam mereka dengan hantaman yang keras. Sesungguhnya Kami adalah Pemberi balasan.\" (Ad Dukhan: 16)."},"4131":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ يَعْلَى إِنَّ سَعِيدَ بْنَ جُبَيْرٍ أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ نَاسًا مِنْ أَهْلِ الشِّرْكِ كَانُوا قَدْ قَتَلُوا وَأَكْثَرُوا وَزَنَوْا وَأَكْثَرُوا فَأَتَوْا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّ الَّذِي تَقُولُ وَتَدْعُو إِلَيْهِ لَحَسَنٌ لَوْ تُخْبِرُنَا أَنَّ لِمَا عَمِلْنَا كَفَّارَةً فَنَزَلَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ }وَنَزَلَتْ{ قُلْ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] mengabarkan kepada mereka dia berkata; [Ya'laa], [Sa'id bin Jubair] telah mengabarkan kepadanya dari [Ibnu Abbas radliallahu 'anhuma], bahwa orang-orang musyrik dahulu sering membunuh, sering berzina dan lalu mereka mendatangi Nabi shallallahu 'alaihi wasallam dan berkata; wahai Muhammad, apa yang engkau katakan dan engkau serukan adalah baik jika engkau mengabarkan kepada kami bahwa apa yang telah kami perbuat ada kafaratnya, lalu Allah Azza wa jalla menurunkan ayat: Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar dan tidak berzina, dan turunlah ayat: Katakanlah: \"Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah. (Az Zumar: 53)."},"4132":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ حَبْرٌ مِنْ الْأَحْبَارِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا مُحَمَّدُ إِنَّا نَجِدُ أَنَّ اللَّهَ يَجْعَلُ السَّمَوَاتِ عَلَى إِصْبَعٍ وَالْأَرَضِينَ عَلَى إِصْبَعٍ وَالشَّجَرَ عَلَى إِصْبَعٍ وَالْمَاءَ وَالثَّرَى عَلَى إِصْبَعٍ وَسَائِرَ الْخَلَائِقِ عَلَى إِصْبَعٍ فَيَقُولُ أَنَا الْمَلِكُ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ تَصْدِيقًا لِقَوْلِ الْحَبْرِ ثُمَّ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَمَا قَدَرُوا اللَّهَ حَقَّ قَدْرِهِ وَالْأَرْضُ جَمِيعًا قَبْضَتُهُ يَوْمَ الْقِيَامَةِ وَالسَّمَوَاتُ مَطْوِيَّاتٌ بِيَمِينِهِ سُبْحَانَهُ وَتَعَالَى عَمَّا يُشْرِكُونَ }","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Ibrahim] dari [Abidah] dari [Abdullah radliallahu 'anhu] dia berkata; Seorang rahib datang kepada Nabi shallallahu 'alaihi wasallam lalu dia berkata; 'Ya Muhammad, Kami mendapatkan bahwa Allah Ta'ala memegang langit, bumi, pohon-pohon, air, binatang-binatang, dan seluruh makhluk dengan jari-Nya seraya berkata; 'Akulah Raja (Penguasa)! 'Maka Rasulullah shallallahu 'alaihi wasallam pun tertawa hingga nampak gigi serinya sebagai pembenaran terhadap perkataan rahib tersebut. Kemudian beliau membaca ayat: 'Dan mereka tidak mengagungkan Allah dengan pengagungan yang semestinya padahal bumi seluruhnya dalam genggaman-Nya pada hari kiamat dan langit digulung dengan tangan kanan-Nya. Maha Suci Tuhan dan Maha Tinggi Dia dari apa yang mereka persekutukan.' (Az Zumar: 67)."},"4133":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدِ بْنِ مُسَافِرٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقْبِضُ اللَّهُ الْأَرْضَ وَيَطْوِي السَّمَوَاتِ بِيَمِينِهِ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ مُلُوكُ الْأَرْضِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] dia berkata; Telah menceritakan kepadaku [Al Laits] dia berkata; Telah menceritakan kepadaku [Abdurrahman bin Khalid bin Musafir] dari [Ibnu Syihab] dari [Abu Salamah] bahwa [Abu Hurairah] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menggenggam bumi dan melipat langit dengan tangan kanannya seraya berkata: 'Akulah Raja, mana yang mengaku raja dibumi? '\""},"4134":{"ar":"حَدَّثَنِي الْحَسَنُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ خَلِيلٍ أَخْبَرَنَا عَبْدُ الرَّحِيمِ عَنْ زَكَرِيَّاءَ بْنِ أَبِي زَائِدَةَ عَنْ عَامِرٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي أَوَّلُ مَنْ يَرْفَعُ رَأْسَهُ بَعْدَ النَّفْخَةِ الْآخِرَةِ فَإِذَا أَنَا بِمُوسَى مُتَعَلِّقٌ بِالْعَرْشِ فَلَا أَدْرِي أَكَذَلِكَ كَانَ أَمْ بَعْدَ النَّفْخَةِ","id":"Telah menceritakan kepadaku [Al Hasan] Telah menceritakan kepada kami [Ismail bin Khalil] Telah mengabarkan kepada kami [Abdurrahim] dari [Zakaria bin Abu Zaidah] dari ['Amir] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: Akulah orang yang pertama kali mengangkat kepalanya setelah tiupan sangkakala terakhir. Namun tiba-tiba aku melihat Musa bergantung dibawah Arsy, aku tidak tahu apakah ia ikut pingsan atau bangkit lebih dulu setelah tiupan sangkakala."},"4135":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ أَبَا صَالِحٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَ النَّفْخَتَيْنِ أَرْبَعُونَ قَالُوا يَا أَبَا هُرَيْرَةَ أَرْبَعُونَ يَوْمًا قَالَ أَبَيْتُ قَالَ أَرْبَعُونَ سَنَةً قَالَ أَبَيْتُ قَالَ أَرْبَعُونَ شَهْرًا قَالَ أَبَيْتُ وَيَبْلَى كُلُّ شَيْءٍ مِنْ الْإِنْسَانِ إِلَّا عَجْبَ ذَنَبِهِ فِيهِ يُرَكَّبُ الْخَلْقُ","id":"Telah menceritakan kepada kami [Amru bin Hafsh] Telah menceritakan kepada kami [Bapakku] dia berkata; Telah menceritakan kepada kami [Al A'masy] dia berkata; Aku mendengar [Abu Shalih] berkata; Aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Antara dua tiupan sangkakala terdapat empat puluh.\" Mereka bertanya: Hai Abu Hurairah? Empat puluh harikah? Abu Hurairah berkata: 'Aku enggan menjawab.' Mereka bertanya: Empat puluh tahunkah? Abu Hurairah berkata: Aku enggan menjawab. Mereka bertanya: 'Empat puluh bulankah? ' Abu Hurairah berkata: Aku enggan menjawab. Ia berkata: Tidak ada sesuatupu pun melainkan telah hancur kecuali satu tulang, yaitu tulang ekor. Dari situlah manusia disusun."},"4136":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ قَالَ قُلْتُ لِعَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَخْبِرْنِي بِأَشَدِّ مَا صَنَعَ الْمُشْرِكُونَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِفِنَاءِ الْكَعْبَةِ إِذْ أَقْبَلَ عُقْبَةُ بْنُ أَبِي مُعَيْطٍ فَأَخَذَ بِمَنْكِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوَى ثَوْبَهُ فِي عُنُقِهِ فَخَنَقَهُ بِهِ خَنْقًا شَدِيدًا فَأَقْبَلَ أَبُو بَكْرٍ فَأَخَذَ بِمَنْكِبِهِ وَدَفَعَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ{ أَتَقْتُلُونَ رَجُلًا أَنْ يَقُولَ رَبِّيَ اللَّهُ وَقَدْ جَاءَكُمْ بِالْبَيِّنَاتِ مِنْ رَبِّكُمْ }","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Al Walid bin Muslim] Telah menceritakan kepada kami [Al Auza'i] dia berkata; Telah menceritakan kepadaku [Yahya bin Abu Katsir] dia berkata; Telah menceritakan kepadaku [Muhammad bin Ibrahim At Taimi] dia berkata; Telah menceritakan kepadaku [Urwah bin Zubair] dia berkata kepada [Abdullah bin Amru bin Al Ash]; \"Kabarkanlah kepadaku perbuatan paling kejam yang dilakukan kaum musyrikin terhadap Rasulullah shallallahu 'alaihi wasallam. Dia berkata; \"Ketika Rasulullah sedang shalat di halaman Ka'bah tiba-tiba `Uqbah bin Abi Mu'aith menghampiri beliau dan menarik bahunya shallallahu 'alaihi wasallam serta melilitkan bajunya ke leher beliau dan mencekiknya kuat-kuat. Kemudian Abu Bakar mendekatinya, lalu dia menarik bahunya dan mendorongnya dari Rasulullah shallallahu 'alaihi wasallam seraya berkata: \"Apakah kamu akan membunuh seorang laki-laki karena dia menyatakan: \"Rabbku adalah Allah, padahal telah datang kepadamu keterangan-keterangan dari Rabbmu.\""},"4137":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ رَوْحِ بْنِ الْقَاسِمِ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ ابْنِ مَسْعُودٍ{ وَمَا كُنْتُمْ تَسْتَتِرُونَ أَنْ يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَا أَبْصَارُكُمْ }الْآيَةَ قَالَ كَانَ رَجُلَانِ مِنْ قُرَيْشٍ وَخَتَنٌ لَهُمَا مِنْ ثَقِيفَ أَوْ رَجُلَانِ مِنْ ثَقِيفَ وَخَتَنٌ لَهُمَا مِنْ قُرَيْشٍ فِي بَيْتٍ فَقَالَ بَعْضُهُمْ لِبَعْضٍ أَتُرَوْنَ أَنَّ اللَّهَ يَسْمَعُ حَدِيثَنَا قَالَ بَعْضُهُمْ يَسْمَعُ بَعْضَهُ وَقَالَ بَعْضُهُمْ لَئِنْ كَانَ يَسْمَعُ بَعْضَهُ لَقَدْ يَسْمَعُ كُلَّهُ فَأُنْزِلَتْ{ وَمَا كُنْتُمْ تَسْتَتِرُونَ أَنْ يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَا أَبْصَارُكُمْ }الْآيَةَ","id":"Telah menceritakan kepada kami [As Shalt bin Muhammad] Telah menceritakan kepada kami [Yazid bin Zura'i] dari [Rauh bin Al Qasim] dari [Manshur] dari [Mujahid] dari [Abu Ma'mar] dari [Ibnu Mas'ud] mengenai firman Allah: \"Kamu sekali-sekali tidak dapat bersembunyi dari kesaksian pendengaran, penglihatan dan kulitmu kepadamu bahkan kamu mengira bahwa Allah tidak mengetahui kebanyakan dari apa yang kamu kerjakan.\" (Fushshilat: 22). Ada dua orang Quraisy salah dan seorang lagi dari Tsaqif, atau dua orang dari Tsaqif sedangkan satu lagi dari Quraisy disisi Ka'bah. Salah seorang mereka berkata kepada yang lainnya; Apakah menurut kalian Allah mendengar perkataan kita ini? Sebagian berkata: Dia mendengar sebagian saja. Sebagian yang lain berkata; Jika Dia mendengar sebagiannya pasti Dia mendengar semuanya. Maka turunlah ayat; \"Kamu sekali-sekali tidak dapat bersembunyi dari kesaksian pendengaran, penglihatan dan kulitmu kepadamu bahkan kamu mengira bahwa Allah tidak mengetahui kebanyakan dari apa yang kamu kerjakan.\" (Fushshilat: 22)."},"4138":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مَنْصُورٌ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَاجْتَمَعَ عِنْدَ الْبَيْتِ قُرَشِيَّانِ وَثَقَفِيٌّ أَوْ ثَقَفِيَّانِ وَقُرَشِيٌّ كَثِيرَةٌ شَحْمُ بُطُونِهِمْ قَلِيلَةٌ فِقْهُ قُلُوبِهِمْ فَقَالَ أَحَدُهُمْ أَتُرَوْنَ أَنَّ اللَّهَ يَسْمَعُ مَا نَقُولُ قَالَ الْآخَرُ يَسْمَعُ إِنْ جَهَرْنَا وَلَا يَسْمَعُ إِنْ أَخْفَيْنَا وَقَالَ الْآخَرُ إِنْ كَانَ يَسْمَعُ إِذَا جَهَرْنَا فَإِنَّهُ يَسْمَعُ إِذَا أَخْفَيْنَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا كُنْتُمْ تَسْتَتِرُونَ أَنْ يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَا أَبْصَارُكُمْ وَلَا جُلُودُكُمْ }الْآيَةَوَكَانَ سُفْيَانُ يُحَدِّثُنَا بِهَذَا فَيَقُولُ حَدَّثَنَا مَنْصُورٌ أَوْ ابْنُ أَبِي نَجِيحٍ أَوْ حُمَيْدٌ أَحَدُهُمْ أَوْ اثْنَانِ مِنْهُمْ ثُمَّ ثَبَتَ عَلَى مَنْصُورٍ وَتَرَكَ ذَلِكَ مِرَارًا غَيْرَ مَرَّةٍ وَاحِدَةٍحَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Manshur] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah radliallahu 'anhu] dia berkata; Suatu ketika ada tiga orang berkumpul di samping Ka'bah; dua orang dari Quraisy dan satu orang dari Tsaqif atau yang dua orang dari Tsaqif dan satu orang dari Quraisy, perut mereka besar namun hati mereka sedikit memiliki ilmu, lalu salah seorang dari mereka berkata: Apakah menurut kalian Allah mendengar apa yang kita katakan? Yang lain berkata: Jika kita berbicara dengan keras Dia mendengarnya dan jika kita berkata dengan pelan Dia tidak mendengarnya, sedangkan yang lainnya lagi berkata: Jika Dia mendengar ketika kita bicara keras, pasti Dia juga mendengar ketika kita bicara pelan. kemudian Allah menurunkan ayat: \"Kamu sekali-sekali tidak dapat bersembunyi dari kesaksian pendengaran, penglihatan dan kulitmu kepadamu bahkan kamu mengira bahwa Allah tidak mengetahui kebanyakan dari apa yang kamu kerjakan\" (Fushshilat: 22). [Sufyan] bercerita kepada kami mengenai Hadits ini, ia berkata; Telah menceritakan kepada kami [Manshur] atau [Ibnu Abu Najih] atau [Humaid] salah satu atau dua orang dari mereka. Kemudian ia menetapkan riwayat Manshur dengan meninggalkan yang lainnya. Telah menceritakan kepada kami [Amru bin Ali] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Sufyan At Tsauri] dia berkata; Telah menceritakan kepadaku [Manshur] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] dengan Hadits yang serupa."},"4139":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ قَالَ سَمِعْتُ طَاوُسًا عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ سُئِلَ عَنْ قَوْلِهِ{ إِلَّا الْمَوَدَّةَ فِي الْقُرْبَى }فَقَالَ سَعِيدُ بْنُ جُبَيْرٍ قُرْبَى آلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ابْنُ عَبَّاسٍ عَجِلْتَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ بَطْنٌ مِنْ قُرَيْشٍ إِلَّا كَانَ لَهُ فِيهِمْ قَرَابَةٌ فَقَالَ إِلَّا أَنْ تَصِلُوا مَا بَيْنِي وَبَيْنَكُمْ مِنْ الْقَرَابَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Maisarah] dia berkata; Aku mendengar [Thawus] dari [Ibnu Abbas radliallahu 'anhuma] bahwa ia ditanya mengenai firman Allah: kecuali kasih sayang dalam kekeluargaan … (QS. Asysyura 23), maka Sa'id bin Jubair berkata; 'Qurbaa' maksudnya adalah Keluarga Muhammad shallallahu 'alaihi wasallam. Ibnu 'Abbas berkata; \"Engkau terlalu terburu-buru, sesungguhnya Rasulullah shallallahu 'alaihi wasallam bukanlah marga (clan) dari Quraisy selain beliau shallallahu 'alaihi wasallam hanyalah mempunyai hubungan keluarga dengan mereka. Ibnu Abbas berkata; maksudnya kecuali kalian bisa menyambung hubungan kekeluargaan antara diriku dengan kalian.\""},"4140":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَى الْمِنْبَرِ{ وَنَادَوْا يَا مَالِكُ لِيَقْضِ عَلَيْنَا رَبُّكَ }وَقَالَ قَتَادَةُ{ مَثَلًا لِلْآخِرِينَ }عِظَةً لِمَنْ بَعْدَهُمْ وَقَالَ غَيْرُهُ{ مُقْرِنِينَ }ضَابِطِينَ يُقَالُ فُلَانٌ مُقْرِنٌ لِفُلَانٍ ضَابِطٌ لَهُ وَالْأَكْوَابُ الْأَبَارِيقُ الَّتِي لَا خَرَاطِيمَ لَهَا{ أَوَّلُ الْعَابِدِينَ }أَيْ مَا كَانَ فَأَنَا أَوَّلُ الْآنِفِينَ وَهُمَا لُغَتَانِ رَجُلٌ عَابِدٌ وَعَبِدٌ وَقَرَأَ عَبْدُ اللَّهِ وَقَالَ الرَّسُولُ يَا رَبِّ وَيُقَالُ{ أَوَّلُ الْعَابِدِينَ }الْجَاحِدِينَ مِنْ عَبِدَ يَعْبَدُ وَقَالَ قَتَادَةُ{ فِي أُمِّ الْكِتَابِ }جُمْلَةِ الْكِتَابِ أَصْلِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru] dari ['Atha] dari [Shafwan bin Ya'la] dari [Bapaknya] dia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam di atas mimbar membaca ayat: Mereka berseru: \"Hai Malik biarlah Tuhanmu membunuh kami saja.\" (Az Zukhruf: 77). Qatadah berkata; MATSALAN LIL AAKHARIIN; Yaitu pelajaran bagi orang-orang sesudah mereka."},"4141":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَمَضَى خَمْسٌ الدُّخَانُ وَالرُّومُ وَالْقَمَرُ وَالْبَطْشَةُ وَاللِّزَامُ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah] dia berkata; lima hal telah berlalu; Kabut, kekalahan Ramawi, terbelah bulan, Hantaman keras dan kematian.\""},"4142":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ قَالَ قَالَ عَبْدُ اللَّهِإِنَّمَا كَانَ هَذَا لِأَنَّ قُرَيْشًا لَمَّا اسْتَعْصَوْا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا عَلَيْهِمْ بِسِنِينَ كَسِنِي يُوسُفَ فَأَصَابَهُمْ قَحْطٌ وَجَهْدٌ حَتَّى أَكَلُوا الْعِظَامَ فَجَعَلَ الرَّجُلُ يَنْظُرُ إِلَى السَّمَاءِ فَيَرَى مَا بَيْنَهُ وَبَيْنَهَا كَهَيْئَةِ الدُّخَانِ مِنْ الْجَهْدِ فَأَنْزَلَ اللَّهُ تَعَالَى{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ يَغْشَى النَّاسَ هَذَا عَذَابٌ أَلِيمٌ }قَالَ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ لَهُ يَا رَسُولَ اللَّهِ اسْتَسْقِ اللَّهَ لِمُضَرَ فَإِنَّهَا قَدْ هَلَكَتْ قَالَ لِمُضَرَ إِنَّكَ لَجَرِيءٌ فَاسْتَسْقَى لَهُمْ فَسُقُوا فَنَزَلَتْ{ إِنَّكُمْ عَائِدُونَ }فَلَمَّا أَصَابَتْهُمْ الرَّفَاهِيَةُ عَادُوا إِلَى حَالِهِمْ حِينَ أَصَابَتْهُمْ الرَّفَاهِيَةُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ يَوْمَ نَبْطِشُ الْبَطْشَةَ الْكُبْرَى إِنَّا مُنْتَقِمُونَ }قَالَ يَعْنِي يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Muslim] dari [Masruq] dia berkata; [Abdullah] berkata; sesungguhnya ayat ini adalah bagi orang-orang Quraisy tatkala mereka durhaka kepada Nabi shallallahu 'alaihi wasallam. lalu beliau mendoakan mereka agar tertimpa kelaparan seperti kaum Yusuf. Mereka tertimpa kemarau dan penderitaan hingga seseorang melihat ke langit, ia melihat seperti wujud kabut antara dirinya dan langit, hingga mereka memakan tulang karena musim kemarau itu. Maka Allah menurunkan ayat: \"Maka tunggulah hari ketika langit membawa kabut yang nyata, yang meliputi manusia.\" (Ad Dukhaan: 10). Seseorang kemudian mendatangi nabi shallallahu 'alaihi wasallam dan berkata: Wahai Rasulullah, mintakan hujan pada Allah untuk Mudlar karena mereka telah binasa. Beliau bersabda kepada Mudlar: \"Sesungguhnya kau gegabah.\" Maka Nabi shallallahu 'alaihi wasallam berdoa meminta hujan untuk mereka lalu Allah 'azza wajalla menurunkan hujan, lalu turunlah ayat: \"Sesungguhnya (kalau) kami akan melenyapkan siksaan itu agak sedikit. Sesungguhnya kamu akan kembali (ingkar).\" (Ad Dukhaan: 10-15). Dan saat mereka mendapatkan kemakmuran, mereka kembali lagi seperti semula. Lalu Allah 'azza wajalla menurunkan: (Ingatlah) hari (ketika) Kami menghantam mereka dengan hantaman yang keras. Sesungguhnya Kami adalah Pemberi balasan. (Ad Dukhaan: 16). Abdullah berkata: Maksudnya yaitu perang Badar."},"4143":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ دَخَلْتُ عَلَى عَبْدِ اللَّهِ فَقَالَإِنَّ مِنْ الْعِلْمِ أَنْ تَقُولَ لِمَا لَا تَعْلَمُ اللَّهُ أَعْلَمُ إِنَّ اللَّهَ قَالَ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ قُلْ مَا أَسْأَلُكُمْ عَلَيْهِ مِنْ أَجْرٍ وَمَا أَنَا مِنْ الْمُتَكَلِّفِينَ }إِنَّ قُرَيْشًا لَمَّا غَلَبُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَعْصَوْا عَلَيْهِ قَالَ اللَّهُمَّ أَعِنِّي عَلَيْهِمْ بِسَبْعٍ كَسَبْعِ يُوسُفَ فَأَخَذَتْهُمْ سَنَةٌ أَكَلُوا فِيهَا الْعِظَامَ وَالْمَيْتَةَ مِنْ الْجَهْدِ حَتَّى جَعَلَ أَحَدُهُمْ يَرَى مَا بَيْنَهُ وَبَيْنَ السَّمَاءِ كَهَيْئَةِ الدُّخَانِ مِنْ الْجُوعِ قَالُوا{ رَبَّنَا اكْشِفْ عَنَّا الْعَذَابَ إِنَّا مُؤْمِنُونَ }فَقِيلَ لَهُ إِنْ كَشَفْنَا عَنْهُمْ عَادُوا فَدَعَا رَبَّهُ فَكَشَفَ عَنْهُمْ فَعَادُوا فَانْتَقَمَ اللَّهُ مِنْهُمْ يَوْمَ بَدْرٍ فَذَلِكَ قَوْلُهُ تَعَالَى{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ إِلَى قَوْلِهِ جَلَّ ذِكْرُهُ إِنَّا مُنْتَقِمُونَ }","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Ad Dluha] dari [Masruq] dia berkata; ketika aku menemui [Abdullah] dia berkata; Diantara tanda pemahaman (ilmu) seseorang adalah dengan mengatakan Allahu a'lam untuk sesuatu yang tidak ia ketahui. Sesungguhnya Allah berfirman kepada Nabi-Nya: Katakanlah (hai Muhammad): \"Aku tidak meminta upah sedikitpun padamu atas da'wahku dan bukanlah aku termasuk orang-orang yang mengada-adakan. (Shaad: 86). Sesunggunya kaum Quraisy tatkala menyerang Nabi shallallahu 'alaihi wasallam dan mendurhakai beliau, beliau mendoakan mereka: \"Ya Allah timpakan kepada mereka kelaparan seperti kaum Yusuf. Maka mereka tertimpa tahun kekeringan dan penderitaan hingga mereka memakan tulang dan bangkai. Seseorang melihat ke langit, ia melihat seperti wujud kabut antara dirinya dan langit karena kelaparan. Lalu mereka berkata; \"Ya Tuhan kami, lenyapkanlah dari kami azab itu. Sesungguhnya kami akan beriman.\" Maka dikatakan kepada beliau, jika kami lenyapkan adzab dari mereka, mereka akan kembali durhaka. Namun Rasulullah shallallahu 'alaihi wasallam memohon kepada Rabbnya, Allah pun melenyapkannya dari mereka. Kemudian mereka kembali durhaka. Maka Allah membalas mereka pada hari perang Badar, itulah yang dimaksud firman Allah: \"Maka tunggulah hari ketika langit membawa kabut yang nyata, yang meliputi manusia. inilah azab yang pedih.\" Hingga ayat: Sesungguhnya Kami adalah Pemberi balasan."},"4144":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ دَخَلْتُ عَلَى عَبْدِ اللَّهِ ثُمَّ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا دَعَا قُرَيْشًا كَذَّبُوهُ وَاسْتَعْصَوْا عَلَيْهِ فَقَالَ اللَّهُمَّ أَعِنِّي عَلَيْهِمْ بِسَبْعٍ كَسَبْعِ يُوسُفَ فَأَصَابَتْهُمْ سَنَةٌ حَصَّتْ يَعْنِي كُلَّ شَيْءٍ حَتَّى كَانُوا يَأْكُلُونَ الْمَيْتَةَ فَكَانَ يَقُومُ أَحَدُهُمْ فَكَانَ يَرَى بَيْنَهُ وَبَيْنَ السَّمَاءِ مِثْلَ الدُّخَانِ مِنْ الْجَهْدِ وَالْجُوعِ ثُمَّ قَرَأَ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ يَغْشَى النَّاسَ هَذَا عَذَابٌ أَلِيمٌ حَتَّى بَلَغَ إِنَّا كَاشِفُو الْعَذَابِ قَلِيلًا إِنَّكُمْ عَائِدُونَ }قَالَ عَبْدُ اللَّهِ أَفَيُكْشَفُ عَنْهُمْ الْعَذَابُ يَوْمَ الْقِيَامَةِ قَالَ وَالْبَطْشَةُ الْكُبْرَى يَوْمَ بَدْرٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Jarir bin Hazim] dari [Al A'masy] dari [Abu Ad Dluha] dari [Masruq] dia berkata; Aku menemui [Abdullah] lalu ia berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam tatkala menyeru kaum Quraisy, mereka mendustakannya dan berbuat durhaka kepada beliau. Maka Nabi shallallahu 'alaihi wasallam berdo'a: \"Ya Allah timpakan kepada mereka kelaparan seperti kaum Yusuf. Maka mereka tertimpa tahun kelaparan hingga mereka memakan bangkai. Salah seorang dari mereka berdiri melihat ke langit, ia melihat seperti wujud kabut antara dirinya dan langit karena kelaparan dan keletihan. Kemudian Abdullah membaca: \"Maka tunggulah hari ketika langit membawa kabut yang nyata, yang meliputi manusia. inilah azab yang pedih.\" Hingga ayat: Sesungguhnya (kalau) Kami akan melenyapkan siksaan itu agak sedikit sesungguhnya kamu akan kembali (ingkar). Abdullah berkata; Maka bagaimana siksa itu akan dilenyapkan dari mereka pada hari kiamat? Dia juga berkata; 'Hantaman keras maksudnya adalah pada waktu perang Badar.'"},"4145":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدٌ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ وَمَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ قَالَ عَبْدُ اللَّهِإِنَّ اللَّهَ بَعَثَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ{ قُلْ مَا أَسْأَلُكُمْ عَلَيْهِ مِنْ أَجْرٍ وَمَا أَنَا مِنْ الْمُتَكَلِّفِينَ }فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا رَأَى قُرَيْشًا اسْتَعْصَوْا عَلَيْهِ فَقَالَ اللَّهُمَّ أَعِنِّي عَلَيْهِمْ بِسَبْعٍ كَسَبْعِ يُوسُفَ فَأَخَذَتْهُمْ السَّنَةُ حَتَّى حَصَّتْ كُلَّ شَيْءٍ حَتَّى أَكَلُوا الْعِظَامَ وَالْجُلُودَ فَقَالَ أَحَدُهُمْ حَتَّى أَكَلُوا الْجُلُودَ وَالْمَيْتَةَ وَجَعَلَ يَخْرُجُ مِنْ الْأَرْضِ كَهَيْئَةِ الدُّخَانِ فَأَتَاهُ أَبُو سُفْيَانَ فَقَالَ أَيْ مُحَمَّدُ إِنَّ قَوْمَكَ قَدْ هَلَكُوا فَادْعُ اللَّهَ أَنْ يَكْشِفَ عَنْهُمْ فَدَعَا ثُمَّ قَالَ تَعُودُونَ بَعْدَ هَذَا فِي حَدِيثِ مَنْصُورٍ ثُمَّ قَرَأَ{ فَارْتَقِبْ يَوْمَ تَأْتِي السَّمَاءُ بِدُخَانٍ مُبِينٍ إِلَى عَائِدُونَ }أَنَكْشِفُ عَنْهُمْ عَذَابَ الْآخِرَةِ فَقَدْ مَضَى الدُّخَانُ وَالْبَطْشَةُ وَاللِّزَامُ وَقَالَ أَحَدُهُمْ الْقَمَرُ وَقَالَ الْآخَرُ وَالرُّومُ","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah mengabarkan kepada kami [Muhammad] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dan [Manshur] dari [Abu Ad Dluha] dari [Masruq] dia berkata; [Abdullah] berkata; Sesungguhnya Allah mengutus Rasulullah shallallahu 'alaihi wasallam seraya berkata; Katakanlah (hai Muhammad): \"Aku tidak meminta upah sedikitpun padamu atas da'wahku dan bukanlah aku termasuk orang-orang yang mengada-adakan. (Shaad: 86). Dan Rasulullah shallallahu 'alaihi wasallam tatkala melihat kaum Quraisy berbuat durhaka kepada beliau, beliau shallallahu 'alaihi wasallam berdo'a: \"Ya Allah timpakan kepada mereka kelaparan seperti kaum Yusuf. Maka mereka tertimpa tahun kelaparan hingga mereka memakan tulang dan kulit. Yang lainnya mengatakan; hingga memakan kulit dan bangkai. Salah seorang dari mereka berdiri melihat ke langit, ia melihat seperti wujud kabut antara dirinya dan langit. Kemudian Abu Sufyan menemui Nabi shallallahu 'alaihi wasallam seraya berkata; Wahai Muhammad, sesungguhnya kaummu telah binasa, maka do'akanlah kepada Allah agar Dia melenyapkan adzab dari mereka. Lalu beliau mendoakannya. Kemudian beliau bersabda: 'Apakah kalian akan kembali durhaka setelah ini? Sedangkan di dalam Hadits Manshur disebutkan; Kemudian beliau membaca: \"Maka tunggulah hari ketika langit membawa kabut yang nyata, yang meliputi manusia. inilah azab yang pedih.\" Hingga ayat: Sesungguhnya (kalau) Kami akan melenyapkan siksaan itu agak sedikit sesungguhnya kamu akan kembali (ingkar). Abdullah berkata; Maka bagaimana siksa itu akan dilenyapkan dari mereka pada hari kiamat? Padahal telah berlalu kabut, hantaman keras dan kematian. Yang lainnya menambahkan; dan terbelahnya bulan. Dan satu lagi menambahkan; dan kekalahan Ramawi.'"},"4146":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَخَمْسٌ قَدْ مَضَيْنَ اللِّزَامُ وَالرُّومُ وَالْبَطْشَةُ وَالْقَمَرُ وَالدُّخَانُ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Muslim] dari [Masruq] dari [Abdullah] dia berkata; lima hal telah berlalu; \"Kematian, kekalahan Ramawi, hantaman keras, terbelahnya bulan, dan kabut.\""},"4147":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ عَزَّ وَجَلَّ يُؤْذِينِي ابْنُ آدَمَ يَسُبُّ الدَّهْرَ وَأَنَا الدَّهْرُ بِيَدِي الْأَمْرُ أُقَلِّبُ اللَّيْلَ وَالنَّهَارَ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza wa Jalla berfirman: Anak Adam telah menyakiti-Ku dia suka mencela masa. Padahal Aku pencipta masa. Akulah yang menggilir siang dan malam.\""},"4148":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ قَالَكَانَ مَرْوَانُ عَلَى الْحِجَازِ اسْتَعْمَلَهُ مُعَاوِيَةُ فَخَطَبَ فَجَعَلَ يَذْكُرُ يَزِيدَ بْنَ مُعَاوِيَةَ لِكَيْ يُبَايَعَ لَهُ بَعْدَ أَبِيهِ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍ شَيْئًا فَقَالَ خُذُوهُ فَدَخَلَ بَيْتَ عَائِشَةَ فَلَمْ يَقْدِرُوا فَقَالَ مَرْوَانُ إِنَّ هَذَا الَّذِي أَنْزَلَ اللَّهُ فِيهِ{ وَالَّذِي قَالَ لِوَالِدَيْهِ أُفٍّ لَكُمَا أَتَعِدَانِنِي }فَقَالَتْ عَائِشَةُ مِنْ وَرَاءِ الْحِجَابِ مَا أَنْزَلَ اللَّهُ فِينَا شَيْئًا مِنْ الْقُرْآنِ إِلَّا أَنَّ اللَّهَ أَنْزَلَ عُذْرِي","id":"Telah menceritakan kepada kami [Musa bin Ismail] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Yusuf bin Mahik] dia berkata; Mu'awiyah mengangkat Marwan untuk pemimpin di Hijaz. Lalu Marwan menyebut-nyebut kebaikan Yazid bin Mu'wiyah agar ia dibai'at setelah bapaknya. Kemudian Abdurrahman bin Abu Bakr berkata sesuatu kepadanya yang membuat ia marah. Maka Marwan berkata; Tangkaplah ia. Abdurrahman pun masuk ke rumah Aisyah hingga mereka tidak mampu menangkapnya. Marwan berkata; Rumah ini adalah rumah yang di dalamnya Allah menurunkan ayat: Dan orang yang berkata kepada dua orang ibu bapaknya: \"Cis bagi kamu keduanya, apakah kamu keduanya memperingatkan kepadaku bahwa aku akan dibangkitkan, padahal sungguh telah berlalu beberapa umat sebelumku?, (Al Ahqaf: 17). Maka [Aisyah] pun berkata dibalik tabir; Allah tidak menurunkan sesuatu pun dari Al Qur'an kepada kami, kecuali Dia hanya menurunkan tentang udzurku (pembebasanku) mengenai berita bohong."},"4149":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو أَنَّ أَبَا النَّضْرِ حَدَّثَهُ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا حَتَّى أَرَى مِنْهُ لَهَوَاتِهِ إِنَّمَا كَانَ يَتَبَسَّمُ قَالَتْ وَكَانَ إِذَا رَأَى غَيْمًا أَوْ رِيحًا عُرِفَ فِي وَجْهِهِ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ إِذَا رَأَوْا الْغَيْمَ فَرِحُوا رَجَاءَ أَنْ يَكُونَ فِيهِ الْمَطَرُ وَأَرَاكَ إِذَا رَأَيْتَهُ عُرِفَ فِي وَجْهِكَ الْكَرَاهِيَةُ فَقَالَ يَا عَائِشَةُ مَا يُؤْمِنِّي أَنْ يَكُونَ فِيهِ عَذَابٌ عُذِّبَ قَوْمٌ بِالرِّيحِ وَقَدْ رَأَى قَوْمٌ الْعَذَابَ فَقَالُوا{ هَذَا عَارِضٌ مُمْطِرُنَا }","id":"Telah menceritakan kepada kami [Ahmad bin 'Isa] Telah menceritakan kepada kami [Ibnu Wahab] Telah mengabarkan kepada kami [Amru] bahwa [Abu An Nadrl] menceritakan kepadanya, dari [Sulaiman bin Yasar] dari [Aisyah radliallahu 'anha] -istri Rasulullah shallallahu 'alaihi wasallam- ia berkata; \"Saya tidak pernah melihat Rasulullah shalallahu'alaihi wa sallam tertawa terbahak-bahak hingga terlihat anak lidahnya, beliau hanya tersenyum.\" Aisyah berkata; \"Apabila beliau melihat awan atau angin maka hal itu dapat diketahui pada wajahnya.\" Dia berkata; \"Wahai Rasulullah! Apabila orang-orang melihat awan, mereka sangat bahagia berharap supaya turun hujan. Sedangkan saya melihat engkau setiap kali melihatnya tampak kekhawatiran di wajahmu.\" Beliau bersabda: \"Wahai Aisyah! Saya tidak merasa aman, jangan-jangan isinya mendatangkan siksaan. Telah diadzab suatu kaum dengan angin dan suatu kaum lagi melihat adzab, namun dia malah mengatakan; 'Ini adalah awan yang mengandung hujan, yang akan menghujani kami (padahal justru awan itu akan mendatangkan siksa) '. (QS. Al Ahqaf 24).\""},"4150":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ قَالَ حَدَّثَنِي مُعَاوِيَةُ بْنُ أَبِي مُزَرِّدٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَلَقَ اللَّهُ الْخَلْقَ فَلَمَّا فَرَغَ مِنْهُ قَامَتْ الرَّحِمُ فَأَخَذَتْ بِحَقْوِ الرَّحْمَنِ فَقَالَ لَهُ مَهْ قَالَتْ هَذَا مَقَامُ الْعَائِذِ بِكَ مِنْ الْقَطِيعَةِ قَالَ أَلَا تَرْضَيْنَ أَنْ أَصِلَ مَنْ وَصَلَكِ وَأَقْطَعَ مَنْ قَطَعَكِ قَالَتْ بَلَى يَا رَبِّ قَالَ فَذَاكِ قَالَ أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ{ فَهَلْ عَسَيْتُمْ إِنْ تَوَلَّيْتُمْ أَنْ تُفْسِدُوا فِي الْأَرْضِ وَتُقَطِّعُوا أَرْحَامَكُمْ }حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا حَاتِمٌ عَنْ مُعَاوِيَةَ قَالَ حَدَّثَنِي عَمِّي أَبُو الْحُبَابِ سَعِيدُ بْنُ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ بِهَذَا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا إِنْ شِئْتُمْ{ فَهَلْ عَسَيْتُمْ }حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مُعَاوِيَةُ بْنُ أَبِي الْمُزَرَّدِ بِهَذَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقْرَءُوا إِنْ شِئْتُمْ{ فَهَلْ عَسَيْتُمْ }","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] Telah menceritakan kepada kami [Sulaiman] dia berkata; Telah menceritakan kepadaku [Mu'awiyah bin Abu Muzarrad] dari [Sa'id bin Yasar] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: 'Setelah Allah Azza wa Jalla menciptakan semua makhluk, maka rahim pun berdiri bangkit dan memegang pinggang Ar Rohman, lalu ia berkata; 'Inikah tempat bagi yang berlindung dari terputusnya silaturahim (Menyambung silaturahim).' Allah Subhanahu wa Ta'ala menjawab: Tidakkah kamu rela bahwasanya Aku akan menyambung orang yang menyambungmu dan memutuskan yang memutuskanmu? ' Rahim menjawab; 'Tentu wahai Rabbku.' Allah berfirman: 'ltulah yang kamu miliki.' Abu Hurairah: 'Jika kamu mau, maka bacalah ayat berikut ini: Maka apakah kiranya jika kamu berkuasa kamu akan berbuat kerusakan di muka bumi dan memutuskan hubungan kekeluargaan? (QS. Muhammad 22). Telah menceritakan kepada kami [Ibrahim bin Hamzah] Telah menceritakan kepada kami [Hatim] dari [Mu'awiyah] dia berkata; Telah menceritakan kepadaku pamanku, [Abu Al Khabab Said bin Yasar] dari [Abu Hurairah] mengenai Hadits ini. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: Jika kalian mau, bacalah oleh kalian: Maka apakah kiranya jika kamu berkuasa kamu akan berbuat kerusakan di muka bumi dan memutuskan hubungan kekeluargaan? (Muhammad: 22). Telah menceritakan kepada kami [Bisyr bin Muhammad] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Mu'awiyah bin Abu Al Muzarrad] mengenai Hadits ini. Rasulullah shallallahu 'alaihi wasallam bersabda: jika kalian mau, bacalah ayat: Maka apakah kiranya jika kamu berkuasa kamu akan berbuat kerusakan di muka bumi dan memutuskan hubungan kekeluargaan? (Muhammad: 22)."},"4151":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسِيرُ فِي بَعْضِ أَسْفَارِهِ وَعُمَرُ بْنُ الْخَطَّابِ يَسِيرُ مَعَهُ لَيْلًا فَسَأَلَهُ عُمَرُ بْنُ الْخَطَّابِ عَنْ شَيْءٍ فَلَمْ يُجِبْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ ثَكِلَتْ أُمُّ عُمَرَ نَزَرْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ كُلَّ ذَلِكَ لَا يُجِيبُكَ قَالَ عُمَرُ فَحَرَّكْتُ بَعِيرِي ثُمَّ تَقَدَّمْتُ أَمَامَ النَّاسِ وَخَشِيتُ أَنْ يُنْزَلَ فِيَّ قُرْآنٌ فَمَا نَشِبْتُ أَنْ سَمِعْتُ صَارِخًا يَصْرُخُ بِي فَقُلْتُ لَقَدْ خَشِيتُ أَنْ يَكُونَ نَزَلَ فِيَّ قُرْآنٌ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ اللَّيْلَةَ سُورَةٌ لَهِيَ أَحَبُّ إِلَيَّ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ ثُمَّ قَرَأَ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا }","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Zaid bin Aslam] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam pergi dalam salah satu perjalanannya. Dan Umar bin Khattab bersama beliau pada malam hari itu. Umar bertanya kepada beliau tentang suatu hal, namun beliau tidak menjawabnya. Dia bertanya lagi, namun beliau tetap tidak menjawab. Dia bertanya lagi, namun beliau tetap tidak menjawab. ' [Umar] berkata; \"Huss kamu, 'Umar. Kamu telah memaksa Rasulullah shallallahu 'alaihi wasallam tiga kali namun semuanya itu tidak ada yang dijawabnya.' 'Umar berkata; \"Saya gerakkan untaku, dan aku maju ke hadapan orang-orang, saya khawatir jika turun padaku Al qur'an. tidak berapa lama, saya mendengar orang yang berteriak ke arahku.\" ('Umar radliallahu 'anhu) berkata; \"Saya berkata; \"Saya khawatir jika ada ayat yang turun kepadaku, \" 'Umar radliallahu 'anhu berkata; \"Maka saya mendatangi Rasulullah shallallahu 'alaihi wasallam. Saya mengucapkan salam kepada beliau. Beliau bersabda: 'Telah turun padaku tadi malam satu surat, yang lebih saya cintai daripada matahari terbit'. Beliau membaca: 'INNAA FATAHNA LAKA FATHAN MUBINAA'.\" (QS. Alfath)."},"4152":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ سَمِعْتُ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ{ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا }قَالَ الْحُدَيْبِيَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] Aku mendengar [Qatadah] dari [Anas radliallahu 'anhu] mengenai firman Allah: 'INNAA FATAHNA LAKA FATHAN MUBINAA'.\" Ia berkata; yaitu Al Hudaibiyah."},"4153":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ سُورَةَ الْفَتْحِ فَرَجَّعَ فِيهَا قَالَ مُعَاوِيَةُ لَوْ شِئْتُ أَنْ أَحْكِيَ لَكُمْ قِرَاءَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَفَعَلْتُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Mu'awiyah bin Qurrah] dari [Abdullah bin Mughaffal] dia berkata; pada waktu fathu Makkah, Nabi shallallahu 'alaihi wasallam membaca surat Al Fath, dan beliau mengulang-ngulangnya. Mu'awiyah berkata; Jika aku ingin menceritakan kepada kalian bacaan Nabi shallallahu 'alaihi wasallam, tentu akan aku ceritakan.'"},"4154":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ حَدَّثَنَا زِيَادٌ هُوَ ابْنُ عِلَاقَةَ أَنَّهُ سَمِعَ الْمُغِيرَةَ يَقُولُقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَوَرَّمَتْ قَدَمَاهُ فَقِيلَ لَهُ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ قَالَ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadl] Telah mengabarkan kepada kami [Ibnu Uyainah] Telah menceritakan kepada kami [Ziyad] yaitu Ibnu 'Ilaaqah bahwa dia mendengar [Al Mughirah] berkata; Nabi shallallahu 'alaihi wasallam berdiri shalat hingga kedua telapak kakinya bengkak-bengkak. Maka dikatakan kepada beliau; 'Bukankah Allah telah mengampuni anda terhadap dosa-dosa anda yang lalu maupun yang akan datang? Beliau menjawab: \"Tidak bolehkah saya menjadi hamba yang bersyukur.\""},"4155":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَبْدِ الْعَزِيزِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَحْيَى أَخْبَرَنَا حَيْوَةُ عَنْ أَبِي الْأَسْوَدِ سَمِعَ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُومُ مِنْ اللَّيْلِ حَتَّى تَتَفَطَّرَ قَدَمَاهُ فَقَالَتْ عَائِشَةُ لِمَ تَصْنَعُ هَذَا يَا رَسُولَ اللَّهِ وَقَدْ غَفَرَ اللَّهُ لَكَ مَا تَقَدَّمَ مِنْ ذَنْبِكَ وَمَا تَأَخَّرَ قَالَ أَفَلَا أُحِبُّ أَنْ أَكُونَ عَبْدًا شَكُورًا فَلَمَّا كَثُرَ لَحْمُهُ صَلَّى جَالِسًا فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ فَقَرَأَ ثُمَّ رَكَعَ","id":"Telah menceritakan kepada kami [Al Hasan bin Abdul Aziz] Telah menceritakan kepada kami [Abdullah bin Yahya] Telah mengabarkan kepada kami [Haiwah] dari [Abu Al Aswad] dia mendengar [Urwah] dari [Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat malam hingga kaki beliau bengkak-bengkak. Aisyah berkata: Wahai Rasulullah, kenapa Anda melakukan ini padahal Allah telah mengampuni dosa anda yang telah berlalu dan yang akan datang? Beliau bersabda: \"Apakah aku tidak suka jika menjadi hamba yang bersyukur?\" Dan tatkala beliau gemuk, beliau shalat sambil duduk, apabila beliau hendak ruku' maka beliau berdiri kemudian membaca beberapa ayat lalu ruku.'"},"4156":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ هِلَالِ بْنِ أَبِي هِلَالٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ هَذِهِ الْآيَةَ الَّتِي فِي الْقُرْآنِ يَا أَيُّهَا النَّبِيُّ{ إِنَّا أَرْسَلْنَاكَ شَاهِدًا وَمُبَشِّرًا وَنَذِيرًا }قَالَ فِي التَّوْرَاةِ يَا أَيُّهَا النَّبِيُّ إِنَّا أَرْسَلْنَاكَ شَاهِدًا وَمُبَشِّرًا وَحِرْزًا لِلْأُمِّيِّينَ أَنْتَ عَبْدِي وَرَسُولِي سَمَّيْتُكَ الْمُتَوَكِّلَ لَيْسَ بِفَظٍّ وَلَا غَلِيظٍ وَلَا سَخَّابٍ بِالْأَسْوَاقِ وَلَا يَدْفَعُ السَّيِّئَةَ بِالسَّيِّئَةِ وَلَكِنْ يَعْفُو وَيَصْفَحُ وَلَنْ يَقْبِضَهُ اللَّهُ حَتَّى يُقِيمَ بِهِ الْمِلَّةَ الْعَوْجَاءَ بِأَنْ يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَيَفْتَحَ بِهَا أَعْيُنًا عُمْيًا وَآذَانًا صُمًّا وَقُلُوبًا غُلْفًا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] Telah menceritakan kepada kami [Abdul 'Aziz bin Abu Salamah] dari [Hilal bin Abu Hilal] dari ['Atha bin Yasar] dari [Abdullah bin Amru bin Al 'Ash radliallahu 'anhuma] bahwa ayat yang di dalam Al Qur'an ini: \"Hai Nabi, sesungguhnya Kami mengutusmu untuk jadi saksi, dan pembawa kabar gembira dan pemberi peringatan.., \" (Al Fathu: 8). Sama dengan ayat yang ada di dalam Taurat berbunyi: \"Hai Nabi, sesungguhnya Kami mengutusmu untuk jadi saksi, dan pembawa kabar gembira dan pemberi peringatan dan pelindung bagi orang-orang `Arab, kamu adalah hamba-Ku dan Rasul-Ku, dan Aku menamaimu Al Mutawakkil (orang yang bertawakkal tinggi). Engkau bukan orang yang berperangai buruk, juga bukan berwatak keras dan bukan sakhkhob (orang yang cerewet, berteriak keras-keras) di pasar.\" Dan beliau tidak membalas kejahatan dengan kejahatan serupa akan tetapi beliau mema'afkan dan mengampuninya, dan Allah tidak akan mewafatkan beliau sampai beliau meluruskan Millah (dien) Nya yang bengkok, hingga manusia mengucapkan Laa Ilaaha IllAllah, sehingga dengannya beliau dapat membukakan mata yang buta, telinga yang tuli dan hati yang lalai.\""},"4157":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ وَفَرَسٌ لَهُ مَرْبُوطٌ فِي الدَّارِ فَجَعَلَ يَنْفِرُ فَخَرَجَ الرَّجُلُ فَنَظَرَ فَلَمْ يَرَ شَيْئًا وَجَعَلَ يَنْفِرُ فَلَمَّا أَصْبَحَ ذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ السَّكِينَةُ تَنَزَّلَتْ بِالْقُرْآنِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Baraa radliallahu 'anhu] dia berkata; Ketika seorang laki-laki dari sahabat Rasulullah shallallahu 'alaihi wasallam membaca, kuda miliknya sudah dalam keadaan terikat dirumahnya. Namun ia selalu merasa tidak tenang, ia lari keluar, tapi ia tidak melihat sesuatu, dan hal itu selalu membuat ia tidak tenang. Di pagi harinya ia mengabarkan hal itu kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ketenangan itu akan turun bersama Al Qur'an.\""},"4158":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرٍ قَالَكُنَّا يَوْمَ الْحُدَيْبِيَةِ أَلْفًا وَأَرْبَعَ مِائَةٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Sufyan] dari [Amru] dari [Jabir] dia berkata; \"Pada hari Hudaibiyah kami berjumlah seribu empat ratus.\""},"4159":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ عُقْبَةَ بْنَ صُهْبَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّإِنِّي مِمَّنْ شَهِدَ الشَّجَرَةَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَذْفِوَعَنْ عُقْبَةَ بْنِ صُهْبَانَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ الْمُزَنِيَّفِي الْبَوْلِ فِي الْمُغْتَسَلِ يَأْخُذُ مِنْهُ الْوَسْوَاسُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Syababah] Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; Aku mendengar ['Uqbah bin Shahban] dari [Abdullah bin Mughaffal Al Muzani], Sesungguhnya aku termasuk orang yang menghadiri peristiwa bai'atur Ridwan. Rasulullah shallallahu 'alaihi wasallam melarang melempar buruan dengan batu. Dan dari Uqbah bin Shahban dia berkata; Aku mendengar Abdullah bin Mughaffal Al Muzani berkata mengenai kencing ditempat pemandian menyebabkan rasa was-was."},"4160":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ رَضِيَ اللَّهُ عَنْهُوَكَانَ مِنْ أَصْحَابِ الشَّجَرَةِ","id":"Telah menceritakan kepadaku [Muhammad bin Al Walid] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Tsabit bin Dlahak radliallahu 'anhu], dan dia termasuk peserta bai'atur Ridwan."},"4161":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَاقَ السُّلَمِيُّ حَدَّثَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ سِيَاهٍ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَ أَتَيْتُ أَبَا وَائِلٍأَسْأَلُهُ فَقَالَ كُنَّا بِصِفِّينَ فَقَالَ رَجُلٌ أَلَمْ تَرَ إِلَى الَّذِينَ يُدْعَوْنَ إِلَى كِتَابِ اللَّهِ فَقَالَ عَلِيٌّ نَعَمْ فَقَالَ سَهْلُ بْنُ حُنَيْفٍ اتَّهِمُوا أَنْفُسَكُمْ فَلَقَدْ رَأَيْتُنَا يَوْمَ الْحُدَيْبِيَةِ يَعْنِي الصُّلْحَ الَّذِي كَانَ بَيْنَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُشْرِكِينَ وَلَوْ نَرَى قِتَالًا لَقَاتَلْنَا فَجَاءَ عُمَرُ فَقَالَ أَلَسْنَا عَلَى الْحَقِّ وَهُمْ عَلَى الْبَاطِلِ أَلَيْسَ قَتْلَانَا فِي الْجَنَّةِ وَقَتْلَاهُمْ فِي النَّارِ قَالَ بَلَى قَالَ فَفِيمَ نُعْطِي الدَّنِيَّةَ فِي دِينِنَا وَنَرْجِعُ وَلَمَّا يَحْكُمِ اللَّهُ بَيْنَنَا فَقَالَ يَا ابْنَ الْخَطَّابِ إِنِّي رَسُولُ اللَّهِ وَلَنْ يُضَيِّعَنِي اللَّهُ أَبَدًا فَرَجَعَ مُتَغَيِّظًا فَلَمْ يَصْبِرْ حَتَّى جَاءَ أَبَا بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ أَلَسْنَا عَلَى الْحَقِّ وَهُمْ عَلَى الْبَاطِلِ قَالَ يَا ابْنَ الْخَطَّابِ إِنَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَنْ يُضَيِّعَهُ اللَّهُ أَبَدًا فَنَزَلَتْ سُورَةُ الْفَتْحِ","id":"Telah menceritakan kepada kami [Ahmad bin Ishaq As Sulami] Telah menceritakan kepada kami [Ya'la] Telah menceritakan kepada kami [Abdul Aziz bin Siyah] dari [Habib bin Abu Tsabit] dia berkata; Aku menemui [Abu Wa'il] untuk menanyakan sesuatu. Katanya; ketika itu kami di Shiffin, lantas seseorang berkata; Tidakkah kamu telah melihat orang-orang yang menyeru kepada kitabullah?. Maka Ali menjawab; 'Ya.' [Sahal bin Hunaif] berkata; Tolong koreksilah diri kalian, sungguh aku pernah melihat kami pada hari perjanjian Hudaibiyah, yang terjadi antara Nabi shallallahu 'alaihi wasallam dan kaum Musyrikin, kalaulah kita berpendapat untuk berperang maka tentu kita akan berperang, hingga Umar datang dan berkata; 'Bukankah kita berada dalam kebenaran sedangkan mereka dalam kebatilan, bukankah orang-orang yang terbunuh dari kami berada di Surga, sedangkan orang-orang yang terbunuh dari mereka berada di Neraka? Nabi shallallahu 'alaihi wasallam menjawab; 'Ya.' Umar berkata; kalau begitu kenapa kita merendahkan agama kita dan kembali, padahal Allah belum memutuskan untuk kita. Maka Nabi shallallahu 'alaihi wasallam bersabda: Wahai Ibnu Khaththab; Sesungguhnya aku Rasulullah shallallahu 'alaihi wasallam, sekali-kali Allah tidak akan menyia-nyiakanku. Maka Umar pun kembali dalam keadaan tidak puas dan tidak sabar, lalu ia menemui Abu Bakr seraya berkata; Wahai Abu Bakr, bukankah kita berada dalam kebenaran dan mereka dalam kebatilan, Abu Bakr menjawab; Wahai Ibnu Khatthab, sesunggunya ia adalah Rasulullah shallallahu 'alaihi wasallam, Allah pasti tidak akan menyia-nyiakannya untuk selama-lamanya, maka turunlah surat Al Fath."},"4162":{"ar":"حَدَّثَنَا يَسَرَةُ بْنُ صَفْوَانَ بْنِ جَمِيلٍ اللَّخْمِيُّ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَكَادَ الْخَيِّرَانِ أَنْ يَهْلِكَا أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا رَفَعَا أَصْوَاتَهُمَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَدِمَ عَلَيْهِ رَكْبُ بَنِي تَمِيمٍ فَأَشَارَ أَحَدُهُمَا بِالْأَقْرَعِ بْنِ حَابِسٍ أَخِي بَنِي مُجَاشِعٍ وَأَشَارَ الْآخَرُ بِرَجُلٍ آخَرَ قَالَ نَافِعٌ لَا أَحْفَظُ اسْمَهُ فَقَالَ أَبُو بَكْرٍ لِعُمَرَ مَا أَرَدْتَ إِلَّا خِلَافِي قَالَ مَا أَرَدْتُ خِلَافَكَ فَارْتَفَعَتْ أَصْوَاتُهُمَا فِي ذَلِكَ فَأَنْزَلَ اللَّهُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَرْفَعُوا أَصْوَاتَكُمْ }الْآيَةَقَالَ ابْنُ الزُّبَيْرِ فَمَا كَانَ عُمَرُ يُسْمِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذِهِ الْآيَةِ حَتَّى يَسْتَفْهِمَهُ وَلَمْ يَذْكُرْ ذَلِكَ عَنْ أَبِيهِ يَعْنِي أَبَا بَكْرٍ","id":"Telah menceritakan kepada kami [Yasarah bin Shafwan bin Jamil Al Lakhmi] Telah menceritakan kepada kami [Nafi' bin Umar] dari [Ibnu Abu Mulaikah] dia berkata; hampir saja dua orang terbaik binasa, yaitu Abu Bakar dan 'Umar radliallahu 'anhuma, keduanya mengangkat suara mereka di hadapan Nabi shallallahu 'alaihi wasallam. Yaitu tatkala datang kepada Nabi shallallahu 'alaihi wasallam utusan Bani Tamim. salah satu dari keduanya menunjuk Al Aqra' bin Habis Al Hanzhali, saudara Bani Mujasyi', dan yang lain menunjuk pada yang lainnya. Abu Bakar berkata kepada 'Umar, sesungguhnya kamu hanya ingin menyelisihiku. 'Umar berkata, saya tidak menginginkannya, lalu kedua suaranya meninggi di sisi Nabi shallallahu 'alaihi wasallam maka turunlah ayat; Hai orang-orang yang beriman, janganlah kamu meninggikan suaramu melebihi suara nabi, [Ibnu Az Zubair] berkata, 'Maka Umar setelah turun ayat itu tidaklah mendengar perkataan Rasulullah shallallahu 'alaihi wasallam hingga ia betul-betul memahaminnya. Dan Ibnu Az Zubair tidak menyebutkan hal itu dari Bapaknya (kakeknya) yaitu Abu Bakr."},"4163":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَزْهَرُ بْنُ سَعْدٍ أَخْبَرَنَا ابْنُ عَوْنٍ قَالَ أَنْبَأَنِي مُوسَى بْنُ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَقَدَ ثَابِتَ بْنَ قَيْسٍ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَنَا أَعْلَمُ لَكَ عِلْمَهُ فَأَتَاهُ فَوَجَدَهُ جَالِسًا فِي بَيْتِهِ مُنَكِّسًا رَأْسَهُ فَقَالَ لَهُ مَا شَأْنُكَ فَقَالَ شَرٌّ كَانَ يَرْفَعُ صَوْتَهُ فَوْقَ صَوْتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدْ حَبِطَ عَمَلُهُ وَهُوَ مِنْ أَهْلِ النَّارِ فَأَتَى الرَّجُلُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ أَنَّهُ قَالَ كَذَا وَكَذَا فَقَالَ مُوسَى فَرَجَعَ إِلَيْهِ الْمَرَّةَ الْآخِرَةَ بِبِشَارَةٍ عَظِيمَةٍ فَقَالَ اذْهَبْ إِلَيْهِ فَقُلْ لَهُ إِنَّكَ لَسْتَ مِنْ أَهْلِ النَّارِ وَلَكِنَّكَ مِنْ أَهْلِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Azhar bin Sa'ad] Telah mengabarkan kepada kami [Ibnu 'Aun] dia berkata; Telah memberitakan kepadaku [Musa bin Anas] dari [Anas bin Malik radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam mencari Tsabit bin Qais, lalu seeorang berkata; Ya Rasulullah, Aku tahu keberadaan dia, lalu dia mendatanginya dan ditemuinya sedang duduk di rumahnya dalam keadaan menundukan kepalanya. Orang itu berkata kepadanya; Ada apa denganmu? Tsabit menjawab; sungguh jelek ia (Tsabit), ia telah mengangkat suaranya melebihi suara Nabi shallallahu 'alaihi wasallam, sungguh telah hancur amal perbuatannya dan dia termasuk penghuni neraka. Maka orang itu menemui Nabi shallallahu 'alaihi wasallam dan mengabarkan berita keadaannya bahwa ia berkata begini dan begitu. Musa berkata; -kemudian orang itu kembali kepadanya dengan membawa kabar gembira yang besar.- Nabi shallallahu 'alaihi wasallam berkata kepadanya; pergilah kepada Tsabit dan katakan kepadanya bahwa ia bukan penghuni neraka, tapi ia penghuni surga."},"4164":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ أَخْبَرَهُمْأَنَّهُ قَدِمَ رَكْبٌ مِنْ بَنِي تَمِيمٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَمِّرْ الْقَعْقَاعَ بْنَ مَعْبَدٍ وَقَالَ عُمَرُ بَلْ أَمِّرْ الْأَقْرَعَ بْنَ حَابِسٍ فَقَالَ أَبُو بَكْرٍ مَا أَرَدْتَ إِلَى أَوْ إِلَّا خِلَافِي فَقَالَ عُمَرُ مَا أَرَدْتُ خِلَافَكَ فَتَمَارَيَا حَتَّى ارْتَفَعَتْ أَصْوَاتُهُمَا فَنَزَلَ فِي ذَلِكَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُقَدِّمُوا بَيْنَ يَدَيْ اللَّهِ وَرَسُولِهِ }حَتَّى انْقَضَتْ الْآيَةُ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad] Telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; Telah mengabarkan kepadaku [Ibnu Abu Mulaikah] bahwa [Abdullah bin Zubair] mengabarkan kepadanya, ketika datang kepada Nabi shallallahu 'alaihi wasallam utusan Bani Tamim. Abu Bakr berkata; angkatlah Al Qa'qaa' bin Ma'bad. Sedangkan Umar berkata; Angkatlah Al Aqra' bin Habis. Maka Abu Bakar berkata kepada 'Umar, Apakah kamu ingin menyelisihiku? 'Umar berkata, saya tidak menginginkannya, lalu kedua berdebat hingga suaranya meninggi. maka turunlah ayat; Hai orang-orang yang beriman, janganlah kamu meninggikan suaramu melebihi suara nabi.., hingga akhir ayat."},"4165":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُلْقَى فِي النَّارِ{ وَتَقُولُ هَلْ مِنْ مَزِيدٍ }حَتَّى يَضَعَ قَدَمَهُ فَتَقُولُ قَطْ قَطْ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Al Aswad] Telah menceritakan kepada kami [Harami bin 'Umarah] Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: orang-orang dilemparkan ke neraka hingga neraka itu berkata; 'Apakah ada tambahan lagi? Maka Allah meletakan kaki-Nya, dan neraka itu berkata; 'Cukup, cukup.'"},"4166":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْقَطَّانُ حَدَّثَنَا أَبُو سُفْيَانَ الْحِمْيَرِيُّ سَعِيدُ بْنُ يَحْيَى بْنِ مَهْدِيٍّ حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ رَفَعَهُ وَأَكْثَرُ مَا كَانَ يُوقِفُهُ أَبُو سُفْيَانَيُقَالُ{ لِجَهَنَّمَ هَلْ امْتَلَأْتِ وَتَقُولُ هَلْ مِنْ مَزِيدٍ }فَيَضَعُ الرَّبُّ تَبَارَكَ وَتَعَالَى قَدَمَهُ عَلَيْهَا فَتَقُولُ قَطْ قَطْ","id":"Telah menceritakan kepada kami [Muhammad bin Musa Al Qaththan] Telah menceritakan kepada kami [Abu Sufyan Al Himyari Sa'id bin Yahya bin Mahdi] Telah menceritakan kepada kami ['Auf] dari [Muhammad] dari [Abu Hurairah] secara marfu, namun Abu Sufyan mendapatkan Hadits ini kebanyakan bersifat mauquf. dikatakan kepada neraka Jahannam; Apakah sudah penuh? Neraka Jahannam bertanya; Apakah ada tambahan lagi? Maka Allah Tabaraka wa Ta'ala meletakan kakinya di atasnya, kemudian neraka itu berkata; 'Cukup, cukup.'"},"4167":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحَاجَّتْ الْجَنَّةُ وَالنَّارُ فَقَالَتْ النَّارُ أُوثِرْتُ بِالْمُتَكَبِّرِينَ وَالْمُتَجَبِّرِينَ وَقَالَتْ الْجَنَّةُ مَا لِي لَا يَدْخُلُنِي إِلَّا ضُعَفَاءُ النَّاسِ وَسَقَطُهُمْ قَالَ اللَّهُ تَبَارَكَ وَتَعَالَى لِلْجَنَّةِ أَنْتِ رَحْمَتِي أَرْحَمُ بِكِ مَنْ أَشَاءُ مِنْ عِبَادِي وَقَالَ لِلنَّارِ إِنَّمَا أَنْتِ عَذَابِي أُعَذِّبُ بِكِ مَنْ أَشَاءُ مِنْ عِبَادِي وَلِكُلِّ وَاحِدَةٍ مِنْهُمَا مِلْؤُهَا فَأَمَّا النَّارُ فَلَا تَمْتَلِئُ حَتَّى يَضَعَ رِجْلَهُ فَتَقُولُ قَطْ قَطْ فَهُنَالِكَ تَمْتَلِئُ وَيُزْوَى بَعْضُهَا إِلَى بَعْضٍ وَلَا يَظْلِمُ اللَّهُ عَزَّ وَجَلَّ مِنْ خَلْقِهِ أَحَدًا وَأَمَّا الْجَنَّةُ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ يُنْشِئُ لَهَا خَلْقًا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Surga dan neraka berbantah-bantahan. Neraka berkata: 'Orang-orang congkak dan sombong memasukiku. Surga berkata: Sedangkan aku, tidak ada yang memasukiku selain orang-orang lemah, yang hina dalam pandangan manusia. Lalu Allah berfirman kepada surga: 'Kau adalah rahmatKu, denganmu Aku merahmati siapa saja yang Aku kehendaki dari hamba-hambaKu.' Kemudian Allah berfirman kepada neraka: 'Kau adalah siksaKu, denganmu Aku menyiksa siapa pun yang Aku kehendaki. Dan masing-masing dari keduanya ada isinya.' Sedangkan neraka tidak terisi penuh hingga Allah meletakkan kakiNya kemudian neraka berkata: 'Cukup, cukup.' Saat itulah neraka penuh dan sebagiannya menindih sebagaian yang lain. Allah tidak menzhalimi seorang pun dari makhlukNya. Sedangkan surga, Allah menciptakan penghuninya.\""},"4168":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ عَنْ جَرِيرٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا جُلُوسًا لَيْلَةً مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةَ أَرْبَعَ عَشْرَةَ فَقَالَ إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا لَا تُضَامُونَ فِي رُؤْيَتِهِ فَإِنْ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا ثُمَّ قَرَأَ{ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ }","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dari [Jarir] dari [Ismail] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah] dia berkata; \"Ketika kami duduk-duduk di sisi Rasulullah shallallahu 'alaihi wasallam di malam hari ke empat belas, beliau melihat bulan, kemudian bersabda: \"Sesungguhnya kalian akan melihat Rabb kalian sebagaimana kalian melihat bulan ini. Kalian tidak akan kesulitan (ragu) ketika melihatnya. Jika kalian mampu untuk tidak ketinggalan shalat sebelum terbitnya fajar dan sebelum terbenamnya matahari maka lakukanlah.\" Kemudian beliau membaca: \"Dan bertasbihlah dengan memuji Rabbmu, sebelum terbit matahari dan terbenamnya.\" (Qaaf: 39)."},"4169":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ ابْنُ عَبَّاسٍأَمَرَهُ أَنْ يُسَبِّحَ فِي أَدْبَارِ الصَّلَوَاتِ كُلِّهَا يَعْنِي قَوْلَهُ{ وَإِدْبَارَ السُّجُودِ }","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Warqa] dari [Ibnu Abu Najih] dari [Mujahid] ia berkata; [Ibnu Abbas] menyuruhnya untuk bertashbih di akhir semua shalat sebagaimana maksud firman Allah: Dan bertasbihlah kamu kepada-Nya di malam hari dan setiap selesai sembahyang. (Qaaf: 40)."},"4170":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْشَكَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَشْتَكِي فَقَالَ طُوفِي مِنْ وَرَاءِ النَّاسِ وَأَنْتِ رَاكِبَةٌ فَطُفْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى جَنْبِ الْبَيْتِ يَقْرَأُ بِالطُّورِ وَكِتَابٍ مَسْطُورٍ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Muhammad bin Abdurrahman bin Naufal] dari [Urwah] dari [Zainab binti Abu Salamah] dari [Ummu Salamah] dia berkata; saya pernah mengadu kepada Rasulullah shallallahu 'alaihi wasallam bahwa saya sedang sakit. Kemudian beliau bersabda: \"Berthawaflah di belakang manusia dalam keadaan berkendaraan.\" Maka saya melakukan thawaf dan Rasulullah shallallahu 'alaihi wasallam sedang melakukan shalat di samping Ka'bah membaca; \"WATH THUUR WA KITAABIN MASTHUUR.\""},"4171":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثُونِي عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالطُّورِ فَلَمَّا بَلَغَ هَذِهِ الْآيَةَ{ أَمْ خُلِقُوا مِنْ غَيْرِ شَيْءٍ أَمْ هُمْ الْخَالِقُونَ أَمْ خَلَقُوا السَّمَوَاتِ وَالْأَرْضَ بَلْ لَا يُوقِنُونَ أَمْ عِنْدَهُمْ خَزَائِنُ رَبِّكَ أَمْ هُمْ الْمُسَيْطِرُونَ }قَالَ كَادَ قَلْبِي أَنْ يَطِيرَقَالَ سُفْيَانُ فَأَمَّا أَنَا فَإِنَّمَا سَمِعْتُ الزُّهْرِيَّ يُحَدِّثُ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالطُّورِ وَلَمْ أَسْمَعْهُ زَادَ الَّذِي قَالُوا لِي","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] dia berkata; mereka menceritakan kepadaku dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya radliallahu 'anhu] dia berkata; AKu mendengar Nabi shallallahu 'alaihi wasallam membaca surat At Thuur pada shalat Maghrib. Tatkala sampai ayat ini; Apakah mereka diciptakan tanpa sesuatupun ataukah mereka yang menciptakan (diri mereka sendiri)? Ataukah mereka telah menciptakan langit dan bumi itu?; sebenarnya mereka tidak meyakini (apa yang mereka katakan). Ataukah di sisi mereka ada perbendaharaan Tuhanmu atau merekakah yang berkuasa?. (At Thuur: 35-37). Beliau bersabda: 'Hatiku hampir saja akan terbang.' Sufyan berkata; Adapun aku mendengar hal itu dari Az Zuhri ia bercerita dari Muhammad bin Jubair bin Muth'im dari Bapaknya aku mendengar Nabi shallallahu 'alaihi wasallam membaca surat At Thuur pada shalat Maghrib, dan aku tidak mendengarnya ada tambahan lagi dari apa yang mereka katakan kepadaku."},"4172":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ قَالَ قُلْتُ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَايَا أُمَّتَاهْ هَلْ رَأَى مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبَّهُ فَقَالَتْ لَقَدْ قَفَّ شَعَرِي مِمَّا قُلْتَ أَيْنَ أَنْتَ مِنْ ثَلَاثٍ مَنْ حَدَّثَكَهُنَّ فَقَدْ كَذَبَ مَنْ حَدَّثَكَ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَبَّهُ فَقَدْ كَذَبَ ثُمَّ قَرَأَتْ{ لَا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ وَهُوَ اللَّطِيفُ الْخَبِيرُ }{ وَمَا كَانَ لِبَشَرٍ أَنْ يُكَلِّمَهُ اللَّهُ إِلَّا وَحْيًا أَوْ مِنْ وَرَاءِ حِجَابٍ }وَمَنْ حَدَّثَكَ أَنَّهُ يَعْلَمُ مَا فِي غَدٍ فَقَدْ كَذَبَ ثُمَّ قَرَأَتْ{ وَمَا تَدْرِي نَفْسٌ مَاذَا تَكْسِبُ غَدًا }وَمَنْ حَدَّثَكَ أَنَّهُ كَتَمَ فَقَدْ كَذَبَ ثُمَّ قَرَأَتْ{ يَا أَيُّهَا الرَّسُولُ بَلِّغْ مَا أُنْزِلَ إِلَيْكَ مِنْ رَبِّكَ }الْآيَةَ وَلَكِنَّهُ رَأَى جِبْرِيلَ عَلَيْهِ السَّلَام فِي صُورَتِهِ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Ismail bin Abu Khalid] dari ['Amir] dari [Masruq] dia berkata; Aku bertanya kepada ['Aisyah radliallahu 'anha] wahai Ibu, Apakah benar Nabi shallallahu 'alaihi wasallam pernah melihat Rabbnya? Aisyah menjawab; Sungguh rambutku berdiri (karena kaget) atas apa yang kamu katakan. Tiga perkara yang barang siapa mengatakannya kepadamu, maka sungguh ia telah berdusta. Barang siapa mengatakan kepadamu bahwa Muhammad shallallahu 'alaihi wasallam pernah melihat Rabbnya, maka ia telah berdusta. Lalu Aisyah membaca ayat; Dia tidak dapat dicapai oleh penglihatan mata, sedang Dia dapat melihat segala yang kelihatan; dan Dialah Yang Maha Halus lagi Maha Mengetahui. (Al An'am: 103). Dan tidak mungkin bagi seorang manusiapun bahwa Allah berkata-kata dengan dia kecuali dengan perantaraan wahyu atau dibelakang tabir. (As Syura: 51). Dan barang siapa yang mengatakan kepadamu bahwa beliau mengetahui apa yang akan terjadi pada hari esok maka ia telah berdusta. Lalu Aisyah membaca ayat; Dan tiada seorangpun yang dapat mengetahui (dengan pasti) apa yang akan diusahakannya besok. (Luqman: 34). Dan barang siapa yang mengatakan kepadamu bahwa beliau menyembunyikan sesuatu, maka ia telah berdusta. Lalu Aisyah membaca ayat; Hai Rasul, sampaikanlah apa yang diturunkan kepadamu dari Tuhanmu. (Al Maidah; 67). Hanya saja beliau pernah melihat bentuk Jibril dua kali."},"4173":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ قَالَ سَمِعْتُ زِرًّا عَنْ عَبْدِ اللَّهِ{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }قَالَ حَدَّثَنَا ابْنُ مَسْعُودٍ أَنَّهُ رَأَى جِبْرِيلَ لَهُ سِتُّ مِائَةِ جَنَاحٍ","id":"Telah menceritakan kepada kami [Abu An Nu'man] Telah menceritakan kepada kami [Abdul Wahid] Telah menceritakan kepada kami [As Syibani] dia berkata; Aku mendengar [Zirr] dari [Abdullah] mengenai firman Allah: maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi). Lalu dia menyampaikan kepada hamba-Nya (Muhammad) apa yang telah Allah wahyukan, (An Najm: 9-10). Zirr berkata; Telah menceritakan kepada kami Ibnu Mas'ud bahwa Nabi shallallahu 'alaihi wasallam melihat Jibril mempunyai enam ratus sayap.'"},"4174":{"ar":"حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا زَائِدَةُ عَنْ الشَّيْبَانِيِّ قَالَ سَأَلْتُ زِرًّاعَنْ قَوْلِهِ تَعَالَى{ فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَى فَأَوْحَى إِلَى عَبْدِهِ مَا أَوْحَى }قَالَ أَخْبَرَنَا عَبْدُ اللَّهِ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى جِبْرِيلَ لَهُ سِتُّ مِائَةِ جَنَاحٍ","id":"Telah menceritakan kepada kami [Thalq bin Ghannam] Telah menceritakan kepada kami [Zaidah] dari [As Syaibani] dia berkata; Aku bertanya kepada [Zirr] tentang firman Allah Ta'ala: maka jadilah dia dekat (pada Muhammad sejarak) dua ujung busur panah atau lebih dekat (lagi). Lalu dia menyampaikan kepada hamba-Nya (Muhammad) apa yang telah Allah wahyukan, (An Najm: 9-10). Zirr berkata; Telah mengabarkan kepada kami [Abdullah bin Mas'ud] bahwa Muhammad shallallahu 'alaihi wasallam melihat Jibril mempunyai enam ratus sayap.'"},"4175":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَ��َا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ{ لَقَدْ رَأَى مِنْ آيَاتِ رَبِّهِ الْكُبْرَى }قَالَ رَأَى رَفْرَفًا أَخْضَرَ قَدْ سَدَّ الْأُفُقَ","id":"Telah menceritakan kepada kami [Qabishah] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah radliallahu 'anhu] mengenai firman Allah: Sesungguhnya dia telah melihat sebahagian tanda-tanda (kekuasaan) Tuhannya yang paling besar, (An Najm: 18). Abdullah berkata; Rasulullah shallallahu 'alaihi wasallam melihat karpet berwarna hijau telah menutupi bagian ufuk."},"4176":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو الْأَشْهَبِ حَدَّثَنَا أَبُو الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ{ اللَّاتَ وَالْعُزَّى }كَانَ اللَّاتُ رَجُلًا يَلُتُّ سَوِيقَ الْحَاجِّ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] Telah menceritakan kepada kami [Abul Asyhab] Telah menceritakan kepada kami [Abu Al Jauza] dari [Ibnu Abbas radliallahu 'anhuma] mengenai firman Allah: al Laata dan al Uzza, (An Najm: 19). 'Al Laata adalah seorang laki-laki yang biasa mengaduk sawik untuk makanan orang-orang yang haji.'"},"4177":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ فَقَالَ فِي حَلِفِهِ وَاللَّاتِ وَالْعُزَّى فَلْيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ وَمَنْ قَالَ لِصَاحِبِهِ تَعَالَ أُقَامِرْكَ فَلْيَتَصَدَّقْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah mengabarkan kepada kami [Hisyam bin Yusuf] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Humaid bin Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang bersumpah dan berkata; \"Demi Laata dan Uzza maka hendaknya ia mengatakan; Laa Ilaaha Illallaah. Dan barang siapa yang berkata kepada sahabatnya kemarilah saya berjudi denganmu, maka hendaknya ia bersedekah.\""},"4178":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ سَمِعْتُ عُرْوَةَ قُلْتُ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْإِنَّمَا كَانَ مَنْ أَهَلَّ بِمَنَاةَ الطَّاغِيَةِ الَّتِي بِالْمُشَلَّلِ لَا يَطُوفُونَ بَيْنَ الصَّفَا وَالْمَرْوَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }فَطَافَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمُونَقَالَ سُفْيَانُ مَنَاةُ بِالْمُشَلَّلِ مِنْ قُدَيْدٍ وَقَالَ عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ نَزَلَتْ فِي الْأَنْصَارِ كَانُوا هُمْ وَغَسَّانُ قَبْلَ أَنْ يُسْلِمُوا يُهِلُّونَ لِمَنَاةَ مِثْلَهُ وَقَالَ مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ كَانَ رِجَالٌ مِنْ الْأَنْصَارِ مِمَّنْ كَانَ يُهِلُّ لِمَنَاةَ وَمَنَاةُ صَنَمٌ بَيْنَ مَكَّةَ وَالْمَدِينَةِ قَالُوا يَا نَبِيَّ اللَّهِ كُنَّا لَا نَطُوفُ بَيْنَ الصَّفَا وَالْمَرْوَةِ تَعْظِيمًا لِمَنَاةَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Az Zuhri] Aku mendengar ['Urwah] berkata; 'pernah bertanya kepada ['Aisyah radliallahu 'anha], lalu ia menjawab; Sesungguhnya dahulu orang yang telah bertalbiyah untuk berhala Manat yang berada di Al Musyallal tidak melakukan thawaf antara Shafa dan Marwa. Lalu Allah menurunkan ayat; Sesungguhnya shofa dan marwah termasuk syiar Allah. Maka Rasulullah shallallahu 'alaihi wasallam dan kaum muslimin melakukan thawaf. Sufyan berkata; berhala Manat yang berada di Al Musyallal letaknya antara Makkah dan Madinah. [Abdurrahman bin Khalid] berkata; dari [Ibnu Syihab], [Urwah] berkata; ['Aisyah] berkata; Ayat ini turun berkenaan dengan orang-orang Anshar yang mana mereka dan kabilah Ghassan sebelum mereka masuk Islam biasa bertalbiyah untuk berhala Manat, -seterusnya dengan redaksi yang serupa.- sedangkan [Ma'mar] berkata; dari [Az Zuhri] dari [Urwah] dari [Aisyah]; bahwa beberapa orang Anshar yang telah bertalbiyah bagi berhala Manat -yaitu berhala yang berada diantara Makkah dan Madinah- mereka berkata; Ya Nabiyullah, Kami tidak melakukan Thawaf antara Shafa dan Marwa, karena mengagungkan Manat. -dengan Hadits yang serupa.-"},"4179":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّجْمِ وَسَجَدَ مَعَهُ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْجِنُّ وَالْإِنْسُتَابَعَهُ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَيُّوبَ وَلَمْ يَذْكُرِ ابْنُ عُلَيَّةَ ابْنَ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami ['Abdul Warits] Telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] dia berkata; \"Nabi shallallahu 'alaihi wasallam bersujud pada surat An Najm, demikian juga kaum muslimin, orang-orang musyrik, jin dan seluruh manusia yang hadir.\" Hal ini diriwayatkan pula oleh [Ibrahim bin Thahman] dari [Ayyub], namun [Ibnu 'Ulayyah] tidak menyebutkan Ibnu Abbas."},"4180":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنِي أَبُو أَحْمَدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَأَوَّلُ سُورَةٍ أُنْزِلَتْ فِيهَا سَجْدَةٌ وَالنَّجْمِ قَالَ فَسَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَجَدَ مَنْ خَلْفَهُ إِلَّا رَجُلًا رَأَيْتُهُ أَخَذَ كَفًّا مِنْ تُرَابٍ فَسَجَدَ عَلَيْهِ فَرَأَيْتُهُ بَعْدَ ذَلِكَ قُتِلَ كَافِرًا وَهُوَ أُمَيَّةُ بْنُ خَلَفٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali] Telah mengabarkan kepadaku [Abu Ahmad] Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dari [Abdullah radliallahu 'anhu] dia berkata; Surat pertama kali yang di dalamnya ada ayat sajdah adalah surat An Najm. Abdullah berkata; Maka Rasulullah shallallahu 'alaihi wasallam dan orang-orang yang berada dibelakang beliau pun bersujud, kecuali seorang laki-laki yang aku lihat ia mengambil segenggam tanah lalu ia bersujud di atasnya. Setelah itu aku melihat orang itu terbunuh dalam keadaan kafir. Ia adalah Umayyah bin Khalaf."},"4181":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ وَسُفْيَانَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي مَعْمَرٍ عَنْ ابْنِ مَسْعُودٍ قَالَانْشَقَّ الْقَمَرُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِرْقَتَيْنِ فِرْقَةً فَوْقَ الْجَبَلِ وَفِرْقَةً دُونَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْهَدُوا","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dan [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Abu Ma'mar] dari [Ibnu Mas'ud] dia berkata; Pada masa Rasulullah shallallahu 'alaihi wasallam bulan terbelah menjadi dua bagian. Sebagian di atas bulan, sebagian lagi dibawahnya. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Saksikanlah!\""},"4182":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ أَخْبَرَنَا ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أَبِي مَعْمَرٍ عَنْ عَبْدِ اللَّهِ قَالَانْشَقَّ الْقَمَرُ وَنَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَارَ فِرْقَتَيْنِ فَقَالَ لَنَا اشْهَدُوا اشْهَدُوا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah mengabarkan kepada kami [Ibnu Abu Najih] dari [Mujahid] dari [Abu Ma'mar] dari [Abdullah] dia berkata; Ketika kami bersama Nabi shallallahu 'alaihi wasallam, bulan terbelah menjadi dua. Beliau berkata kepada kami: \"Saksikanlah, saksikanlah!\""},"4183":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنِي بَكْرٌ عَنْ جَعْفَرٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَانْشَقَّ الْقَمَرُ فِي زَمَانِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] dia berkata; Telah menceritakan kepadaku [Bakr] dari [Ja'far] dari ['Irak bin Malik] dari [Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] dari [Ibnu Abbas radliallahu 'anhuma] dia berkata; 'Bulan terbelah pada masa Nabi shallallahu 'alaihi wasallam.'"},"4184":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلَ أَهْلُ مَكَّةَ أَنْ يُرِيَهُمْ آيَةً فَأَرَاهُمْ انْشِقَاقَ الْقَمَرِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Yunus bin Muhammad] Telah menceritakan kepada kami [Syaiban] dari [Qatadah] dari [Anas radliallahu 'anhu] dia berkata; Penduduk Makkah meminta Rasul untuk memperlihatkan sebuah tanda, Maka Nabi shallallahu 'alaihi wasallam memperlihatkan kepada mereka terbelahnya bulan.'"},"4185":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَانْشَقَّ الْقَمَرُ فِرْقَتَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dia berkata; \"Bulan terbelah menjadi dua.\""},"4186":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ{ فَهَلْ مِنْ مُدَّكِرٍ }","id":"Telah menceritakan kepada kami [Hafsh bin Umar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] dia berkata; Nabi shallallahu 'alaihi wasallam membaca ayat: \"FAHAL MIN MUDDAKIR.\" (maka adakah orang yang mau mengambil pelajaran?). (AL Qamar: 15)."},"4187":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّه كَانَ يَقْرَأُ{ فَهَلْ مِنْ مُدَّكِرٍ }","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bahwasanya beliau membaca ayat: \"FAHAL MIN MUDDAKIR.\" (maka adakah orang yang mau mengambil pelajaran?). (AL Qamar: 15)."},"4188":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَاقَ أَنَّهُ سَمِعَ رَجُلًا سَأَلَ الْأَسْوَدَ{ فَهَلْ مِنْ مُدَّكِرٍ }أَوْ مُذَّكِرٍ فَقَالَ سَمِعْتُ عَبْدَ اللَّهِيَقْرَؤُهَا{ فَهَلْ مِنْ مُدَّكِرٍ }قَالَ وَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا{ فَهَلْ مِنْ مُدَّكِرٍ }دَالًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] bahwa dia mendengar seorang laki-laki bertanya kepada [Al Aswad] mengenai ayat apakah lafazhnya FAHAL MIN MUDDAKIR atau FAHAL MIN MUDZAKIR? Lalu dia menjawab; Aku mendengar [Abdullah] membacanya dengan lafazh; FAHAL MIN MUDDAKIR. Abdullah berkata; dan aku mendengar Nabi shallallahu 'alaihi wasallam membacanya dengan lafazh FAHAL MIN MUDDAKIR, menggunakan huruf Daal."},"4189":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا أَبِي عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ فَهَلْ مِنْ مُدَّكِرٍ }الْآيَةَ","id":"Telah menceritakan kepada kami ['Abdan] Telah mengabarkan kepada kami [Bapakku] dari [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam beliau membaca: FAHAL MIN MUDDAKIR. (maka adakah orang yang mau mengambil pelajaran?). (AL Qamar: 15)."},"4190":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ{ فَهَلْ مِنْ مُدَّكِرٍ }","id":"Telah menceritakan kepada kami [Muhammad] Telah menceritakan kepada kami [Gundar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau membaca: \"FAHAL MIN MUDDAKIR.\" (maka adakah orang yang mau mengambil pelajaran?). (AL Qamar: 15)."},"4191":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَقَرَأْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلْ مِنْ مُذَّكِرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ فَهَلْ مِنْ مُدَّكِرٍ }","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari [Al Aswad bin Yazid] dari [Abdullah] dia berkata; Aku membacakan ayat kepada Nabi shallallahu 'alaihi wasallam FAHAL MIN MUDZAKIR. Maka Nabi shallallahu 'alaihi wasallam membenarkan dengan lafazh FAHAL MIN MUDDAKIR. (maka adakah orang yang mau mengambil pelajaran?). (AL Qamar: 15)."},"4192":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ ح و حَدَّثَنِي مُحَمَّدٌ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ عَنْ وُهَيْبٍ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ فِي قُبَّةٍ يَوْمَ بَدْرٍ اللَّهُمَّ إِنِّي أَنْشُدُكَ عَهْدَكَ وَوَعْدَكَ اللَّهُمَّ إِنْ تَشَأْ لَا تُعْبَدْ بَعْدَ الْيَوْمِ فَأَخَذَ أَبُو بَكْرٍ بِيَدِهِ فَقَالَ حَسْبُكَ يَا رَسُولَ اللَّهِ أَلْحَحْتَ عَلَى رَبِّكَ وَهُوَ يَثِبُ فِي الدِّرْعِ فَخَرَجَ وَهُوَ يَقُولُ{ سَيُهْزَمُ الْجَمْعُ وَيُوَلُّونَ الدُّبُرَ }بَاب قَوْلِهِ{ بَلْ السَّاعَةُ مَوْعِدُهُمْ وَالسَّاعَةُ أَدْهَى وَأَمَرُّ }يَعْنِي مِنْ الْمَرَارَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Hausyab] Telah menceritakan kepada kami [Abdul Wahab] Telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] Demikian juga diriwayatkan dari jalur lainnya, Dan telah menceritakan kepadaku [Muhammad] Telah menceritakan kepada kami ['Affan bin Muslim] dari [Wuhaib] Telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: ketika beliau berada di Quba pada hari Badar: \"ALLOOHUMMA INNII ANSYUDUKA 'AHDAKA WAWA'DAKA, ALLOOHUMMA IN TASYA' LAA TU'BAD BA'DAL YAUM Ya Allah, sesungguhnya aku memohon kepadaMu akan sumpah dan janjiMu, ya Allah, jika Engkau mau, maka engkau tidak akan disembah lagi setelah hari ini.\" Lalu Abu Bakar meraih tangan beliau dan berkata; Cukuplah wahai Rasulullah, engkau telah memaksa atas Tuhanmu. Lalu beliau pun mengenakan baju perangnya, kemudian beliau keluar dan mengucapkan (firman Allah): \"Golongan itu pasti akan dikalahkan dan mereka akan mundur ke belakang. Sebenarnya hari kiamat itulah hari yang dijanjikan kepada mereka dan kiamat itu lebih dahsyat dan lebih pahit.\" (Al Qamar: 45-46)."},"4193":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي يُوسُفُ بْنُ مَاهَكٍ قَالَ إِنِّي عِنْدَ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْلَقَدْ أُنْزِلَ عَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ وَإِنِّي لَجَارِيَةٌ أَلْعَبُ{ بَلْ السَّاعَةُ مَوْعِدُهُمْ وَالسَّاعَةُ أَدْهَى وَأَمَرُّ }","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah menceritakan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] mengabarkan kepada mereka seraya berkata; Telah mengabarkan kepadaku [Yusuf bin Mahik] dia berkata; Sungguh aku berada di samping [Aisyah] ketika dia berkata; Sesungguhnya telah diturunkan kepada Muhammad shallallahu 'alaihi wasallam ketika beliau di Makkah, dan pada waktu itu aku bersama seorang budak sedang bermain-main. Ayat itu berbunyi: Sebenarnya hari kiamat itulah hari yang dijanjikan kepada mereka dan kiamat itu lebih dahsyat dan lebih pahit.\" (Al Qamar: 45-46)."},"4194":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا خَالِدٌ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ فِي قُبَّةٍ لَهُ يَوْمَ بَدْرٍ أَنْشُدُكَ عَهْدَكَ وَوَعْدَكَ اللَّهُمَّ إِنْ شِئْتَ لَمْ تُعْبَدْ بَعْدَ الْيَوْمِ أَبَدًا فَأَخَذَ أَبُو بَكْرٍ بِيَدِهِ وَقَالَ حَسْبُكَ يَا رَسُولَ اللَّهِ فَقَدْ أَلْحَحْتَ عَلَى رَبِّكَ وَهُوَ فِي الدِّرْعِ فَخَرَجَ وَهُوَ يَقُولُ{ سَيُهْزَمُ الْجَمْعُ وَيُوَلُّونَ الدُّبُرَ بَلْ السَّاعَةُ مَوْعِدُهُمْ وَالسَّاعَةُ أَدْهَى وَأَمَرُّ }","id":"Telah menceritakan kepadaku [Ishaq] Telah menceritakan kepada kami [Khalid] dari [Khalid] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda ketika beliau berada di Quba pada hari Badar: \"ANSYUDUKA 'AHDAKA WAWA'DAKA, ALLOOHUMMA IN SYI'TA LAA TU'BAD BA'DAL YAUM Ya Allah, sesungguhnya aku memohon kepadaMu akan sumpah dan janjiMu, ya Allah, jika Engkau mau, maka engkau tidak akan disembah lagi setelah hari ini.\" Lalu Abu Bakar meraih tangan beliau dan berkata; Cukuplah wahai Rasulullah, engkau telah memaksa atas Tuhanmu. Lalu beliau pun mengenakan baju perangnya, kemudian beliau keluar dan mengucapkan (firman Allah): \"Golongan itu pasti akan dikalahkan dan mereka akan mundur ke belakang. Sebenarnya hari kiamat itulah hari yang dijanjikan kepada mereka dan kiamat itu lebih dahsyat dan lebih pahit.\" (Al Qamar: 45-46)."},"4195":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ الْعَمِّيُّ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَنَّتَانِ مِنْ فِضَّةٍ آنِيَتُهُمَا وَمَا فِيهِمَا وَجَنَّتَانِ مِنْ ذَهَبٍ آنِيَتُهُمَا وَمَا فِيهِمَا وَمَا بَيْنَ الْقَوْمِ وَبَيْنَ أَنْ يَنْظُرُوا إِلَى رَبِّهِمْ إِلَّا رِدَاءُ الْكِبْرِ عَلَى وَجْهِهِ فِي جَنَّةِ عَدْنٍ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Al Aswad] Telah menceritakan kepada kami [Abdul 'Aziz bin Abdus Shamad Al 'Ammi] Telah menceritakan kepada kami [Abu 'Imran Al Jauni] dari [Abu Bakr bin Abdullah bin Qais] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam berkata; \"Dua bagian dari surga yang perabotnya dan segala isi di dalamnya terbuat dari perak. Dan dua bagian dari surga yang perabotnya serta segala isi di dalamnya terbuat dari emas. Tidak ada yang menghalangi suatu kaum untuk melihat Rabb mereka selain selendang keagungan yang ada di wajah-Nya di surga 'Adn.\""},"4196":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ اللَّهِ بْنِ قَيْسٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ خَيْمَةً مِنْ لُؤْلُؤَةٍ مُجَوَّفَةٍ عَرْضُهَا سِتُّونَ مِيلًا فِي كُلِّ زَاوِيَةٍ مِنْهَا أَهْلٌ مَا يَرَوْنَ الْآخَرِينَ يَطُوفُ عَلَيْهِمْ الْمُؤْمِنُونَ وَجَنَّتَانِ مِنْ فِضَّةٍ آنِيَتُهُمَا وَمَا فِيهِمَا وَجَنَّتَانِ مِنْ كَذَا آنِيَتُهُمَا وَمَا فِيهِمَا وَمَا بَيْنَ الْقَوْمِ وَبَيْنَ أَنْ يَنْظُرُوا إِلَى رَبِّهِمْ إِلَّا رِدَاءُ الْكِبْرِ عَلَى وَجْهِهِ فِي جَنَّةِ عَدْنٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepadaku [Abdul Aziz bin Abdush Shamad] Telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Abu Bakr bin Abdullah bin Qais] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dalam surga terdapat kemah yang terbuat dari permata yang berongga dengan luas enam puluh mil. Pada setiap sudutnya terdapat penghuni, namun mereka tidak dapat melihat yang lain, orang-orang mukmin mengelilingi mereka. Dan (di dalam surga juga terdapat) dua kebun yang gelas-gelas, serta segala sesuatu yang berada di dalamnya terbuat dari perak. Tidak ada lagi yang menghalangi antara suatu kaum untuk melihat Rabb mereka kecuali pakaian kesombongan yang melekat di wajah-Nya di dalam Jannah Aden.\""},"4197":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ شَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا وَاقْرَءُوا إِنْ شِئْتُمْ{ وَظِلٍّ مَمْدُودٍ }","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dalam surga terdapat sebatang pohon yang bilamana seorang yang berkendaraan berjalan di bawahnya selama seratus tahun, maka dia belum habis melewati bayangannya. Karena itu, bacalah jika kalian mau yaitu ayat, 'WA ZHILLIM MAMDUUD (Dan naungan -pohon- yang terbentang luas). (QS. Alwaqi'ah 30) '\""},"4198":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍسُورَةُ التَّوْبَةِ قَالَ التَّوْبَةُ هِيَ الْفَاضِحَةُ مَا زَالَتْ تَنْزِلُ وَمِنْهُمْ وَمِنْهُمْ حَتَّى ظَنُّوا أَنَّهَا لَنْ تُبْقِيَ أَحَدًا مِنْهُمْ إِلَّا ذُكِرَ فِيهَا قَالَ قُلْتُ سُورَةُ الْأَنْفَالِ قَالَ نَزَلَتْ فِي بَدْرٍ قَالَ قُلْتُ سُورَةُ الْحَشْرِ قَالَ نَزَلَتْ فِي بَنِي النَّضِيرِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah menceritakan kepada kami [Sa'id bin Sulaiman] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] ia berkata; Aku pernah bertanya kepada [Ibnu Abbas] mengenai surat At Taubah, maka ia pun menjelaskan, \"Surat At Taubah adalah diistilahkan Al Fadlihah (yang membongkar kejahatan kaum munafik). Ia senantiasa turun dengan ungkapan, 'WA MINHUM.., WA MINHUM.. (Dan di antara mereka.. dan di antara mereka) ' hingga mereka pun menyangka bahwa tidak ada seorang pun yang tersisa dari mereka kecuali disebutkan dalam surat tersebut.\" Kemudian aku bertanya, \"Bagaimana dengan surat Al Anfal? ' Ia menjelaskan, \"Surat itu turun pada saat terjadinya perang Badar.\" Aku bertanya lagi, \"Kalau surat Al Hasyr?\" Ia pun menjelaskan, \"Surat itu turun berkenaan dengan Bani Nadlir.\""},"4199":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُدْرِكٍ حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاسُورَةُ الْحَشْرِ قَالَ قُلْ سُورَةُ النَّضِيرِ","id":"Telah menceritakan kepada kami [Al Hasan bin Mudrik] Telah menceritakan kepada kami [Yahya bin Hammad] Telah mengabarkan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id] ia berkta; Aku pernah bertanya kepada [Ibnu Abbas] mengenai surat Al Hasyr, maka ia pun menjawab, \"Surat itu adalah surat An Nadlir (surat yang turun berkenaan dengan Bani Nadlir).\""},"4200":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّقَ نَخْلَ بَنِي النَّضِيرِ وَقَطَعَ وَهِيَ الْبُوَيْرَةُ فَأَنْزَلَ اللَّهُ تَعَالَى{ مَا قَطَعْتُمْ مِنْ لِينَةٍ أَوْ تَرَكْتُمُوهَا قَائِمَةً عَلَى أُصُولِهَا فَبِإِذْنِ اللَّهِ وَلِيُخْزِيَ الْفَاسِقِينَ }","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwasanya Rasulullah shallallahu 'alaihi wasallam membakar pepohonan kurma Bani Nadlir dan juga memotongnya, yakni Al Buwairah, maka Allah Ta'ala pun menurunkan ayat, \"Pepohonan (kurma) yang telah kalian tebang atau yang kalian biarkan berdiri tegak di atas pokoknya adalah atas dasar izin dari Allah, dan untuk menghinakan orang-orang yang fasik.\" (QS. Alhasyr 5)."},"4201":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ غَيْرَ مَرَّةٍ عَنْ عَمْرٍو عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَتْ أَمْوَالُ بَنِي النَّضِيرِ مِمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا لَمْ يُوجِفْ الْمُسْلِمُونَ عَلَيْهِ بِخَيْلٍ وَلَا رِكَابٍ فَكَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً يُنْفِقُ عَلَى أَهْلِهِ مِنْهَا نَفَقَةَ سَنَتِهِ ثُمَّ يَجْعَلُ مَا بَقِيَ فِي السِّلَاحِ وَالْكُرَاعِ عُدَّةً فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] lebih dari sekali dari [Amru] dari [Az Zuhri] dari [Malik bin Aus bin Al Hadatsan] dari [Umar radliallahu 'anhu] ia berkata: \"Harta kekayaan Bani Nadlir yang telah dijadikan Fai` oleh Allah atas Rasul-Nya shallallahu 'alaihi wasallam adalah termasuk harta yang diperoleh tanpa campur tangan sedikit pun dari kaum muslimin, baik itu dengan kuda perang atau yang lainnya. Sesungguhnya harta itu adalah milik Rasulullah shallallahu 'alaihi wasallam secara khusus dan sebagai nafkah bagi keluarganya. Sedangkan sisanya untuk perlengkapan persenjataan perang dan sejumlah kuda perang fi Sabilillah.\""},"4202":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ اللَّهُ الْوَاشِمَاتِ وَالْمُوتَشِمَاتِ وَالْمُتَنَمِّصَاتِ وَالْمُتَفَلِّجَاتِ لِلْحُسْنِ الْمُغَيِّرَاتِ خَلْقَ اللَّهِ فَبَلَغَ ذَلِكَ امْرَأَةً مِنْ بَنِي أَسَدٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ فَجَاءَتْ فَقَالَتْ إِنَّهُ بَلَغَنِي عَنْكَ أَنَّكَ لَعَنْتَ كَيْتَ وَكَيْتَ فَقَالَ وَمَا لِي أَلْعَنُ مَنْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ هُوَ فِي كِتَابِ اللَّهِ فَقَالَتْ لَقَدْ قَرَأْتُ مَا بَيْنَ اللَّوْحَيْنِ فَمَا وَجَدْتُ فِيهِ مَا تَقُولُ قَالَ لَئِنْ كُنْتِ قَرَأْتِيهِ لَقَدْ وَجَدْتِيهِ أَمَا قَرَأْتِ{ وَمَا آتَاكُمْ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا }قَالَتْ بَلَى قَالَ فَإِنَّهُ قَدْ نَهَى عَنْهُ قَالَتْ فَإِنِّي أَرَى أَهْلَكَ يَفْعَلُونَهُ قَالَ فَاذْهَبِي فَانْظُرِي فَذَهَبَتْ فَنَظَرَتْ فَلَمْ تَرَ مِنْ حَاجَتِهَا شَيْئًا فَقَالَ لَوْ كَانَتْ كَذَلِكَ مَا جَامَعْتُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata, \"Semoga Allah melaknati Al Wasyimaat (wanita yang mentato) dan Al Mutawatasyimaat (wanita yang meminta untuk ditato), Al Mutanammishaat (wanita yang mencukur alisnya), serta Al Mutafallijaat (merenggangkan gigi) untuk keindahan, yang mereka merubah-rubah ciptaan Allah.\" Kemudian ungkapan itu sampai kepada salah seorang wanita dari Bani Asad yang biasa dipanggil Ummu Ya'qub. Lalu wanita itu pun datang dan berkata, \"Telah sampai kepadaku berita tentang Anda. Bahwa Anda telah melaknat yang ini dan itu.\" Abdullah berkata, \"Mengapakah aku tidak melaknat mereka yang telah dilaknat oleh Rasulullah shallallahu 'alaihi wasallam dan mereka yang terdapat di dalam Kitabullah?.\" Kemudian wanita berkata, \"Sungguh, aku telah membaca di atara kedua lembarannya, namun di dalamnya aku tidaklah mendapatkan apa yang telah Anda katakan.\" Abdullah menjelaskan, \"Sekiranya Anda membacanya secara keseluruhan, maka niscaya saudari akan menemukannya. Bukankah Allah telah berfirman: 'Apa yang dibawa Rasul untuk kalian, maka ambillah, sedangkan apa yang dilarangnya, maka tingalkanlah? '\" (QS. Alhasyr 7). Wanita itu menjawab, \"Ya, benar.\" Abdullah melanjutkan, \"Sesungguhnya beliau telah melarang hal itu.\" Wanita itu kembali berkata, \"Tetapi, sesungguhnya aku menduga kuat, bahwa isteri anda sendiri melakukan hal itu.\" Abdullah berkata, \"Kalau itu anggapanmu, berangkatlah dan lihatlah.\" Lalu wanita itu pun pergi untuk melihatnya, namun ternyata tidak mendapatkan kebenaran dugaannya sedikit pun. Kemudian Abdullah pun berkata, \"Sekiranya isteriku seperti itu, niscaya aku tidak akan mencampurinya.\""},"4203":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ قَالَ ذَكَرْتُ لِعَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ حَدِيثَ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَلَعَنَ اللَّهُ الْوَاصِلَةَفَقَالَ سَمِعْتُهُ مِنْ امْرَأَةٍ يُقَالُ لَهَا أُمُّ يَعْقُوبَ عَنْ عَبْدِ اللَّهِ مِثْلَ حَدِيثِ مَنْصُورٍ","id":"Telah menceritakan kepada kami [Ali] Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] ia berkata; Aku menuturkan kepada [Ibnu Abis] hadits [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah radliallahu 'anhu], ia berkata: \"Semoga Allah melaknat Al Washilah (wanita yang menyambung rambutnya).\" Maka Ia pun berkata, \"Aku mendengarnya dari seorang wanita yang biasa dipanggil [Ummu Ya'qub], dari [Abdullah], sebagaimana hadis Manshur.\""},"4204":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي ابْنَ عَيَّاشٍ عَنْ حُصَيْنٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُأُوصِي الْخَلِيفَةَ بِالْمُهَاجِرِينَ الْأَوَّلِينَ أَنْ يَعْرِفَ لَهُمْ حَقَّهُمْ وَأُوصِي الْخَلِيفَةَ بِالْأَنْصَارِ الَّذِينَ تَبَوَّءُوا الدَّارَ وَالْإِيمَانَ مِنْ قَبْلِ أَنْ يُهَاجِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقْبَلَ مِنْ مُحْسِنِهِمْ وَيَعْفُوَ عَنْ مُسِيئِهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] Telah menceritakan kepada kami [Abu Bakr] yakni Ibnu Ayyasy, dari [Husain] dari [Amru bin Maimun] ia berkata; [Umar bin Al Khaththab] radliallahu 'anhu berkata, \"Aku wasiatkan khalifah untuk memperhatikan kaum Muhajirin yang pertama-tama kali hijrah, agar ia mengetahui apa yang menjadi hak mereka. Dan aku juga wasiatkan khalifah untuk memperhatikan orang-orang Anshar yang telah menyediakan tempat kediaman dan keimanan sebelum Nabi shallallahu 'alaihi wasallam berhijrah, agar ia menerima orang yang berbuat baik dari mereka dan memaafkan orang yang berbuat buruk dari mereka.\""},"4205":{"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ كَثِيرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ حَدَّثَنَا أَبُو حَازِمٍ الْأَشْجَعِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَصَابَنِي الْجَهْدُ فَأَرْسَلَ إِلَى نِسَائِهِ فَلَمْ يَجِدْ عِنْدَهُنَّ شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا رَجُلٌ يُضَيِّفُهُ هَذِهِ اللَّيْلَةَ يَرْحَمُهُ اللَّهُ فَقَامَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ أَنَا يَا رَسُولَ اللَّهِ فَذَهَبَ إِلَى أَهْلِهِ فَقَالَ لِامْرَأَتِهِ ضَيْفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَدَّخِرِيهِ شَيْئًا قَالَتْ وَاللَّهِ مَا عِنْدِي إِلَّا قُوتُ الصِّبْيَةِ قَالَ فَإِذَا أَرَادَ الصِّبْيَةُ الْعَشَاءَ فَنَوِّمِيهِمْ وَتَعَالَيْ فَأَطْفِئِي السِّرَاجَ وَنَطْوِي بُطُونَنَا اللَّيْلَةَ فَفَعَلَتْ ثُمَّ غَدَا الرَّجُلُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَقَدْ عَجِبَ اللَّهُ عَزَّ وَجَلَّ أَوْ ضَحِكَ مِنْ فُلَانٍ وَفُلَانَةَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيُؤْثِرُونَ عَلَى أَنْفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ }","id":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim bin Katsir] Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Fudlail bin Ghazwan] Telah menceritakan kepada kami [Abu Hazim Al Asyja'i] dari [Abu Hurairah radliallahu 'anhu] ia berkata; Seorang laki-laki mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sungguh, aku mengalami kesulitan (tidak mendapatkan makanan).\" Maka beliau pun mengutus seseorang kepada isteri-isterinya, namun ternyata utusan itu tidak mendapatkan (sesuatu makanan pun). Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah ada seorang pun yang mau menjamunya untuk malam hari ini, semoga Allah merahmatinya.\" Kemudian berdirilah seorang laki-laki dari kalangan Anshar seraya berkata, \"Aku wahai Rasulullah.\" Lalu laki-laki itu pun pergi menemui keluarganya dan berkata kepada isterinya, \"Ini adalah tamu Rasulullah shallallahu 'alaihi wasallam, janganlah kamu mengecewakannya barang sedikit pun.\" Sang isteri pun berkata, \"Demi Allah, aku tidak lagi memiliki apa-apa kecuali makanan untuk anak kita yang kecil.\" Laki-laki itu berkata, \"Jika anak-anak ingin makan malam, maka tidurkanlah mereka. Lalu kemarilah dan matikanlah lampu, kemudian kita berpura-pura menyantap makanan.\" Akhirnya sang isteri pun melakukannya. Pada keesokan harinya, laki-laki itu pun menemui Rasulullah shallallahu 'alaihi wasallam, dan beliau pun bersabda: \"Sungguh, Allah merasa ta'ajjub atau tertawa lantaran apa yang dilakukan si Fulan dan si Fulanah.\" Sehinngga Allah 'azza wajalla pun menurunkan ayat, \"Dan mereka lebih mementingkan yang lain, meskipun mereka sendiri sangat kesusahan.\" (QS. Alhasyr 9)."},"4206":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ حَدَّثَنِي الْحَسَنُ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ أَنَّهُ سَمِعَ عُبَيْدَ اللَّهِ بْنَ أَبِي رَافِعٍ كَاتِبَ عَلِيٍّ يَقُولُ سَمِعْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ يَقُولُبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَالزُّبَيْرَ وَالْمِقْدَادَ فَقَالَ انْطَلِقُوا حَتَّى تَأْتُوا رَوْضَةَ خَاخٍ فَإِنَّ بِهَا ظَعِينَةً مَعَهَا كِتَابٌ فَخُذُوهُ مِنْهَا فَذَهَبْنَا تَعَادَى بِنَا خَيْلُنَا حَتَّى أَتَيْنَا الرَّوْضَةَ فَإِذَا نَحْنُ بِالظَّعِينَةِ فَقُلْنَا أَخْرِجِي الْكِتَابَ فَقَالَتْ مَا مَعِي مِنْ كِتَابٍ فَقُلْنَا لَتُخْرِجِنَّ الْكِتَابَ أَوْ لَنُلْقِيَنَّ الثِّيَابَ فَأَخْرَجَتْهُ مِنْ عِقَاصِهَا فَأَتَيْنَا بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا فِيهِ مِنْ حَاطِبِ بْنِ أَبِي بَلْتَعَةَ إِلَى أُنَاسٍ مِنْ الْمُشْرِكِينَ مِمَّنْ بِمَكَّةَ يُخْبِرُهُمْ بِبَعْضِ أَمْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذَا يَا حَاطِبُ قَالَ لَا تَعْجَلْ عَلَيَّ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ امْرَأً مِنْ قُرَيْشٍ وَلَمْ أَكُنْ مِنْ أَنْفُسِهِمْ وَكَانَ مَنْ مَعَكَ مِنْ الْمُهَاجِرِينَ لَهُمْ قَرَابَاتٌ يَحْمُونَ بِهَا أَهْلِيهِمْ وَأَمْوَالَهُمْ بِمَكَّةَ فَأَحْبَبْتُ إِذْ فَاتَنِي مِنْ النَّسَبِ فِيهِمْ أَنْ أَصْطَنِعَ إِلَيْهِمْ يَدًا يَحْمُونَ قَرَابَتِي وَمَا فَعَلْتُ ذَلِكَ كُفْرًا وَلَا ارْتِدَادًا عَنْ دِينِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ قَدْ صَدَقَكُمْ فَقَالَ عُمَرُ دَعْنِي يَا رَسُولَ اللَّهِ فَأَضْرِبَ عُنُقَهُ فَقَالَ إِنَّهُ شَهِدَ بَدْرًا وَمَا يُدْرِيكَ لَعَلَّ اللَّهَ عَزَّ وَجَلَّ اطَّلَعَ عَلَى أَهْلِ بَدْرٍ فَقَالَ اعْمَلُوا مَا شِئْتُمْ فَقَدْ غَفَرْتُ لَكُمْقَالَ عَمْرٌو وَنَزَلَتْ فِيهِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَتَّخِذُوا عَدُوِّي وَعَدُوَّكُمْ أَوْلِيَاءَ }قَالَ لَا أَدْرِي الْآيَةَ فِي الْحَدِيثِ أَوْ قَوْلُ عَمْرٍو حَدَّثَنَا عَلِيٌّ قَالَ قِيلَ لِسُفْيَانَ فِي هَذَا فَنَزَلَتْ{ لَا تَتَّخِذُوا عَدُوِّي وَعَدُوَّكُمْ أَوْلِيَاءَ }الْآيَةَ قَالَ سُفْيَانُ هَذَا فِي حَدِيثِ النَّاسِ حَفِظْتُهُ مِنْ عَمْرٍو مَا تَرَكْتُ مِنْهُ حَرْفًا وَمَا أُرَى أَحَدًا حَفِظَهُ غَيْرِي","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Amru bin Dinar] ia berkata, Telah menceritakan kepadaku [Al Hasan bin Muhammad bin Ali] bahwa ia mendengar [Ubaidullah bin Abu Rafi'] sekretaris Ali, berkata, Aku mendengar [Ali radliallahu 'anhu] berkata; Aku, Zubair dan Miqdad pernah diutus oleh Rasulullah shallallahu 'alaihi wasallam, dan bersabda: \"Berangkatlah kalian hingga kalian tiba di Raudlah Khakh, sebab di tempat itu ada seorang wanita yang membawa surat, dan ambillah surat itu darinya.\" Setelah itu, kami pun segera pergi dengan memacu kuda berlari kencang hingga kami sampai di Ar Raudlah, dan ternyata kami pun mendapati seorang wanita yang dimaksud. Kami berkata, \"Tolong keluarkan surat itu.\" Wanita itu menjawab, \"Aku tidak membawa surat?\" kami katakan, \"Kamu keluarkan kitab itu, ataukah kami benar-benar akan melucuti pakaianmu.\" Akhirnya wanita itu pun mengeluarkan surat dari jalinan rambutnya. Dan kami segera membawanya kepada Nabi shallallahu 'alaihi wasallam. Dan ternyata surat itu ditulis oleh Hathib bin Balta'ah dan akan disampaikan kepada orang-orang musyrik yang bertempat tingga di Makkah. Ia mengabarkan tentang beberapa agenda Rasulullah shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Apa-apaan ini wahai Hathib?\" Hathib berkata, \"Janganlah Anda terburu-buru dalam memberikan putusan atasku wahai Rasulullah. Aku adalah seorang yang berkebangsaan Quraisy, namun aku bukanlah bagian dari diri mereka. Orang-orang yang bersama Anda dari kalangan Muhajirin sesungguhnya memiliki kerabat yang dapat memberikan pengamanan untuk keluarga dan juga harta mereka di Makkah. Karena itulah aku ingin ketika aku tidak lagi memiliki pertalian nasab terhadap mereka untuk berbuat sesuatu yang dengannya mereka mau turut menjaga kerabatku. Tidaklah aku melakukannya karena kekufuran atau lantaran murtad dari agamaku.\" Akhirnya Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya, ia telah berkata jujur pada kalian.\" Tiba-tiba Umar berkata, \"Izinkanlah aku untuk menebas lehernya wahai Rasulullah.\" Beliau bersabda: \"Sesungguhnya ia turut dalam peperangan Badar. Apa alasanmu, bukankah Allah telah memberikan kekhususan terhadap Ahlu Badar seraya berfirman: 'Beramallah kalian, sesuka kalian. Sesungguhnya, Aku telah mengampuni kalian.'\" Amru berkata; Terkait denga peristiwa ini, maka turun pulalah ayat: \"Wahai orang-orang yang beriman, janganlah kalian mengambil musuh-Ku dan musuh kalian sebagai wali.\" (QS. Almumtahanah 1) Aku tidak tahu, apakah itu adalah ayat yang tercantum di dalam hadis, ataukah ungkapannya Amru. Ali menceritakan kepada kami; Ia berkata; Pernah diceritakan kepada Sufyan bahwa, dalam persoalan ini turunlah ayat: \"Janganlah kalian menjadikan musuh-Ku dan musuh kalian sebagai wali.\" (QS. Almumtahanah 1) Maka Sufyan berkata, \"Hal ini terkait dengan peristiwa itu. Aku menghafalnya dari Amru dan aku tidaklah meninggalkan satu huruf pun darinya. Dan aku belum pernah melihat orang yang menghafalnya selain aku.\" "},"4207":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْتَحِنُ مَنْ هَاجَرَ إِلَيْهِ مِنْ الْمُؤْمِنَاتِ بِهَذِهِ الْآيَةِ بِقَوْلِ اللَّهِ{ يَا أَيُّهَا النَّبِيُّ إِذَا جَاءَكَ الْمُؤْمِنَاتُ يُبَايِعْنَكَ إِلَى قَوْلِهِ غَفُورٌ رَحِيمٌ }قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ فَمَنْ أَقَرَّ بِهَذَا الشَّرْطِ مِنْ الْمُؤْمِنَاتِ قَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ بَايَعْتُكِ كَلَامًا وَلَا وَاللَّهِ مَا مَسَّتْ يَدُهُ يَدَ امْرَأَةٍ قَطُّ فِي الْمُبَايَعَةِ مَا يُبَايِعُهُنَّ إِلَّا بِقَوْلِهِ قَدْ بَايَعْتُكِ عَلَى ذَلِكِتَابَعَهُ يُونُسُ وَمَعْمَرٌ وَعَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ الزُّهْرِيِّ وَقَالَ إِسْحَاقُ بْنُ رَاشِدٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ وَعَمْرَةَ","id":"Telah menceritakan kepada kami [Ishaq] Telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'dari] Telah menceritakan kepada kami [Anak saudaraku Ibnu Syihab] dari [pamannya] Telah mengabarkan kepadaku [Urwah] bahwanya [Aisyah radliallahu 'anha] Telah mengabarkan kepadanya, bahwasanya; Rasulullah shallallahu 'alaihi wasallam menguji kaum wanita yang berhijrah kepadanya dengan ayat ini: \"Wahai sang Nabi, apabila wanita-wanita mukminat datang kepadaku hendak berbai'at -hingga firman-Nya- (Allah) Maha Pengampun dan juga Penyayang.\" (QS. Almumtahanah 2). Urwah berkata; Aisyah berkata; Wanita-wanita mukminat yang mengikrarkan syarat ini, maka Rasulullah shallallahu 'alaihi wasallam bersabda padanya: \"Sesungguhnya aku telah membai'atmu.\" Yakni beliau membai'atnya hanya sebatas ungkapan. Dan demi Allah, tangan beliau tidak pernah menyentuh tangan seorang wanita pun dalam berbai'at. Beliau tidak pernah membaiat mereka kecuali dengan ungkapan: \"Sungguh, aku telah membai'atmu atas perkataan itu.\" Hadits ini dikuatkan oleh [Yunus], [Ma'mar] dan [Abdurrahman bin Ishaq] dari [Az Zuhri]. Dan [Ishaq bin Rasyid] berkata; dari [Az Zuhri] dari [Urwah] dan ['Amrah]."},"4208":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْبَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ عَلَيْنَا{ أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا }وَنَهَانَا عَنْ النِّيَاحَةِ فَقَبَضَتْ امْرَأَةٌ يَدَهَا فَقَالَتْ أَسْعَدَتْنِي فُلَانَةُ أُرِيدُ أَنْ أَجْزِيَهَا فَمَا قَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَانْطَلَقَتْ وَرَجَعَتْ فَبَايَعَهَا","id":"Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Ayyub] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah radliallahu 'anha] ia berkata; Kami berbai'at kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau pun membacakan ayat kepada kami: \"Dan janganlah mereka menyekutukan Allah dengan sesuatu apapun.\" Kemudian beliau juga melarang kami untuk melakukan Niyahah (meratap saat tertimpa musibah). Lalu seorang wanita menggenggam tangannya dan berkata, \"Sesungguhnya si Fulanah telah membahagiakanku, dan aku ingin segera membalasnya.\" Namun, Nabi shallallahu 'alaihi wasallam tidak berkata apa pun pada wanita itu. Wanita itu pergi, kemudian kembali lagi, dan beliau pun membai'atnya."},"4209":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ الزُّبَيْرَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ تَعَالَى{ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }قَالَ إِنَّمَا هُوَ شَرْطٌ شَرَطَهُ اللَّهُ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Wahb bin Jarir] ia berkata, Telah menceritakan kepada kami [bapakku] ia berkata, Aku mendengar [Az Zubair] dari [Ikrimah] dari [Ibnu Abbas] terkait dengan firman Allah Ta'ala: \"Dan janganlah mereka mendurhakaimu dalam kebaikan.\" Ia berkata, \"Sesungguhnya hal itu hanyalah syarat yang Allah persyaratkan untuk kaum wanita.\""},"4210":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ حَدَّثَنَاهُ قَالَ حَدَّثَنِي أَبُو إِدْرِيسَ سَمِعَ عُبَادَةَ بْنَ الصَّامِتِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتُبَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَزْنُوا وَلَا تَسْرِقُوا وَقَرَأَ آيَةَ النِّسَاءِوَأَكْثَرُ لَفْظِ سُفْيَانَ قَرَأَ الْآيَةَ فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ فَهُوَ كَفَّارَةٌ لَهُ وَمَنْ أَصَابَ مِنْهَا شَيْئًا مِنْ ذَلِكَ فَسَتَرَهُ اللَّهُ فَهُوَ إِلَى اللَّهِ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُ تَابَعَهُ عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ فِي الْآيَةِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] berkata; [Az Zuhri] Telah menceritakannya kepada kami, ia berkata; telah menceritakan kepadaku [Abu Idris] bahwa telah mendengar [Ubadah bin Shamit radliallahu 'anhu] berkata; Suatu hari, kami berada di sisi Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Apakah kalian mau berbai'at kepadaku bahwa kalian tidak akan menyekutukan Allah dengan sesuatu apa pun, dan kalian tidak akan berzina dan tidak pula akan mencuri?\" kemudian beliau membaca ayat dari surat An Nisa`. Dan mayoritas redaksi Sufyan \"Ia membacakan ayat\" (Bukan ayat surat Annisa'). Barangsiapa di antara kalian yang memenuhi janjinya, maka ganjaran pahala ada di sisi Allah. Dan siapa yang melanggar satu darinya lalu ia disiksa, maka hal itu adalah kafarah baginya. Namun, siapa yang melanggar satu darinya lalu Allah menyembunyikan kesalahannya, maka dosa hal itu kembali kepada Allah, bila Dia berkehendak, maka Dia akan menyiksanya, dan bila menghendaki, Dia akan mengampuninya. Hadits ini diperkuat oleh [Abdurrazzaq] dari [Ma'mar], yakni terkait dengan ayat."},"4211":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ وَأَخْبَرَنِي ابْنُ جُرَيْجٍ أَنَّ الْحَسَنَ بْنَ مُسْلِمٍ أَخْبَرَهُ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَشَهِدْتُ الصَّلَاةَ يَوْمَ الْفِطْرِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ فَكُلُّهُمْ يُصَلِّيهَا قَبْلَ الْخُطْبَةِ ثُمَّ يَخْطُبُ بَعْدُ فَنَزَلَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَأَنِّي أَنْظُرُ إِلَيْهِ حِينَ يُجَلِّسُ الرِّجَالَ بِيَدِهِ ثُمَّ أَقْبَلَ يَشُقُّهُمْ حَتَّى أَتَى النِّسَاءَ مَعَ بِلَالٍ فَقَالَ{ يَا أَيُّهَا النَّبِيُّ إِذَا جَاءَكَ الْمُؤْمِنَاتُ يُبَايِعْنَكَ عَلَى أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا وَلَا يَسْرِقْنَ وَلَا يَزْنِينَ وَلَا يَقْتُلْنَ أَوْلَادَهُنَّ وَلَا يَأْتِينَ بِبُهْتَانٍ يَفْتَرِينَهُ بَيْنَ أَيْدِيهِنَّ وَأَرْجُلِهِنَّ }حَتَّى فَرَغَ مِنْ الْآيَةِ كُلِّهَا ثُمَّ قَالَ حِينَ فَرَغَ أَنْتُنَّ عَلَى ذَلِكَ فَقَالَتْ امْرَأَةٌ وَاحِدَةٌ لَمْ يُجِبْهُ غَيْرُهَا نَعَمْ يَا رَسُولَ اللَّهِ لَا يَدْرِي الْحَسَنُ مَنْ هِيَ قَالَ فَتَصَدَّقْنَ وَبَسَطَ بِلَالٌ ثَوْبَهُ فَجَعَلْنَ يُلْقِينَ الْفَتَخَ وَالْخَوَاتِيمَ فِي ثَوْبِ بِلَالٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] Telah menceritakan kepada kami [Harun bin Ma'ruf] Telah menceritakan kepada kami [Abdullah bin Wahb] ia berkata, Telah mengabarkan kepadaku [Ibnu Juraij] bahwa [Al Hasan bin Muslim] Telah mengabarkan kepadanya dari [Thawus] dari [Ibnu Abbas radliallahu 'anhuma] ia berkata; Aku pernah turut menunaikan Shalat 'Idul Fithri bersama Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman, maka semuanya shalat terlebih dahulu sebelum khuthbah. Dan setelah shalat, barulah mereka menyampaikan khuthbah. Ketika Nabi shallallahu 'alaihi wasallam turun, maka aku melihat saat beliau memerintahkan dengan tangannya agar kaum lelaki duduk. Dan setelah itu, beliau berjalan ditemani Bilal melewati mereka hingga sampai di tempat kaum wanita berada. Kemudian beliau membaca: \"Wahai sang Nabi, apabila wanita-wanita mukminat datang kepadamu hendak berbai'at bahwa mereka tidak akan menyekutukan Allah dengan sesuatu apa pun, tidak mencuri, tidak berzina, dan tidak akan membunuh anak-anak mereka, serta tidak akan berbuat kebohongan...\"(QS. ALmumtahanah 12). hingga beliau selesai membaca ayat itu keseluruhannya. Setelah itu beliau bersabda: \"Kalian semua berada di atas janji itu.\" Lalu salah seorang wanita menjawab, \"Ya, wahai Rasulullah.\" Sementara yang lain diam. Al Hasan tidak tahu, siapakah wanita itu. Akhirnya para wanita bersedekah, sedangkan Bilal membentangkan pakaiannya, sementara mereka melemparkan gelang dan cincin-cincin mereka ke dalam pakaian Bilal."},"4212":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ لِي أَسْمَاءً أَنَا مُحَمَّدٌ وَأَنَا أَحْمَدُ وَأَنَا الْمَاحِي الَّذِي يَمْحُو اللَّهُ بِيَ الْكُفْرَ وَأَنَا الْحَاشِرُ الَّذِي يُحْشَرُ النَّاسُ عَلَى قَدَمِي وَأَنَا الْعَاقِبُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata, Telah mengabarkan kepadaku [Muhammad bin Jubair bin Muth'im] dair [bapaknya radliallahu 'anhu] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam berabda: \"Sesungguhnya aku memiliki beberapa nama. Aku adalah Muhammad, Ahmad, Al Mahi yang maknanya dengankulah Allah menghilangkan kekafiran. Aku juga adalah Al Hasyir, yang maknanya manusia dibangkitkan di atas telapak kakiku. Dan aku juga Al 'Aqib.\" "},"4213":{"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ ثَوْرٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُنْزِلَتْ عَلَيْهِ سُورَةُ الْجُمُعَةِ{ وَآخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا بِهِمْ }قَالَ قُلْتُ مَنْ هُمْ يَا رَسُولَ اللَّهِ فَلَمْ يُرَاجِعْهُ حَتَّى سَأَلَ ثَلَاثًا وَفِينَا سَلْمَانُ الْفَارِسِيُّ وَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَى سَلْمَانَ ثُمَّ قَالَ لَوْ كَانَ الْإِيمَانُ عِنْدَ الثُّرَيَّا لَنَالَهُ رِجَالٌ أَوْ رَجُلٌ مِنْ هَؤُلَاءِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا عَبْدُ الْعَزِيزِ أَخْبَرَنِي ثَوْرٌ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنَالَهُ رِجَالٌ مِنْ هَؤُلَاءِ","id":"Telah menceritakan kepadaku [Abdul Aziz bin Abdullah] ia berkata, Telah menceritakan kepadaku [Sulaiman bin Bilal] dari [Tsaur] dari [Abul Ghaits] dari [Abu Hurairah radliallahu 'anhu] ia berkata; Suatu hari, kami duduk-duduk di sisi Nabi shallallahu 'alaihi wasallam, lalu diturunkanlah pada beliau surat Al Jumu'ah dan \"WA `AAKHARIINA MINHUM LAMMAA YALHAQUU BIHIM.\" Maka aku pun bertanya, \"Siapa mereka itu wahai Rasulullah?\" Namun, beliau belum juga menjawab hingga tiga orang bertanya. Di antara kami ada Salman Al Farisi. Kemudian Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya pada Salman dan bersabda: \"Sekiranya keimanan itu ada di gugusan bintang, niscaya keimanan itu tetap akan diperoleh oleh sekelompok atau seseorang dari mereka itu (Orang-orang Persi).\" Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] Telah menceritakan kepada kami [Abdul Aziz] Telah mengabarkan kepadaku [Tsaur] dari [Abul Ghaits] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Niscaya (keimanan) itu akan diperoleh oleh sekelompok orang dari mereka (Orang Persi).\""},"4214":{"ar":"حَدَّثَنِي حَفْصُ بْنُ عُمَرَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حُصَيْنٌ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ وَعَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَقْبَلَتْ عِيرٌ يَوْمَ الْجُمُعَةِ وَنَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَثَارَ النَّاسُ إِلَّا اثْنَيْ عَشَرَ رَجُلًا فَأَنْزَلَ اللَّهُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","id":"Telah menceritakan kepadaku [Hafsh bin Umar] Telah menceritakan kepada kami [Khalid bin Abdullah] Telah menceritakan kepada kami [Hushain] dari [Salim bin Abul Ja'dari] dan dari [Abu Sufyan] dari [Jabir bin Abdullah radliallahu 'anhuma] ia berkata; Pada hari Jum'at, datanglah barang dagangan sementara kami saat itu sedang bersama Nabi shallallahu 'alaihi wasallam. Maka orang-orang pun pergi kecuali dua belas orang yang tersisa, maka Allah menurunkan ayat: \"Dan ketika mereka melihat perdagangan atau kesenangan mereka bergegas padanya dan meninggalkanmu dalam keadaan berdiri (menyampaikan khuthbah).\" (QS. Aljumu'ah 11)."},"4215":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكُنْتُ فِي غَزَاةٍ فَسَمِعْتُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ يَقُولُ لَا تُنْفِقُوا عَلَى مَنْ عِنْدَ رَسُولِ اللَّهِ حَتَّى يَنْفَضُّوا مِنْ حَوْلِهِ وَلَئِنْ رَجَعْنَا مِنْ عِنْدِهِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ فَذَكَرْتُ ذَلِكَ لِعَمِّي أَوْ لِعُمَرَ فَذَكَرَهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَانِي فَحَدَّثْتُهُ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَبْدِ اللَّهِ بْنِ أُبَيٍّ وَأَصْحَابِهِ فَحَلَفُوا مَا قَالُوا فَكَذَّبَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَدَّقَهُ فَأَصَابَنِي هَمٌّ لَمْ يُصِبْنِي مِثْلُهُ قَطُّ فَجَلَسْتُ فِي الْبَيْتِ فَقَالَ لِي عَمِّي مَا أَرَدْتَ إِلَى أَنْ كَذَّبَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَقَتَكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِذَا جَاءَكَ الْمُنَافِقُونَ }فَبَعَثَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ فَقَالَ إِنَّ اللَّهَ قَدْ صَدَّقَكَ يَا زَيْدُ","id":"Telah menceritakan kepada kami [Abdullah bin Raja`] Telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Zaid bin Arqam] ia berkata; Aku berada dalam suatu peperangan, lalu aku mendengar Abdullah bin Ubbay berkata, \"Janganlah kalian berinfak atas orang-orang yang bersama Rasulullah shallallahu 'alaihi wasallam sehingga mereka lari darinya. Dan jika kita kembali dari sisinya, niscaya orang-orang mulia (kuat) akan mengeluarkan orang-orang yang hina darinya.\" Maka aku pun menuturkan hal itu pada pamanku atau Umar dan ia pun menuturkannya kepada Nabi shallallahu 'alaihi wasallam. Kemudian beliau memanggilku, maka aku menceritakan kejadian tersebut. Akhirnya Rasulullah shallallahu 'alaihi wasallam mengirimkan utusan kepada Abdullah bin Ubbay dan para sahabatnya, namun mereka bersumpah bahwa mereka tidak mengatakannya. Maka Rasulullah shallallahu 'alaihi wasallam pun mendustakanku dan membenarkan Abdullah bin Ubbay beserta sahabat-sahabatnya. Sehingga aku tertimpa kesedihan yang belum pernah kualami sebelumnya. Aku duduk termenung di Ka'bah, kemudian pamanku bertanya padaku, \"Apa yang kamu inginkan sehingga Rasulullah shallallahu 'alaihi wasallam mendustakanmu dan memarahimu?\" Maka Allah menurunkan surat: \"IDZAA JAA`AKAL MUNAAFIQUUNA.\" (QS. Almunafiqun). Akhirnya Rasulullah shallallahu 'alaihi wasallam mengutus seseorang kepadaku dan membacakan surat itu, kemudian utusan itu berkata, \"Sesungguhnya Allah telah membenarkanmu wahai Zaid.\""},"4216":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ زَيْدِ بْنِ أَرْقَمَ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ عَمِّي فَسَمِعْتُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ ابْنَ سَلُولَ يَقُولُ لَا تُنْفِقُوا عَلَى مَنْ عِنْدَ رَسُولِ اللَّهِ حَتَّى يَنْفَضُّوا وَقَالَ أَيْضًا لَئِنْ رَجَعْنَا إِلَى الْمَدِينَةِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ فَذَكَرْتُ ذَلِكَ لِعَمِّي فَذَكَرَ عَمِّي لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَبْدِ اللَّهِ بْنِ أُبَيٍّ وَأَصْحَابِهِ فَحَلَفُوا مَا قَالُوا فَصَدَّقَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَذَّبَنِي فَأَصَابَنِي هَمٌّ لَمْ يُصِبْنِي مِثْلُهُ قَطُّ فَجَلَسْتُ فِي بَيْتِي فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ إِذَا جَاءَكَ الْمُنَافِقُونَ إِلَى قَوْلِهِ هُمْ الَّذِينَ يَقُولُونَ لَا تُنْفِقُوا عَلَى مَنْ عِنْدَ رَسُولِ اللَّهِ إِلَى قَوْلِهِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ }فَأَرْسَلَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهَا عَلَيَّ ثُمَّ قَالَ إِنَّ اللَّهَ قَدْ صَدَّقَكَ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Zaid bin Arqam] radliallahu 'anhu, ia berkata; Suatu ketika, aku berada bersama pamanku, lalu aku mendengar Abdullah bin Ubbay bin Salul berkata, \"Janganlah kalian memberi infak kepada mereka yang berada di sisi Rasulullah shallallahu 'alaihi wasallam hingga mereka lari darinya.\" Dan ia juga mengatakan, \"Jika kita kembali ke Madinah, niscaya orang-orang mulia akan mengeluarkan orang-orang yang terhina darinya.\" Maka aku pun menuturkan hal itu pada pamanku dan ia pun menyampaikannya kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam mengirim utusan kepada Abdullah bin Ubbay dan para sahabatnya, dan mereka bersumpah atas apa yang mereka katakan. Dan akhirnya Rasulullah shallallahu 'alaihi wasallam membenarkan mereka dan mendustakanku. Aku pun tertimpa rasa sedih yang belum pernah kurasakan sebelumnya. Aku hanya bisa duduk di dalam rumahku, sehingga Allah menurunkan surat: \"IDZAA JAA`AKAL MUNAAFIQUUNA..-hingga firman Allah- HUMULLADZIINA QAALUU LAA TUNFIQUU 'ALAA MAN 'INDA RASULILLAH (mereka itulah orang-orang yang mengtaakan 'Janganlah kalian berinfak kepada orang-orang yang bersama Rasulullah)...-hingga firman Allah- LAYUKHRIJANNAL A'AZZU MINHAL ADZALL.\" (Niscaya orang yang kuat akan mengusir yang lemah). Lalu Rasulullah shallallahu 'alaihi wasallam mengutus seseorang padaku dan membacakannya atasku kemudian berkata, \"Sesungguhnya Allah telah membenarkanmu.\""},"4217":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ كَعْبٍ الْقُرَظِيَّ قَالَ سَمِعْتُ زَيْدَ بْنَ أَرْقَمَ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا قَالَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ{ لَا تُنْفِقُوا عَلَى مَنْ عِنْدَ رَسُولِ اللَّهِ }وَقَالَ أَيْضًا{ لَئِنْ رَجَعْنَا إِلَى الْمَدِينَةِ }أَخْبَرْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَامَنِي الْأَنْصَارُ وَحَلَفَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ مَا قَالَ ذَلِكَ فَرَجَعْتُ إِلَى الْمَنْزِلِ فَنِمْتُ فَدَعَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ فَقَالَ إِنَّ اللَّهَ قَدْ صَدَّقَكَ وَنَزَلَ{ هُمْ الَّذِينَ يَقُولُونَ لَا تُنْفِقُوا }الْآيَةَوَقَالَ ابْنُ أَبِي زَائِدَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرٍو عَنْ ابْنِ أَبِي لَيْلَى عَنْ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata; Aku mendengar [Muhammad bin Ka'ab Al Qurazhi] berkata, Aku mendengar [Zaid bin Arqam radliallahu 'anhu] berkata; Ketika Abdullah bin Ubbay berkata, \"Janganlah kalain memberikan infak atas orang-orang yang berada bersama Rasulullah shallallahu 'alaihi wasallam.\" Dan ia juga berkata, \"Jika kita kembali ke kota Madinah..\" Maka aku pun mengbarkan hal itu pada Nabi shallallahu 'alaihi wasallam sehingga orang-orang Anshar pun mencelaku. Kemudian Abdullah bin Ubbay bersumpah bahwa ia tidak mengatakannya. Lalu aku pulang ke rumahku dan tidur. Kemudian Rasulullah shallallahu 'alaihi wasallam memanggilku dan aku pun mendatangi beliau. Beliau bersabda: \"Sesungguhnya Allah telah membenarkanmu.\" Dan turun pula ayat, \"HUMULLADZIINA YAQUULU LAA TUNFIQUU 'ALAA MAN 'INDA RASULULLAH.\" (QS. Almunafiqun 7). [Ibnu Abu Za`idah] berkata; dari [Al A'masy] dari [Amru] dari [Ibnu Abu Laila] dari [Zaid] dari Nabi shallallahu 'alaihi wasallam."},"4218":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ زَيْدَ بْنَ أَرْقَمَ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ أَصَابَ النَّاسَ فِيهِ شِدَّةٌ فَقَالَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ لِأَصْحَابِهِ لَا تُنْفِقُوا عَلَى مَنْ عِنْدَ رَسُولِ اللَّهِ حَتَّى يَنْفَضُّوا مِنْ حَوْلِهِ وَقَالَ لَئِنْ رَجَعْنَا إِلَى الْمَدِينَةِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَأَرْسَلَ إِلَى عَبْدِ اللَّهِ بْنِ أُبَيٍّ فَسَأَلَهُ فَاجْتَهَدَ يَمِينَهُ مَا فَعَلَ قَالُوا كَذَبَ زَيْدٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَقَعَ فِي نَفْسِي مِمَّا قَالُوا شِدَّةٌ حَتَّى أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ تَصْدِيقِي فِي{ إِذَا جَاءَكَ الْمُنَافِقُونَ }فَدَعَاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَسْتَغْفِرَ لَهُمْ فَلَوَّوْا رُءُوسَهُمْ وَقَوْلُهُ{ خُشُبٌ مُسَنَّدَةٌ }قَالَ كَانُوا رِجَالًا أَجْمَلَ شَيْءٍ","id":"Telah menceritakan kepada kami [Amru bin Khalid] Telah menceritakan kepada kami [Zuhair bin Mu'awiyah] Telah menceritakan kepada kami [Abu Ishaq] ia berkata; Aku mendengar [Zaid bin Arqam] ia berkata; Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, saat itu orang-orang tertimpa kesulitan, lalu Abdullah bin Ubbay berkata kepada para sahabatnya, \"Janganlah kalian memberikan perbekalan kepada orang-orang yang berada di sisi Rasulullah shallallahu 'alaihi wasallam hingga mereka lari daripadanya.\" Dan ia juga mengatakan, \"Jika kita kembali ke Madinah, niscaya orang-orang mulia akan mengeluarkan orang-orang yang hina darinya.\" Maka aku pun segera menemui Nabi shallallahu 'alaihi wasallam dan mengabarkan kejadian itu. Kemudian Rasulullah shallallahu 'alaihi wasallam mengirim utusan kepada Abdullah bin Ubbay untuk menanyakan hal itu, namun ternyata mereka bersumpah dengan sungguh-sungguh bahwa mereka tidak mengatakannya. Mereka katakan, \"Zaid telah mendustai Rasulullah shallallahu 'alaihi wasallam.\" Sejak itu, maka ungkapan mereka itu begitu menyakitkan hatiku hingga Allah 'azza wajalla membenarkanku dalam ayat, \"IDZAA JAA`AKAL MUNAAFIQUUNA.\" Akhirnya Nabi shallallahu 'alaihi wasallam memanggil mereka agar beliau memintakan ampunan bagi mereka, namun mereka memalingkan muka. Firman Allah, \"KHUSYUBUM MUSYANNADAH.\" Yakni, maknanya mereka adalah orang-orang yang paling tampan."},"4219":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكُنْتُ مَعَ عَمِّي فَسَمِعْتُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ ابْنَ سَلُولَ يَقُولُ لَا تُنْفِقُوا عَلَى مَنْ عِنْدَ رَسُولِ اللَّهِ حَتَّى يَنْفَضُّوا وَلَئِنْ رَجَعْنَا إِلَى الْمَدِينَةِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ فَذَكَرْتُ ذَلِكَ لِعَمِّي فَذَكَرَ عَمِّي لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَانِي فَحَدَّثْتُهُ فَأَرْسَلَ إِلَى عَبْدِ اللَّهِ بْنِ أُبَيٍّ وَأَصْحَابِهِ فَحَلَفُوا مَا قَالُوا وَكَذَّبَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَدَّقَهُمْ فَأَصَابَنِي غَمٌّ لَمْ يُصِبْنِي مِثْلُهُ قَطُّ فَجَلَسْتُ فِي بَيْتِي وَقَالَ عَمِّي مَا أَرَدْتَ إِلَى أَنْ كَذَّبَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَقَتَكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالُوا نَشْهَدُ إِنَّكَ لَرَسُولُ اللَّهِ }وَأَرْسَلَ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهَا وَقَالَ إِنَّ اللَّهَ قَدْ صَدَّقَكَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Abu Ishaq] dari [Zaid bin Arqam] ia berkata; Suatu ketika, aku bersama pamanku, lalu aku mendengar Abdullah bin Ubbay bin Salul berkata, \"Janganlah kalian memberikan perbekalan kepada orang-orang yang berada di sisi Rasulullah shallallahu 'alaihi wasallam hingga mereka lari daripadanya. Dan jika kita kembali ke Madinah, niscaya orang-orang mulia akan mengeluarkan orang-orang yang hina darinya.\" Maka aku pun menuturkan hal itu pada pamanku, dan pamanku menyampaikannya kepada Nabi shallallahu 'alaihi wasallam. Kemudian beliau memanggilku, maka aku pun menceritakannya. Lalu beliau mengirim utusan kepada Abdullah bin Ubbay dan para sahabatnya, namun mereka bersumpah bahwa mereka tidak mengatakannya. Akhirnya Nabi shallallahu 'alaihi wasallam mendustakanku dan membenarkan mereka. Sejak itu, aku pun tertimpa kesedihan yang belum pernah aku rasakan sebelumnya. Aku hanya duduk di dalam rumahku. Pamanku berkata, \"Apa yang kamu inginkan hingga Rasulullah shallallahu 'alaihi wasallam mendustakan dan memarahimu?\" Akhirnya Allah Ta'ala menurunkan: \"IDZAA JAA`AKAL MUNAAFIQUUNA QAALUU NASYHADU INNAKA RASULULLAH (Ketika orang-orang munafik datang kepadamu, mereka berkata, 'Kami bersaksi bahwa Anda adalah Rasulullah).\" Dan Nabi shallallahu 'alaihi wasallam mengutus seseorang padaku dan membacakannya kemudian berkata, \"Sesungguhnya Allah telah membenarkanmu.\""},"4220":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا فِي غَزَاةٍ قَالَ سُفْيَانُ مَرَّةً فِي جَيْشٍ فَكَسَعَ رَجُلٌ مِنْ الْمُهَاجِرِينَ رَجُلًا مِنْ الْأَنْصَارِ فَقَالَ الْأَنْصَارِيُّ يَا لَلْأَنْصَارِ وَقَالَ الْمُهَاجِرِيُّ يَا لَلْمُهَاجِرِينَ فَسَمِعَ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُ دَعْوَى الْجَاهِلِيَّةِ قَالُوا يَا رَسُولَ اللَّهِ كَسَعَ رَجُلٌ مِنْ الْمُهَاجِرِينَ رَجُلًا مِنْ الْأَنْصَارِ فَقَالَ دَعُوهَا فَإِنَّهَا مُنْتِنَةٌ فَسَمِعَ بِذَلِكَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ فَقَالَ فَعَلُوهَا أَمَا وَاللَّهِ لَئِنْ رَجَعْنَا إِلَى الْمَدِينَةِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ عُمَرُ فَقَالَ يَا رَسُولَ اللَّهِ دَعْنِي أَضْرِبْ عُنُقَ هَذَا الْمُنَافِقِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُ لَا يَتَحَدَّثُ النَّاسُ أَنَّ مُحَمَّدًا يَقْتُلُ أَصْحَابَهُ وَكَانَتْ الْأَنْصَارُ أَكْثَرَ مِنْ الْمُهَاجِرِينَ حِينَ قَدِمُوا الْمَدِينَةَ ثُمَّ إِنَّ الْمُهَاجِرِينَ كَثُرُوا بَعْدُقَالَ سُفْيَانُ فَحَفِظْتُهُ مِنْ عَمْرٍو قَالَ عَمْرٌو سَمِعْتُ جَابِرًا كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali] Telah menceritakan kepada kami [Sufyan], berkata [Amru]; Aku mendengar [Jabir bin Abdullah radliallahu 'anhuma] berkata; Suatu ketika dalam satu peperangan -sekali waktu Sufyan mengatakan; Dalam suatu perkumpulan pasukan- tiba-tiba seorang laki-laki dari kalangan Anshar mendorong seseorang dari Anshar, maka sang Anshar pun menyeru, \"Wahai orang-orang Anshar.\" Dan sang Muhajir pun berkata, \"Wahai orang-orang Muhajirin.\" Rasulullah shallallahu 'alaihi wasallam pun mendengar hal itu, maka beliau bersabda: \"Kenapa panggilan-panggilan Jahiliyyah itu masih saja kalian lestarikan?\" para sahabat pun berkata, \"Wahai Rasulullah, seorang laki-laki dari kalangan Muhajirin mendorong seorang dari Anshar.\" Akhirnya beliau bersabda: \"Tinggalkanlah, karena hal itu adalah sesuatu yang busuk.\" Abdullah bin Ubbay yang mendengar hal itu berkata, \"Lakukanlah hal itu. Demi Allah, jika kita kembali ke Madinah, niscaya orang-orang mulia akan mengusir orang-orang hina darinya.\" Berita ungkapan itu pun sampai kepada Nabi shallallahu 'alaihi wasallam. Kemudian Umar berdiri, \"Wahai Rasulullah, izinkanlah aku untuk menebas leher seorang munafik ini.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Biarkanlah ia, sehingga orang-orang tidak berkomentar bahwa Muhammad membunuh sahabatnya.\" Ketika itu jumlah orang-orang Anshar lebih banyak dari pada jumlah kaum Muhajirin saat mereka datang. Namun, setelah itu jumlah kaum Muhajirin menjadi lebih banyak. Sufyan berkata: Aku menghafalnya dari Amru. Amru berkata; Aku mendengar Jabir berkata; Suatu ketika, kami berada bersama Nabi shallallahu 'alaihi wasallam."},"4221":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عُقْبَةَ عَنْ مُوسَى بْنِ عُقْبَةَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ الْفَضْلِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُحَزِنْتُ عَلَى مَنْ أُصِيبَ بِالْحَرَّةِ فَكَتَبَ إِلَيَّ زَيْدُ بْنُ أَرْقَمَ وَبَلَغَهُ شِدَّةُ حُزْنِي يَذْكُرُ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اغْفِرْ لِلْأَنْصَارِ وَلِأَبْنَاءِ الْأَنْصَارِوَشَكَّ ابْنُ الْفَضْلِ فِي أَبْنَاءِ أَبْنَاءِ الْأَنْصَارِ فَسَأَلَ أَنَسًا بَعْضُ مَنْ كَانَ عِنْدَهُ فَقَالَ هُوَ الَّذِي يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الَّذِي أَوْفَى اللَّهُ لَهُ بِأُذُنِهِ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] ia berkta, Telah menceritakan kepadaku [Isma'il bin Ibrahim bin Uqbah] dari [Musa bin Uqbah] ia berkata, Telah menceritakan kepadaku [Abdullah bin Al Fadl] bahwa ia mendengar [Anas bin Malik] berkata; Aku merasa sedih terhadap mereka yang terbunuh dalam peristiwa Harrah. Lalu [Zaid bin Arqam] menulis surat kepadaku. Dan berita kesedihanku ternyata telah sampai padanya. Ia menyebutkan bahwa, ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya, Allah, berilah maghfirah bagi orang-orang Anshar dan juga bagi anak-anak kaum Anshar.\" Ibnul Fadl ragu-ragu terkait dengan ungkapan; Anak-anak Anshar. Lalu sebagian orang yang tengah berada di sisi Anas bertanya padanya, maka ia pun menjawab, \"Itulah yang disabdakan oleh Rasulullah shallallahu 'alaihi wasallam. Inilah yang telah disempurnakan Allah melalui pendengarannya.\""},"4222":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ مِنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُكُنَّا فِي غَزَاةٍ فَكَسَعَ رَجُلٌ مِنْ الْمُهَاجِرِينَ رَجُلًا مِنْ الْأَنْصَارِ فَقَالَ الْأَنْصَارِيُّ يَا لَلْأَنْصَارِ وَقَالَ الْمُهَاجِرِيُّ يَا لَلْمُهَاجِرِينَ فَسَمَّعَهَا اللَّهُ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا هَذَا فَقَالُوا كَسَعَ رَجُلٌ مِنْ الْمُهَاجِرِينَ رَجُلًا مِنْ الْأَنْصَارِ فَقَالَ الْأَنْصَارِيُّ يَا لَلْأَنْصَارِ وَقَالَ الْمُهَاجِرِيُّ يَا لَلْمُهَاجِرِينَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعُوهَا فَإِنَّهَا مُنْتِنَةٌ قَالَ جَابِرٌ وَكَانَتْ الْأَنْصَارُ حِينَ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ ثُمَّ كَثُرَ الْمُهَاجِرُونَ بَعْدُ فَقَالَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ أَوَقَدْ فَعَلُوا وَاللَّهِ لَئِنْ رَجَعْنَا إِلَى الْمَدِينَةِ لَيُخْرِجَنَّ الْأَعَزُّ مِنْهَا الْأَذَلَّ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ دَعْنِي يَا رَسُولَ اللَّهِ أَضْرِبْ عُنُقَ هَذَا الْمُنَافِقِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُ لَا يَتَحَدَّثُ النَّاسُ أَنَّ مُحَمَّدًا يَقْتُلُ أَصْحَابَهُ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] ia berkata, Aku menghafalnya dari [Amru bin Dinar] ia berkata; Aku mendengar [Jabir bin Abdullah radliallahu 'anhuma] berkata; Saat kami berada dalam suatu peperangan, tiba-tiba seorang laki-laki dari kaum Muhajirin mendorong seseorang dari kalangan Anshar, maka sang Anshar pun berseru, \"Wahai orang-orang Anshar.\" Dan sang Muhajir pun berseru, \"Wahai orang-orang Muhajirin.\" Maka Allah memperdengarkan ungkapan itu pada Rasul-Nya shallallahu 'alaihi wasallam. Maka beliau pun bersabda: \"Apa-apaan ini?\" para sahabat menjawab, \"Seorang laki-laki dari kaum Muhajirin mendorong seseorang dari kaum Anshar. Sang Anshar berseru, 'Wahai kaum Anshar.' Dan seorang Muhajir itu pun berseru, 'Wahai kaum Muhajirin.'\" Akhirnya Nabi shallallahu 'alaihi wasallam bersabda: \"Tinggalkanlah perbuatan itu, sebab itu adalah kebusukan.\" Jabir berkata; Jumlah kaum Anshar saat Nabi shallallahu 'alaihi wasallam datang lebih banyak, namun setelah itu jumlah kaum Muhajirin menjadi lebih banyak dari jumlah mereka. Kemudian Abdullah bin Ubbay berkata, \"Bukankah mereka telah melakukannya? Demi Allah, jika kita kembali ke Madinah, niscaya orang-orang mulia akan mengusir orang-orang hina darinya.\" Umar bin Al Khaththab radliallahu 'anhu berkata, \"Izinkanlah aku wahai Rasulullah untuk menebas leher orang munafik ini.\" Tetapi Nabi shallallahu 'alaihi wasallam bersabda: \"Biarkanlah ia, agar orang-orang tidak berkomentar bahwa Muhammad membunuh sahabatnya sendiri.\""},"4223":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمٌ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ عُمَرُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَغَيَّظَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ لِيُرَاجِعْهَا ثُمَّ يُمْسِكْهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ فَتَطْهُرَ فَإِنْ بَدَا لَهُ أَنْ يُطَلِّقَهَا فَلْيُطَلِّقْهَا طَاهِرًا قَبْلَ أَنْ يَمَسَّهَا فَتِلْكَ الْعِدَّةُ كَمَا أَمَرَ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] ia berkata, Telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] ia berkata, Telah mengabarkan kepadaku [Salim] bahwa [Abdullah bin Umar radliallahu 'anhuma] Telah mengabarkan kepadanya; Bahawasanya ia pernah mentalak isterinya dalam keadaan haidl. Maka Umar pun menyampaikan hal itu pada Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam marah dan bersabda: \"Hendaklah ia meruju'nya kembali, lalu menahannya hingga ia suci dan haidl hingga ia suci kembali. Bila ia (Ibnu Umar) mau menceraikannya, maka ia boleh mentalaknya dalam keadaan suci sebelum ia menggaulinya. Itulah Al 'Iddah sebagaimana yang telah diperintahkan Allah 'azza wajalla.\""},"4224":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ قَالَ جَاءَ رَجُلٌ إِلَى ابْنِ عَبَّاسٍ وَأَبُو هُرَيْرَةَ جَالِسٌ عِنْدَهُ فَقَالَ أَفْتِنِي فِي امْرَأَةٍ وَلَدَتْ بَعْدَ زَوْجِهَا بِأَرْبَعِينَ لَيْلَةً فَقَالَ ابْنُ عَبَّاسٍ آخِرُ الْأَجَلَيْنِ قُلْتُ أَنَا{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }قَالَ أَبُو هُرَيْرَةَ أَنَا مَعَ ابْنِ أَخِي يَعْنِي أَبَا سَلَمَةَ فَأَرْسَلَ ابْنُ عَبَّاسٍ غُلَامَهُ كُرَيْبًا إِلَى أُمِّ سَلَمَةَ يَسْأَلُهَا فَقَالَتْقُتِلَ زَوْجُ سُبَيْعَةَ الْأَسْلَمِيَّةِ وَهِيَ حُبْلَى فَوَضَعَتْ بَعْدَ مَوْتِهِ بِأَرْبَعِينَ لَيْلَةً فَخُطِبَتْ فَأَنْكَحَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ أَبُو السَّنَابِلِ فِيمَنْ خَطَبَهَاوَقَالَ سُلَيْمَانُ بْنُ حَرْبٍ وَأَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ كُنْتُ فِي حَلْقَةٍ فِيهَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى وَكَانَ أَصْحَابُهُ يُعَظِّمُونَهُ فَذَكَرُوا لَهُ فَذَكَرَ آخِرَ الْأَجَلَيْنِ فَحَدَّثْتُ بِحَدِيثِ سُبَيْعَةَ بِنْتِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ فَضَمَّزَ لِي بَعْضُ أَصْحَابِهِ قَالَ مُحَمَّدٌ فَفَطِنْتُ لَهُ فَقُلْتُ إِنِّي إِذًا لَجَرِيءٌ إِنْ كَذَبْتُ عَلَى عَبْدِ اللَّهِ بْنِ عُتْبَةَ وَهُوَ فِي نَاحِيَةِ الْكُوفَةِ فَاسْتَحْيَا وَقَالَ لَكِنْ عَمُّهُ لَمْ يَقُلْ ذَاكَ فَلَقِيتُ أَبَا عَطِيَّةَ مَالِكَ بْنَ عَامِرٍ فَسَأَلْتُهُ فَذَهَبَ يُحَدِّثُنِي حَدِيثَ سُبَيْعَةَ فَقُلْتُ هَلْ سَمِعْتَ عَنْ عَبْدِ اللَّهِ فِيهَا شَيْئًا فَقَالَ كُنَّا عِنْدَ عَبْدِ اللَّهِ فَقَالَ أَتَجْعَلُونَ عَلَيْهَا التَّغْلِيظَ وَلَا تَجْعَلُونَ عَلَيْهَا الرُّخْصَةَ لَنَزَلَتْ سُورَةُ النِّسَاءِ الْقُصْرَى بَعْدَ الطُّولَى{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] Telah menceritakan kepada kami [Syaiban] dari [Yahya] ia berkata; Telah mengabarkan kepadaku [Abu Salamah] ia berkata; Seorang laki-laki datang kepada Ibnu Abbas sementara Abu Hurairah sedang duduk. Laki-laki itu berkata, \"Berilah fatwa kepadaku, terhadap seorang wanita yang melahirkan setelah kematian suaminya selang empat puluh malam.\" Maka [Ibnu Abbas] berkata, \"Masa Iddahnya adalah batasan yang paling terakhir (maksudnya empat bulan sepuluh hari, meskipun ia melahirkan sebelum itu).\" [Abu Hurairah] berkata; \"Kalau aku, maka aku sependapat dengan anak saudaraku, yakni Abu Salamah.\" Lalu Ibnu Abbas mengutus pembantunya, [Kuraib], kepada [Ummu Salamah] untuk bertanya kepadanya. Ummu Salamah menjawab, \"Ketika suami Subai'ah Al Aslamiyyah meninggal sementara ia dalam keadaan hamil, lalu melahirkan setelah kematian suaminya selang empat puluh malam. Ia kemudian dikhithbah, dan Rasulullah shallallahu 'alaihi wasallam menikahinya. Abu As Sanabil adalah termasuk salah seorang yang mengkhithbahnya. Dan [Sulaiman bin Harb] dan [Abu Nu'man] berkata; Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] ia berkata; Suatu ketika, aku berada dalam halaqah, dan disitu terdapat Abdurrahman bin Abu Laila, sedangkan para sahabatnya mengagungkannya. Mereka mengadukan permasalahan itu, lalu ia menyebutkan bahwa masa iddahnya adalah yang paling terakhir habis (maksudnya empat bulan sepuluh hari, meskipun ia melahirkan sebelum itu). Maka aku pun menceritakan hadits dengan hadits [Subai'ah binti Al Harits] dari [Abdullah bin Utbah]. Akhirnya sebagian sahabatnya mengerutkan dahi padaku. Muhammad berkata; Aku pun mengerti apa maksudnya. Kukatakan, \"Kalau begitu, aku adalah seorang yang nekat, bila aku berdusta atas nama Abdullah bin Utbah. Sekarang ia berada di Kufah. Maka keduanya pun malu dan berkata, \"Akan tetapi pamannya, tidak berkata demikian.\" Kemudian aku menemui [Abu 'Athiyyah Malik bin Amir] dan bertanya padanya, lalu ia pun menceritakan kepadaku hadits [Subai'ah]. Aku bertanya padanya, \"Apakah Anda mendengar sesuatu tentangnya dari Abdullah?\" Ia menjawab, \"Suatu ketika, kami berada di sisi [Abdullah], dan ia pun berkata, 'Apakah kalian akan memberatkan wanita itu, dan kalian tidak memberikan rukhshah untuknya?. Sungguh, surat An Nisa yang pendek itu turun setelah surat Albaqarah yang panjang. 'Bahwa wanita-wanita yang hamil, maka masa iddah mereka adalah ketika mereka melahirkan.'\""},"4225":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ ابْنِ حَكِيمٍ هُوَ يَعْلَى بْنُ حَكِيمٍ الثَّقَفِيُّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَفِي الْحَرَامِ يُكَفَّرُ وَقَالَ ابْنُ عَبَّاسٍ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ إِسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] Telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Ibnu Hakim] ia adalah Ya'laa bin Hakim Ats Tsaqafi, dari [Sa'id bin Jubair] bahwa [Ibnu Abbas radliallahu 'anhuma] berkata tentang seorang suami yang mengatakan kepada isterinya 'Engkau haram bagiku', maka ia harus membayar kaffarat sumpah, namun tidak dihitung menceraikannya.\" Dan Ibnu Abbas juga berkata, \"Sesungguhnya pada diri Rasululah terdapat suri tauladan bagi kalian.\""},"4226":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْرَبُ عَسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَيَمْكُثُ عِنْدَهَا فَوَاطَيْتُ أَنَا وَحَفْصَةُ عَلَى أَيَّتُنَا دَخَلَ عَلَيْهَا فَلْتَقُلْ لَهُ أَكَلْتَ مَغَافِيرَ إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ قَالَ لَا وَلَكِنِّي كُنْتُ أَشْرَبُ ��َسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ فَلَنْ أَعُودَ لَهُ وَقَدْ حَلَفْتُ لَا تُخْبِرِي بِذَلِكَ أَحَدًا","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] dari [Ibnu Juraij] dari [Atha`] dari [Ubaid bin Umair] dari [Aisyah radliallahu 'anha] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah minum madu di kediaman Zainad binti Jahsyin dan bermalam di tempatnya. Lalu aku dan Hafshah pun bersepakat bahwa, siapa saja diantara kita yang ditemui oleh Rasulullah shallallahu 'alaihi wasallam, maka hendaklah ia berkata pada beliau, \"Apakah Anda memakan buah Maghafir? Sungguh, aku mendapatkan bau Maghafir dari Anda.\" Maka beliau berkata, \"Tidak. Akan tetapi aku hanya minum madu di tempat Zainab binti Jahsyin, namun aku tidak akan kembali lagi padanya. Dan aku telah bersumpah, dan kamu jangan menyampaikan hal itu kepada seorang pun.\""},"4227":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى عَنْ عُبَيْدِ بْنِ حُنَيْنٍ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يُحَدِّثُ أَنَّهُ قَالَمَكَثْتُ سَنَةً أُرِيدُ أَنْ أَسْأَلَ عُمَرَ بْنَ الْخَطَّابِ عَنْ آيَةٍ فَمَا أَسْتَطِيعُ أَنْ أَسْأَلَهُ هَيْبَةً لَهُ حَتَّى خَرَجَ حَاجًّا فَخَرَجْتُ مَعَهُ فَلَمَّا رَجَعْنَا وَكُنَّا بِبَعْضِ الطَّرِيقِ عَدَلَ إِلَى الْأَرَاكِ لِحَاجَةٍ لَهُ قَالَ فَوَقَفْتُ لَهُ حَتَّى فَرَغَ ثُمَّ سِرْتُ مَعَهُ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ اللَّتَانِ تَظَاهَرَتَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَزْوَاجِهِ فَقَالَ تِلْكَ حَفْصَةُ وَعَائِشَةُ قَالَ فَقُلْتُ وَاللَّهِ إِنْ كُنْتُ لَأُرِيدُ أَنْ أَسْأَلَكَ عَنْ هَذَا مُنْذُ سَنَةٍ فَمَا أَسْتَطِيعُ هَيْبَةً لَكَ قَالَ فَلَا تَفْعَلْ مَا ظَنَنْتَ أَنَّ عِنْدِي مِنْ عِلْمٍ فَاسْأَلْنِي فَإِنْ كَانَ لِي عِلْمٌ خَبَّرْتُكَ بِهِ قَالَ ثُمَّ قَالَ عُمَرُ وَاللَّهِ إِنْ كُنَّا فِي الْجَاهِلِيَّةِ مَا نَعُدُّ لِلنِّسَاءِ أَمْرًا حَتَّى أَنْزَلَ اللَّهُ فِيهِنَّ مَا أَنْزَلَ وَقَسَمَ لَهُنَّ مَا قَسَمَ قَالَ فَبَيْنَا أَنَا فِي أَمْرٍ أَتَأَمَّرُهُ إِذْ قَالَتْ امْرَأَتِي لَوْ صَنَعْتَ كَذَا وَكَذَا قَالَ فَقُلْتُ لَهَا مَا لَكَ وَلِمَا هَا هُنَا وَفِيمَ تَكَلُّفُكِ فِي أَمْرٍ أُرِيدُهُ فَقَالَتْ لِي عَجَبًا لَكَ يَا ابْنَ الْخَطَّابِ مَا تُرِيدُ أَنْ تُرَاجَعَ أَنْتَ وَإِنَّ ابْنَتَكَ لَتُرَاجِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يَظَلَّ يَوْمَهُ غَضْبَانَ فَقَامَ عُمَرُ فَأَخَذَ رِدَاءَهُ مَكَانَهُ حَتَّى دَخَلَ عَلَى حَفْصَةَ فَقَالَ لَهَا يَا بُنَيَّةُ إِنَّكِ لَتُرَاجِعِينَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يَظَلَّ يَوْمَهُ غَضْبَانَ فَقَالَتْ حَفْصَةُ وَاللَّهِ إِنَّا لَنُرَاجِعُهُ فَقُلْتُ تَعْلَمِينَ أَنِّي أُحَذِّرُكِ عُقُوبَةَ اللَّهِ وَغَضَبَ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بُنَيَّةُ لَا يَغُرَّنَّكِ هَذِهِ الَّتِي أَعْجَبَهَا حُسْنُهَا حُبُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاهَا يُرِيدُ عَائِشَةَ قَالَ ثُمَّ خَرَجْتُ حَتَّى دَخَلْتُ عَلَى أُمِّ سَلَمَةَ لِقَرَابَتِي مِنْهَا فَكَلَّمْتُهَا فَقَالَتْ أُمُّ سَلَمَةَ عَجَبًا لَكَ يَا ابْنَ الْخَطَّابِ دَخَلْتَ فِي كُلِّ شَيْءٍ حَتَّى تَبْتَغِيَ أَنْ تَدْخُلَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَزْوَاجِهِ فَأَخَذَتْنِي وَاللَّهِ أَخْذًا كَسَرَتْنِي عَنْ بَعْضِ مَا كُنْتُ أَجِدُ فَخَرَجْتُ مِنْ عِنْدِهَا وَكَانَ لِي صَاحِبٌ مِنْ الْأَنْصَارِ إِذَا غِبْتُ أَتَانِي بِالْخَبَرِ وَإِذَا غَابَ كُنْتُ أَنَا آتِيهِ بِالْخَبَرِ وَنَحْنُ نَتَخَوَّفُ مَلِكًا مِنْ مُلُوكِ غَسَّانَ ذُكِرَ لَنَا أَنَّهُ يُرِيدُ أَنْ يَسِيرَ إِلَيْنَا فَقَدْ امْتَلَأَتْ صُدُورُنَا مِنْهُ فَإِذَا صَاحِبِي الْأَنْصَارِيُّ يَدُقُّ الْبَابَ فَقَالَ افْتَحْ افْتَحْ فَقُلْتُ جَاءَ الْغَسَّانِيُّ فَقَالَ بَلْ أَشَدُّ مِنْ ذَلِكَ اعْتَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَزْوَاجَهُ فَقُلْتُ رَغَمَ أَنْفُ حَفْصَةَ وَعَائِشَةَ فَأَخَذْتُ ثَوْبِي فَأَخْرُجُ حَتَّى جِئْتُ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَشْرُبَةٍ لَهُ يَرْقَى عَلَيْهَا بِعَجَلَةٍ وَغُلَامٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْوَدُ عَلَى رَأْسِ الدَّرَجَةِ فَقُلْتُ لَهُ قُلْ هَذَا عُمَرُ بْنُ الْخَطَّابِ فَأَذِنَ لِي قَالَ عُمَرُ فَقَصَصْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْحَدِيثَ فَلَمَّا بَلَغْتُ حَدِيثَ أُمِّ سَلَمَةَ تَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّهُ لَعَلَى حَصِيرٍ مَا بَيْنَهُ وَبَيْنَهُ شَيْءٌ وَتَحْتَ رَأْسِهِ وِسَادَةٌ مِنْ أَدَمٍ حَشْوُهَا لِيفٌ وَإِنَّ عِنْدَ رِجْلَيْهِ قَرَظًا مَصْبُوبًا وَعِنْدَ رَأْسِهِ أَهَبٌ مُعَلَّقَةٌ فَرَأَيْتُ أَثَرَ الْحَصِيرِ فِي جَنْبِهِ فَبَكَيْتُ فَقَالَ مَا يُبْكِيكَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ كِسْرَى وَقَيْصَرَ فِيمَا هُمَا فِيهِ وَأَنْتَ رَسُولُ اللَّهِ فَقَالَ أَمَا تَرْضَى أَنْ تَكُونَ لَهُمْ الدُّنْيَا وَلَنَا الْآخِرَةُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] Telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya] dari [Ubaid bin Hunain] bahwa ia mendengar [Ibnu Abbas radliallahu 'anhu] menceritakan, bahwa ia berkata; Aku menahan diri selama satu tahun. Sebenarnya aku ingin bertanya kepada Umar bin Al Khaththab mengenai satu ayat, namun aku tidak bertanya padanya hanya karena perasaan segan. Sampai suatu ketika, ia keluar untuk menunaikan ibadah haji, lalu aku pun keluar bersamanya. Di tengah perjalanan kembali, Umar menyingkir ke arah pepohonan Araq hendak buang hajat, dan aku pun berdiri menungguinya hingga hajatnya selesai. Kemudian aku pun merasa senang dengannya, aku bertanya, \"Wahai Amirul Mukminin, siapakah dua orang wanita dari isteri-isteri Nabi shallallahu 'alaihi wasallam yang saling bantu membantu menyusahkan beliau?\" Maka [Umar] menjawab, \"Keduanya adalah Hafshah dan Aisyah.\" Aku berkata, \"Demi Allah, sesungguhnya sejak setahun yang lalu aku ingin menanyakan hal ini pada, hanya tidak pernah aku lakukan lantaran segan kepada Anda.\" Umar berkata, \"Janganlah kamu melakukan hal itu. Bila kamu menduga bahwa mengetahui tentang sesuatu, maka tanyakanlah. Jika memang aku mengetahuinya, niscaya aku akan mengabarkannya padamu.\" Kemudian Umar berkata, \"Demi Allah, di masa jahiliyah dulu, kami tidak pernah mempertimbangkan ide atau saran yang berasal dari kaum wanita, sehingga Allah menurunkan ayat berkenaan dengan hak mereka, dan Dia membagi hak yang dibagikan-Nya.\" Umar melanjutkan, \"Maka ketika menghadapi suatu persoalan yang hendak aku pertimbangkan, tiba-tiba isteriku berkata, 'Seandainya Anda berbuat seperti ini dan itu! ' Maka kukatakan padanya, 'Ada apa denganmu, kenapa turut campur, dan untuk apa campur tanganmu dalam persoalan yang aku inginkan? ' Isteriku menjawab, 'Sungguh Engkau sangat aneh wahai Ibnul Khathathab! Apakah Anda tidak mau diajak berdiskusi padahal anak wanitamu sendiri mengajak diskusi bersama Rasulullah shallallahu 'alaihi wasallam hingga beliau melewati hari-harinya dengan perasan marah? '\" Akhirnya Umar bergegas mengambil pakaiannya dan segera menemui Hafshah dan berkata padanya, \"Wahai anakku, sesungguhnya kamu mengajak diskusi bersama Rasulullah shallallahu 'alaihi wasallam hingga beliau melewati hari-harinya dengan perasaan marah.\" Hafshah berkata, \"Demi Allah, kami benar-benar akan mengajak diskusi bersama beliau.\" Aku katakan padanya, \"Ketahuilah, aku peringatkan padamu akan siksaan Allah dan juga amarah Rasul-Nya shallallahu 'alaihi wasallam wahai anakku. Jangan sekali-kali engkau merasa rugi, karena kecintaan Rasulullah shallallahu 'alaihi wasallam padanya.\" Maksudnya adalah kecintaan beliau pada Aisyah. Umar melanjutkan kisahnya; Kemudian aku keluar hingga aku menemui Ummu Salamah karena dekatnya hubungan kerabatku dengannya, lalu aku membicarakannya padanya. Ummu Salamah berkata, \"Sungguh aneh Anda ini wahai Ibnul Khaththab. Kamu telah memasuki semua urusan. Hingga kamu hendak memasuki urusan yang terjadi antara Rasulullah shallallahu 'alaihi wasallam dengan para isteri-isterinya.\" Ummu Salamah membantahku, dengan sebuah bantahan yang telah menghilangkan apa yang menjadi keinginanku sebelumnya. Maka aku pun segera keluar dari kediamannya. Waktu itu, aku memiliki seorang sahabat dari kalangan Anshar, jika aku tidak hadir (dalam majelis Rasulullah) maka ia akan menyampaikan berita yang ada. Dan jika ia yang absen, maka akulah yang menyampaikan berita baru padanya. Saat itu, kami takut terhadap seorang raja dari raja-raja Ghassan. Telah tersebar berita, bahwa ia akan berjalan ke arah kami berada. Sementara bayang-bayangnya telah memenuhi dada-dada kami. Ternyata, salah seorang sahabatku yang Anshar itu mengetuk pintu, seraya berkata, \"Bukalah pintu, bukalah pintu.\" Aku bertanya, \"Apakah raja Al Ghassani telah datang?\" Ia menjawab, \"Bahkan yang lebih dahsyat daripada itu. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah menceraikan isteri-isterinya terlebih lagi Hafshah dan Aisyah\" Maka aku segera mengambil pakaianku dan keluar hingga bertemu dengan Rasulullah shallallahu 'alaihi wasallam di tempat minum miliknya, yang jika beliau menaikinya maka beliau pergunakan tangga. Sementara pembantu Rasulullah shallallahu 'alaihi wasallam Aswad berada di tangga. Maka aku katakan kepadanya, \"Katakanlah pada beliau bahwa ini Umar bin Al Khaththab.\" Kemudian beliau pun mengizinkanku. Lalu aku menuturkan kisah kejadian ini pada beliau. Ketika kisahnya sampai pada kejadian bersama Ummu Salamah, Rasulullah shallallahu 'alaihi wasallam pun tersenyum. Saat itu beliau berada di atas tikar yang tidak dilapisi sesuatu apa pun. Di bawah kepalanya hanya terdapat bantal yang terbuat dari kulit yang berisikan sabut. Pada kedua kakinya terdapat dedaunan yang dituangkan, sementara di kepalanya terdapat kulit yang telah disamak. Aku melihat bekas tikar itu di sebelah kiri badannya, dan aku pun menangis. Beliau bertanya, \"Apa yang menyebabkanmu menangis?\" Aku menjawab, \"Wahai Rasulullah, sesungguhnya Kisra dan Kaisar keduanya berada dalam kesenangan, sementara Anda wahai Rasulullah..\" akhirnya beliau bersabda: \"Tidakkah kamu ridla apabila dunia ini menjadi milik mereka, sedangkan akhirat untuk kita?\""},"4228":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْتُ عُبَيْدَ بْنَ حُنَيْنٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَرَدْتُ أَنْ أَسْأَلَ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ اللَّتَانِ تَظَاهَرَتَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا أَتْمَمْتُ كَلَامِي حَتَّى قَالَ عَائِشَةُ وَحَفْصَةُ","id":"Telah menceritakan kepada kami [Ali] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Yahya bin Sa'id] ia berkata; Aku mendengar [Ubaid bin Hunain] berkata; Aku mendengar [Ibnu Abbas radliallahu 'anhuma] berkata; Aku ingin bertanya kepada [Umar bin Al Khaththab] radliallahu 'anhu. Aku pun berkata, \"Wahai Amirul Mukminin, siapakah dua wanita yang bantu-membantu untuk menyusahkan Rasulullah shallallahu 'alaihi wasallam?\" belum selesai aku bertanya beliu sudah lebih dulu menjawab, \"Yaitu Aisyah dan Hafshah.\""},"4229":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ سَمِعْتُ عُبَيْدَ بْنَ حُنَيْنٍ يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُكُنْتُ أُرِيدُ أَنْ أَسْأَلَ عُمَرَ عَنْ الْمَرْأَتَيْنِ اللَّتَيْنِ تَظَاهَرَتَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَكَثْتُ سَنَةً فَلَمْ أَجِدْ لَهُ مَوْضِعًا حَتَّى خَرَجْتُ مَعَهُ حَاجًّا فَلَمَّا كُنَّا بِظَهْرَانَ ذَهَبَ عُمَرُ لِحَاجَتِهِ فَقَالَ أَدْرِكْنِي بِالْوَضُوءِ فَأَدْرَكْتُهُ بِالْإِدَاوَةِ فَجَعَلْتُ أَسْكُبُ عَلَيْهِ الْمَاءَ وَرَأَيْتُ مَوْضِعًا فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ اللَّتَانِ تَظَاهَرَتَا قَالَ ابْنُ عَبَّاسٍ فَمَا أَتْمَمْتُ كَلَامِي حَتَّى قَالَ عَائِشَةُ وَحَفْصَةُ","id":"Telah menceritakan kepada kami [Al Humaid] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Yahya bin Sa'id] ia berkata; Aku mendengar [Ubaid bin Hunain] berkata, Aku mendengar [Ibnu Abbas] berkata; Aku ingin bertanya kepada [Umar bin Al Khaththab] mengenai dua wanita yang bantu-membantu untuk menyusahkan Rasulullah shallallahu 'alaihi wasallam. Dan aku pun menahan keinginan itu selama satu tahun, namun aku belum juga mendapat kesempatan yang pas untuk menanyakannya. Hingga pada suatu hari aku keluar bersamanya untuk menunaikan ibadah haji. Ketika kami berada di Zhahran, Umar pergi untuk buang hajat, lalu ia berkata, \"Bawakanlah aku air untuk berwudlu.\" Maka aku pun membawakan untuknya, lalu menuangkan air wudlu untuktunya. Pada saat itulah, aku melihatnya sebagai saat yang tepat untuk bertanya. Maka apu pun bertanya, \"Wahai Amirul Mukminin, siapakah dua orang wanita yang pernah bantu membantu untuk menyusahkan Rasulullah shallallahu 'alaihi wasallam?\" Ibnu Abbas berkata; Aku belum selesai bertanya, tetapi ia telah lebih dahulu menjawab, \"Yaitu Aisyah dan Hafshah.\""},"4230":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُاجْتَمَعَ نِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغَيْرَةِ عَلَيْهِ فَقُلْتُ لَهُنَّ{ عَسَى رَبُّهُ إِنْ طَلَّقَكُنَّ أَنْ يُبَدِّلَهُ أَزْوَاجًا خَيْرًا مِنْكُنَّ }فَنَزَلَتْ هَذِهِ الْآيَةُ","id":"Telah menceritakan kepada kami [Amru bin Aun] Telah menceritakan kepada kami [Husyaim] dari [Humaid] dari [Anas] ia berkata, [Umar radliallahu 'anhu] berkata; Para isteri-isteri Nabi shallallahu 'alaihi wasallam berkumpul untuk membuat sesuatu sebagai bentuk rasa kecemburuan mereka terhadap beliau. Maka aku pun berkata pada mereka, \"Bila saja Rabb-nya -jika beliau menceraikan kalian- mudah-mudahan Ia menggantikan untuknya isteri-isteri yang lebih baik dari kalian.\" Maka turunlah ayat ini."},"4231":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي حَصِينٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ عُتُلٍّ بَعْدَ ذَلِكَ زَنِيمٍ }قَالَ رَجُلٌ مِنْ قُرَيْشٍ لَهُ زَنَمَةٌ مِثْلُ زَنَمَةِ الشَّاةِ","id":"Telah menceritakan kepada kami [Mahmud] Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra'il] dari [Abu Hashin] dari [Mujahid] dari [Ibnu Abbas radliallahu 'anhuma]: \"'UTULLIM BA'DA DZAALIKA ZANIIM.\" Ia berkata, \"Yaitu seorang laki-laki Quraisy yang memiliki telinga terpotong seperti telinga kambing yang terpotong.\""},"4232":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ الْخُزَاعِيَّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا أُخْبِرُكُمْ بِأَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَعِّفٍ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ كُلُّ عُتُلٍّ جَوَّاظٍ مُسْتَكْبِرٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ma'bad bin Khalid] ia berkata, Aku mendengar [Haritsah bin Wahb Al Khuza'i] ia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Maukah kalian aku beritahukan mengenai penghuni surga? Yaitu setiap orang lemah dan ditindas, yang sekiranya ia bersumpah atas nama Allah, niscaya Allah mengabulkannya. Dan maukah kalian aku beritahukan mengenai penghuni neraka? Yaitu setiap yang beringas membela kebatilan, kasar lagi sombong.\""},"4233":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكْشِفُ رَبُّنَا عَنْ سَاقِهِ فَيَسْجُدُ لَهُ كُلُّ مُؤْمِنٍ وَمُؤْمِنَةٍ فَيَبْقَى كُلُّ مَنْ كَانَ يَسْجُدُ فِي الدُّنْيَا رِيَاءً وَسُمْعَةً فَيَذْهَبُ لِيَسْجُدَ فَيَعُودُ ظَهْرُهُ طَبَقًا وَاحِدًا","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Al Laits] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abu Sa'id radliallahu 'anhu] ia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Rabb kita menampakkan betisnya, maka sujudlah setiap orang mukmin dan mukminah, sehingga yang tersisa hanyalah orang-orang yang ketika di dunia ia sujud karena riya` dan sum'ah. Mereka mencoba untuk sujud, namun punggung mereka kembali tegak.\""},"4234":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ وَقَالَ عَطَاءٌ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاصَارَتْ الْأَوْثَانُ الَّتِي كَانَتْ فِي قَوْمِ نُوحٍ فِي الْعَرَبِ بَعْدُ أَمَّا وَدٌّ كَانَتْ لِكَلْبٍ بِدَوْمَةِ الْجَنْدَلِ وَأَمَّا سُوَاعٌ كَانَتْ لِهُذَيْلٍ وَأَمَّا يَغُوثُ فَكَانَتْ لِمُرَادٍ ثُمَّ لِبَنِي غُطَيْفٍ بِالْجَوْفِ عِنْدَ سَبَإٍ وَأَمَّا يَعُوقُ فَكَانَتْ لِهَمْدَانَ وَأَمَّا نَسْرٌ فَكَانَتْ لِحِمْيَرَ لِآلِ ذِي الْكَلَاعِ أَسْمَاءُ رِجَالٍ صَالِحِينَ مِنْ قَوْمِ نُوحٍ فَلَمَّا هَلَكُوا أَوْحَى الشَّيْطَانُ إِلَى قَوْمِهِمْ أَنْ انْصِبُوا إِلَى مَجَالِسِهِمْ الَّتِي كَانُوا يَجْلِسُونَ أَنْصَابًا وَسَمُّوهَا بِأَسْمَائِهِمْ فَفَعَلُوا فَلَمْ تُعْبَدْ حَتَّى إِذَا هَلَكَ أُولَئِكَ وَتَنَسَّخَ الْعِلْمُ عُبِدَتْ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hasyim] dari [Ibnu Juraij] dan [Atha`] berkata; dari [Ibnu Abbas radliallahu 'anhuma] bahwanya; Berhala-berhala yang dahulu di agungkan oleh kaum Nabi Nuh, di kemudian hari tersebar di bangsa 'Arab. Wadd menjadi berhala untuk kamu Kalb di Daumah Al Jandal. Suwa' untuk Bani Hudzail. Yaquts untuk Murad dan Bani Ghuthaif di Jauf tepatnya di Saba`. Adapun Ya'uq adalah untuk Bani Hamdan. Sedangkan Nashr untuk Himyar keluarga Dzul Kala'. Itulah nama-nama orang Shalih dari kaum Nabi Nuh. Ketika mereka wafat, syetan membisikkan kepada kaum mereka untuk mendirikan berhala pada majelis mereka dan menamakannya dengan nama-nama mereka. Maka mereka pun melakukan hal itu, dan saat itu berhala-berhala itu belum disembah hingga mereka wafat, sesudah itu, setelah ilmu tiada, maka berhala-berhala itu pun disembah.\""},"4235":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَانْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَائِفَةٍ مِنْ أَصْحَابِهِ عَامِدِينَ إِلَى سُوقِ عُكَاظٍ وَقَدْ حِيلَ بَيْنَ الشَّيَاطِينِ وَبَيْنَ خَبَرِ السَّمَاءِ وَأُرْسِلَتْ عَلَيْهِمْ الشُّهُبُ فَرَجَعَتْ الشَّيَاطِينُ فَقَالُوا مَا لَكُمْ فَقَالُوا حِيلَ بَيْنَنَا وَبَيْنَ خَبَرِ السَّمَاءِ وَأُرْسِلَتْ عَلَيْنَا الشُّهُبُ قَالَ مَا حَالَ بَيْنَكُمْ وَبَيْنَ خَبَرِ السَّمَاءِ إِلَّا مَا حَدَثَ فَاضْرِبُوا مَشَارِقَ الْأَرْضِ وَمَغَارِبَهَا فَانْظُرُوا مَا هَذَا الْأَمْرُ الَّذِي حَدَثَ فَانْطَلَقُوا فَضَرَبُوا مَشَارِقَ الْأَرْضِ وَمَغَارِبَهَا يَنْظُرُونَ مَا هَذَا الْأَمْرُ الَّذِي حَالَ بَيْنَهُمْ وَبَيْنَ خَبَرِ السَّمَاءِ قَالَ فَانْطَلَقَ الَّذِينَ تَوَجَّهُوا نَحْوَ تِهَامَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَخْلَةَ وَهُوَ عَامِدٌ إِلَى سُوقِ عُكَاظٍ وَهُوَ يُصَلِّي بِأَصْحَابِهِ صَلَاةَ الْفَجْرِ فَلَمَّا سَمِعُوا الْقُرْآنَ تَسَمَّعُوا لَهُ فَقَالُوا هَذَا الَّذِي حَالَ بَيْنَكُمْ وَبَيْنَ خَبَرِ السَّمَاءِ فَهُنَالِكَ رَجَعُوا إِلَى قَوْمِهِمْ فَقَالُوا يَا قَوْمَنَا{ إِنَّا سَمِعْنَا قُرْآنًا عَجَبًا يَهْدِي إِلَى الرُّشْدِ فَآمَنَّا بِهِ وَلَنْ نُشْرِكَ بِرَبِّنَا أَحَدًا }وَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ قُلْ أُوحِيَ إِلَيَّ أَنَّهُ اسْتَمَعَ نَفَرٌ مِنْ الْجِنِّ }وَإِنَّمَا أُوحِيَ إِلَيْهِ قَوْلُ الْجِنِّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Abu Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah keluar bersama sekelompok orang dari sahabatnya menuju Pasar 'Ukazh. Sedangkan para setan telah dihalangi untuk mencuri berita langit. Bahkan, mereka dilempari dengan bintang (meteor) dan mereka pun kembali. Maka mereka (sahabat setan) pun bertanya, \"Ada apa dengan kalian?\" Mereka menjawab, \"Kami telah dihalangi untuk mencuri berita langit. Dan kami juga dilempari dengan bintang (meteor).\" Mereka berkata, \"Tidaklah kalian dihalangi untuk mencuri berita langit kecuali karena suatu kejadian. Karena itu, cermatilah ke seluruh penjuru bumi dari barat dan timur, lihatlah peristiwa apa yang sebenarnya telah terjadi.\" Akhirnya mereka pun pergi menelusuri penjuru bumi, barat dan timur guna melihat peristiwa apa yang telah terjadi sehingga menghalangi antara mereka dan berita langit. Mereka berjalan ke arah Tihamah menuju Rasulullah shallallahu 'alaihi wasallam yang sedang berada pada sebatang pohon kurma hendak menuju ke pasar 'Ukazh. Saat itu, beliau sedang shalat Fajar (Shalat subuh) bersama para sahabatnya. Maka ketika para setan mendengar Al Qur`an, mereka pun menyimaknya dan berkata, \"Inilah yang menghalangi antara kalian dan berita langit.\" Akhirnya mereka kembali kepada kaumnya dan berkata, \"Wahai kamu kami (Sesungguhnya kami telah mendengar Al Qur'an yang begitu menakjubkan, yang memberi petunjuk kepada jalan yang benar, hingga kami pun beriman kepadanya dan kami tidak akan menyekutukan Rabb kami dengan sesuatu apa pun).\" (QS. Aljin 1-2). Dan Allah 'azza wajalla pun menurunkan wahyu kepada Nabi-Nya shallallahu 'alaihi wasallam, \"Katakanlah: 'Telah diwahyukan kepadaku, bahwasanya sekelompok jin telah mendengarkan (Al Qur`an).'\" (QS. Aljin 1). Yang diwahyukan kepada beliau adalah perkataan Jin."},"4236":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ سَأَلْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِعَنْ أَوَّلِ مَا نَزَلَ مِنْ الْقُرْآنِ قَالَ{ يَا أَيُّهَا الْمُدَّثِّرُ }قُلْتُ يَقُولُونَ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ }فَقَالَ أَبُو سَلَمَةَ سَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا عَنْ ذَلِكَ وَقُلْتُ لَهُ مِثْلَ الَّذِي قُلْتَ فَقَالَ جَابِرٌ لَا أُحَدِّثُكَ إِلَّا مَا حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَاوَرْتُ بِحِرَاءٍ فَلَمَّا قَضَيْتُ جِوَارِي هَبَطْتُ فَنُودِيتُ فَنَظَرْتُ عَنْ يَمِينِي فَلَمْ أَرَ شَيْئًا وَنَظَرْتُ عَنْ شِمَالِي فَلَمْ أَرَ شَيْئًا وَنَظَرْتُ أَمَامِي فَلَمْ أَرَ شَيْئًا وَنَظَرْتُ خَلْفِي فَلَمْ أَرَ شَيْئًا فَرَفَعْتُ رَأْسِي فَرَأَيْتُ شَيْئًا فَأَتَيْتُ خَدِيجَةَ فَقُلْتُ دَثِّرُونِي وَصُبُّوا عَلَيَّ مَاءً بَارِدًا قَالَ فَدَثَّرُونِي وَصَبُّوا عَلَيَّ مَاءً بَارِدًا قَالَ فَنَزَلَتْ{ يَا أَيُّهَا الْمُدَّثِّرُ قُمْ فَأَنْذِرْ وَرَبَّكَ فَكَبِّرْ }","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] aku bertanya kepada [Abu Salamah bin Abdurrahman] mengenai ayat Al Qur`an yang pertama kali turun, maka ia pun menjawab, \"YAA `AYYUHAL MUDDATSTSIR.\" Aku berkata, \"Orang-orang mengatakan bahwa yang pertama kali turun adalah: 'IQRA`BISMI RABBIKALLADZII KHALAQ.'\" Maka Abu Salamah berkata; Aku pernah menanyakan hal itu pada [Jabir bin Abdullah] radliallahu 'anhuma. Dan aku juga mengatakan seperti apa kamu katakan. Namun Jabir berkata; Aku tidak akan menceritakan kepadamu, kecuali dengan sesuatu yang telah diceritakan oleh Rasulullah shallallahu 'alaihi wasallam. Beliau bersabda: \"Aku berdiam diri di gua Hira` Setelah selesai, aku pun beranjak keluar dan tiba-tiba aku mendengar seseorang memanggilku, maka aku pun menoleh ke sebelah kananku, namun aku tidak melihat siapa-siapa, ke sebelah kiri, juga aku tidak melihat seseorang, kuarahkan pandanganku ke depan juga tidak ada seorang pun yang terlihat, akhirnya aku menoleh ke belakang, aku juga tidak melihat siapa-siapa. Lalu aku mengangkat kepalaku, dan ternyata aku melihat sesuatu di atas langit. Setelah itu, aku segera mendatangi Khadijah dan berkata, 'Selimutilah aku. Dan tuangkanlah air dingin pada tubuhku.' Pada saat itulah, diturunkanlah ayat ini padaku: 'YAA `AYYUHAL MUDDATSTSIR, QUM FA`ANDZIR, WA RABBAKA FAKABBIR (Wahai orang yang berselimut, bangunlah dan berilah peringatakan. Dan Tuhan-mu, agungkanlah).'\""},"4237":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَغَيْرُهُ قَالَا حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَاوَرْتُ بِحِرَاءٍمِثْلَ حَدِيثِ عُثْمَانَ بْنِ عُمَرَ عَنْ عَلِيِّ بْنِ الْمُبَارَكِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan selainnya, keduanya berkata, Telah menceritakan kepada kami [Harb bin Syaddad] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir bin Abdullah radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku berdiam diri di gua Hira`..\" Yakni sama persis dengan hadits [Utsman bin Umar] dari [Ali bin Al Mubarak]."},"4238":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَرْبٌ حَدَّثَنَا يَحْيَى قَالَ سَأَلْتُ أَبَا سَلَمَةَأَيُّ الْقُرْآنِ أُنْزِلَ أَوَّلُ فَقَالَ{ يَا أَيُّهَا الْمُدَّثِّرُ }فَقُلْتُ أُنْبِئْتُ أَنَّهُ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ }فَقَالَ أَبُو سَلَمَةَ سَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ أَيُّ الْقُرْآنِ أُنْزِلَ أَوَّلُ فَقَالَ{ يَا أَيُّهَا الْمُدَّثِّرُ }فَقُلْتُ أُنْبِئْتُ أَنَّهُ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ }فَقَالَ لَا أُخْبِرُكَ إِلَّا بِمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاوَرْتُ فِي حِرَاءٍ فَلَمَّا قَضَيْتُ جِوَارِي هَبَطْتُ فَاسْتَبْطَنْتُ الْوَادِيَ فَنُودِيتُ فَنَظَرْتُ أَمَامِي وَخَلْفِي وَعَنْ يَمِينِي وَعَنْ شِمَالِي فَإِذَا هُوَ جَالِسٌ عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالْأَرْضِ فَأَتَيْتُ خَدِيجَةَ فَقُلْتُ دَثِّرُونِي وَصُبُّوا عَلَيَّ مَاءً بَارِدًا وَأُنْزِلَ عَلَيَّ{ يَا أَيُّهَا الْمُدَّثِّرُ قُمْ فَأَنْذِرْ وَرَبَّكَ فَكَبِّرْ }","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [Harb] Telah menceritakan kepada kami [Yahya] ia berkata; Aku pernah bertanya kepada [Abu Salamah], \"Bagian manakah dari Al Qur`an yang pertama kali turun?\" Ia pun menjawab, \"YAA AYYUHAL MUDDATSTSIR.\" Aku berkata, \"Aku pernah dikabarkan bahwa bagian Al Qur`an yang pertama kali turun adalah: 'IQRA` BISMI RABIKALLADZII KHALAQ (Sebutlah dengan nama Tuhanmu yang telah menciptakan).'\" Maka Abu Salamah pun berkata; Aku pernah bertanya kepada [Jabir bin Abdullah], \"Bagian Al Qur`an yang manakah yang pertama kali turun?\" Maka ia menjawab, \"YA `AYYUHAL MUDDATSTSIR.\" Kukatakan, \"Pernah diberitakan kepadaku, bahwa yang pertama kali turun adalah, 'IQRA` BISMI RABIKALLADZII KHALAQ.'\" Maka ia menjelaskan kembali; Aku tidak akan mengabarkan kepadamu kecuali dengan sesuatu yang telah dikatakan oleh Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berdiam diri di gua Hira`. Setelah selesai, aku pun beranjak keluar dan menelusuri lembah, tiba-tiba aku mendengar seseorang memanggilku, maka aku pun menoleh ke depan, ke arah belakang, ke samping kanan dan juga ke kiri. Ternyata, yang memanggilku duduk di atas kursi yang terbentang antara langit dan bumi. Setelah itu, aku segera mendatangi Khadijah dan berkata, 'Selimutilah aku. Dan tuangkanlah air dingin pada tubuhku.' Pada saat itulah, diturunkanlah ayat ini padaku: 'YAA `AYYUHAL MUDDATSTSIR, QUM FA`ANDZIR, WA RABBAKA FAKABBIR (Wahai orang yang berselimut, bangunlah dan berilah peringatakan. Dan Tuhan-mu, agungkanlah).'\""},"4239":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ الزُّهْرِيُّ فَأَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُحَدِّثُ عَنْ فَتْرَةِ الْوَحْيِ فَقَالَ فِي حَدِيثِهِ فَبَيْنَا أَنَا أَمْشِي إِذْ سَمِعْتُ صَوْتًا مِنْ السَّمَاءِ فَرَفَعْتُ رَأْسِي فَإِذَا الْمَلَكُ الَّذِي جَاءَنِي بِحِرَاءٍ جَالِسٌ عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالْأَرْضِ فَجَئِثْتُ مِنْهُ رُعْبًا فَرَجَعْتُ فَقُلْتُ زَمِّلُونِي زَمِّلُونِي فَدَثَّرُونِي فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الْمُدَّثِّرُ إِلَى وَالرِّجْزَ فَاهْجُرْ }قَبْلَ أَنْ تُفْرَضَ الصَّلَاةُ وَهِيَ الْأَوْثَانُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] -dalam riwayat lain- Dan Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Abdurrazzaq] Telah mengabarkan kepada kami [Ma'mar] bahwa [Az Zuhri] berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dari [Jabir bin Abdullah radliallahu 'anhuma] ia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda menceritakan peristiwa Fatratul Wahyu (Masa-masa kevakuman wahyu): \"Ketika aku tengah berjalan, tiba-tiba aku mendengar suara yang berasal dari langit, maka aku pun mengangkat pandanganku ke arah langit, ternyata di atas terdapat Malaikat yang sebelumnya mendatangiku di gua Hira` tengah duduk di atas kursi antara langit dan bumi. Aku merasa ketakutan hingga aku jatuh tersungkur ke tanah. Lalu aku pun segera menemui keluargaku seraya berkata, 'Selimutilah aku, selimutilah aku.' Maka keluargaku pun segera menyelimutiku. Akhirnya Allah Ta'ala menurunkan ayat: 'YAA AYYUHAL MUDDATSTSIR QUM FA`ANDZIR (Wahai orang yang berselimut, bangkitlah, dan berilah peringatan).'\" Hingga firman-Nya: \"WAR RIJZA FAHJUR (Dan berhala-berhala itu, maka tinggalkanlah).\" Yakni sebelum perintah shalat diwajibkan. Ar Rijz adalah berhala."},"4240":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ قَالَ ابْنُ شِهَابٍ سَمِعْتُ أَبَا سَلَمَةَ قَالَ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُ عَنْ فَتْرَةِ الْوَحْيِ فَبَيْنَا أَنَا أَمْشِي سَمِعْتُ صَوْتًا مِنْ السَّمَاءِ فَرَفَعْتُ بَصَر��ي قِبَلَ السَّمَاءِ فَإِذَا الْمَلَكُ الَّذِي جَاءَنِي بِحِرَاءٍ قَاعِدٌ عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالْأَرْضِ فَجَئِثْتُ مِنْهُ حَتَّى هَوَيْتُ إِلَى الْأَرْضِ فَجِئْتُ أَهْلِي فَقُلْتُ زَمِّلُونِي زَمِّلُونِي فَزَمَّلُونِي فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الْمُدَّثِّرُ قُمْ فَأَنْذِرْ إِلَى قَوْلِهِ فَاهْجُرْ }قَالَ أَبُو سَلَمَةَ وَالرِّجْزَ الْأَوْثَانَ ثُمَّ حَمِيَ الْوَحْيُ وَتَتَابَعَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dan [Ibnu Syihab] berkata; Aku mendengar [Abu Salamah] berkata; Telah mengabarkan kepadaku [Jabir bin Abdullah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam menceritakan tentang awalnya wahyu turun pada beliau. Beliau berkisah: \"Ketika aku tengah berjalan, tiba-tiba aku mendengar suara yang berasal dari langit, maka aku pun mengangkat pandanganku ke arah langit, ternyata di atas terdapat Malaikat yang sebelumnya mendatangiku di gua Hira` tengah duduk di atas kursi antara langit dan bumi. Aku merasa ketakutan hingga aku jatuh tersungkur ke tanah. Lalu aku pun segera menemui keluargaku seraya berkata, 'Selimutilah aku, selimutilah aku.' Maka keluargaku pun segera menyelimutiku. Akhirnya Allah Ta'ala menurunkan ayat: 'YAA AYYUHAL MUDDATSTSIR QUM FA`ANDZIR (Wahai orang yang berselimut, bangkitlah, dan berilah peringatan).'\" Hingga firman-Nya: \"FAHJUR.\" Abu Salamah berkata; Ar Rijz artinya adalah berhala-berhala. Setelah itu, turunlah wahyu secara berturut-turut."},"4241":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مُوسَى بْنُ أَبِي عَائِشَةَ وَكَانَ ثِقَةً عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَزَلَ عَلَيْهِ الْوَحْيُ حَرَّكَ بِهِ لِسَانَهُ وَوَصَفَ سُفْيَانُ يُرِيدُ أَنْ يَحْفَظَهُ فَأَنْزَلَ اللَّهُ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ }","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Musa bin Abu Aisyah] -ia adalah seorang yang Tsiqqah- dari [Sa'id bin Jubair] dari [Ibnu Abbas radliallahu 'anhuma] ia berkata; Apabila turun wahyu, biasanya Nabi shallallahu 'alaihi wasallam menggerak-gerakkan lisannya. Sufyan menafsirkannya; Bahwa maksud beliau menggerak-gerakkan bibirnya adalah untuk menghafalnya. Maka Allah menurunkan firman-Nya, \"LAA TUHARRIK BIHI LISAANAKA LITA'JALA BIHI (Janganlah kamu menggerak-gerakkkan lisanmu untuk segera menyudahinya).\""},"4242":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ أَنَّهُ سَأَلَ سَعِيدَ بْنَ جُبَيْرٍعَنْ قَوْلِهِ تَعَالَى{ لَا تُحَرِّكْ بِهِ لِسَانَكَ }قَالَ وَقَالَ ابْنُ عَبَّاسٍ كَانَ يُحَرِّكُ شَفَتَيْهِ إِذَا أُنْزِلَ عَلَيْهِ فَقِيلَ لَهُ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ }يَخْشَى أَنْ يَنْفَلِتَ مِنْهُ{ إِنَّ عَلَيْنَا جَمْعَهُ وَقُرْآنَهُ }أَنْ نَجْمَعَهُ فِي صَدْرِكَ وَقُرْآنَهُ أَنْ تَقْرَأَهُ{ فَإِذَا قَرَأْنَاهُ }يَقُولُ أُنْزِلَ عَلَيْهِ{ فَاتَّبِعْ قُرْآنَهُ ثُمَّ إِنَّ عَلَيْنَا بَيَانَهُ }أَنْ نُبَيِّنَهُ عَلَى لِسَانِكَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Musa bin Abu Aisyah] bahwa ia pernah bertanya kepada [Sa'id bin Jubair] mengenai firman Allah: \"LAA TUHARRIK BIHI LISAANAK.\" Ia menjawab; [Ibnu Abbas] berkata; Biasa beliau menggerak-gerakkan kedua bibirnya saat wahyu diturunkan padanya. Oleh karena itu, dikatakanlah pada beliau, \"Janganlah kamu menggerak-gerakkan lisanmu -saat menerimanya- karena khawatir sesuatu akan terlewatkan darinya.\" Firman Allah: \"INNA 'ALAINA JAM'AHU WA QUR`AANAH.\" Maksudnya adalah, Kamilah yang akan mengumpulkannya di dalam dadamu agar kamu bisa mengungkapkannya. Dan firman-Nya: \"FAIDZAA QARA`NAAHU FATTABI' QUR`AANAH.\" Ibnu Abbas menjelaskan; Maksudnya adalah ketika diturunkan padanya. Maka, ikutilah. Kemudian firman-Nya: \"INNA 'ALAINAA BAYAANAH.\" Maksudnya; Kamilah yang akan menjelaskannya melalui lisanmu."},"4243":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ }قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَزَلَ جِبْرِيلُ بِالْوَحْيِ وَكَانَ مِمَّا يُحَرِّكُ بِهِ لِسَانَهُ وَشَفَتَيْهِ فَيَشْتَدُّ عَلَيْهِ وَكَانَ يُعْرَفُ مِنْهُ فَأَنْزَلَ اللَّهُ الْآيَةَ الَّتِي فِي لَا أُقْسِمُ بِيَوْمِ الْقِيَامَةِ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ إِنَّ عَلَيْنَا جَمْعَهُ وَقُرْآنَهُ }قَالَ عَلَيْنَا أَنْ نَجْمَعَهُ فِي صَدْرِكَ وَقُرْآنَهُ{ فَإِذَا قَرَأْنَاهُ فَاتَّبِعْ قُرْآنَهُ }فَإِذَا أَنْزَلْنَاهُ فَاسْتَمِعْ{ ثُمَّ إِنَّ عَلَيْنَا بَيَانَهُ }عَلَيْنَا أَنْ نُبَيِّنَهُ بِلِسَانِكَ قَالَ فَكَانَ إِذَا أَتَاهُ جِبْرِيلُ أَطْرَقَ فَإِذَا ذَهَبَ قَرَأَهُ كَمَا وَعَدَهُ اللَّهُ عَزَّ وَجَلَّ{ أَوْلَى لَكَ فَأَوْلَى }تَوَعُّدٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Musa bin Abu Aisyah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] terkait dengan firman Allah: \"LAA TUHARRIK LISAANAKA LITA'JALA BIHI.\" Ibnu Abbas berkata; Ketika Jibril turun membawa wahyu, biasa Rasulullah shallallahu 'alaihi wasallam menggerakkan lisan dan kedua bibirnya, dan bisa diketahui bahwa beliau berat dalam menerimanya. Maka Allah menurunkan ayat: \"LAA UQSIMU BIYAMIL QIYAAMAH. LAA TUHARRIK BIHI LISAANAKA LITA'JALA BIH INNA 'ALAINAA JAM'AHU WA QUR`AANAH.\""},"4244":{"ar":"حَدَّثَنِي مَحْمُودٌ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُنْزِلَتْ عَلَيْهِ وَالْمُرْسَلَاتِ وَإِنَّا لَنَتَلَقَّاهَا مِنْ فِيهِ فَخَرَجَتْ حَيَّةٌ فَابْتَدَرْنَاهَا فَسَبَقَتْنَا فَدَخَلَتْ جُحْرَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُقِيَتْ شَرَّكُمْ كَمَا وُقِيتُمْ شَرَّهَاحَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ أَخْبَرَنَا يَحْيَى بْنُ آدَمَ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ بِهَذَا وَعَنْ إِسْرَائِيلَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ مِثْلَهُ وَتَابَعَهُ أَسْوَدُ بْنُ عَامِرٍ عَنْ إِسْرَائِيلَ وَقَالَ حَفْصٌ وَأَبُو مُعَاوِيَةَ وَسُلَيْمَانُ بْنُ قَرْمٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ يَحْيَى بْنُ حَمَّادٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ وَقَالَ ابْنُ إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Mahmud] Telah menceritakan kepada kami [Ubaidullah] dari [Isra`il] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah radliallahu 'anhu] ia berkata; Suatu ketika kami berada bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba turunlah wahyu kepada beliau, yakni surat Al Mursalat. Maka saat itu, kami langsung mendengarkannya dari lisan beliau. Tiba-tiba keluarlah ular, lalu kami langsung menerkamnya, namun ular itu telah lebih dahulu masuk ke dalam lubangnya. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Ia telah terbebas dari keburukan kalian, sementara kalian pun telah diselamatkan dari keburukannya.\" Telah menceritakan kepada kami [Abdah bin Abdullah] Telah mengabarkan kepada kami [Yahya bin Adam] dari [Isra`il] dari [Manshur] dengan hadits ini, dan dari [Isra`il] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dengan hadits semisalnya. Hadis ini diperkuat oleh [Aswad bin Amir] dari [Isra`il]. [Hafsh] berkata; dan [Abu Mu'awiyah] dan [Sulaiman bin Qarm] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] kemudian [Yahya bin Hammad] berkata; Telah mengabarkan kepada kami [Abu 'Awanah] dari [Al Mughirah] dari [Ibrahim] dari ['Alqamah] dari [Abdullah], dan [Ibnu Ishaq] berkata; Dari [Abdurrahman bin Al Aswad] dari [bapaknya] dari [Abdullah]."},"4245":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ قَالَ عَبْدُ اللَّهِبَيْنَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَارٍ إِذْ نَزَلَتْ عَلَيْهِ وَالْمُرْسَلَاتِ فَتَلَقَّيْنَاهَا مِنْ فِيهِ وَإِنَّ فَاهُ لَرَطْبٌ بِهَا إِذْ خَرَجَتْ حَيَّةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ اقْتُلُوهَا قَالَ فَابْتَدَرْنَاهَا فَسَبَقَتْنَا قَالَ فَقَالَ وُقِيَتْ شَرَّكُمْ كَمَا وُقِيتُمْ شَرَّهَا","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] ia berkata; [Abdullah] berkata; Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam berada di dalam gua, tiba-tiba turunlah wahyu kepada beliau yakni surat Al Mursalat. Maka kami pun langsung memperoleh surat itu langsung dari lisan beliau. Dan saat itu, bibir beliau basah lembab karena membacanya. Tiba-tiba nampaklah seekor ular, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Segera kalian bunuhlah ular itu.\" Maka kami pun langsung mengejarnya, namun ular itu telah lebih dahulu kabur. Beliau bersabda: \"Ia telah terbebas dari keburukan kalian, sementara kalian pun telah diselamatkan dari keburukannya.\""},"4246":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَابِسٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍإِنَّهَا تَرْمِي بِشَرَرٍ كَالْقَصَرِ قَالَ كُنَّا نَرْفَعُ الْخَشَبَ بِقَصَرٍ ثَلَاثَةَ أَذْرُعِ أَوْ أَقَلَّ فَنَرْفَعُهُ لِلشِّتَاءِ فَنُسَمِّيهِ الْقَصَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] Telah menceritakan kepada kami [Abdurrahman bin Abis] ia berkata; Aku mendengar [Ibnu Abbas] menjelaskan ayat: \"INNAHAA TARMII BISYARARIN KALQASHR.\" Ia berkata, \"Biasanya kami mengangkat papan setinggi tiga hasta atau lebih rendah dari itu dengan tongkat guna memasuki musim dingin, lalu kami pun menamakannya Al Qashr.\""},"4247":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى أَخْبَرَنَا سُفْيَانُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَابِسٍ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاتَرْمِي بِشَرَرٍ كَالْقَصَرِ قَالَ كُنَّا نَعْمِدُ إِلَى الْخَشَبَةِ ثَلَاثَةَ أَذْرُعٍ أَوْ فَوْقَ ذَلِكَ فَنَرْفَعُهُ لِلشِّتَاءِ فَنُسَمِّيهِ الْقَصَرَ{ كَأَنَّهُ جِمَالَاتٌ صُفْرٌ }حِبَالُ السُّفُنِ تُجْمَعُ حَتَّى تَكُونَ كَأَوْسَاطِ الرِّجَالِ","id":"Telah menceritakan kepada kami [Amru bin Ali] Telah menceritakan kepada kami [Yahya] Telah mengabarkan kepada kami [Sufyan] Telah menceritakan kepadaku [Abdurrahman bin Abis] Aku mendengar [Ibnu Abbas radliallahu 'anhuma] berkata terkait dengan firman-Nya: \"TARMI BISYARARIN KAL QASHR.\" Ia menjelaskan, \"Kami biasanya bersandar pada kayu yang tingginya tiga hasta atau lebih tinggi dari itu. Kami mengangkatnya ketika memasuki musim dingin dan kami pun menamakannyha Al Qashr.\" Kemudian firman-Nya: \"KA`ANNAHU JIMAALAATUN SHUFR.\" Ia menjelaskan, \"Tali-tali bahtera yang dikumpulkan hingga menyerupai cambuk.\""},"4248":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي إِبْرَاهِيمُ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَبَيْنَمَا نَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَارٍ إِذْ نَزَلَتْ عَلَيْهِ وَالْمُرْسَلَاتِ فَإِنَّهُ لَيَتْلُوهَا وَإِنِّي لَأَتَلَقَّاهَا مِنْ فِيهِ وَإِنَّ فَاهُ لَرَطْبٌ بِهَا إِذْ وَثَبَتْ عَلَيْنَا حَيَّةٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتُلُوهَا فَابْتَدَرْنَاهَا فَذَهَبَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُقِيَتْ شَرَّكُمْ كَمَا وُقِيتُمْ شَرَّهَاقَالَ عُمَرُ حَفِظْتُهُ مِنْ أَبِي فِي غَارٍ بِمِنًى","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepadaku [Ibrahim] dari [Al Aswad] dari [Abdullah] ia berkata; Ketika kami berada di dalam gua bersama Rasulullah shallallahu 'alaihi wasallam, turunlah wahyu pada beliau yakni surat Al Mursalaat. Beliau benar-benar membacanya dan kami pun menerimanya langsung dari lisan beliau yang saat itu basah lembab. Dan tiba-tiba seekor ular keluar ke tempat kami, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Bunuhlah ular itu!\" Maka kami pun segera mengejarnya, namun ular telah lebih dahulu kabur, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ia telah terbebas dari keburukan kalian, sementara kalian pun telah diselamatkan dari keburukannya.\" Umar berkata; Aku menghafalnya dari bapakku di dalam gua yang berlokasi di Mina."},"4249":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ النَّفْخَتَيْنِ أَرْبَعُونَ قَالَ أَرْبَعُونَ يَوْمًا قَالَ أَبَيْتُ قَالَ أَرْبَعُونَ شَهْرًا قَالَ أَبَيْتُ قَالَ أَرْبَعُونَ سَنَةً قَالَ أَبَيْتُ قَالَ ثُمَّ يُنْزِلُ اللَّهُ مِنْ السَّمَاءِ مَاءً فَيَنْبُتُونَ كَمَا يَنْبُتُ الْبَقْلُ لَيْسَ مِنْ الْإِنْسَانِ شَيْءٌ إِلَّا يَبْلَى إِلَّا عَظْمًا وَاحِدًا وَهُوَ عَجْبُ الذَّنَبِ وَمِنْهُ يُرَكَّبُ الْخَلْقُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepadaku [Muhammad] Telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jarak antara dua tiupan (sangkakala) adalah empat puluh.\" Ibnu Abbas bertanya, \"Empat puluh hari?\" beliau menjawab: \"Tidak.\" Ia bertanya lagi, \"Empat puluh bulan?\" beliau menjwab: \"Tidak.\" Ia bertanya lagi, \"Empat puluh tahun?\" Beliau menjawab: \"Tidak.\" Beliau kemudian bersabda: \"Setelah itu, Allah menurunkan air dari langit, maka mereka pun hidup kembali sebagaimana tumbuhnya sayur-sayuran. Tidak ada tersisa seorang pun kecuali ia akan binasa, kecuali satu tulang yakni tulang ekor. Dari tulang itulah, manusia dibangkitkan kembali pada hari kiamat.\""},"4250":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْمِقْدَامِ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو حَازِمٍ حَدَّثَنَا سَهْلُ بْنُ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِإِصْبَعَيْهِ هَكَذَا بِالْوُسْطَى وَالَّتِي تَلِي الْإِبْهَامَ بُعِثْتُ وَالسَّاعَةُ كَهَاتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Al Miqdam] Telah menceritakan kepada kami [Al Fudlail bin Sulaiman] Telah menceritakan kepada kami [Abu Hazim] Telah menceritakan kepada kami [Sahl bin Sa'dari] radliallahu 'anhu, ia berkata; Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berkata sambil memberi isyarat dengan kedua jarinya seperti ini -yakni dengan jari tengah dan jari telunjuk-: \"Sesungguhnya aku di utus, sementara kedatangan hari kiamat adalah sebagaimana jarak antara kedua jari ini (jarak selisih antara jari tengah dan telunjuk).\""},"4251":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ زُرَارَةَ بْنَ أَوْفَى يُحَدِّثُ عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الَّذِي يَقْرَأُ الْقُرْآنَ وَهُوَ حَافِظٌ لَهُ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ وَمَثَلُ الَّذِي يَقْرَأُ وَهُوَ يَتَعَاهَدُهُ وَهُوَ عَلَيْهِ شَدِيدٌ فَلَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Qatadah] ia berkata; Aku mendengar [Zurarah bin Aufa] menceritakan dari [Sa'd bin Hisyam] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaan orang membaca Al Qur`an sedangkan ia menghafalnya, maka ia akan bersama para Malaikat mulia. Sedangkan perumpamaan seorang yang membaca Al Qur`an dengan tekum, dan ia mengalami kesulitan atasnya, maka dia akan mendapat dua ganjaran pahala.\""},"4252":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ يَوْمَ يَقُومُ النَّاسُ لِرَبِّ الْعَالَمِينَ }حَتَّى يَغِيبَ أَحَدُهُمْ فِي رَشْحِهِ إِلَى أَنْصَافِ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Ma'n] ia berkata; Telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdulah bin Umar radliallahu 'anhuma] bahwasanya; Nabi shallallahu 'alaihi wasallam bersabda: \"Pada hari ketika seluruh manusia bangkit kepada Rabb semesta alam, salah seorang dari mereka tenggelam dengan keringatnya sendiri bahkan genangan keringatnya mencapai pertengahan kedua telinganya.\""},"4253":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ أَبِي يُونُسَ حَاتِمِ بْنِ أَبِي صَغِيرَةَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ أَحَدٌ يُحَاسَبُ إِلَّا هَلَكَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ جَعَلَنِي اللَّهُ فِدَاءَكَ أَلَيْسَ يَقُولُ اللَّهُ عَزَّ وَجَلَّ{ فَأَمَّا مَنْ أُوتِيَ كِتَابَهُ بِيَمِينِهِ فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا }قَالَ ذَاكَ الْعَرْضُ يُعْرَضُونَ وَمَنْ نُوقِشَ الْحِسَابَ هَلَكَ","id":"Telah menceritakan kepada kami [Amru bin Ali] Telah menceritakan kepada kami [Yahya] dari [Utsman bin Al Aswad] ia berkata; Aku mendengar [Ibnu Abu Mulaikah] Aku mendengar [Aisyah radliallahu 'anha] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam berabda. -dalam riwayat lain- Dan Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam. -dalam riwayat lain- Dan Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Abu Yunus Hatim bin Abu Shaghirah] dari [Ibnu Abu Mulaikah] dari [Al Qasim] dari [Aisyah radliallahu 'anha] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak seorang pun yang dihisab, kecuali ia akan binasa.\" Aisyah berkata; Aku bertanya, \"Wahai Rasulullah, Allah telah menjadikanku sebagai tebusanmu, bukankah Allah telah berfirman: 'Makan barangsiapa yang didatangkan kitabnya dari sebelah kanannya, maka niscaya ia akan dihisab dengan perhitungan yang ringan? '\" beliau menjawab: \"Itulah adalah Al 'Ardlu (hari ketika amal ditampakkan) Namun siapa saja yang hisabnya diperdebatkan, maka dia akan binasa.\""},"4254":{"ar":"حَدَّثَنِي سَعِيدُ بْنُ النَّضْرِ أَخْبَرَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ جَعْفَرُ بْنُ إِيَاسٍ عَنْ مُجَاهِدٍ قَالَ قَالَ ابْنُ عَبَّاسٍ{ لَتَرْكَبُنَّ طَبَقًا عَنْ طَبَقٍ }حَالًا بَعْدَ حَالٍ قَالَ هَذَا نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Sa'id bin An Nadlr] Telah mengabarkan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr Ja'far bin Iyas] dari [Mujahid] ia berkata; [Ibnu Abbas] berkata terkat dengan firman Allah: \"LATARKABUNNA THABAQAN 'AN THABAQ.\" Maksudnya adalah proses demi proses. Katanya, dan itulah Nabi kalian shallallahu 'alaihi wasallam."},"4255":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَأَوَّلُ مَنْ قَدِمَ عَلَيْنَا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُصْعَبُ بْنُ عُمَيْرٍ وَابْنُ أُمِّ مَكْتُومٍ فَجَعَلَا يُقْرِئَانِنَا الْقُرْآنَ ثُمَّ جَاءَ عَمَّارٌ وَبِلَالٌ وَسَعْدٌ ثُمَّ جَاءَ عُمَرُ بْنُ الْخَطَّابِ فِي عِشْرِينَ ثُمَّ جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا رَأَيْتُ أَهْلَ الْمَدِينَةِ فَرِحُوا بِشَيْءٍ فَرَحَهُمْ بِهِ حَتَّى رَأَيْتُ الْوَلَائِدَ وَالصِّبْيَانَ يَقُولُونَ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ جَاءَ فَمَا جَاءَ حَتَّى قَرَأْتُ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى فِي سُوَرٍ مِثْلِهَا","id":"Telah menceritakan kepada kami [Abdan] ia berkata; Telah mengabarkan kepadaku [bapakku] dari [Syu'bah] dari [Abu Ishaq] dari [Al Bara` radliallahu 'anhu] ia berkata; Orang yang pertama-tama kali menemui kami dari sahabat Nabi shallallahu 'alaihi wasallam adalah Mush'ab bin Umair dan Ibnu Ummu Maktum. Lalu keduanya pun membacakan Al Qur`an kepada kami. Setelah itu, datanglah Bilal dan Sa'd. Lalu disusul kemudian oleh Umar bin Al Khaththab bersama dua puluh orang. Setelah itu, barulah Nabi shallallahu 'alaihi wasallam datang. Maka aku tidak pernah melihat penduduk Madinah gembira menyerupai senang dan gembiranya mereka dengan kedatangan beliau, sampai-sampai anak-anak kecil dan para hamba sahaya pun berseru, \"Ini adalah Rasulullah shallallahu 'alaihi wasallam telah datang.\" Tidaklah beliau datang hingga aku selesai membaca surat Al A'la dan surat-surat semisalnya."},"4256":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ عَبْدُ اللَّهِ بْنُ زَمْعَةَأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ وَذَكَرَ النَّاقَةَ وَالَّذِي عَقَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ إِذْ انْبَعَثَ أَشْقَاهَا }انْبَعَثَ لَهَا رَجُلٌ عَزِيزٌ عَارِمٌ مَنِيعٌ فِي رَهْطِهِ مِثْلُ أَبِي زَمْعَةَ وَذَكَرَ النِّسَاءَ فَقَالَ يَعْمِدُ أَحَدُكُمْ فَيَجْلِدُ امْرَأَتَهُ جَلْدَ الْعَبْدِ فَلَعَلَّهُ يُضَاجِعُهَا مِنْ آخِرِ يَوْمِهِ ثُمَّ وَعَظَهُمْ فِي ضَحِكِهِمْ مِنْ الضَّرْطَةِ وَقَالَ لِمَ يَضْحَكُ أَحَدُكُمْ مِمَّا يَفْعَلُوَقَالَ أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلُ أَبِي زَمْعَةَ عَمِّ الزُّبَيْرِ بْنِ الْعَوَّامِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Wuhaib] Telah menceritakan kepada kami [Hisyam] dari [bapaknya] bahwa [Abdullah bin Zam'ah] telah mengabarkan kepadanya bahwa ia mendengar Nabi shallallahu 'alaihi wasallam menyampaikan khuthbah lalu menyebutkan Unta yang dan orang yang melukainya (maksudnya dari kaum Tsamud). Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Muncul dari kalangan mereka seorang laki-laki terhormat, perangainya jahat dan mempunyai banyak pendukung di kalangannya, laki-laki itu seperti Abu Zum'ah.\" Kemudian beliau juga menyebut tentang wanita. Beliau bersabda: \"APakah layak salah seorang dari kalian memukul isterinya sebagaimana ia memukul seorang budak, namun di akhir petang malah menggaulinya?.\" Beliau kemudian memberi nasehat kepada mereka terhadap kebiasaan tertawa lantaran kentut. Setelah itu, beliau bersabda: \"Kenapa salah seorang dari kalian tertawa terhadap apa yang ia lakukan?\" [Abu Mu'awiyah] berkata; Telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Abdullah bin Zam'ah] bahwa Nabi shallallahu 'alaihi wasallam mengatakan bahwa laki-laki Tsamud tersebut seperti Abu Zam'ah paman Az Zubair bin Al 'Awwam."},"4257":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَدَخَلْتُ فِي نَفَرٍ مِنْ أَصْحَابِ عَبْدِ اللَّهِ الشَّأْمَ فَسَمِعَ بِنَا أَبُو الدَّرْدَاءِ فَأَتَانَا فَقَالَ أَفِيكُمْ مَنْ يَقْرَأُ فَقُلْنَا نَعَمْ قَالَ فَأَيُّكُمْ أَقْرَأُ فَأَشَارُوا إِلَيَّ فَقَالَ اقْرَأْ فَقَرَأْتُ{ وَاللَّيْلِ إِذَا يَغْشَى وَالنَّهَارِ إِذَا تَجَلَّى }وَالذَّكَرِ وَالْأُنْثَى قَالَ أَنْتَ سَمِعْتَهَا مِنْ فِي صَاحِبِكَ قُلْتُ نَعَمْ قَالَ وَأَنَا سَمِعْتُهَا مِنْ فِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَؤُلَاءِ يَأْبَوْنَ عَلَيْنَا","id":"Telah menceritakan kepada kami [Qabishah bin Uqbah] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] ia berkata; Aku bergabung dalam suatu kelompok yang terdiri dari sabahat-sahabatnya Abdullah Asy Sya'a, lalu Abu Darda` mendengar kami, maka ia pun bergegas datang. Kemudian ia bertanya, \"Adakah di antara kalian yang bisa membaca (Al Qur`an)?\" kami menjawab, \"Ya, ada.\" Ia bertanya lagi, \"Lalu, siapakah diantara kalian yang paling bagus bacaannya?\" Maka mereka pun menunjuk ke arahku. [Abu Darda'] berkata, \"Kalau begitu, bacalah.\" Maka aku pun membaca, \"WAL LAAILI IDZAA YAGHSYAA WAN NAHAARI IDZAA TAJALLAA WADZ DZAKARI WAL UNTSAA.\" Ia bertanya lagi, \"Apakah kamu mendengarnya langsung dari bibir temanmu (Ibnu Mas'ud)?\" aku menjawab, \"Ya.\" Ia berkata, \"Kalau aku mendengarnya langsung dari bibir Nabi shallallahu 'alaihi wasallam, namun orang-orang itu mengingkarinya.\""},"4258":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ قَالَقَدِمَ أَصْحَابُ عَبْدِ اللَّهِ عَلَى أَبِي الدَّرْدَاءِ فَطَلَبَهُمْ فَوَجَدَهُمْ فَقَالَ أَيُّكُمْ يَقْرَأُ عَلَى قِرَاءَةِ عَبْدِ اللَّهِ قَالَ كُلُّنَا قَالَ فَأَيُّكُمْ أَحْفَظُ فَأَشَارُوا إِلَى عَلْقَمَةَ قَالَ كَيْفَ سَمِعْتَهُ يَقْرَأُ{ وَاللَّيْلِ إِذَا يَغْشَى }قَالَ عَلْقَمَةُ وَالذَّكَرِ وَالْأُنْثَى قَالَ أَشْهَدُ أَنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ هَكَذَا وَهَؤُلَاءِ يُرِيدُونِي عَلَى أَنْ أَقْرَأَ{ وَمَا خَلَقَ الذَّكَرَ وَالْأُنْثَى }وَاللَّهِ لَا أُتَابِعُهُمْ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] ia berkata; Para sahabat Abdullah datang menemui Abu Darda`. Ia mencari mereka dan akhirnya menemukan mereka. Maka [Abu Darda`] bertanya kepada mereka, \"Siapakah di antara kalian yang membaca dengan bacaan [Abdullah]\" salah seorang menjawab, \"Kami semua membaca dengan bacaannya Abdullah.\" Ia bertanya lagi, \"Lalu siapa di antara kalian yang paling baik bacaannya?\" Maka mereka pun menunjuk ke arah 'Alqamah. Abu Darda` pun bertanya padanya, \"Bagaimana kamu mendengarnya membaca ayat: 'WAL LAILI IDZAA YAGHSYAA.'?\" [Alqamah] menjawab, \"WADZ DZAKARI WAL UNTSAA.\" Abu Darda` berkata, \"Demi Allah, aku telah mendengar Nabi shallallahu 'alaihi wasallam membacanya seperti ini. Akan tetapi mereka itu, menginginkan agar aku membacanya: 'WAMAA KHALAQADZ DZAKARA WAL UNTSAA.' Demi Allah, aku tidak akan mengikuti mereka.\""},"4259":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَقِيعِ الْغَرْقَدِ فِي جَنَازَةٍ فَقَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ كُتِبَ مَقْعَدُهُ مِنْ الْجَنَّةِ وَمَقْعَدُهُ مِنْ النَّارِ فَقَالُوا يَا رَسُولَ اللَّهِ أَفَلَا نَتَّكِلُ فَقَالَ اعْمَلُوا فَكُلٌّ مُيَسَّرٌ ثُمَّ قَرَأَ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى وَصَدَّقَ بِالْحُسْنَى إِلَى قَوْلِهِ لِلْعُسْرَى }حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ كُنَّا قُعُودًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Ali radliallahu 'anhu] ia berkata; Suatu kami berada dalam kelompok pelayatan jenazah bersama Nabi shallallahu 'alaihi wasallam tepatnya di Baqi' Al Gharqad, maka beliau pun bersabda: \"Tidak ada seorang pun dari kalian kecuali tempat duduknya dari surga atau dari neraka telah ditulis.\" Para sahabat pun bertanya, \"Wahai Rasulullah, bagaimana kalau kita sebaiknya hanya bertawakkal saja?\" beliau menjawab: \"Beramallah kalian, sebab setiap orang akan dimudahkan.\" Kemudian beliau bersabda: \"FA`AMMAA MAN `A'THAA WAT TAQAA WA SHADDAQA BIL HUSNAA (Dan barangsiapa yang memberi, dan bertakwa serta membenarkan kebaikan)..\" hingga firman-Nya: \"LIL'USRAA.\" Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Abdul Wahid] Telah menceritakan kepada kami [Al A'masy] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman] dari [Ali radliallahu 'anhu] ia berkata; Suatu ketika, kami duduk-duduk di sisi Nabi shallallahu 'alaihi wasallam. Lalu ia pun menyebutkan hadits semisalnya."},"4260":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ فِي جَنَازَةٍ فَأَخَذَ عُودًا يَنْكُتُ فِي الْأَرْضِ فَقَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ كُتِبَ مَقْعَدُهُ مِنْ النَّارِ أَوْ مِنْ الْجَنَّةِ قَالُوا يَا رَسُولَ اللَّهِ أَفَلَا نَتَّكِلُ قَالَ اعْمَلُوا فَكُلٌّ مُيَسَّرٌ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى وَصَدَّقَ بِالْحُسْنَى }الْآيَةَقَالَ شُعْبَةُ وَحَدَّثَنِي بِهِ مَنْصُورٌ فَلَمْ أُنْكِرْهُ مِنْ حَدِيثِ سُلَيْمَانَ","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] Telah mengabarkan kepada kami [Muhamad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Ali radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam, bahwasanya; Suatu ketika beliau berada dalam rombongan pelayat jenazah, lalu beliau mengambil tongkat dan menancapkannya di tanah. Kemudian beliau bersabda: \"Tidak ada seorang pun dari kalian kecuali tempat duduknya dari surga atau dari neraka telah ditulis.\" Para sahabat pun bertanya, \"Wahai Rasulullah, bagaimana kalau sebaiknya kita hanya bertawakkal saja?\" beliau menjawab: \"Beramallah kalian, sebab setiap orang akan dimudahkan.\" Kemudian beliau bersabda: \"FA`AMMAA MAN `A'THAA WAT TAQAA WA SHADDAQA BIL HUSNAA (Dan barangsiapa yang memberi, dan bertakwa serta membenarkan kebaikan)..\" Syu'bah berkata; [Manshur] telah menceritakan hadits ini kepadaku, namun aku tidak mengingkarinya bahwa itu adalah dari haditsnya Sulaiman."},"4261":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ عَلَيْهِ السَّلَام قَالَكُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ كُتِبَ مَقْعَدُهُ مِنْ الْجَنَّةِ وَمَقْعَدُهُ مِنْ النَّارِ فَقُلْنَا يَا رَسُولَ اللَّهِ أَفَلَا نَتَّكِلُ قَالَ لَا اعْمَلُوا فَكُلٌّ مُيَسَّرٌ ثُمَّ قَرَأَ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى وَصَدَّقَ بِالْحُسْنَى فَسَنُيَسِّرُهُ لِلْيُسْرَى إِلَى قَوْلِهِ فَسَنُيَسِّرُهُ لِلْعُسْرَى }","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman] dari [Ali] ia berkata; Suatu ketika, kami duduk-duduk di sisi Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Tidak ada seorang pun dari kalian, kecuali tempat duduknya dari surga dan dari neraka telah ditulis.\" Maka kami pun bertanya, \"Wahai Rasulullah, bagaimana bila kita sebaiknya hanya bertawakkal saja?\" beliau menjawab: \"Tidak! Tetapi beramallah kalian, sebab setiap orang akan dimudahkah.\" Kemudian beliau membacakan ayat: \"FA`AMMAA MAN `A'THAA WAT TAQAA WA SHADDAQA BIL HUSNAA FASANUYASSIRUHU LILYUSRAA (Dan barangsiapa yang memberi, dan bertakwa serta membenarkan kebaikan)..\" hingga firman-Nya, \"FASANUYASSIRUHU LIL'USRAA.\""},"4262":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا فِي جَنَازَةٍ فِي بَقِيعِ الْغَرْقَدِ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَعَدَ وَقَعَدْنَا حَوْلَهُ وَمَعَهُ مِخْصَرَةٌ فَنَكَّسَ فَجَعَلَ يَنْكُتُ بِمِخْصَرَتِهِ ثُمَّ قَالَ مَا مِنْكُمْ مِنْ أَحَدٍ وَمَا مِنْ نَفْسٍ مَنْفُوسَةٍ إِلَّا كُتِبَ مَكَانُهَا مِنْ الْجَنَّةِ وَالنَّارِ وَإِلَّا قَدْ كُتِبَتْ شَقِيَّةً أَوْ سَعِيدَةً قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَفَلَا نَتَّكِلُ عَلَى كِتَابِنَا وَنَدَعُ الْعَمَلَ فَمَنْ كَانَ مِنَّا مِنْ أَهْلِ السَّعَادَةِ فَسَيَصِيرُ إِلَى عَمَلِ أَهْلِ السَّعَادَةِ وَمَنْ كَانَ مِنَّا مِنْ أَهْلِ الشَّقَاءِ فَسَيَصِيرُ إِلَى عَمَلِ أَهْلِ الشَّقَاوَةِ قَالَ أَمَّا أَهْلُ السَّعَادَةِ فَيُيَسَّرُونَ لِعَمَلِ أَهْلِ السَّعَادَةِ وَأَمَّا أَهْلُ الشَّقَاوَةِ فَيُيَسَّرُونَ لِعَمَلِ أَهْلِ الشَّقَاءِ ثُمَّ قَرَأَ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى وَصَدَّقَ بِالْحُسْنَى }الْآيَةَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Ali radliallahu 'anhu] ia berkata; Suatu ketika, kami berada dalam pelayatan jenazah di Baqi' Al Gharqad. Kemudian Rasulullah shallallahu 'alaihi wasallam datang lalu duduk dan kami pun ikut duduk di sekitar beliau. Saat itu, beliau membawa tongkat kecil dan beliau tegakkan dengan kakinya. Kemudian beliau bersabda: Tidak ada seorang pun, dan tidak ada satu jiwa pun yang bernafas, kecuali tempatnya telah ditulis di neraka dan di surga. Dan telah pula di tulis, apakah ia akan hidup sengsara atau bahagia.\" Maka seorang laki-laki bertanya, \"Wahai Rasulullah, bagaimana kalau kita bertawakkal saja terhadap kitab kita (catatan yang telah ditetapkan) dan meninggalkan amal? Siapa diantara kita yang termasuk golongan yang beruntung, maka niscaya ia akan berjalan di atas amalan golongan yang beruntung (penghuni surga). Dan siapa yang termasuk Ahlusy Syaqa` (golongan selaka), maka niscaya ia akan berjalan di atas amalan Ahlusy Syaqa (golongan celaka, penghuni neraka)?.\" Beliau bersabda: \"Adapun Ahlus Sa'adah (golongan yang beruntung, penghuni surga), maka ia akan dimudahkan untuk mengerjalan amalan Ahlus Sa'adah (golongan yang beruntung penghuni surga). Dan Ahlusy Syaqa` (golongan celaka) juga akan dimudahkan untuk melakukan amalan Ahlusy Syaqa` (golongan celaka).\" Kemudian beliau membaca ayat: \"FA`AMMAA MAN `A'THAA WAT TAQAA WA SHADDAQA BIL HUSNAA (Dan barangsiapa yang memberi, dan bertakwa serta membenarkan kebaikan)..\""},"4263":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَالَ سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ يُحَدِّثُ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنَازَةٍ فَأَخَذَ شَيْئًا فَجَعَلَ يَنْكُتُ بِهِ الْأَرْضَ فَقَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَقَدْ كُتِبَ مَقْعَدُهُ مِنْ النَّارِ وَمَقْعَدُهُ مِنْ الْجَنَّةِ قَالُوا يَا رَسُولَ اللَّهِ أَفَلَا نَتَّكِلُ عَلَى كِتَابِنَا وَنَدَعُ الْعَمَلَ قَالَ اعْمَلُوا فَكُلٌّ مُيَسَّرٌ لِمَا خُلِقَ لَهُ أَمَّا مَنْ كَانَ مِنْ أَهْلِ السَّعَادَةِ فَيُيَسَّرُ لِعَمَلِ أَهْلِ السَّعَادَةِ وَأَمَّا مَنْ كَانَ مِنْ أَهْلِ الشَّقَاءِ فَيُيَسَّرُ لِعَمَلِ أَهْلِ الشَّقَاوَةِ ثُمَّ قَرَأَ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى وَصَدَّقَ بِالْحُسْنَى }الْآيَةَ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] ia berkata; Aku mendengar [Sa'd bin Ubaidah] menceritakan dari [Abu Abdurrahman As Sulami] dari [Ali radliallahu 'anhu] ia berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam berada dalam rombongan pelayat Jenazah, lalu beliau mengambil sesuatu dan memukulkannya ke tangah. Kemudian beliau bersabda: \"Tidak ada seorang pun, kecuali tempat duduknya telah ditulis di neraka dan tempat duduknya di surga.\" Para sahabat bertanya, \"Wahai Rasulullah, kalau begitu, bagaimana bila kita bertawakkal saja terhadap takdir kita tanpa beramal?\" beliau menajawab: \"Ber'amallah kalian, karena setiap orang akan dimudahkan kepada yang dicipta baginya. Barangsiapa yang diciptakan sebagai Ahlus Sa'adah (penduduk surga), maka ia akan dimudahkan untuk mengamalkan amalan Ahlus Sa'adah. Namun, barangsiapa yang diciptakan sebagai Ahlusy Syaqa` (penghuni neraka), maka ia akan dimudahkan pula untuk melakukan amalan Ahlusy Syaqa`.\" Kemudian beliau membacakan ayat: \"FA`AMMAA MAN `A'THAA WAT TAQAA WA SHADDAQA BIL HUSNAA (Dan barangsiapa yang memberi, dan bertakwa serta membenarkan kebaikan)..\""},"4264":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَ��َّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ قَالَ سَمِعْتُ جُنْدُبَ بْنَ سُفْيَانَ رَضِيَ اللَّهُ عَنْهُ قَالَاشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَقُمْ لَيْلَتَيْنِ أَوْ ثَلَاثًا فَجَاءَتْ امْرَأَةٌ فَقَالَتْ يَا مُحَمَّدُ إِنِّي لَأَرْجُو أَنْ يَكُونَ شَيْطَانُكَ قَدْ تَرَكَكَ لَمْ أَرَهُ قَرِبَكَ مُنْذُ لَيْلَتَيْنِ أَوْ ثَلَاثَةٍ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَالضُّحَى وَاللَّيْلِ إِذَا سَجَى مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }قَوْلُهُ{ مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }تُقْرَأُ بِالتَّشْدِيدِ وَالتَّخْفِيفِ بِمَعْنًى وَاحِدٍ مَا تَرَكَكَ رَبُّكَ وَقَالَ ابْنُ عَبَّاسٍ مَا تَرَكَكَ وَمَا أَبْغَضَكَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami [Al Aswad bin Qais] ia berkata; Aku mendengar [Jundub bin Sufyan radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam menderita sakit hingga beliau tidak bisa bangun selama dua malam atau tiga. Lalu datanglah seorang wanita seraya berkata, \"Wahai Muhammad, aku benar-benar mengharap bahwa syetanmu telah meninggalkanmu. Sebab, aku tidak lagi melihatnya semenjak dua hari ini atau tiga hari.\" Maka Allah 'azza wajalla menurunkan surat: \"WADLDLUHAA WALLAILI IDZAA SAJAA MAA WADDA'AKA RABBUKA WAMAA QALAA.\" Firman Allah: \"MAA WADDA'AKA RABBUKA WAMAA QALAA.\" (QS. Adhdhuha 3) Dibaca dengan tasydid atau pun Takhfif maknanya tetap satu, yakni Rabb-mu tidaklah meninggalkanmu. Ibnu Abbas menafsirkan, \"(Rabb-mu) tidaklah meninggalkan dan memurkaimu.\""},"4265":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ قَالَ سَمِعْتُ جُنْدُبًا الْبَجَلِيَّقَالَتْ امْرَأَةٌ يَا رَسُولَ اللَّهِ مَا أُرَى صَاحِبَكَ إِلَّا أَبْطَأَكَ فَنَزَلَتْ{ مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Muhammad bin Ja'far Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Al Aswad bin Qais] ia berkata; Aku mendengar [Jundub Al Bajali] berkata; Seorang wanita berkata, \"Wahai Rasulullah, tidaklah aku melihat Syetanmu itu, kecuali ia telah meninggalkanmu.\" Maka turunlah surat: \"MAA WADDA'AKA RABBUKA WAMAA QALAA (Rabb-mu tidaklah meninggalkanmu tidak pula menelantarkanmu). (QS. Adhdhuha 3) \""},"4266":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَدِيٌّ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ فَقَرَأَ فِي الْعِشَاءِ فِي إِحْدَى الرَّكْعَتَيْنِ بِالتِّينِ وَالزَّيْتُونِ{ تَقْوِيمٍ }الْخَلْقِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Syu'bah] ia berkata; Telah mengabarkan kepadaku [Adi] ia berkata; Aku telah mendengar [Al Baraa`] radliallahu 'anhu, bahwasanya; Nabi shallallahu 'alaihi wasallam berada dalam suatu perjalanan, lalu pada saat shalat Isya` yakni pada salah satu raka'atnya beliau membaca, \"AT TIINI WAZ ZAITUUN.\" Dan maksud istilah taqwiim adalah alkhalq, atau penciptaan."},"4267":{"ar":"بَاب حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنِي سَعِيدُ بْنُ مَرْوَانَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ أَخْبَرَنَا أَبُو صَالِحٍ سَلْمَوَيْهِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ عَنْ يُونُسَ بْنِ يَزِيدَ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ أَخْبَرَهُ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ أَوَّلَ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا الصَّادِقَةُ فِي النَّوْمِ فَكَانَ لَا يَرَى رُؤْيَا إِلَّا جَاءَتْ مِثْلَ فَلَقِ الصُّبْحِ ثُمَّ حُبِّبَ إِلَيْهِ الْخَلَاءُ فَكَانَ يَلْحَقُ بِغَارِ حِرَاءٍ فَيَتَحَنَّثُ فِيهِ قَالَ وَالتَّحَنُّثُ التَّعَبُّدُ اللَّيَالِيَ ذَوَاتِ الْعَدَدِ قَبْلَ أَنْ يَرْجِعَ إِلَى أَهْلِهِ وَيَتَزَوَّدُ لِذَلِكَ ثُمَّ يَرْجِعُ إِلَى خَدِيجَةَ فَيَتَزَوَّدُ بِمِثْلِهَا حَتَّى فَجِئَهُ الْحَقُّ وَهُوَ فِي غَارِ حِرَاءٍ فَجَاءَهُ الْمَلَكُ فَقَالَ اقْرَأْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنَا بِقَارِئٍ قَالَ فَأَخَذَنِي فَغَطَّنِي حَتَّى بَلَغَ مِنِّي الْجُهْدَ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ قُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي الثَّانِيَةَ حَتَّى بَلَغَ مِنِّي الْجُهْدَ ثُمَّ أَرْسَلَنِي فَقَالَ اقْرَأْ قُلْتُ مَا أَنَا بِقَارِئٍ فَأَخَذَنِي فَغَطَّنِي الثَّالِثَةَ حَتَّى بَلَغَ مِنِّي الْجُهْدَ ثُمَّ أَرْسَلَنِي فَقَالَ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ خَلَقَ الْإِنْسَانَ مِنْ عَلَقٍ اقْرَأْ وَرَبُّكَ الْأَكْرَمُ الَّذِي عَلَّمَ بِالْقَلَمِ الْآيَاتِ إِلَى قَوْلِهِ عَلَّمَ الْإِنْسَانَ مَا لَمْ يَعْلَمْ }فَرَجَعَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَرْجُفُ بَوَادِرُهُ حَتَّى دَخَلَ عَلَى خَدِيجَةَ فَقَالَ زَمِّلُونِي زَمِّلُونِي فَزَمَّلُوهُ حَتَّى ذَهَبَ عَنْهُ الرَّوْعُ قَالَ لِخَدِيجَةَ أَيْ خَدِيجَةُ مَا لِي لَقَدْ خَشِيتُ عَلَى نَفْسِي فَأَخْبَرَهَا الْخَبَرَ قَالَتْ خَدِيجَةُ كَلَّا أَبْشِرْ فَوَاللَّهِ لَا يُخْزِيكَ اللَّهُ أَبَدًا فَوَاللَّهِ إِنَّكَ لَتَصِلُ الرَّحِمَ وَتَصْدُقُ الْحَدِيثَ وَتَحْمِلُ الْكَلَّ وَتَكْسِبُ الْمَعْدُومَ وَتَقْرِي الضَّيْفَ وَتُعِينُ عَلَى نَوَائِبِ الْحَقِّ فَانْطَلَقَتْ بِهِ خَدِيجَةُ حَتَّى أَتَتْ بِهِ وَرَقَةَ بْنَ نَوْفَلٍ وَهُوَ ابْنُ عَمِّ خَدِيجَةَ أَخِي أَبِيهَا وَكَانَ امْرَأً تَنَصَّرَ فِي الْجَاهِلِيَّةِ وَكَانَ يَكْتُبُ الْكِتَابَ الْعَرَبِيَّ وَيَكْتُبُ مِنْ الْإِنْجِيلِ بِالْعَرَبِيَّةِ مَا شَاءَ اللَّهُ أَنْ يَكْتُبَ وَكَانَ شَيْخًا كَبِيرًا قَدْ عَمِيَ فَقَالَتْ خَدِيجَةُ يَا ابْنَ عَمِّ اسْمَعْ مِنْ ابْنِ أَخِيكَ قَالَ وَرَقَةُ يَا ابْنَ أَخِي مَاذَا تَرَى فَأَخْبَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَبَرَ مَا رَأَى فَقَالَ وَرَقَةُ هَذَا النَّامُوسُ الَّذِي أُنْزِلَ عَلَى مُوسَى لَيْتَنِي فِيهَا جَذَعًا لَيْتَنِي أَكُونُ حَيًّا ذَكَرَ حَرْفًا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَمُخْرِجِيَّ هُمْ قَالَ وَرَقَةُ نَعَمْ لَمْ يَأْتِ رَجُلٌ بِمَا جِئْتَ بِهِ إِلَّا أُوذِيَ وَإِنْ يُدْرِكْنِي يَوْمُكَ حَيًّا أَنْصُرْكَ نَصْرًا مُؤَزَّرًا ثُمَّ لَمْ يَنْشَبْ وَرَقَةُ أَنْ تُوُفِّيَ وَفَتَرَ الْوَحْيُ فَتْرَةً حَتَّى حَزِنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ مُحَمَّدُ بْنُ شِهَابٍ فَأَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ رَضِيَ اللَّهُ عَنْهُمَا قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُحَدِّثُ عَنْ فَتْرَةِ الْوَحْيِ قَالَ فِي حَدِيثِهِ بَيْنَا أَنَا أَمْشِي سَمِعْتُ صَوْتًا مِنْ السَّمَاءِ فَرَفَعْتُ بَصَرِي فَإِذَا الْمَلَكُ الَّذِي جَاءَنِي بِحِرَاءٍ جَالِسٌ عَلَى كُرْسِيٍّ بَيْنَ السَّمَاءِ وَالْأَرْضِ فَفَرِقْتُ مِنْهُ فَرَجَعْتُ فَقُلْتُ زَمِّلُونِي زَمِّلُونِي فَدَثَّرُوهُ فَأَنْزَلَ اللَّهُ تَعَالَى{ يَا أَيُّهَا الْمُدَّثِّرُ قُمْ فَأَنْذِرْ وَرَبَّكَ فَكَبِّرْ وَثِيَابَكَ فَطَهِّرْ وَالرِّجْزَ فَاهْجُرْ }قَالَ أَبُو سَلَمَةَ وَهِيَ الْأَوْثَانُ الَّتِي كَانَ أَهْلُ الْجَاهِلِيَّةِ يَعْبُدُونَ قَالَ ثُمَّ تَتَابَعَ الْوَحْيُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] -dalam riwayat lain- Dan Telah menceritakan kepadaku [Sa'id bin Marwan] Telah menceritakan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah] Telah mengabarkan kepada kami [Abu Shalih Salmawaih] ia berkata; Telah menceritakan kepadaku [Abdullah] dari [Yunus bin Yazid] ia berkata, Telah mengabarkan kepadaku [Ibnu Syihab] bahwa [Urwah bin Zubair] Telah mengabarkan kepadanya, bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam berkata; Peristiwa awal turunnya wahyu kepada Rasulullah shallallahu 'alaihi wasallam adalah diawali dengan Ar Ru`yah Ash Shadiqah (mimpi yang benar) di dalam tidur. Tidaklah beliau bermimpi, kecuali yang beliau lihat adalah sesuatu yang menyerupai belahan cahaya subuh. Dan di dalam dirinya dimasukkan perasaan untuk selalu ingin menyendiri. Maka beliau pun memutuskan untuk berdiam diri di dalam gua Hira`, beribadah di dalamnya pada malam hari selama beberapa hari dan untuk itu, beliau membawa bekal. Setelah perbekalannya habis, maka beliau kembali dan mengambil bekal. Begitulah seterusnya sehingga kebenaran pun datang pada beliau, yakni saat beliau berada di dalam gua Hira`. Malaikat mendatanginya seraya berkata, \"Bacalah.\" Maka Rasulullah shallallahu 'alaihi wasallam menjawab, \"Aku tidak bisa membaca.\" Beliau menjelaskan: \"Lalu Malaikat itu pun menarik dan menutupiku, hingga aku pun merasa kesusahan. Kemudian Malaikat itu kembali lagi padaku dan berkata, 'Bacalah.' Aku menjawab, 'Aku tidak bisa membaca.' Malaikat itu menarikku kembali dan mendekapku hingga aku merasa kesulitan, lalu memerintahkan kepadaku untuk kedua kalinya seraya berkata, 'Bacalah.' Aku menjawab, 'Aku tidak bisa membaca.' Ia menarik lagi dan mendekapku ketiga kalinya hingga aku merasa kesusahan. Kemudian Malaikat itu menyuruhku kembali seraya membaca, 'IQRA` BISMIKAL LADZII KHALAQ, KHALAQAL INSAANA MIN 'ALAQ IQRA` WA RABBUKAL AKRAM ALLADZII 'ALLAMAL BIL QALAM.. -hingga- 'ALLAMAL INSAANA MAA LAM YA'LAM.'\" Maka dengan badan yang menggigil, akhirnya Rasulullah shallallahu 'alaihi wasallam kembali kepada Khadijah seraya berkata, \"Selimutilah aku..selimutilah aku.\" Hingga perasaan takut beliau pun hilang. Setelah itu, beliau berkata kepada Khadijah, \"Wahai Khadijah, apa yang terjadi denganku, sungguh aku merasa khawatir atas diriku sendiri.\" Akhirnya, beliau pun menuturkan kejadian yang beliau alami. Khadijah berkata, \"Tidak. Bergembiralah engkau. Demi Allah, Allah tidak akan mencelakakanmu demi selama-lamanya. Sesungguhnya engkau benar-benar seorang yang senantiasa menyambung silaturahmi, seorang yang jujur kata-katanya, menolong yang lemah, memberi kepada orang yang tak punya, engkau juga memuliakan tamu dan membela kebenaran.\" Akhirnya Khadijah pergi dengan membawa beliau hingga bertemu dengan Waraqah bin Naufal, ia adalah anak pamannya Khadijah, yakni saudara bapaknya. An Naufal adalah seorang penganut agama Nashrani pada masa Jahiliyah. Ia seorang yang menulis kitab Arab. Ia menulis dari kitab Injil dengan bahasa Arab. Saat itu, ia telah menjadi syeikh yang tua renta lagi buta. Khadijah berkata padanya, \"Wahai anak pamanku. Dengarkanlah tuturan dari anak saudaramu.\" Waraqah berkata, \"Wahai anak pamanku apa yang telah kamu lihat?\" Maka Nabi shallallahu 'alaihi wasallam pun mengabarkan padanya tentang kejadian yang telah beliau alami. Kemudian Waraqah pun berkata, \"Ini adalah Namus yang pernah diturunkan kepada Musa. Sekiranya aku masih muda, dan sekiranya aku masih hidup...\" ia mengatakan beberapa kalimat. Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah mereka akan mengusirku?\" Waraqah menjawab, \"Ya, tidak ada seorang pun yang datang dengan membawa seperti apa yang kamu bawa, kecuali ia akan disakiti. Dan sekiranya aku masih mendapati hari itu, niscaya aku akan menolongmu dengan pertolongan yang hebat.\" Tidak lama kemudian, Waraqah pun meninggal, sementara wahyu terputus hingga membuat Rasulullah shallallahu 'alaihi wasallam sedih. [Muhammad bin Syihab] berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Jabir bin Abdullah Al Anshari] radliallahu 'anhuma berkata; Rasulullah shallallahu 'alaihi wasallam menceritakan kejadian pertamakali turunnya wahyu, beliau bersabda: \"Ketika aku tengah berjalan, tiba-tiba aku mendengar suara yang berasal dari langit, maka aku pun mengangkat pandanganku ke arah langit, ternyata di atas terdapat Malaikat yang sebelumnya mendatangiku di gua Hira` tengah duduk di atas kursi antara langit dan bumi. Aku pun lari darinya dan segera pulang menemui keluargaku seraya berkata, 'Selimutilah aku, selimutilah aku.'\" Maka keluarga beliau pun segera menyelimutinya. Kemudian Allah menurunkan firman-Nya: 'YAA AYYUHAL MUDDATSTSIR QUM FA`ANDZIR WA RABBAKA FAKABBIR WA TSIYAABAKA FATHAHHIR WAR RUJZA FAHJUR (Wahai orang yang berselimut, bangkitlah, dan berilah peringatan. Dan Tuhan-mu agungkanlah. Dan pakaianmu sucikanlah, Dan tinggalkanlah sesembahan berhala).'\" Abu Salamah berkata; Ar Rijza adalah berhala-berhala yang disembah oleh kaum Jahiliyah. Setelah itu, maka turunlah wahyu dengan beruntun."},"4268":{"ar":"حَدَّثَنَا ابْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا الصَّالِحَةُ فَجَاءَهُ الْمَلَكُ فَقَالَ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ خَلَقَ الْإِنْسَانَ مِنْ عَلَقٍ اقْرَأْ وَرَبُّكَ الْأَكْرَمُ }","id":"Telah menceritakan kepada kami [Ibnu Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Urwah] bahwa [Aisyah] radliallahu 'anha berkata, \"Peristiwa turunnya wahyu yang pertama kali kepadanya Rasulullah shallallahu 'alaihi wasallam adalah Ar Ru`yah Shalihah (mimpi yang baik). Yaitu malaikat mendatangi beliau seraya berkata, 'IQRA` BISMI RABBIKAL LADZII KHALAQ, KHALAQAL INSAANA MIN 'ALAQ, IQRA` WARABBUKAL AKRAM.'\""},"4269":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ ح وَقَالَ اللَّيْثُ حَدَّثَنِي عُقَيْلٌ قَالَ مُحَمَّدٌ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَوَّلُ مَا بُدِئَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا الصَّادِقَةُ جَاءَهُ الْمَلَكُ فَقَالَ{ اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ خَلَقَ الْإِنْسَانَ مِنْ عَلَقٍ اقْرَأْ وَرَبُّكَ الْأَكْرَمُ الَّذِي عَلَّمَ بِالْقَلَمِ }","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Abdurrazzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] -dalam riwayat lain- Dan [Al Laits] berkata; Telah menceritakan kepadaku ['Uqail] ia berkata; Telah berkata [Muhammad] Telah mengabarkan kepadaku [Urwah] dari [Aisyah] radliallahu 'anha. Wahyu yang pertama kali diturunkan kepada Rasulullah shallallahu 'alaihi wasallam adalah Ar Ru`yah Ash Shadiqah (mimpi yang benar). Ketika itu, Malaikat mendatanginya seraya berkata, \"IQRA` BISMI RABBIKAL LADZII KHALAQ, KHALAQAL INSAANA MIN 'ALAQ, IQRA` WARABBUKAL AKRAM ALLADZII 'ALLAMAL BIL QALAM.\""},"4270":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ سَمِعْتُ عُرْوَةَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَافَرَجَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَدِيجَةَ فَقَالَ زَمِّلُونِي زَمِّلُونِي فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] ia berkata; Aku mendengar [Urwah] berkata; [Aisyah] radliallahu 'anha berkata; Kemudian, Nabi shallallahu 'alaihi wasallam pun kembali kepada Khadijah seraya berkata, \"Selimutilah aku, selimutilah aku.\" Lalu ia pun menyebutkan hadits."},"4271":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ عِكْرِمَةَ قَالَ ابْنُ عَبَّاسٍقَالَ أَبُو جَهْلٍ لَئِنْ رَأَيْتُ مُحَمَّدًا يُصَلِّي عِنْدَ الْكَعْبَةِ لَأَطَأَنَّ عَلَى عُنُقِهِ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ فَعَلَهُ لَأَخَذَتْهُ الْمَلَائِكَةُتَابَعَهُ عَمْرُو بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ عَبْدِ الْكَرِيمِ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Abdul Karim Al Jazari] dari [Ikrimah] ia berkata; [Ibnu Abbas] berkata; Abu Jahal berkata, \"Jika aku melihat Muhammad shalat di Ka'bah, maka aku benar-benar akan mencekik lehernya.\" Kemudian, ungkapan itu pun akhirnya sampai kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Kalau dia benar melakukannya, maka niscaya Malaikat akan menghajarnya.\" Periwayatan hadits ini, diikuti pula (Muta'abah) oleh [Amru bin Khalid] dari [Ubaidullah] dari [Abdul Karim]."},"4272":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ سَمِعْتُ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُبَيٍّ إِنَّ اللَّهَ أَمَرَنِي أَنْ أَقْرَأَ عَلَيْكَ{ لَمْ يَكُنْ الَّذِينَ كَفَرُوا }قَالَ وَسَمَّانِي قَالَ نَعَمْ فَبَكَى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] Aku mendengar [Qatadah] dari [Anas bin Malik] radliallahu 'anhu, ia berakta; Nabi shallallahu 'alaihi wasallam bersabda kepada Ubbay bin Ka'ab, \"Sesungguhnya Allah telah memerintahkanku untuk membacakan Al Qur`an kepadamu. Yaitu ayat: 'LAM YAKUNIL LADZIINA KAFARUU..'\" Ubbay bertatanya, \"Apakah Allah juga menyebut namaku?.\" Beliau menjawab: \"Ya.\" Akhirnya, Ubbay pun menangis."},"4273":{"ar":"حَدَّثَنَا حَسَّانُ بْنُ حَسَّانَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُبَيٍّ إِنَّ اللَّهَ أَمَرَنِي أَنْ أَقْرَأَ عَلَيْكَ الْقُرْآنَ قَالَ أُبَيٌّ أَاللَّهُ سَمَّانِي لَكَ قَالَ اللَّهُ سَمَّاكَ لِي فَجَعَلَ أُبَيٌّ يَبْكِي قَالَ قَتَادَةُ فَأُنْبِئْتُ أَنَّهُ قَرَأَ عَلَيْهِ{ لَمْ يَكُنْ الَّذِينَ كَفَرُوا مِنْ أَهْلِ الْكِتَابِ }","id":"Telah menceritakan kepada kami [Hassan bin Hassan] Telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepada Ubbay bin Ka'ab: \"Sesungguhnya Allah memerintahkanku untuk membacakan Al Qur`an padamu.\" Ubbay bertanya, \"Apakah Allah menyebut dan memperdengarkan namaku pada Anda?\" beliau menjawab: \"Ya, Allah menyebutkan namamu padaku.\" Akhirnya Ubbay pun menangis terharu. Qatadah berkata; Telah diberitakan kepadaku, bahwa beliau pun membacakan Al Qur`an padanya yakni: \"LAM YAKUNIL LADZIINA KAFARUU MIN AHLIL KITAABI..\""},"4274":{"ar":"حَدَّثَنَا أَبُو جَعْفَرٍ الْمُنَادِي حَدَّثَنَا رَوْحٌ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأُبَيِّ بْنِ كَعْبٍ إِنَّ اللَّهَ أَمَرَنِي أَنْ أُقْرِئَكَ الْقُرْآنَ قَالَ أَاللَّهُ سَمَّانِي لَكَ قَالَ نَعَمْ قَالَ وَقَدْ ذُكِرْتُ عِنْدَ رَبِّ الْعَالَمِينَ قَالَ نَعَمْ فَذَرَفَتْ عَيْنَاهُ","id":"Telah menceritakan kepada kami [Abu Ja'far Al Munadi] Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Ubbay bin Ka'ab: \"Sesungguhnya Allah telah memerintahkan kepadaku untuk membacakan Al Qur`an kepadamu.\" Ubbay bin Ka'ab bertanya, \"Apakah Allah menyebut namaku pada Anda? ' beliau menjawab: \"Ya.\" Ubbay berkata, \"Sungguh benarkah, namaku telah disebut di sisi Rabb semesta alam?\" beliau menjawab: \"Ya.\" Lalu, kedua matanya pun meneteskan air."},"4275":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ لِثَلَاثَةٍ لِرَجُلٍ أَجْرٌ وَلِرَجُلٍ سِتْرٌ وَعَلَى رَجُلٍ وِزْرٌ فَأَمَّا الَّذِي لَهُ أَجْرٌ فَرَجُلٌ رَبَطَهَا فِي سَبِيلِ اللَّهِ فَأَطَالَ لَهَا فِي مَرْجٍ أَوْ رَوْضَةٍ فَمَا أَصَابَتْ فِي طِيَلِهَا ذَلِكَ فِي الْمَرْجِ وَالرَّوْضَةِ كَانَ لَهُ حَسَنَاتٍ وَلَوْ أَنَّهَا قَطَعَتْ طِيَلَهَا فَاسْتَنَّتْ شَرَفًا أَوْ شَرَفَيْنِ كَانَتْ آثَارُهَا وَأَرْوَاثُهَا حَسَنَاتٍ لَهُ وَلَوْ أَنَّهَا مَرَّتْ بِنَهَرٍ فَشَرِبَتْ مِنْهُ وَلَمْ يُرِدْ أَنْ يَسْقِيَ بِهِ كَانَ ذَلِكَ حَسَنَاتٍ لَهُ فَهِيَ لِذَلِكَ الرَّجُلِ أَجْرٌ وَرَجُلٌ رَبَطَهَا تَغَنِّيًا وَتَعَفُّفًا وَلَمْ يَنْسَ حَقَّ اللَّهِ فِي رِقَابِهَا وَلَا ظُهُورِهَا فَهِيَ لَهُ سِتْرٌ وَرَجُلٌ رَبَطَهَا فَخْرًا وَرِئَاءً وَنِوَاءً فَهِيَ عَلَى ذَلِكَ وِزْرٌ فَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحُمُرِ قَالَ مَا أَنْزَلَ اللَّهُ عَلَيَّ فِيهَا إِلَّا هَذِهِ الْآيَةَ الْفَاذَّةَ الْجَامِعَةَ{ فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ }","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] Telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari [Abu Shalih Asy Syamman] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang memiliki kuda itu ada tiga kelompok. Yaitu; Bagi seorang yang dengannya ia mendapatkan ganjaran pahala kebaikan. Kedua, seorang yang kudanya sebagai penjaga kehormatan (solusi, penyelesaian). Sedangkan yang terakhir, adalah seorang yang memiliki kuda, namun yang ia dapatkan hanyalah dosa. Bagi yang mendapatkan pahala adalah seseorang yang menggunakannya di jalan Allah, lalu ia meletakkannya di dalam pinggiran kolam atau kebun, maka apa yang ia makan atau minum di sutu adalah bernilai kebaikan untuknya. Atau ia meninggalkannya ditempat, lalu kuda itu pun menaiki satu bukit atau dua bukit, maka bekas kaki atau kotorannya adalah bernilai kebaikan untuknya. Dan bila kuda itu melewati aliran sungai lalu meminum air darinya, meskipun pemiliknya tidak bermaksud untuk memberinya minum, maka itu merupakan kebaikan baginya. Karena itulah, pemiliknya akan mendapatkan kebaikan yang banyak. Kemudian seorang yang memiliki kuda sebagai alat untuk mencari kekayaan dan menjaga kehormatan diri, namun ia juga tidak melupakan hal Allah pada leher dan punggung kudanya, maka kuda itu akan menjadi penyelesai kebutuhannya. Kemudian yang ketiga, adalah seorang yang memelihara kuda dengan maksud kebanggaan, dan riya`, maka karena itulah ia mendapatkan dosa.\" Kemudian Rasulullah shallallahu 'alaihi wasallam ditanya tentang Himar. Maka beliau pun bersabda: \"Allah tidak menurunkan ayat berkenaan dengannya kecuali ayat yang maknanya luas dan mencakup, 'FAMAN YA'MAL MITSQAALA DZARRAH KHAIRAN YARAH, WA MAN YA'MAL MITSQAALA DZARRATIN SYARRAN YARAH (Barangsiapa yang melakukan kebaikan sekecil biji Dzarrah, maka ia akan melihat pahalanya, dan siapa yang melakukan keburukan sekecil biji Dzarrah, niscaya juga akan melihat dampak buruknya).'\""},"4276":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحُمُرِ فَقَالَ لَمْ يُنْزَلْ عَلَيَّ فِيهَا شَيْءٌ إِلَّا هَذِهِ الْآيَةُ الْجَامِعَةُ الْفَاذَّةُ{ فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ }","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] ia berkata, Telah menceritakan kepadaku [Ibnu Wahb] ia berkata; Telah mengabarkan kepadaku [Malik] dari [Zaid bin Aslam] dari [Abu Shalih As Samman] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya; Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai himar(keledai), maka beliau pun menjawab: \"Belum pernah ada wahyu yang diturunkan padaku yang berbicara tentangnya kecuali ayat yang pendek lagi mencakup ini, 'FAMAN YA'MAL MITSQAALA DZARRAH KHAIRAN YARAH, WA MAN YA'MAL MITSQAALA DZARRATIN SYARRAN YARAH (Barangsiapa yang melakukan kebaikan sekecil biji Dzarrah, maka ia akan melihat pahalanya, dan siapa yang melakukan keburukan sekecil biji Dzarrah, niscaya juga akan melihat dampak buruknya). (QS. Azzalzalah 7-8)."},"4277":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا عُرِجَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى السَّمَاءِ قَالَ أَتَيْتُ عَلَى نَهَرٍ حَافَتَاهُ قِبَابُ اللُّؤْلُؤِ مُجَوَّفًا فَقُلْتُ مَا هَذَا يَا جِبْرِيلُ قَالَ هَذَا الْكَوْثَرُ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syaiban] Telah menceritakan kepada kami [Qatadah] dari [Anas] radliallahu 'anhu, Ia berkata; Ketika Nabi shallallahu 'alaihi wasallam mengalami peristiwa Mi'raj ke langit, beliau pun bersabda: \"Aku mendatangi telaga, pada kedua tepinya terdapat Qubah berongga yang terbuat dari mutiara. Maka aku pun bertanya, 'Apa ini wahai Jibril? ' Ia menjawab, 'Ini adalah Al Kautsar.'\""},"4278":{"ar":"حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ الْكَاهِلِيُّ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَسَأَلْتُهَا عَنْ قَوْلِهِ تَعَالَى{ إِنَّا أَعْطَيْنَاكَ الْكَوْثَرَ }قَالَتْ نَهَرٌ أُعْطِيَهُ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاطِئَاهُ عَلَيْهِ دُرٌّ مُجَوَّفٌ آنِيَتُهُ كَعَدَدِ النُّجُومِرَوَاهُ زَكَرِيَّاءُ وَأَبُو الْأَحْوَصِ وَمُطَرِّفٌ عَنْ أَبِي إِسْحَاقَ","id":"Telah menceritakan kepada kami [Khalid bin Yazid Al Kahili] Telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Abu Ubaidah] dari [Aisyah] radliallahu 'anha. Aku pernah bertanya kepadanya tentang firman Allah Ta'ala, \"INNAA A'THAINAAKAL KAUTSAR.\" Maka Aisyah pun menjawab, \"Itu adalah sungai yang telah diberikan kepada Nabi kalian shallallahu 'alaihi wasallam. Kedua tepinya terdapat mutiara yang berlubang. Bejana-bejana sejumlah bintang di langit. Hadits ini juga diriwayatkan oleh [Zakaria], [Abu Al Ahwash] dan [Mutharrif] dari [Abu Ishaq]."},"4279":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَفِي الْكَوْثَرِ هُوَ الْخَيْرُ الَّذِي أَعْطَاهُ اللَّهُ إِيَّاهُ قَالَ أَبُو بِشْرٍ قُلْتُ لِسَعِيدِ بْنِ جُبَيْرٍ فَإِنَّ النَّاسَ يَزْعُمُونَ أَنَّهُ نَهَرٌ فِي الْجَنَّةِ فَقَالَ سَعِيدٌ النَّهَرُ الَّذِي فِي الْجَنَّةِ مِنْ الْخَيْرِ الَّذِي أَعْطَاهُ اللَّهُ إِيَّاهُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Husyaim] Telah menceritakan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, bahwa ia berkata terkait dengan firman Allah: \"AL KAUTSAR.\" Ia menjelaskan, \"Itu adalah kebaikan yang diberikan Allah kepadanya.\" Abu Bisyr berkata; Aku berkata kepada Sa'id bin Jubair, \"Namun orang-orang menganggap bahwa hal itu adalah sungai yang ada di surga.\" Maka Sa'id pun berkata, \"Sungai yang ada di dalam surga, juga merupakan kebaikan yang diberikan Allah pada beliau.\""},"4280":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً بَعْدَ أَنْ نَزَلَتْ عَلَيْهِ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ إِلَّا يَقُولُ فِيهَا سُبْحَانَكَ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي","id":"Telah menceritakan kepada kami [Al Hasan bin Ar Rabi'] Telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dari [Aisyah] radliallahu 'anha, ia berkata; Nabi shallallahu 'alaihi wasallam tidak shalat setelah turunnya ayat, \"IDZAA JAA`A NASHRULLAHI WAL FATH.\" Kecuali di dalam shalatnya membaca: \"SUBHAANAKA RABBANAA WA BIHAMDIKA ALLAHUMMAGH FIRLII (Maha Suci Engkau, wahai Rabb kami, dan segala puji bagi-Mu. Ya Allah ampunilah aku).\""},"4281":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ أَنْ يَقُولَ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي يَتَأَوَّلُ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Dluha] dari [Masruq] dari [Aisyah] radliallahu 'anhu, ia berkata: Pada saat ruku' dan sujud, Rasulullah shallallahu 'alaihi wasallam memperbanyak membaca: \"ALLAHUMMA RABBANAA WABIHAMDIKA, ALLAHUMMAGHFIRLII (Ya Allah, Rabb kami, segala puji hanya bagi-Mu. Ya Allah, ampunilah aku).\" Beliau menghindari bacaan Al Qur`an."},"4282":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ عُمَرَ رَضِيَ اللَّهُ عَنْهُ سَأَلَهُمْ عَنْ قَوْلِهِ تَعَالَى إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ قَالُوا فَتْحُ الْمَدَائِنِ وَالْقُصُورِ قَالَ مَا تَقُولُ يَا ابْنَ عَبَّاسٍ قَالَ أَجَلٌ أَوْ مَثَلٌ ضُرِبَ لِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُعِيَتْ لَهُ نَفْسُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Syaibah] Telah menceritakan kepada kami [Abdurrahman] ia berkata; Telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwasanya Umar menanyakan kepada mereka (para pembesar Badar) mengenai firman Allah Ta'ala, \"IDZAA JAA`A NASHRULLAHI WAL FATH.\" Mereka menjawab: \"Yaitu, penaklukan kota-kota dan istana-istana.\" Umar berkata, \"Bagaimanakah pendapatmu wahai Ibnu Abbas? ' Ibnu Abbas menjawab, \"Maksudnya adalah ajal, atau suatu permisalan yang diberikan untuk Muhammad shallallahu 'alaihi wasallam bahwa ajal beliau telah dekat.\""},"4283":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ عُمَرُ يُدْخِلُنِي مَعَ أَشْيَاخِ بَدْرٍ فَكَأَنَّ بَعْضَهُمْ وَجَدَ فِي نَفْسِهِ فَقَالَ لِمَ تُدْخِلُ هَذَا مَعَنَا وَلَنَا أَبْنَاءٌ مِثْلُهُ فَقَالَ عُمَرُ إِنَّهُ مَنْ قَدْ عَلِمْتُمْ فَدَعَاهُ ذَاتَ يَوْمٍ فَأَدْخَلَهُ مَعَهُمْ فَمَا رُئِيتُ أَنَّهُ دَعَانِي يَوْمَئِذٍ إِلَّا لِيُرِيَهُمْ قَالَ مَا تَقُولُونَ فِي قَوْلِ اللَّهِ تَعَالَى إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ فَقَالَ بَعْضُهُمْ أُمِرْنَا أَنْ نَحْمَدَ اللَّهَ وَنَسْتَغْفِرَهُ إِذَا نُصِرْنَا وَفُتِحَ عَلَيْنَا وَسَكَتَ بَعْضُهُمْ فَلَمْ يَقُلْ شَيْئًا فَقَالَ لِي أَكَذَاكَ تَقُولُ يَا ابْنَ عَبَّاسٍ فَقُلْتُ لَا قَالَ فَمَا تَقُولُ قُلْتُ هُوَ أَجَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمَهُ لَهُ قَالَ إِذَا جَاءَ نَصْرُ اللَّهِ وَالْفَتْحُ وَذَلِكَ عَلَامَةُ أَجَلِكَ{ فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُ إِنَّهُ كَانَ تَوَّابًا }فَقَالَ عُمَرُ مَا أَعْلَمُ مِنْهَا إِلَّا مَا تَقُولُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; Suatu ketika Umar mengajakku masuk berkumpul bersama para syaikh pemuka-pemuka Badar, dan sepertinya, sebagian dari mereka memendam sesuatu pada dirinya. Maka salah seorang dari mereka pun bertanya, \"Kenapa Anda mengikutsertakan anak ini bersama kami, padahal kami juga memiliki anak-anak yang sebaya dengannya?\" Maka Umar pun berkata, \"Sesungguhnya anak itu mempunyai kecerdasan tersendiri seperti yang telah kalian kenal.\" Kemudian pada suatu hari, Umar memangilnya dan mengingutsertakannya bersama mereka. Ibnu Abbas berkata; Aku tahu, bahwa tidak ada maksud lain Umar memanggilku, kecuali untuk memperlihatkan aku pada mereka. Umar berkata, \"Bagaimanakah pendapat kalian berkenaan dengan ayat ini: 'IDZAA JAA`A NASHRULLAHI WAL FATH.'\" Maka sebagian dari mereka berkata, \"Kita diperintahkan untuk memuji Allah dan meminta maghfirah-Nya, yakni ketika kita diberi pertolongan dan kekuatan untuk menaklukkan suatu negeri.\" Lalu sebagian yang lain diam tak berkata sepatah kata pun. Setelah itu, Umar bertanya padaku, \"Apakah seperti itu juga pendapatmu wahai Ibnu Abbas?\" Aku menjawab, \"Tidak.\" Umar bertanya lagi, \"Lalu bagaimanakah pendapatmu?\" Aku menjawab, \"Hal itu terkait dengan ajal Rasulullah shallallahu 'alaihi wasallam, Allah telah memberitahukan padanya. Firman Allah: 'IDZAA JAA`A NASHRULLAHI WAL FATH.' Itu adalah alamat akan ajalmu. 'FASABBIH BIHAMDI RABBIKA WAS TAGHFIRHU INNAHU KAANA TAWWAABAA (Karena itu, sucikanlah Rabbu dengan memuji-Nya. Dan mintalah ampunan dari-Nya, sesungguhnya Dia Maha Menerima taubat).'\" Umar berkata, \"Tidak ada jawaban yang lebih tepat, kecuali apa yang telah kamu katakan.\""},"4284":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا نَزَلَتْ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }وَرَهْطَكَ مِنْهُمْ الْمُخْلَصِينَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى صَعِدَ الصَّفَا فَهَتَفَ يَا صَبَاحَاهْ فَقَالُوا مَنْ هَذَا فَاجْتَمَعُوا إِلَيْهِ فَقَالَ أَرَأَيْتُمْ إِنْ أَخْبَرْتُكُمْ أَنَّ خَيْلًا تَخْرُجُ مِنْ سَفْحِ هَذَا الْجَبَلِ أَكُنْتُمْ مُصَدِّقِيَّ قَالُوا مَا جَرَّبْنَا عَلَيْكَ كَذِبًا قَالَ فَإِنِّي نَذِيرٌ لَكُمْ بَيْنَ يَدَيْ عَذَابٍ شَدِيدٍ قَالَ أَبُو لَهَبٍ تَبًّا لَكَ مَا جَمَعْتَنَا إِلَّا لِهَذَا ثُمَّ قَامَ فَنَزَلَتْ{ تَبَّتْ يَدَا أَبِي لَهَبٍ وَتَبَّ }وَقَدْ تَبَّ هَكَذَا قَرَأَهَا الْأَعْمَشُ يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Amru bin Murrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; Ketika turunnya ayat: \"WA ANDZIR 'ASYIIRATAKAL AQRABIIN WA RAHBATHAKA MINHUMUL MUKHLASHIIN.\" Rasulullah shallallahu 'alaihi wasallam keluar hingga naik ke atas bukit Shafa dan menyerukan: \"Wahai sekalian manusia.\" Orang-orang Quraisy pun bertanya, \"Siapakah orang ini?\" akhirnya mereka pun berkumpul kepada beliau. Beliau bersabda: \"Bagaimana pendapat kalian, jika aku mengabarkan bahwa di balik bukit ada pasukan berkuda akan segera keluar (menerkam), apakah kalain akan membenarkanku?\" Mereka menjawab, \"Ya, kami belum pernah mendengar bahwa kamu berdusta.\" Beliau kemudian bersabda: \"Sesungguhnya aku adalah seorang pemberi peringatan bagi kalian bahwa di hadapanku ada adzab yang sangat pedih.\" Maka Abu Lahab pun berkata, \"Celaka kamu wahai Muhammad. Apakah hanya lantaran ini kamu mengumpulkan kami?\" Setelah itu, ia langsung beranjak, dan turunlah firman Allah, \"TABBAT YADAA ABIY LAHABIW WATAB.\" Hari itu, Al A'masy membacanya: \"WA QAD TABBAT (sungguh, ia memang telah celaka).\""},"4285":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْبَطْحَاءِ فَصَعِدَ إِلَى الْجَبَلِ فَنَادَى يَا صَبَاحَاهْ فَاجْتَمَعَتْ إِلَيْهِ قُرَيْشٌ فَقَالَ أَرَأَيْتُمْ إِنْ حَدَّثْتُكُمْ أَنَّ الْعَدُوَّ مُصَبِّحُكُمْ أَوْ مُمَسِّيكُمْ أَكُنْتُمْ تُصَدِّقُونِي قَالُوا نَعَمْ قَالَ فَإِنِّي نَذِيرٌ لَكُمْ بَيْنَ يَدَيْ عَذَابٍ شَدِيدٍ فَقَالَ أَبُو لَهَبٍ أَلِهَذَا جَمَعْتَنَا تَبًّا لَكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ تَبَّتْ يَدَا أَبِي لَهَبٍ }إِلَى آخِرِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Salam] Telah mengabarkan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Al A'masy] dari [Amru bin Murrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa suatu hari Nabi shallallahu 'alaihi wasallam keluar menuju Bathha`, kemudian beliau naik ke bukit seraya berseru, \"Wahai sekalian manusia.\" Maka orang-orang Quraisy pun berkumpul. Kemudian beliau bertanya, \"Bagaimana, sekiranya aku mengabarkan kepada kalian, bahwa musuh (di balik bukit ini) akan segera menyergap kalian, apakah kalian akan membenarkanku?\" mereka menjawab, \"Ya.\" Beliau bersabda lagi: \"Sesungguhnya aku adalah seorang pemberi peringatan bagi kalian. Sesungguhnya di hadapanku akan ada adzab yang pedih.\" Akhirnya Abu Lahab pun berkata, \"Apakah hanya karena itu kamu mengumpulkan kami? Sungguh kecelakanlah bagimu.\" Maka Allah menurunkan firman-Nya: \"TABBAT YADAA ABII LAHAB..\" Hingga akhir ayat."},"4286":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاقَالَ أَبُو لَهَبٍ تَبًّا لَكَ أَلِهَذَا جَمَعْتَنَا فَنَزَلَتْ{ تَبَّتْ يَدَا أَبِي لَهَبٍ }إِلَى آخِرِهَا","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepadaku [Amru bin Murrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; Abu Lahab berkata, \"Celaka kamu wahai (Muhammad), apakah hanya lantaran ini kamu mengumpulkan kami.\" Maka turunlah ayat: \"TABBAT YADAA ABII LAHAB..\" Hingga akhir ayat."},"4287":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ كَذَّبَنِي ابْنُ آدَمَ وَلَمْ يَكُنْ لَهُ ذَلِكَ وَشَتَمَنِي وَلَمْ يَكُنْ لَهُ ذَلِكَ فَأَمَّا تَكْذِيبُهُ إِيَّايَ فَقَوْلُهُ لَنْ يُعِيدَنِي كَمَا بَدَأَنِي وَلَيْسَ أَوَّلُ الْخَلْقِ بِأَهْوَنَ عَلَيَّ مِنْ إِعَادَتِهِ وَأَمَّا شَتْمُهُ إِيَّايَ فَقَوْلُهُ اتَّخَذَ اللَّهُ وَلَدًا وَأَنَا الْأَحَدُ الصَّمَدُ لَمْ أَلِدْ وَلَمْ أُولَدْ وَلَمْ يَكُنْ لِي كُفْئًا أَحَدٌ","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah menceritakan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah berfirman: 'Anak Adam telah mendustakan-Ku, padahal ia tidaklah mempunyai alasan sedikit pun. Dan ia juga telah mencemoohku padahal ia tidak mempunyai alasan melakukan hal itu. Ada pun kedustaanya padaku adalah ungkapannya, 'Dia tidak akan mengembalikanku sebagaimana ia telah menciptakanku pertama kali.' Padahal penciptaan yang pertama tidak lebih mudah daripada hanya sekedar mengembalikannya. Adapun pelecehannya pada-Ku adalah ungkapannya, 'Allah telah menjadikan anak untuk diri-Nya.' Sementara Aku adalah Rabb Yang Maha Esa, Yang tidak beranak dan tidak pula diperanakkan, dan tidak ada sesuatu pun yang serupa Dengan-Ku.'\""},"4288":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ قَالَ وَحَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ كَذَّبَنِي ابْنُ آدَمَ وَلَمْ يَكُنْ لَهُ ذَلِكَ وَشَتَمَنِي وَلَمْ يَكُنْ لَهُ ذَلِكَ أَمَّا تَكْذِيبُهُ إِيَّايَ أَنْ يَقُولَ إِنِّي لَنْ أُعِيدَهُ كَمَا بَدَأْتُهُ وَأَمَّا شَتْمُهُ إِيَّايَ أَنْ يَقُولَ اتَّخَذَ اللَّهُ وَلَدًا وَأَنَا الصَّمَدُ الَّذِي لَمْ أَلِدْ وَلَمْ أُولَدْ وَلَمْ يَكُنْ لِي كُفُؤًا أَحَدٌ{ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُؤًا أَحَدٌ }كُفُؤًا وَكَفِيئًا وَكِفَاءً وَاحِدٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] ia berkata; dan Telah menceritakan kepada kami [Abdurrazzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman: 'Anak Adam telah mendustakan-Ku, padahal ia tidaklah mempunyai alasan sedikit pun. Dan ia juga telah mencemoohku padahal ia tidak mempunyai alasan melakukan hal itu. Ada pun kedustaanya padaku adalah ungkapannya, 'Dia tidak akan mengembalikanku sebagaimana ia telah menciptakanku pertama kali.' Padahal mencipta pertama tidak lebih mudah daripada hanya sekedar mengembalikannya. Adapun pelecehannya pada-Ku adalah ungkapannya, 'Allah telah menjadikan anak untuk diri-Nya.' Sementara Aku adalah Rabb Yang Maha Esa, Yang tidak beranak dan tidak pula diperanakkan, dan tidak ada sesuatu pun yang serupa Dengan-Ku.'\" Firman Allah: \"LAM YALID WALAM YUULAD, WALAM YAKUN LAHUU KUFU`AN AHAD.\" Kufu`an, Kafii`an dan Kifaa`an maknanya adalah satu."},"4289":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ وَعَبْدَةَ عَنْ زِرِّ بْنِ حُبَيْشٍ قَالَ سَأَلْتُ أُبَيَّ بْنَ كَعْبٍعَنْ الْمُعَوِّذَتَيْنِ فَقَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قِيلَ لِي فَقُلْتُ فَنَحْنُ نَقُولُ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Sufyan] dari [Ashim] dan [Abdah] dari [Zirr bin Hubaisy] ia berkata; Aku pernya bertanya kepada [Ubbay bin Ka'ab] mengenai Al Mu'awwidzatain, maka ia pun menjawab; Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, lalu aku pun memperoleh jawaban. Maka aku pun berkata, \"Kalau begitu, kami akan mengatakan sebagaimana apa yang telah dikatakan oleh Rasulullah shallallahu 'alaihi wasallam.\""},"4290":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَبْدَةُ بْنُ أَبِي لُبَابَةَ عَنْ زِرِّ بْنِ حُبَيْشٍ ح وَحَدَّثَنَا عَاصِمٌ عَنْ زِرٍّ قَالَ سَأَلْتُ أُبَيَّ بْنَ كَعْبٍ قُلْتُيَا أَبَا الْمُنْذِرِ إِنَّ أَخَاكَ ابْنَ مَسْعُودٍ يَقُولُ كَذَا وَكَذَا فَقَالَ أُبَيٌّ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي قِيلَ لِي فَقُلْتُ قَالَ فَنَحْنُ نَقُولُ كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Abdah bin Abu Lubabah] dari [Zirr bin Hubaisy] -dalam riwayat lain- Dan Telah menceritakan kepada kami [Ashim] dari [Zirr] ia berkata; Aku bertanya kepada [Ubbay bin Ka'ab], aku katakan, \"Wahai Abu Mundzir, sesungguhnya saudaramu Ibnu Mas'ud mengatakan seperti ini dan itu.\" Maka Ubbay pun berkata, \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda padaku. Lalu dikatakanlah padaku, maka aku pun berkata, 'Akan tetapi, kami akan mengatakan sebagaimana apa yang telah dikatakan oleh Rasulullah shallallahu 'alaihi wasallam.'\""},"4291":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ أَخْبَرَتْنِي عَائِشَةُ وَابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ قَالَالَبِثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ عَشْرَ سِنِينَ يُنْزَلُ عَلَيْهِ الْقُرْآنُ وَبِالْمَدِينَةِ عَشْرَ سِنِينَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Syaiban] dari [Yahya] dari [Abu Salamah] ia berkata; Telah mengabarkan kepadaku [Aisyah] dan [Ibnu Abbas] radliallahu 'anhum, keduanya berkata; Nabi shallallahu 'alaihi wasallam berdiam diri di Makkah selama sepuluh tahun, dan Al Qur`an diturunkan kepada beliau. Sementara di Madinah adalah juga sepuluh tahun."},"4292":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي عَنْ أَبِي عُثْمَانَ قَالَ أُنْبِئْتُأَنَّ جِبْرِيلَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أُمُّ سَلَمَةَ فَجَعَلَ يَتَحَدَّثُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُمِّ سَلَمَةَ مَنْ هَذَا أَوْ كَمَا قَالَ قَالَتْ هَذَا دِحْيَةُ فَلَمَّا قَامَ قَالَتْ وَاللَّهِ مَا حَسِبْتُهُ إِلَّا إِيَّاهُ حَتَّى سَمِعْتُ خُطْبَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخْبِرُ خَبَرَ جِبْرِيلَ أَوْ كَمَا قَالَ قَالَ أَبِي قُلْتُ لِأَبِي عُثْمَانَ مِمَّنْ سَمِعْتَ هَذَا قَالَ مِنْ أُسَامَةَ بْنِ زَيْدٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Mu'tamir] ia berkata; Aku mendengar [bapakku] dari [Abu Utsman] ia berkata; Telah diberitakan kepadaku, bahwa Jibril mendatangi Nabi shallallahu 'alaihi wasallam, sementara di sisi beliau ada Ummu Salamah. Maka Jibril pun berbincang-bincang. Kemudian Nabi shallallahu 'alaihi wasallam bertanya kepada Ummu Salamah: \"Siapakah ini?\" Ia menjawab, \"Ini adalah Dihyah.\" Setelah beranjak, Ummu Salamah berkata, \"Demi Allah, tidaklah aku menduganya bahwa ia adalah Jibril, hingga aku mendengar Khuthbah Nabi shallallahu 'alaihi wasallam yang menyampaikan berita tentang Jibril.\" Atau sebagaimana yang dikatakan Abu Utsman. Aku bertanya kepada Abu Utsman, \"Dari mana Anda mendengar hadits ini?\" Ia menjawab, \"Dari [Usamah bin Zaid].\""},"4293":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ الْأَنْبِيَاءِ نَبِيٌّ إِلَّا أُعْطِيَ مَا مِثْلهُ آمَنَ عَلَيْهِ الْبَشَرُ وَإِنَّمَا كَانَ الَّذِي أُوتِيتُ وَحْيًا أَوْحَاهُ اللَّهُ إِلَيَّ فَأَرْجُو أَنْ أَكُونَ أَكْثَرَهُمْ تَابِعًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] Telah menceritakan kepada kami [Sa'id Al Maqburi] dari [bapaknya] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang Nabi pun kecuali telah diberi keistimewaan-keistimewaan khusus yang tidak diberikan kepada manusia lainnya sehingga orang-orang beriman padanya. Dan ada pun yang diberikan padaku adalah wahyu yang Allah turunkan kepadaku. Maka aku berharap, bahwa adalah Nabi yang paling banyak pengikutnya pada hari kiamat.\""},"4294":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ اللَّهَ تَعَالَى تَابَعَ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَحْيَ قَبْلَ وَفَاتِهِ حَتَّى تَوَفَّاهُ أَكْثَرَ مَا كَانَ الْوَحْيُ ثُمَّ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ","id":"Telah menceritakan kepada kami [Amru bin Muhammad] Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [bapakku] dari [Shalih bin Kaisan] dari [Ibnu Syihab] ia berkata, Telah mengabarkan kepadaku [Anas bin Malik] radliallahu 'anhu, bahwa Allah telah menurunkan wahyu secara berturut-turut kepada Rasulullah shallallahu 'alaihi wasallam sebelum wafatnya, setelah turunnya wahyu sempurnya, maka wafatlah Rasulullah shallallahu 'alaihi wasallam."},"4295":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ قَالَ سَمِعْتُ جُنْدَبًا يَقُولُاشْتَكَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَقُمْ لَيْلَةً أَوْ لَيْلَتَيْنِ فَأَتَتْهُ امْرَأَةٌ فَقَالَتْ يَا مُحَمَّدُ مَا أُرَى شَيْطَانَكَ إِلَّا قَدْ تَرَكَكَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَالضُّحَى وَاللَّيْلِ إِذَا سَجَى مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Al Aswad bin Qais] ia berkata, Aku mendengar [Jundub] berkata; Rasulullah shallallahu 'alaihi wasallam pernah jatuh sakit hingga beliau tidak bisa bangun selama sehari atau dua hari, maka seorang wanita pun datang kepada beliau dan berkata, \"Wahai Muhammad, tidaklah aku melihat syetanmu itu, kecuali ia telah meninggalkanmu.\" Maka Allah 'azza wajalla menurunkan ayat: \"WADLDLUHAA WALLAILI IDZAA SAJAA MAA WADDA'AKA RABBUKA WAMAA QALAA (Demi waktu Dluha. Dan demi waktu malam ketika tiba. Sesungguhnya Tuhan-mu tidaklah meninggalkanmu). (QS. Adhdhuha 1-3)."},"4296":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ وَأَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ قَالَفَأَمَرَ عُثْمَانُ زَيْدَ بْنَ ثَابِتٍ وَسَعِيدَ بْنَ الْعَاصِ وَعَبْدَ اللَّهِ بْنَ الزُّبَيْرِ وَعَبْدَ الرَّحْمَنِ بْنَ الْحَارِثِ بْنِ هِشَامٍ أَنْ يَنْسَخُوهَا فِي الْمَصَاحِفِ وَقَالَ لَهُمْ إِذَا اخْتَلَفْتُمْ أَنْتُمْ وَزَيْدُ بْنُ ثَابِتٍ فِي عَرَبِيَّةٍ مِنْ عَرَبِيَّةِ الْقُرْآنِ فَاكْتُبُوهَا بِلِسَانِ قُرَيْشٍ فَإِنَّ الْقُرْآنَ أُنْزِلَ بِلِسَانِهِمْ فَفَعَلُوا","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] Dan Telah mengabarkan kepadaku [Anas bin Malik] ia berkata; Utsman memerintahkan kepada Zaid bin Tsabit, Sa'id bin Al 'Ash, Abdullah bin Zubair dan Abdurrahman bin Al Harits bin Hisyam untuk menyalin Al Qur`an ke dalam Mushaf (pembukuan Alquran). Dan Utsman berkata pada mereka, \"Jika kalian berselisih dengan Zaid dalam masalah bahasa Arab Al Qur`an, maka tulislah berdasarkan lisannya bangsa Quraisy, sebab Al Qur`an dengan bahasa mereka.\" Maka mereka pun melakukannya."},"4297":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءٌ وَقَالَ مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ قَالَ أَخْبَرَنِي صَفْوَانُ بْنُ يَعْلَى بْنِ أ��مَيَّةَ أَنَّ يَعْلَى كَانَ يَقُولُلَيْتَنِي أَرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ يُنْزَلُ عَلَيْهِ الْوَحْيُ فَلَمَّا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْجِعْرَانَةِ عَلَيْهِ ثَوْبٌ قَدْ أَظَلَّ عَلَيْهِ وَمَعَهُ نَاسٌ مِنْ أَصْحَابِهِ إِذْ جَاءَهُ رَجُلٌ مُتَضَمِّخٌ بِطِيبٍ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ تَرَى فِي رَجُلٍ أَحْرَمَ فِي جُبَّةٍ بَعْدَ مَا تَضَمَّخَ بِطِيبٍ فَنَظَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاعَةً فَجَاءَهُ الْوَحْيُ فَأَشَارَ عُمَرُ إِلَى يَعْلَى أَنْ تَعَالَ فَجَاءَ يَعْلَى فَأَدْخَلَ رَأْسَهُ فَإِذَا هُوَ مُحْمَرُّ الْوَجْهِ يَغِطُّ كَذَلِكَ سَاعَةً ثُمَّ سُرِّيَ عَنْهُ فَقَالَ أَيْنَ الَّذِي يَسْأَلُنِي عَنْ الْعُمْرَةِ آنِفًا فَالْتُمِسَ الرَّجُلُ فَجِيءَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَّا الطِّيبُ الَّذِي بِكَ فَاغْسِلْهُ ثَلَاثَ مَرَّاتٍ وَأَمَّا الْجُبَّةُ فَانْزِعْهَا ثُمَّ اصْنَعْ فِي عُمْرَتِكَ كَمَا تَصْنَعُ فِي حَجِّكَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Hamam] Telah menceritakan kepada kami ['Atha`] sementara [Musaddad] berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] ia berkata; Telah mengabarkan kepadaku ['Ahta`] ia berkata; Telah mengabarkan [Shafwan bin Ya'la bin Umayyah] bahwa [Ya'laa] berkata; Duh sekiranya aku dapat melihat gelagat Rasulullah shallallahu 'alaihi wasallam ketika wahyu diturunkan pada beliau. Maka ketika Nabi shallallahu 'alaihi wasallam berada di Ji'ranah, beliau bernaung di bawah kain yang beliau kenakan dan beliau ditemani oleh beberapa orang sahabatnya. Tiba-tiba beliau didatangi oleh seseorang yang telah mengenakan wewangian. Laki-laki itu bertanya, \"Wahai Rasulullah, bagaimakah pendapat Anda terhadap seorang laki-laki yang melakukan ihram dengan mengenakan Jubah setelah melumurinya dengan wewangian.\" Sesaat kemudian, datanglah Ya'la, lalu ia pun memasukkan kepalanya, ternyata ia mendapati wajah Rasulullah shallallahu 'alaihi wasallam yang telah memerah. Keadaan itu berlangsung sesaat, lalu kembali seperti semula. Kemudian beliau bertanya: \"Manakah orang yang tadi bertanya kepadaku tentang Umrah?\" Maka laki-laki itu pun dicari dan dihadapkan pada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Mengenai wewangiat yang masih melekat pada tubuhmu, maka cucilah sebanyak tiga kali, sedangkan jubah itu lepaskanlah. Lakukanlah pada umrahmu sebagaimana apa kamu lakukan pada ibadah hajimu.\""},"4298":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ بْنِ السَّبَّاقِ أَنَّ زَيْدَ بْنَ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَرْسَلَ إِلَيَّ أَبُو بَكْرٍ مَقْتَلَ أَهْلِ الْيَمَامَةِ فَإِذَا عُمَرُ بْنُ الْخَطَّابِ عِنْدَهُ قَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ إِنَّ عُمَرَ أَتَانِي فَقَالَ إِنَّ الْقَتْلَ قَدْ اسْتَحَرَّ يَوْمَ الْيَمَامَةِ بِقُرَّاءِ الْقُرْآنِ وَإِنِّي أَخْشَى أَنْ يَسْتَحِرَّ الْقَتْلُ بِالْقُرَّاءِ بِالْمَوَاطِنِ فَيَذْهَبَ كَثِيرٌ مِنْ الْقُرْآنِ وَإِنِّي أَرَى أَنْ تَأْمُرَ بِجَمْعِ الْقُرْآنِ قُلْتُ لِعُمَرَ كَيْفَ تَفْعَلُ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُمَرُ هَذَا وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ عُمَرُ يُرَاجِعُنِي حَتَّى شَرَحَ اللَّهُ صَدْرِي لِذَلِكَ وَرَأَيْتُ فِي ذَلِكَ الَّذِي رَأَى عُمَرُ قَالَ زَيْدٌ قَالَ أَبُو بَكْرٍ إِنَّكَ رَجُلٌ شَابٌّ عَاقِلٌ لَا نَتَّهِمُكَ وَقَدْ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَتَبَّعْ الْقُرْآنَ فَاجْمَعْهُ فَوَاللَّهِ لَوْ كَلَّفُونِي نَقْلَ جَبَلٍ مِنْ الْجِبَالِ مَا كَانَ أَثْقَلَ عَلَيَّ مِمَّا أَمَرَنِي بِهِ مِنْ جَمْعِ الْقُرْآنِ قُلْتُ كَيْفَ تَفْعَلُونَ شَيْئًا لَمْ يَفْعَلْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هُوَ وَاللَّهِ خَيْرٌ فَلَمْ يَزَلْ أَبُو بَكْرٍ يُرَاجِعُنِي حَتَّى شَرَحَ اللَّهُ صَدْرِي لِلَّذِي شَرَحَ لَهُ صَدْرَ أَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَتَتَبَّعْتُ الْقُرْآنَ أَجْمَعُهُ مِنْ الْعُسُبِ وَاللِّخَافِ وَصُدُورِ الرِّجَالِ حَتَّى وَجَدْتُ آخِرَ سُورَةِ التَّوْبَةِ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ }حَتَّى خَاتِمَةِ بَرَاءَةَ فَكَانَتْ الصُّحُفُ عِنْدَ أَبِي بَكْرٍ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ عِنْدَ عُمَرَ حَيَاتَهُ ثُمَّ عِنْدَ حَفْصَةَ بِنْتِ عُمَرَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Musa bin Isa'il] dari [Ibrahim bin Sa'd] Telah menceritakan kepada kami [Ibnu Syihab] dari [Ubaid bin As Sabbaq] bahwa [Zaid bin Tsabit] radliallahu 'anhu, ia berkata; Abu Bakar mengirim para korban perang Yamamah kepadaku, dan ternyata Umar bin Al Khaththab ada di sisinya. Abu Bakar radliallahu 'anhu berkata, \"Sesungguhnya Umar mendatangiku dan berkata, 'Mayoritas korban perang Yamamah adalah para penghafal Al Qur`an. Dengan gugurnya mayoritas penghafal Al Qur`an, maka aku khawatir sebagian besar Al Qur`an juga akan hilang. Maka aku berpendapat, sebaiknya Anda segera memerintahkan guna melakukan dokumentasi alquran.' Maka aku pun bertanya kepada Umar, 'Bagaimana kamu akan melakukan sesuatu yang belum pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam? ' Umar menjawab, 'Perkara ini, demi Allah adalah ide yang baik.' Umar selalu membujukku hingga Allah memberikan kelapangan dadaku, dan akhirnya aku sependapat dengan Umar.\" Zaid berkata; Abu Bakar berkata, \"Sesungguhnya kamu adalah seorang pemuda yang cerdas, kami sama sekali tidak curiga sedikit pun padamu. Dan sungguh, kamulah yang telah menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam. Karena itu, telusurilah Al Qur`an dan kumpulkanlah.\" Zaid berkata, \"Demi Allah, sekiranya mereka memerintahkanku untuk memindahkan gunung, niscaya hal itu tidaklah lebih berat daripada apa yang mereka perintahkan padaku, yakni dokumentasi alquran.\" Zaid bertanya, \"Bagaimana kalian melakukan sesuatu yang belum pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam?\" Ia menjawab, \"Demi Allah, itu adalah kebaikan.\" Abu Bakar terus membujukku, hinnga Allah pun memberikan kelapangan dadaku, sebagaimana Abu Bakar dan Umar radliallahu 'anhuma. Maka aku pun mulai menelusuri Al Qur`an, mengumpulkannya dari tulang-tulang, kulit-kulit dan dari hafalan para Qari`. Dan akhirnya aku pun mendapatkan bagian akhir dari surat At Taubah bersama Abu Khuzaimah Al Anshari, yang aku tidak mendapatkannya pada seorang pun selainnya. Yakni ayat: 'Sungguh, telah datang pada kalian seorang Rasul dari kaum kalian sendiri, yang sangat berat olehnya kesulitan yang menimpa kalian..'\" hingga akhir surat Al Bara`ah. Lembaran-lembaran Al Qur`an itu pun tetap tersimpan pada Abu Bakar hingga Allah mewafatkannya. Kemudian beralih kepada Umar semasa hidupnya, lalu berpindah lagi ke tangan Hafshah binti Umar radliallahu 'anhu."},"4299":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا إِبْرَاهِيمُ حَدَّثَنَا ابْنُ شِهَابٍ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُ أَنَّ حُذَيْفَةَ بْنَ الْيَمَانِ قَدِمَ عَلَى عُثْمَانَ وَكَانَ يُغَازِي أَهْلَ الشَّأْمِ فِي فَتْحِ إِرْمِينِيَةَ وَأَذْرَبِيجَانَ مَعَ أَهْلِ الْعِرَاقِ فَأَفْزَعَ حُذَيْفَةَ اخْتِلَافُهُمْ فِي الْقِرَاءَةِ فَقَالَ حُذَيْفَةُ لِعُثْمَانَ يَا أَمِيرَ الْمُؤْمِنِينَ أَدْرِكْ هَذِهِ الْأُمَّةَ قَبْلَ أَنْ يَخْتَلِفُوا فِي الْكِتَابِ اخْتِلَافَ الْيَهُودِ وَالنَّصَارَى فَأَرْسَلَ عُثْمَانُ إِلَى حَفْصَةَ أَنْ أَرْسِلِي إِلَيْنَا بِالصُّحُفِ نَنْسَخُهَا فِي الْمَصَاحِفِ ثُمَّ نَرُدُّهَا إِلَيْكِ فَأَرْسَلَتْ بِهَا حَفْصَةُ إِلَى عُثْمَانَ فَأَمَرَ زَيْدَ بْنَ ثَابِتٍ وَعَبْدَ اللَّهِ بْنَ الزُّبَيْرِ وَسَعِيدَ بْنَ الْعَاصِ وَعَبْدَ الرَّحْمَنِ بْنَ الْحَارِثِ بْنِ هِشَامٍ فَنَسَخُوهَا فِي الْمَصَاحِفِ وَقَالَ عُثْمَانُ لِلرَّهْطِ الْقُرَشِيِّينَ الثَّلَاثَةِ إِذَا اخْتَلَفْتُمْ أَنْتُمْ وَزَيْدُ بْنُ ثَابِتٍ فِي شَيْءٍ مِنْ الْقُرْآنِ فَاكْتُبُوهُ بِلِسَانِ قُرَيْشٍ فَإِنَّمَا نَزَلَ بِلِسَانِهِمْ فَفَعَلُوا حَتَّى إِذَا نَسَخُوا الصُّحُفَ فِي الْمَصَاحِفِ رَدَّ عُثْمَانُ الصُّحُفَ إِلَى حَفْصَةَ وَأَرْسَلَ إِلَى كُلِّ أُفُقٍ بِمُصْحَفٍ مِمَّا نَسَخُوا وَأَمَرَ بِمَا سِوَاهُ مِنْ الْقُرْآنِ فِي كُلِّ صَحِيفَةٍ أَوْ مُصْحَفٍ أَنْ يُحْرَقَ قَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي خَارِجَةُ بْنُ زَيْدِ بْنِ ثَابِتٍ سَمِعَ زَيْدَ بْنَ ثَابِتٍ قَالَفَقَدْتُ آيَةً مِنْ الْأَحْزَابِ حِينَ نَسَخْنَا الْمُصْحَفَ قَدْ كُنْتُ أَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهَا فَالْتَمَسْنَاهَا فَوَجَدْنَاهَا مَعَ خُزَيْمَةَ بْنِ ثَابِتٍ الْأَنْصَارِيِّ{ مِنْ الْمُؤْمِنِينَ رِجَالٌ صَدَقُوا مَا عَاهَدُوا اللَّهَ عَلَيْهِ }فَأَلْحَقْنَاهَا فِي سُورَتِهَا فِي الْمُصْحَفِ","id":"Telah menceritakan kepada kami [Musa] Telah menceritakan kepada kami [Ibrahim] Telah menceritakan kepada kami [Ibnu Syihab] bahwasanya [Anas bin Malik] telah menceritakan kepadanya, bahwasanya; Hudzaifah bin Al Yamani datang kepada Utsman setelah sebelumnya memerangi Ahlus Syam yakni pada saat penaklukan Armenia dan Azerbaijan bersama penduduk Irak. Dan ternyata perselisihan mereka dalam Qira`ah mengejutkan Hudzaifah. Maka Hudzaifah pun berkata kepada Utsman, \"Rangkullah ummat ini sebelum mereka berselisih tentang Al Qur`an sebagaimana perselisihan yang telah terjadi pada kaum Yahudi dan Nasrani.\" Akhirnya, Utsman mengirim surat kepada Hafshah yang berisikan, \"Tolong, kirimkanlah lembaran alquran kepada kami, agar kami dapat segera menyalinnya ke dalam lembaran yang lain, lalu kami akan segera mengembalikannya pada Anda.\" Maka Hafshah pun mengirimkannya kepada Utsman. Lalu Utsman memerintahkan kepada Zaid bin Tsabit, Abdullah bin Zubair, Sa'id bin Al Ash dan Abdurrahman bin Al Harits bin Hisyam, sehingga mereka pun menyalinnya ke dalam lembaran shuhuf yang lain. Utsman berkata kepada tiga orang Quraisy dari mereka, \"Jika kalian berselisih dengan Zaid bin Tsabit terkait dengan Al Qur`an, maka tulislah dengan bahasa Quraisy, sebab Al Qur`an turun dengan bahasa mereka.\" Kemudian mereka mengindahkan perintah itu hingga penyalinan selesai dan Utsman pun mengembalikannya ke Hafshah. Setelah itu, Utsman mengirimkan sejumlah Shuhuf yang telah disalin ke berbagai penjuru negeri kaum muslimin, dan memerintahkan untuk membakar Al Qur`an yang terdapat pada selain Shuhuf tersebut. Ibnu Syihab berkata; [Kharijah bin Zaid] telah mengabarkan kepadaku bahwa ia mendengar [Zaid bin Tsabit] berkata, \"Kami kehilangan satu ayat dari surat Al Ahzab saat kami menyalinnya, yang sungguh aku telah mendengarnya langsung dari Rasulullah shallallahu 'alaihi wasallam saat beliau membacanya. Lalu kami pun mencarinya, dan ternyata kami menemukannya pada Khuzaimah bin Tsabit Al Anshari. Yakni ayat, \"MINAL MUKMINIINA RIJAALUN SHADAQUU MAA 'AAHADUU ALLAAHA 'ALAIHI.\" Maka kami pun menggabungkannya di dalam mushhaf."},"4300":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ أَنَّ ابْنَ السَّبَّاقِ قَالَ إِنَّ زَيْدَ بْنَ ثَابِتٍ قَالَأَرْسَلَ إِلَيَّ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ قَالَ إِنَّكَ كُنْتَ تَكْتُبُ الْوَحْيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاتَّبِعْ الْقُرْآنَ فَتَتَبَّعْتُ حَتَّى وَجَدْتُ آخِرَ سُورَةِ التَّوْبَةِ آيَتَيْنِ مَعَ أَبِي خُزَيْمَةَ الْأَنْصَارِيِّ لَمْ أَجِدْهُمَا مَعَ أَحَدٍ غَيْرِهِ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ }إِلَى آخِرِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Yunus] Telah menceritakan kepada kami [Ibnu Syihab] bahwa [Ibnu As Sabbaq] berkata; [Zaid bin Tsabit] berkata; Abu Bakar pernah mengutus seseorang padaku seraya mengatakan, \"Sesungguhnya, kamulah yang pernah menulis wahyu untuk Rasulullah shallallahu 'alaihi wasallam. Karena itu, telusurilah Al Qur`an.\" Maka aku pun segera menelusurinya, hingga aku mendapati akhir dari surat At Taubah, yakni dua ayat bersama Abu Khuzaimah Al Anshari, yang aku tidak mendapatkannya pada seorang pun selainnya. Yakni, \"LAQAD JAA`AKUM RASUULUM MIN ANFUSIKUM 'AZIIZUN 'ALAIHI MAA 'ANITTUM..\" Hingga akhir ayat."},"4301":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ قَالَلَمَّا نَزَلَتْ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْعُ لِي زَيْدًا وَلْيَجِئْ بِاللَّوْحِ وَالدَّوَاةِ وَالْكَتِفِ أَوْ الْكَتِفِ وَالدَّوَاةِ ثُمَّ قَالَ اكْتُبْ{ لَا يَسْتَوِي الْقَاعِدُونَ }وَخَلْفَ ظَهْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمْرُو بْنُ أُمِّ مَكْتُومٍ الْأَعْمَى قَالَ يَا رَسُولَ اللَّهِ فَمَا تَأْمُرُنِي فَإِنِّي رَجُلٌ ضَرِيرُ الْبَصَرِ فَنَزَلَتْ مَكَانَهَا{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }{ وَالْمُجَاهِدُونَ فِي سَبِيلِ اللَّهِ }{ غَيْرُ أُولِي الضَّرَرِ }","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Abu Ishaq] dari [Al Baraa`] ia berkata; Ketika turunnya ayat, \"LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FI SABIILILLAH (Tidaklah sama antara orang-orang yang duduk dari kaum mukminin dengan para Mujahid yang berjuang di jalan Allah).\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Panggilkanlah Zaid bin Tsabit, dan hendaklah ia membawa alat tulis dan tinta serta tulang.\" Kemudian beliau bersabda: \"Tuliskanlah: 'LAA YASTAWIL QAA`IDUUNA...'\" Sementara saat itu, pas di belakang Rasulullah shallallahu 'alaihi wasallam ada Amru bin Ummu Maktum Al A'ma, ia berkata, \"Wahai Rasulullah, apa yang mau Anda perintahkan kepadaku? Aku adalah seorang yang buta tak bisa melihat.\" Maka turunlah ayat: \"LAA YASTAWIL QAA'IDUUNA MINAL MUKMINIINA WAL MUJAAHIDUUNA FI SABIILILLAH GHAIRA ULIDL DLARARA (Tidaklah sama antara orang-orang yang duduk dari kaum mukminin dengan para Mujahid yang berjuang di jalan Allah, kecuali bagi yang memiliki udzur yang syari'). (QS. Annisa'; 95)."},"4302":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقْرَأَنِي جِبْرِيلُ عَلَى حَرْفٍ فَرَاجَعْتُهُ فَلَمْ أَزَلْ أَسْتَزِيدُهُ وَيَزِيدُنِي حَتَّى انْتَهَى إِلَى سَبْعَةِ أَحْرُفٍ","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] ia berkata; Telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] ia berkata; Telah menceritakan kepadaku [Ubaidullah] bahwa [Abdullah bin Abbas] radliallahu 'anhuma telah menceritakan kepadanya bahwa; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril telah membacakan padaku dengan satu dialek, maka aku pun kembali kepadanya untuk meminta agar ditambahkan, begitu berulang-ulang hingga berakhirlah dengan Sab'atu Ahruf (Tujuh dialek yang berbeda).\""},"4303":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ الْقَارِيَّ حَدَّثَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ لِقِرَاءَتِهِ فَإِذَا هُوَ يَقْرَأُ عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَتَصَبَّرْتُ حَتَّى سَلَّمَ فَلَبَّبْتُهُ بِرِدَائِهِ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَأُ قَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ كَذَبْتَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَقْرَأَنِيهَا عَلَى غَيْرِ مَا قَرَأْتَ فَانْطَلَقْتُ بِهِ أَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ بِسُورَةِ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ اقْرَأْ يَا هِشَامُ فَقَرَأَ عَلَيْهِ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَلِكَ أُنْزِلَتْ ثُمَّ قَالَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُ الْقِرَاءَةَ الَّتِي أَقْرَأَنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَلِكَ أُنْزِلَتْ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] ia berkata, Telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] ia berkata; Telah menceritakan kepadaku [Urwah bin Zubair] bahwa [Al Miswar bin Makhzamah] dan [Abdurrahman bin Abd Al Qari`] keduanya menceritakan kepadanya bahwa keduanya mendengar [Umar bin Al Khaththab] berkata, \"Aku pernah mendengar Hisyam bin Hakim bin Hizam sedang membaca surat Al Furqan di masa Rasulullah shallallahu 'alaihi wasallam, aku pun mendengarkan bacaannya dengan seksama. Maka, ternyata ia membacakan dengan huruf yang banyak yang Rasulullah shallallahu 'alaihi wasallam belum pernah membacakannya seperti itu padaku. Maka aku hampir saja mencekiknya saat shalat, namun aku pun bersabar menunggu sampai ia selesai salam. Setelah itu, aku langsung meninting lengan bajunya seraya bertanya, \"Siapa yang membacakan surat ini yang telah aku dengan ini kepadamu?\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam yang telah membacakannya padaku.\" Aku katakan, \"Kamu telah berdusta. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah membacakannya padaku, namun tidak sebagaimana apa yang engkau baca.\" Maka aku pun segera menuntunnya untuk menemui Rasulullah shallallahu 'alaihi wasallam. Selanjutnya, kukatakan kepada beliau, \"Sesungguhnya aku mendengar orang ini membaca surat Al Furqan dengan huruf (dialek bacaan) yang belum pernah Anda bacakan kepadaku.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Bacalah wahai Hisyam.\" Lalu ia pun membaca dengan bacaan yang telah aku dengar sebelumnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Begitulah ia diturunkan.\" Kemudian beliau bersabda: \"Bacalah wahai Umar.\" Maka aku pun membaca dengan bacaan sebagaimana yang dibacakan oleh Rasulullah shallallahu 'alaihi wasallam kepadaku. Setelah itu, beliau bersabda: \"Seperti itulah surat itu diturunkan. Sesungguhnya Al Qur`an ini diturunkan dengan tujuh huruf (tujuh dialek bacaan). Maka bacalah ia, sesuai dengan dialek bacaan yang kalian bisa.\""},"4304":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ وَأَخْبَرَنِي يُوسُفُ بْنُ مَاهَكٍ قَالَإِنِّي عِنْدَ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا إِذْ جَاءَهَا عِرَاقِيٌّ فَقَالَ أَيُّ الْكَفَنِ خَيْرٌ قَالَتْ وَيْحَكَ وَمَا يَضُرُّكَ قَالَ يَا أُمَّ الْمُؤْمِنِينَ أَرِينِي مُصْحَفَكِ قَالَتْ لِمَ قَالَ لَعَلِّي أُوَلِّفُ الْقُرْآنَ عَلَيْهِ فَإِنَّهُ يُقْرَأُ غَيْرَ مُؤَلَّفٍ قَالَتْ وَمَا يَضُرُّكَ أَيَّهُ قَرَأْتَ قَبْلُ إِنَّمَا نَزَلَ أَوَّلَ مَا نَزَلَ مِنْهُ سُورَةٌ مِنْ الْمُفَصَّلِ فِيهَا ذِكْرُ الْجَنَّةِ وَالنَّارِ حَتَّى إِذَا ثَابَ النَّاسُ إِلَى الْإِسْلَامِ نَزَلَ الْحَلَالُ وَالْحَرَامُ وَلَوْ نَزَلَ أَوَّلَ شَيْءٍ لَا تَشْرَبُوا الْخَمْرَ لَقَالُوا لَا نَدَعُ الْخَمْرَ أَبَدًا وَلَوْ نَزَلَ لَا تَزْنُوا لَقَالُوا لَا نَدَعُ الزِّنَا أَبَدًا لَقَدْ نَزَلَ بِمَكَّةَ عَلَى مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنِّي لَجَارِيَةٌ أَلْعَبُ{ بَلْ السَّاعَةُ مَوْعِدُهُمْ وَالسَّاعَةُ أَدْهَى وَأَمَرُّ }وَمَا نَزَلَتْ سُورَةُ الْبَقَرَةِ وَالنِّسَاءِ إِلَّا وَأَنَا عِنْدَهُ قَالَ فَأَخْرَجَتْ لَهُ الْمُصْحَفَ فَأَمْلَتْ عَلَيْهِ آيَ السُّوَرِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, ia berkata; Dan Telah mengabarkan kepadaku [Yusuf bin Mahik] ia berkata; Suatu ketika, aku berada di tempat Aisyah Ummul Mukminin radliallahu 'anha, tiba-tiba seorang dari Irak menemuinya seraya berkata, \"Kain kafan yang bagaimanakah yang lebih baik?\" Aisyah menjawab, \"Huss kamu, apakah yang menimpamu?\" laki-laki itu berkata, \"Wahai Ummul Mukminin, tunjukkanlah Mushhaf Anda padaku.\" [Aisyah] bertanya, \"Untuk apa?\" Ia menjawab, \"Agar aku dapat menyusunnya. Sebab, Al Qur`an itu dibaca secara tidak tersusun.\" Aisyah berkata, \"Lalu apa yang menghalangimu untuk membaca bagian apa saja darinya. Sesungguhnya yang pertama-tama kali turun darinya adalah surat Al Mufashshal yang di dalamnya disebutkan tentang surga dan neraka. Dan ketika manusia telah condong ke Islam, maka turunlah kemudian ayat-ayat tentang halal dan haram. Sekiranya yang pertama kali turun adalah ayat, 'Janganlah kalian minum khamer.' Niscaya mereka akan mengatakan, 'Sekali-kali kami tidak akan bisa meninggalkan khamer selama-lamanya.' Dan sekiranya juga yang pertamakali turun adalah ayat, \"Janganlah kalian berzina..' niscaya mereka akan berkomentar, 'Kami tidak akan meniggalkan zina selama-lamanya.' Ayat yang diturunkan kepada Rasulullah shallallahu 'alaihi wasallam di Makkah yang pada saat itu aku masih anak-anak adalah: 'BAL AS SAA'ATU MAU'IDUHUM WAS SAA'ATU ADHAA WA AMARR.(QS. ALqamar 46).' Dan tidaklah surat Al Baqarah dan An Nisa` kecuali aku berada di sisi beliau.\" Akhirnya, Aisyah mengeluarkan Mushhaf dan mendiktekan kepada orang Irak itu beberapa surat."},"4305":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ بْنِ قَيْسٍ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُفِي بَنِي إِسْرَائِيلَ وَالْكَهْفِ وَمَرْيَمَ وَطه وَالْأَنْبِيَاءِ إِنَّهُنَّ مِنْ الْعِتَاقِ الْأُوَلِ وَهُنَّ مِنْ تِلَادِي","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, Aku mendengar [Abdurrahman bin Yazid bin Qais] Aku mendengar [Ibnu Mas'ud] berkata terkait dengan surat Bani Isra`il, Al Kahfi Maryam, Thaaha dan Al Anbiya`, \"Sesungguhnya itu semua adalah dari surat-surat pertama yang diturunkan, dan semuanya pernah saya baca semenjak dahulu.\""},"4306":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ أَنْبَأَنَا أَبُو إِسْحَاقَ سَمِعَ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَتَعَلَّمْتُ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى قَبْلَ أَنْ يَقْدَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] Telah memberitakan kepada kami [Abu Ishaq] bahwa ia mendengar [Al Bara` bin Azib] radliallahu 'anhu, ia berkata; Aku mempelajari surat, \"SABBIHISMA RABBIKAL A'LAA..\" sebelum kedatangan Nabi shallallahu 'alaihi wasallam."},"4307":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَ قَالَ عَبْدُ اللَّهِلَقَدْ تَعَلَّمْتُ النَّظَائِرَ الَّتِي كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهُنَّ اثْنَيْنِ اثْنَيْنِ فِي كُلِّ رَكْعَةٍ فَقَامَ عَبْدُ اللَّهِ وَدَخَلَ مَعَهُ عَلْقَمَةُ وَخَرَجَ عَلْقَمَةُ فَسَأَلْنَاهُ فَقَالَ عِشْرُونَ سُورَةً مِنْ أَوَّلِ الْمُفَصَّلِ عَلَى تَأْلِيفِ ابْنِ مَسْعُودٍ آخِرُهُنَّ الْحَوَامِيمُ حم الدُّخَانِ وَعَمَّ يَتَسَاءَلُونَ","id":"Telah menceritakan kepada kami [Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Syaqiq] ia berkata; [Abdullah] berkata, \"Aku mempelajari An Nazhaa`ir, yang mana Rasulullah shallallahu 'alaihi wasallam biasa membacanya dua-dua dalam setiap raka'at.\" Kemudian Abdullah berdiri, dan 'Alqamah ikut masuk bersamanya. Setelah itu, 'Alqamah keluar, maka kami pun bertanya padanya. 'Alqamah berkata, \"Yaitu dua puluh surat yakni, dari awal Al Mufashshal -menurut Ibnu Mas'ud- sedangkan yang paling terakhir darinya adalah Al Hawaamiim, Haa`miim, Ad Dukhkhaan dan 'Amma Yatasaa`aluun.\" "},"4308":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْوَدَ النَّاسِ بِالْخَيْرِ وَأَجْوَدُ مَا يَكُونُ فِي شَهْرِ رَمَضَانَ لِأَنَّ جِبْرِيلَ كَانَ يَلْقَاهُ فِي كُلِّ لَيْلَةٍ فِي شَهْرِ رَمَضَانَ حَتَّى يَنْسَلِخَ يَعْرِضُ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقُرْآنَ فَإِذَا لَقِيَهُ جِبْرِيلُ كَانَ أَجْوَدَ بِالْخَيْرِ مِنْ الرِّيحِ الْمُرْسَلَةِ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] Telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; Nabi shallallahu 'alaihi wasallam adalah seorang yang paling ringan untuk berbuat kebaikan. Dan paling dermawan lagi pada bulan Ramadlan. Sebab, Jibril menemuinya pada setiap malam dalam bulan Ramadlan hingga ia berbaring sementara Rasulullah shallallahu 'alaihi wasallam memperdengarkan bacaan Al Qur`annya. Maka di saat Jibril menemuinya, pada saat itu pulalah beliau menjadi orang yang lebih cepat berbuat kebaikan bahkan melebihi cepatnya angin yang berhembus."},"4309":{"ar":"حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ يَعْرِضُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقُرْآنَ كُلَّ عَامٍ مَرَّةً فَعَرَضَ عَلَيْهِ مَرَّتَيْنِ فِي الْعَامِ الَّذِي قُبِضَ فِيهِ وَكَانَ يَعْتَكِفُ كُلَّ عَامٍ عَشْرًا فَاعْتَكَفَ عِشْرِينَ فِي الْعَام الَّذِي قُبِضَ فِيهِ","id":"Telah menceritakan kepada kami [Khalid bin Yazid] Telah menceritakan kepada kami [Abu Bakr] dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; \"Biasa Jibril mengecek bacaan Al Qur`an Nabi shallallahu 'alaihi wasallam sekali pada setiap tahunnya. Namun pada tahun wafatnya Rasulullah shallallahu 'alaihi wasallam, Jibril melakukannya dua kali. Dan beliau Rasulullah shallallahu 'alaihi wasallam beri'tikaf sepuluh hari pada setiap tahunnya. Sedangkan pada tahun wafatnya, beliau beri'tikaf selama dua puluh hari.\""},"4310":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ ذَكَرَ عَبْدُ اللَّهِ بْنُ عَمْرٍوعَبْدَ اللَّهِ بْنَ مَسْعُودٍ فَقَالَ لَا أَزَالُ أُحِبُّهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خُذُوا الْقُرْآنَ مِنْ أَرْبَعَةٍ مِنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَسَالِمٍ وَمُعَاذِ بْنِ جَبَلٍ وَأُبَيِّ بْنِ كَعْبٍ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] Telah menceritakan kepada kami [Syu'bah] dari [Amru] dari [Ibrahim] dari [Masruq] bahwasanya; [Abdullah bin Amru] menyebut Abdullah bin Mas'ud seraya berkata, \"Aku senantiasa mencintainya. Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: 'Ambillah Al Qur`an itu dari empat orang. Yaitu dari, Abdullah bin Mas'ud, Salim, Mu'adz bin Jabal dan Ubay bin Ka'ab.'\""},"4311":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا شَقِيقُ بْنُ سَلَمَةَ قَالَ خَطَبَنَا عَبْدُ اللَّهِ بْنُ مَسْعُودٍ فَقَالَوَاللَّهِ لَقَدْ أَخَذْتُ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضْعًا وَسَبْعِينَ سُورَةً وَاللَّهِ لَقَدْ عَلِمَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي مِنْ أَعْلَمِهِمْ بِكِتَابِ اللَّهِ وَمَا أَنَا بِخَيْرِهِمْ قَالَ شَقِيقٌ فَجَلَسْتُ فِي الْحِلَقِ أَسْمَعُ مَا يَقُولُونَ فَمَا سَمِعْتُ رَادًّا يَقُولُ غَيْرَ ذَلِكَ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Syaqiq bin Salamah] ia berkata; [Abdullah bin Mas'ud] menyampaikan khuthbah kepada kami, ia berkata, \"Aku telah mendapatkan dari bibir Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh puluh lebih surat. Dan demi Allah, para sahabat Rasulullah shallallahu 'alaihi wasallam pun telah mengetahui bahwa aku adalah orang yang paham mengenai kitabullah, namun aku bukanlah orang yang terbaik di antara mereka.\" Syaqiq berkata, \"Suatu ketika aku duduk di suatu Halaqah, lalu aku pun mendengar apa yang mereka katakan. Dan aku tidak mendapati seorang pun yang membantahnya."},"4312":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَكُنَّا بِحِمْصَ فَقَرَأَ ابْنُ مَسْعُودٍ سُورَةَ يُوسُفَ فَقَالَ رَجُلٌ مَا هَكَذَا أُنْزِلَتْ قَالَ قَرَأْتُ عَلَى رَسُولِ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحْسَنْتَ وَوَجَدَ مِنْهُ رِيحَ الْخَمْرِ فَقَالَ أَتَجْمَعُ أَنْ تُكَذِّبَ بِكِتَابِ اللَّهِ وَتَشْرَبَ الْخَمْرَ فَضَرَبَهُ الْحَدَّ","id":"Telah menceritakan kepadaku [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] ia berkata; Suatu ketika, kami berada di Himsh, lalu Ibnu Mas'ud membaca surat Yusuf. Kemudian seorang laki-laki berkata, \"Bacaan surat ini diturunkan tidaklah seperti itu.\" [Ibnu Mas'ud] berkata, \"Aku telah membacanya di hadapan Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: 'Bacaanmu adalah benar.'\" Dan ternyata Ibnu Mas'ud mendapatkan bau khamer dari mulut laki-laki itu, maka ia pun langsung berkata, \"Apakah kamu akan menggabungkan antara pendustaan atas Allah dan meminum khamer.\" Setelah itu, ia pun menegakkan hukuman padanya."},"4313":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا مُسْلِمٌ عَنْ مَسْرُوقٍ قَالَ قَالَ عَبْدُ اللَّهِ رَضِيَ اللَّهُ عَنْهُوَاللَّهِ الَّذِي لَا إِلَهَ غَيْرُهُ مَا أُنْزِلَتْ سُورَةٌ مِنْ كِتَابِ اللَّهِ إِلَّا أَنَا أَعْلَمُ أَيْنَ أُنْزِلَتْ وَلَا أُنْزِلَتْ آيَةٌ مِنْ كِتَابِ اللَّهِ إِلَّا أَنَا أَعْلَمُ فِيمَ أُنْزِلَتْ وَلَوْ أَعْلَمُ أَحَدًا أَعْلَمَ مِنِّي بِكِتَابِ اللَّهِ تُبَلِّغُهُ الْإِبِلُ لَرَكِبْتُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Muslim] dari [Masruq] ia berkata; [Abdullah] radliallahu 'anhu berkata, \"Demi Allah Yang tidak ada Ilah selain-Nya. Tidaklah satu surat pun yang diturunkan dari Kitabullah, kecuali saya tahu, di mana surat itu diturunkan. Dan tidak ada satu ayat pun dari Kitabullah kecuali tahu, kepada siapa ayat itu diturunkan. Sekiranya aku tahu, ada orang yang lebih tahu tentang Kitabullah dan tempatnya bisa ditempuh oleh Unta, maka niscaya aku akan berangkat menemuinya.\""},"4314":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُمَنْ جَمَعَ الْقُرْآنَ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعَةٌ كُلُّهُمْ مِنْ الْأَنْصَارِ أُبَيُّ بْنُ كَعْبٍ وَمُعَاذُ بْنُ جَبَلٍ وَزَيْدُ بْنُ ثَابِتٍ وَأَبُو زَيْدٍتَابَعَهُ الْفَضْلُ عَنْ حُسَيْنِ بْنِ وَاقِدٍ عَنْ ثُمَامَةَ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami [Qatadah] ia berkata; Aku bertanya kepada [Anas bin Malik] radliallahu 'anhu, \"Siapakah yang mengumpulkan Al Qur`an pada masa Nabi shallallahu 'alaihi wasallam?\" ia menjawab, \"Ada empat orang dan semuanya dari kaum Anshar. Yaitu, Ubay bin Ka'ab, Mu'adz bin Jabal, Zaid bin Tsabit dan Abu Zaid.\" Hadits ini diperkuat oleh [Al Fadllu] dari [Husain bin Waqid] dari [Tsumamah] dari [Anas]. "},"4315":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي ثَابِتٌ الْبُنَانِيُّ وَثُمَامَةُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَاتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَجْمَعْ الْقُرْآنَ غَيْرُ أَرْبَعَةٍ أَبُو الدَّرْدَاءِ وَمُعَاذُ بْنُ جَبَلٍ وَزَيْدُ بْنُ ثَابِتٍ وَأَبُو زَيْدٍ قَالَ وَنَحْنُ وَرِثْنَاهُ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] Telah menceritakan kepada kami [Abdullah bin Al Mutsanna] ia berkata; Telah menceritakan kepadaku [Tsabit Al Bunani] dan [Tsumamah] dari [Anas bin Malik] ia berkata; Nabi shallallahu 'alaihi wasallam wafat, sementara beliau belum mengumpulkan Al Qur`an kecuali oleh empat orang, yaitu Abu Darda`, Mu'adz bin Jabal, Zaid bin Tsabit dan Abu Zaid. Ia berkata; Dan kami akan mewarisinya."},"4316":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ مِنْ لَحَنِ أُبَيٍّ وَأُبَيٌّ يَقُولُ أَخَذْتُهُ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَتْرُكُهُ لِشَيْءٍ قَالَ اللَّهُ تَعَالَى{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] Telah mengabarkan kepada kami [Yahya] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, [Umar] berkata, \"Orang yang paling baik bacaannya di antara kita adalah Ubbay, dan kita akan meninggalkan Qira`ah Ubay.\" Maka [Ubay] pun berkata, \"Aku telah mengambilnya langsung dari bibir Rasulullah shallallahu 'alaihi wasallam, karena itu aku tidak akan meninggalkannya lantaran karena suatu masalah. Allah Ta'ala berfirman: 'MAA NANSAKH MIN `AAYATIN AW NUNSIKHA NA`TI BIKHAIR MINHAA AW MITSLIHAA (Tidaklah kami menghapus suatu ayat pun, atau ayat itu dihapus, kecuali kami akan menggantinya dengan yang lebih baik darinya atau semisalnya). (QS. Albaqarah 106).'\""},"4317":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى قَالَكُنْتُ أُصَلِّي فَدَعَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أُجِبْهُ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ أُصَلِّي قَالَ أَلَمْ يَقُلْ اللَّهُ{ اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ }ثُمَّ قَالَ أَلَا أُعَلِّمُكَ أَعْظَمَ سُورَةٍ فِي الْقُرْآنِ قَبْلَ أَنْ تَخْرُجَ مِنْ الْمَسْجِدِ فَأَخَذَ بِيَدِي فَلَمَّا أَرَدْنَا أَنْ نَخْرُجَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ قُلْتَ لَأُعَلِّمَنَّكَ أَعْظَمَ سُورَةٍ مِنْ الْقُرْآنِ قَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ هِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepadaku [Khubaib bin Abdurrahman] dari [Hafsh bin Ashim] dari [Abu Sa'id Al Mu'alla] ia berkata; Suatu ketika aku sedang shalat, tiba-tiba Rasulullah shallallahu 'alaihi wasallam memanggilku namun aku tidak menjawab panggilannya. Seusai shalat, aku berkata kepada beliau, \"Wahai Rasulullah, sesungguhnya tadi aku sedang shalat.\" Beliau bersabda: \"Bukankah Allah telah berfirman: 'Penuhilah panggilan Allah dan panggilan Rasul-Nya bila ia mengajak kalian..'\" kemudian beliau bersabda: \"Maukah kamu aku ajari satu surat yang paling agung yang terdapat dalam Al Qur`an sebelum kamu keluar dari Masjid?\" Lalu beliau memegang tanganku, dan ketika kami hendak keluar, aku berkata, \"Wahai Rasulullah, sesungguhnya Anda telah berkata, 'Sungguh, aku akan mengajarkan padamu suatu surat yang paling agung dari Al Qur`an.'\" Beliau pun bersabda: \"Yaitu: 'AL HAMDULILLAHI RABBIL 'AALAMIIN..' ia adalah As Sab'u Al Matsaanii dan Al Qur`an yang agung yang telah diberikan kepadaku.\""},"4318":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا وَهْبٌ حَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ مَعْبَدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكُنَّا فِي مَسِيرٍ لَنَا فَنَزَلْنَا فَجَاءَتْ جَارِيَةٌ فَقَالَتْ إِنَّ سَيِّدَ الْحَيِّ سَلِيمٌ وَإِنَّ نَفَرَنَا غَيْبٌ فَهَلْ مِنْكُمْ رَاقٍ فَقَامَ مَعَهَا رَجُلٌ مَا كُنَّا نَأْبُنُهُ بِرُقْيَةٍ فَرَقَاهُ فَبَرَأَ فَأَمَرَ لَهُ بِثَلَاثِينَ شَاةً وَسَقَانَا لَبَنًا فَلَمَّا رَجَعَ قُلْنَا لَهُ أَكُنْتَ تُحْسِنُ رُقْيَةً أَوْ كُنْتَ تَرْقِي قَالَ لَا مَا ر��قَيْتُ إِلَّا بِأُمِّ الْكِتَابِ قُلْنَا لَا تُحْدِثُوا شَيْئًا حَتَّى نَأْتِيَ أَوْ نَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ ذَكَرْنَاهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَمَا كَانَ يُدْرِيهِ أَنَّهَا رُقْيَةٌ اقْسِمُوا وَاضْرِبُوا لِي بِسَهْمٍوَقَالَ أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا هِشَامٌ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ حَدَّثَنِي مَعْبَدُ بْنُ سِيرِينَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ بِهَذَا","id":"Telah menceritakan kepadaku [Muhammad bin Al Mtsanna] Telah menceritakan kepada kami [Wahb] Telah menceritakan kepada kami [Hisyam] dari [Muhammad] dari [Ma'bad] dari [Abu Sa'id Al Khudri] ia berkata; Dalam perjalanan yang kami lakukan, kami singgah di suatu tempat, lalu datanglah seorang wanita dan berkata, \"Sesungguhnya ada seorang kepala kampung sakit, sementara orang-orang kami sedang tiada. Apakah salah seorang dari kalian ada yang bisa meruqyah?\" Maka berdirilah seorang laki-laki yang kami sendiri tidak tahu bahwa ia bisa meruqyah. Ia beranjak bersama wanita itu, lalu meruqyah, dan ternyata yang diruqyah sembuh. Kemudian sang kepala kampung memerintahkan agar laki-laki itu diberi tiga puluh ekor kambing, dan kami pun diberinya minuman susu. Setelah pulang, kami bertanya padanya, \"Apakah kamu memang seorang yang pandai meruqyah?\" Ia menjawab, \"Tidak, dan tidaklah aku meruqyahnya, kecuali dengan Ummul Kitab.\" Kami katakan, \"Janganlah kalian berbuat apa-apa, hingga kita sampai kepada Nabi shallallahu 'alaihi wasallam dan bertanya pada beliau.\" Ketika kami sampai di Madinah, kami pun menuturkan hal itu pada Nabi shallallahu 'alaihi wasallam, dan beliau bersabda: \"Lalu siapa yang memberitahukannya, bahwa itu adalah ruqyah. Bagikanlah kambing itu, dan aku juga diberi bagian.\" [Abu Ma'mar] berkata; Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Hisyam] Telah menceritakan kepada kami [Muhammad bin Sirin] Telah menceritakan kepadaku [Ma'bad bin Sirin] dari [Sa'id Al Khudri] dengan hadits ini."},"4319":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَرَأَ بِالْآيَتَيْنِ و حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَمَنْ قَرَأَ بِالْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُوَقَالَ عُثْمَانُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَوْفٌ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ وَكَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحِفْظِ زَكَاةِ رَمَضَانَ فَأَتَانِي آتٍ فَجَعَلَ يَحْثُو مِنْ الطَّعَامِ فَأَخَذْتُهُ فَقُلْتُ لَأَرْفَعَنَّكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَّ الْحَدِيثَ فَقَالَ إِذَا أَوَيْتَ إِلَى فِرَاشِكَ فَاقْرَأْ آيَةَ الْكُرْسِيِّ لَنْ يَزَالَ مَعَكَ مِنْ اللَّهِ حَافِظٌ وَلَا يَقْرَبُكَ شَيْطَانٌ حَتَّى تُصْبِحَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَكَ وَهُوَ كَذُوبٌ ذَاكَ شَيْطَانٌ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Abdurrahman] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membaca dua ayat..\" Dan Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] radliallahu 'anhu ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca dua ayat terakhir dari surat Al Baqarah pada suatu malam, niscaya kedua ayat itu akan mencukupinya.\" Utsmana bin Al Haitsam berkata; Telah menceritakan kepada kami 'Auf dari Muhammad bin Sirin dari Abu Hurairah radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam menugaskanku untuk menjaga harta zakat. Lalu pada suatu hari ada seseorang yang menyusup hendak mengambil makanan, maka aku pun menyergapnya seraya berkata, \"Aku benar-benar akan menyerahkanmu kepada Rasulullah shallallahu 'alaihi wasallam..\" lalu ia bercerita dan berkata, \"Jika kamu hendak beranjak ke tempat tidur maka bacalah ayat kursi, niscaya Allah akan senantiasa menjagamu dan syetan tidak akan mendekatimu hingga pagi.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Ia telah berkata benar padamu, padahal ia adalah pendusta. Si penyusup tadi sebenarnya adalah syetan.\""},"4320":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَجُلٌ يَقْرَأُ سُورَةَ الْكَهْفِ وَإِلَى جَانِبِهِ حِصَانٌ مَرْبُوطٌ بِشَطَنَيْنِ فَتَغَشَّتْهُ سَحَابَةٌ فَجَعَلَتْ تَدْنُو وَتَدْنُو وَجَعَلَ فَرَسُهُ يَنْفِرُ فَلَمَّا أَصْبَحَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ تِلْكَ السَّكِينَةُ تَنَزَّلَتْ بِالْقُرْآنِ","id":"Telah menceritakan kepada kami [Amru bin Khalid] Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami [Abu Ishaq] dari [Al Barra` bin 'Aazib] ia berkata; Seorang laki-laki membaca surat Al Kahfi, sementara di sisinya terdapat seekor kuda yang terikat dengan dua tali, ternyata di atasnya terdapat kabut yang menaunginya. Kabut itu mendekat dan semakin mendekat sehingga membuat kudanya lari ingin beranjak. Ketika waktu pagi datang, laki-laki itu pun mendatangi Nabi shallallahu 'alaihi wasallam dan menuturkan kejadian yang dialaminya, Nabi shallallahu 'alaihi wasallam bersabda: \"Itu adalah As Sakinah (ketenangan) yang turun karena Al Qur`an.\""},"4321":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسِيرُ فِي بَعْضِ أَسْفَارِهِ وَعُمَرُ بْنُ الْخَطَّابِ يَسِيرُ مَعَهُ لَيْلًا فَسَأَلَهُ عُمَرُ عَنْ شَيْءٍ فَلَمْ يُجِبْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ ثُمَّ سَأَلَهُ فَلَمْ يُجِبْهُ فَقَالَ عُمَرُ ثَكِلَتْكَ أُمُّكَ نَزَرْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ كُلَّ ذَلِكَ لَا يُجِيبُكَ قَالَ عُمَرُ فَحَرَّكْتُ بَعِيرِي حَتَّى كُنْتُ أَمَامَ النَّاسِ وَخَشِيتُ أَنْ يَنْزِلَ فِيَّ قُرْآنٌ فَمَا نَشِبْتُ أَنْ سَمِعْتُ صَارِخًا يَصْرُخُ بِي قَالَ فَقُلْتُ لَقَدْ خَشِيتُ أَنْ يَكُونَ نَزَلَ فِيَّ قُرْآنٌ قَالَ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ فَقَالَ لَقَدْ أُنْزِلَتْ عَلَيَّ اللَّيْلَةَ سُورَةٌ لَهِيَ أَحَبُّ إِلَيَّ مِمَّا طَلَعَتْ عَلَيْهِ الشَّمْسُ ثُمَّ قَرَأَ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا","id":"Telah menceritakan kepada kami [Isma'il] ia berkata, Telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari [bapaknya] bahwasanya; Rasulullah shallallahu 'alaihi wasallam tengah berjalan dalam suatu safar yang dilakukannya. Lalu pada suatu malam, Umar bin Al Khaththab berjalan bersama beliau, lalu Umar bertanya tentang sesuatu, namun Rasulullah shallallahu 'alaihi wasallam tidak menjawabnya. Kemudian ia bertanya lagi, dan belum juga menjawabnya. Lalu bertanya lagi, tetapi tidak menjawabnya. Maka [Umar] pun berkata, \"Alangkah merugilah kamu, kamu bertanya kepada Rasulullah shallallahu 'alaihi wasallam, namun semua itu tidak dihiraukannya.\" Kemudian Umar berkata; \"Maka aku pun memacu Untau hingga berjalan di hadapan orang-orang, dan aku khawatir ayat Al Qur`an akan turun berkenaan denganku. Aku tak peduli lagi, bilamana aku mendengar teriakan suara yang memanggilku.\" Umar melanjutkan, \"Sungguh, aku khawatir ayat Al Qur`an akan turun berkenaan denganku. Karena itu, aku segera mendatangi Rasulullah shallallahu 'alaihi wasallam lalu mengucapkan salam atasnya. Beliau bersabda: 'Sesungguhnya, semalam telah turun satu surat padaku, dan surat itu lebih aku sukai, daripada terbitnya matahari.' Dan beliau pun membacakannya pada kami: 'INNAA FATAHNAA LAKA FATHAN MUBIINAA..'\" (QS. Alfath) "},"4322":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا سَمِعَ رَجُلًا يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ يُرَدِّدُهَا فَلَمَّا أَصْبَحَ جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ وَكَأَنَّ الرَّجُلَ يَتَقَالُّهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّهَا لَتَعْدِلُ ثُلُثَ الْقُرْآنِوَزَادَ أَبُو مَعْمَرٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَخْبَرَنِي أَخِي قَتَادَةُ بْنُ النُّعْمَانِ أَنَّ رَجُلًا قَامَ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ مِنْ السَّحَرِ قُلْ هُوَ اللَّهُ أَحَدٌ لَا يَزِيدُ عَلَيْهَا فَلَمَّا أَصْبَحْنَا أَتَى الرَّجُلُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abdurrahman bin Abdullah bin Abdurrahman bin Abu Sha'shah] dari [bapaknya] dari [Abu Sa'id Al Khudri] bahwa seorang laki-laki mendengar seseorang yang membaca surat: \"QUL HUWALLAHU AHAD.\" dan orang itu selalu mengulang-ngulangnya. Di pagi harinya, maka laki-laki itu pun segera menemui Rasulullah shallallahu 'alaihi wasallam dan mengadukan mengenai seseorang yang ia dengar semalam membaca surat yang sepertinya ia menganggap sangat sedikit. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sesungguhnya surat itu benar-benar menyamai sepertiga Al Qur`an.\" [Abu Ma'mar] menambahkan dan Telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Malik] dari [Abdurrahman bin Abdullah bin Abdurrahman bin Sha'sha'ah] dari [bapaknya] dari [Abu S'aid Al Khudri] Telah mengabarkan kepadaku adikku [Qatadah bin An Nu'man] bahwasanya; Ada seorang laki-laki yang berdiri menunaikan shalat di waiktu sahur, dan ia membaca surat, \"QUL HUWALLAHU AHAD..\" lalu ia tidaklah menambahkan sesuatu pun pada surat itu.\" Maka ketika pagi, maka seseorang mendatangi Nabi shallallahu 'alaihi wasallam. Yakni dengan hadists semisalnya."},"4323":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا إِبْرَاهِيمُ وَالضَّحَّاكُ الْمَشْرِقِيُّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ أَيَعْجِزُ أَحَدُكُمْ أَنْ يَقْرَأَ ثُلُثَ الْقُرْآنِ فِي لَيْلَةٍ فَشَقَّ ذَلِكَ عَلَيْهِمْ وَقَالُوا أَيُّنَا يُطِيقُ ذَلِكَ يَا رَسُولَ اللَّهِ فَقَالَ اللَّهُ الْوَاحِدُ الصَّمَدُ ثُلُثُ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Ibrahim] dan [Adl Dlahak Al Masyriqi] dari [Abu Sa'id Al Khudri] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: \"Apakah salah seorang dari kalian tidak mampu bila ia membaca sepertiga dari Al Qur`an pada setiap malamnya?\" dan ternyata para sahabat merasa kesulitan seraya berkata, \"Siapakah di antara kami yang mampu melakukan hal itu wahai Rasulullah?\" maka beliau pun bersabda: \"ALLAHUL WAAHID ASH SHAMAD (maksudnya surat al-ikhlash) nilainya adalah sepertiga Al Qur`an.\""},"4324":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اشْتَكَى يَقْرَأُ عَلَى نَفْسِهِ بِالْمُعَوِّذَاتِ وَيَنْفُثُ فَلَمَّا اشْتَدَّ وَجَعُهُ كُنْتُ أَقْرَأُ عَلَيْهِ وَأَمْسَحُ بِيَدِهِ رَجَاءَ بَرَكَتِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] radliallahu 'anha, bahwasanya; Apabila Rasulullah shallallahu 'alaihi wasallam menderita sakit, maka beliau membacakan Al Mu'awwidzaat untuk dirinya sendiri, lalu beliau meniupkannya. Dan ketika sakitnya parah, maka akulah yang membacakannya pada beliau, lalu mengusapkan dengan menggunakan tangannya guna mengharap keberkahannya. "},"4325":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَوَى إِلَى فِرَاشِهِ كُلَّ لَيْلَةٍ جَمَعَ كَفَّيْهِ ثُمَّ نَفَثَ فِيهِمَا فَقَرَأَ فِيهِمَا قُلْ هُوَ اللَّهُ أَحَدٌ وَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ ثُمَّ يَمْسَحُ بِهِمَا مَا اسْتَطَاعَ مِنْ جَسَدِهِ يَبْدَأُ بِهِمَا عَلَى رَأْسِهِ وَوَجْهِهِ وَمَا أَقْبَلَ مِنْ جَسَدِهِ يَفْعَلُ ذَلِكَ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Al Mufadldlal bin Fadlalah] dari [Uqail] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] bahwa biasa Nabi shallallahu 'alaihi wasallam bila hendak beranjak ke tempat tidurnya pada setiap malam, beliau menyatukan kedua telapak tangannya, lalu meniupnya dan membacakan: \"QULHUWALLAHU AHAD..\" dan, \"QUL `A'UUDZU BIRABBIL FALAQ...\" serta, \"QUL `A'UUDZU BIRABBIN NAAS..\" Setelah itu, beliau mengusapkan dengan kedua tangannya pada anggota tubuhnya yang terjangkau olehnya. Beliau memulainya dari kepala, wajah dan pada anggota yang dapat dijangkaunya. Hal itu, beliau ulangi sebanyak tiga kali."},"4326":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ قَالَدَخَلْتُ أَنَا وَشَدَّادُ بْنُ مَعْقِلٍ عَلَى ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ لَهُ شَدَّادُ بْنُ مَعْقِلٍ أَتَرَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ شَيْءٍ قَالَ مَا تَرَكَ إِلَّا مَا بَيْنَ الدَّفَّتَيْنِقَالَ وَدَخَلْنَا عَلَى مُحَمَّدِ بْنِ الْحَنَفِيَّةِ فَسَأَلْنَاهُ فَقَالَ مَا تَرَكَ إِلَّا مَا بَيْنَ الدَّفَّتَيْنِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Sufyan] dari [Abdul Aziz bin Rufai'] ia berkata; Aku dan Syaddad bin Ma'qil menemui [Ibnu Abbas] radliallahu 'anhuma, lalu Syaddad bin Ma'qil pun bertanya padanya, \"Apakah Nabi shallallahu 'alaihi wasallam meninggalkan sesuatu?\" Ia menjawab, \"Tidaklah meninggalkan sesuatu pun kecuali apa yang ada di antara dua sisi kitab.\" Lalu kami menemui [Muhammad bin Ali Al Hanafiyyah] dan bertanya padanya, maka ia pun menjawab, \"Tidaklah beliau meninggalkan sesuatu, kecuali apa yang terdapat di antara dua sisi kitab.\""},"4327":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ أَبُو خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الَّذِي يَقْرَأُ الْقُرْآنَ كَالْأُتْرُجَّةِ طَعْمُهَا طَيِّبٌ وَرِيحُهَا طَيِّبٌ وَالَّذِي لَا يَقْرَأُ الْقُرْآنَ كَالتَّمْرَةِ طَعْمُهَا طَيِّبٌ وَلَا رِيحَ لَهَا وَمَثَلُ الْفَاجِرِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْفَاجِرِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ طَعْمُهَا مُرٌّ وَلَا رِيحَ لَهَا","id":"Telah menceritakan kepada kami [Hudbah bin Khalid Abu Khalid] Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami [Qatadah] Telah menceritakan kepada kami [Anas bin Malik] dari [Abu Musa Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaan orang yang membaca Al Qur`an adalah seperti buah Utrujjah, rasanya lezat dan baunya juga sedap. Sedang orang yang tidak membaca Al Qur`an adalah seperti buah kurma, rasanya manis, namun baunya tidak ada. Adapun orang Fajir yang membaca Al Qur`an adalah seperti buah Raihanah, baunya harum, namun rasanya pahit. Dan perumpamaan orang Fajir yang tidak membaca Al Qur`an adalah seperti buah Hanzhalah, rasanya pahit dan baunya juga tidak sedap.\""},"4328":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا أَجَلُكُمْ فِي أَجَلِ مَنْ خَلَا مِنْ الْأُمَمِ كَمَا بَيْنَ صَلَاةِ الْعَصْرِ وَمَغْرِبِ الشَّمْسِ وَمَثَلُكُمْ وَمَثَلُ الْيَهُودِ وَالنَّصَارَى كَمَثَلِ رَجُلٍ اسْتَعْمَلَ عُمَّالًا فَقَالَ مَنْ يَعْمَلُ لِي إِلَى نِصْفِ النَّهَارِ عَلَى قِيرَاطٍ فَعَمِلَتْ الْيَهُودُ فَقَالَ مَنْ يَعْمَلُ لِي مِنْ نِصْفِ النَّهَارِ إِلَى الْعَصْرِ عَلَى قِيرَاطٍ فَعَمِلَتْ النَّصَارَى ثُمَّ أَنْتُمْ تَعْمَلُونَ مِنْ الْعَصْرِ إِلَى الْمَغْرِبِ بِقِيرَاطَيْنِ قِيرَاطَيْنِ قَالُوا نَحْنُ أَكْثَرُ عَمَلًا وَأَقَلُّ عَطَاءً قَالَ هَلْ ظَلَمْتُكُمْ مِنْ حَقِّكُمْ قَالُوا لَا قَالَ فَذَاكَ فَضْلِي أُوتِيهِ مَنْ شِئْتُ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Sufyan] Telah menceritakan kepadaku [Abdullah bin Dinar] ia berkata, Aku mendengar [Ibnu Umar] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya perumpamaan jaman kalian dan jaman umat-umat sebelum kalian, hanyalah bagaikan jarak atara shalat Ashar dan terbenamnya matahari. Sedang perumpamaan kalian dengan ummat Yahudi dan Nashrani, adalah seperti seorang yang memperkerjakan beberapa orang pekerja seraya berkata, 'Siapa yang berkerja untukku hingga pertengahan hari, maka baginya adalah satu Qirath.' Maka kaum Yahudi pun beramal. Kemudian sang juragan itu pun berkata lagi, 'Siapa yang bekerja untukku dan sejak pertengahan hari hingga Ashar, maka baginya satu Qirath.' Maka orang-orang Nashrani pun bekerja. Lalu kalian bekerja dari sejak Ashar hingga Maghrib tiba dengan ganjaran dua Qirath. Maka mereka pun protes, 'Kamilah yang paling banyak bekerja, akan tetapi ganjaran kami paling sedikit.' Sang juragan pun berkata, 'Apakah aku menzhalimi hak kalian barang sedikit pun? ' mereka menjawab, 'Tidak.' Ia berkata, 'Itulah kelebihan-Ku, yang Aku berikan kepada siapa saja yang Aku maui.'\""},"4329":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ حَدَّثَنَا طَلْحَةُ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَىآوْصَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا فَقُلْتُ كَيْفَ كُتِبَ عَلَى النَّاسِ الْوَصِيَّةُ أُمِرُوا بِهَا وَلَمْ يُوصِ قَالَ أَوْصَى بِكِتَابِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Malik bin Mighwal] Telah menceritakan kepada kami [Thalhah] ia berkata; Aku bertanya kepada [Abdullah bin Abu Aufa], \"Apakah Nabi shallallahu 'alaihi wasallam pernah berwasiat?\" Ia menjawab, \"Tidak.\" Aku berkata, \"Lalu bagaimana wasiat itu diwajibkan atas orang-orang untuk menunaikannya sementara beliau tidaklah berwasiat?\" Ia menjawab, \"Beliau telah berwasiat dengan Kitabullah.\""},"4330":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ كَانَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَأْذَنْ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِلنَّبِيِّ أَنْ يَتَغَنَّى بِالْقُرْآنِ وَقَالَ صَاحِبٌ لَهُ يُرِيدُ يَجْهَرُ بِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] ia berkata, Telah menceritakan kepadaku [Al Laits] dari [Uqail] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu, bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak pernah mengijinkan sesuatu pun kepada Nabi sebagaimana ijin-Nya untuk melagukan Al Qur`an.\" Salah seorang sahabatnya berkata; Maksudnya adalah melagukannya dengan suara yang keras."},"4331":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِلنَّبِيِّ أَنْ يَتَغَنَّى بِالْقُرْآنِقَالَ سُفْيَانُ تَفْسِيرُهُ يَسْتَغْنِي بِهِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah tidak mengizinkan pada sesuatu pun, sebagaimana Allah mengizinkan kepada Nabi untuk melagukan Al Qur`an.\" Sufyan berkata, \"Tafsirnya adalah, bahwa ia melagu-lagu dengannya.\""},"4332":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا حَسَدَ إِلَّا عَلَى اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ الْكِتَابَ وَقَامَ بِهِ آنَاءَ اللَّيْلِ وَرَجُلٌ أَعْطَاهُ اللَّهُ مَالًا فَهُوَ يَتَصَدَّقُ بِهِ آنَاءَ اللَّيْلِ وَالنَّهَارِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah menceritakan kepadaku [Salim bin Abdullah] bahwasanya; [Abdullah bin Umar] radliallahu 'anhuma berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak diperbolehkan hasad kecuali pada dua hal, yaitu; Seorang yang diberi karunia Alquran oleh Allah sehingga ia membacanya (shalat dengannya) di pertengahan malam dan siang. Dan seseorang yang diberi karunia harta oleh, sehingga ia menginfakkannya pada malam dan siang hari.\""},"4333":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ سَمِعْتُ ذَكْوَانَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ عَلَّمَهُ اللَّهُ الْقُرْآنَ فَهُوَ يَتْلُوهُ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ فَسَمِعَهُ جَارٌ لَهُ فَقَالَ لَيْتَنِي أُوتِيتُ مِثْلَ مَا أُوتِيَ فُلَانٌ فَعَمِلْتُ مِثْلَ مَا يَعْمَلُ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا فَهُوَ يُهْلِكُهُ فِي الْحَقِّ فَقَالَ رَجُلٌ لَيْتَنِي أُوتِيتُ مِثْلَ مَا أُوتِيَ فُلَانٌ فَعَمِلْتُ مِثْلَ مَا يَعْمَلُ","id":"Telah menceritakan kepada kami [Ali bin Ibrahim] Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] Aku mendengar [Dzakwan] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak diperbolehkan hasad kecuali pada dua perkara, yaitu; Seseorang yang telah diajari Al Qur`an oleh Allah, sehingga ia membacanya di pertengahan malam dan siang, sampai tetangga yang mendengarnya berkata, 'Duh.., sekiranya aku diberikan sebagaimana apa yang diberikan kepada si Fulan, niscaya aku akan melakukan apa yang dilakukannya.' Kemudian seseorang diberi karunia harta oleh Allah, sehingga ia dapat membelanjakannya pada kebenaran, lalu orang pun berkata, 'Seandainya aku diberi karunia sebagaimana si Fulan, maka niscaya aku akan melakukan sebagaimana yang dilakukannya.'\""},"4334":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَلْقَمَةُ بْنُ مَرْثَدٍ سَمِعْتُ سَعْدَ بْنَ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ قَالَ وَأَقْرَأَ أَبُو عَبْدِ الرَّحْمَنِ فِي إِمْرَةِ عُثْمَانَ حَتَّى كَانَ الْحَجَّاجُ قَالَ وَذَاكَ الَّذِي أَقْعَدَنِي مَقْعَدِي هَذَا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Syu'bah] ia berkata, Telah mengabarkan kepadaku ['Alqamah bin Martsad] Aku mendengar [Sa'd bin Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Utsman] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang paling baik di antara kalian adalah seorang yang belajar Al Qur`an dan mengajarkannya.\" Abu Abdirrahman membacakan (Al Qur`an) pada masa Utsman hingga Hajjaj pun berkata, \"Dan hal itulah yang menjadikanku duduk di tempat dudukku ini.\""},"4335":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَفْضَلَكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Alqamah bin Martsad] dari [Abu Abdurrahman As Sulami] dari [Utsman bin 'Affan] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang paling utama di antara kalian adalah seorang yang belajar Al Qur`an dan mengajarkannya.\""},"4336":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ فَقَالَتْ إِنَّهَا قَدْ وَهَبَتْ نَفْسَهَا لِلَّهِ وَلِرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا لِي فِي النِّسَاءِ مِنْ حَاجَةٍ فَقَالَ رَجُلٌ زَوِّجْنِيهَا قَالَ أَعْطِهَا ثَوْبًا قَالَ لَا أَجِدُ قَالَ أَعْطِهَا وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَاعْتَلَّ لَهُ فَقَالَ مَا مَعَكَ مِنْ الْقُرْآنِ قَالَ كَذَا وَكَذَا قَالَ فَقَدْ زَوَّجْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Amru bin 'Aun] Telah menceritakan kepada kami [Hammad] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata; Seorang wanita mendatangi Nabi shallallahu 'alaihi wasallam dan berkata bahwasanya, ia telah menyerahkan dirinya untuk Allah dan Rasul-Nya shallallahu 'alaihi wasallam. Maka beliau bersabda: \"Aku tidak berhasrat terhadap wanita itu.\" Tiba-tiba seorang laki-laki berkata, \"Nikahkanlah aku dengannya.\" Beliau bersabda: \"Berikanlah mahar (berupa) pakaian padanya.\" Laki-laki itu berkata, \"Aku tidak punya.\" Beliau pun bersabda kembali, \"Berikanlah meskipun hanya berupa cincin besi.\" Ternyata ia pun tak punya. Kemudian beliau bertanya, \"Apakah kamu memiliki hafalan Al Qur`an?\" laki-laki itu menjawab, \"Ya, surat ini dan ini.\" Maka beliau bersabda: \"Aku telah menikahkanmu dengan wanita itu, dengan mahar hafalan Al Qur`anmu.\""},"4337":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ امْرَأَةً جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ جِئْتُ لِأَهَبَ لَكَ نَفْسِي فَنَظَرَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَعَّدَ النَّظَرَ إِلَيْهَا وَصَوَّبَهُ ثُمَّ طَأْطَأَ رَأْسَهُ فَلَمَّا رَأَتْ الْمَرْأَةُ أَنَّهُ لَمْ يَقْضِ فِيهَا شَيْئًا جَلَسَتْ فَقَامَ رَجُلٌ مِنْ أَصْحَابِهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنْ لَمْ يَكُنْ لَكَ بِهَا حَاجَةٌ فَزَوِّجْنِيهَا فَقَالَ هَلْ عِنْدَكَ مِنْ شَيْءٍ فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ قَالَ اذْهَبْ إِلَى أَهْلِكَ فَانْظُرْ هَلْ تَجِدُ شَيْئًا فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ مَا وَجَدْتُ شَيْئًا قَالَ انْظُرْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ وَلَا خَاتَمًا مِنْ حَدِيدٍ وَلَكِنْ هَذَا إِزَارِي قَالَ سَهْلٌ مَا لَهُ رِدَاءٌ فَلَهَا نِصْفُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصْنَعُ بِإِزَارِكَ إِنْ لَبِسْتَهُ لَمْ يَكُنْ عَلَيْهَا مِنْهُ شَيْءٌ وَإِنْ لَبِسَتْهُ لَمْ يَكُنْ عَلَيْكَ شَيْءٌ فَجَلَسَ الرَّجُلُ حَتَّى طَالَ مَجْلِسُهُ ثُمَّ قَامَ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَلِّيًا فَأَمَرَ بِهِ فَدُعِيَ فَلَمَّا جَاءَ قَالَ مَاذَا مَعَكَ مِنْ الْقُرْآنِ قَالَ مَعِي سُورَةُ كَذَا وَسُورَةُ كَذَا وَسُورَةُ كَذَا عَدَّهَا قَالَ أَتَقْرَؤُهُنَّ عَنْ ظَهْرِ قَلْبِكَ قَالَ نَعَمْ قَالَ اذْهَبْ فَقَدْ مَلَّكْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwasanya, ada seorang wanita mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku datang untuk menyerahkan diriku padamu.\" Lalu Rasulullah shallallahu 'alaihi wasallam pun memandangi wanita dari atas hingga ke bawah lalu beliau menunduk. Dan ketika wanita itu melihat, bahwa beliau belum memberikan keputusan akan dirinya, ia pun duduk. Tiba-tiba seorang laki-laki dari sahabat beliau berdiri dan berkata, \"Wahai Rasulullah, jika Anda tidak berhasrat dengannya, maka nikahkanlah aku dengannya.\" Lalu beliau pun bertanya: \"Apakah kamu punya sesuatu (untuk dijadikan sebagai mahar)?\" Laki-laki itu menjawab, \"Tidak, demi Allah wahai Rasulullah.\" Kemudian beliau bersabda: \"Kembalilah kepada keluargamu dan lihatlah apakah ada sesuatu?\" Laki-laki itu pun pergi dan kembali lagi seraya bersabda: \"Tidak, demi Allah wahai Rasulullah, aku tidak mendapatkan apa-apa?\" beliau bersabda: \"Lihatlah kembali, meskipun yang ada hanyalah cincin besi.\" Laki-laki itu pergi lagi, kemudian kembali dan berkata, \"Tidak, demi Allah wahai Rasulullah, meskipun cincin emas aku tak punya, tetapi yang ada hanyalah kainku ini.\" Sahl berkata, \"Tidaklah kain yang ia punyai itu kecuali hanya setengahnya.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bertanya: \"Apa yang dapat kamu lakukan dengan kainmu itu? Bila kamu mengenakannya, maka ia tidak akan memperoleh apa-apa dan bila ia memakainya, maka kamu juga tak memperoleh apa-apa.\" Lalu laki-laki itu pun duduk agak lama dan kemudian beranjak. Rasulullah shallallahu 'alaihi wasallam melihatnya dan beliau pun langsung menyuruh seseorang untuk memanggilkannya. Ia pun dipanggil, dan ketika datang, beliau bertanya, \"Apakah kamu punya hafalan Al Qur`an?\" laki-laki itu menjawab, \"Ya, aku hafal surat ini dan ini.\" Ia sambil menghitungnya. Beliau bertanya lagi, \"Apakah kami benar-benar menghafalnya?\" ia menjawab, \"Ya.\" Akhirnya beliau bersabda: \"Kalau begitu, perigilah. Sesungguhnya kau telah kunikahkan dengannya dengan mahar apa yang telah kamu hafal dari Al Qur`an.\""},"4338":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا مَثَلُ صَاحِبِ الْقُرْآنِ كَمَثَلِ صَاحِبِ الْإِبِلِ الْمُعَقَّلَةِ إِنْ عَاهَدَ عَلَيْهَا أَمْسَكَهَا وَإِنْ أَطْلَقَهَا ذَهَبَتْ","id":"Telah menceritakan kepada kami [Abudllah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perumpamaan para penghafal Al Qur`an adalah seperti seorang yang memiliki Utna yang terikat, jika ia selalu menjaganya, maka ia pun akan selalu berada padanya, dan jika ia melepaskannya, niscaya akan hilang dan pergi.\""},"4339":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَ مَا لِأَحَدِهِمْ أَنْ يَقُولَ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ نُسِّيَ وَاسْتَذْكِرُوا الْقُرْآنَ فَإِنَّهُ أَشَدُّ تَفَصِّيًا مِنْ صُدُورِ الرِّجَالِ مِنْ النَّعَمِحَدَّثَنَا عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ مِثْلَهُ تَابَعَهُ بِشْرٌ عَنْ ابْنِ الْمُبَارَكِ عَنْ شُعْبَةَ وَتَابَعَهُ ابْنُ جُرَيْجٍ عَنْ عَبْدَةَ عَنْ شَقِيقٍ سَمِعْتُ عَبْدَ اللَّهِ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] ia berkata, Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang mengatakan, 'Aku lupa ayat ini dan ini.' Akan tetapi katakanlah \"Aku telah dilupakan.\" Selalu ulangi-ulangilah bacaan Al Qur`an, sebab ia begitu cepat perginya dari dada seseorang dari pada hilangnya Unta.\" Telah menceritakan kepada kami [Utsman] Telah menceritakan kepada kami [Jarir] dari [Manshur] semisalnya. Mutaba'ahnya adalah [Bisyr] dari [Ibnul Mubarak] dari [Syu'bah]. Dan diikuti pula (mutaba'ah) oleh [Ibnu Juraij] dari [Abdah] dari [Syaqiq] ia berkata; Aku mendengar [Abdullah]; Aku mendengar Nabi shallallahu 'alaihi wasallam."},"4340":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَاهَدُوا الْقُرْآنَ فَوَالَّذِي نَفْسِي بِيَدِهِ لَهُوَ أَشَدُّ تَفَصِّيًا مِنْ الْإِبِلِ فِي عُقُلِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] Telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Peliharalah selalu Al Qur`an, demi Dzat yang jiwaku berada di Tangan-Nya, sungguh ia cepat hilang daripada Unta yang terikat.\""},"4341":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَبُو إِيَاسٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ وَهُوَ يَقْرَأُ عَلَى رَاحِلَتِهِ سُورَةَ الْفَتْحِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Syu'bah] ia berkata; Telah mengabarkan kepadaku [Abu Iyas] ia berkata; Aku mendengar [Abdullah bin Mughaffal] berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam pada hari Fathu Makkah, dan saat itu, beliau sedang membaca surat Al Fath di atas kendaraannya.\""},"4342":{"ar":"حَدَّثَنِي مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَإِنَّ الَّذِي تَدْعُونَهُ الْمُفَصَّلَ هُوَ الْمُحْكَمُ قَالَ وَقَالَ ابْنُ عَبَّاسٍ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا ابْنُ عَشْرِ سِنِينَ وَقَدْ قَرَأْتُ الْمُحْكَمَ","id":"Telah menceritakan kepadaku [Musa bin Isma'il] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] ia berkata; \"Sesungguhnya, surat-surat yang kalian anggap Al Mufashshal itulah Al Muhkam.\" [Ibnu Abbas] juga berkata, \"Rasulullah shallallahu 'alaihi wasallam wafat, sementara aku baru menginjak usia sepuluh tahun. Dan sungguh, aku telah membaca Al Muhkam."},"4343":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاجَمَعْتُ الْمُحْكَمَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ وَمَا الْمُحْكَمُ قَالَ الْمُفَصَّلُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu, ia berkata, \"Aku telah mengumpulkan Al Muhkam pada masa Rasulullah shallallahu 'alaihi wasallam.\" Aku pun bertanya kepadanya, \"Apakah Al Muhkam itu?\" ia menjawab, \"Yaitu, Al Mufashshal (surat-surat pendek).\" "},"4344":{"ar":"حَدَّثَنَا رَبِيعُ بْنُ يَحْيَى حَدَّثَنَا زَائِدَةُ حَدَّثَنَا هِشَامٌ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقْرَأُ فِي الْمَسْجِدِ فَقَالَ يَرْحَمُهُ اللَّهُ لَقَدْ أَذْكَرَنِي كَذَا وَكَذَا آيَةً مِنْ سُورَةِ كَذَاحَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى عَنْ هِشَامٍ وَقَالَ أَسْقَطْتُهُنَّ مِنْ سُورَةِ كَذَا تَابَعَهُ عَلِيُّ بْنُ مُسْهِرٍ وَعَبْدَةُ عَنْ هِشَامٍ","id":"Telah menceritakan kepada kami [Rabi' bin Yahya] Telah menceritakan kepada kami [Za`idah] Telah menceritakan kepada kami [Hisyam] dari [Urwah] dari [Aisyah] radliallahu 'anha, ia berkata; Nabi shallallahu 'alaihi wasallam pernah mendengar seseorang membaca (Al Qur`an) di dalam masjid, lalu beliau bersabda: \"Semoga Allah merahmati si Fulan, sesungguhnya ia telah mengingatkanku ayat ini dan ini, yakni ayat dari surat ini.\" Telah menceritakan kepada kami [Muhammad bin Ubaid bin Maimun] Telah menceritakan kepada kami [Isa] dari [Hisyam] yakni, beliau bersabda: \"Yang aku gugurkan dari surat ini.\" Hadis ini diperkuat oleh [Ali bin Mushir] dan [Abdah] dari [Hisyam]."},"4345":{"ar":"حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقْرَأُ فِي سُورَةٍ بِاللَّيْلِ فَقَالَ يَرْحَمُهُ اللَّهُ لَقَدْ أَذْكَرَنِي كَذَا وَكَذَا آيَةً كُنْتُ أُنْسِيتُهَا مِنْ سُورَةِ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Ahmad bin Abu Raja`] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] ia berkakta; Rasulullah shallallahu 'alaihi wasallam pernah mendengar seseorang membaca suatu surat di malam hari, maka beliau pun bersabda: \"Semoga Allah merahmati si Fulan, sungguh, ia telah mengingatkanku ayat ini dan ini aku telah dilupakan dari surat ini dan ini.\""},"4346":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَ مَا لِأَحَدِهِمْ يَقُولُ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Alangkah celakanya seorang yang mengatakan, 'Aku lupa ayat ini dan ini.' Akan tetapi hendaklah ia mengatakan, 'Aku telah dilupakan.'\""},"4347":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ عَلْقَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآيَتَانِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ مَنْ قَرَأَ بِهِمَا فِي لَيْلَةٍ كَفَتَاهُ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] ia berkata; Telah menceritakan kepadaku [Ibrahim] dari ['Alqamah] dan [Abdurrahman bin Yazid] dari [Abu Mas'ud Al Anshar] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Dua ayat terakhir dari surat Al Baqarah, siapa yang membacanya pada suatu malam, niscaya kedua ayat itu akan mencukupinya.\""},"4348":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ حَدِيثِ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ لِقِرَاءَتِهِ فَإِذَا هُوَ يَقْرَؤُهَا عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَانْتَظَرْتُهُ حَتَّى سَلَّمَ فَلَبَبْتُهُ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَأُ قَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ كَذَبْتَ فَوَاللَّهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُوَ أَقْرَأَنِي هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ فَانْطَلَقْتُ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقُودُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا وَإِنَّكَ أَقْرَأْتَنِي سُورَةَ الْفُرْقَانِ فَقَالَ يَا هِشَامُ اقْرَأْهَا فَقَرَأَهَا الْقِرَاءَةَ الَّتِي سَمِعْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُهَا الَّتِي أَقْرَأَنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Urwah bin Zubair] dari hadits [Al Miswar bin Makhzamah] dan [Abdurrahman bin Abd Al Qari`] bahwa keduanya mendengar [Umar bin Al Khaththab] berkata, Pada masa Rasulullah shallallahu 'alaihi wasallam, aku pernah mendengar Hisyam bin Hakim bin Hizam membacakan surat Al Furqan, maka aku pun mendengarkan bacaannya dengan seksama. Dan ternyata ia membacanya dengan Huruf (cara bacaan) yang begitu banyak, yang Rasulullah shallallahu 'alaihi wasallam sendiri belum membacakan bacaan seperti itu padaku, maka aku pun ingin segera menyergapnya di dalam shalat, namun aku menunggunya hingga selesai salam dan langsung meninting lengan bajunya seraya bertanya, \"Siapa yang membacakan surat ini padamu?\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam yang membacakannya padaku.\" Maka kukatakan padanya, \"Kamu telah berdusta. Demi Allah, sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah membacakan surat -yang telah aku dengar ini darimu- padaku.\" Maka aku pun segera membawanya menghadap Rasulullah shallallahu 'alaihi wasallam. Aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku mendengar orang ini membaca surat Al Furqan dengan cara baca yang belum pernah Anda ajarkan padakku. Dan sungguh, Anda telah membacakan surat Al Furqan padaku.\" Akhirnya beliau bersabda: \"Wahai Hisyam, bacalah surat itu.\" Maka Hisyam pun membacanya bacaan yang telah aku dengan sebelumnya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seperti inilah surat itu diturunkan.\" Kemudian beliau bersabda lagi: \"Bacalah wahai Umar.\" Lalu aku pun membacanya sebagaimana yang telah diajarkan beliau. Kemudian beliau bersabda: \"Seperti ini pulalah ia diturunkan.\" Dan Rasulullah shallallahu 'alaihi wasallam bersabda lagi: \"Al Qur`an diturunkan dengan Sab'atu Ahruf (tujuh dialek) karena itu bacalah sesuai kemampuan kalian.\""},"4349":{"ar":"حَدَّثَنَا بِشْرُ بْنُ آدَمَ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَارِئًا يَقْرَأُ مِنْ اللَّيْلِ فِي الْمَسْجِدِ فَقَالَ يَرْحَمُهُ اللَّهُ لَقَدْ أَذْكَرَنِي كَذَا وَكَذَا آيَةً أَسْقَطْتُهَا مِنْ سُورَةِ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Bisyr bin Adam] Telah mengabarkan kepada kami [Ali bin Mushir] Telah mengabarkan kepada kami [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, ia berkata; Pada suatu malam, Nabi shallallahu 'alaihi wasallam mendengar seseorang membaca Al Qur`an di dalam Masjid, maka beliau pun bersabda: \"Semoga Allah merahmatinya, sungguh ia telah mengingatkanku ayat ini dan ini, yakni ayat yang telah aku gugurkan dari surat ini dan ini.\""},"4350":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا وَاصِلٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَغَدَوْنَا عَلَى عَبْدِ اللَّهِ فَقَالَ رَجُلٌ قَرَأْتُ الْمُفَصَّلَ الْبَارِحَةَ فَقَالَ هَذًّا كَهَذِّ الشِّعْرِ إِنَّا قَدْ سَمِعْنَا الْقِرَاءَةَ وَإِنِّي لَأَحْفَظُ الْقُرَنَاءَ الَّتِي كَانَ يَقْرَأُ بِهِنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيَ عَشْرَةَ سُورَةً مِنْ الْمُفَصَّلِ وَسُورَتَيْنِ مِنْ آلِ حم","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Mahdi bin Maimun] Telah menceritakan kepada kami [Washil] dari [Abu Wa`il] dari [Abdullah] ia berkata; Kami pergi menemui Abdullah, lalu seorang laki-laki berkata, \"Semalam aku membaca Al Mufashshal.\" Maka Abdullah berkata, \"Bacalah sebagaimana pembacaan Sya'ir. Sesungguhnya kami telah mendengar bacaan itu. Dan aku benar-benar telah menghafal Al Quran yang biasa dibaca oleh Nabi shallallahu 'alaihi wasallam, yakni delapan belas surat dari Al Mufashshal, dari dua surat dari `Aali Haamiim.\""},"4351":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَافِي قَوْلِهِ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ }قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَزَلَ جِبْرِيلُ بِالْوَحْيِ وَكَانَ مِمَّا يُحَرِّكُ بِهِ لِسَانَهُ وَشَفَتَيْهِ فَيَشْتَدُّ عَلَيْهِ وَكَانَ يُعْرَفُ مِنْهُ فَأَنْزَلَ اللَّهُ الْآيَةَ الَّتِي فِي لَا أُقْسِمُ بِيَوْمِ الْقِيَامَةِ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ إِنَّ عَلَيْنَا جَمْعَهُ }فَإِنَّ عَلَيْنَا أَنْ نَجْمَعَهُ فِي صَدْرِكَ{ وَقُرْآنَهُ فَإِذَا قَرَأْنَاهُ فَاتَّبِعْ قُرْآنَهُ }فَإِذَا أَنْزَلْنَاهُ فَاسْتَمِعْ{ ثُمَّ إِنَّ عَلَيْنَا بَيَانَهُ }قَالَ إِنَّ عَلَيْنَا أَنْ نُبَيِّنَهُ بِلِسَانِكَ قَالَ وَكَانَ إِذَا أَتَاهُ جِبْرِيلُ أَطْرَقَ فَإِذَا ذَهَبَ قَرَأَهُ كَمَا وَعَدَهُ اللَّهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Musa bin Abu Aisyah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma, yakni terkait dengan firman-Nya, \"LAA TUHARRIK BIHI LISAANAKA LITA'JALA BIHI.\" Ibnu Abbas berkata, \"Apabila Jibril turun kepada Rasulullah shallallahu 'alaihi wasallam dengan membawa wahyu, maka biasanya beliau mengerakkan dan lisan dan kedua bibirnya, serta agaknya beliau merasakan sesuatu yang berat. Maka Allah menurunkan ayat yang di dalamnya terdapat ungkapan, \"LAA UQSIMU BIHAADZA BIYAUMIL QIYAAMAH.., LAA TUHARRIK BIHI LISAANAKA LITA'JALA BIHI, INNA 'ALAINA JAM'AHU..\" maksudnya adalah, bahwa Kamilah yang akan mengumpulkannya di dalam dadamu.\"FA`IDZAA QARA`NAAHU FATTABI' QUR`AANAH..\" Yakni, apabila kami menurunkannya maka dengarkanlah.\"TSUMMA 'ALAINAA BAYAANAH..\" Yakni, Kamilah yang akan menjelaskannya melalui perantara lisanmu. Biasanya, apabila beliau didatangi oleh Jibril, maka beliau menunduk, dan setelah Jibril pergi, beliau membacanya sebagaimana yang diperintahkan Allah."},"4352":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ الْأَزْدِيُّ حَدَّثَنَا قَتَادَةُ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍعَنْ قِرَاءَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ يَمُدُّ مَدًّا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] Telah menceritakan kepada kami [Jarir bin Hazim Al Azdi] Telah menceritakan kepada kami [Qatadah] ia berkata; Aku pernah bertanya kepada [Anas bin Malik] mengenai bacaan Nabi shallallahu 'alaihi wasallam, maka ia pun menjawab, \"Bacaan beliau adalah memanjangkan sehingga bisa dibaca.\""},"4353":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ سُئِلَ أَنَسٌكَيْفَ كَانَتْ قِرَاءَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَتْ مَدًّا ثُمَّ قَرَأَ{ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ }يَمُدُّ بِبِسْمِ اللَّهِ وَيَمُدُّ بِالرَّحْمَنِ وَيَمُدُّ بِالرَّحِيمِ","id":"Telah menceritakan kepada kami [Amru bin 'Ashim] Telah menceritakan kepada kami [Hammam] dari [Qatadah] ia berkata; [Anas] pernah ditanya, \"Bagaimankah bacaan Nabi shallallahu 'alaihi wasallam?\" Ia pun menjawab, \"Bacaan beliau adalah panjang.\" Lalu ia pun membaca: \"BISMILLAAHIRRAHMAANIRRAHIIM.\" Anas menjelaskan, \"Beliau memanjangkan bacaan, 'BISMILLAH' dan juga memanjangkan bacaan, 'ARRAHMAAN' serta bacaan, 'ARRAHIIM.'\""},"4354":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِيَاسٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ وَهُوَ عَلَى نَاقَتِهِ أَوْ جَمَلِهِ وَهِيَ تَسِيرُ بِهِ وَهُوَ يَقْرَأُ سُورَةَ الْفَت��حِ أَوْ مِنْ سُورَةِ الْفَتْحِ قِرَاءَةً لَيِّنَةً يَقْرَأُ وَهُوَ يُرَجِّعُ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abu Iyas] ia berkata, Aku mendengar [Abdullah bin Mughaffal] berkata; Aku pernah melihat Nabi shallallahu 'alaihi wasallam membaca saat beliau berada di atas Untanya yang berjalan, ketika itu beliau membaca surat Al Fath atau bagian dari surat Al Fath, yakni dengan bacaan yang pelan seraya mengulang-ngulangnya.\""},"4355":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفٍ أَبُو بَكْرٍ حَدَّثَنَا أَبُو يَحْيَى الْحِمَّانِيُّ حَدَّثَنَا بُرَيْدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَا أَبَا مُوسَى لَقَدْ أُوتِيتَ مِزْمَارًا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Telah menceritakan kepada kami [Muhammd bin Khalaf Abu Bakr] Telah menceritakan kepada kami [Abu Yahya Al Himmani] Telah menceritakan kepada kami [Buraid bin Abdulla bin Abu Burdah] dari [kakeknya, Abu Burdah] dari [Abu Musa] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda kepadanya: \"Wahai Abu Musa, sesungguhnya aku telah diberi Mizmar (seruling) dari Mazaamir (seruling) -nya keluarga Dawud.\""},"4356":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي عَنْ الْأَعْمَشِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ الْقُرْآنَ قُلْتُ آقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [bapakku] dari [Al A'masy] ia berkata; Telah menceritakan kepadaku [Ibrahim] dari [Abidah] dari [Abdullah] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam pernah bersabda padaku: \"Bacakanlah Al Qur`an untukku.\" Aku pun berkata, \"Apakah aku akan membacakan untuk Anda, padahal ia diturunkan kepada Anda?\" beliau bersabda: \"Sesungguhnya aku suka untuk mendengarnya dari orang lain.\""},"4357":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ قُلْتُ يَا رَسُولَ اللَّهِ آقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ نَعَمْ فَقَرَأْتُ سُورَةَ النِّسَاءِ حَتَّى أَتَيْتُ إِلَى هَذِهِ الْآيَةِ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ حَسْبُكَ الْآنَ فَالْتَفَتُّ إِلَيْهِ فَإِذَا عَيْنَاهُ تَذْرِفَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Abidah] dari [Abdullah bin Mas'ud] ia berkata; Nabi shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Bacakanlah Al Qur`an untukku.\" Maka aku pun berkata, \"Wahai Rasulullah, apakah aku akan membacanya untuk Anda, padahal kepada Andalah alquran diturunkan?\" beliau menjawab: \"Ya.\" Lalu aku pun membacakan surat An Nisa, hingga aku sampai pada ayat: \"Dan bagaimanakah sekiranya Kami mendatangkan manusia dari seluruh umat dengan seorang saksi, lalu kami mendatangkanmu sebagai saksi atas mereka.\" Maka beliau pun bersabda padaku: \"Cukuplah.\" Lalu aku menoleh ke arah beliau dan ternyata kedua matanya meneteskan air."},"4358":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُقَالَ لِي ابْنُ شُبْرُمَةَ نَظَرْتُ كَمْ يَكْفِي الرَّجُلَ مِنْ الْقُرْآنِ فَلَمْ أَجِدْ سُورَةً أَقَلَّ مِنْ ثَلَاثِ آيَاتٍ فَقُلْتُ لَا يَنْبَغِي لِأَحَدٍ أَنْ يَقْرَأَ أَقَلَّ مِنْ ثَلَاثِ آيَاتٍ قَالَ عَلِيٌّ حَدَّثَنَا سُفْيَانُ أَخْبَرَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ أَخْبَرَهُ عَلْقَمَةُ عَنْ أَبِي مَسْعُودٍ وَلَقِيتُهُ وَهُوَ يَطُوفُ بِالْبَيْتِ فَذَكَرَ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَنْ قَرَأَ بِالْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","id":"Telah menceritakan kepada kami Ali Telah menceritakan kepada kami Sufyan bahwa Ibnu Syubrumah berkata kepadaku, \"Aku berfikir, berapa ayatkah yang paling minimal dibaca oleh seseorang, namun aku tidak mendapatkan satu suratpun yang kurang dari tiga ayat. Karena itu aku pun berkata, bahwa tidak selayaknya bagi seorang pun untuk membaca Al Qur`an kurang dari tiga ayat.\" [Ali] berkata; Telah menceritakan kepada kami [Sufyan] Telah mengabarkan kepada kami [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] bahwa [Alqamah] telah mengabarkan kepadanya dari [Abu Mas'ud] dan saya pun menemuinya saat ia melakukan thawaf di Baitullah. Lalu ia menyebutkan sabda Nabi shallallahu 'alaihi wasallam, bahwasanya: \"Barangsiapa yang membaca dua ayat terakhir dari surat Al Baqarah pada suatu malam, maka kedua ayat itu akan mencukupinya.\""},"4359":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُغِيرَةَ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَأَنْكَحَنِي أَبِي امْرَأَةً ذَاتَ حَسَبٍ فَكَانَ يَتَعَاهَدُ كَنَّتَهُ فَيَسْأَلُهَا عَنْ بَعْلِهَا فَتَقُولُ نِعْمَ الرَّجُلُ مِنْ رَجُلٍ لَمْ يَطَأْ لَنَا فِرَاشًا وَلَمْ يُفَتِّشْ لَنَا كَنَفًا مُنْذُ أَتَيْنَاهُ فَلَمَّا طَالَ ذَلِكَ عَلَيْهِ ذَكَرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْقَنِي بِهِ فَلَقِيتُهُ بَعْدُ فَقَالَ كَيْفَ تَصُومُ قَالَ كُلَّ يَوْمٍ قَالَ وَكَيْفَ تَخْتِمُ قَالَ كُلَّ لَيْلَةٍ قَالَ صُمْ فِي كُلِّ شَهْرٍ ثَلَاثَةً وَاقْرَإِ الْقُرْآنَ فِي كُلِّ شَهْرٍ قَالَ قُلْتُ أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ ثَلَاثَةَ أَيَّامٍ فِي الْجُمُعَةِ قُلْتُ أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ أَفْطِرْ يَوْمَيْنِ وَصُمْ يَوْمًا قَالَ قُلْتُ أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ صُمْ أَفْضَلَ الصَّوْمِ صَوْمَ دَاوُدَ صِيَامَ يَوْمٍ وَإِفْطَارَ يَوْمٍ وَاقْرَأْ فِي كُلِّ سَبْعِ لَيَالٍ مَرَّةً فَلَيْتَنِي قَبِلْتُ رُخْصَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَاكَ أَنِّي كَبِرْتُ وَضَعُفْتُ فَكَانَ يَقْرَأُ عَلَى بَعْضِ أَهْلِهِ السُّبْعَ مِنْ الْقُرْآنِ بِالنَّهَارِ وَالَّذِي يَقْرَؤُهُ يَعْرِضُهُ مِنْ النَّهَارِ لِيَكُونَ أَخَفَّ عَلَيْهِ بِاللَّيْلِ وَإِذَا أَرَادَ أَنْ يَتَقَوَّى أَفْطَرَ أَيَّامًا وَأَحْصَى وَصَامَ مِثْلَهُنَّ كَرَاهِيَةَ أَنْ يَتْرُكَ شَيْئًا فَارَقَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِقَالَ أَبُو عَبْد اللَّهِ وَقَالَ بَعْضُهُمْ فِي ثَلَاثٍ وَفِي خَمْسٍ وَأَكْثَرُهُمْ عَلَى سَبْعٍ","id":"Telah menceritakan kepada kami [Musa] Telah menceritakan kepada kami [Abu 'Awanah] dari [Al Mughirah] dari [Mujahid] dari [Abdullah bin Amru] ia berkata; Bapakku menikahkanku dengan seorang wanita yang memiliki kemuliaan leluhur. Lalu bapakku bertanya pada sang menantunya mengenai suaminya. Maka sang menantu pun berkata, \"Dia adalah laki-laki terbaik, ia belum pernah meniduriku dan tidak juga memelukku mesra semenjak aku menemuinya.\" Maka setelah selang beberapa lama, bapakku pun mengadukan hal itu pada Nabi shallallahu 'alaihi wasallam, akhirnya beliau bersabda: \"Bawalah ia kemari.\" Maka setelah itu, aku pun datang menemui beliau, dan belaiau bersabda: \"Bagaimanakah ibadah puasamu?\" aku menjawab, \"Yaitu setiap hari.\" Beliau bertanya lagi, \"Lalu bagaimana dengan Khataman Al Qur`anmu?\" aku menjawab, \"Yaitu setiap malam.\" Akhirnya beliau bersabda: \"Berpuasalah tiga hari pada setiap bulannya. Dan bacalah (Khatamkanlah) Al Qur`an sekali pada setiap bulannya.\" Aku katakan, \"Aku mampu lebih dari itu.\" Beliau bersabda: \"Kalau begitu, berpuasalah tiga hari dalam satu pekan.\" Aku berkata, \"Aku masih mampu lebih dari itu.\" Beliau bersabda: \"Kalau begitu, berbukalah sehari dan berpuasalah sehari.\" Aku katakan, \"Aku masih mampu lebih dari itu.\" Beliau bersabda: \"Berpuasalah dengan puasa yang paling utama, yakni puasa Dawud, yaitu berpuasa sehari dan berbuka sehari. Dan khatamkanlah Al Qur`an sekali dalam tujuh hari.\" Maka sekiranya aku menerima keringanan yang diberikan Nabi shallallahu 'alaihi wasallam, saat itu aku masih kuat, sementara sekarang telah menjadi lemah. Mujahid berkata; Lalu ia membacakan sepertujuh dari Al Qur`an kepada keluarganya pada siang hari, dan ayat yang ia baca, ia perlihatkan pada siang harinya hingga pada malam harinya ia bisa lebih mudah membacanya. Dan bila ingin memperoleh kekuatan, maka ia akan berbuka beberapa hari dan menghitungnya, lalu ia berpuasa sebanyak itu pula, sebab ia tak suka meninggalkan sesuatu yang menyelisihi Nabi shallallahu 'alaihi wasallam. Abu Abdullah berkata; Dan sebagian mereka berkata; Tiga, atau lima, dan yang terbanyak adalah tujuh."},"4360":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كَمْ تَقْرَأُ الْقُرْآنَ","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Muhammad bin Abdurrahman] dari [Abu Salamah] dari [Abdullah bin Amru] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Berapa lamakah kamu membaca (mampu mengkhatamkan) Al Qur`an?\""},"4361":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَيْبَانَ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى بَنِي زُهْرَةَ عَنْ أَبِي سَلَمَةَ قَالَ وَأَحْسِبُنِي قَالَ سَمِعْتُ أَنَا مِنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَإِ الْقُرْآنَ فِي شَهْرٍ قُلْتُ إِنِّي أَجِدُ قُوَّةً حَتَّى قَالَ فَاقْرَأْهُ فِي سَبْعٍ وَلَا تَزِدْ عَلَى ذَلِكَ","id":"Telah menceritakan kepadaku [Ishaq] Telah mengabarkan kepada kami [Ubaidullah bin Musa] dari [Syaiban] dari [Yahya] dari [Muhamamd bin Abdurrahman] Maula Bani Zuhrah, dari [Abu Salamah] ia berkata; -dan aku menduga ia berkata- Aku mendengar dari Abu Salamah dari [Abdullah bin Amru] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah Al Qur`an itu dalam satu bulan.\" Aku berkata, \"Sesungguhnya aku lebih mampu dari itu.\" Beliau bersabda: \"Kalau begitu, bacalah (khatamkanlah) ia dalam tujuh hari, dan janganlah melewati batas itu.\""},"4362":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَ يَحْيَى بَعْضُ الْحَدِيثِ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَ الْأَعْمَشُ وَبَعْضُ الْحَدِيثِ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنْ إِبْرَاهِيمَ وَعَنْ أَبِيهِ عَنْ أَبِي الضُّحَى عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ قَالَ قُلْتُ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أَشْتَهِي أَنْ أَسْمَعَهُ مِنْ غَيْرِي قَالَ فَقَرَأْتُ النِّسَاءَ حَتَّى إِذَا بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }قَالَ لِي كُفَّ أَوْ أَمْسِكْ فَرَأَيْتُ عَيْنَيْهِ تَذْرِفَانِ","id":"Telah menceritakan kepada kami [Shadaqah] Telah mengabarkan kepada kami [Yahya] dari [Sufyan] dari [Sulaiman] dari [Ibrahim] dari [Abidah] dari [Abdullah] - [Yahya] berkata, sebagian hadits dari [Amru bin Murrah] - ia berkata; Nabi shallallahu 'alaihi wasallam bersabda padaku.. Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Sufyan] dari [Al A'masy] dari [Ibrahim] dari [Abidah] dari [Abdullah] - [Al A'masy] berkata; dan sebagian hadits- Telah menceritakan kepadaku [Amru bin Murrah] dari [Ibrahim] dari [bapaknya] dari [Abu Dluhaa] dari [Abdulalh] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacakanlah Al Qur`an padaku.\" Aku pun berkata, \"Aku membacakannya untuk Anda, padahal kepada Andalah ia diturunkan?\" beliau bersabda: \"Sesungguhnya aku suka mendengarnya dari orang lain.\" Akhirnya aku pun membacakan surat An-Nisa` dan ketika sampai pada ayat: \"Dan bagaimanakah sekiranya Kami mendatangkan manusia dari seluruh umat dengan seorang saksi, lalu kami mendatangkanmu sebagai saksi atas mereka.\" Maka beliau pun bersabda padaku: \"Cukuplah.\" Lalu aku pun melihat kedua mata beliau meneteskan air."},"4363":{"ar":"حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ السَّلْمَانِيِّ عَنْ عَبْدِ اللَّهِ بْن�� مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ قُلْتُ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي","id":"Telah menceritakan kepada kami [Qais bin Hafsh] Telah menceritakan kepada kami [Abdul Wahid] Telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Abidah As Silmani] dari [Abdullah bin Mas'ud] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam pernah bersabda padaku: \"Bacakanlah Al Qur`an padaku.\" Aku pun berkata, \"Aku membacakannya untuk Anda, padahal kepada Andalah ia diturunkan?\" beliau bersabda: \"Sesungguhnya aku suka mendengarnya dari orang lain.\""},"4364":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ عَنْ خَيْثَمَةَ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَأْتِي فِي آخِرِ الزَّمَانِ قَوْمٌ حُدَثَاءُ الْأَسْنَانِ سُفَهَاءُ الْأَحْلَامِ يَقُولُونَ مِنْ خَيْرِ قَوْلِ الْبَرِيَّةِ يَمْرُقُونَ مِنْ الْإِسْلَامِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ لَا يُجَاوِزُ إِيمَانُهُمْ حَنَاجِرَهُمْ فَأَيْنَمَا لَقِيتُمُوهُمْ فَاقْتُلُوهُمْ فَإِنَّ قَتْلَهُمْ أَجْرٌ لِمَنْ قَتَلَهُمْ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] Telah menceritakan kepada kami [Al A'masy] dari [Khaitsamah] dari [Suwaid bin Ghaflah] bahwa [Ali] radliallahu 'anhu berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Pada akhir zaman nanti, akan datang suatu kaum yang muda usianya lagi bodoh. Mereka berkata-kata dengan kebaikan, akan tetapi mereka keluar dari Islam sebagaimana meluncurnya anak panah dari busurnya. Keimanan mereka tidaklah melewati batas tenggorokan (tidak meresap dalam hati). Karena itu, dimana pun kalian menemukannya, maka bunuhlah mereka. Karena sesungguhnya membunuh mereka merupakan pahala, yakni pahala pada hari kiamat bagi yang membunuh mereka.\""},"4365":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَخْرُجُ فِيكُمْ قَوْمٌ تَحْقِرُونَ صَلَاتَكُمْ مَعَ صَلَاتِهِمْ وَصِيَامَكُمْ مَعَ صِيَامِهِمْ وَعَمَلَكُمْ مَعَ عَمَلِهِمْ وَيَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَنَاجِرَهُمْ يَمْرُقُونَ مِنْ الدِّينِ كَمَا يَمْرُقُ السَّهْمُ مِنْ الرَّمِيَّةِ يَنْظُرُ فِي النَّصْلِ فَلَا يَرَى شَيْئًا وَيَنْظُرُ فِي الْقِدْحِ فَلَا يَرَى شَيْئًا وَيَنْظُرُ فِي الرِّيشِ فَلَا يَرَى شَيْئًا وَيَتَمَارَى فِي الْفُوقِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Muhammad ibn Ibrahim bin Al Harits At Taimi] dari [Abu Salamah bin Abdurrahman] dari [Abu Said Al Khudri] radliallahu 'anhu, ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada suatu kaum yang berada ditengah-tengah kalian, dan kalian akan meremehkan shalat kalian bila melihat shalat mereka, begitu juga dengan shaum kalian jika melihat shaum mereka, serta amal kalian jika melihat amal mereka. Akan tetapi, mereka membaca Al Qur`an, namun bacaan mereka tidak sampai melewati batas tenggorokan, mereka keluar dari Din, sebagaimana meluncurnya anak panah dari busurnya. Ia melihat pada ujung panahnya, namun ia tidak mendapatkan sesuatu, kemudian melihat pada lubangnya, juga tak menemukan sesuatu, lalu ia melihat pada bulunya juga tidak melihat sesuatu. Ia pun saling berselisih akan ujung panahnya.\""},"4366":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ الَّذِي يَقْرَأُ الْقُرْآنَ وَيَعْمَلُ بِهِ كَالْأُتْرُجَّةِ طَعْمُهَا طَيِّبٌ وَرِيحُهَا طَيِّبٌ وَالْمُؤْمِنُ الَّذِي لَا يَقْرَأُ الْقُرْآنَ وَيَعْمَلُ بِهِ كَالتَّمْرَةِ طَعْمُهَا طَيِّبٌ وَلَا رِيحَ لَهَا وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ كَالرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَالْحَنْظَلَةِ طَعْمُهَا مُرٌّ أَوْ خَبِيثٌ وَرِيحُهَا مُرٌّ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang mukmin yang membaca Al Qur`an dan beramal denganya adalah bagaikan buah utrujah, rasanya lezat dan baunya juga sedap. Dan orang mukmin yang tidak membaca Al Qur`an namun beramal dengannya adalah seperti buah kurma, rasanya manis, namun tidak ada baunya. Sedangkan perumpamaan orang munafik yang membaca Al Qur`an adalah seperti Ar Raihanah, aromanya sedap, tetapi rasanya pahit. Dan perumpamaan orang munafik yang tidak membaca Al Qur`an adalah seperti Al Hanzhalah, rasanya pahit dan baunya juga busuk.\""},"4367":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ جُنْدَبِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْرَءُوا الْقُرْآنَ مَا ائْتَلَفَتْ قُلُوبُكُمْ فَإِذَا اخْتَلَفْتُمْ فَقُومُوا عَنْهُ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad] dari [Abu Imran Al Jauni] dari [Jundub bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bacalah Al Qur`an ketika hati-hati kalian memang menyatu, namun jika kalian berselisih, maka beranjaklah darinya.\""},"4368":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سَلَّامُ بْنُ أَبِي مُطِيعٍ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ جُنْدَبٍقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا الْقُرْآنَ مَا ائْتَلَفَتْ عَلَيْهِ قُلُوبُكُمْ فَإِذَا اخْتَلَفْتُمْ فَقُومُوا عَنْهُتَابَعَهُ الْحَارِثُ بْنُ عُبَيْدٍ وَسَعِيدُ بْنُ زَيْدٍ عَنْ أَبِي عِمْرَانَ وَلَمْ يَرْفَعْهُ حَمَّادُ بْنُ سَلَمَةَ وَأَبَانُ وَقَالَ غُنْدَرٌ عَنْ شُعْبَةَ عَنْ أَبِي عِمْرَانَ سَمِعْتُ جُنْدَبًا قَوْلَهُ وَقَالَ ابْنُ عَوْنٍ عَنْ أَبِي عِمْرَانَ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ عُمَرَ قَوْلَهُ وَجُنْدَبٌ أَصَحُّ وَأَكْثَرُ","id":"Telah menceritakan kepada kami [Amru bin Ali] Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Sallam bin Abu Muthi'] dari [Abu Imran Al Jauni] dari [Jundub] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Bacalah Al Qur`an ketika hati kalian memang menyatu, namun jika kalian berselisih, maka beranjaklah darinya.\" Termasuk Mutaba'ahnya adalah [Al Harits bin Ubaid] dan [Sa'id bin Zaid], dari [Abu Imran] namun [Hammad bin Salamah] dan [Aban] tidak memarfu'kannya. [Ghundar] berkata,; dari [Syu'bah] dari [Abu Imran] Aku mendengar [Jundub] berkata; Dan [Ibnu 'Aun] berkata; dari [Abu Imran] dari [Abdullah bin Shamit] dari [Umar]. Ungkapannya; Dan Jundub adalah lebih shahih dan lebih banyak."},"4369":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ النَّزَّالِ بْنِ سَبْرَةَ عَنْ عَبْدِ اللَّهِأَنَّهُ سَمِعَ رَجُلًا يَقْرَأُ آيَةً سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِلَافَهَا فَأَخَذْتُ بِيَدِهِ فَانْطَلَقْتُ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كِلَاكُمَا مُحْسِنٌ فَاقْرَأَا أَكْبَرُ عِلْمِي قَالَ فَإِنَّ مَنْ كَانَ قَبْلَكُمْ اخْتَلَفُوا فَأُهْلِكُوا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Maisarah] dari [An Nazzal bin Sabrah] dari [Abdullah] bahwa ia mendengar seorang laki-laki membaca ayat, sementara ia mendengar Nabi shallallahu 'alaihi wasallam membacanya tidak seperti itu. Maka aku pun mengambil tanganya dan pergi bersamanya menghadap Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Bacaan keduanya adalah sama baiknya. Bacalah, 'AKBARU 'ILMI.'\" Beliau bersabda: \"Sesungguhnya orang-orang sebelum kalian telah berselisih, sehingga mereka pun binasa.\""},"4370":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنَا حُمَيْدُ بْنُ أَبِي حُمَيْدٍ الطَّوِيلُ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُجَاءَ ثَلَاثَةُ رَهْطٍ إِلَى بُيُوتِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُونَ عَنْ عِبَادَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أُخْبِرُوا كَأَنَّهُمْ تَقَالُّوهَا فَقَالُوا وَأَيْنَ نَحْنُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ قَالَ أَحَدُهُمْ أَمَّا أَنَا فَإِنِّي أُصَلِّي اللَّيْلَ أَبَدًا وَقَالَ آخَرُ أَنَا أَصُومُ الدَّهْرَ وَلَا أُفْطِرُ وَقَالَ آخَرُ أَنَا أَعْتَزِلُ النِّسَاءَ فَلَا أَتَزَوَّجُ أَبَدًا فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِمْ فَقَالَ أَنْتُمْ الَّذِينَ قُلْتُمْ كَذَا وَكَذَا أَمَا وَاللَّهِ إِنِّي لَأَخْشَاكُمْ لِلَّهِ وَأَتْقَاكُمْ لَهُ لَكِنِّي أَصُومُ وَأُفْطِرُ وَأُصَلِّي وَأَرْقُدُ وَأَتَزَوَّجُ النِّسَاءَ فَمَنْ رَغِبَ عَنْ سُنَّتِي فَلَيْسَ مِنِّي","id":"Telah menceritakan kepada kami [Sa'id bin Amir Abu Maryam] Telah mengabarkan kepada kami [Muhammad bin Ja'far] Telah mengabarkan kepada kami [Humaid bin Abu Humaid Ath Thawil] bahwa ia mendengar [Anas bin Malik] radliallahu 'anhu berkata; Ada tiga orang mendatangi rumah isteri-isteri Nabi shallallahu 'alaihi wasallam dan bertanya tentang ibadah Nabi shallallahu 'alaihi wasallam. Dan setelah diberitakan kepada mereka, sepertinya mereka merasa hal itu masih sedikit bagi mereka. Mereka berkata, \"Ibadah kita tak ada apa-apanya dibanding Rasulullah shallallahu 'alaihi wasallam, bukankah beliau sudah diampuni dosa-dosanya yang telah lalu dan juga yang akan datang?\" Salah seorang dari mereka berkata, \"Sungguh, aku akan shalat malam selama-lamanya.\" Kemudian yang lain berkata, \"Kalau aku, maka sungguh, aku akan berpuasa Dahr (setahun penuh) dan aku tidak akan berbuka.\" Dan yang lain lagi berkata, \"Aku akan menjauhi wanita dan tidak akan menikah selama-lamanya.\" Kemudian datanglah Rasulullah shallallahu 'alaihi wasallam kepada mereka seraya bertanya: \"Kalian berkata begini dan begitu. Ada pun aku, demi Allah, adalah orang yang paling takut kepada Allah di antara kalian, dan juga paling bertakwa. Aku berpuasa dan juga berbuka, aku shalat dan juga tidur serta menikahi wanita. Barangsiapa yang benci sunnahku, maka bukanlah dari golonganku.\""},"4371":{"ar":"حَدَّثَنَا عَلِيٌّ سَمِعَ حَسَّانَ بْنَ إِبْرَاهِيمَ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَعَنْ قَوْلِهِ تَعَالَى{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ مَثْنَى وَثُلَاثَ وَرُبَاعَ فَإِنْ خِفْتُمْ أَلَّا تَعْدِلُوا فَوَاحِدَةً أَوْ مَا مَلَكَتْ أَيْمَانُكُمْ ذَلِكَ أَدْنَى أَلَّا تَعُولُوا }قَالَتْ يَا ابْنَ أُخْتِي الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي مَالِهَا وَجَمَالِهَا يُرِيدُ أَنْ يَتَزَوَّجَهَا بِأَدْنَى مِنْ سُنَّةِ صَدَاقِهَا فَنُهُوا أَنْ يَنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فَيُكْمِلُوا الصَّدَاقَ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ مِنْ النِّسَاءِ","id":"Telah menceritakan kepada kami [Ali] Ia telah mendengar [Hassan bin Ibrahim] dari [Yunus bin Yazid] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Urwah] bahwa ia bertanya kepada [Aisyah] tentang firman Allah Ta'ala: \"Dan jika kalian khawatir tidak bisa berlaku adil terhadap anak yatim, maka nikahilah wanita yang baik-baik, dua, tiga, atau empat, jika kalian tidak bisa berlaku adil, maka kawinilah satu saja, atau hamba sahaya kalian, itu lebih dekat agar kalian tidak melanggar batas (QS. Annisa' 3). Maka Aisyah menjelaskan, \"Wahai anak saudaraku, maksudnya adalah seorang anak perempuan yatim bertempat tinggal di rumah walinya. Lalu ia pun menginginkan harta dan juga kecantikannya. Ia ingin menikahinya dengan mahar yang sedikit, maka mereka dilarang untuk menikahinya kecuali mereka dapat berbuat adil terhadap mereka dan menyempurnakan mahar. Karena itu, mereka diperintahkan untuk menikahi wanita-wanita selain mereka.\""},"4372":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ عَلْقَمَةَ قَالَ كُنْتُ مَعَ عَبْدِ اللَّهِفَلَقِيَهُ عُثْمَانُ بِمِنًى فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّ لِي إِلَيْكَ حَاجَةً فَخَلَوَا فَقَالَ عُثْمَانُ هَلْ لَكَ يَا أَبَا عَبْدِ الرَّحْمَنِ فِي أَنْ نُزَوِّجَكَ بِكْرًا تُذَكِّرُكَ مَا كُنْتَ تَعْهَدُ فَلَمَّا رَأَى عَبْدُ اللَّهِ أَنْ لَيْسَ لَهُ حَاجَةٌ إِلَى هَذَا أَشَارَ إِلَيَّ فَقَالَ يَا عَلْقَمَةُ فَانْتَهَيْتُ إِلَيْهِ وَهُوَ يَقُولُ أَمَا لَئِنْ قُلْتَ ذَلِكَ لَقَدْ قَالَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الشَّبَابِ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّهُ لَهُ وِجَاءٌ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] ia berkata; Telah menceritakan kepadaku [Ibrahim] dari ['Alqamah] ia berkata; Aku berada bersama [Abdullah], lalu ia pun ditemui oleh Utsman di Mina. Utsman berkata, \"Wahai Abu Abdurrahman, sesungguhnya aku memiliki hajat padamu.\" Maka keduanya berbicara empat mata. Utsman bertanya, \"Apakah kamu wahai Abu Abdurrahman kami nikahkan dengan seorang gadis yang akan mengingatkanmu apa yang kamu lakukan?\" Maka ketika Abdullah melihat bahwa ia tidak berhasrat akan hal ini, ia pun memberi isyarat padaku seraya berkata, \"Wahai 'Alqamah.\" Maka aku pun segera menuju ke arahnya. Ia berkata, \"Kalau Anda berkata seperti itu, maka sesungguhnya Nabi shallallahu 'alaihi wasallam telah bersabda kepada kita: 'Wahai sekalian pemuda, siapa di antara kalian yang telah mempunyai kemampuan, maka hendaklah ia menikah, dan barangsiapa yang belum mampu, hendaklah ia berpuasa karena hal itu akan lebih bisa meredakan gejolaknya.'\""},"4373":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي عُمَارَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَدَخَلْتُ مَعَ عَلْقَمَةَ وَالْأَسْوَدِ عَلَى عَبْدِ اللَّهِ فَقَالَ عَبْدُ اللَّهِ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَبَابًا لَا نَجِدُ شَيْئًا فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الشَّبَابِ مَنْ اسْتَطَاعَ الْبَاءَةَ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّهُ لَهُ وِجَاءٌ","id":"Telah menceritakan kepada kami [Amru bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] ia berkata; Telah menceritakan kepadaku [Umarah] dari [Abdurrahman bin Yazid] ia berkata; Aku, Alqamah dan Al Aswad pernah menemui [Abdullah], lalu ia pun berkata; Pada waktu muda dulu, kami pernah berada bersama Nabi shallallahu 'alaihi wasallam. Saat itu, kami tidak sesuatu pun, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Wahai sekalian pemuda, siapa diantara kalian telah mempunyai kemampuan, maka hendaklah ia menikah, karena menikah itu dapat menundukkan pandangan, dan juga lebih bisa menjaga kemaluan. Namun, siapa yang belum mampu, hendaklah ia berpuasa, sebab hal itu dapat meredakan nafsunya.\""},"4374":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي عَطَاءٌ قَالَ حَضَرْنَا مَعَ ابْنِ عَبَّاسٍجِنَازَةَ مَيْمُونَةَ بِسَرِفَ فَقَالَ ابْنُ عَبَّاسٍ هَذِهِ زَوْجَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا رَفَعْتُمْ نَعْشَهَا فَلَا تُزَعْزِعُوهَا وَلَا تُزَلْزِلُوهَا وَارْفُقُوا فَإِنَّهُ كَانَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعٌ كَانَ يَقْسِمُ لِثَمَانٍ وَلَا يَقْسِمُ لِوَاحِدَةٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka, ia berkata; Telah mengabarkan kepadaku [Atha`] ia berkata; Kami pernah menghadiri jenazah Maimunah bersama Ibnu Abbas di Saif, lalu [Ibnu Abbas] berkata, \"Ini adalah salah seorang isteri Nabi shallallahu 'alaihi wasallam. Jika kalian mengangkat usungannya, maka janganlah kalian menggoncangkannya dengan keras, kokohkanlah dengan sempurna. Sesungguhnya di sisi Nabi shallallahu 'alaihi wasallam ada sembilan orang isteri, beliau membagi hari-hari kepada delapan orang, sementara kepada yang satu orang tidak.\""},"4375":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي لَيْلَةٍ وَاحِدَةٍ وَلَهُ تِسْعُ نِسْوَةٍو قَالَ لِي خَلِيفَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ أَنَّ أَنَسًا حَدَّثَهُمْ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yazid bin Zurai'] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] radliallahu 'anhu, bahwasanya Nabi shallallahu 'alaihi wasallam pernah menggilir para isterinya dalam satu malam, sementara saat itu beliau memiliki sembilan orang isteri. [Khalifah] berkata kepadaku; Telah menceritakan kepada kami [Yazid bin Zurai'] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] bahwa [Anas] telah menceritakan kepada mereka, dari Nabi shallallahu 'alaihi wasallam."},"4376":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْحَكَمِ الْأَنْصَارِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ رَقَبَةَ عَنْ طَلْحَةَ الْيَامِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قَالَ لِي ابْنُ عَبَّاسٍهَلْ تَزَوَّجْتَ قُلْتُ لَا قَالَ فَتَزَوَّجْ فَإِنَّ خَيْرَ هَذِهِ الْأُمَّةِ أَكْثَرُهَا نِسَاءً","id":"Telah menceritakan kepada kami [Ali bin Al Hakam Al Anshari] Telah menceritakan kepada kami [Abu 'Awanah] dari [Raqabah] dari [Thalhah Al Yami] dari [Sa'id bin Jubair] ia berkata; [Ibnu Abbas] pernah bertanya kepadaku, \"Apakah kamu sudah menikah?\" aku menjawab, \"Tidak.\" Ia kemudian berkata, \"Menikahlah, karena orang yang terbaik dari ummat ini adalah seorang yang paling banyak wanitanya.\""},"4377":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَمَلُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَتْ هِجْرَتُهُ إِلَى دُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَنْكِحُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] Telah menceritakan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim bin Al Harits] dari ['Alqamah bin Waqash] dari [Umar bin Al Khaththab] radliallahu 'anhu ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setiap amal itu tergantung pada niatnya. Dan bagi seseorang adalah apa yang ia niatkan. Barangsiapa yang hijrahnya kepada Allah dan Rasul-Nya, maka hijrahnya itu kepada Allah dan Rasul-Nya, dan barangsiapa yang hijrahnya lantaran dunia yang hendak ia kejar atau wanita yang ingin dinikahinya, maka hijrahnya itu adalah sekedar kepada apa yang ia inginkan.\""},"4378":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي قَيْسٌ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نَغْزُو مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَنَا نِسَاءٌ فَقُلْنَا يَا رَسُولَ اللَّهِ أَلَا نَسْتَخْصِي فَنَهَانَا عَنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Qais] dari [Ibnu Mas'ud] radliallahu 'anhu, ia berkata; Kami pernah berperang bersama-sama dengan Nabi shallallahu 'alaihi wasallam, saat itu kami tidak mempunyai isteri, maka kami pun berkata, \"Wahai Rasulullah, apakah kami harus mengebiri?.\" Namun, beliau melarang kami untuk melakukannya."},"4379":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُفْيَانَ عَنْ حُمَيْدٍ الطَّوِيلِ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَقَدِمَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فَآخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُ وَبَيْنَ سَعْدِ بْنِ الرَّبِيعِ الْأَنْصَارِيِّ وَعِنْدَ الْأَنْصَارِيِّ امْرَأَتَانِ فَعَرَضَ عَلَيْهِ أَنْ يُنَاصِفَهُ أَهْلَهُ وَمَالَهُ فَقَالَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ دُلُّونِي عَلَى السُّوقِ فَأَتَى السُّوقَ فَرَبِحَ شَيْئًا مِنْ أَقِطٍ وَشَيْئًا مِنْ سَمْنٍ فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ أَيَّامٍ وَعَلَيْهِ وَضَرٌ مِنْ صُفْرَةٍ فَقَالَ مَهْيَمْ يَا عَبْدَ الرَّحْمَنِ فَقَالَ تَزَوَّجْتُ أَنْصَارِيَّةً قَالَ فَمَا سُقْتَ إِلَيْهَا قَالَ وَزْنَ نَوَاةٍ مِنْ ذَهَبٍ قَالَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Sufyan] dari [Humaid Ath Thawil] ia berkata; Aku mendengar [Anas bin Malik] berkata; Ketika Abdurrahman bin Auf datang, maka Nabi shallallahu 'alaihi wasallam mempersaudarakannya dengan Sa'd bin Rabi' Al Anshari. Seorang Anshari itu memiliki dua isteri, maka ia menawarkan satu isteri dan setengah dari hartanya kepada Abdurrahman bin Auf. Namun, Abdurrahman berkata, \"Semoga Allah memberkahimu dalam harta dan juga keluargamu. Cukup engkau tunjukkan padaku dimanakah pasar.\" Setelah itu, ia pun langsung ke pasar dan langsung memperoleh keuntungan berupa keju dan samin. Setelah beberapa hari, Nabi shallallahu 'alaihi wasallam melihatnya dan padanya terdapat berkas-berkas kuning, maka beliau pun bersabda: \"Selamat wahai Abdurrahman.\" Abdurrahman berkata, \"Aku telah menikahi seorang wanita Anshariyyah.\" Beliau bertanya: \"Lalu apa yang kamu berikan padanya?\" ia berkata, \"Yaitu emas yang beratnya kira-kira satu ons.\" beliau bersabda: \"Rayakanlah dengan walimah meskipun hanya dengan seekor kambing.\""},"4380":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنَا ابْنُ شِهَابٍ سَمِعَ سَعِيدَ بْنَ الْمُسَيَّبِ يَقُولُ سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُرَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عُثْمَانَ بْنِ مَظْعُونٍ التَّبَتُّلَ وَلَوْ أَذِنَ لَهُ لَاخْتَصَيْنَاحَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّهُ سَمِعَ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُ لَقَدْ رَدَّ ذَلِكَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عُثْمَانَ بْنِ مَظْعُونٍ وَلَوْ أَجَازَ لَهُ التَّبَتُّلَ لَاخْتَصَيْنَا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] Telah menceritakan kepada kami [Ibrahim bin Sa'd] Telah mengabarkan kepada kami [Ibnu Syihab] ia mendengar [Sa'id bin Al Musayyab] berkata; Aku mendengar [Sa'd bin Abu Waqqash] berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang Utsman bin Mazh'un untuk hidup membujang. Dan sekiranya beliau mengizinkannya, niscaya kami akan mengebiri. Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa ia mendengar [Sa'd bin Abu Waqqash] berkata; Sesungguhnya Nabi shallallahu 'alaihi wasallam telah melarang Abdullah bin Mazh'un untuk melakukan hal itu, sekiranya beliau melakukannya, niskami kami telah mengebiri."},"4381":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ قَالَ قَالَ عَبْدُ اللَّهِكُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ لَنَا شَيْءٌ فَقُلْنَا أَلَا نَسْتَخْصِي فَنَهَانَا عَنْ ذَلِكَ ثُمَّ رَخَّصَ لَنَا أَنْ نَنْكِحَ الْمَرْأَةَ بِالثَّوْبِ ثُمَّ قَرَأَ عَلَيْنَا{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تُحَرِّمُوا طَيِّبَاتِ مَا أَحَلَّ اللَّهُ لَكُمْ وَلَا تَعْتَدُوا إِنَّ اللَّهَ لَا يُحِبُّ الْمُعْتَدِينَ }وَقَالَ أَصْبَغُ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ شَابٌّ وَأَنَا أَخَافُ عَلَى نَفْسِي الْعَنَتَ وَلَا أَجِدُ مَا أَتَزَوَّجُ بِهِ النِّسَاءَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَسَكَتَ عَنِّي ثُمَّ قُلْتُ مِثْلَ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ جَفَّ الْقَلَمُ بِمَا أَنْتَ لَاقٍ فَاخْتَصِ عَلَى ذَلِكَ أَوْ ذَرْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Jarir] dari [Isma'il] dari [Qais] ia berkata; [Abdullah] berkata; Kami pernah berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam, dan saat itu kami tak punya apa-apa. Kemudian kami pun berkata, \"Apakah kami harus mengebiri?\" Dan ternyata beliau pun melarang kami untuk melakukannya, lalu beliau memberikan rukhshah kepada kami, yakni menikahi wanita meskipun dengan mahar kain. Kemudian membacakan ayat: \"Wahai orang-orang yang beriman, janganlah kamu mengharamkan sesuatu yang baik yang dihalalkan Allah untuk kalian, dan janganlah kalian melampau batas, sesungguhnya Allah tidak menyukai orang yang melampaui batas.\" (QS. Almaidah 87). [Ashbagh] berkata; Telah mengabarkan kepadaku [Ibnu Wahb] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Aku berkata, \"Wahai Rasulullah, aku adalah seorang pemuda, dan aku khawatir terhadap diriku bila terjerumus dalam kekejian, namun aku tidak memiliki sesuatu untuk menikahi wanita.\" Beliau terdiam. Aku pun berkata lagi seperti itu, beliau masih terdiam. Aku pun mengulanginya kembali, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Hurairah, qalam telah mengering (takdir telah ditetapkan) atas semua yang harus kamu hadapi, bolehlah kamu mengebiri, atau silahkan tinggalkan.\""},"4382":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ لَوْ نَزَلْتَ وَادِيًا وَفِيهِ شَجَرَةٌ قَدْ أُكِلَ مِنْهَا وَوَجَدْتَ شَجَرًا لَمْ يُؤْكَلْ مِنْهَا فِي أَيِّهَا كُنْتَ تُرْتِعُ بَعِيرَكَ قَالَ فِي الَّذِي لَمْ يُرْتَعْ مِنْهَا تَعْنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَتَزَوَّجْ بِكْرًا غَيْرَهَا","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] ia berkata; Telah menceritakan kepadaku [saudaraku] dari [Sulaiman] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] radliallahu 'anha, ia berkata; Aku pernah bertanya kepada, \"Wahai Rasulullah, bagaimanakah sekiranya Anda singgah di suatu lembah, dan di dalam lembah itu terdapat pohon yang buahnya telah dimakan, lalu Anda mendapatkan satu pohon yang buahnya belum di makan, maka pada pohon manakah Anda akan menambatkan Unta Anda?\" belia pun menjawab: \"Pada pohon yang belum dijamah.\" Maksudnya, adalah bahwa Rasulullah shallallahu 'alaihi wasallam belum pernah menikahi gadis selainnya."},"4383":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيتُكِ فِي الْمَنَامِ مَرَّتَيْنِ إِذَا رَجُلٌ يَحْمِلُكِ فِي سَرَقَةِ حَرِيرٍ فَيَقُولُ هَذِهِ امْرَأَتُكَ فَأَكْشِفُهَا فَإِذَا هِيَ أَنْتِ فَأَقُولُ إِنْ يَكُنْ هَذَا مِنْ عِنْدِ اللَّهِ يُمْضِهِ","id":"Telah menceritakan kepada kami [Ubaid bin Isma'il] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Engkau telah diperlihatkan padaku di dalam mimpi sebanyak dua kali. Seorang laki-laki membawamu dalam balutan kain sutera seraya berkata, 'Ini adalah isterimu.' Maka aku pun menyingkap kain itu, dan ternyata di dalamnya adalah kamu.' Maka aku pun berkata, 'Jika ini dari Allah, niscaya Dia akan menjadikannya kenyataan.'\""},"4384":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا سَيَّارٌ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَفَلْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَةٍ فَتَعَجَّلْتُ عَلَى بَعِيرٍ لِي قَطُوفٍ فَلَحِقَنِي رَاكِبٌ مِنْ خَلْفِي فَنَخَسَ بَعِيرِي بِعَنَزَةٍ كَانَتْ مَعَهُ فَانْطَلَقَ بَعِيرِي كَأَجْوَدِ مَا أَنْتَ رَاءٍ مِنْ الْإِبِلِ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا يُعْجِلُكَ قُلْتُ كُنْتُ حَدِيثَ عَهْدٍ بِعُرُسٍ قَالَ أَبِكْرًا أَمْ ثَيِّبًا قُلْتُ ثَيِّبًا قَالَ فَهَلَّا جَارِيَةً تُلَاعِبُهَا وَتُلَاعِبُكَ قَالَ فَلَمَّا ذَهَبْنَا لِنَدْخُلَ قَالَ أَمْهِلُوا حَتَّى تَدْخُلُوا لَيْلًا أَيْ عِشَاءً لِكَيْ تَمْتَشِطَ الشَّعِثَةُ وَتَسْتَحِدَّ الْمُغِيبَةُ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Husyaim] Telah menceritakan kepada kami [Sayyar] dari [Asy Sya'bi] dari [Jabir bin Abdullah] ia berkata; Kami pulang dari peperangan bersama Rasulullah shallallahu 'alaihi wasallam, maka aku segera memacu untaku yang berjalan pelan. Kemudian seorang pengendara menyusulku dari belakang dan mencucuk Unta milikku dengan tongkat sehingga laju Untaku pun menjadi lamban seperti lambannya Unta yang kantuk. Dan ternyata orang itu adalah Nabi shallallahu 'alaihi wasallam, beliau bertanya: \"Apa yang menyebabkanmu tergesa-gesa?\" aku menjawab, \"Karena aku baru saja memenikah.\" Beliau bertanya lagi: \"Gadis ataukah janda?\" aku menjawab, \"Janda.\" Beliau bersabda: \"Kenapa bukan gadis sehingga kamu dapat bercanda dengannya dan ia pun dapat bermain-main denganmu?\" Maka saat kami berangkat, beliau bersabda: \"Berjalanlah dengan santai, hinga kalian sampai tepat pada malam hari -yakni Isya`- dan agar keluarga yang masih kusut rambutnya dapat bersisir, dan juga bisa mempersiapkan diri.\""},"4385":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَارِبٌ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُتَزَوَّجْتُ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَزَوَّجْتَ فَقُلْتُ تَزَوَّجْتُ ثَيِّبًا فَقَالَ مَا لَكَ وَلِلْعَذَارَى وَلِعَابِهَافَذَكَرْتُ ذَلِكَ لِعَمْرِو بْنِ دِينَارٍ فَقَالَ عَمْرٌو سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلَّا جَارِيَةً تُلَاعِبُهَا وَتُلَاعِبُكَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Muharib] ia berkata; Aku mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; aku telah menikah, Rasulullah shallallahu 'alaihi wasallam bertanya padaku: \"Bagaimana wanita yang kamu nikahi? Kujawab; aku menikahi seorang janda.\" Beliau bersabda: \"Kenapa kamu tidak menikah dengan seorang gadis, sehinga kamu dapat bermain-main dengannya.?\" Lalu aku pun menuturkan hal itu pada Amru bin Dinar, lalu [Amru] berkata; Aku mendengar [Jabir bin Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda padaku: \"(Kenapa bukan) wanita yang masih gadis, sehingga kamu dapat bermain-main dengannya dan ia pun dapat bermain-main denganmu.\""},"4386":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ عَنْ عِرَاكٍ عَنْ عُرْوَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ عَائِشَةَ إِلَى أَبِي بَكْرٍ فَقَالَ لَهُ أَبُو بَكْرٍ إِنَّمَا أَنَا أَخُوكَ فَقَالَ أَنْتَ أَخِي فِي دِينِ اللَّهِ وَكِتَابِهِ وَهِيَ لِي حَلَالٌ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] dari [Yazid] dari [Irak] dari [Urwah] bahwa Nabi shallallahu 'alaihi wasallam mengkhithbah (meminang) Aisyah kepada Abu Bakar. Maka Abu Bakar pun berkata pada beliau, \"Sesungguhnya saya adalah saudara Anda.\" Beliau bersabda: \"Yang kumaksudkan kamu adalah saudaraku di dalam Dinullah dan Kitab-Nya, maka Aisyah adalah halal bagiku.\""},"4387":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ نِسَاءٍ رَكِبْنَ الْإِبِلَ صَالِحُ نِسَاءِ قُرَيْشٍ أَحْنَاهُ عَلَى وَلَدٍ فِي صِغَرِهِ وَأَرْعَاهُ عَلَى زَوْجٍ فِي ذَاتِ يَدِهِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik wanita adalah yang dapat mengendarai unta. Sebaik-baik wanita Quraisy adalah adalah yang paling lembut dan simpati pada anak di masa kecilnya, dan paling bisa menjaga harta suaminya.\""},"4388":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا صَالِحُ بْنُ صَالِحٍ الْهَمْدَانِيُّ حَدَّثَنَا الشَّعْبِيُّ قَالَ حَدَّثَنِي أَبُو بُرْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ كَانَتْ عِنْدَهُ وَلِيدَةٌ فَعَلَّمَهَا فَأَحْسَنَ تَعْلِيمَهَا وَأَدَّبَهَا فَأَحْسَنَ تَأْدِيبَهَا ثُمَّ أَعْتَقَهَا وَتَزَوَّجَهَا فَلَهُ أَجْرَانِ وَأَيُّمَا رَجُلٍ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ وَآمَنَ بِي فَلَهُ أَجْرَانِ وَأَيُّمَا مَمْلُوكٍ أَدَّى حَقَّ مَوَالِيهِ وَحَقَّ رَبِّهِ فَلَهُ أَجْرَانِ قَالَ الشَّعْبِيُّ خُذْهَا بِغَيْرِ شَيْءٍ قَدْ كَانَ الرَّجُلُ يَرْحَلُ فِيمَا دُونَهَا إِلَى الْمَدِينَةِوَقَالَ أَبُو بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَهَا ثُمَّ أَصْدَقَهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Abdul Wahid] Telah menceritakan kepada kami [Shalih bin Shalih Al Hamdani] Telah menceritakan kepada kami [Asy Sya'bi] ia berkata; Telah menceritakan kepadaku [Abu Burdah] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki memiliki seorang budak wanita, lalu ia mengajarinya dengan sebaik-baiknya, dan mendidiknya dengan didikan yang terbaik, kemudian ia merdekakan dan menikahinya, maka baginya adalah dua pahala. Dan siapa pun dari kalangan ahli kitab yang beriman kepada nabinya dan beriman kepadaku, maka baginya adalah dua pahala. Dan siapa saja dari kalangan budak yang menunaikan hak tuannya dan juga hak Rabb-nya, maka baginya adalah dua pahala.\" [Abu Bakr] berkata; dari [Abu Al Hashin] dari [Abu Burdah] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam: \"Ia membebaskan lalu memberinya mahar.\""},"4389":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ تَلِيدٍ قَالَ أَخْبَرَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي جَرِيرُ بْنُ حَازِمٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا سُلَيْمَانُ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكْذِبْ إِبْرَاهِيمُ إِلَّا ثَلَاثَ كَذَبَاتٍ بَيْنَمَا إِبْرَاهِيمُ مَرَّ بِجَبَّارٍ وَمَعَهُ سَارَةُ فَذَكَرَ الْحَدِيثَ فَأَعْطَاهَا هَاجَرَ قَالَتْ كَفَّ اللَّهُ يَدَ الْكَافِرِ وَأَخْدَمَنِي آجَرَقَالَ أَبُو هُرَيْرَةَفَتِلْكَ أُمُّكُمْ يَا بَنِي مَاءِ السَّمَاءِ","id":"Telah menceritakan kepada kami [Sa'id bin Talid] Telah mengabarkan kepadaku [Ibnu Wahb] ia berkata; Telah mengabarkan kepadaku [Jarir bin Hazim] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda. -dalam riwayat lain- Telah menceritakan kepada kami [Sulaiman] dari [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Ibrahim tidak pernah berdusta kecuali tiga kedustaan. Yaitu; Ketika Ibrahim melewati Penguasa diktator bersama Sarah. -Lalu beliau pun menuturkan kisahnya- lantas raja dictator itu malahan memberi Sarah seorang hamba sahaya namanya Hajar. Sarah berkata, 'Allah telah menahan tangan orang kafir (untuk menyentuhku) dan malahan memberiku seorang pelayan yang namanya Ajar (maksudnya sama, Hajar).'\" Abu Hurairah berkata; Itulah nenek moyang kalian wahai Bani Ma`as Sama`."},"4390":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ خَيْبَرَ وَالْمَدِينَةِ ثَلَاثًا يُبْنَى عَلَيْهِ بِصَفِيَّةَ بِنْتِ حُيَيٍّ فَدَعَوْتُ الْمُسْلِمِينَ إِلَى وَلِيمَتِهِ فَمَا كَانَ فِيهَا مِنْ خُبْزٍ وَلَا لَحْمٍ أُمِرَ بِالْأَنْطَاعِ فَأَلْقَى فِيهَا مِنْ التَّمْرِ وَالْأَقِطِ وَالسَّمْنِ فَكَانَتْ وَلِيمَتَهُ فَقَالَ الْمُسْلِمُونَ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ أَوْ مِمَّا مَلَكَتْ يَمِينُهُ فَقَالُوا إِنْ حَجَبَهَا فَهِيَ مِنْ أُمَّهَاتِ الْمُؤْمِنِينَ وَإِنْ لَمْ يَحْجُبْهَا فَهِيَ مِمَّا مَلَكَتْ يَمِينُهُ فَلَمَّا ارْتَحَلَ وَطَّى لَهَا خَلْفَهُ وَمَدَّ الْحِجَابَ بَيْنَهَا وَبَيْنَ النَّاسِ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam bermukim tiga hari di daerah antara Khaibar dan Madinah, beliau menikahi Shafiyyah binti Huyay. Maka aku pun mengundang kaum muslimin untuk menghadiri walimahnya. Dan di dalam walimahan itu tidak ada roti dan tidak pula daging. Beliau menyuruh agar dibuatkan hamparan kulit lalu di dalamnya diberi kurma, keju dan samin. Seperti itulah acara walimah beliau. Maka kaum muslimin pun berkata, \"Ia adalah salah seorang dari Ummahatil Muslimin ataukah sekedar hamba sahayanya.\" Mereka katakan, \"Jika beliau menghijabinya, maka ia adalah termasuk Ummahat Muslimin, namun jika tidak, maka ia adalah hamba sahayanya.\" Maka ketika berangkat, beliau meletakkannya agak rendah di belakang, lalu beliau membentangkan hijab yang menutupi antara ia dan orang banyak."},"4391":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ وَشُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَ صَفِيَّةَ وَجَعَلَ عِتْقَهَا صَدَاقَهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Hammad] dari [Tsabit] dan [Syu'aib bin Al Habhab] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam membebaskan Shafiyyah dan menjadikan pembebasnya itu sebagai maharnya."},"4392":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ جِئْتُ أَهَبُ لَكَ نَفْسِي قَالَ فَنَظَرَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَعَّدَ النَّظَرَ فِيهَا وَصَوَّبَهُ ثُمَّ طَأْطَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ فَلَمَّا رَأَتْ الْمَرْأَةُ أَنَّهُ لَمْ يَقْضِ فِيهَا شَيْئًا جَلَسَتْ فَقَامَ رَجُلٌ مِنْ أَصْحَابِهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنْ لَمْ يَكُنْ لَكَ بِهَا حَاجَةٌ فَزَوِّجْنِيهَا فَقَالَ وَهَلْ عِنْدَكَ مِنْ شَيْءٍ قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ فَقَالَ اذْهَبْ إِلَى أَهْلِكَ فَانْظُرْ هَلْ تَجِدُ شَيْئًا فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ مَا وَجَدْتُ شَيْئًا فَقَالَ رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ وَلَا خَاتَمًا مِنْ حَدِيدٍ وَلَكِنْ هَذَا إِزَارِي قَالَ سَهْلٌ مَا لَهُ رِدَاءٌ فَلَهَا نِصْفُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصْنَعُ بِإِزَارِكَ إِنْ لَبِسْتَهُ لَمْ يَكُنْ عَلَيْهَا مِنْهُ شَيْءٌ وَإِنْ لَبِسَتْهُ لَمْ يَكُنْ عَلَيْكَ مِنْهُ شَيْءٌ فَجَلَسَ الرَّجُلُ حَتَّى إِذَا طَالَ مَجْلِسُهُ قَامَ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَلِّيًا فَأَمَرَ بِهِ فَدُعِيَ فَلَمَّا جَاءَ قَالَ مَاذَا مَعَكَ مِنْ الْقُرْآنِ قَالَ مَعِي سُورَةُ كَذَا وَسُورَةُ كَذَا عَدَّدَهَا فَقَالَ تَقْرَؤُهُنَّ عَنْ ظَهْرِ قَلْبِكَ قَالَ نَعَمْ قَالَ اذْهَبْ فَقَدْ مَلَّكْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [bapaknya] dari [Sahl bin Sa'd As Sa'idi] ia berkata; Seorang wanita datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku datang untuk menghibahkan diriku untuk Anda.\" Lalu Rasulullah shallallahu 'alaihi wasallam memandangi wanita itu, beliau arahkan pandangannya ke atas dan kebawah lalu beliau menundukkkan kepalanya. Maka wanita itu melihat bahwa Rasulullah shallallahu 'alaihi wasallam tidak memberi putusan apa-apa terkait dengan dirinya, maka ia pun duduk. Tiba-tiba seorang sahabat berdiri dan berkata, \"Wahai Rasulullah, jika Anda tidak berhasrat kepada wanita itu maka nikahkanlah aku dengannya.\" Maka beliau pun bertanya: \"Apakah kamu mempunyai sesuatu (untuk dijadikan mahar)?\" sahabat itu menjawab, \"Tidak, demi Allah wahai Rasulullah.\" Beliau bersabda: \"Pergilah kepada keluargamu, dan lihatlah apakah ada sesuatu.\" Laki-laki itu pun pergi dan kembali seraya berkata, \"Tidak, demi Allah wahai Rasulullah, aku tidak mendapatkan sesuatu.\" Beliau bersabda lagi: \"Lihatlah, meskipun yang ada hanyalah cincin dari besi.\" Laki-laki itu pergi laki kemudian kembali dan berkata, \"Tidak, demi Allah wahai Rasulullah meskipun hanya cincin besi. Akan tetapi aku mempunya kain ini.\" Sahl berkata; Ia tidak memiliki kain kecuali setengah. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Apa yang dapat kamu lakukan dengan kainmu itu. Jika kamu memakainya maka ia tidak akan kebagian, dan jika ia memakainya maka tidak akan kebagian.\" Akhirnya laki-laki itu duduk hingga lama, lalu ia beranjak. Kemudian Rasulullah shallallahu 'alaihi wasallam pun melihatnya hendak pulang. Maka beliau memerintahkan seseorang agar memanggilnya. Ketika laki-laki itu datang, beliau bertanya: \"Surat apa yang kamu hafal dari Al Qur`an.\" Ia berkata, \"Yaitu surat ini.\" Ia menghitungnya. Beliau bersabda: \"Apakah kamu menghafalnya dengan baik?\" laki-laki itu menjawab, \"Ya.\" Akhirnya beliau bersabda: \"Sesungguhnya aku telah menikahkanmu dengan wanita itu dengan mahar hafalan Al Qur`anmu.\""},"4393":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ أَبَا حُذَيْفَةَ بْنَ عُتْبَةَ بْنِ رَبِيعَةَ بْنِ عَبْدِ شَمْسٍ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبَنَّى سَالِمًا وَأَنْكَحَهُ بِنْتَ أَخِيهِ هِنْدَ بِنْتَ الْوَلِيدِ بْنِ عُتْبَةَ بْنِ رَبِيعَةَ وَهُوَ مَوْلًى لِامْرَأَةٍ مِنْ الْأَنْصَارِ كَمَا تَبَنَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا وَكَانَ مَنْ تَبَنَّى رَجُلًا فِي الْجَاهِلِيَّةِ دَعَاهُ النَّاسُ إِلَيْهِ وَوَرِثَ مِنْ مِيرَاثِهِ حَتَّى أَنْزَلَ اللَّهُ{ ادْعُوهُمْ لِآبَائِهِمْ إِلَى قَوْلِهِ وَمَوَالِيكُمْ }فَرُدُّوا إِلَى آبَائِهِمْ فَمَنْ لَمْ يُعْلَمْ لَهُ أَبٌ كَانَ مَوْلًى وَأَخًا فِي الدِّينِ فَجَاءَتْ سَهْلَةُ بِنْتُ سُهَيْلِ بْنِ عَمْرٍو الْقُرَشِيِّ ثُمَّ العَامِرِيِّ وَهِيَ امْرَأَةُ أَبِي حُذَيْفَةَ بْنِ عُتْبَةَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَرَى سَالِمًا وَلَدًا وَقَدْ أَنْزَلَ اللَّهُ فِيهِ مَا قَدْ عَلِمْتَفَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Urwah bin Zubair] dari [Aisyah] radliallahu 'anha, bahwasanya; Abu Hudzaifah bin Utbah bin Abdu Syamsy -ia adalah seorang ahli Badar bersama Nabi shallallahu 'alaihi wasallam- menjadikan Salim sebagai anak angkat dan menikahkannya dengan anak perempuan saudarinya Hindu binti Al Walid bin Utbah bin Rabi'ah. Dan ia adalah bekas budak dari seorang wanita Anshar. Yakni, sebagaimana Nabi shallallahu 'alaihi wasallam pernah menjadikan Zaid sebagai anak angkat. Beliau termasuk orang yang mengambil anak angkat pada masa Jahiliyyah hingga orang-orang pun menduga bahwa Zaid nantinya akan mewarisi hartanya, hingga pada akhirnya Allah menurunkan ayat: \"UD'UUHUM ILAA `AABAA`IHIM..\" hingga firman-Nya, \"WA MAWAALIIKUM.\" Akhinya mereka pun mengembalikan (nasabnya) kepada bapak-bapak mereka. Dan siapa yang tidak diketahui bapaknya, maka ia adalah maula (budak yang dimerdekakan) dan saudara seagama. Kemudian datanglah Sahlah binti Suhail bin Amru Al Qurasyii lalu Al 'Amiri -ia adalah isteri Abu Hudzaifah bin Utbah- kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya kami menganggap Salim sebagai anak, sementara Allah telah menurunkan sebagaimana apa yang telah Anda kethaui.\" Kemudian ia pun menyebutkan hadits."},"4394":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ضُبَاعَةَ بِنْتِ الزُّبَيْرِ فَقَالَ لَهَا لَعَلَّكِ أَرَدْتِ الْحَجَّ قَالَتْ وَاللَّهِ لَا أَجِدُنِي إِلَّا وَجِعَةً فَقَالَ لَهَا حُجِّي وَاشْتَرِطِي وَقُولِي اللَّهُمَّ مَحِلِّي حَيْثُ حَبَسْتَنِي وَكَانَتْ تَحْتَ الْمِقْدَادِ بْنِ الْأَسْوَدِ","id":"Telah menceritakan kepada kami [Ubaid bin Ismail] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam menemui Dlubabah binti Az Zubair, maka beliau bersabda: \"Sepertinya kamu ingin menunaikan ibadah haji.\" Ia pun berkata, \"Demi Allah, tidak ada yang menghalangiku kecuali sakit.\" Beliau pun bersabda: \"Tunaikanlah haji, dan berilah syarat. Bacalah: 'ALLAHUMMA MAHILLII HAITSU HABASTANII (Ya Allah, tempat miqatku adalah di tempat Engkau merintangiku).'\" Saat itu, ia adalah isteri daripada Miqdad bin Al Aswad."},"4395":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُنْكَحُ الْمَرْأَةُ لِأَرْبَعٍ لِمَالِهَا وَلِحَسَبِهَا وَجَمَالِهَا وَلِدِينِهَا فَاظْفَرْ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Ubaidullah] ia berkata; Telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [bapaknya] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wanita itu dinikahi karena empat hal, karena hartanya, karena keturunannya, karena kecantikannya dan karena agamanya. Maka pilihlah karena agamanya, niscaya kamu akan beruntung.\""},"4396":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍ قَالَمَرَّ رَجُلٌ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا تَقُولُونَ فِي هَذَا قَالُوا حَرِيٌّ إِنْ خَطَبَ أَنْ يُنْكَحَ وَإِنْ شَفَعَ أَنْ يُشَفَّعَ وَإِنْ قَالَ أَنْ يُسْتَمَعَ قَالَ ثُمَّ سَكَتَ فَمَرَّ رَجُلٌ مِنْ فُقَرَاءِ الْمُسْلِمِينَ فَقَالَ مَا تَقُولُونَ فِي هَذَا قَالُوا حَرِيٌّ إِنْ خَطَبَ أَنْ لَا يُنْكَحَ وَإِنْ شَفَعَ أَنْ لَا يُشَفَّعَ وَإِنْ قَالَ أَنْ لَا يُسْتَمَعَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا خَيْرٌ مِنْ مِلْءِ الْأَرْضِ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] Telah menceritakan kepada kami [Ibnu Abu Hazim] dari [bapaknya] dari [Sahl] ia berkata; Seorang laki-laki lewat di hadapan Rasulullah shallallahu 'alaihi wasallam, maka beliau pun bertanya kepada sahabatnya: \"Bagaimana pendapat kalian mengenai orang ini?\" mereka menjawab, \"Ia begitu berwibawa. Bila ia meminang pasti diterima, dan bila memberi perlindungan pasti akan dipenuhi, dan bila ia berbicara, niscaya akan didengarkan.\" Beliau kemudian terdiam, lalu lewatlah seorang laki-laki dari fuqara` kaum muslimin, dan beliau pun bertanya lagi: \"Lalu bagaimanakah pendapat kalian terhadap orang ini?\" mereka menjawab, \"Ia pantas bila meminang untuk ditolak, jika memberi perlindungan tak akan digubris, dan bila berbicara niscaya ia tidak didengarkan.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang ini lebih baik daripada seluruh kekayaan dunia yang seperti ini.\""},"4397":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى }قَالَتْ يَا ابْنَ أُخْتِي هَذِهِ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي جَمَالِهَا وَمَالِهَا وَيُرِيدُ أَنْ يَنْتَقِصَ صَدَاقَهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا فِي إِكْمَالِ الصَّدَاقِ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ قَالَتْ وَاسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ إِلَى وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }فَأَنْزَلَ اللَّهُ لَهُمْ أَنَّ الْيَتِيمَةَ إِذَا كَانَتْ ذَاتَ جَمَالٍ وَمَالٍ رَغِبُوا فِي نِكَاحِهَا وَنَسَبِهَا وَسُنَّتِهَا فِي إِكْمَالِ الصَّدَاقِ وَإِذَا كَانَتْ مَرْغُوبَةً عَنْهَا فِي قِلَّةِ الْمَالِ وَالْجَمَالِ تَرَكُوهَا وَأَخَذُوا غَيْرَهَا مِنْ النِّسَاءِ قَالَتْ فَكَمَا يَتْرُكُونَهَا حِينَ يَرْغَبُونَ عَنْهَا فَلَيْسَ لَهُمْ أَنْ يَنْكِحُوهَا إِذَا رَغِبُوا فِيهَا إِلَّا أَنْ يُقْسِطُوا لَهَا وَيُعْطُوهَا حَقَّهَا الْأَوْفَى فِي الصَّدَاقِ","id":"Telah menceritakan kepadaku [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Urwah] bahwa ia pernah bertanya kepada Aisyah radliallahu 'anha mengenai firman-Nya, \"WA IN KHIFTUM ANLAA TUQSITHUU FIL YATAAMAA..\" [Aisyah] menjelaskan, \"Wahai anak saudaraku, maksudnya adalah anak perempuan yatim yang tinggal di rumah walinya, lalu sang wali pun berhasrat pada kecantikan dan juga hartanya. Namun sang wali itu hendak mengurangi maharnya. Karena itu, mereka pun dilarang untuk menikahi anak-anak perempuan yatim itu kecuali dengan menyempurnakan maharnya. Akhirnya mereka pun diperintahkan untuk menikahi wanita-wanita selain mereka.\" Aisyah juga menjelaskan, \"Setelah itu, orang-orang pun pada meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam. Maka Allah menurunkan ayat, 'WA YASTAFTUUNAKA FIN NISAA`..' hingga firman-Nya, 'WA TARGHABUUNA AN TANKIHUUHUNNA.' Maka Allah pun menurunkan ayat kepada mereka, bahwa jika ada anak perempuan yatim yang memiliki kecantikan wajah dan harta, apabila mereka ingin menikahinya, mereka diminta untuk menyempurnakan mahar. Apabila anak puteri yatim itu tidak mereka senangi lantaran tak memiliki harta dan kecantikan maka mereka pun meninggalkannya dan mencari wanita lain. Karena itu, sebagaimana mereka meninggalkannya ketika mereka tak menyukainya, maka mereka pun tidak diizinkan untuk menikahinya saat mereka berkeinginan kecuali dengan berbuat adil pada mereka dan memberikan haknya yang harus dipenuhi yakni Mahar.\""},"4398":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ وَسَالِمٍ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّؤْمُ فِي الْمَرْأَةِ وَالدَّارِ وَالْفَرَسِ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Hamzah] dan [Salim] keduanya adalah anak Abdullah bin Umar, dari [Abdullah bin Umar] radliallahu 'anhuma, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \" Adakalanya kesialan itu ada pada wanita, rumah dan juga kuda.\""},"4399":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِنْهَالٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا عُمَرُ بْنُ مُحَمَّدٍ الْعَسْقَلَانِيُّ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَذَكَرُوا الشُّؤْمَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ الشُّؤْمُ فِي شَيْءٍ فَفِي الدَّارِ وَالْمَرْأَةِ وَالْفَرَسِ","id":"Telah menceritakan kepada kami [Muhammad bin Minhal] Telah menceritakan kepada kami [Yazid bin Zurai'] Telah menceritakan kepada kami [Umar bin Muhammad Al Asyqalani] dari [bapaknya] dari [Ibnu Umar] ia berkata; Mereka membicarakan kesialan di sisi Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Sekiranya kesialan itu ada pada sesuatu, maka niscaya akan terdapat pada rumah, wanita dan kuda.\""},"4400":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كَانَ فِي شَيْءٍ فَفِي الْفَرَسِ وَالْمَرْأَةِ وَالْمَسْكَنِ","id":"Telah menceritakan kepada kami [Abudllah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abu Hazim] dari [Sahl bin Sa'dari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya kesialan itu ada pada sesuatu, maka niscaya akan terdapat kuda, wanita dan rumah.\""},"4401":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ التَّيْمِيِّ قَالَ سَمِعْتُ أَبَا عُثْمَانَ النَّهْدِيَّ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا تَرَكْتُ بَعْدِي فِتْنَةً أَضَرَّ عَلَى الرِّجَالِ مِنْ النِّسَاءِ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dari [Sualaiman At Taimi] ia berkata; Aku mendengar [Abu Utsman An Nahdi] dari [Usamah bin Zaid] radliallahu 'anhuma berkata; dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah aku meninggalkan suatu fitnah setelahku yang lebih dahsyat bagi kaum laki-laki melebihi fitnah wanita.\""},"4402":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ فِي بَرِيرَةَ ثَلَاثُ سُنَنٍ عَتَقَتْ فَخُيِّرَتْ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ أَعْتَقَ وَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبُرْمَةٌ عَلَى النَّارِ فَقُرِّبَ إِلَيْهِ خُبْزٌ وَأُدْمٌ مِنْ أُدْمِ الْبَيْتِ فَقَالَ أَلَمْ أَرَ الْبُرْمَةَ فَقِيلَ لَحْمٌ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ وَأَنْتَ لَا تَأْكُلُ الصَّدَقَةَ قَالَ هُوَ عَلَيْهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Rabi'ah bin Abu Abdurrahman] dari [Al Qasim bin Muhammad] dari [Aisyah] radliallahu 'anha, ia berkata; Pada Barirah terdapat tiga sunnah. Ia dimerdekakan, lalu diberi pilihan. Dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hak waris kepemilikan budak (wala') itu adalah bagi yang memerdekakan.\" Kemudian suatu ketika, Rasulullah shallallahu 'alaihi wasallam masuk sementara periuk berada di atas api, lalu beliau pun disuguhkan roti beserta lauk. Maka beliau bersabda: \"Bukankah tadi aku melihat periuk?\" dikatakanlah pada beliau, \"Periuk itu berisikan daging yang disedekahkan kepada Barirah, sementara Anda tidak makan sedekah.\" Beliau bersabda: \"Baginya sedekah, tetapi bagi kita adalah hadiah.\""},"4403":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى }قَالَتْ الْيَتِيمَةُ تَكُونُ عِنْدَ الرَّجُلِ وَهُوَ وَلِيُّهَا فَيَتَزَوَّجُهَا عَلَى مَالِهَا وَيُسِيءُ صُحْبَتَهَا وَلَا يَعْدِلُ فِي مَالِهَا فَلْيَتَزَوَّجْ مَا طَابَ لَهُ مِنْ النِّسَاءِ سِوَاهَا مَثْنَى وَثُلَاثَ وَرُبَاعَ","id":"Telah menceritakan kepada kami [Muhammad] Telah mengabarkan kepada kami [Abdah] dari [Hisyam] dari [bapaknya] dari [Aisyah] Terkait dengan firman Allah, \"WA IN KHIFTUM ANLAA TUQSIMUU FIL YATAAMA..\" Ia berkata; \"Maksudnya adalah seorang anak perempuan yatim yang terdapat pada seorang laki-laki, yakni walinya. Kemudian sang wali pun menikahinya lantaran ingin mendapatkan hartanya, namun bergaul dengannya dengan tidak baik, dan tidak pula bersikap adil pada hartanya, maka dari itu hendaklah ia menikahi wanita lain dua, tiga atau empat.\""},"4404":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَهَا وَأَنَّهَا سَمِعَتْ صَوْتَ رَجُلٍ يَسْتَأْذِنُ فِي بَيْتِ حَفْصَةَ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا رَجُلٌ يَسْتَأْذِنُ فِي بَيْتِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرَاهُ فُلَانًا لِعَمِّ حَفْصَةَ مِنْ الرَّضَاعَةِ قَالَتْ عَائِشَةُ لَوْ كَانَ فُلَانٌ حَيًّا لِعَمِّهَا مِنْ الرَّضَاعَةِ دَخَلَ عَلَيَّ فَقَالَ نَعَمْ الرَّضَاعَةُ تُحَرِّمُ مَا تُحَرِّمُ الْوِلَادَةُ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Abdullah bin Abu Bakr] dari ['Amrah binti Abdurrahman] bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa; Suatu ketika, Rasulullah shallallahu 'alaihi wasallam berada di sisinya, dan ia mendengar suara seorang laki-laki yang meminta izin tepat di rumah Hafshah. Maka Aisyah berkata; Aku berkata, \"Wahai Rasulullah, laki-laki ini meminta izin di rumah Anda.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Aku menduga bahwa ia adalah si Fulan, paman Hafshah karena susuan.\" Aisyah bertanya, \"Sekiranya si Fulan itu hidup dari pamannya sesusuan, apakah ia boleh masuk kepadaku?\" beliau menjawab: \"Ya.\" Beliau bersabda: \"Sesungguhnya sepersusuan itu mengharamkan apa yang diharamkan oleh hubungan keturunan.\""},"4405":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تَتَزَوَّجُ ابْنَةَ حَمْزَةَ قَالَ إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِوَقَالَ بِشْرُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ سَمِعْتُ قَتَادَةَ سَمِعْتُ جَابِرَ بْنَ زَيْدٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Qatadah] dari [Jabir bin Zaid] dari [Ibnu Abbas] ia berkata; Pernah ditanyakan kepada Nabi shallallahu 'alaihi wasallam, \"Apakah Anda akan menikahi anak perempuan Hamzah?\" beliau bersabda: \"Sesungguhnya perempuan itu adalah anak saudara sesusuan saya.\" [Bisyr bin Umar] berkata; Telah menceritakan kepada kami [Syu'bah] Aku mendengar [Qatadah] Aku mendengar [Jabir bin Zaid] semisalnya."},"4406":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّ حَبِيبَةَ بِنْتَ أَبِي سُفْيَانَ أَخْبَرَتْهَا أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ انْكِحْ أُخْتِي بِنْتَ أَبِي سُفْيَانَ فَقَالَ أَوَتُحِبِّينَ ذَلِكِ فَقُلْتُ نَعَمْ لَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَبُّ مَنْ شَارَكَنِي فِي خَيْرٍ أُخْتِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ ذَلِكِ لَا يَحِلُّ لِي قُلْتُ فَإِنَّا نُحَدَّثُ أَنَّكَ تُرِيدُ أَنْ تَنْكِحَ بِنْتَ أَبِي سَلَمَةَ قَالَ بِنْتَ أُمِّ سَلَمَةَ قُلْتُ نَعَمْ فَقَالَ لَوْ أَنَّهَا لَمْ تَكُنْ رَبِيبَتِي فِي حَجْ��ِي مَا حَلَّتْ لِي إِنَّهَا لَابْنَةُ أَخِي مِنْ الرَّضَاعَةِ أَرْضَعَتْنِي وَأَبَا سَلَمَةَ ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّ قَالَ عُرْوَةُ وثُوَيْبَةُ مَوْلَاةٌ لِأَبِي لَهَبٍ كَانَ أَبُو لَهَبٍ أَعْتَقَهَا فَأَرْضَعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا مَاتَ أَبُو لَهَبٍ أُرِيَهُ بَعْضُ أَهْلِهِ بِشَرِّ حِيبَةٍ قَالَ لَهُ مَاذَا لَقِيتَ قَالَ أَبُو لَهَبٍ لَمْ أَلْقَ بَعْدَكُمْ غَيْرَ أَنِّي سُقِيتُ فِي هَذِهِ بِعَتَاقَتِي ثُوَيْبَةَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Urwah bin Az Zubair] bahwa [Zainab binta Abu Salamah] Telah mengabarkan kepadanya bahwa [Ummu Habibah binti Abu Sufyan] Telah mengabarkan kepadanya bahwa ia pernah berkata, \"Wahai Rasulullah nikahilah saudaraku binti Abu Sufyan.\" Maka beliau balik bertanya: \"Apakah suka akan hal itu?\" aku menjawab, \"Ya. Namun aku tidak mau ditinggal oleh Anda. Hanya saja aku suka bila saudariku ikut serta denganku dalam kebaikan.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya hal itu tidaklah halal bagiku.\" Aku berkata, \"Telah beredar berita, bahwa Anda ingin menikahi binti Abu Salamah.\" Beliau bertanya: \"Anak wanita Ummu Salamah?\" aku menjawab, \"Ya.\" Maka beliau pun bersabda: \"Meskipun ia bukan anak tiriku, ia tidaklah halal bagiku. Sesungguhnya ia adalah anak saudaraku sesusuan. Tsuwaibah telah menyusuiku dan juga Abu Salamah. Karena itu, janganlah kalian menawarkan anak-anak dan saudari-saudari kalian padaku.\" Urwah berkata; Tsuwaibah adalah bekas budak Abu Lahab. Waktu itu, Abu Lahab membebaskannya, lalu Tsuwaibah pun menyusui Nabi shallallahu 'alaihi wasallam. Dan ketika Abu Lahab meninggal, ia pun diperlihatkan kepada sebagian keluarganya di alam mimpi dengan keadaan yang memprihatinkan. Sang kerabat berkata padanya, \"Apa yang telah kamu dapatkan?\" Abu Lahab berkata.\"Setelah kalian, aku belum pernah mendapati sesuatu nikmat pun, kecuali aku diberi minum lantaran memerdekakan Tsuwaibah.\""},"4407":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا رَجُلٌ فَكَأَنَّهُ تَغَيَّرَ وَجْهُهُ كَأَنَّهُ كَرِهَ ذَلِكَ فَقَالَتْ إِنَّهُ أَخِي فَقَالَ انْظُرْنَ مَنْ إِخْوَانُكُنَّ فَإِنَّمَا الرَّضَاعَةُ مِنْ الْمَجَاعَةِ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats] dari [bapaknya] dari [Masruq] dari [Aisyah] radliallahu 'anha, bahwa Nabi shallallahu 'alaihi wasallam suatu ketika menemuinya, sementara di tempatnya terdapat seorang laki-laki dan sepertinya rona wajah beliau berubah dan membencinya, maka Aisyah pun berkata, \"Sesungguhnya ia adalah saudaraku.\" Maka beliau bersabda: \"Lihatlah siapakah saudara-saudara sesusuan kalian, karena susuan itu karena lapar.\""},"4408":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ أَفْلَحَ أَخَا أَبِي الْقُعَيْسِ جَاءَ يَسْتَأْذِنُ عَلَيْهَا وَهُوَ عَمُّهَا مِنْ الرَّضَاعَةِ بَعْدَ أَنْ نَزَلَ الْحِجَابُ فَأَبَيْتُ أَنْ آذَنَ لَهُ فَلَمَّا جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرْتُهُ بِالَّذِي صَنَعْتُ فَأَمَرَنِي أَنْ آذَنَ لَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Urwah bin Az Zubair] dari [Aisyah] bahwa setelah turunnya perintah hijab, Aflah saudara Abu Al Qu'aisi datang dan meminta izin padanya, dan ia adalah paman sesusuannya. Aisyah berkata; Maka aku pun menolak untuk memberi izin padanya, dan ketika Rasulullah shallallahu 'alaihi wasallam datang, aku mengabarkan apa yang kulakukan, maka beliau memerintahkanku untuk mengizinkannya."},"4409":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُبَيْدُ بْنُ أَبِي مَرْيَمَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قالَ وَقَدْ سَمِعْتُهُ مِنْ عُقْبَةَ لَكِنِّي لِحَدِيثِ عُبَيْدٍ أَحْفَظُ قَالَتَزَوَّجْتُ امْرَأَةً فَجَاءَتْنَا امْرَأَةٌ سَوْدَاءُ فَقَالَتْ أَرْضَعْتُكُمَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ تَزَوَّجْتُ فُلَانَةَ بِنْتَ فُلَانٍ فَجَاءَتْنَا امْرَأَةٌ سَوْدَاءُ فَقَالَتْ لِي إِنِّي قَدْ أَرْضَعْتُكُمَا وَهِيَ كَاذِبَةٌ فَأَعْرَضَ عَنِّي فَأَتَيْتُهُ مِنْ قِبَلِ وَجْهِهِ قُلْتُ إِنَّهَا كَاذِبَةٌ قَالَ كَيْفَ بِهَا وَقَدْ زَعَمَتْ أَنَّهَا قَدْ أَرْضَعَتْكُمَا دَعْهَا عَنْكَ وَأَشَارَ إِسْمَاعِيلُ بِإِصْبَعَيْهِ السَّبَّابَةِ وَالْوُسْطَى يَحْكِي أَيُّوبَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Isma'il bin Ibrahim] Telah mengabarkan kepada kami [Ayyub] dari [Abdullah bin Abu Mulaikah] ia berkata; Telah menceritakan kepadaku [Ubaidah bin Maryam] dari [Uqbah bin Al Harits] -Abu Mulaikah berkata; Dan aku telah mendengarnya dari Uqbah, tetapi hadits Ubaid lebih aku hafal- ia berkata; Aku menikahi seorang wanita, lalu seorang wanita berkulit hitam mendatangi kami seraya berkata, \"Sesungguhnya aku pernah menyusui kalian berdua.\" Lalu aku pun segera mendatangi Nabi shallallahu 'alaihi wasallam. Aku berkata, \"Aku telah menikahi si Fulanah binti Fulan, lalu kami didatangi oleh seorang wanita berkulit hitam seraya berkata padaku, 'Sesungguhnya aku pernah menyusui kalian berdua.' Wanita itu pembohong.\" Lalu beliau pun berpaling dariku, lalu aku menghadap lagi ke wajah beliau dan berkata, \"Sesungguhnya wanita itu adalah pembohong.\" Beliau bersabda: \"Apa salah wanita itu, dan bukankah ia telah berkata yang sesungguhnya, bahwa ia benar-benar telah menyusui kalian berdua. Tinggalkanlah si Fulanah itu.\" Isma'iI memberikan isyarat dengan jari telunjuk dan jari tengahnya saat mengkisahkannya kepada Ayyub."},"4410":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ زَيْنَبَ عَنْ أُمِّ حَبِيبَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ هَلْ لَكَ فِي بِنْتِ أَبِي سُفْيَانَ قَالَ فَأَفْعَلُ مَاذَا قُلْتُ تَنْكِحُ قَالَ أَتُحِبِّينَ قُلْتُ لَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَبُّ مَنْ شَرِكَنِي فِيكَ أُخْتِي قَالَ إِنَّهَا لَا تَحِلُّ لِي قُلْتُ بَلَغَنِي أَنَّكَ تَخْطُبُ قَالَ ابْنَةَ أُمِّ سَلَمَةَ قُلْتُ نَعَمْ قَالَ لَوْ لَمْ تَكُنْ رَبِيبَتِي مَا حَلَّتْ لِي أَرْضَعَتْنِي وَأَبَاهَا ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّوَقَالَ اللَّيْثُ حَدَّثَنَا هِشَامٌ دُرَّةُ بِنْتُ أَبِي سَلَمَةَ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Zainab] dari [Ummu Habibah] ia berkata; Aku bertanya, \"Wahai Rasulullah, adakah Anda berhasrat terhadap anak wanita Abu Sufyan?\" beliau balik bertanya: \"Saya suruh apa memangnya?.\" Aku berkata, \" Maksudku, engkau menikahinya. Rasul bertanya 'Apakah engkau menyukainya? Saya katakan, saya tak ingin jika kebaikanmu kunikmati sendiri, namun saya ingin agar kebaikanmu juga dinikmati saudariku.\" Beliau bersabda: \"Sesungguhnya ia tidaklah halal bagiku.\" Aku berkata, \"Telah sampai berita kepadaku bahwa Anda ingin tengah meminang.\" Beliau bertanya, \"Maksudmu adalah anak wanita Ummu Salamah?\" aku menjawab, \"Ya.\" Beliau bersabda: \"Meskipun ia bukan anak tiriku, tidaklah ia halal bagiku. Tsuwaibah telah menyusuiku dan juga bapaknya. Janganlah kalian menawarkan anak-anak perempuan dan juga saudari-saudari kalian padaku.\" [Al Laits] berkata; [Hisyam] menceritakan kepada kami bahwa, Durra adalah bintu Abu Salamah."},"4411":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ أَخْبَرَهُ أَنَّ زَيْنَبَ بِنْ��َ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّ حَبِيبَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ انْكِحْ أُخْتِي بِنْتَ أَبِي سُفْيَانَ قَالَ وَتُحِبِّينَ قُلْتُ نَعَمْ لَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَبُّ مَنْ شَارَكَنِي فِي خَيْرٍ أُخْتِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ ذَلِكِ لَا يَحِلُّ لِي قُلْتُ يَا رَسُولَ اللَّهِ فَوَاللَّهِ إِنَّا لَنَتَحَدَّثُ أَنَّكَ تُرِيدُ أَنْ تَنْكِحَ دُرَّةَ بِنْتَ أَبِي سَلَمَةَ قَالَ بِنْتَ أُمِّ سَلَمَةَ فَقُلْتُ نَعَمْ قَالَ فَوَاللَّهِ لَوْ لَمْ تَكُنْ فِي حَجْرِي مَا حَلَّتْ لِي إِنَّهَا لَابْنَةُ أَخِي مِنْ الرَّضَاعَةِ أَرْضَعَتْنِي وَأَبَا سَلَمَةَ ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] bahwa [Urwah bin Az Zubair] Telah mengabarkan kepadanya, bahwa [Zainab binti Abu Salamah] Telah mengabarkan keapdanya bahwa [Ummu Habibah] berkata; Aku berkata, \"Wahai Rasulullah, nikahilah saudaraku binti Abu Sufyan.\" Beliau bersabda: \"Apakah kamu suka?\" Aku menjawab, \"Ya, dan bukan berarti aku mau berpisah dengan Anda. Tetapi, orang yang paling aku sukai dapat ikut serta dalam kebaikan denganku adalah saudara perempuanku.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hal itu tidaklah halal bagiku.\" Aku berkata lagi, \"Wahai Rasulullah, sesungguhnya kami tengah berbincang-bincang bahwa Anda ingin menikahi Durrah binti Abu Salamah.\" Beliau balik bertanya: \"Binta Ummi Salamah?\" Aku menjawab, \"Ya.\" Beliau bersabda: \"Demi Allah, sekiranya ia tidak dalam asuhanku, ia pun tidaklah halal bagiku. Sesungguhnya ia adalah anak dari saudara sesusuanku. Yang demikian karena Tsuwaibah telah menyusui aku dan juga Abu Salamah. Karena itu, janganlah kalian menawarkan anak-anak perempuan kalian kepadaku dan jangan pula saudara-saudara perempuan kalian.\""},"4412":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمٌ عَنْ الشَّعْبِيِّ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا أَوْ خَالَتِهَاوَقَالَ دَاوُدُ وَابْنُ عَوْنٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Abdan] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ashim] dari [Asy Sya'bi] bahwa ia mendengar [Jabir] radliallahu 'anhu berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang bilamana wanita dimadu dengan bibinya baik dari jalur ibu atau bapaknya.\" [Dawud] berkata; Dan [Ibnu 'Aun] dari [Asy Sya'bi] dari [Abu Hurairah]."},"4413":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُجْمَعُ بَيْنَ الْمَرْأَةِ وَعَمَّتِهَا وَلَا بَيْنَ الْمَرْأَةِ وَخَالَتِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wanita tidak boleh dimadu dengan bibinya baik dari jalur ibu atau ayah.\""},"4414":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنِي يُونُسُ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي قَبِيصَةُ بْنُ ذُؤَيْبٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا وَالْمَرْأَةُ وَخَالَتُهَافَنُرَى خَالَةَ أَبِيهَا بِتِلْكَ الْمَنْزِلَةِ لِأَنَّ عُرْوَةَ حَدَّثَنِي عَنْ عَائِشَةَ قَالَتْ حَرِّمُوا مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah menceritakan kepada kami [Abdan] Telah mengabarkan kepada kami [Abdullah] ia berkata; Telah mengabarkan kepadaku [Yunus] dari [Az Zuhri] ia berkata; Telah menceritakan kepadaku [Qabishah bin Dzu`aib] bahwa ia mendengar [Abu Hurairah] berkata; Nabi shallallahu 'alaihi wasallam melarang bilamana wanita dimadu dengan bibinya (baik dari ibnu atau bapak). Dan menurut kami, bibi bapaknya termasuk juga dalam larangan tersebut. Sebabnya, [Urwah] Telah menceritakan kepadaku dari [Aisyah], ia berkata, \"Persusuan akan mengharamkan sebagaimana apa yang diharamkan nasab.\""},"4415":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشِّغَارِ وَالشِّغَارُ أَنْ يُزَوِّجَ الرَّجُلُ ابْنَتَهُ عَلَى أَنْ يُزَوِّجَهُ الْآخَرُ ابْنَتَهُ لَيْسَ بَيْنَهُمَا صَدَاقٌ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwasanya; Rasulullah shallallahu 'alaihi wasallam melarang Asy Syiqhar. Asy Syighar adalah sesorang menikahkan anak perempuannya kepada orang lain agar orang lain tersebut juga mau menikahkan anak perempuannya dengannya, sedangkan diantara keduanya tidak ada mahar."},"4416":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ قَالَكَانَتْ خَوْلَةُ بِنْتُ حَكِيمٍ مِنْ اللَّائِي وَهَبْنَ أَنْفُسَهُنَّ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ عَائِشَةُ أَمَا تَسْتَحِي الْمَرْأَةُ أَنْ تَهَبَ نَفْسَهَا لِلرَّجُلِ فَلَمَّا نَزَلَتْ{ تُرْجِئُ مَنْ تَشَاءُ مِنْهُنَّ }قُلْتُ يَا رَسُولَ اللَّهِ مَا أَرَى رَبَّكَ إِلَّا يُسَارِعُ فِي هَوَاكَرَوَاهُ أَبُو سَعِيدٍ الْمُؤَدِّبُ وَمُحَمَّدُ بْنُ بِشْرٍ وَعَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ يَزِيدُ بَعْضُهُمْ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sallam] Telah menceritakan kepada kami [Ibnu Fudlail] Telah menceritakan kepada kami [Hisyam] dari [bapaknya] ia berkata; Khaulah binti Hakim adalah termasuk salah seorang dari para wanita yang telah mengibahkan dirinya kepada Nabi shallallahu 'alaihi wasallam. Maka [Aisyah] pun berkata, \"Tidakkah seorang wanita itu merasa malu, saat menghibahkan dirinya kepada seorang laki-laki?\" Maka ketika ayat ini turun, \"TURJI`U MAN TASYAA`U MINHUNNA..\" aku berkata, \"Wahai Rasulullah, tidaklah aku melihat Rabb-mu, kecuali Dia mempercepat hasrat Anda.\" Ini diriwayatkan oleh [Abu Sa'id Al Mu`addibi], [Muhammad bin Bisyr] dan [Abdah] dari [Hisyam] dari [bapaknya] dari [Aisyah]. Dan sebagian mereka menambah atas sebagian yang lain."},"4417":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ أَخْبَرَنَا ابْنُ عُيَيْنَةَ أَخْبَرَنَا عَمْرٌو حَدَّثَنَا جَابِرُ بْنُ زَيْدٍ قَالَ أَنْبَأَنَا ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاتَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] Telah mengabarkan kepada kami [Ibnu Uyainah] Telah mengabarkan kepada kami [Amru] Telah menceritakan kepada kami [Jabir bin Zaid] ia berkata; Telah memberitakan kepada kami [Ibnu Abbas] radliallahu 'anhuma; Nabi shallallahu 'alaihi wasallam menikah pada saat beliau dalam keadaan berihram."},"4418":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا ابْنُ عُيَيْنَةَ أَنَّهُ سَمِعَ الزُّهْرِيَّ يَقُولُ أَخْبَرَنِي الْحَسَنُ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ وَأَخُوهُ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ عَنْ أَبِيهِمَا أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُقَالَ لِابْنِ عَبَّاسٍ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُتْعَةِ وَعَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ زَمَنَ خَيْبَرَ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] Telah menceritakan kepada kami [Ibnu Uyainah] bahwa ia mendengar [Az Zuhri] berkata; Telah mengabarkan kepadaku [Al Hasan bin Muhammad bin Ali] dan saudaranya [Abdullah bin Muhammad] dari [bapak keduanya] bahwasanya; [Ali] radliallahu 'anhu berkata kepada Ibnu Abbas, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam telah melarang nikat Mut'ah dan memakan daging himar yang jinak pada zaman Khaibar.\""},"4419":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍسُئِلَ عَنْ مُتْعَةِ النِّسَاءِ فَرَخَّصَ فَقَالَ لَهُ مَوْلًى لَهُ إِنَّمَا ذَلِكَ فِي الْحَالِ الشَّدِيدِ وَفِي النِّسَاءِ قِلَّةٌ أَوْ نَحْوَهُ فَقَالَ ابْنُ عَبَّاسٍ نَعَمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Abu Jamrah] ia berkata; Aku mendengar [Ibnu Abbas] ketika ia ditanya mengenai nikah Mut'ah, lalu ia memberi rukhshah. Maka bekas budaknya pun berkata, \"Sesungguhnya yang demikiannya itu hanya boleh pada saat seseorang memang berada dalam keadaan yang sangat memperihatinkan dan ketika wanita sangat sedikit.\" Maka Ibnu Abbas berkata, \"Ya, benar.\""},"4420":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو عَنْ الْحَسَنِ بْنِ مُحَمَّدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَسَلَمَةَ بْنِ الْأَكْوَعِ قَالَاكُنَّا فِي جَيْشٍ فَأَتَانَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ قَدْ أُذِنَ لَكُمْ أَنْ تَسْتَمْتِعُوا فَاسْتَمْتِعُواوَقَالَ ابْنُ أَبِي ذِئْبٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ وَامْرَأَةٍ تَوَافَقَا فَعِشْرَةُ مَا بَيْنَهُمَا ثَلَاثُ لَيَالٍ فَإِنْ أَحَبَّا أَنْ يَتَزَايَدَا أَوْ يَتَتَارَكَا تَتَارَكَا فَمَا أَدْرِي أَشَيْءٌ كَانَ لَنَا خَاصَّةً أَمْ لِلنَّاسِ عَامَّةً قَالَ أَبُو عَبْد اللَّهِ وَبَيَّنَهُ عَلِيٌّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَنْسُوخٌ","id":"Telah menceritakan kepada kami [Ali] Telah menceritakan kepada kami [Sufyan] Telah berkata [Amru] dari [Al Hasan bin Muhammad] dari [Jabir bin Abdullah] dan [Salamah bin Al Akwa'] keduanya berkata; Ketika kami berada dalam suatu pasukan perang, Rasulullah shallallahu 'alaihi wasallam mendatangi kami dan bersabda: \"Sesungguhnya telah dizinkan bagi kalian untuk melakukan nikah Mut'ah, karena itu lakukanlah.\" [Ibnu Abu Dzi`b] berkata; Telah menceritakan kepadaku [Iyas bin Salamah bin Al Akwa'] dari [bapaknya] dari Rasulullah shallallahu 'alaihi wasallam, \"Bilamana seorang laki-laki dan perempuan telah bersepakat, maka batas maksimal antara mereka berdua adalah tiga malam. Jika keduanya suka, maka keduanya boleh menambah, atau pun berpisah.\" Aku tidak tahu, apakah perkara itu adalah khusus bagi kami, ataukah juga orang lain secara umum. Abu Abdullah berkata; Dan Ali menjelaskan dari Nabi shallallahu 'alaihi wasallam, bahwa perkara tersebut telah Mansukh (dihapus)."},"4421":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ بْنِ مِهْرَانَ قَالَ سَمِعْتُ ثَابِتًا الْبُنَانِيَّ قَالَكُنْتُ عِنْدَ أَنَسٍ وَعِنْدَهُ ابْنَةٌ لَهُ قَالَ أَنَسٌ جَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْرِضُ عَلَيْهِ نَفْسَهَا قَالَتْ يَا رَسُولَ اللَّهِ أَلَكَ بِي حَاجَةٌفَقَالَتْ بِنْتُ أَنَسٍ مَا أَقَلَّ حَيَاءَهَا وَا سَوْأَتَاهْ وَا سَوْأَتَاهْ قَالَ هِيَ خَيْرٌ مِنْكِ رَغِبَتْ فِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَضَتْ عَلَيْهِ نَفْسَهَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Marhum bin Abdul Aziz bin Mihran] ia berkata; Aku mendengar [Tsabit Al Bunani] berkata; Aku pernah berada di tempat Anas, sedang ia memiliki anak wanita. [Anas] berkata, \"Ada seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam lalu menghibahkan dirinya kepada beliau. Wanita itu berkata, 'Wahai Rasulullah, adakah Anda berhasrat padaku?\" lalu anak wanita Anas pun berkomentar, \"Alangkah sedikitnya rasa malunya..\" Anas berkata, \"Wanita lebih baik daripada kamu, sebab ia suka pada Nabi shallallahu 'alaihi wasallam, hingga ia menghibahkan dirinya pada beliau.\""},"4422":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ امْرَأَةً عَرَضَتْ نَفْسَهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ زَوِّجْنِيهَا فَقَالَ مَا عِنْدَكَ قَالَ مَا عِنْدِي شَيْءٌ قَالَ اذْهَبْ فَالْتَمِسْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ مَا وَجَدْتُ شَيْئًا وَلَا خَاتَمًا مِنْ حَدِيدٍ وَلَكِنْ هَذَا إِزَارِي وَلَهَا نِصْفُهُ قَالَ سَهْلٌ وَمَا لَهُ رِدَاءٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا تَصْنَعُ بِإِزَارِكَ إِنْ لَبِسْتَهُ لَمْ يَكُنْ عَلَيْهَا مِنْهُ شَيْءٌ وَإِنْ لَبِسَتْهُ لَمْ يَكُنْ عَلَيْكَ مِنْهُ شَيْءٌ فَجَلَسَ الرَّجُلُ حَتَّى إِذَا طَالَ مَجْلِسُهُ قَامَ فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَاهُ أَوْ دُعِيَ لَهُ فَقَالَ لَهُ مَاذَا مَعَكَ مِنْ الْقُرْآنِ فَقَالَ مَعِي سُورَةُ كَذَا وَسُورَةُ كَذَا لِسُوَرٍ يُعَدِّدُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْلَكْنَاكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] Telah menceritakan kepada kami [Abu Ghassan] ia berkata; Telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] bahwasanya; Ada seorang wanita menawarkan dan menghibahkan dirinya kepada Nabi shallallahu 'alaihi wasallam, lalu seorang laki-laki pun berkata pada beliau, \"Wahai Rasulullah, nikahkanlah aku dengannya.\" Beliau bertanya, \"Apa yang kamu punyai?\" laki-laki itu menjawab, \"Aku tidak punya apa-apa.\" Beliau bersabda: \"Pergi dan carilah meskipun hanya cincin besi.\" Maka laki-laki itu pun pergi, kemudian kembali dan berkata, \"Tidak, demi Allah aku mendapatkan sesuatu apa pun, kecuali sarungku ini, biarlah wanita itu mendapat setengahnya.\" Sahl berkata; Laki-laki itu tidak memiliki baju atas. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apa yang dapat kamu perbuat dengan kainmu itu. Jika kamu memakainya, maka badanmu tidak tertutup, dan bila nanti isterimu memakainya, badan atasnya juga tak tertutup.\" Akhinya laki-laki itu pun duduk hingga agak lama, lalu beranjak. Kemudian Nabi shallallahu 'alaihi wasallam melihatnya, maka beliau pun memanggilnya -atau dipanggilkan untuknya- lalu bertanya padanya: \"Apa saja yang telah kamu hafal dari Al Qur`an?\" laki-laki itu menjawab, \"Aku hafal surat ini dan ini.\" Ia menghitungnya. Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Kami telah menikahkanmu dengan wanita itu dengan mahar hafalan Al Qur`anmu.\""},"4423":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يُحَدِّثُأَنَّ عُمَرَ بْنَ الْخَطَّابِ حِينَ تَأَيَّمَتْ حَفْصَةُ بِنْتُ عُمَرَ مِنْ خُنَيْسِ بْنِ حُذَافَةَ السَّهْمِيِّ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتُوُفِّيَ بِالْمَدِينَةِ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ أَتَيْتُ عُثْمَانَ بْنَ عَفَّانَ فَعَرَضْتُ عَلَيْهِ حَفْصَةَ فَقَالَ سَأَنْظُرُ فِي أَمْرِي فَلَبِثْتُ لَيَالِيَ ثُمَّ لَقِيَنِي فَقَالَ قَدْ بَدَا لِي أَنْ لَا أَتَزَوَّجَ يَوْمِي هَذَا قَالَ عُمَرُ فَلَقِيتُ أَبَا بَكْرٍ الصِّدِّيقَ فَقُلْتُ إِنْ شِئْتَ زَوَّجْتُكَ حَفْصَةَ بِنْتَ عُمَرَ فَصَمَتَ أَبُو بَكْرٍ فَلَمْ يَرْجِعْ إِلَيَّ شَيْئًا وَكُنْتُ أَوْجَدَ عَلَيْهِ مِنِّي عَلَى عُثْمَانَ فَلَبِثْتُ لَيَالِيَ ثُمَّ خَطَبَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْكَحْتُهَا إِيَّاهُ فَلَقِيَنِي أَبُو بَكْرٍ فَقَالَ لَعَلَّكَ وَجَدْتَ عَلَيَّ حِينَ عَرَضْتَ عَلَيَّ حَفْصَةَ فَلَمْ أَرْجِعْ إِلَيْكَ شَيْئًا قَالَ عُمَرُ قُلْتُ نَعَمْ قَالَ أَبُو بَكْرٍ فَإِنَّهُ لَمْ يَمْنَعْنِي أَنْ أَرْجِعَ إِلَيْكَ فِيمَا عَرَضْتَ عَلَيَّ إِلَّا أَنِّي كُنْتُ عَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ ذَكَرَهَا فَلَمْ أَكُنْ لِأُفْشِيَ سِرَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ تَرَكَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبِلْتُهَا","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] Telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih bin Kaisan] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Salim bin Abdullah] bahwa ia mendengar [Abdullah bin Umar] radliallahu 'anhuma menceritakan bahwasanya; Ketika Hafshah binti Umar menjadi janda lantaran wafatnya Khunais bin Hudzafah As Sahmi -termasuk salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, dan ia wafat di Madinah-, Maka Umar bin Al Khaththab berkata; Aku mendatangi Utsman bin Affan dan menawarkan Hafshah padanya, maka ia pun berkata, \"Aku akan berfikir terlebih dahulu.\" Lalu aku pun menunggu beberapa malam, kemudian ia menemuiku dan berkata, \"Aku telah mengambil keputusan, bahwa aku tidak akan menikah untuk hari-hari ini.\" Lalu aku pun menemui Abu Bakar Ash Shiddiq dan berkata padanya, \"Jika kamu mau, maka aku akan menikahkanmu dengan Hafshah.\" Namun ia tidak memberi jawaban apa pun padaku. Maka aku menunggu selama beberapa malam, dan akhirnya ia pun dikhithbah oleh Rasulullah shallallahu 'alaihi wasallam, maka aku menikahkannya dengan beliau. Kemudian Abu Bakar menemuiku dan berkata, \"Sepertinya kamu merasa kecewa saat menawarkan Hafshah padaku.\" Umar berkata; Aku berkata, \"Ya.\" Abu Bakar berkata, \"Sesungguhnya tidak ada yang menghalangiku untuk menerima tawaranmu, kecuali bahwa aku tahu Rasulullah shallallahu 'alaihi wasallam telah menyebutnya. Dan aku tidak mau membuka rahasia Rasulullah shallallahu 'alaihi wasallam. Dan sekiranya Rasulullah shallallahu 'alaihi wasallam meninggalkannya, niscaya aku akan menerimanya.\""},"4424":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِرَاكِ بْنِ مَالِكٍ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّ حَبِيبَةَقَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا قَدْ تَحَدَّثْنَا أَنَّكَ نَاكِحٌ دُرَّةَ بِنْتَ أَبِي سَلَمَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعَلَى أُمِّ سَلَمَةَ لَوْ لَمْ أَنْكِحْ أُمَّ سَلَمَةَ مَا حَلَّتْ لِي إِنَّ أَبَاهَا أَخِي مِنْ الرَّضَاعَةِ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari ['Irak bin Malik] bahwa [Zainab binti Abu Salamah] Telah mengabarkan kepadanya bahwa [Ummu Habibah] berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Kami telah berbincang-bincang bahwa Anda ingin menikahi Durrah binti Abu Salamah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah juga dengan menyatukan Ummu Salamah? Sekiranya aku tidak menikahi Ummu Salamah pun, maka ia juga tidak halal bagiku. Sesungguhnya bapaknya adalah saudara sesusuan denganku.\""},"4425":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُكِ فِي الْمَنَامِ يَجِيءُ بِكِ الْمَلَكُ فِي سَرَقَةٍ مِنْ حَرِيرٍ فَقَالَ لِي هَذِهِ امْرَأَتُكَ فَكَشَفْتُ عَنْ وَجْهِكِ الثَّوْبَ فَإِذَا أَنْتِ هِيَ فَقُلْتُ إِنْ يَكُ هَذَا مِنْ عِنْدِ اللَّهِ يُمْضِهِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Aku melihatmu di alam mimpiku. Kamu dibawa oleh Malaikat dengan bertutupkan kain sutera, lalu Malaikat itu pun berkata padaku, 'Ini adalah isterimu.' Maka aku pun menyingkap kain yang menutupi wajahmu, dan ternyata wanita itu adalah kamu. Maka aku pun berkata, 'Kalau hal ini datangnya dari Allah, maka Allah pasti akan menjadikan kenyataan.'\""},"4426":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ امْرَأَةً جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ جِئْتُ لِأَهَبَ لَكَ نَفْسِي فَنَظَرَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَعَّدَ النَّظَرَ إِلَيْهَا وَصَوَّبَهُ ثُمَّ طَأْطَأَ رَأْسَهُ فَلَمَّا رَأَتْ الْمَرْأَةُ أَنَّهُ لَمْ يَقْضِ فِيهَا شَيْئًا جَلَسَتْ فَقَامَ رَجُلٌ مِنْ أَصْحَابِهِ فَقَالَ أَيْ رَسُولَ اللَّهِ إِنْ لَمْ تَكُنْ لَكَ بِهَا حَاجَةٌ فَزَوِّجْنِيهَا فَقَالَ هَلْ عِنْدَكَ مِنْ شَيْءٍ قَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ قَالَ اذْهَبْ إِلَى أَهْلِكَ فَانْظُرْ هَلْ تَجِدُ شَيْئًا فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ مَا وَجَدْتُ شَيْئًا قَالَ انْظُرْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ وَلَا خَاتَمًا مِنْ حَدِيدٍ وَلَكِنْ هَذَا إِزَارِي قَالَ سَهْلٌ مَا لَهُ رِدَاءٌ فَلَهَا نِصْفُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصْنَعُ بِإِزَارِكَ إِنْ لَبِسْتَهُ لَمْ يَكُنْ عَلَيْهَا مِنْهُ شَيْءٌ وَإِنْ لَبِسَتْهُ لَمْ يَكُنْ عَلَيْكَ مِنْهُ شَيْءٌ فَجَلَسَ الرَّجُلُ حَتَّى طَالَ مَجْلِسُهُ ثُمَّ قَامَ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَلِّيًا فَأَمَرَ بِهِ فَدُعِيَ فَلَمَّا جَاءَ قَالَ مَاذَا مَعَكَ مِنْ الْقُرْآنِ قَالَ مَعِي سُورَةُ كَذَا وَسُورَةُ كَذَا وَسُورَةُ كَذَا عَدَّدَهَا قَالَ أَتَقْرَؤُهُنَّ عَنْ ظَهْرِ قَلْبِكَ قَالَ نَعَمْ قَالَ اذْهَبْ فَقَدْ مَلَّكْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Ya'qub] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa ada seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku datang untuk menghibahkan diriku untuk Anda.\" Maka Rasulullah shallallahu 'alaihi wasallam mengamati wanita dengan cermat dan setelah itu beliau menundukkan kepala. Ketika wanita itu melihat, bahwa beliau belum memberikan putusan apa-apa terhadapnya, ia pun duduk. Tiba-tiba berdirilah seorang laki-laki dari sahabat beliau dan berkata, \"Wahai Rasulullah, bila Anda tak berhasrat pada wanita itu, maka nikahkanlah aku dengannya.\" Beliau bertanya: \"Apakah kamu punya sesuatu (sebagai mahar)?\" ia menjawab, \"Tidak, demi Allah wahai Rasulullah.\" Beliau bersabda: \"Kalau begitu, pergilah kepada keluargamu, dan lihatlah apakah ada sesuatu yang kamu dapatkan.\" Laki-laki itu pun pergi, lalu kembali dan berkata, \"Tidak, demi Allah wahai Rasulullah, aku tidak mendapatkan sesuatu.\" Beliau bersabda: \"Lihatlah meskipun itu hanya cincin dari besi.\" Laki-laki itu pergi lagi, lalu kembali dan berkata, \"Tidak ada, demi Allah wahai Rasulullah, meskipun hanya cincin besi. Tetapi, ini adalah kainku.\" Sahl berkata; Ia tidaklah memiliki baju, maka calon isterinya berilah setengah sarungnya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang bisa kamu lakukan jika kau gunakan setengah sarungmu. Bila kamu memakainya, maka separoh badanmu tak tertutup kain, dan bila calon isterimu memakainya, separoh badannya pun tak tertutup kain.\" Akhirnya laki-laki itu pun duduk hingga lama, lalu ia beranjak hendak pergi. Kemudian Rasulullah shallallahu 'alaihi wasallam melihatnya, beliau pun memeritahkan agar orang itu dipanggil. Dan ketika laki-laki itu datang beliau bertanya: \"Apa yang kamu hafal dari Al Qur`an?\" laki-laki itu menjawab, \"Aku menghafal surat ini dan ini.\" Ia menghitungnya. Kemudian beliau bersabda: \"Bacalah dari hafalanmu itu untuknya.\" Ia menjawab, \"Baik.\" Beliau bersabda: \"Pergilah, sesungguhnya aku telah menikahkanmu dengan wanita itu dan hafalan Al Qur`anmu sebagai mahar.\""},"4427":{"ar":"قَالَ يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ ح و حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَنْبَسَةُ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ النِّكَاحَ فِي الْجَاهِلِيَّةِ كَانَ عَلَى أَرْبَعَةِ أَنْحَاءٍ فَنِكَاحٌ مِنْهَا نِكَاحُ النَّاسِ الْيَوْمَ يَخْطُبُ الرَّجُلُ إِلَى الرَّجُلِ وَلِيَّتَهُ أَوْ ابْنَتَهُ فَيُصْدِقُهَا ثُمَّ يَنْكِحُهَا وَنِكَاحٌ آخَرُ كَانَ الرَّجُلُ يَقُولُ لِامْرَأَتِهِ إِذَا طَهُرَتْ مِنْ طَمْثِهَا أَرْسِلِي إِلَى فُلَانٍ فَاسْتَبْضِعِي مِنْهُ وَيَعْتَزِلُهَا زَوْجُهَا وَلَا يَمَسُّهَا أَبَدًا حَتَّى يَتَبَيَّنَ حَمْلُهَا مِنْ ذَلِكَ الرَّجُلِ الَّذِي تَسْتَبْضِعُ مِنْهُ فَإِذَا تَبَيَّنَ حَمْلُهَا أَصَابَهَا زَوْجُهَا إِذَا أَحَبَّ وَإِنَّمَا يَفْعَلُ ذَلِكَ رَغْبَةً فِي نَجَابَةِ الْوَلَدِ فَكَانَ هَذَا النِّكَاحُ نِكَاحَ الِاسْتِبْضَاعِ وَنِكَاحٌ آخَرُ يَجْتَمِعُ الرَّهْطُ مَا دُونَ الْعَشَرَةِ فَيَدْخُلُونَ عَلَى الْمَرْأَةِ كُلُّهُمْ يُصِيبُهَا فَإِذَا حَمَلَتْ وَوَضَعَتْ وَمَرَّ عَلَيْهَا لَيَالٍ بَعْدَ أَنْ تَضَعَ حَمْلَهَا أَرْسَلَتْ إِلَيْهِمْ فَلَمْ يَسْتَطِعْ رَجُلٌ مِنْهُمْ أَنْ يَمْتَنِعَ حَتَّى يَجْتَمِعُوا عِنْدَهَا تَقُولُ لَهُمْ قَدْ عَرَفْتُمْ الَّذِي كَانَ مِنْ أَمْرِكُمْ وَقَدْ وَلَدْتُ فَهُوَ ابْنُكَ يَا فُلَانُ تُسَمِّي مَنْ أَحَبَّتْ بِاسْمِهِ فَيَلْحَقُ بِهِ وَلَدُهَا لَا يَسْتَطِيعُ أَنْ يَمْتَنِعَ بِهِ الرَّجُلُ وَنِكَاحُ الرَّابِعِ يَجْتَمِعُ النَّاسُ الْكَثِيرُ فَيَدْخُلُونَ عَلَى الْمَرْأَةِ لَا تَمْتَنِعُ مِمَّنْ جَاءَهَا وَهُنَّ الْبَغَايَا كُنَّ يَنْصِبْنَ عَلَى أَبْوَابِهِنَّ رَايَاتٍ تَكُونُ عَلَمًا فَمَنْ أَرَادَهُنَّ دَخَلَ عَلَيْهِنَّ فَإِذَا حَمَلَتْ إِحْدَاهُنَّ وَوَضَعَتْ حَمْلَهَا جُمِعُوا لَهَا وَدَعَوْا لَهُمْ الْقَافَةَ ثُمَّ أَلْحَقُوا وَلَدَهَا بِالَّذِي يَرَوْنَ فَالْتَاطَ بِهِ وَدُعِيَ ابْنَهُ لَا يَمْتَنِعُ مِنْ ذَلِكَ فَلَمَّا بُعِثَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَقِّ هَدَمَ نِكَاحَ الْجَاهِلِيَّةِ كُلَّهُ إِلَّا نِكَاحَ النَّاسِ الْيَوْمَ","id":"Telah berkata [Yahya bin Sulaiman] Telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] -dalam riwayat lain- Dan Telah menceritakan kepada kami [Ahmad bin Shalih] Telah menceritakan kepada kami [Anbasah] Telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa; Sesungguhnya pada masa Jahiliyah ada empat macam bentuk pernikahan. Pertama, adalah pernikahan sebagaimana dilakukan orang-orang pada saat sekarang ini, yaitu seorang laki-laki meminang kepada wali sang wanita, kemudian memberikannya mahar lalu menikahinya. Bentuk kedua yaitu; Seorang suami berkata kepada isterinya pada saat suci (tidak haidl/subur), \"Temuilah si Fulan dan bergaullah (bersetubuh) dengannya.\" Sementara sang suami menjauhinya sementara waktu (tidak menjima'nya) hingga benar-benar ia positif hamil dari hasil persetubuhannya dengan laki-laki itu. Dan jika dinyatakan telah positif hamil, barulah sang suami tadi menggauli isterinya bila ia suka. Ia melakukan hal itu, hanya untuk mendapatkan keturuan yang baik. Istilah nikah ini adalah Nikah Al Istibdlaa'. Kemudian bentuk ketiga; Sekelompok orang (kurang dari sepuluh) menggauli seorang wanita. Dan jika ternyata wanita itu hamil dan melahirkan. Maka setelah masa bersalinnya telah berlalu beberapa hari, wanita itu pun mengirimkan surat kepada sekelompok laki-laki tadi, dan tidak seorang pun yang boleh menolak. Hingga mereka pun berkumpul di tempat sang wanita itu. Lalu wanita itu pun berkata, \"Kalian telah tahu apa urusan kalian yang dulu. Dan aku telah melahirnya, maka anak itu adalah anakmu wania Fulan.\" Yakni, wanita itu memilih nama salah seorang dari mereka yang ia sukai, dan laki-laki yang ditunjuk tidak dapat mengelak. Kemudian bentuk keempat; Orang banyak berkumpul, lalu menggauli seorang wanita, dan tak seorang pun yang dapat menolak bagi yang orang yang telah menggauli sang wanita. Para wanita itu adalah wanita pelacur. Mereka menancapkan tanda pada pintu-pintu rumah mereka sebagai tanda, siapa yang ingin mereka maka ia boleh masuk dan bergaul dengan mereka. Dan ketika salah seorang dari mereka hamil, lalu melahirkan, maka mereka (orang banyak itu) pun dikumpulkan, lalu dipanggilkanlah orang yang ahli seluk beluk nasab (Alqafah), dan Al Qafah inilah yang menyerahkan anak sang wanita itu kepada orang yang dianggapnya sebagai bapaknya, sehingga anak itu dipanggil sebagai anak darinya. Dan orang itu tidak bisa mengelak. Maka ketika Nabi Muhammad shallallahu 'alaihi wasallam diutus dengan membawa kebenaran, beliau pun memusnahkan segala bentuk pernikahan jahiliyah, kecuali pernikahan yang dilakoni oleh orang-orang hari ini."},"4428":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ{ وَمَا يُتْلَى عَلَيْكُمْ فِي الْكِتَابِ فِي يَتَامَى النِّسَاءِ اللَّاتِي لَا تُؤْتُونَهُنَّ مَا كُتِبَ لَهُنَّ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }قَالَتْ هَذَا فِي الْيَتِيمَةِ الَّتِي تَكُونُ عِنْدَ الرَّجُلِ لَعَلَّهَا أَنْ تَكُونَ شَرِيكَتَهُ فِي مَالِهِ وَهُوَ أَوْلَى بِهَا فَيَرْغَبُ عَنْهَا أَنْ يَنْكِحَهَا فَيَعْضُلَهَا لِمَالِهَا وَلَا يُنْكِحَهَا غَيْرَهُ كَرَاهِيَةَ أَنْ يَشْرَكَهُ أَحَدٌ فِي مَالِهَا","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah], yakni terkait dengan firman-Nya: \"WA MAA YUTLAA 'ALAIKUM FILYATAAMAAN NISAA`IL LAATII LAA TU`TUUHUNNA MAA KUTIBA LAHUNNA WA TARGHUBUUNA AN TANKIHUUHUNNA, (QS. Annisa'; 127), Ia berkata, \"Ini terkait dengan anak perempuan yatim yang berada di bawah asuhan seseorang, yang ia berharap anak perempuan yatim itu dapat menjadi syarikat dalam hartanya. Dan dia merasa bahwa dialah orang yang paling berhak akan hal itu. Karena itu ia tidak mau menikahinya sebab akan menghalangi dirinya untuk mendapatkan harta sang anak perempuan yatim. Dan ia pun tidak sudi menikahkannya dengan orang lain, karena tak suka bila ada seseorang yang turut campur dalam hartanya.\""},"4429":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي سَالِمٌ أَنَّ ابْنَ عُمَرَ أَخْبَرَهُأَنَّ عُمَرَ حِينَ تَأَيَّمَتْ حَفْصَةُ بِنْتُ عُمَرَ مِنْ ابْنِ حُذَافَةَ السَّهْمِيِّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَهْلِ بَدْرٍ تُوُفِّيَ بِالْمَدِينَةِ فَقَالَ عُمَرُ لَقِيتُ عُثْمَانَ بْنَ عَفَّانَ فَعَرَضْتُ عَلَيْهِ فَقُلْتُ إِنْ شِئْتَ أَنْكَحْتُكَ حَفْصَةَ فَقَالَ سَأَنْظُرُ فِي أَمْرِي فَلَبِثْتُ لَيَالِيَ ثُمَّ لَقِيَنِي فَقَالَ بَدَا لِي أَنْ لَا أَتَزَوَّجَ يَوْمِي هَذَا قَالَ عُمَرُ فَلَقِيتُ أَبَا بَكْرٍ فَقُلْتُ إِنْ شِئْتَ أَنْكَحْتُكَ حَفْصَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] Telah menceritakan kepada kami [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Salim] bahwa [Ibnu Umar] Telah mengabarkan kepadanya, bahwasanya; Ketika Hafshah binti Umar menjadi janda lantaran wafat Ibnu Hudzafah As Sahmi -ia termasuk salah seorang sahabat Nabi shallallahu 'alaihi wasallam, ahli Badar yang wafat di Madinah- maka Umar berkata; Aku menemui Utsman bin Affan dan menawarkan Hafshah padanya, kukatakan padanya, \"Jika kamu mau, maka aku akan menikahkan Hafshah denganmu.\" Ia berkata, \"Aku akan memikirkannya terlebih dahulu.\" Maka aku pun menunggu beberapa malam, lalu ia mendatangiku dan berkata, \"Aku telah mengambil keputusan, bahwa aku tidak akan menikah untuk hari-hari ini.\" Kemudian aku menemui Abu Bakar dan berkata, \"Jika kamu mau, aku akan menikahkan Hafshah denganmu.\""},"4430":{"ar":"حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي عَمْرٍو قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ يُونُسَ عَنْ الْحَسَنِ{ فَلَا تَعْضُلُوهُنَّ }قَالَ حَدَّثَنِي مَعْقِلُ بْنُ يَسَارٍ أَنَّهَا نَزَلَتْ فِيهِ قَالَ زَوَّجْتُ أُخْتًا لِي مِنْ رَجُلٍ فَطَلَّقَهَا حَتَّى إِذَا انْقَضَتْ عِدَّتُهَا جَاءَ يَخْطُبُهَا فَقُلْتُ لَهُ زَوَّجْتُكَ وَفَرَشْتُكَ وَأَكْرَمْتُكَ فَطَلَّقْتَهَا ثُمَّ جِئْتَ تَخْطُبُهَا لَا وَاللَّهِ لَا تَعُودُ إِلَيْكَ أَبَدًا وَكَانَ رَجُلًا لَا بَأْسَ بِهِ وَكَانَتْ الْمَرْأَةُ تُرِيدُ أَنْ تَرْجِعَ إِلَيْهِ فَأَنْزَلَ اللَّهُ هَذِهِ الْآيَةَ{ فَلَا تَعْضُلُوهُنَّ }فَقُلْتُ الْآنَ أَفْعَلُ يَا رَسُولَ اللَّهِ قَالَ فَزَوَّجَهَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Amru] ia berkata; Telah menceritakan kepadaku [bapakku] ia berkata; Telah menceritakan kepadaku [Ibrahim] dari [Yunus] dari [Al Hasan] keduanya berkata; Terkait dengan Firman Allah: \"FALAA TA'DLULUUHUNNA..\" Ia berkata; [Ma'qil bin Yasar] telah menceritakan kepadaku, bahwa ayat itu turun berkenaan dengan dirinya. Ia berkata; Aku menikahkan saudara perempuanku kepada seorang laki-laki, kemudian ia menceraikannya. Lalu ketika masa iddahnya habis laki-laki itu datang kembali maka kukatakan kepadanya, \"Aku telah menikahkanmu, dan memuliakanmu lalu kamu menceraikannya, kemudian saat kamu datang untuk meminangnya kembali, tidak, demi Allah, adikku itu tidak akan kembali kepadamu selama-lamanya.\" Sebenarnya, tidak ada masalah pada laki-laki itu dan saudara perempuanku juga mau ruju' kepadanya, maka Allah pun menurunkan ayat ini, \"FALAA TA'DLULUUHUNNA..\" Karena itu, aku pun berkata, \"Sekarang aku akan melakukannya wahai Rasulullah.\" Maka ia pun menikahkan wanita itu kepadanya."},"4431":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فِي قَوْلِهِ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ }إِلَى آخِرِ الْآيَةِ قَالَتْ هِيَ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ الرَّجُلِ قَدْ شَرِكَتْهُ فِي مَالِهِ فَيَرْغَبُ عَنْهَا أَنْ يَتَزَوَّجَهَا وَيَكْرَهُ أَنْ يُزَوِّجَهَا غَيْرَهُ فَيَدْخُلَ عَلَيْهِ فِي مَالِهِ فَيَحْبِسُهَا فَنَهَاهُمْ اللَّهُ عَنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Ibnu Salam] Telah mengabarkan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, yakni terkait dengan firman-Nya: \"WA YASTAFTUUNAKA FIN NISAA` QULILLAHU YUFTIIKUM FIIHINNA..\" hingga akhir ayat. Aisyah berkata, \"Maksudnya adalah seorang anak perempuan yatim yang berada pada asuhan seorang laki-laki, dan sang anak perempuan yatim juga telah berserikat pada hartanya. Lalu laki-laki itu tidak ingin menikahinya dan ia tidak suka bila anak perempuan yatim itu dinikahi oleh orang lain karena dikhawatirkan mencampuri hartanya. Maka Allah melarang mereka untuk melakukan hal itu.\""},"4432":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْمِقْدَامِ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو حَازِمٍ حَدَّثَنَا سَهْلُ بْنُ سَعْدٍكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُلُوسًا فَجَاءَتْهُ امْرَأَةٌ تَعْرِضُ نَفْسَهَا عَلَيْهِ فَخَفَّضَ فِيهَا النَّظَرَ وَرَفَعَهُ فَلَمْ يُرِدْهَا فَقَالَ رَجُلٌ مِنْ أَصْحَابِهِ زَوِّجْنِيهَا يَا رَسُولَ اللَّهِ قَالَ أَعِنْدَكَ مِنْ شَيْءٍ قَالَ مَا عِنْدِي مِنْ شَيْءٍ قَالَ وَلَا خَاتَمٌ مِنْ حَدِيدٍ قَالَ وَلَا خَاتَمٌ مِنْ حَدِيدٍ وَلَكِنْ أَشُقُّ بُرْدَتِي هَذِهِ فَأُعْطِيهَا النِّصْفَ وَآخُذُ النِّصْفَ قَالَ لَا هَلْ مَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ قَالَ اذْهَبْ فَقَدْ زَوَّجْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Ahmad bin Al Miqdam] Telah menceritakan kepada kami [Fudlail bin Sulaiman] Telah menceritakan kepada kami [Abu Hazim] Telah menceritakan kepada kami [Sahl bin Sa'd] ia berkata; Suatu ketika, kami duduk di sisi Nabi shallallahu 'alaihi wasallam, lalu beliau didatangi oleh seorang wanita yang hendak menawarkan diri pada beliau, maka beliau pun memandangi wanita itu dengan cermat, namun beliau belum juga memberi jawaban. Maka seorang laki-laki dari sahabatnya berkakta, \"Nikahkanlah aku dengannya wahai Rasulullah.\" Beliau bertanya, \"Apakah kamu memiliki sesuatu (untuk dijadikan mahar)?\" laki-laki itu menjawab, \"Aku tak punya apa-apa.\" Beliau bertanya: \"Meskipun hanya cincin besi?\" laki-laki itu menjawab, \"Ya, meskipun hanya cincin besi. Tetapi kainku ini akan aku robek dan memberikan untuknya setengah darinya dan setengah yang lain untukku.\" Beliau bertanya lagi: \"Apakah kamu memiliki hafalan Al Qur`an?\" Laki-laki itu menjawab, \"Ya.\" Akhirnya beliau bersabda: \"Pergilah, sesungguhnya aku telah menikahkanmu dengan wanita itu dengan mahar hafalan Al Qur`anmu.\""},"4433":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْه��اأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَهَا وَهِيَ بِنْتُ سِتِّ سِنِينَ وَأُدْخِلَتْ عَلَيْهِ وَهِيَ بِنْتُ تِسْعٍ وَمَكَثَتْ عِنْدَهُ تِسْعًا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, bahwasanya; Nabi shallallahu 'alaihi wasallam menikahinya saat ia berumur enam tahun, dan ia digauli saat berumur sembilan tahun. Dan Aisyah hidup bersama dengan beliau selama sembilan tahun."},"4434":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَهَا وَهِيَ بِنْتُ سِتِّ سِنِينَ وَبَنَى بِهَا وَهِيَ بِنْتُ تِسْعِ سِنِينَ قَالَ هِشَامٌ وَأُنْبِئْتُ أَنَّهَا كَانَتْ عِنْدَهُ تِسْعَ سِنِينَ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] Telah menceritakan kepada kami [Wuhaib] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam menikahinya saat itu berusia enam tahun, dan mulai menggaulinya saat ia berumur sembilan tahun. Hisyam berkata; Dan telah diberitakan kepadaku bahwa Aisyah hidup bersama Rasulullah shallallahu 'alaihi wasallam selama sembilan tahun."},"4435":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي وَهَبْتُ مِنْ نَفْسِي فَقَامَتْ طَوِيلًا فَقَالَ رَجُلٌ زَوِّجْنِيهَا إِنْ لَمْ تَكُنْ لَكَ بِهَا حَاجَةٌ قَالَ هَلْ عِنْدَكَ مِنْ شَيْءٍ تُصْدِقُهَا قَالَ مَا عِنْدِي إِلَّا إِزَارِي فَقَالَ إِنْ أَعْطَيْتَهَا إِيَّاهُ جَلَسْتَ لَا إِزَارَ لَكَ فَالْتَمِسْ شَيْئًا فَقَالَ مَا أَجِدُ شَيْئًا فَقَالَ الْتَمِسْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَلَمْ يَجِدْ فَقَالَ أَمَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ سُورَةُ كَذَا وَسُورَةُ كَذَا لِسُوَرٍ سَمَّاهَا فَقَالَ قَدْ زَوَّجْنَاكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata; Ada seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya aku menghibahkan diriku.\" Wanita itu berdiri agak lama, lalu seorang laki-laki pun berkata, \"Nikahkahkanlah aku dengannya, jika memang Anda tidak berhasrat padanya.\" Beliau bertanya: \"Apakah kamu memiliki sesuatu untuk maharnya?\" laki-laki itu berkata, \"Aku tidak punya apa-apa kecuali kainku ini.\" Beliau bersabda: \"Jika kamu memberikannya dan kamu duduk tak berkain. Carilah sesuatu.\" Laki-laki itu menjawab, \"Aku tidak mendapatkan sesuatu.\" Beliau bersabda lagi: \"Carilah, meskipun hanya berupa cincin emas.\" Namun laki-laki itu ternyata tak mendapatkan sesuatu, akhirnya beliau bertanya: \"Apakah kamu hafal sesuatu dari Al Qur`an?\" laki-laki itu menjawab, \"Ya, yaitu surat ini dan ini.\" Ia menyebutkannya. Maka beliau bersabda: \"Sesungguhnya aku telah menikahkanmu dengan wanita itu dengan mahar hafalan Al Qur`anmu.\""},"4436":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الْأَيِّمُ حَتَّى تُسْتَأْمَرَ وَلَا تُنْكَحُ الْبِكْرُ حَتَّى تُسْتَأْذَنَ قَالُوا يَا رَسُولَ اللَّهِ وَكَيْفَ إِذْنُهَا قَالَ أَنْ تَسْكُتَ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] Telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] bahwa [Abu Hurairah] menceritakan kepada mereka bahwasanya; Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang janda tidak boleh dinikahi hingga ia dimintai pendapatnya, sedangkan gadis tidak boleh dinikahkan hingga dimintai izinnya.\" Para sahabat bertanya, \"Wahai Rasulullah, seperti apakah izinnya?\" beliau menjawab: \"Bila ia diam tak berkata.\""},"4437":{"ar":"حَدَّثَنَا عَمْرُو بْنُ الرَّبِيعِ بْنِ طَارِقٍ قَالَ أَخْبَرَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أَبِي عَمْرٍو مَوْلَى عَائِشَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ إِنَّ الْبِكْرَ تَسْتَحِي قَالَ رِضَاهَا صَمْتُهَا","id":"Telah menceritakan kepada kami [Amru bin Ar Rabi' bin Thariq] ia berkata; Telah mengabarkan kepada kami [Al Laits] dari [Ibnu Abu Mulaikah] dari [Abu Amru] bekas budak Aisyah, dari [Aisyah] bahwa ia berkata, \"Wahai Rasulullah, sesungguhnya seorang gadis itu pemalu.\" Beliau pun bersabda: \"Keridla`annya adalah diamnya.\""},"4438":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ وَمُجَمِّعٍ ابْنَيْ يَزِيدَ بْنِ جَارِيَةَ عَنْ خَنْسَاءَ بِنْتِ خِذَامٍ الْأَنْصَارِيَّةِأَنَّ أَبَاهَا زَوَّجَهَا وَهْيَ ثَيِّبٌ فَكَرِهَتْ ذَلِكَ فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ نِكَاحَهُحَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا يَحْيَى أَنَّ الْقَاسِمَ بْنَ مُحَمَّدٍ حَدَّثَهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ وَمُجَمِّعَ بْنَ يَزِيدَ حَدَّثَاهُ أَنَّ رَجُلًا يُدْعَى خِذَامًا أَنْكَحَ ابْنَةً لَهُ نَحْوَهُ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Abdurrahman bin Al Qasim] dari [bapaknya] dari [Abdurrahman] dan [Mujammi'] keduanya anak Yazid bin Jaariyah, dari [Khansa` binti Khizam Al Anshariyyah] bahwa bapaknya menikahkannya saat ia janda, lalu ia pun tak suka. Lalu ia pun mendatangi Rasulullah shallallahu 'alaihi wasallam, maka beliau pun menolak pernikahannya. Telah menceritakan kepada kami [Ishaq] Telah mengabarkan kepada kami [Yazid] Telah mengabarkan kepada kami [Yahya] bahwa [Al Qasim bin Muhammad] telah menceritakan kepadanya bahwa [Abdurrahman bin Yazid] dan [Mujammi' bin Yazid] telah menceritakan kepadanya bahwa seorang laki-laki yang biasa dipanggil Khidzam menikahkan seorang anak perempuannya. Yakni semisalnya."},"4439":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ وَقَالَ اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاقَالَ لَهَا يَا أُمَّتَاهْ{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى إِلَى قَوْلِهِ مَا مَلَكَتْ أَيْمَانُكُمْ }قَالَتْ عَائِشَةُ يَا ابْنَ أُخْتِي هَذِهِ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا فَيَرْغَبُ فِي جَمَالِهَا وَمَالِهَا وَيُرِيدُ أَنْ يَنْتَقِصَ مِنْ صَدَاقِهَا فَنُهُوا عَنْ نِكَاحِهِنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ فِي إِكْمَالِ الصَّدَاقِ وَأُمِرُوا بِنِكَاحِ مَنْ سِوَاهُنَّ مِنْ النِّسَاءِ قَالَتْ عَائِشَةُ اسْتَفْتَى النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ فَأَنْزَلَ اللَّهُ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ إِلَى قَوْلِهِ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ لَهُمْ فِي هَذِهِ الْآيَةِ أَنَّ الْيَتِيمَةَ إِذَا كَانَتْ ذَاتَ مَالٍ وَجَمَالٍ رَغِبُوا فِي نِكَاحِهَا وَنَسَبِهَا وَالصَّدَاقِ وَإِذَا كَانَتْ مَرْغُوبًا عَنْهَا فِي قِلَّةِ الْمَالِ وَالْجَمَالِ تَرَكُوهَا وَأَخَذُوا غَيْرَهَا مِنْ النِّسَاءِ قَالَتْ فَكَمَا يَتْرُكُونَهَا حِينَ يَرْغَبُونَ عَنْهَا فَلَيْسَ لَهُمْ أَنْ يَنْكِحُوهَا إِذَا رَغِبُوا فِيهَا إِلَّا أَنْ يُقْسِطُوا لَهَا وَيُعْطُوهَا حَقَّهَا الْأَوْفَى مِنْ الصَّدَاقِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dan telah berkata [Al Laits] Telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] Telah mengabarkan kepadaku [Urwah bin Zubair] bahwa ia pernah bertanya kepada Aisyah radliallahu 'anha, ia berkata padanya, \"Wahai Ummul Mukminin apakah maksud firman-Nya, 'WA IN KHIFTUM ALLAA TUQSITHUU FIL YATAAMAA..' hingga firman-Nya, 'MAA MALAKAT AIMAANUKUM.'\" [Aisyah] berkata, \"Wahai anak saudaraku, hal ini terkait dengan anak perempuan Yatim yang berada dalam asuhan walinya, lalu sang wali pun tertarik pada kecantikan dan juga hartanya, namun ia ingin mengurangi maharnya. Lalu mereka dilarang untuk menikahi mereka kecuali dengan berlaku adil dan menyempurnakan maharnya, sehingga mereka pun diperintahkan untuk menikahi wanita-wanita lain.\" Aisyah berkata lagi, \"Setelah itu, orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam, maka Allah menurunkan ayat, 'WA YASTAFTUUNAKA FIN NISAA`..' hingga firman-Nya, 'WA TARGHABUUNA AN TANKIHUUHUNNA.' Maka di dalam ayat ini Allah menurunkan bahwa, seorang perempuan yatim itu memiliki harta, dan kecantikan, mereka pun ingin menikahinya, menginginkan nasabnya dan juga maharnya. Namun bila mereka tidak menyukai wanita itu lantaran tak mempunyai hal itu, mereka pun meninggalkan dan menikahi wanita lain.\" Aisyah melanjutkan, \"Sebagaimana mereka meninggalkan mereka ketika mereka tak menyukainya, maka mereka tidak boleh menikahinya saat mereka ingin, kecuali dengan berbuat adil pada mereka dan memberikan haknya yang cukup sebagai mahar.\""},"4440":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ امْرَأَةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَضَتْ عَلَيْهِ نَفْسَهَا فَقَالَ مَا لِي الْيَوْمَ فِي النِّسَاءِ مِنْ حَاجَةٍ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ زَوِّجْنِيهَا قَالَ مَا عِنْدَكَ قَالَ مَا عِنْدِي شَيْءٌ قَالَ أَعْطِهَا وَلَوْ خَاتَمًا مِنْ حَدِيدٍ قَالَ مَا عِنْدِي شَيْءٌ قَالَ فَمَا عِنْدَكَ مِنْ الْقُرْآنِ قَالَ كَذَا وَكَذَا قَالَ فَقَدْ مَلَّكْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Hazim] dari [Sahl bin Sa'dari] radliallahu 'anhu, bahwa seorang wanita mendatangi Nabi shallallahu 'alaihi wasallam dan menawarkan dirinya pada beliau, maka beliau pun bersabda: \"Hari ini aku tak berhasrat pada wanita.\" Tiba-tiba seorang laki-laki berkata, \"Wahai Rasulullah, nikahkanlah aku dengannya.\" Maka beliau bertanya: \"Apa yang kamu miliki (untuk dijadikan sebagai mahar)?\" ia menjawab, \"Aku tidak punya apa-apa.\" Beliau bersabda: \"Berikanlan ia (mahar) meskipun hanya cincin besi.\" Laki-laki itu berkata, \"Aku tak punya apa-apa.\" Akhirnya beliau bertanya: \"Apa yang kamu hafal dari Al Qur`an?\" laki-laki itu menjawab, \"Surat ini dan ini.\" Beliau bersabda: \"Aku telah menikahkanmu dengan wanita itu dan sebagai maharnya adalah hafalan Al Qur`anmu.\""},"4441":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ نَافِعًا يُحَدِّثُ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا كَانَ يَقُولُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا يَخْطُبَ الرَّجُلُ عَلَى خِطْبَةِ أَخِيهِ حَتَّى يَتْرُكَ الْخَاطِبُ قَبْلَهُ أَوْ يَأْذَنَ لَهُ الْخَاطِبُ","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] Telah menceritakan kepada kami [Ibnu Juraij] ia berkata, Aku mendengar [Nafi'] menceritakan bahwa [Ibnu Umar] radliallahu 'anhuma berkata, \"Nabi shallallahu 'alaihi wasallam telah melarang sebagian kalian untuk berjual beli atas jual beli saudaranya. Dan janganlah seseorang meminang atas pinangan yang lain hingga ia meninggalkannya atau pun menerimanya, atau pun ia telah diberi izin oleh sang peminang pertama.\""},"4442":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ قَالَ قَالَ أَبُو هُرَيْرَةَيَأْثُرُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالظَّنَّ فَإِنَّ الظَّنَّ أَكْذَبُ الْحَدِيثِ وَلَا تَجَسَّسُوا وَلَا تَحَسَّسُوا وَلَا تَبَاغَضُوا وَكُونُوا إِخْوَانًا وَلَا يَخْطُبُ الرَّجُلُ عَلَى خِطْبَةِ أَخِيهِ حَتَّى يَنْكِحَ أَوْ يَتْرُكَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Al A'raj] ia berkata; [Abu Hurairah] berkata; Satu warisan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jauhilah oleh kalian perasangka, sebab perasangka itu adalah ungkapan yang paling dusta. Dan janganlah kalian mencari-cari aib orang lain, jangan pula saling menebar kebencian dan jadilah kalian orang-orang yang bersaudara. Janganlah seorang laki-laki meminang atas pinangan saudaranya hingga ia menikahinya atau meninggalkannya.\""},"4443":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يُحَدِّثُأَنَّ عُمَرَ بْنَ الْخَطَّابِ حِينَ تَأَيَّمَتْ حَفْصَةُ قَالَ عُمَرُ لَقِيتُ أَبَا بَكْرٍ فَقُلْتُ إِنْ شِئْتَ أَنْكَحْتُكَ حَفْصَةَ بِنْتَ عُمَرَ فَلَبِثْتُ لَيَالِيَ ثُمَّ خَطَبَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيَنِي أَبُو بَكْرٍ فَقَالَ إِنَّهُ لَمْ يَمْنَعْنِي أَنْ أَرْجِعَ إِلَيْكَ فِيمَا عَرَضْتَ إِلَّا أَنِّي قَدْ عَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ ذَكَرَهَا فَلَمْ أَكُنْ لِأُفْشِيَ سِرَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ تَرَكَهَا لَقَبِلْتُهَاتَابَعَهُ يُونُسُ وَمُوسَى بْنُ عُقْبَةَ وَابْنُ أَبِي عَتِيقٍ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Salim bin Abdullah] bahwa ia mendengar [Abdullah bin Umar] radliallahu 'anhuma menceritakan bahwasanya; Ketika Hafshah binti Umar bin Al Khaththab menjadi janda, Umar berkata; Aku mendatangi Abu Bakar dan berkata padanya, \"Jika kamu mau, maka aku akan menikahkanmu dengan Hafshah binti Umar.\" Sesudah itu, aku pun menunggu beberapa malam, hingga kemudian Rasulullah shallallahu 'alaihi wasallam meminang Hafshah. Setelah itu Abu Bakar menemuiku dan berkata, \"Sesungguhnya tidak ada yang menghalangiku untuk kembali menemuimu dan menerima tawaranmu kecuali, selain karena aku tahu bahwa Rasulullah shallallahu 'alaihi wasallam pernah menyebutnya, dan aku tidak mau membuka rahasia dari Rasulullah shallallahu 'alaihi wasallam, kalau beliau meninggalkannya niscaya aku akan menerimanya sebagai isteri.\" Hadis ini diperkuat oleh [Yunus], [Musa bin Utbah] dan [Ibnu Abu 'Atiq], dari [Az Zuhri]."},"4444":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُجَاءَ رَجُلَانِ مِنْ الْمَشْرِقِ فَخَطَبَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْبَيَانِ لَسِحْرًا","id":"Telah menceritakan kepada kami [Qabishah] Telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] ia berkata; Aku mendengar [Ibnu Umar] berkata; Ada dua orang laki-laki dari Masyriq, lalu keduanya pun berkhuthbah. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Diantara lafadz yang indah terdapat apa yang disebut sihir.\""},"4445":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا خَالِدُ بْنُ ذَكْوَانَ قَالَ قَالَتْ الرُّبَيِّعُ بِنْتُ مُعَوِّذِ بْنِ عَفْرَاءَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ حِينَ بُنِيَ عَلَيَّ فَجَلَسَ عَلَى فِرَاشِي كَمَجْلِسِكَ مِنِّي فَجَعَلَتْ جُوَيْرِيَاتٌ لَنَا يَضْرِبْنَ بِالدُّفِّ وَيَنْدُبْنَ مَنْ قُتِلَ مِنْ آبَائِي يَوْمَ بَدْرٍ إِذْ قَالَتْ إِحْدَاهُنَّ وَفِينَا نَبِيٌّ يَعْلَمُ مَا فِي غَدٍ فَقَالَ دَعِي هَذِهِ وَقُولِي بِالَّذِي كُنْتِ تَقُولِينَ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] Telah menceritakan kepada kami [Khalid bin Dzakwan] ia berkata; [Ar Rubayyi' binti Mu'awwidz bin 'Afran] berkata; suatu ketika, Nabi shallallahu 'alaihi wasallam dan masuk saat aku membangun mahligai rumah tangga (menikah). Lalu beliau duduk di atas kasurku, sebagaimana posisi dudukmu dariku. Kemudian para budak-budak wanita pun memukul rebana dan mengenang keistimewaan-keistimewaan prajurit yang gugur pada saat perang Badar. Lalu salah seorang dari mereka pun berkata, \"Dan di tengah-tengah kita ada seorang Nabi, yang mengetahui apa yang akan terjadi esok hari.\" Maka beliau bersabda: \"Tinggalkanlah ungkapan ini, dan katakanlah apa yang ingin kamu katakan.\""},"4446":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍأَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ تَزَوَّجَ امْرَأَةً عَلَى وَزْنِ نَوَاةٍ فَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشَاشَةَ الْعُرْسِ فَسَأَلَهُ فَقَالَ إِنِّي تَزَوَّجْتُ امْرَأَةً عَلَى وَزْنِ نَوَاةٍوَعَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ تَزَوَّجَ امْرَأَةً عَلَى وَزْنِ نَوَاةٍ مِنْ ذَهَبٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Abdul Aziz bin Shuhaib] dari [Anas] bahwa Abdurrahman bin Auf menikahi seorang wanita dengan mahar berupa Wazn Nawat (butiran emas), lalu Nabi shallallahu 'alaihi wasallam menyaksikan pesta walimahan yang penuh keceriaan, maka Abdurrahman pun berkata, \"Sesungguhnya aku telah menikahi seorang wanita dengan mahar satu ons emas.\" Dan dari [Qatadah] dari [Anas] bahwasanya; Abdurrahman bin Auf menikahi seorang wanita dengan mahar satu ons emas."},"4447":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ سَمِعْتُ أَبَا حَازِمٍ يَقُولُ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ يَقُولُإِنِّي لَفِي الْقَوْمِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ قَامَتْ امْرَأَةٌ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ وَهَبَتْ نَفْسَهَا لَكَ فَرَ فِيهَا رَأْيَكَ فَلَمْ يُجِبْهَا شَيْئًا ثُمَّ قَامَتْ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ وَهَبَتْ نَفْسَهَا لَكَ فَرَ فِيهَا رَأْيَكَ فَلَمْ يُجِبْهَا شَيْئًا ثُمَّ قَامَتْ الثَّالِثَةَ فَقَالَتْ إِنَّهَا قَدْ وَهَبَتْ نَفْسَهَا لَكَ فَرَ فِيهَا رَأْيَكَ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَنْكِحْنِيهَا قَالَ هَلْ عِنْدَكَ مِنْ شَيْءٍ قَالَ لَا قَالَ اذْهَبْ فَاطْلُبْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ فَطَلَبَ ثُمَّ جَاءَ فَقَالَ مَا وَجَدْتُ شَيْئًا وَلَا خَاتَمًا مِنْ حَدِيدٍ فَقَالَ هَلْ مَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ مَعِي سُورَةُ كَذَا وَسُورَةُ كَذَا قَالَ اذْهَبْ فَقَدْ أَنْكَحْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Aku mendengar [Abu Hazim] berkata; Aku mendengar [Sahl bin Sa'd As Sa'idi] berkata; Aku pernah berada di tengah-tengah suatu kaum yang tengah berada di sisi Rasulullah shallallahu 'alaihi wasallam, tiba-tiba berdirilah seorang wanita seraya berkata, \"Wahai Rasulullah, sesungguhnya ia telah menyerahkan dirinya untuk Anda, karena itu berilah keputusan padanya.\" Namun beliau tidak memberi jawaban apa pun, kemudian wanita itu pun berdiri dan berkata lagi, \"Wahai Rasulullah, sesungguh ia telah menyerahkan dirinya untuk Anda, karena itu berilah putusan padanya.\" Ternyata ia belum juga memberi putusan apa-apa. Kemudian wanita itu berdiri lagi pada kali yang ketiga seraya berkata, \"Wahai Rasulullah, sesungguhnya ia telah menyerahkan dirinya untuk Anda, karena itu berilah keputusan padanya.\" Maka berdirilah seorang laki-laki dan berkata, \"Wahai Rasulullah, nikahkanlah aku dengannya.\" Beliau pun bertanya: \"Apakah kamu memiliki sesuatu (untuk dijadikan mahar)?\" laki-laki itu menjawab, \"Tidak.\" Beliau bersabda: \"Pergi dan carilah sesuatu meskipun hanya cincin dari emas.\" Kemudian laki-laki itu pergi dan mencari sesuatu untuk mahar, kemudian ia kembali lagi dan berkata, \"Aku tidak mendapatkan apa-apa, meskipun hanya cincin dari emas.\" Lalu beliau bertanya: \"Apakah kamu mempunyai hafalan Al Qur`an?\" laki-laki itu menjawab, \"Ya, aku hafal surat ini dan ini.\" Akhirnya beliau bersabda: \"Pergilah, telah menikahkanmu dengan wanita itu dan maharnya adalah hafalan Al Qur`anmu.\""},"4448":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ تَزَوَّجْ وَلَوْ بِخَاتَمٍ مِنْ حَدِيدٍ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwasanya; Nabi shallallahu 'alaihi wasallam bersabda kepada seseorang: \"Menikahlah meskipun maharnya hanya dengan cincin besi.\""},"4449":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحَقُّ مَا أَوْفَيْتُمْ مِنْ الشُّرُوطِ أَنْ تُوفُوا بِهِ مَا اسْتَحْلَلْتُمْ بِهِ الْفُرُوجَ","id":"Telah menceritakan kepada kami [Abul Walid Hisyam bin Abdul Malik] Telah menceritakan kepada kami [Laits] dari [Yazid bin Abu Habib] dari [Abul Khair] dari [Uqbah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Syarat yang paling berhak untuk kalian penuhi adalah, syarat yang dengannya farji dihalalkan (menikah).\""},"4450":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ زَكَرِيَّاءَ هُوَ ابْنُ أَبِي زَائِدَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تَسْأَلُ طَلَاقَ أُخْتِهَا لِتَسْتَفْرِغَ صَحْفَتَهَا فَإِنَّمَا لَهَا مَا قُدِّرَ لَهَا","id":"Telah menceritakan kepada kami [Abdullah bin Musa] dari [Zakariya] ia adalah Ibnu Abu Za`idah, dari [Sa'd bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seorang wanita untuk meminta agar saudaranya semadunya untuk diceraikan dengan maksud agar nafkahnya lebih banyak. Sesungguhnya baginya adalah apa yang telah ditakdirkan untuknya.\""},"4451":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِهِ أَثَرُ صُفْرَةٍ فَسَأَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ أَنَّهُ تَزَوَّجَ امْرَأَةً مِنْ الْأَنْصَارِ قَالَ كَمْ سُقْتَ إِلَيْهَا قَالَ زِنَةَ نَوَاةٍ مِنْ ذَهَبٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Humaid Ath Thawil] dari [Anas bin Malik] radliallahu 'anhu, bahwasnya; Abdurrahman bin Auf datang kepada Rasulullah shallallahu 'alaihi wasallam sementara pada dirinya masih terdapat bekas-bekas warna kuning minyak wangi, maka Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya, ia pun memberitahu bahwa ia telah menikahi seorang wanita dari Anshar. Beliau bertanya: \"Seberapa mahar yang kamu berikan?\" Abdurrahman menjawab, \"satu ons emas.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adakanlah walimah meskipun dengan seekor kambing.\""},"4452":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَأَوْلَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَيْنَبَ فَأَوْسَعَ الْمُسْلِمِينَ خَيْرًا فَخَرَجَ كَمَا يَصْنَعُ إِذَا تَزَوَّجَ فَأَتَى حُجَرَ أُمَّهَاتِ الْمُؤْمِنِينَ يَدْعُو وَيَدْعُونَ لَهُ ثُمَّ انْصَرَفَ فَرَأَى رَجُلَيْنِ فَرَجَعَ لَا أَدْرِي آخْبَرْتُهُ أَوْ أُخْبِرَ بِخُرُوجِهِمَا","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Humaid] dari [Anas] ia berkata; Nabi shallallahu 'alaihi wasallam mengadakan walimah saat menikahi Zainab, dan beliau menebar kebaikan untuk keum muslimin. Beliau keluar sebagaimana yang beliau lakukan bila beliau menikah. Beliau mendatangi rumah isteri-isterinya Ummahatul Mukminin, beliau mengajak dan mereka pun mengundang orang lain. Setelah itu beliau beranjak, lalu melihat dua orang, lalu kembali lagi, aku tidak tahu apakah aku yang memberitahukan, ataukah beliau diberitahui kepergian dua orang itu."},"4453":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَثَرَ صُفْرَةٍ قَالَ مَا هَذَا قَالَ إِنِّي تَزَوَّجْتُ امْرَأَةً عَلَى وَزْنِ نَوَاةٍ مِنْ ذَهَبٍ قَالَ بَارَكَ اللَّهُ لَكَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad] ia adalah Ibnu Zaid, dari [Tsabit] dari [Anas] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam melihat bekas Shufr pada Abdurrahman bin Auf, maka beliau pun bertanya: \"Apa ini?\" ia menjawab, \"Sesungguhnya aku telah menikahi seorang wanita dengan mahar Wazn Nawat dari emas.\" Beliau besabda: \"Semoga Allah memberkahimu. Adakanlah walimah meskipun dengan seekor kambing.\""},"4454":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاتَزَوَّجَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَتْنِي أُمِّي فَأَدْخَلَتْنِي الدَّارَ فَإِذَا نِسْوَةٌ مِنْ الْأَنْصَارِ فِي الْبَيْتِ فَقُلْنَ عَلَى الْخَيْرِ وَالْبَرَكَةِ وَعَلَى خَيْرِ طَائِرٍ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra`] Telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, Ia berkata; Nabi shallallahu 'alaihi wasallam menikahiku, lalu ibuku pun mendatangiku dan memasukkanku ke dalam rumah, ternyata di dalam ada beberapa kaum wanita dari Anshar. Mereka mendo'akan kebaikan dan keberkahan dan semoga selalu berada di atas kebaikan selamanya."},"4455":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غَزَا نَبِيٌّ مِنْ الْأَنْبِيَاءِ فَقَالَ لِقَوْمِهِ لَا يَتْبَعْنِي رَجُلٌ مَلَكَ بُضْعَ امْرَأَةٍ وَهُوَ يُرِيدُ أَنْ يَبْنِيَ بِهَا وَلَمْ يَبْنِ بِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] Telah menceritakan kepada kami [Abdullah bin Mubarak] dari [Ma'mar] dari [Hammam] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ada seorang Nabi berperang, lalu ia berkata pada kaumnya, 'Jangan mengikutiku seorang laki-laki yang telah memiliki kesempatan untuk berhubungan dengan isterinya, yang ia telah ingin mengajaknya berumah tangga namun belum kesampaian.\" "},"4456":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَتَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِشَةَ وَهِيَ بِنْتُ سِتِّ سِنِينَ وَبَنَى بِهَا وَهِيَ بِنْتُ تِسْعٍ وَمَكَثَتْ عِنْدَهُ تِسْعًا","id":"Telah menceritakan kepada kami [Qabishah bin Utbah] Telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Urwah] dari [Urwah] bahwasnya; \"Nabi shallallahu 'alaihi wasallam menikahi Aisyah saat ia berumur enam tahun, kemudian beliau hidup bersama dengannya (menggaulinya) saat berumur sembilan tahun. Dan Aisyah hidup bersama Rasulullah shallallahu 'alaihi wasallam juga selama sembilan tahun.\""},"4457":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَأَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ خَيْبَرَ وَالْمَدِينَةِ ثَلَاثًا يُبْنَى عَلَيْهِ بِصَفِيَّةَ بِنْتِ حُيَيٍّ فَدَعَوْتُ الْمُسْلِمِينَ إِلَى وَلِيمَتِهِ فَمَا كَانَ فِيهَا مِنْ خُبْزٍ وَلَا لَحْمٍ أَمَرَ بِالْأَنْطَاعِ فَأُلْقِيَ فِيهَا مِنْ التَّمْرِ وَالْأَقِطِ وَالسَّمْنِ فَكَانَتْ وَلِيمَتَهُ فَقَالَ الْمُسْلِمُونَ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ أَوْ مِمَّا مَلَكَتْ يَمِينُهُ فَقَالُوا إِنْ حَجَبَهَا فَهِيَ مِنْ أُمَّهَاتِ الْمُؤْمِنِينَ وَإِنْ لَمْ يَحْجُبْهَا فَهِيَ مِمَّا مَلَكَتْ يَمِينُهُ فَلَمَّا ارْتَحَلَ وَطَّى لَهَا خَلْفَهُ وَمَدَّ الْحِجَابَ بَيْنَهَا وَبَيْنَ النَّاسِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] Telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bermukim tiga hari antara Khaibar dan Madinah yaitu ketika menikahi Shafiyyah binti Huyyi. Lalu aku pun mengundang kaum muslimin untuk menghadiri walimahnya. Di dalam walimahan itu tidak ada roti dan tidak pula daging. Beliau menyuruh agar permadani kulit dihamparkan, lalu kurma, tepung dan keju dihidangkan. Seperti itulah walimahnya. Kemudian kaum muslimin bertanya, \"Ia adalah ummahatul Mukminin ataukah hamba sahaya?.\" Dan mereka pun berkata, \"Jika beliau menghijabinya, maka ia termasuk Ummatul Mukminin, dan bila tidak, maka ia adalah hamba sahaya.\" Maka pada saat berangkat, beliau meletakkannya agak rendah di belakang, lalu beliau membentangkan hijab yang menutupi antara dirinya dengan orang banyak."},"4458":{"ar":"حَدَّثَنِي فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْتَزَوَّجَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَتْنِي أُمِّي فَأَدْخَلَتْنِي الدَّارَ فَلَمْ يَرُعْنِي إِلَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضُحًى","id":"Telah menceritakan kepadaku [Farwah bin Abu Al Maghra`] Telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, ia berkata; Nabi shallallahu 'alaihi wasallam menikahiku. Kemudian aku didatangi oleh ibuku, lalu ia memasukkanku ke dalam rumah, tidak ada yang membuatku merasa terharu kecuali Rasulullah shallallahu 'alaihi wasallam di waktu Dluha."},"4459":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ اتَّخَذْتُمْ أَنْمَاطًا قُلْتُ يَا رَسُولَ اللَّهِ وَأَنَّى لَنَا أَنْمَاطٌ قَالَ إِنَّهَا سَتَكُونُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] radliallahu 'anhuma, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian menyediakan permadani?\" Aku pun berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam dari mana kami mendapatkan permadani?\" beliau bersabda: \"Sesungguhnya nanti hal itu akan terjadi.\""},"4460":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ يَعْقُوبَ حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّهَا زَفَّتْ امْرَأَةً إِلَى رَجُلٍ مِنْ الْأَنْصَارِ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَائِشَةُ مَا كَانَ مَعَكُمْ لَهْوٌ فَإِنَّ الْأَنْصَارَ يُعْجِبُهُمْ اللَّهْوُ","id":"Telah menceritakan kepada kami [Al Fadllu bin Ya'qub] Telah menceritakan kepada kami [Muhammad bin Sabiq] Telah menceritakan kepada kami [Isra'il] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] bahwa ia menyerahkan pengantin wanita kepada seorang laki-laki dari kalangan Anshar. Kemudian Nabi shallallahu 'alaihi wasallam pun bersabda: \"Wahai Aisyah, apakah tidak ada hiburan, sebab orang-orang Anshar senang akan hiburan?.\""},"4461":{"ar":"حَدَّثَنِي عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا اسْتَعَارَتْ مِنْ أَسْمَاءَ قِلَادَةً فَهَلَكَتْ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاسًا مِنْ أَصْحَابِهِ فِي طَلَبِهَا فَأَدْرَكَتْهُمْ الصَّلَاةُ فَصَلَّوْا بِغَيْرِ وُضُوءٍ فَلَمَّا أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَكَوْا ذَلِكَ إِلَيْهِ فَنَزَلَتْ آيَةُ التَّيَمُّمِ فَقَالَ أُسَيْدُ بْنُ حُضَيْرٍ جَزَاكِ اللَّهُ خَيْرًا فَوَاللَّهِ مَا نَزَلَ بِكِ أَمْرٌ قَطُّ إِلَّا جَعَلَ اللَّهُ لَكِ مِنْهُ مَخْرَجًا وَجُعِلَ لِلْمُسْلِمِينَ فِيهِ بَرَكَةٌ","id":"Telah menceritakan kepadaku [Ubaid bin Isma'il] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, bahwa ia pernah meminjam kalung dari Asma`, lalu kalung itu pun hilang. Maka Rasulullah shallallahu 'alaihi wasallam mengutus beberapa orang dari sahabatnya untuk mencari kalung tersebut. Lalu waktu shalat pun tiba, akhirnya mereka shalat tanpa berwudlu terlebih dahulu. Ketika mereka menemui Nabi shallallahu 'alaihi wasallam, mereka pun mengadukannya. Maka turunlah ayat Tayammum. Karena itu, Usaid bin Hudlair berkata kepada Aisyah, \"Semoga Allah membalasmu dengan kebaikan. Demi Allah, tidak ada suatu perkara pun yang menimpa Anda, kecuali Allah menciptakan jalan keluar pula bagi Anda, lalu kaum muslimin pun mendapat barakah dari perkara itu.\""},"4462":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا لَوْ أَنَّ أَحَدَهُمْ يَقُولُ حِينَ يَأْتِي أَهْلَهُ بِاسْمِ اللَّهِ اللَّهُمَّ جَنِّبْنِي الشَّيْطَانَ وَجَنِّبْ الشَّيْطَانَ مَا رَزَقْتَنَا ثُمَّ قُدِّرَ بَيْنَهُمَا فِي ذَلِكَ أَوْ قُضِيَ وَلَدٌ لَمْ يَضُرَّهُ شَيْطَانٌ أَبَدًا","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] Telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Salim bin Abul Ja'd] dari [Kuraib] dari [Ibnu Abbas] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya saat mereka mendatangi isterinya membaca: 'BISMILLAHI ALLAHUMMA JANNIBNISY SYAITHAANA WA JANNIBISY SYAITHAANA MA RAZAQTANAA.' Lalu mereka pun ditakdirkan mendapat keturunan dari hasil pergaulan itu, atau mereka dikaruniyai anak, maka ia tidak akan diganggu oleh syetan selama-lamanya.\""},"4463":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ كَانَ ابْنَ عَشْرِ سِنِينَ مَقْدَمَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَكَانَ أُمَّهَاتِي يُوَاظِبْنَنِي عَلَى خِدْمَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَدَمْتُهُ عَشْرَ سِنِينَ وَتُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا ابْنُ عِشْرِينَ سَنَةً فَكُنْتُ أَعْلَمَ النَّاسِ بِشَأْنِ الْحِجَابِ حِينَ أُنْزِلَ وَكَانَ أَوَّلَ مَا أُنْزِلَ فِي مُبْتَنَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَيْنَبَ بِنْتِ جَحْشٍ أَصْبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَا عَرُوسًا فَدَعَا الْقَوْمَ فَأَصَابُوا مِنْ الطَّعَامِ ثُمَّ خَرَجُوا وَبَقِيَ رَهْطٌ مِنْهُمْ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَطَالُوا الْمُكْثَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ وَخَرَجْتُ مَعَهُ لِكَيْ يَخْرُجُوا فَمَشَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَشَيْتُ حَتَّى جَاءَ عَتَبَةَ حُجْرَةِ عَائِشَةَ ثُمَّ ظَنَّ أَنَّهُمْ خَرَجُوا فَرَجَعَ وَرَجَعْتُ مَعَهُ حَتَّى إِذَا دَخَلَ عَلَى زَيْنَبَ فَإِذَا هُمْ جُلُوسٌ لَمْ يَقُومُوا فَرَجَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَعْتُ مَعَهُ حَتَّى إِذَا بَلَغَ عَتَبَةَ حُجْرَةِ عَائِشَةَ وَظَنَّ أَنَّهُمْ خَرَجُوا فَرَجَعَ وَرَجَعْتُ مَعَهُ فَإِذَا هُمْ قَدْ خَرَجُوا فَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنِي وَبَيْنَهُ بِالسِّتْرِ وَأُنْزِلَ الْحِجَابُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] ia berkata; Telah menceritakan kepadaku [Al Laits] dari [Uqail] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Anas bin Malik] radliallahu 'anhu bahwasanya; Saat Rasulullah shallallahu 'alaihi wasallam datang di Madinah, ia masih anak-anak usia sepuluh tahun. Ia mengkisahkan; ibuku menyuruhku untuk berkhidmat kepada Nabi shallallahu 'alaihi wasallam. Maka aku pun berkhidmat untuk beliau selama sepuluh tahun, maka saat Nabi shallallahu 'alaihi wasallam wafat aku adalah pemuda yang telah berumur dua puluh tahun. Akulah orang yang paling mengerti tentang hijab saat perintah itu diturunkan. Itu adalah perintah yang pertama kali turun pada pernikahan Rasulullah shallallahu 'alaihi wasallam dengan Zainab binti Jahsyin. Saat itu Rasulullah shallallahu 'alaihi wasallam mengadakan walimah, beliau mengundang orang-orang dan mereka pun menikmati makanan yang dihidangkan. Setelah itu, mereka pun keluar pergi, kecuali beberapa orang yang masih tetap berada di sisi Rasulullah shallallahu 'alaihi wasallam, mereka memperlama duduk di situ. Maka Nabi shallallahu 'alaihi wasallam pun beranjak dan keluar, lalu aku pun ikut keluar bersama beliau agar orang-orang itu juga ikut keluar. Kemudian Nabi shallallahu 'alaihi wasallam berjalan, dan aku juga ikut berjalan hingga sampai di ambang pintu rumah Aisyah. Lalu beliau mengira, bahwa mereka yang duduk tadi telah keluar, maka beliau pun kembali lagi dan aku juga ikut kembali hingga beliau sampai di tempat Zainab, dan ternyata orang-orang itu masih ada di situ dan belum beranjak. Akhirnya Nabi shallallahu 'alaihi wasallam pun kembali lagi dan aku juga ikut kembali bersamanya. Dan ketika sampai di ambang pintu Aisyah, beliau menduga bahwa mereka pasti sudah pergi, maka beliau kembali lagi dan aku juga ikut kembali bersama beliau, dan ternyata orang-orang itu sudak keluar pergi, maka Nabi shallallahu 'alaihi wasallam meletakkan pembatas antara aku dan beliau, maka saat itu diturunkan perintah Hijab."},"4464":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي حُمَيْدٌ أَنَّهُ سَمِعَ أَنَسًا رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ وَتَزَوَّجَ امْرَأَةً مِنْ الْأَنْصَارِ كَمْ أَصْدَقْتَهَا قَالَ وَزْنَ نَوَاةٍ مِنْ ذَهَبٍوَعَنْ حُمَيْدٍ سَمِعْتُ أَنَسًا قَالَ لَمَّا قَدِمُوا الْمَدِينَةَ نَزَلَ الْمُهَاجِرُونَ عَلَى الْأَنْصَارِ فَنَزَلَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ عَلَى سَعْدِ بْنِ الرَّبِيعِ فَقَالَ أُقَاسِمُكَ مَالِي وَأَنْزِلُ لَكَ عَنْ إِحْدَى امْرَأَتَيَّ قَالَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ فَخَرَجَ إِلَى السُّوقِ فَبَاعَ وَاشْتَرَى فَأَصَابَ شَيْئًا مِنْ أَقِطٍ وَسَمْنٍ فَتَزَوَّجَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Ali] Telah menceritakan kepada kami [Sufyan] ia berkata; Telah menceritakan kepadaku [Humaid] bahwa ia mendengar [Anas] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam pernah bertanya kepada Abdurrahman bin Auf saat ia menikahi seorang wanita Anshriyah, \"Berapa mahar kamu berikan padanya?\" ia pun menjawab, \"Seukuran biji berupa emas.\" Dan dari Humaid; Aku mendengar Anas berkata; Ketika mereka sampai di kota Madinah, kaum Muhajirin pun singgah di tepat kediaman orang-orang Anshar. Lalu Abdurrahman bin Auf tinggal di kediaman Sa'd bin Ar Rabi'. Sa'd bin Rabi' pun berkata padanya, \"Aku akan membagi hartaku kepadaku dan menikahkanmu dengan salah seorang isteriku.\" Abdurrahman berkata, \"Semoga Allah memberi keberkahan pada keluarga dan juga hartamu.\" Lalu ia pun keluar menuju pasar dan berjual beli hingga ia mendapatkan keuntungan berupa keju dan samin, dan ia pun, menikah. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Adakanlah walimah meskipun hanya dengan seekor kambing.\""},"4465":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَمَا أَوْلَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى شَيْءٍ مِنْ نِسَائِهِ مَا أَوْلَمَ عَلَى زَيْنَبَ أَوْلَمَ بِشَاةٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas] ia berkata; Nabi shallallahu 'alaihi wasallam tidak pernah mengadakan walimah terhadap seorang pun dari isteri-isterinya sebagaimana walimah yang beliau adakan atas pernikahannya dengan Zainab. Saat itu, beliau mengadakan walimah dengan seekor kambing."},"4466":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ شُعَيْبٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَ صَفِيَّةَ وَتَزَوَّجَهَا وَجَعَلَ عِتْقَهَا صَدَاقَهَا وَأَوْلَمَ عَلَيْهَا بِحَيْسٍ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Abdul Warits] dari [Syu'aib] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam membebaskan Shafiyya lalu beliau menikahinya, dan beliau menjadikan pembebasannya itu sebagai maharnya. Kemudian beliau mengadakan walimah dengan Hais (sejenis makanan dengan bahan kurma, tepung dan samin)."},"4467":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا زُهَيْرٌ عَنْ بَيَانٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُبَنَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِامْرَأَةٍ فَأَرْسَلَنِي فَدَعَوْتُ رِجَالًا إِلَى الطَّعَامِ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] Telah menceritakan kepada kami [Zuhair] dari [Bayan] ia berkata; Aku mendengar [Anas] berkata; \"Nabi shallallahu 'alaihi wasallam menikahi seorang wanita, lalu beliau mengutusku hingga aku pun mengundang beberapa orang untuk makan-makan.\""},"4468":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ قَالَ ذُكِرَتَزْوِيجُ زَيْنَبَ بِنْتِ جَحْشٍ عِنْدَ أَنَسٍ فَقَالَ مَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلَمَ عَلَى أَحَدٍ مِنْ نِسَائِهِ مَا أَوْلَمَ عَلَيْهَا أَوْلَمَ بِشَاةٍ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] ia berkata; Suatu ketika, pernah disebutkan mengenai perkawinan Zainab binti Jahsyi di hadapan [Anas], maka ia pun berkata, \"Aku belum pernah melihat Rasulullah shallallahu 'alaihi wasallam mengadakan walimah terhadap seorang pun dari para isteri-isterinya sebagaimana walimah yang beliau adakan terhadapnya. Saat itu, beliau mengadakan walimah dengan seekor kambing.\""},"4469":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورِ بْنِ صَفِيَّةَ عَنْ أُمِّهِ صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْأَوْلَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَعْضِ نِسَائِهِ بِمُدَّيْنِ مِنْ شَعِيرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Manshur bin Shafiyyah] dari [Ibunya Shafiyyah binti Syaibah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengadakan walimah terhadap sebagian dari isteri-isterinya, yakni dengan dua Mud gandum."},"4470":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دُعِيَ أَحَدُكُمْ إِلَى الْوَلِيمَةِ فَلْيَأْتِهَا","id":"Telah menceritakan kepada kami [Abdullah bih Yusuf] Telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian diundang ke acara walimahan, hendaklah ia datang.\""},"4471":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فُكُّوا الْعَانِيَ وَأَجِيبُوا الدَّاعِيَ وَعُودُوا الْمَرِيضَ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Sufyan] ia berkata; Telah menceritakan kepadaku [Manshur] dari [Abu Wa`il] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Lepaskanlah tawanan, penuhilah undangan dan jenguklah orang sakit.\""},"4472":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَشْعَثِ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدٍ قَالَ الْبَرَاءُ بْنُ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَاأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ أَمَرَنَا بِعِيَادَةِ الْمَرِيضِ وَاتِّبَاعِ الْجِنَازَةِ وَتَشْمِيتِ الْعَاطِسِ وَإِبْرَارِ الْقَسَمِ وَنَصْرِ الْمَظْلُومِ وَإِفْشَاءِ السَّلَامِ وَإِجَابَةِ الدَّاعِي وَنَهَانَا عَنْ خَوَاتِيمِ الذَّهَبِ وَعَنْ آنِيَةِ الْفِضَّةِ وَعَنْ الْمَيَاثِرِ وَالْقَسِّيَّةِ وَالْإِسْتَبْرَقِ وَالدِّيبَاجِتَابَعَهُ أَبُو عَوَانَةَ وَالشَّيْبَانِيُّ عَنْ أَشْعَثَ فِي إِفْشَاءِ السَّلَامِ","id":"Telah menceritakan kepada kami [Al Hasan bin Rabi'] Telah menceritakan kepada kami [Abul Ahwash] dari [Al Asy'ats] dari [Mu'awiyah bin Suwaid] bahwa [Al Bara` bin Azib] radliallahu 'anhuma berkata; Nabi shallallahu 'alaihi wasallam telah memerintahkan kami tujuh perkara dan juga melarang kami dari tujuh perkara. Beliau memerintahkan kami untuk menjenguk orang sakit, mengantar jenazah, menjawab orang yang bersin, menunaikan sumpah, menolong orang yang terzhalimi, menebarkan salam dan memenuhi undangan. Kemudian beliau melarang kami untuk mengenakan cincin emas, memakai bejana perak, mencabut uban, mengenakan Al Qassiyyah (pakaian yang bercampur dengan bahan sutera), Al Istibraq (kain yang dilapisi dengan bahan sutera) dan Ad Diibaj (sejenis pakain dari kain sutera). Hadits ini diperkuat oleh [Abu Awanah] dan [Asy Syaibani] dari [Asy'ats] dalam menyebarkan salam."},"4473":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَدَعَا أَبُو أُسَيْدٍ السَّاعِدِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عُرْسِهِ وَكَانَتْ امْرَأَتُهُ يَوْمَئِذٍ خَادِمَهُمْ وَهِيَ الْعَرُوسُ قَالَ سَهْلٌ تَدْرُونَ مَا سَقَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْقَعَتْ لَهُ تَمَرَاتٍ مِنْ اللَّيْلِ فَلَمَّا أَكَلَ سَقَتْهُ إِيَّاهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata; Abu Sa'id As Sa'idi mengundang Rasulullah shallallahu 'alaihi wasallam dalam pesta walimahannya. Saat itu, isterinya adalah yang melayani mereka, padahal ia adalah pengantin wanita. Sahl bertkata, \"Tahukah kalian minuman apa yang ia suguhkan kepada Rasulullah shallallahu 'alaihi wasallam? Wanita itu menyediakan kurma yang telah direndam semalaman dan ketika beliau makan, maka wanita itu pun menyuguhkan air pada beliau.\""},"4474":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ كَانَ يَقُولُشَرُّ الطَّعَامِ طَعَامُ الْوَلِيمَةِ يُدْعَى لَهَا الْأَغْنِيَاءُ وَيُتْرَكُ الْفُقَرَاءُ وَمَنْ تَرَكَ الدَّعْوَةَ فَقَدْ عَصَى اللَّهَ وَرَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, bahwa ia berkata; \"Seburuk-buruk jamuan adalah jamuan walimah, yang diundang sebatas orang-orang kaya, sementara orang-orang miskin tidak diundang. Siapa yang tidak memenuhi undangan maka sungguh ia telah bermaksiat kepada Allah dan Rasul-Nya shallallahu 'alaihi wasallam.\""},"4475":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ دُعِيتُ إِلَى كُرَاعٍ لَأَجَبْتُ وَلَوْ أُهْدِيَ إِلَيَّ كُرَاعٌ لَقَبِلْتُ","id":"Telah menceritakan kepada kami [Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seandainya aku diundang ke penghujung negeri, niscaya aku akan mendatanginya. Dan seandainya aku beri daging bagian kaki, niscaya aku akan menerimanya.\""},"4476":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا الْحَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجِيبُوا هَذِهِ الدَّعْوَةَ إِذَا دُعِيتُمْ لَهَا قَالَ وَكَانَ عَبْدُ اللَّهِ يَأْتِي الدَّعْوَةَ فِي الْعُرْسِ وَغَيْرِ الْعُرْسِ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Ali bin Abdullah bin Ibarahim] Telah menceritakan kepada kami [Al Hajjaj bin Muhammad] ia berkata; Telah berkata [Ibnu Juraij] Telah menceritakan kepadaku [Musa bin Uqbah] dari [Nafi'] ia berkata; Aku mendengar [Abdullah bin Umar] radliallahu 'anhuma berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penuhilah seruan ini (walimahan), bila kalian diundang untuk mendatanginya.\" Karena itu, Abdullah selalu mendangi undangan walimahan atau pun bukan waliman, sementara ia sendiri sedang berpuasa."},"4477":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَبْصَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءً وَصِبْيَانًا مُقْبِلِينَ مِنْ عُرْسٍ فَقَامَ مُمْتَنًّا فَقَالَ اللَّهُمَّ أَنْتُمْ مِنْ أَحَبِّ النَّاسِ إِلَيَّ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mubarak] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] radliallahu 'anhu, ia berkata; Suatu ketika Nabi shallallahu 'alaihi wasallam melihat para wanita dan anak-anak perempuan yang sedang memenuhi undangan walimahan, maka beliau pun berdiri dengan segera seraya mengatakan: \"Ya Allah, kalian adalah orang-orang yang paling aku cintai.\""},"4478":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ ق��الَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا أَخْبَرَتْهُ أَنَّهَا اشْتَرَتْ نُمْرُقَةً فِيهَا تَصَاوِيرُ فَلَمَّا رَآهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ عَلَى الْبَابِ فَلَمْ يَدْخُلْ فَعَرَفْتُ فِي وَجْهِهِ الْكَرَاهِيَةَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُوبُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ مَاذَا أَذْنَبْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَالُ هَذِهِ النُّمْرُقَةِ قَالَتْ فَقُلْتُ اشْتَرَيْتُهَا لَكَ لِتَقْعُدَ عَلَيْهَا وَتَوَسَّدَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يُعَذَّبُونَ يَوْمَ الْقِيَامَةِ وَيُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ وَقَالَ إِنَّ الْبَيْتَ الَّذِي فِيهِ الصُّوَرُ لَا تَدْخُلُهُ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Al Qasim bin Muhammad] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa ia telah mengabarkan kepadanya bahwasanya; Ia pernah membeli bantal yang bergambar. Ketika Rasulullah shallallahu 'alaihi wasallam melihatnya, beliau pun berdiri di pintu dan tidak mau masuk, maka aku pun tahu akan rona tak suka pada wajahnya, aku berkata, \"Wahai Rasulullah, aku bertaubat kepada Allah dan juga kepada Rasul-Nya. Dosa apa yang telah kulakukan?\" Selanjutnya Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Kenapa ada bantal seperti ini?\" Aisyah berkata, \"Aku membelinya untuk Anda agar Anda pergunakan untuk duduk dan juga berbantal dengannya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang melukis gambar ini akan disiksa kelak pada hari kiamat, dan kepada mereka akan dikatakan, 'Hidupkanlah apa yang telah kalian ciptakan.'\" Dan beliau juga bersabda: \"Sesungguhnya rumah yang di dalamnya terdapat gambar-gambar, maka rumah itu tidak akan dimasuki malaikat.\""},"4479":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلٍ قَالَلَمَّا عَرَّسَ أَبُو أُسَيْدٍ السَّاعِدِيُّ دَعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ فَمَا صَنَعَ لَهُمْ طَعَامًا وَلَا قَرَّبَهُ إِلَيْهِمْ إِلَّا امْرَأَتُهُ أُمُّ أُسَيْدٍ بَلَّتْ تَمَرَاتٍ فِي تَوْرٍ مِنْ حِجَارَةٍ مِنْ اللَّيْلِ فَلَمَّا فَرَغَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الطَّعَامِ أَمَاثَتْهُ لَهُ فَسَقَتْهُ تُتْحِفُهُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] Telah menceritakan kepada kami [Abu Ghassan] ia berkata; Telah menceritakan kepadaku [Abu Hazim] dari [Sahl] ia berkata; \"Ketika Abu Sa'id As Sa'idi mengadakan acara walimahan, ia mengundang Nabi shallallahu 'alaihi wasallam dan para sahabatnya, namun mereka tidak membuat jamuan makanan untuk mereka dan tidak pula menyuguhkan sesuatu, kecuali isterinya yaitu Ummu Usaid yang menumbuk kurma dalam bejana kecil yang terbuat dari batu, dan telah dibuatnya di malam hari. Maka ketika Nabi shallallahu 'alaihi wasallam usai menyantap makanan, maka ia pun menumbuknya halus untuk beliau. Akhirnya wanita itu pun mempersembahkan minuman itu untuk beliau.\""},"4480":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ الْقَارِيُّ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍأَنَّ أَبَا أُسَيْدٍ السَّاعِدِيَّ دَعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعُرْسِهِ فَكَانَتْ امْرَأَتُهُ خَادِمَهُمْ يَوْمَئِذٍ وَهِيَ الْعَرُوسُ فَقَالَتْ أَوْ قَالَ أَتَدْرُونَ مَا أَنْقَعَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْقَعَتْ لَهُ تَمَرَاتٍ مِنْ اللَّيْلِ فِي تَوْرٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qari] dari [Abu Hazim] ia berkata; Aku mendengar [Sahl bin Sa'd] bahwa Abu Usaid As Sa'idi mengundang Nabi shallallahu 'alaihi wasallam untuk menghadiri acara walimahannya. Sedangkan yang melayani santapan mereka adalah isterinya sendiri, padahal ia adalah sebagai pengantin wanita. Ia berkata, \"Apakah kalian tahu, apa yang dibuat oleh wanita itu untuk Rasulullah shallallahu 'alaihi wasallam? Wanita itu merendam kurma semalaman dalam bejana kecil yang terbuat dari batu.\""},"4481":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَرْأَةُ كَالضِّلَعِ إِنْ أَقَمْتَهَا كَسَرْتَهَا وَإِنْ اسْتَمْتَعْتَ بِهَا اسْتَمْتَعْتَ بِهَا وَفِيهَا عِوَجٌ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] ia berkata; Telah menceritakan kepadaku [Malik bin Anas] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita itu bagaikan tulang rusuk, bila kamu memaksa untuk meluruskannya, niscaya kamu akan mematahkannya, dan jika kamu bermesraan dan menurutinya, maka kamu dapat bermesraan namun padanya terdapat kebengkokan.\""},"4482":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ مَيْسَرَةَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يُؤْذِي جَارَهُ وَاسْتَوْصُوا بِالنِّسَاءِ خَيْرًا فَإِنَّهُنَّ خُلِقْنَ مِنْ ضِلَعٍ وَإِنَّ أَعْوَجَ شَيْءٍ فِي الضِّلَعِ أَعْلَاهُ فَإِنْ ذَهَبْتَ تُقِيمُهُ كَسَرْتَهُ وَإِنْ تَرَكْتَهُ لَمْ يَزَلْ أَعْوَجَ فَاسْتَوْصُوا بِالنِّسَاءِ خَيْرًا","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] Telah menceritakan kepada kami [Husain Al Ju'fi] dari [Za`idah] dari [Maisarah] dari [Abu Hazim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang beriman kepada Allah dan juga kepada hari akhir, maka janganlah ia menyakiti tetangganya. Pergaulilah wanita kaum wanita dengan baik, sesungguhnya mereka diciptakan dari tulang rusuk. Dan sesuatu yang paling bengkok yang terdapat tulang rusuk adalah bagian paling atas. Jika kamu meluruskannya dengan seketika, niscaya kamu akan mematahkannya, namun jika kamu membiarkannya maka ia pun akan selalu dalam keadaan bengkok. Karena itu pergaulilah wanita dengan penuh kebijakan.\""},"4483":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا نَتَّقِي الْكَلَامَ وَالِانْبِسَاطَ إِلَى نِسَائِنَا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَيْبَةَ أَنْ يَنْزِلَ فِينَا شَيْءٌ فَلَمَّا تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكَلَّمْنَا وَانْبَسَطْنَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma, ia berkata; Di masa Nabi shallallahu 'alaihi wasallam, Dahulu kami khawatir untuk menasehati dan memberi arahan pada isteri-isteri kami dan kami juga khawatir jangan-jangan wahyu turun berkenaan dengan kami. Maka ketika Nabi shallallahu 'alaihi wasallam wafat, kami pun berani angkat bicara dan memberi arahan pada mereka."},"4484":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ فَالْإِمَامُ رَاعٍ وَهُوَ مَسْئُولٌ وَالرَّجُلُ رَاعٍ عَلَى أَهْلِهِ وَهُوَ مَسْئُولٌ وَالْمَرْأَةُ رَاعِيَةٌ عَلَى بَيْتِ زَوْجِهَا وَهِيَ مَسْئُولَةٌ وَالْعَبْدُ رَاعٍ عَلَى مَالِ سَيِّدِهِ وَهُوَ مَسْئُولٌ أَلَا فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Abdullah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap kalian adalah pemimpin, dan setiap kalain akan dimintai pertanggungjawabannya. Seorang laki-laki adalah pemimpin atas keluarganya dan ia akan dimintai pertanggungjawabannya. Seorang wanita adalah pemimpin atas rumah suaminya, dan ia pun akan dimintai pertanggungjawabannya. Dan seorang budak juga pemimpin atas atas harta tuannya dan ia juga akan dimintai pertanggungjawabannya. Sungguh setiap kalain adalah pemimpin dan setiap kalian akan dimintai pertanggungjawabannya.\""},"4485":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ عَبْدِ الرَّحْمَنِ وَعَلِيُّ بْنُ حُجْرٍ قَالَا أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَلَسَ إِحْدَى عَشْرَةَ امْرَأَةً فَتَعَاهَدْنَ وَتَعَاقَدْنَ أَنْ لَا يَكْتُمْنَ مِنْ أَخْبَارِ أَزْوَاجِهِنَّ شَيْئًا قَالَتْ الْأُولَى زَوْجِي لَحْمُ جَمَلٍ غَثٍّ عَلَى رَأْسِ جَبَلٍ لَا سَهْلٍ فَيُرْتَقَى وَلَا سَمِينٍ فَيُنْتَقَلُ قَالَتْ الثَّانِيَةُ زَوْجِي لَا أَبُثُّ خَبَرَهُ إِنِّي أَخَافُ أَنْ لَا أَذَرَهُ إِنْ أَذْكُرْهُ أَذْكُرْ عُجَرَهُ وَبُجَرَهُ قَالَتْ الثَّالِثَةُ زَوْجِي الْعَشَنَّقُ إِنْ أَنْطِقْ أُطَلَّقْ وَإِنْ أَسْكُتْ أُعَلَّقْ قَالَتْ الرَّابِعَةُ زَوْجِي كَلَيْلِ تِهَامَةَ لَا حَرٌّ وَلَا قُرٌّ وَلَا مَخَافَةَ وَلَا سَآمَةَ قَالَتْ الْخَامِسَةُ زَوْجِي إِنْ دَخَلَ فَهِدَ وَإِنْ خَرَجَ أَسِدَ وَلَا يَسْأَلُ عَمَّا عَهِدَ قَالَتْ السَّادِسَةُ زَوْجِي إِنْ أَكَلَ لَفَّ وَإِنْ شَرِبَ اشْتَفَّ وَإِنْ اضْطَجَعَ الْتَفَّ وَلَا يُولِجُ الْكَفَّ لِيَعْلَمَ الْبَثَّ قَالَتْ السَّابِعَةُ زَوْجِي غَيَايَاءُ أَوْ عَيَايَاءُ طَبَاقَاءُ كُلُّ دَاءٍ لَهُ دَاءٌ شَجَّكِ أَوْ فَلَّكِ أَوْ جَمَعَ كُلًّا لَكِ قَالَتْ الثَّامِنَةُ زَوْجِي الْمَسُّ مَسُّ أَرْنَبٍ وَالرِّيحُ رِيحُ زَرْنَبٍ قَالَتْ التَّاسِعَةُ زَوْجِي رَفِيعُ الْعِمَادِ طَوِيلُ النِّجَادِ عَظِيمُ الرَّمَادِ قَرِيبُ الْبَيْتِ مِنْ النَّادِ قَالَتْ الْعَاشِرَةُ زَوْجِي مَالِكٌ وَمَا مَالِكٌ مَالِكٌ خَيْرٌ مِنْ ذَلِكِ لَهُ إِبِلٌ كَثِيرَاتُ الْمَبَارِكِ قَلِيلَاتُ الْمَسَارِحِ وَإِذَا سَمِعْنَ صَوْتَ الْمِزْهَرِ أَيْقَنَّ أَنَّهُنَّ هَوَالِكُ قَالَتْ الْحَادِيَةَ عَشْرَةَ زَوْجِي أَبُو زَرْعٍ وَمَا أَبُو زَرْعٍ أَنَاسَ مِنْ حُلِيٍّ أُذُنَيَّ وَمَلَأَ مِنْ شَحْمٍ عَضُدَيَّ وَبَجَّحَنِي فَبَجِحَتْ إِلَيَّ نَفْسِي وَجَدَنِي فِي أَهْلِ غُنَيْمَةٍ بِشِقٍّ فَجَعَلَنِي فِي أَهْلِ صَهِيلٍ وَأَطِيطٍ وَدَائِسٍ وَمُنَقٍّ فَعِنْدَهُ أَقُولُ فَلَا أُقَبَّحُ وَأَرْقُدُ فَأَتَصَبَّحُ وَأَشْرَبُ فَأَتَقَنَّحُ أُمُّ أَبِي زَرْعٍ فَمَا أُمُّ أَبِي زَرْعٍ عُكُومُهَا رَدَاحٌ وَبَيْتُهَا فَسَاحٌ ابْنُ أَبِي زَرْعٍ فَمَا ابْنُ أَبِي زَرْعٍ مَضْجَعُهُ كَمَسَلِّ شَطْبَةٍ وَيُشْبِعُهُ ذِرَاعُ الْجَفْرَةِ بِنْتُ أَبِي زَرْعٍ فَمَا بِنْتُ أَبِي زَرْعٍ طَوْعُ أَبِيهَا وَطَوْعُ أُمِّهَا وَمِلْءُ كِسَائِهَا وَغَيْظُ جَارَتِهَا جَارِيَةُ أَبِي زَرْعٍ فَمَا جَارِيَةُ أَبِي زَرْعٍ لَا تَبُثُّ حَدِيثَنَا تَبْثِيثًا وَلَا تُنَقِّثُ مِيرَتَنَا تَنْقِيثًا وَلَا تَمْلَأُ بَيْتَنَا تَعْشِيشًا قَالَتْ خَرَجَ أَبُو زَرْعٍ وَالْأَوْطَابُ تُمْخَضُ فَلَقِيَ امْرَأَةً مَعَهَا وَلَدَانِ لَهَا كَالْفَهْدَيْنِ يَلْعَبَانِ مِنْ تَحْتِ خَصْرِهَا بِرُمَّانَتَيْنِ فَطَلَّقَنِي وَنَكَحَهَا فَنَكَحْتُ بَعْدَهُ رَجُلًا سَرِيًّا رَكِبَ شَرِيًّا وَأَخَذَ خَطِّيًّا وَأَرَاحَ عَلَيَّ نَعَمًا ثَرِيًّا وَأَعْطَانِي مِنْ كُلِّ رَائِحَةٍ زَوْجًا وَقَالَ كُلِي أُمَّ زَرْعٍ وَمِيرِي أَهْلَكِ قَالَتْ فَلَوْ جَمَعْتُ كُلَّ شَيْءٍ أَعْطَانِيهِ مَا بَلَغَ أَصْغَرَ آنِيَةِ أَبِي زَرْعٍ قَالَتْ عَائِشَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْتُ لَكِ كَأَبِي زَرْعٍ لِأُمِّ زَرْعٍقَالَ أَبُو عَبْد اللَّهِ قَالَ سَعِيدُ بْنُ سَلَمَةَ عَنْ هِشَامٍ وَلَا تُعَشِّشُ بَيْتَنَا تَعْشِيشًا قَالَ أَبُو عَبْد اللَّهِ وَقَالَ بَعْضُهُمْ فَأَتَقَمَّحُ بِالْمِيمِ وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Sulaiman bin Abdurrahman] dan [Ali bin Hujr] keduanya berkata, Telah mengabarkan kepada kami [Isa bin Yunus] Telah menceritakan kepada kami [Hisyam bin Urwah] dari [Abdullah bin Urwah] dari [Urwah] dari [Aisyah] ia berkata; Sebelas wanita duduk-duduk kemudian berjanji sesama mereka untuk tidak mnyembunyikan sedikitpun seluk-beluk suami mereka. Wanita pertama berkata, \"Suamiku adalah daging unta yang kurus, berada di puncak gunung yang sulit, tidak mudah didaki, dan tidak gemuk sehingga mudah diangkat.\" Wanita kedua berkata, \"Suamiku? Aku tidak akan menyebarkan seluk-beluk tentang dirinya. Aku takut tidak bisa meninggalkannya jika aku menyebutnya, aku menyebutkan kebaikan dan keburukannya sekaligus.\" Wanita ketiga berkata, \"Suamiku jangkung. Jika aku berkata, ia menceraikanku. Jika aku diam, ia menggantungkan (urusanku).\" Wanita keempat berkata, \"Suamiku sedang, seperti cuaca Gunung Tihamah. Ia tidak panas, dingin, menakutkan, dan membosankan.\" Wanita kelima berucap, \"Suamiku? Jika ia masuk, ia seperti anak singa. Jika ia keluar, ia seperti singa. Ia tidak pernah bertanya apa yang ia ketahui.\" Wanita keenam mengemukakan, \"Suamiku? Jika makan, ia mencampur semua jenis makanan. Jika minum, ia menghabiskan seluruh air. Jika tidur, ia berselimut. Ia tidak memasukkan telapak tangan untuk mengetahui kesedihan (tidak penyayang kepadanya).\" Wanita ketujuh berkata, \"Suamiku tidak tahu kemaslahatan dirinya dan bodoh. Baginya, semua penyakit adalah obat. Ia membelah kepalamu atau memecahkanmu, atau melakukan kedua-duanya terhadapmu.\" Wanita kedelapan berkata, \"Suamiku halus sehalus kelinci dan harum seharum zarrab (tanaman yang harum).\" Wanita kesembilan mengatakan, \"Suamiku tinggi tiangnya, panjang bantuannya, besar asapnya, dan rumahnya dengan api.\" Wanita kesepuluh mengemukakan, \"Suamiku adalah majikan dan tidak ada majikan sebaik dia. Ia mempunyai unta yang banyak sekali dan dekat pengembalaannya. Jika unta-unta tersebut mendengar suara rebana sebagai tanda kedatangan tamu, unta-unta tersebut merasa yakin bahwa mereka akan disembelih.\" Wanita kesebelas berkata, \"Suamiku adalah Abu Zar'in. Tahukah kamu siapakah Abu Zar'in? Ia menggerak-gerakkan perhiasan kedua telingaku, memenuhi lemak kedua lenganku, dan membahagiakanku hingga jiwaku berbahagia. Ia mendapatiku di tempat pemilik kambing kecil di gunung kemudian membawaku ke pemilik kuda yang banyak, unta yang banyak, penggiling makanan, dan pengusir burung. Di tempatnya, aku berkata dan tidak menjelek-jelekkan, tidur hingga pagi, dan minum hingga puas. Ibu Abu Zar'in. siapakah ibu Abu Zar'in? Tempat makanannya besar dan rumahnya luas. Anak laki-laki Abu Zar'in. Siapakah anak laki-laki Abu Zar'in? Tempat tidurnya seperti pedang yang diambil dari sarungnya (ringan) dan ia dibuat kenyang dengan lengan kambing yang berusia empat bulan. Anak perempuan Abu Zar'in. Siapakah anak perempuan Abu Zar'in? Ia patuh kepada ayah ibunya dan membuat marah tetanggganya. Budak wanita Abu Zar'in. Siapakah budak wanita Abu Zar'in? Ia tidak merusak pembicaraan kami, tidak memindahkan warisan kami, dan tidak memenuhi rumah kami dengan kotoran seperti rumput. Abu Zar'in keluar sedang tempat-tempat susu digerak-gerakkan dengan keras, kemudian ia bertemu dengan seorang wanita bersama dua anaknya seperti anak singa yang sedang bermain di bawah pinggangnya dengan dua buah delima, kemudian Abu Zar'in menceraikanku dan menikahi wanita tersebut. Sesudahnya aku menikah dengan seorang laki-laki yang mulia, mengendarai dengan cepat, mengambil tombak, mengembalikan hewan ternak kepadaku, dan memberiku bau harum semuanya sepasang. Ia berkata, 'Makanlah hai Ummu Zar'in dan berilah makan keluargamu.' Jika aku kumpulkan semua yang diberikan suami keduaku tersebut, tidak mencapai bejana terkecil Abu Zar'in. Aisyah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Terhadapmu aku seperti Abu Zar'in terhadap Ummu Zar'in.\" berkata Abu Abdullah; berkata [Sa'id bin Salamah] dari [Hisyam] dan janganlah engkau penuhi rumah kami dengan sisa-sisa rumah (sampah). Abu Abdullah mengatakan, sebagian mengatakan \"Maka aku minum hingga puas.\". Dan ini lebih sahih."},"4486":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَ��نَ الْحَبَشُ يَلْعَبُونَ بِحِرَابِهِمْ فَسَتَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَنْظُرُ فَمَا زِلْتُ أَنْظُرُ حَتَّى كُنْتُ أَنَا أَنْصَرِفُ فَاقْدُرُوا قَدْرَ الْجَارِيَةِ الْحَدِيثَةِ السِّنِّ تَسْمَعُ اللَّهْوَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Hisyam] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari [Aisyah] ia berkta; Suatu ketika, orang-orang Habasyah sedang bermain-main dengan peralatan perang mereka, lalu Rasulullah shallallahu 'alaihi wasallam pun menutupiku, sementara aku menonton mereka. Begitulah seterusnya hingga aku sendirilah yang bosan dan beranjak sendiri. Karena itu, jadilah kalian seperti anak kecil yang suka bergurau."},"4487":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي ثَوْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمْ أَزَلْ حَرِيصًا عَلَى أَنْ أَسْأَلَ عُمَرَ بْنَ الْخَطَّابِ عَنْ الْمَرْأَتَيْنِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَيْنِ قَالَ اللَّهُ تَعَالَى{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }حَتَّى حَجَّ وَحَجَجْتُ مَعَهُ وَعَدَلَ وَعَدَلْتُ مَعَهُ بِإِدَاوَةٍ فَتَبَرَّزَ ثُمَّ جَاءَ فَسَكَبْتُ عَلَى يَدَيْهِ مِنْهَا فَتَوَضَّأَ فَقُلْتُ لَهُ يَا أَمِيرَ الْمُؤْمِنِينَ مَنْ الْمَرْأَتَانِ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّتَانِ قَالَ اللَّهُ تَعَالَى{ إِنْ تَتُوبَا إِلَى اللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا }قَالَ وَاعَجَبًا لَكَ يَا ابْنَ عَبَّاسٍ هُمَا عَائِشَةُ وَحَفْصَةُ ثُمَّ اسْتَقْبَلَ عُمَرُ الْحَدِيثَ يَسُوقُهُ قَالَ كُنْتُ أَنَا وَجَارٌ لِي مِنْ الْأَنْصَارِ فِي بَنِي أُمَيَّةَ بْنِ زَيْدٍ وَهُمْ مِنْ عَوَالِي الْمَدِينَةِ وَكُنَّا نَتَنَاوَبُ النُّزُولَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَنْزِلُ يَوْمًا وَأَنْزِلُ يَوْمًا فَإِذَا نَزَلْتُ جِئْتُهُ بِمَا حَدَثَ مِنْ خَبَرِ ذَلِكَ الْيَوْمِ مِنْ الْوَحْيِ أَوْ غَيْرِهِ وَإِذَا نَزَلَ فَعَلَ مِثْلَ ذَلِكَ وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا عَلَى الْأَنْصَارِ إِذَا قَوْمٌ تَغْلِبُهُمْ نِسَاؤُهُمْ فَطَفِقَ نِسَاؤُنَا يَأْخُذْنَ مِنْ أَدَبِ نِسَاءِ الْأَنْصَارِ فَصَخِبْتُ عَلَى امْرَأَتِي فَرَاجَعَتْنِي فَأَنْكَرْتُ أَنْ تُرَاجِعَنِي قَالَتْ وَلِمَ تُنْكِرُ أَنْ أُرَاجِعَكَ فَوَاللَّهِ إِنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُرَاجِعْنَهُ وَإِنَّ إِحْدَاهُنَّ لَتَهْجُرُهُ الْيَوْمَ حَتَّى اللَّيْلِ فَأَفْزَعَنِي ذَلِكَ وَقُلْتُ لَهَا قَدْ خَابَ مَنْ فَعَلَ ذَلِكِ مِنْهُنَّ ثُمَّ جَمَعْتُ عَلَيَّ ثِيَابِي فَنَزَلْتُ فَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ لَهَا أَيْ حَفْصَةُ أَتُغَاضِبُ إِحْدَاكُنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَوْمَ حَتَّى اللَّيْلِ قَالَتْ نَعَمْ فَقُلْتُ قَدْ خِبْتِ وَخَسِرْتِ أَفَتَأْمَنِينَ أَنْ يَغْضَبَ اللَّهُ لِغَضَبِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَهْلِكِي لَا تَسْتَكْثِرِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تُرَاجِعِيهِ فِي شَيْءٍ وَلَا تَهْجُرِيهِ وَسَلِينِي مَا بَدَا لَكِ وَلَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكِ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ قَالَ عُمَرُ وَكُنَّا قَدْ تَحَدَّثْنَا أَنَّ غَسَّانَ تُنْعِلُ الْخَيْلَ لِغَزْوِنَا فَنَزَلَ صَاحِبِي الْأَنْصَارِيُّ يَوْمَ نَوْبَتِهِ فَرَجَعَ إِلَيْنَا عِشَاءً فَضَرَبَ بَابِي ضَرْبًا شَدِيدًا وَقَالَ أَثَمَّ هُوَ فَفَزِعْتُ فَخَرَجْتُ إِلَيْهِ فَقَالَ قَدْ حَدَثَ الْيَوْمَ أَمْرٌ عَظِيمٌ قُلْتُ مَا هُوَ أَجَاءَ غَسَّانُ قَالَ لَا بَلْ أَعْظَمُ مِنْ ذَلِكَ وَأَهْوَلُ طَلَّقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُوَقَالَ عُبَيْدُ بْنُ حُنَيْنٍ سَمِعَ ابْنَ عَبَّاسٍ عَنْ عُمَرَ فَقَالَ اعْتَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَزْوَاجَهُ فَقُلْتُ خَابَتْ حَفْصَةُ وَخَسِرَتْ قَدْ كُنْتُ أَظُنُّ هَذَا يُوشِكُ أَنْ يَكُونَ فَجَمَعْتُ عَلَيَّ ثِيَابِي فَصَلَّيْتُ صَلَاةَ الْفَجْرِ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَشْرُبَةً لَهُ فَاعْتَزَلَ فِيهَا وَدَخَلْتُ عَلَى حَفْصَةَ فَإِذَا هِيَ تَبْكِي فَقُلْتُ مَا يُبْكِيكِ أَلَمْ أَكُنْ حَذَّرْتُكِ هَذَا أَطَلَّقَكُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَا أَدْرِي هَا هُوَ ذَا مُعْتَزِلٌ فِي الْمَشْرُبَةِ فَخَرَجْتُ فَجِئْتُ إِلَى الْمِنْبَرِ فَإِذَا حَوْلَهُ رَهْطٌ يَبْكِي بَعْضُهُمْ فَجَلَسْتُ مَعَهُمْ قَلِيلًا ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْمَشْرُبَةَ الَّتِي فِيهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لِغُلَامٍ لَهُ أَسْوَدَ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ الْغُلَامُ فَكَلَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَجَعَ فَقَالَ كَلَّمْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرْتُكَ لَهُ فَصَمَتَ فَانْصَرَفْتُ حَتَّى جَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ فَقُلْتُ لِلْغُلَامِ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ ثُمَّ رَجَعَ فَقَالَ قَدْ ذَكَرْتُكَ لَهُ فَصَمَتَ فَرَجَعْتُ فَجَلَسْتُ مَعَ الرَّهْطِ الَّذِينَ عِنْدَ الْمِنْبَرِ ثُمَّ غَلَبَنِي مَا أَجِدُ فَجِئْتُ الْغُلَامَ فَقُلْتُ اسْتَأْذِنْ لِعُمَرَ فَدَخَلَ ثُمَّ رَجَعَ إِلَيَّ فَقَالَ قَدْ ذَكَرْتُكَ لَهُ فَصَمَتَ فَلَمَّا وَلَّيْتُ مُنْصَرِفًا قَالَ إِذَا الْغُلَامُ يَدْعُونِي فَقَالَ قَدْ أَذِنَ لَكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ مُضْطَجِعٌ عَلَى رِمَالِ حَصِيرٍ لَيْسَ بَيْنَهُ وَبَيْنَهُ فِرَاشٌ قَدْ أَثَّرَ الرِّمَالُ بِجَنْبِهِ مُتَّكِئًا عَلَى وِسَادَةٍ مِنْ أَدَمٍ حَشْوُهَا لِيفٌ فَسَلَّمْتُ عَلَيْهِ ثُمَّ قُلْتُ وَأَنَا قَائِمٌ يَا رَسُولَ اللَّهِ أَطَلَّقْتَ نِسَاءَكَ فَرَفَعَ إِلَيَّ بَصَرَهُ فَقَالَ لَا فَقُلْتُ اللَّهُ أَكْبَرُ ثُمَّ قُلْتُ وَأَنَا قَائِمٌ أَسْتَأْنِسُ يَا رَسُولَ اللَّهِ لَوْ رَأَيْتَنِي وَكُنَّا مَعْشَرَ قُرَيْشٍ نَغْلِبُ النِّسَاءَ فَلَمَّا قَدِمْنَا الْمَدِينَةَ إِذَا قَوْمٌ تَغْلِبُهُمْ نِسَاؤُهُمْ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قُلْتُ يَا رَسُولَ اللَّهِ لَوْ رَأَيْتَنِي وَدَخَلْتُ عَلَى حَفْصَةَ فَقُلْتُ لَهَا لَا يَغُرَّنَّكِ أَنْ كَانَتْ جَارَتُكِ أَوْضَأَ مِنْكِ وَأَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرِيدُ عَائِشَةَ فَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبَسُّمَةً أُخْرَى فَجَلَسْتُ حِينَ رَأَيْتُهُ تَبَسَّمَ فَرَفَعْتُ بَصَرِي فِي بَيْتِهِ فَوَاللَّهِ مَا رَأَيْتُ فِي بَيْتِهِ شَيْئًا يَرُدُّ الْبَصَرَ غَيْرَ أَهَبَةٍ ثَلَاثَةٍ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ فَلْيُوَسِّعْ عَلَى أُمَّتِكَ فَإِنَّ فَارِسَ وَالرُّومَ قَدْ وُسِّعَ عَلَيْهِمْ وَأُعْطُوا الدُّنْيَا وَهُمْ لَا يَعْبُدُونَ اللَّهَ فَجَلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ مُتَّكِئًا فَقَالَ أَوَفِي هَذَا أَنْتَ يَا ابْنَ الْخَطَّابِ إِنَّ أُولَئِكَ قَوْمٌ عُجِّلُوا طَيِّبَاتِهِمْ فِي الْحَيَاةِ الدُّنْيَا فَقُلْتُ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِي فَاعْتَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ مِنْ أَجْلِ ذَلِكَ الْحَدِيثِ حِينَ أَفْشَتْهُ حَفْصَةُ إِلَى عَائِشَةَ تِسْعًا وَعِشْرِينَ لَيْلَةً وَكَانَ قَالَ مَا أَنَا بِدَاخِلٍ عَلَيْهِنَّ شَهْرًا مِنْ شِدَّةِ مَوْجِدَتِهِ عَلَيْهِنَّ حِينَ عَاتَبَهُ اللَّهُ فَلَمَّا مَضَتْ تِسْعٌ وَعِشْرُونَ لَيْلَةً دَخَلَ عَلَى عَائِشَةَ فَبَدَأَ بِهَا فَقَالَتْ لَهُ عَائِشَةُ يَا رَسُولَ اللَّهِ إِنَّكَ كُنْتَ قَدْ أَقْسَمْتَ أَنْ لَا تَدْخُلَ عَلَيْنَا شَهْرًا وَإِنَّمَا أَصْبَحْتَ مِنْ تِسْعٍ وَعِشْرِينَ لَيْلَةً أَعُدُّهَا عَدًّا فَقَالَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ لَيْلَةً فَكَانَ ذَلِكَ الشَّهْرُ تِسْعًا وَعِشْرِينَ لَيْلَةً قَالَتْ عَائِشَةُ ثُمَّ أَنْزَلَ اللَّهُ تَعَالَى آيَةَ التَّخَيُّرِ فَبَدَأَ بِي أَوَّلَ امْرَأَةٍ مِنْ نِسَائِهِ فَاخْتَرْتُهُ ثُمَّ خَيَّرَ نِسَاءَهُ كُلَّهُنَّ فَقُلْنَ مِثْلَ مَا قَالَتْ عَائِشَةُ","id":"Telah menceritakan kepada kami [Abu Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin Abu Tsaur] dari [Abdullah bin Abbas] radliallahu 'anhuma, ia berkata; Aku selalu bersikeras untuk menanyakan kepada Umar bin Al Khaththab tentang dua orang wanita dari isteri-isteri Nabi shallallahu 'alaihi wasallam, yang Allah berfirman terhadap mereka berdua: \"IN TATUUBAA ILALLAHI FAQAD SHAGHAT QULUUBUKUMAA.\" Hingga suatu saat, ia menunaikan haji dan aku pun ikut menunaikan haji bersamanya. Dalam perjalanan ia menyingkir hendak buang hajat, lalu aku mengikutinya dengan membawakan kantong air. Ia pun buang air besar, dan ia kembali aku pun menuangkan air pada kedua tangannya, lalu ia pun berwudlu. Saat itulah aku bertanya, \"Wahai Amirul Mukminin, siapakah dua orang wanita dari isteri-isteri Nabi shallallahu 'alaihi wasallam yang Allah Ta'ala berfirman kepada keduanya, 'IN TATUUBAA ILALLAHI FAQAD SHAGHAT QULUUBUKUMAA (Jika kamu berdua bertaubat kepada Allah, Maka Sesungguhnya hati kamu berdua Telah condong (untuk menerima kebaikan..).'\" [Umar] pun menjawab, \"Sungguhnya mengherankan kamu ini wahai Ibnu Abbas. Kedua wanita itu adalah Aisyah dan Hafshah.\" Kemudian Umar menceritakan haditsnya dengan lebih luas, ia berkata; Dulu, aku mempunyai seorang tetangga dari kalangan Anshar di Bani Umayyah bin Zaid yang mereka adalah para penduduk Manidah yang fakir. Kami saling bergantian untuk menghadiri majelis Nabi shallallahu 'alaihi wasallam. Aku hadir sehari dan ia pun hadir sehari. Bila aku yang hadir, maka aku akan menyampaikan hal-hal yang disampaikan oleh beliau berupa wahyu atau yang lainnya di hari itu. Dan jika gilirannya yang hadir, ia pun melakukan hal yang sama. Kami adalah bangsa Quraisy yang posisinya selalu di atas kaum wanita. Dan setelah kami bertemu dengan kaum Anshar, ternyata mereka adalah kaum yang banya dipengaruhi oleh kaum wanitanya. Maka para isteri-isteri kami pun mulai meniru dan mengambil adab dan kebiasaan wanita-wanita Anshar. Kemudian aku mengajak isteriku berdiskusi, lalu ia pun mendebat argumentasiku. Aku mengingkari akan perlakuannya itu, ia pun berkata, \"Kenapa kamu tidak mengajakku berdiskusi? Demi Allah, sesungguhnya para isteri-isteri Nabi shallallahu 'alaihi wasallam mengajak beliau berdiskusi. Bahkan pada hari ini hingga malam nanti, salah seorang dari mereka mendiamkan beliau.\" Aku pun kaget akan hal itu. Kukatakan padanya, \"Sesungguhnya telah merugilah bagi siapa di antara mereka yang melalukan hal itu.\" Setelah itu, aku bergegas memberesi pakaianku lalu menemui Hafshah. Kukatakan padanya, \"Wahai Hafshah, apakah salah seorang dari kalian telah menyebabkan Nabi shallallahu 'alaihi wasallam marah di hari ini hingga malam?\" Ia menjawab, \"Ya.\" Aku berkata, \"Sesungguh, kamu telah merugi. Apakah engkau merasa sekiranya Allah menjadi marah lantaran marahnya Rasulullah shallallahu 'alaihi wasallam lalu kamu akan binasa? Janganlah kamu menuntut banyak kepada Nabi shallallahu 'alaihi wasallam dan jangan pula kamu membantahnya dalam sesuatu apa pun. Dan janganlah kamu mendiamkannya. Pintalah padaku apa yang kamu mau. Janganlah kamu merasa cemburu terhadap madumu yang lebih dicintai oleh Nabi shallallahu 'alaihi wasallam -maksudnya adalah Aisyah-.\" Umar berkata; Sebelumnya, kami telah saling berbincang bahwa Ghassan tengah mempersiapkan pasukan berkuda untuk memerangi kami. Pada hari gilirannya hadir, sahabatku yang Anshari menghadiri majelis lalu kembali menemuiku setelah sahalat Isya'. Ia mengetuk pintu rumahku dengan sangat keras seraya berkata, \"Cepatlah buka!\" maka aku pun segera keluar menemuinya. Ia berata, \"Sesungguhnya pada hari ini telah terjadi perkara yang besar.\" Aku bertanya, \"Peristiwa apa itu? Apakah Ghassan telah datang?\" Ia menjawab, \"Tidak, bahkan yang lebih besar dari itu. Nabi shallallahu 'alaihi wasallam telah menceraikan isteri-isterinya.\" [Ubaid bin Hunain] berkata; Ia mendengar [Ibnu Abbas], dari [Umar], ia berkata; Nabi shallallahu 'alaihi wasallam meninggalkan isteri-isterinya, maka aku pun berakata, \"Sungguh, Hafshah telah merugi.\" Aku telah menduga hal ini akan terjadi. Aku pun segera mengemasi pakaianku, lalu shalat Fajar bersama Nabi shallallahu 'alaihi wasallam. Setelah itu, Nabi shallallahu 'alaihi wasallam memasuki tempat minumnya dan berdiam diri situ. Kemudian aku masuk menemui Hafshah, ternyata ia sedang menangis. Aku berkata padanya, \"Apa yang menyebabkanmu menangis. Bukankah aku telah mengingatkanmu akan hal ini? Apakah Nabi shallallahu 'alaihi wasallam telah menceraikan kalian?\" Ia menjawab, \"Aku tidak tahu, itu beliau sedang minggat di tempat minum.\" Maka aku pun segera keluar dan mendatangi mimbar, ternyata di sekeliling itu ada beberapa orang yang sebagian dari mereka juga sedang menangis, lalu aku pun duduk bersama mereka sebentar kemudian aku tak kuasa lagi akan suasana itu. Maka aku datang ke tempat minum yang dipergunakan Nabi shallallahu 'alaihi wasallam untuk berdiam. Aku pun berkata kepada budaknya yang hitam, \"Mintakanlah izin untuk Umar.\" Lalu sang budak pun masuk dan berbicara kepada Nabi shallallahu 'alaihi wasallam kemudian kembali dan berkata, \"Aku telah berbica dengan Nabi shallallahu 'alaihi wasallam dan juga telah menyebutmu, namun beliau diam.\" Akhirnya aku pun kembali dan duduk lagi bersama sekelompok orang yang tadi berada di sekitar mimbar. Setelah itu, aku tak sabaran lagi, maka aku mendatangi sang budak itu lagi dan berkata padanya, \"Mintakanlah izin untuk Umar.\" Ia pun masuk lalu kembali seraya berkata, \"Aku telah menyebutmu, namun beliau tetap diam.\" Aku kembali lagi dan duduk bersama beberapa orang yang ada di mimbar. Namun, aku tak sabaran lagi dan mendatangi sang budak itu lalu berkata, \"Mintakanlah ini untuk Umar.\" Ia pun masuk dan kembali seraya berkata, \"Sungguh, aku telah menyebut namamu, namun beliau tetap diam.\" Maka ketika aku berpaling hendak pergi, tiba-tiba sang budak itu memanggilku seraya berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam telah mengizinkanmu.\" Akhirnya aku pun menemui Rasulullah shallallahu 'alaihi wasallam yang sedang berbaring di atas pasir beralaskan tikar tanpa kasur. Pasir-pasir itu telah berbekas pada sisi badan beliau. beliau berbantalkan kulit yang berisikan sabut. Aku mengucapkan salam atasnya dan berkata sambil berdiri, \"Wahai Rasulullah, apakah Anda telah menceraikan isteri-isteri Anda?\" Maka beliau pun mengangkat pandangannya ke arahku dan menjawab: \"Tidak.\" Maka aku pun berkata, \"Allahu Akbar.\" Kukatakan lagi sambil berdiri, \"Aku mendengar wahai Rasulullah, sekiranya Anda melihatku. Kita adalah bangsa Quraisy yang selalu mengatur wanita. Namun, ketika kita mendatangi Madinah, ternyata mereka adalah kaum yang didominasi oleh kaum wanita.\" Kemudian Nabi shallallahu 'alaihi wasallam tersenyum. Lalu aku berkata lagi, \"Wahai Rasulullah, sekiranya Anda mau melihatku. Aku telah menemui Hafshah dan berkata padanya, 'Janganlah sekali-kali kamu merasa cemburu bilamana tetanggamu lebih dicintai oleh Nabi shallallahu 'alaihi wasallam -maksudnya adalah Aisyah-.'\" Kemudian Nabi shallallahu 'alaihi wasallam tersenyum lagi. Maka ketika itu, aku pun duduk dan mengangkat pandanganku ke arah rumahnya. Maka demi Allah, aku tidak melihat sedikit pun di rumah beliau kecuali tiga kulit yang telah disamak. Aku berkata pada beliau, \"Wahai Rasulullah, berdo'alah kepada Allah untuk ummat Anda. Karena orang-orang Persi dan Romawi telah diberi keleluasaan, dan mereka juga telah diberi dunia, padahal mereka tidak menyembah Allah.\" Akhirnya Nabi shallallahu 'alaihi wasallam duduk yang sebelumnya berbaring. Kemudian beliau bersabda: \"Beginikah sikapmu wahai Ibnul Khaththab? Sesungguhnya mereka itu adalah suatu kaum yang kebaikan mereka disegerakan di dunia.\" Aku pun berkata, \"Mintakanlah ampun untukku.\" Jadi, Nabi shallallahu 'alaihi wasallam meninggalkan isteri-isterinya karena perkara itu. Yakni, ketika Hafshah menyebarkannya pada Aisyah, yaitu selama dua puluh sembilan hari. Saat itu, beliau bersabda: \"Aku tidak akan masuk menemui mereka selama satu bulan.\" Demikian itu, karena kerasnya rasa kesal beliau pada mereka, yakni saat Allah menegur dirinya. Dan ketika telah berlalu dua puluh sembilan hari, beliau menemui Aisyah dan beliau memulai darinya. Maka Aisyah pun berkata pada beliau, \"Wahai Rasulullah, sesungguhnya Anda telah bersumpah untuk tidak menemui kami selama satu bulan penuh. Sedangkan hari ini Anda baru memasuki hari yang kedua puluh sembilan, sebagaimana yang aku hitung.\" Kemudian beliau pun bersabda; \"Sesungguhnya hitungan bulan itu adalah dua puluh sembilan hari.\" Dan memang jumlah hari pada bulan itu adalah dua puluh sembilan malam. Aisyah berkata; Kemudian Allah Ta'ala menurunkan ayat At Takhyir (ayat yang berisi pilihan untuk tetap menjadi isteri nabi atau tidak). Beliau memulai dariku, wanita yang pertama dari isteri-isterinya. Dan aku pun lebih memilih beliau. setelah itu, beliau memberi pilihan kepada para isterinya semuanya, dan mereka pun menjawab sebagaimana yang dikatakan Aisyah."},"4488":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَصُومُ الْمَرْأَةُ وَبَعْلُهَا شَاهِدٌ إِلَّا بِإِذْنِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah seorang wanita berpuasa padahal suaminya sedang ada, kecuali dengan seizinnya.\""},"4489":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَعَا الرَّجُلُ امْرَأَتَهُ إِلَى فِرَاشِهِ فَأَبَتْ أَنْ تَجِيءَ لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تُصْبِحَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ibnu Abu Adi] dari [Syu'bah] dari [Sulaiman] dari [Abu Hazim] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seorang suami mengajak isterinya ke tempat tidur, lalu ia enggan untuk memenuhi ajakan suaminya, maka ia akan dilaknat Malaikat hingga pagi.\""},"4490":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَاتَتْ الْمَرْأَةُ مُهَاجِرَةً فِرَاشَ زَوْجِهَا لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تَرْجِعَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Zurarah] dari [Abu Hurairah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabdda: \"Apabila seorang wanita bermalam sementara ia tidak memenuhi ajakan suaminya di tempat tidur, maka Malaikat melaknatnya hingga pagi.\""},"4491":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِلْمَرْأَةِ أَنْ تَصُومَ وَزَوْجُهَا شَاهِدٌ إِلَّا بِإِذْنِهِ وَلَا تَأْذَنَ فِي بَيْتِهِ إِلَّا بِإِذْنِهِ وَمَا أَنْفَقَتْ مِنْ نَفَقَةٍ عَنْ غَيْرِ أَمْرِهِ فَإِنَّهُ يُؤَدَّى إِلَيْهِ شَطْرُهُوَرَوَاهُ أَبُو الزِّنَادِ أَيْضًا عَنْ مُوسَى عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ فِي الصَّوْمِ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] Telah menceritakan kepada kami [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita untuk berpuasa sementara sementara suaminya ada di rumah, kecuai dengan seizinnya. Dan tidak boleh mengizinkan seseorang masuk ke dalam rumahnya kecuali dengan seizinnya. Dan sesuatu yang ia infakkan tanpa seizinnya, maka setengahnya harus dikembalikan pada suaminya.\" Hadits ini juga diriwayatkan oleh [Az Zinad] dari [Musa] dari [bapaknya] dari [Abu Hurairah] dalam bab shaum."},"4492":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُمْتُ عَلَى بَابِ الْجَنَّةِ فَكَانَ عَامَّةَ مَنْ دَخَلَهَا الْمَسَاكِينُ وَأَصْحَابُ الْجَدِّ مَحْبُوسُونَ غَيْرَ أَنَّ أَصْحَابَ النَّارِ قَدْ أُمِرَ بِهِمْ إِلَى النَّارِ وَقُمْتُ عَلَى بَابِ النَّارِ فَإِذَا عَامَّةُ مَنْ دَخَلَهَا النِّسَاءُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Isma'il] Telah mengabarkan kepada kami [At Taimi] dari [Abu Utsman] dari [Usamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku berdiri di ambang pintu surga, maka aku pun menyaksikan bahwa kebanyakan yang memasukinya adalah orang-orang miskin, sedang orang-orang yang memiliki kekayaaan tertahan. Selain penduduk neraka telah diperintahkan untuk dimasukkan dalam neraka. Aku berdiri di ambang neraka, dan ternyata kebanyakan penghuninya adalah para wanita.\""},"4493":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّهُ قَالَخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا نَحْوًا مِنْ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ هَذَا ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ فَقَالَ إِنِّي رَأَيْتُ الْجَنَّةَ أَوْ أُرِيتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَرَأَيْتُ النَّارَ فَلَمْ أَرَ كَالْيَوْمِ مَنْظَرًا قَطُّ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا لِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ يَكْفُرْنَ بِاللَّهِ قَالَ يَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abdullah bin Abbas] bahwa ia berkata; Pernah terjadi gerhana matahari di masa Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat bersama kaum muslimin. Beliau berdiri dengan berdiri yang sangat panjang sebagaimana panjangnya bacaan surat Al Baqarah. Kemudian beliau ruku' dengan ruku' yang panjang pula. Sesudah itu beliau bangkit dari ruku' lalu berdiri lagi dengan sangat panjang namun tidak sebagaimana panjangnya berdiri beliau yang pertama. Kemudian beliau ruku' dengan panjang, namun tidak sepanjang ruku'nya yang pertama. Lalu beliau teruskan dengan sujud. Setelah itu, beliau bangkit kembali dan berdiri dengan panjang, namun tidak sepanjang berdirinya pertama kali. Kemudian ruku' dengan panjang, tetapi tidak sebagaimana ruku'nya yang pertama. Kemudian beliau bangkit lagi dan berdiri dengan lama, namun tidak selama berdirinya yang pertama. Lalu beliau ruku' kembali dengan lama, tetapi tidak seperti ruku'nya yang pertama. Kemudian beliau bangkit lalu sujud. Setelah beliau selesai shalat matahari pun kembali menampakkan cahaya. Maka beliau pun bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda dari tanda-tanda Allah, tidaklah terjadi gerhana pada keduanya karena kematian seseorang atau pun karena kehidupannya. Jika kalian melihat hal itu, maka berdzikirlah kepada Allah.\" Para sahabat berkata, \"Wahai Rasulullah, kamu melihat bahwa Anda sepertinya mendapatkan sesuatu di tempat Anda berdiri, lalu kami melihat bahwa Anda tertahan.\" Maka beliau pun bersabda: \"Sesungguhnya aku melihat surga -atau- surga telah diperlihatkan padaku, lalu aku pun hendak mengambil seranting darinya, sekiranya kau dapat mengambilnya niscaya kalian akan memakannya selama dunia masih ada. Kemudian aku melihat neraka, maka aku tidak pernah melihat pemandangan seperti yang terjadi pada hari ini. Aku melihat kebanyakan penghuninya adalah wanita.\" Mereka bertanya lagi, \"Kenapa wahai Rasulullah.\" Beliau menjawab: \"Karena kekufuran mereka.\" Para sahabat bertanya lagi, \"Apakah lantaran kekafiran mereka kepada Allah?\" beliau menjawab: \"Mereka mengkufuri perlakuan dan kebaikan suaminya. Sekiranya kamu berbuat baik kepada salah seorang dari mereka selama setahun penuh, lalu ia melihat sesuatu yang tidak baik darimu, ia pun akan berkata, 'Aku tidak melihat kebaikan sedikit pun darimu.'\""},"4494":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَوْفٌ عَنْ أَبِي رَجَاءٍ عَنْ عِمْرَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اطَّلَعْتُ فِي الْجَنَّةِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا الْفُقَرَاءَ وَاطَّلَعْتُ فِي النَّارِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَتَابَعَهُ أَيُّوبُ وَسَلْمُ بْنُ زَرِيرٍ","id":"Telah menceritakan kepada kami [Utsman bin Al Haitsam] Telah menceritakan kepada kami ['Auf] dari [Abu Raja`] dari [Imran] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku memperhatikan isi surga, lalu aku mendapatkan bahwa kebanyakan penghuninya adalah orang-orang miskin. Kemudian aku melihat ke dalam neraka, maka aku pun melihat kebanyakan penghuninya adalah para wanita.\" Hadis ini diperkuat oleh [Ayyub] dan [Salm bin Zarir]."},"4495":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ اللَّهِ أَلَمْ أُخْبَرْ أَنَّكَ تَصُومُ النَّهَارَ وَتَقُومُ اللَّيْلَ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ فَلَا تَفْعَلْ صُمْ وَأَفْطِرْ وَقُمْ وَنَمْ فَإِنَّ لِجَسَدِكَ عَلَيْكَ حَقًّا وَإِنَّ لِعَيْنِكَ عَلَيْكَ حَقًّا وَإِنَّ لِزَوْجِكَ عَلَيْكَ حَقًّا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Al Auza'i] ia berkata; Telah menceritakan kepadaku [Yahya bin Abu Katsir] ia berkata; Telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] ia berkata; Telah menceritakan kepadaku [Abdullah bin Amru bin Ash] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abdullah, bukankah telah diberitakan bahwa kamu berpuasa sepanjang hari dan qiyamullail semalan suntuk?\" aku menjawab, \"Benar wahai Rasulullah.\" Beliau bersabda: \"Janganlah kamu melakukan hal itu. Berpuasalah dan juga berbukalah. Tunaikanlah qiyamullail namun sisihkan pula waktu untuk tidur. Sebab bagi jasadmu juga punya hak atas dirimu, kedua matamu juga punya hak atasmu dan bagi isterimu juga punya hak atas dirimu.\""},"4496":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ وَالْأَمِيرُ رَاعٍ وَالرَّجُلُ رَاعٍ عَلَى أَهْلِ بَيْتِهِ وَالْمَرْأَةُ رَاعِيَةٌ عَلَى بَيْتِ زَوْجِهَا وَوَلَدِهِ فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ","id":"Telah menceritakan kepada kami [Abdan] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap kalian adalah pemimpin. Dan setiap kalian akan dimintai pertanggungjawaban terhadap yang dipimpinnya. Seorang Amir adalah pemimpin. Seorang suami juga pemimpin atas keluarganya. Seorang wanita juga pemimpin atas rumah suaminya dan anak-anaknya. Maka setiap kalian adalah pemimpin dan setiap kalian akan dimintai pertanggungjawaban atas yang dipimpinnya.\""},"4497":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ قَالَ حَدَّثَنِي حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُقَالَ آلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نِسَائِهِ شَهْرًا وَقَعَدَ فِي مَشْرُبَةٍ لَهُ فَنَزَلَ لِتِسْعٍ وَعِشْرِينَ فَقِيلَ يَا رَسُولَ اللَّهِ إِنَّكَ آلَيْتَ عَلَى شَهْرٍ قَالَ إِنَّ الشَّهْرَ تِسْعٌ وَعِشْرُونَ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] Telah menceritakan kepada kami [Sulaiman] ia berkata; Telah menceritakan kepadaku [Humaid] dari [Anas] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersumpah untuk tidak mendekati isteri-isterinya selama satu bulan. Kemudian beliau pun duduk di tempat minum miliknya, lalu beliau mendatangi mereka -para isterinya- pada hari yang dua puluh sembilan, maka dikatakanlah pada beliau, \"Wahai Rasulullah, sesungguhnya Anda telah bersumpah untuk sebulan.\" Maka beliau bersabda: \"Sesungguhnya bilangan bulan itu adalah dua puluh sembilan hari.\""},"4498":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي يَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ أَنَّ عِكْرِمَةَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ أَخْبَرَهُ أَنَّ أُمَّ سَلَمَةَ أَخْبَرَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَلَفَ لَا يَدْخُلُ عَلَى بَعْضِ أَهْلِهِ شَهْرًا فَلَمَّا مَضَى تِسْعَةٌ وَعِشْرُونَ يَوْمًا غَدَا عَلَيْهِنَّ أَوْ رَاحَ فَقِيلَ لَهُ يَا نَبِيَّ اللَّهِ حَلَفْتَ أَنْ لَا تَدْخُلَ عَلَيْهِنَّ شَهْرًا قَالَ إِنَّ الشَّهْرَ يَكُونُ تِسْعَةً وَعِشْرِينَ يَوْمًا","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] -dalam riwayat lain- Dan Telah menceritakan kepadaku [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ibnu Juraij] ia berkata; Telah mengabarkan kepadaku [Yahya bin Abdullah bin Shaifi] bahwa [Ikrimah bin Abdurrahman bin Al Harits] Telah mengabarkan kepada mereka, bahwa [Ummu Salamah] telah mengabarkan mereka, bahwa Nabi shallallahu 'alaihi wasallam pernah bersumpah untuk tidak menemui sebagian keluarganya (isteri-isterinya). Maka dua puluh sembilan hari berlalu, di waktu pagi ternyata beliau menemui mereka, maka dikatakanlah pada beliau, \"Wahai Nabiyullah, Anda telah bersumpah untuk tidak masuk menemui mereka selama satu bulan.\" Akhirnya beliau bersabda: \"Sesungguhnya bilangan bulan itu adalah dua puluh sembilan hari.\""},"4499":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ حَدَّثَنَا أَبُو يَعْفُورٍ قَالَ تَذَاكَرْنَا عِنْدَ أَبِي الضُّحَى فَقَالَ حَدَّثَنَا ابْنُ عَبَّاسٍقَالَ أَصْبَحْنَا يَوْمًا وَنِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْكِينَ عِنْدَ كُلِّ امْرَأَةٍ مِنْهُنَّ أَهْلُهَا فَخَرَجْتُ إِلَى الْمَسْجِدِ فَإِذَا هُوَ مَلْآنُ مِنْ النَّاسِ فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ فَصَعِدَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي غُرْفَةٍ لَهُ فَسَلَّمَ فَلَمْ يُجِبْهُ أَحَدٌ ثُمَّ سَلَّمَ فَلَمْ يُجِبْهُ أَحَدٌ ثُمَّ سَلَّمَ فَلَمْ يُجِبْهُ أَحَدٌ فَنَادَاهُ فَدَخَلَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَطَلَّقْتَ نِسَاءَكَ فَقَالَ لَا وَلَكِنْ آلَيْتُ مِنْهُنَّ شَهْرًا فَمَكَثَ تِسْعًا وَعِشْرِينَ ثُمَّ دَخَلَ عَلَى نِسَائِهِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Marwan bin Mu'awiyah] Telah menceritakan kepada kami [Abu Ya'fur] ia berkata; Kami bermudzakarah di sisi [Abu Dluha] maka ia pun berkata; Telah menceritakan kepada kami [Ibnu Abbas] ia berkata; Pada suatu hari saat kami memasuki waktu pagi, ternyata isteri-isteri Nabi shallallahu 'alaihi wasallam menangis, dan di samping setiap orang dari mereka terdapat keluarganya. Lalu aku pun keluar menuju Masjid, ternyata masjid telah dipenuhi oleh kerumunan orang-orang. Kemudian datanglah Umar bin Al Khaththab, dan naik hendak menemui Nabi shallallahu 'alaihi wasallam yang tengah berada di dalam kamarnya. Ia pun mengucapkan salam, namun tak seorang pun yang membalas salamnya, lalu ia mengucapkan salam kembali, namun tak juga ada yang menjawabnya. Akhirnya ia pun dipanggil dan menemui Nabi shallallahu 'alaihi wasallam seraya bertanya, \"Apakah Anda telah menceraikan isteri-isteri Anda?\" beliau menjawab: \"Tidak, tetapi aku telah bersumpah untuk tidak menemui mereka selama satu bulan.\" Setelah dua puluh sembilan hari berlalu, beliau pun menemui mereka."},"4500":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَجْلِدُ أَحَدُكُمْ امْرَأَتَهُ جَلْدَ الْعَبْدِ ثُمَّ يُجَامِعُهَا فِي آخِرِ الْيَوْمِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [bapaknya] dari [Abdullah bin Zam'ah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah salah seorang dari kalian memukul isterinya, seperti ia memukul seorang budak, namun saat hari memasuki waktu senja ia pun menggaulinya.\""}};
